from __future__ import annotations

import copy
from typing import Any, Dict, List, Optional, Tuple

import numpy as np
import onnx
from onnx import numpy_helper

from onnx2tf.tflite_builder.dispatcher import dispatch_node
from onnx2tf.tflite_builder.op_registry import (
    NodeValidationError,
    get_custom_op_candidate_ops,
    get_supported_onnx_ops,
    resolve_node_dispatch,
)
from onnx2tf.tflite_builder.ir import (
    ModelIR,
    OperatorIR,
    QuantParamIR,
    TensorIR,
    normalize_onnx_shape,
)
from onnx2tf.tflite_builder.tensor_buffer_builder import tflite_dtype_from_numpy


_ONNX_TYPE_TO_TFLITE_DTYPE = {
    onnx.TensorProto.FLOAT: "FLOAT32",
    onnx.TensorProto.FLOAT16: "FLOAT16",
    onnx.TensorProto.DOUBLE: "FLOAT64",
    onnx.TensorProto.INT8: "INT8",
    onnx.TensorProto.INT16: "INT16",
    onnx.TensorProto.INT32: "INT32",
    onnx.TensorProto.INT64: "INT64",
    onnx.TensorProto.UINT8: "UINT8",
    onnx.TensorProto.UINT16: "UINT16",
    onnx.TensorProto.UINT32: "UINT32",
    onnx.TensorProto.UINT64: "UINT64",
    onnx.TensorProto.BOOL: "BOOL",
}


def _dtype_from_onnx_elem_type(elem_type: Optional[int]) -> str:
    if elem_type is None:
        return "FLOAT32"
    if elem_type not in _ONNX_TYPE_TO_TFLITE_DTYPE:
        raise NotImplementedError(f"Unsupported ONNX dtype in flatbuffer_direct: elem_type={elem_type}")
    return _ONNX_TYPE_TO_TFLITE_DTYPE[elem_type]


def _collect_constant_arrays(onnx_graph: onnx.ModelProto) -> Dict[str, np.ndarray]:
    constants: Dict[str, np.ndarray] = {}
    for ini in onnx_graph.graph.initializer:
        constants[ini.name] = np.asarray(numpy_helper.to_array(ini))
    for node in onnx_graph.graph.node:
        if str(node.op_type) != "Constant" or len(node.output) < 1:
            continue
        output_name = str(node.output[0])
        if output_name == "":
            continue
        value_attr = None
        for attr in node.attribute:
            if str(attr.name) == "value":
                value_attr = attr
                break
        if value_attr is None:
            continue
        try:
            constants[output_name] = np.asarray(numpy_helper.to_array(value_attr.t))
        except Exception:
            continue
    return constants


def _node_attr_int(node: onnx.NodeProto, attr_name: str, default: int) -> int:
    for attr in node.attribute:
        if str(attr.name) != str(attr_name):
            continue
        if attr.type == onnx.AttributeProto.INT:
            return int(attr.i)
        if attr.type == onnx.AttributeProto.INTS and len(attr.ints) > 0:
            return int(attr.ints[0])
    return int(default)


def _node_attr_ints(node: onnx.NodeProto, attr_name: str) -> List[int]:
    for attr in node.attribute:
        if str(attr.name) != str(attr_name):
            continue
        if attr.type == onnx.AttributeProto.INTS:
            return [int(v) for v in attr.ints]
        if attr.type == onnx.AttributeProto.INT:
            return [int(attr.i)]
    return []


def _infer_missing_tensor_ranks_with_axis_constraints(
    *,
    onnx_graph: onnx.ModelProto,
    shape_map: Dict[str, List[Any]],
) -> None:
    rank_map: Dict[str, int] = {}
    for name, shape in shape_map.items():
        if isinstance(shape, list) and len(shape) > 0:
            rank_map[str(name)] = max(int(rank_map.get(str(name), 0)), int(len(shape)))

    constants = _collect_constant_arrays(onnx_graph)

    def _set_min_rank(tensor_name: str, rank: int) -> bool:
        name = str(tensor_name)
        if name == "" or int(rank) <= 0:
            return False
        prev = int(rank_map.get(name, 0))
        if int(rank) > prev:
            rank_map[name] = int(rank)
            return True
        return False

    def _unify_ranks(names: List[str]) -> bool:
        normalized = [str(v) for v in names if str(v) != ""]
        if len(normalized) == 0:
            return False
        max_rank = max(int(rank_map.get(name, 0)) for name in normalized)
        if max_rank <= 0:
            return False
        changed = False
        for name in normalized:
            changed = _set_min_rank(name, max_rank) or changed
        return changed

    def _slice_axes(node: onnx.NodeProto) -> List[int]:
        if len(node.input) >= 4 and str(node.input[3]) != "":
            axes_arr = constants.get(str(node.input[3]), None)
            if axes_arr is not None:
                return [int(v) for v in np.asarray(axes_arr).reshape(-1).tolist()]
        attr_axes = _node_attr_ints(node, "axes")
        if len(attr_axes) > 0:
            return [int(v) for v in attr_axes]
        if len(node.input) >= 2 and str(node.input[1]) != "":
            starts_arr = constants.get(str(node.input[1]), None)
            if starts_arr is not None:
                starts_len = int(np.asarray(starts_arr).size)
                return [int(v) for v in range(starts_len)]
        return []

    max_iter = max(1, int(len(onnx_graph.graph.node)) * 6)
    for _ in range(max_iter):
        changed = False
        for node in onnx_graph.graph.node:
            op = str(node.op_type)
            inputs = [str(v) for v in node.input if str(v) != ""]
            outputs = [str(v) for v in node.output if str(v) != ""]
            if len(outputs) == 0:
                continue

            if op in {"QuantizeLinear", "DequantizeLinear", "Identity"}:
                if len(inputs) >= 1:
                    changed = _unify_ranks([inputs[0], outputs[0]]) or changed
                continue

            if op in {"Softmax", "LogSoftmax"}:
                if len(inputs) >= 1:
                    changed = _unify_ranks([inputs[0], outputs[0]]) or changed
                    axis = _node_attr_int(node, "axis", 1)
                    if axis >= 0:
                        min_rank = int(axis) + 1
                        changed = _set_min_rank(inputs[0], min_rank) or changed
                        changed = _set_min_rank(outputs[0], min_rank) or changed
                continue

            if op == "Slice":
                if len(inputs) >= 1:
                    changed = _unify_ranks([inputs[0], outputs[0]]) or changed
                    axes = _slice_axes(node)
                    positive_axes = [int(v) for v in axes if int(v) >= 0]
                    if len(positive_axes) > 0:
                        min_rank = max(positive_axes) + 1
                        changed = _set_min_rank(inputs[0], min_rank) or changed
                        changed = _set_min_rank(outputs[0], min_rank) or changed
                continue

            if op == "QLinearConv":
                if len(inputs) >= 1:
                    changed = _set_min_rank(inputs[0], 4) or changed
                changed = _set_min_rank(outputs[0], 4) or changed
                continue

            if op in {"Concat", "QLinearConcat"}:
                if op == "QLinearConcat":
                    data_inputs = [inputs[idx] for idx in range(2, len(inputs), 3)]
                else:
                    data_inputs = list(inputs)
                rank_linked = [str(v) for v in data_inputs if str(v) != ""] + [outputs[0]]
                changed = _unify_ranks(rank_linked) or changed
                axis = _node_attr_int(node, "axis", 1)
                if axis >= 0:
                    min_rank = int(axis) + 1
                    for tensor_name in rank_linked:
                        changed = _set_min_rank(tensor_name, min_rank) or changed
                continue

        if not changed:
            break

    for tensor_name, rank in rank_map.items():
        if int(rank) <= 0:
            continue
        current = shape_map.get(str(tensor_name), None)
        if current is None or len(current) == 0:
            shape_map[str(tensor_name)] = [-1 for _ in range(int(rank))]


def _extract_tensor_info(
    onnx_graph: onnx.ModelProto,
) -> Tuple[Dict[str, List[Any]], Dict[str, str]]:
    shape_map: Dict[str, List[Any]] = {}
    dtype_map: Dict[str, str] = {}

    def _fill_value_info(value_info):
        if not value_info.type.HasField("tensor_type"):
            return
        name = value_info.name
        tensor_type = value_info.type.tensor_type
        dims: List[Any] = []
        if tensor_type.HasField("shape"):
            for d in tensor_type.shape.dim:
                if d.HasField("dim_value") and d.dim_value >= 0:
                    dims.append(int(d.dim_value))
                else:
                    dims.append(-1)
        shape_map[name] = dims
        dtype_map[name] = _dtype_from_onnx_elem_type(tensor_type.elem_type)

    for vi in onnx_graph.graph.input:
        _fill_value_info(vi)
    for vi in onnx_graph.graph.value_info:
        _fill_value_info(vi)
    for vi in onnx_graph.graph.output:
        _fill_value_info(vi)

    for ini in onnx_graph.graph.initializer:
        arr = numpy_helper.to_array(ini)
        shape_map[ini.name] = list(arr.shape)
        dtype_map[ini.name] = tflite_dtype_from_numpy(arr.dtype)

    _infer_missing_tensor_ranks_with_axis_constraints(
        onnx_graph=onnx_graph,
        shape_map=shape_map,
    )

    return shape_map, dtype_map


def _graph_has_missing_rank_info(onnx_graph: onnx.ModelProto) -> bool:
    value_infos = (
        list(onnx_graph.graph.input)
        + list(onnx_graph.graph.value_info)
        + list(onnx_graph.graph.output)
    )
    for vi in value_infos:
        if not vi.type.HasField("tensor_type"):
            continue
        if not vi.type.tensor_type.HasField("shape"):
            return True
    return False


def _infer_shapes_with_fallback(onnx_graph: onnx.ModelProto) -> onnx.ModelProto:
    inferred_graph = onnx_graph
    try:
        inferred_graph = onnx.shape_inference.infer_shapes(inferred_graph)
    except Exception:
        pass

    if not _graph_has_missing_rank_info(inferred_graph):
        return inferred_graph

    try:
        from onnxruntime.tools.symbolic_shape_infer import SymbolicShapeInference
    except Exception:
        return inferred_graph

    try:
        return SymbolicShapeInference.infer_shapes(
            inferred_graph,
            auto_merge=True,
            guess_output_rank=True,
        )
    except TypeError:
        try:
            return SymbolicShapeInference.infer_shapes(inferred_graph)
        except Exception:
            return inferred_graph
    except Exception:
        return inferred_graph


class LoweringContext:
    def __init__(
        self,
        model_ir: ModelIR,
        shape_map: Dict[str, List[Any]],
        dtype_map: Dict[str, str],
        constants: Dict[str, np.ndarray],
        onnx_model: Optional[Any] = None,
        allow_custom_ops: bool = False,
        custom_op_allowlist: Optional[List[str]] = None,
        disable_group_convolution: bool = False,
        tensor_consumer_count: Optional[Dict[str, int]] = None,
        graph_output_names: Optional[List[str]] = None,
        output_nms_with_argmax: bool = False,
    ):
        self.model_ir = model_ir
        self.shape_map = shape_map
        self.dtype_map = dtype_map
        self.constants = constants
        self.onnx_model = onnx_model
        self.allow_custom_ops = bool(allow_custom_ops)
        self.custom_op_allowlist = (
            list(custom_op_allowlist) if custom_op_allowlist is not None else None
        )
        self.disable_group_convolution = bool(disable_group_convolution)
        self.tensor_consumer_count = (
            dict(tensor_consumer_count)
            if isinstance(tensor_consumer_count, dict)
            else {}
        )
        self.graph_output_names = set(graph_output_names) if graph_output_names is not None else set()
        self.output_nms_with_argmax = bool(output_nms_with_argmax)
        self._serial = 0

    def _next_name(self, base: str) -> str:
        self._serial += 1
        return f"{base}_{self._serial}"

    def get_tensor_shape(self, name: str) -> List[int]:
        if name in self.model_ir.tensors:
            return list(self.model_ir.tensors[name].shape)
        shape = self.shape_map.get(name, None)
        norm_shape, _ = normalize_onnx_shape(shape)
        return norm_shape

    def get_tensor_dtype(self, name: str) -> str:
        if name in self.model_ir.tensors:
            return self.model_ir.tensors[name].dtype
        return self.dtype_map.get(name, "FLOAT32")

    def get_constant_array(self, name: str) -> Optional[np.ndarray]:
        if name in self.constants:
            return self.constants[name]
        t = self.model_ir.tensors.get(name, None)
        if t is not None and isinstance(t.data, np.ndarray):
            return t.data
        return None

    def ensure_tensor(self, name: str, dtype: Optional[str] = None, shape: Optional[List[int]] = None) -> str:
        if name == "":
            raise ValueError("Tensor name must not be empty in flatbuffer_direct lowering.")
        if name in self.model_ir.tensors:
            return name
        if dtype is None:
            dtype = self.dtype_map.get(name, "FLOAT32")
        if shape is None:
            shape = self.shape_map.get(name, None)
        shape, signature = normalize_onnx_shape(shape)
        self.model_ir.tensors[name] = TensorIR(
            name=name,
            dtype=dtype,
            shape=list(shape),
            shape_signature=list(signature),
            data=self.constants.get(name, None),
        )
        return name

    def add_const_tensor(self, base_name: str, data: np.ndarray) -> str:
        name = base_name
        if name in self.model_ir.tensors:
            name = self._next_name(base_name)
        data = np.asarray(data)
        dtype = tflite_dtype_from_numpy(data.dtype)
        shape, signature = normalize_onnx_shape(list(data.shape))
        self.model_ir.tensors[name] = TensorIR(
            name=name,
            dtype=dtype,
            shape=shape,
            shape_signature=signature,
            data=data,
        )
        self.constants[name] = data
        return name

    def add_intermediate_tensor(self, base_name: str, dtype: str, shape: List[int]) -> str:
        if base_name == "":
            raise ValueError("Tensor name must not be empty in flatbuffer_direct lowering.")
        name = base_name
        if name in self.model_ir.tensors:
            name = self._next_name(base_name)
        norm_shape, signature = normalize_onnx_shape(shape)
        self.model_ir.tensors[name] = TensorIR(
            name=name,
            dtype=dtype,
            shape=norm_shape,
            shape_signature=signature,
            data=None,
        )
        return name

    def add_operator(self, op: OperatorIR) -> None:
        self.model_ir.operators.append(op)


class _NodeWrap:
    def __init__(
        self,
        n: onnx.NodeProto,
        input_name_remap: Optional[Dict[str, str]] = None,
    ):
        self.name = n.name if n.name else n.op_type
        self.op = n.op_type
        self.attrs = {}
        for a in n.attribute:
            if a.type == onnx.AttributeProto.INT:
                self.attrs[a.name] = int(a.i)
            elif a.type == onnx.AttributeProto.FLOAT:
                self.attrs[a.name] = float(a.f)
            elif a.type == onnx.AttributeProto.INTS:
                self.attrs[a.name] = [int(v) for v in a.ints]
            elif a.type == onnx.AttributeProto.FLOATS:
                self.attrs[a.name] = [float(v) for v in a.floats]
            elif a.type == onnx.AttributeProto.STRING:
                self.attrs[a.name] = a.s.decode("utf-8")
            else:
                pass
        remap = input_name_remap if isinstance(input_name_remap, dict) else {}
        self.inputs = [
            type("In", (), {"name": remap.get(i, i)})
            for i in n.input
            if i != ""
        ]
        self.outputs = [type("Out", (), {"name": o}) for o in n.output if o != ""]


def _build_tensor_consumer_map(model_ir: ModelIR) -> Dict[str, List[int]]:
    consumers: Dict[str, List[int]] = {}
    for op_idx, op in enumerate(model_ir.operators):
        for input_name in op.inputs:
            if input_name not in consumers:
                consumers[input_name] = []
            consumers[input_name].append(op_idx)
    return consumers


def _read_transpose_perm(model_ir: ModelIR, op: OperatorIR) -> Optional[List[int]]:
    if str(op.op_type) != "TRANSPOSE":
        return None
    if len(op.inputs) < 2:
        return None
    perm_tensor_name = op.inputs[1]
    perm_tensor = model_ir.tensors.get(perm_tensor_name, None)
    if perm_tensor is None or perm_tensor.data is None:
        return None
    perm = np.asarray(perm_tensor.data).reshape(-1)
    if perm.size == 0:
        return None
    return [int(v) for v in perm.tolist()]


def _is_identity_perm(perm: List[int]) -> bool:
    return perm == [int(i) for i in range(len(perm))]


def _is_inverse_perm(perm_a: List[int], perm_b: List[int]) -> bool:
    if len(perm_a) != len(perm_b):
        return False
    rank = len(perm_a)
    if sorted(perm_a) != [int(i) for i in range(rank)]:
        return False
    if sorted(perm_b) != [int(i) for i in range(rank)]:
        return False
    for idx, value in enumerate(perm_a):
        if perm_b[value] != idx:
            return False
    return True


def _invert_perm(perm: List[int]) -> Optional[List[int]]:
    rank = len(perm)
    if sorted(perm) != [int(i) for i in range(rank)]:
        return None
    inv = [0 for _ in range(rank)]
    for idx, value in enumerate(perm):
        inv[int(value)] = int(idx)
    return inv


def _append_tensor_lineage_event(
    *,
    model_ir: ModelIR,
    event: Dict[str, Any],
) -> None:
    if "tensor_lineage_events" not in model_ir.metadata:
        model_ir.metadata["tensor_lineage_events"] = []
    events = model_ir.metadata["tensor_lineage_events"]
    if not isinstance(events, list):
        events = []
        model_ir.metadata["tensor_lineage_events"] = events
    normalized_event = dict(event)
    normalized_event["event_index"] = int(len(events))
    events.append(normalized_event)


def _replace_tensor_inputs(model_ir: ModelIR, src_name: str, dst_name: str) -> None:
    if str(src_name) != str(dst_name):
        _append_tensor_lineage_event(
            model_ir=model_ir,
            event={
                "kind": "replace_input",
                "src_name": str(src_name),
                "dst_name": str(dst_name),
            },
        )
    for op in model_ir.operators:
        if len(op.inputs) > 0:
            op.inputs = [dst_name if input_name == src_name else input_name for input_name in op.inputs]


def _set_operator_inputs(
    *,
    model_ir: ModelIR,
    op: OperatorIR,
    new_inputs: List[str],
) -> None:
    old_inputs = [str(v) for v in list(op.inputs)]
    normalized_new_inputs = [str(v) for v in list(new_inputs)]
    pair_count = int(min(len(old_inputs), len(normalized_new_inputs)))
    for index in range(pair_count):
        old_name = str(old_inputs[index])
        new_name = str(normalized_new_inputs[index])
        if old_name == new_name:
            continue
        _append_tensor_lineage_event(
            model_ir=model_ir,
            event={
                "kind": "replace_input",
                "src_name": old_name,
                "dst_name": new_name,
                "source": "set_operator_inputs",
            },
        )
    op.inputs = normalized_new_inputs


def _set_operator_outputs(
    *,
    model_ir: ModelIR,
    op: OperatorIR,
    new_outputs: List[str],
) -> None:
    old_outputs = [str(v) for v in list(op.outputs)]
    normalized_new_outputs = [str(v) for v in list(new_outputs)]
    pair_count = int(min(len(old_outputs), len(normalized_new_outputs)))
    for index in range(pair_count):
        old_name = str(old_outputs[index])
        new_name = str(normalized_new_outputs[index])
        if old_name == new_name:
            continue
        _append_tensor_lineage_event(
            model_ir=model_ir,
            event={
                "kind": "rename_tensor",
                "old_name": old_name,
                "new_name": new_name,
                "source": "set_operator_outputs",
            },
        )
    op.outputs = normalized_new_outputs


def _replace_operator_input_at(
    *,
    model_ir: ModelIR,
    op: OperatorIR,
    input_index: int,
    new_input_name: str,
) -> None:
    if int(input_index) < 0 or int(input_index) >= len(op.inputs):
        return
    old_name = str(op.inputs[int(input_index)])
    new_name = str(new_input_name)
    if old_name != new_name:
        _append_tensor_lineage_event(
            model_ir=model_ir,
            event={
                "kind": "replace_input",
                "src_name": old_name,
                "dst_name": new_name,
                "source": "replace_operator_input_at",
            },
        )
    op.inputs[int(input_index)] = new_name


def _prune_unused_tensors(model_ir: ModelIR) -> None:
    used_tensor_names = set(model_ir.inputs + model_ir.outputs)
    for op in model_ir.operators:
        used_tensor_names.update(op.inputs)
        used_tensor_names.update(op.outputs)
    unused_tensor_names = [name for name in model_ir.tensors.keys() if name not in used_tensor_names]
    if len(unused_tensor_names) > 0:
        _append_tensor_lineage_event(
            model_ir=model_ir,
            event={
                "kind": "prune_unused_tensors",
                "removed_names": [str(v) for v in unused_tensor_names],
            },
        )
    for name in unused_tensor_names:
        del model_ir.tensors[name]


def _prune_dead_operators(model_ir: ModelIR) -> Dict[str, int]:
    """
    Remove operators that do not contribute to graph outputs.

    This pass performs a reverse liveness walk from model outputs and keeps only
    operators whose outputs are required by downstream live operators or graph outputs.
    """
    if len(model_ir.operators) == 0:
        return {"removed_dead_operators": 0}

    live_tensors = set(model_ir.outputs)
    keep_flags = [False for _ in model_ir.operators]

    for op_idx in range(len(model_ir.operators) - 1, -1, -1):
        op = model_ir.operators[op_idx]
        outputs = list(op.outputs)
        if len(outputs) == 0:
            continue
        if any(out_name in live_tensors for out_name in outputs):
            keep_flags[op_idx] = True
            for input_name in op.inputs:
                live_tensors.add(input_name)

    removed = int(sum(1 for keep in keep_flags if not keep))
    if removed == 0:
        return {"removed_dead_operators": 0}

    model_ir.operators = [
        op for idx, op in enumerate(model_ir.operators) if keep_flags[idx]
    ]
    _prune_unused_tensors(model_ir)
    return {"removed_dead_operators": removed}


def _build_tensor_producer_map(model_ir: ModelIR) -> Dict[str, int]:
    producers: Dict[str, int] = {}
    for op_idx, op in enumerate(model_ir.operators):
        for output_name in op.outputs:
            producers[output_name] = op_idx
    return producers


def _rename_tensor_globally(
    model_ir: ModelIR,
    old_name: str,
    new_name: str,
) -> None:
    if old_name == new_name:
        return

    for op in model_ir.operators:
        if len(op.inputs) > 0:
            op.inputs = [new_name if input_name == old_name else input_name for input_name in op.inputs]
        if len(op.outputs) > 0:
            op.outputs = [new_name if output_name == old_name else output_name for output_name in op.outputs]

    if len(model_ir.inputs) > 0:
        model_ir.inputs = [new_name if input_name == old_name else input_name for input_name in model_ir.inputs]
    if len(model_ir.outputs) > 0:
        model_ir.outputs = [new_name if output_name == old_name else output_name for output_name in model_ir.outputs]

    old_tensor = model_ir.tensors.get(old_name, None)
    if old_tensor is None:
        if new_name in model_ir.tensors:
            del model_ir.tensors[new_name]
        return
    old_tensor.name = new_name
    if new_name in model_ir.tensors and new_name != old_name:
        del model_ir.tensors[new_name]
    del model_ir.tensors[old_name]
    model_ir.tensors[new_name] = old_tensor
    _append_tensor_lineage_event(
        model_ir=model_ir,
        event={
            "kind": "rename_tensor",
            "old_name": str(old_name),
            "new_name": str(new_name),
        },
    )


def _clone_quantization(quantization: Any) -> Any:
    if quantization is None:
        return None
    if isinstance(quantization, QuantParamIR):
        return QuantParamIR(
            scale=list(quantization.scale),
            zero_point=list(quantization.zero_point),
            quantized_dimension=int(quantization.quantized_dimension),
            min=list(quantization.min) if quantization.min is not None else None,
            max=list(quantization.max) if quantization.max is not None else None,
        )
    return copy.deepcopy(quantization)


def _quantize_prelu_alpha(
    alpha: np.ndarray,
    target_dtype: str,
) -> Tuple[np.ndarray, QuantParamIR]:
    alpha = np.asarray(alpha, dtype=np.float32)
    if str(target_dtype) == "INT8":
        max_abs = float(np.max(np.abs(alpha))) if alpha.size > 0 else 0.0
        scale = max(max_abs / 127.0, 1e-8)
        quantized = np.clip(np.round(alpha / scale), -128, 127).astype(np.int8)
        return quantized, QuantParamIR(
            scale=[float(scale)],
            zero_point=[0],
            quantized_dimension=0,
        )
    if str(target_dtype) == "UINT8":
        mn = float(np.min(alpha)) if alpha.size > 0 else 0.0
        mx = float(np.max(alpha)) if alpha.size > 0 else 0.0
        scale = max((mx - mn) / 255.0, 1e-8)
        zp = int(np.round(-mn / scale))
        zp = int(np.clip(zp, 0, 255))
        quantized = np.clip(np.round(alpha / scale) + zp, 0, 255).astype(np.uint8)
        return quantized, QuantParamIR(
            scale=[float(scale)],
            zero_point=[int(zp)],
            quantized_dimension=0,
        )
    raise NotImplementedError(f"Quantized PRELU alpha requires INT8/UINT8. got={target_dtype}")


def _quantize_tensor_per_tensor(
    values: np.ndarray,
    target_dtype: str,
) -> Tuple[np.ndarray, QuantParamIR]:
    values = np.asarray(values, dtype=np.float32)
    if str(target_dtype) == "INT8":
        max_abs = float(np.max(np.abs(values))) if values.size > 0 else 0.0
        scale = max(max_abs / 127.0, 1e-8)
        quantized = np.clip(np.round(values / scale), -128, 127).astype(np.int8)
        return quantized, QuantParamIR(
            scale=[float(scale)],
            zero_point=[0],
            quantized_dimension=0,
        )
    if str(target_dtype) == "UINT8":
        mn = float(np.min(values)) if values.size > 0 else 0.0
        mx = float(np.max(values)) if values.size > 0 else 0.0
        scale = max((mx - mn) / 255.0, 1e-8)
        zp = int(np.round(-mn / scale))
        zp = int(np.clip(zp, 0, 255))
        quantized = np.clip(np.round(values / scale) + zp, 0, 255).astype(np.uint8)
        return quantized, QuantParamIR(
            scale=[float(scale)],
            zero_point=[int(zp)],
            quantized_dimension=0,
        )
    raise NotImplementedError(f"Per-tensor quantization supports INT8/UINT8 only. got={target_dtype}")


def _get_per_tensor_scale_zero_point(quantization: Any) -> Optional[Tuple[float, int]]:
    if quantization is None:
        return None
    if not _is_per_tensor_quantization(quantization):
        return None
    if isinstance(quantization, QuantParamIR):
        if len(list(quantization.scale)) == 0 or len(list(quantization.zero_point)) == 0:
            return None
        return float(quantization.scale[0]), int(quantization.zero_point[0])
    if isinstance(quantization, dict):
        try:
            scale = np.asarray(quantization.get("scale", []), dtype=np.float32).reshape(-1)
            zero_point = np.asarray(quantization.get("zero_point", []), dtype=np.int64).reshape(-1)
            if scale.size == 0 or zero_point.size == 0:
                return None
            return float(scale[0]), int(zero_point[0])
        except Exception:
            return None
    return None


def _is_same_per_tensor_quantization(
    quantization_a: Any,
    quantization_b: Any,
    *,
    rtol: float = 1e-6,
    atol: float = 1e-8,
) -> bool:
    qparams_a = _get_per_tensor_scale_zero_point(quantization_a)
    qparams_b = _get_per_tensor_scale_zero_point(quantization_b)
    if qparams_a is None or qparams_b is None:
        return False
    scale_a, zp_a = qparams_a
    scale_b, zp_b = qparams_b
    if int(zp_a) != int(zp_b):
        return False
    return bool(np.isclose(float(scale_a), float(scale_b), rtol=rtol, atol=atol))


def _quant_scale_count(quantization: Any) -> int:
    if quantization is None:
        return 0
    if isinstance(quantization, QuantParamIR):
        return len(list(quantization.scale))
    if isinstance(quantization, dict):
        scale = quantization.get("scale", None)
        if scale is None:
            return 0
        if isinstance(scale, (list, tuple)):
            return len(list(scale))
        try:
            return int(np.asarray(scale).size)
        except Exception:
            return 0
    return 0


def _is_per_tensor_quantization(quantization: Any) -> bool:
    count = _quant_scale_count(quantization)
    return count <= 1


def _permute_shape(shape: Optional[List[int]], perm: List[int]) -> Optional[List[int]]:
    if shape is None:
        return None
    rank = len(shape)
    if len(perm) != rank:
        return None
    if sorted(perm) != [int(i) for i in range(rank)]:
        return None
    return [int(shape[int(axis)]) for axis in perm]


def _shapes_equal(shape_a: Optional[List[int]], shape_b: Optional[List[int]]) -> bool:
    if shape_a is None or shape_b is None:
        return False
    if len(shape_a) != len(shape_b):
        return False
    return all(int(a) == int(b) for a, b in zip(shape_a, shape_b))


def _is_unknown_shape(shape: Optional[List[int]]) -> bool:
    if shape is None:
        return True
    if len(shape) == 0:
        return True
    if any(int(dim) < 0 for dim in shape):
        return True
    # Internal placeholder shape used before static shape propagation.
    if len(shape) == 1 and int(shape[0]) == 1:
        return True
    return False


def _shapes_match_if_known(shape_a: Optional[List[int]], shape_b: Optional[List[int]]) -> bool:
    if _is_unknown_shape(shape_a) or _is_unknown_shape(shape_b):
        return True
    return _shapes_equal(shape_a, shape_b)


def _all_per_tensor_quantized(tensors: List[Optional[TensorIR]]) -> bool:
    for tensor in tensors:
        if tensor is None:
            continue
        if tensor.quantization is None:
            continue
        if not _is_per_tensor_quantization(tensor.quantization):
            return False
    return True


def _resolve_reshape_new_shape_from_static_input(
    new_shape: List[int],
    input_signature: Optional[List[int]],
    allow_zero: Optional[bool] = None,
) -> Optional[List[int]]:
    if len(new_shape) == 0:
        return None
    candidate = [int(v) for v in new_shape]
    if all(int(dim) >= 0 for dim in candidate):
        return list(candidate)

    if any(int(dim) == 0 for dim in candidate):
        # Without allowzero metadata we avoid rewriting zero-dim requests.
        if allow_zero is None:
            return None
        if allow_zero:
            return None
        if input_signature is None or len(input_signature) == 0:
            return None
        for idx, dim in enumerate(candidate):
            if int(dim) != 0:
                continue
            if idx >= len(input_signature):
                return None
            in_dim = int(input_signature[idx])
            if in_dim <= 0:
                return None
            candidate[idx] = int(in_dim)

    minus_one_indices = [idx for idx, dim in enumerate(candidate) if int(dim) == -1]
    if len(minus_one_indices) != 1:
        return None
    if input_signature is None or len(input_signature) == 0:
        return None
    if any(int(dim) <= 0 for dim in input_signature):
        return None

    known_product = 1
    for dim in candidate:
        if int(dim) == -1:
            continue
        if int(dim) <= 0:
            return None
        known_product *= int(dim)
    if known_product <= 0:
        return None

    input_product = int(np.prod(np.asarray(input_signature, dtype=np.int64)))
    if input_product <= 0 or input_product % known_product != 0:
        return None
    inferred = int(input_product // known_product)
    if inferred <= 0:
        return None
    candidate[minus_one_indices[0]] = inferred
    return candidate


def _resolve_dynamic_reshape_shapes(model_ir: ModelIR) -> Dict[str, int]:
    resolved_count = 0
    for op in model_ir.operators:
        if str(op.op_type) != "RESHAPE":
            continue
        if len(op.inputs) < 1 or len(op.outputs) != 1:
            continue

        raw_new_shape = op.options.get("onnxRawNewShape", op.options.get("newShape", []))
        try:
            new_shape = [int(v) for v in np.asarray(raw_new_shape).reshape(-1).tolist()]
        except Exception:
            continue

        input_tensor = model_ir.tensors.get(op.inputs[0], None)
        if input_tensor is None:
            continue
        input_signature = (
            list(input_tensor.shape_signature)
            if input_tensor.shape_signature is not None
            else list(input_tensor.shape)
        )
        resolved_shape = _resolve_reshape_new_shape_from_static_input(
            new_shape=new_shape,
            input_signature=input_signature,
            allow_zero=(
                bool(op.options.get("allowZero"))
                if "allowZero" in op.options
                else None
            ),
        )
        if resolved_shape is None:
            continue

        changed = False
        if [int(v) for v in new_shape] != [int(v) for v in resolved_shape]:
            op.options["newShape"] = [int(v) for v in resolved_shape]
            changed = True

        if len(op.inputs) >= 2:
            shape_tensor = model_ir.tensors.get(op.inputs[1], None)
            if shape_tensor is not None:
                existing_shape_data = None
                if shape_tensor.data is not None:
                    existing_shape_data = [
                        int(v) for v in np.asarray(shape_tensor.data).reshape(-1).tolist()
                    ]
                if existing_shape_data != [int(v) for v in resolved_shape]:
                    shape_tensor.data = np.asarray(resolved_shape, dtype=np.int32)
                    shape_tensor.dtype = "INT32"
                    shape_tensor.shape = [int(len(resolved_shape))]
                    shape_tensor.shape_signature = [int(len(resolved_shape))]
                    changed = True

        output_tensor = model_ir.tensors.get(op.outputs[0], None)
        if output_tensor is not None:
            output_shape = list(output_tensor.shape)
            output_signature = (
                list(output_tensor.shape_signature)
                if output_tensor.shape_signature is not None
                else None
            )
            if output_shape != [int(v) for v in resolved_shape] or output_signature != [int(v) for v in resolved_shape]:
                output_tensor.shape = [int(v) for v in resolved_shape]
                output_tensor.shape_signature = [int(v) for v in resolved_shape]
                changed = True

        if changed:
            resolved_count += 1

    return {"resolved_dynamic_reshape_shapes": int(resolved_count)}


def _is_fully_known_positive_shape(shape: Optional[List[int]]) -> bool:
    if shape is None or len(shape) == 0:
        return False
    return all(int(dim) > 0 for dim in shape)


def _read_const_ints_from_tensor(tensor: Optional[TensorIR]) -> Optional[List[int]]:
    if tensor is None or tensor.data is None:
        return None
    try:
        return [int(v) for v in np.asarray(tensor.data).reshape(-1).tolist()]
    except Exception:
        return None


def _write_const_ints_to_tensor(tensor: Optional[TensorIR], values: List[int]) -> bool:
    if tensor is None:
        return False
    current = _read_const_ints_from_tensor(tensor)
    normalized = [int(v) for v in list(values)]
    if current == normalized:
        return False
    np_dtype = np.int32
    if tensor.data is not None:
        try:
            np_dtype = np.asarray(tensor.data).dtype
        except Exception:
            np_dtype = np.int32
    tensor.data = np.asarray(normalized, dtype=np_dtype)
    tensor.shape = [int(len(normalized))]
    tensor.shape_signature = [int(len(normalized))]
    return True


def _infer_slice_output_shape_and_resolved_params(
    input_shape: Optional[List[int]],
    begin_vals: Optional[List[int]],
    size_vals: Optional[List[int]],
) -> Tuple[Optional[List[int]], Optional[List[int]], Optional[List[int]]]:
    if not _is_fully_known_positive_shape(input_shape):
        return None, None, None
    if begin_vals is None or size_vals is None:
        return None, None, None

    in_shape = [int(v) for v in list(input_shape)]
    begin = [int(v) for v in list(begin_vals)]
    size = [int(v) for v in list(size_vals)]
    rank = len(in_shape)
    if len(begin) != rank or len(size) != rank:
        return None, None, None

    resolved_begin: List[int] = []
    resolved_size: List[int] = []
    out_shape: List[int] = []
    for axis, dim in enumerate(in_shape):
        b = int(begin[axis])
        if b < 0:
            b += int(dim)
        b = max(0, min(int(b), int(dim)))
        remain = max(int(dim) - int(b), 0)

        raw_size = int(size[axis])
        if raw_size == -1:
            s = int(remain)
        elif raw_size >= 0:
            s = int(raw_size)
        else:
            return None, None, None

        out_dim = max(min(int(s), int(remain)), 0)
        resolved_begin.append(int(b))
        resolved_size.append(int(s))
        out_shape.append(int(out_dim))

    return out_shape, resolved_begin, resolved_size


def _broadcast_static_shapes(
    shape_a: Optional[List[int]],
    shape_b: Optional[List[int]],
) -> Optional[List[int]]:
    if not _is_fully_known_positive_shape(shape_a) or not _is_fully_known_positive_shape(shape_b):
        return None
    a = [int(v) for v in list(shape_a)]
    b = [int(v) for v in list(shape_b)]
    rank = max(len(a), len(b))
    a = [1] * (rank - len(a)) + a
    b = [1] * (rank - len(b)) + b
    out: List[int] = []
    for dim_a, dim_b in zip(a, b):
        if int(dim_a) == int(dim_b):
            out.append(int(dim_a))
            continue
        if int(dim_a) == 1:
            out.append(int(dim_b))
            continue
        if int(dim_b) == 1:
            out.append(int(dim_a))
            continue
        return None
    return out


def _broadcast_shape_signatures(
    signature_a: Optional[List[int]],
    signature_b: Optional[List[int]],
) -> Optional[List[int]]:
    if signature_a is None or signature_b is None:
        return None
    a = [int(v) for v in list(signature_a)]
    b = [int(v) for v in list(signature_b)]
    rank = max(len(a), len(b))
    a = [1] * (rank - len(a)) + a
    b = [1] * (rank - len(b)) + b
    out: List[int] = []
    for dim_a, dim_b in zip(a, b):
        if int(dim_a) == int(dim_b):
            out.append(int(dim_a))
            continue
        if int(dim_a) == 1:
            out.append(-1 if int(dim_b) < 0 else int(dim_b))
            continue
        if int(dim_b) == 1:
            out.append(-1 if int(dim_a) < 0 else int(dim_a))
            continue
        if int(dim_a) < 0 and int(dim_b) < 0:
            out.append(-1)
            continue
        if int(dim_a) < 0 and int(dim_b) > 1:
            out.append(int(dim_b))
            continue
        if int(dim_b) < 0 and int(dim_a) > 1:
            out.append(int(dim_a))
            continue
        return None
    return out


def _infer_batch_matmul_output_shape_and_signature(
    shape_a: Optional[List[int]],
    shape_b: Optional[List[int]],
    signature_a: Optional[List[int]],
    signature_b: Optional[List[int]],
    adj_x: bool,
    adj_y: bool,
) -> Tuple[Optional[List[int]], Optional[List[int]]]:
    if not _is_fully_known_positive_shape(shape_a) or not _is_fully_known_positive_shape(shape_b):
        return None, None
    a_shape = [int(v) for v in list(shape_a)]
    b_shape = [int(v) for v in list(shape_b)]
    if len(a_shape) < 2 or len(b_shape) < 2:
        return None, None

    a_sig = (
        [int(v) for v in list(signature_a)]
        if signature_a is not None and len(list(signature_a)) == len(a_shape)
        else list(a_shape)
    )
    b_sig = (
        [int(v) for v in list(signature_b)]
        if signature_b is not None and len(list(signature_b)) == len(b_shape)
        else list(b_shape)
    )

    batch_shape = _broadcast_static_shapes(a_shape[:-2], b_shape[:-2])
    if batch_shape is None:
        return None, None

    a_m_idx = -1 if bool(adj_x) else -2
    a_k_idx = -2 if bool(adj_x) else -1
    b_k_idx = -1 if bool(adj_y) else -2
    b_n_idx = -2 if bool(adj_y) else -1

    a_m = int(a_shape[a_m_idx])
    a_k = int(a_shape[a_k_idx])
    b_k = int(b_shape[b_k_idx])
    b_n = int(b_shape[b_n_idx])

    a_k_sig = int(a_sig[a_k_idx])
    b_k_sig = int(b_sig[b_k_idx])
    if a_k != b_k and a_k_sig >= 0 and b_k_sig >= 0:
        return None, None

    out_shape = [int(v) for v in list(batch_shape)] + [int(a_m), int(b_n)]

    batch_sig = _broadcast_shape_signatures(a_sig[:-2], b_sig[:-2])
    if batch_sig is None:
        batch_sig = [int(v) for v in list(batch_shape)]
    out_sig_m = -1 if int(a_sig[a_m_idx]) < 0 else int(a_m)
    out_sig_n = -1 if int(b_sig[b_n_idx]) < 0 else int(b_n)
    out_signature = [int(v) for v in list(batch_sig)] + [int(out_sig_m), int(out_sig_n)]

    return out_shape, out_signature


def _infer_rank4_signature_from_input(
    *,
    input_signature: Optional[List[int]],
    output_shape: Optional[List[int]],
    existing_output_signature: Optional[List[int]] = None,
    propagate_channel: bool = False,
) -> Optional[List[int]]:
    if output_shape is None or len(list(output_shape)) != 4:
        return None
    signature = [int(v) for v in list(output_shape)]
    if existing_output_signature is not None and len(list(existing_output_signature)) == 4:
        for axis in range(4):
            if int(existing_output_signature[axis]) < 0:
                signature[axis] = -1
    if input_signature is not None and len(list(input_signature)) == 4:
        if int(input_signature[0]) < 0:
            signature[0] = -1
        if int(input_signature[1]) < 0:
            signature[1] = -1
        if int(input_signature[2]) < 0:
            signature[2] = -1
        if propagate_channel and int(input_signature[3]) < 0:
            signature[3] = -1
    return signature


def _normalize_reduce_axes_for_rank(
    axes: Optional[List[int]],
    rank: int,
) -> Optional[List[int]]:
    if axes is None:
        return None
    if rank < 0:
        return None
    normalized: List[int] = []
    for axis in list(axes):
        a = int(axis)
        if a < 0:
            a += int(rank)
        if a < 0 or a >= int(rank):
            return None
        if int(a) not in normalized:
            normalized.append(int(a))
    return normalized


def _infer_reduce_output_shape_and_signature(
    *,
    input_shape: Optional[List[int]],
    input_signature: Optional[List[int]],
    axes: Optional[List[int]],
    keep_dims: bool,
) -> Tuple[Optional[List[int]], Optional[List[int]]]:
    if input_shape is None:
        return None, None
    in_shape = [int(v) for v in list(input_shape)]
    rank = len(in_shape)
    if rank == 0:
        return list(in_shape), list(in_shape)
    normalized_axes = _normalize_reduce_axes_for_rank(axes, rank)
    if normalized_axes is None:
        return None, None

    if input_signature is not None and len(list(input_signature)) == rank:
        in_signature = [int(v) for v in list(input_signature)]
    else:
        in_signature = [int(v) for v in list(in_shape)]

    if bool(keep_dims):
        out_shape = [int(v) for v in list(in_shape)]
        out_signature = [int(v) for v in list(in_signature)]
        for axis in normalized_axes:
            out_shape[int(axis)] = 1
            out_signature[int(axis)] = 1
        return out_shape, out_signature

    reduced_axes = set(int(v) for v in normalized_axes)
    out_shape = [int(in_shape[idx]) for idx in range(rank) if idx not in reduced_axes]
    out_signature = [int(in_signature[idx]) for idx in range(rank) if idx not in reduced_axes]
    return out_shape, out_signature


def _parse_axes_option(raw_axes: Any) -> List[int]:
    if raw_axes is None:
        return []
    if isinstance(raw_axes, (list, tuple, np.ndarray)):
        return [int(v) for v in list(raw_axes)]
    return [int(raw_axes)]


def _normalize_squeeze_axes_for_rank(
    axes: List[int],
    rank: int,
) -> Optional[List[int]]:
    normalized: List[int] = []
    for axis in list(axes):
        a = int(axis)
        if a < 0:
            a += int(rank)
        if a < 0 or a >= int(rank):
            return None
        if int(a) not in normalized:
            normalized.append(int(a))
    return normalized


def _infer_squeeze_output_shape_and_signature(
    *,
    input_shape: Optional[List[int]],
    input_signature: Optional[List[int]],
    squeeze_axes: Optional[List[int]],
) -> Tuple[Optional[List[int]], Optional[List[int]]]:
    if input_shape is None:
        return None, None
    in_shape = [int(v) for v in list(input_shape)]
    rank = len(in_shape)
    if input_signature is not None and len(list(input_signature)) == rank:
        in_signature = [int(v) for v in list(input_signature)]
    else:
        in_signature = [int(v) for v in list(in_shape)]

    axes_list = [int(v) for v in list(squeeze_axes)] if squeeze_axes is not None else []
    normalized_axes = _normalize_squeeze_axes_for_rank(axes_list, rank)
    if normalized_axes is None:
        return None, None
    if len(normalized_axes) == 0:
        normalized_axes = [
            int(idx)
            for idx in range(rank)
            if idx < len(in_signature) and int(in_signature[idx]) == 1
        ]
        if len(normalized_axes) == 0:
            normalized_axes = [
                int(idx)
                for idx, dim in enumerate(in_shape)
                if int(dim) == 1
            ]

    remove_axes = set(int(v) for v in normalized_axes)
    out_shape = [int(in_shape[idx]) for idx in range(rank) if idx not in remove_axes]
    out_signature = [int(in_signature[idx]) for idx in range(rank) if idx not in remove_axes]
    return out_shape, out_signature


def _infer_conv_out_dim(
    in_size: int,
    kernel_size: int,
    stride: int,
    dilation: int,
    padding: str,
) -> Optional[int]:
    if any(int(v) <= 0 for v in [in_size, kernel_size, stride, dilation]):
        return None
    effective_kernel = int((int(kernel_size) - 1) * int(dilation) + 1)
    mode = str(padding).upper()
    if mode == "SAME":
        return int((int(in_size) + int(stride) - 1) // int(stride))
    if mode == "VALID":
        return int((int(in_size) - int(effective_kernel)) // int(stride) + 1)
    return None


def _reconcile_static_tensor_shapes(model_ir: ModelIR) -> Dict[str, int]:
    """
    Recompute static tensor shapes after aggressive graph rewrites.

    Some transpose-bridge optimizations intentionally relax local shape guards and can
    leave stale static metadata. This pass performs a conservative forward fixed-point
    shape propagation and syncs `shape` / `shape_signature` for common TFLite ops.
    """
    updated_tensors = 0

    def _update_tensor_shape(
        tensor_name: str,
        new_shape: Optional[List[int]],
        new_shape_signature: Optional[List[int]] = None,
    ) -> bool:
        nonlocal updated_tensors
        if new_shape is None:
            return False
        if not _is_fully_known_positive_shape(new_shape):
            return False
        tensor = model_ir.tensors.get(tensor_name, None)
        if tensor is None:
            return False
        normalized = [int(v) for v in list(new_shape)]
        if new_shape_signature is not None and len(list(new_shape_signature)) == len(normalized):
            signature = [int(v) for v in list(new_shape_signature)]
        else:
            existing_signature = (
                list(tensor.shape_signature)
                if tensor.shape_signature is not None and len(list(tensor.shape_signature)) == len(normalized)
                else None
            )
            if existing_signature is None:
                signature = [int(v) for v in list(normalized)]
            else:
                # Preserve unknown dims inferred upstream to avoid collapsing dynamic axes
                # into placeholder static 1s during conservative shape reconciliation.
                signature = [
                    int(existing_signature[idx]) if int(existing_signature[idx]) < 0 else int(normalized[idx])
                    for idx in range(len(normalized))
                ]
        if tensor.shape == normalized and tensor.shape_signature == signature:
            return False
        tensor.shape = normalized
        tensor.shape_signature = signature
        updated_tensors += 1
        return True

    max_passes = 32
    for _ in range(max_passes):
        changed = False
        for op in model_ir.operators:
            op_type = str(op.op_type)
            inputs = [str(v) for v in list(op.inputs)]
            outputs = [str(v) for v in list(op.outputs)]
            if len(outputs) == 0:
                continue

            # Pass-through ops: output shape == first input shape.
            if op_type in {"QUANTIZE", "DEQUANTIZE", "SOFTMAX", "LOGISTIC", "TANH", "RELU", "RELU6", "PRELU", "CAST", "NEG"}:
                if len(inputs) >= 1:
                    in_tensor = model_ir.tensors.get(inputs[0], None)
                    if in_tensor is not None and _is_fully_known_positive_shape(in_tensor.shape):
                        in_signature = (
                            list(in_tensor.shape_signature)
                            if in_tensor.shape_signature is not None
                            else list(in_tensor.shape)
                        )
                        changed |= _update_tensor_shape(
                            outputs[0],
                            list(in_tensor.shape),
                            in_signature,
                        )
                continue

            if op_type == "TRANSPOSE" and len(inputs) >= 2 and len(outputs) == 1:
                in_tensor = model_ir.tensors.get(inputs[0], None)
                out_tensor = model_ir.tensors.get(outputs[0], None)
                perm_tensor = model_ir.tensors.get(inputs[1], None)
                perm = _read_const_ints_from_tensor(perm_tensor)
                if perm is None:
                    continue
                perm = [int(v) for v in perm]
                if in_tensor is not None and _is_fully_known_positive_shape(in_tensor.shape):
                    out_shape = _permute_shape(list(in_tensor.shape), perm)
                    in_signature = (
                        list(in_tensor.shape_signature)
                        if in_tensor.shape_signature is not None
                        else list(in_tensor.shape)
                    )
                    out_signature = _permute_shape(in_signature, perm)
                    changed |= _update_tensor_shape(
                        outputs[0],
                        out_shape,
                        out_signature,
                    )
                if out_tensor is not None and _is_fully_known_positive_shape(out_tensor.shape):
                    inv_perm = _invert_perm(perm)
                    if inv_perm is not None:
                        in_shape = _permute_shape(list(out_tensor.shape), inv_perm)
                        out_signature = (
                            list(out_tensor.shape_signature)
                            if out_tensor.shape_signature is not None
                            else list(out_tensor.shape)
                        )
                        in_signature = _permute_shape(out_signature, inv_perm)
                        changed |= _update_tensor_shape(
                            inputs[0],
                            in_shape,
                            in_signature,
                        )
                continue

            if op_type in {"BIDIRECTIONAL_SEQUENCE_LSTM", "UNIDIRECTIONAL_SEQUENCE_LSTM"} \
                and len(inputs) >= 1 and len(outputs) == 1:
                input_tensor = model_ir.tensors.get(inputs[0], None)
                output_tensor = model_ir.tensors.get(outputs[0], None)
                if (
                    input_tensor is None
                    or output_tensor is None
                    or len(list(input_tensor.shape)) != 3
                    or len(list(output_tensor.shape)) != 3
                    or not _is_fully_known_positive_shape(list(input_tensor.shape))
                ):
                    continue
                input_shape = [int(v) for v in list(input_tensor.shape)]
                input_signature = (
                    [int(v) for v in list(input_tensor.shape_signature)]
                    if input_tensor.shape_signature is not None
                    else list(input_shape)
                )
                output_shape = [int(v) for v in list(output_tensor.shape)]
                output_signature_existing = (
                    [int(v) for v in list(output_tensor.shape_signature)]
                    if output_tensor.shape_signature is not None
                    else list(output_shape)
                )
                time_major = bool(op.options.get("timeMajor", True))
                if time_major:
                    inferred_output_shape = [int(input_shape[0]), int(input_shape[1]), int(output_shape[2])]
                    inferred_output_signature = [
                        int(input_signature[0]),
                        int(input_signature[1]),
                        int(output_signature_existing[2]),
                    ]
                else:
                    inferred_output_shape = [int(input_shape[1]), int(input_shape[0]), int(output_shape[2])]
                    inferred_output_signature = [
                        int(input_signature[1]),
                        int(input_signature[0]),
                        int(output_signature_existing[2]),
                    ]
                changed |= _update_tensor_shape(
                    outputs[0],
                    inferred_output_shape,
                    inferred_output_signature,
                )
                continue

            if op_type == "SPLIT" and len(inputs) >= 2 and len(outputs) >= 1:
                axis_tensor = model_ir.tensors.get(inputs[0], None)
                input_tensor = model_ir.tensors.get(inputs[1], None)
                axis_values = _read_const_ints_from_tensor(axis_tensor)
                if (
                    axis_values is None
                    or len(axis_values) == 0
                    or input_tensor is None
                    or not _is_fully_known_positive_shape(list(input_tensor.shape))
                ):
                    continue
                input_shape = [int(v) for v in list(input_tensor.shape)]
                rank = len(input_shape)
                axis = int(axis_values[0])
                if axis < 0:
                    axis += rank
                if axis < 0 or axis >= rank:
                    continue
                num_splits = int(op.options.get("numSplits", len(outputs)))
                if num_splits <= 0 or len(outputs) != num_splits:
                    continue
                if int(input_shape[axis]) % num_splits != 0:
                    continue
                split_dim = int(input_shape[axis] // num_splits)
                input_signature = (
                    [int(v) for v in list(input_tensor.shape_signature)]
                    if input_tensor.shape_signature is not None
                    else list(input_shape)
                )
                split_signature_dim = -1
                if axis < len(input_signature):
                    sig_dim = int(input_signature[axis])
                    if sig_dim > 0 and sig_dim % num_splits == 0:
                        split_signature_dim = int(sig_dim // num_splits)
                for output_name in outputs:
                    out_shape = [int(v) for v in list(input_shape)]
                    out_shape[axis] = int(split_dim)
                    out_signature = [int(v) for v in list(input_signature)]
                    out_signature[axis] = int(split_signature_dim if split_signature_dim > 0 else -1)
                    changed |= _update_tensor_shape(
                        output_name,
                        out_shape,
                        out_signature,
                    )
                continue

            if op_type == "EXPAND_DIMS" and len(inputs) >= 2 and len(outputs) == 1:
                input_tensor = model_ir.tensors.get(inputs[0], None)
                axis_tensor = model_ir.tensors.get(inputs[1], None)
                axis_values = _read_const_ints_from_tensor(axis_tensor)
                if (
                    input_tensor is None
                    or axis_values is None
                    or len(axis_values) == 0
                    or not _is_fully_known_positive_shape(list(input_tensor.shape))
                ):
                    continue
                input_shape = [int(v) for v in list(input_tensor.shape)]
                input_signature = (
                    [int(v) for v in list(input_tensor.shape_signature)]
                    if input_tensor.shape_signature is not None
                    else list(input_shape)
                )
                out_rank = len(input_shape) + 1
                axis = int(axis_values[0])
                if axis < 0:
                    axis += out_rank
                if axis < 0 or axis >= out_rank:
                    continue
                out_shape = [int(v) for v in list(input_shape)]
                out_signature = [int(v) for v in list(input_signature)]
                out_shape.insert(axis, 1)
                out_signature.insert(axis, 1)
                changed |= _update_tensor_shape(
                    outputs[0],
                    out_shape,
                    out_signature,
                )
                continue

            if op_type in {"ADD", "SUB", "MUL", "DIV", "FLOOR_MOD", "MAXIMUM", "MINIMUM"} and len(inputs) >= 2 and len(outputs) == 1:
                in0 = model_ir.tensors.get(inputs[0], None)
                in1 = model_ir.tensors.get(inputs[1], None)
                shape0 = list(in0.shape) if in0 is not None else None
                shape1 = list(in1.shape) if in1 is not None else None
                sig0 = (
                    list(in0.shape_signature)
                    if in0 is not None and in0.shape_signature is not None
                    else (list(shape0) if shape0 is not None else None)
                )
                sig1 = (
                    list(in1.shape_signature)
                    if in1 is not None and in1.shape_signature is not None
                    else (list(shape1) if shape1 is not None else None)
                )
                out_shape = _broadcast_static_shapes(shape0, shape1)
                out_signature = _broadcast_shape_signatures(sig0, sig1)
                if out_shape is not None:
                    changed |= _update_tensor_shape(outputs[0], out_shape, out_signature)
                continue

            if op_type == "BATCH_MATMUL" and len(inputs) >= 2 and len(outputs) == 1:
                in0 = model_ir.tensors.get(inputs[0], None)
                in1 = model_ir.tensors.get(inputs[1], None)
                shape0 = list(in0.shape) if in0 is not None else None
                shape1 = list(in1.shape) if in1 is not None else None
                sig0 = (
                    list(in0.shape_signature)
                    if in0 is not None and in0.shape_signature is not None
                    else (list(shape0) if shape0 is not None else None)
                )
                sig1 = (
                    list(in1.shape_signature)
                    if in1 is not None and in1.shape_signature is not None
                    else (list(shape1) if shape1 is not None else None)
                )
                out_shape, out_signature = _infer_batch_matmul_output_shape_and_signature(
                    shape_a=shape0,
                    shape_b=shape1,
                    signature_a=sig0,
                    signature_b=sig1,
                    adj_x=bool(op.options.get("adjX", False)),
                    adj_y=bool(op.options.get("adjY", False)),
                )
                if out_shape is not None:
                    changed |= _update_tensor_shape(outputs[0], out_shape, out_signature)
                continue

            if op_type == "CONCATENATION" and len(inputs) >= 1 and len(outputs) == 1:
                axis = op.options.get("axis", None)
                if axis is None:
                    continue
                in_shapes: List[List[int]] = []
                in_signatures: List[List[int]] = []
                ranks: List[int] = []
                valid = True
                for input_name in inputs:
                    t = model_ir.tensors.get(input_name, None)
                    if t is None or not _is_fully_known_positive_shape(t.shape):
                        valid = False
                        break
                    shape = [int(v) for v in list(t.shape)]
                    in_shapes.append(shape)
                    in_signatures.append(
                        [int(v) for v in list(t.shape_signature)]
                        if t.shape_signature is not None
                        else list(shape)
                    )
                    ranks.append(len(shape))
                if not valid or len(in_shapes) == 0 or len(set(ranks)) != 1:
                    continue
                rank = int(ranks[0])
                axis_new = int(axis)
                if axis_new < 0:
                    axis_new += rank
                if axis_new < 0 or axis_new >= rank:
                    continue
                out_shape = list(in_shapes[0])
                compatible = True
                for shape in in_shapes[1:]:
                    for dim_idx in range(rank):
                        if dim_idx == axis_new:
                            continue
                        if int(shape[dim_idx]) != int(out_shape[dim_idx]):
                            compatible = False
                            break
                    if not compatible:
                        break
                    out_shape[axis_new] += int(shape[axis_new])
                if compatible:
                    out_signature = [int(v) for v in list(out_shape)]
                    if len(in_signatures) == len(in_shapes):
                        for dim_idx in range(rank):
                            dim_values = [int(sig[dim_idx]) for sig in in_signatures]
                            if dim_idx == axis_new:
                                if any(int(v) < 0 for v in dim_values):
                                    out_signature[dim_idx] = -1
                                else:
                                    out_signature[dim_idx] = int(sum(int(v) for v in dim_values))
                            else:
                                if any(int(v) < 0 for v in dim_values):
                                    out_signature[dim_idx] = -1
                    changed |= _update_tensor_shape(outputs[0], out_shape, out_signature)
                continue

            if op_type == "RESHAPE" and len(inputs) >= 1 and len(outputs) == 1:
                input_tensor = model_ir.tensors.get(inputs[0], None)
                if input_tensor is None:
                    continue
                input_signature = (
                    list(input_tensor.shape_signature)
                    if input_tensor.shape_signature is not None
                    else list(input_tensor.shape)
                )
                raw_new_shape = op.options.get("newShape", [])
                try:
                    new_shape = [int(v) for v in np.asarray(raw_new_shape).reshape(-1).tolist()]
                except Exception:
                    new_shape = []
                resolved = _resolve_reshape_new_shape_from_static_input(
                    new_shape=new_shape,
                    input_signature=input_signature,
                    allow_zero=(
                        bool(op.options.get("allowZero"))
                        if "allowZero" in op.options
                        else None
                    ),
                )
                if resolved is not None and _is_fully_known_positive_shape(resolved):
                    changed |= _update_tensor_shape(outputs[0], resolved)
                continue

            if op_type == "SQUEEZE" and len(inputs) >= 1 and len(outputs) == 1:
                input_tensor = model_ir.tensors.get(inputs[0], None)
                if input_tensor is None or not _is_fully_known_positive_shape(input_tensor.shape):
                    continue
                raw_axes = op.options.get("squeezeDims", [])
                squeeze_axes = _parse_axes_option(raw_axes)
                input_signature = (
                    list(input_tensor.shape_signature)
                    if input_tensor.shape_signature is not None
                    else list(input_tensor.shape)
                )
                out_shape, out_signature = _infer_squeeze_output_shape_and_signature(
                    input_shape=list(input_tensor.shape),
                    input_signature=input_signature,
                    squeeze_axes=squeeze_axes,
                )
                if out_shape is None or not _is_fully_known_positive_shape(out_shape):
                    continue
                changed |= _update_tensor_shape(
                    outputs[0],
                    out_shape,
                    out_signature,
                )
                continue

            if op_type == "MEAN" and len(inputs) >= 2 and len(outputs) == 1:
                input_tensor = model_ir.tensors.get(inputs[0], None)
                axes_tensor = model_ir.tensors.get(inputs[1], None)
                if input_tensor is None or not _is_fully_known_positive_shape(input_tensor.shape):
                    continue
                axes_vals = _read_const_ints_from_tensor(axes_tensor)
                keep_dims = bool(op.options.get("keepDims", False))
                input_signature = (
                    list(input_tensor.shape_signature)
                    if input_tensor.shape_signature is not None
                    else list(input_tensor.shape)
                )
                out_shape, out_signature = _infer_reduce_output_shape_and_signature(
                    input_shape=list(input_tensor.shape),
                    input_signature=input_signature,
                    axes=axes_vals,
                    keep_dims=keep_dims,
                )
                if out_shape is None or not _is_fully_known_positive_shape(out_shape):
                    continue
                changed |= _update_tensor_shape(
                    outputs[0],
                    out_shape,
                    out_signature,
                )
                continue

            if op_type == "SLICE" and len(inputs) >= 3 and len(outputs) == 1:
                input_tensor = model_ir.tensors.get(inputs[0], None)
                begin_tensor = model_ir.tensors.get(inputs[1], None)
                size_tensor = model_ir.tensors.get(inputs[2], None)
                if input_tensor is None:
                    continue
                begin_vals = _read_const_ints_from_tensor(begin_tensor)
                size_vals = _read_const_ints_from_tensor(size_tensor)
                out_shape, resolved_begin, resolved_size = _infer_slice_output_shape_and_resolved_params(
                    input_shape=list(input_tensor.shape),
                    begin_vals=begin_vals,
                    size_vals=size_vals,
                )
                if out_shape is None or resolved_begin is None or resolved_size is None:
                    continue
                changed |= _update_tensor_shape(outputs[0], out_shape)
                changed |= _write_const_ints_to_tensor(begin_tensor, resolved_begin)
                changed |= _write_const_ints_to_tensor(size_tensor, resolved_size)
                continue

            if op_type in {"CONV_2D", "DEPTHWISE_CONV_2D"} and len(inputs) >= 2 and len(outputs) == 1:
                in_tensor = model_ir.tensors.get(inputs[0], None)
                filter_tensor = model_ir.tensors.get(inputs[1], None)
                out_tensor = model_ir.tensors.get(outputs[0], None)
                if (
                    in_tensor is None
                    or filter_tensor is None
                    or not _is_fully_known_positive_shape(in_tensor.shape)
                    or not _is_fully_known_positive_shape(filter_tensor.shape)
                ):
                    continue
                in_shape = [int(v) for v in list(in_tensor.shape)]
                filter_shape = [int(v) for v in list(filter_tensor.shape)]
                if len(in_shape) != 4 or len(filter_shape) != 4:
                    continue
                padding = str(op.options.get("padding", "SAME"))
                stride_h = int(op.options.get("strideH", 1))
                stride_w = int(op.options.get("strideW", 1))
                dilation_h = int(op.options.get("dilationHFactor", 1))
                dilation_w = int(op.options.get("dilationWFactor", 1))
                kernel_h = int(filter_shape[1])
                kernel_w = int(filter_shape[2])
                out_h = _infer_conv_out_dim(in_shape[1], kernel_h, stride_h, dilation_h, padding)
                out_w = _infer_conv_out_dim(in_shape[2], kernel_w, stride_w, dilation_w, padding)
                if out_h is None or out_w is None or int(out_h) <= 0 or int(out_w) <= 0:
                    continue
                if op_type == "CONV_2D":
                    out_c = int(filter_shape[0])
                else:
                    # TFLite depthwise filter layout: [1, KH, KW, OC]
                    out_c = int(filter_shape[3])
                out_shape = [int(in_shape[0]), int(out_h), int(out_w), int(out_c)]
                input_signature = (
                    list(in_tensor.shape_signature)
                    if in_tensor.shape_signature is not None
                    else list(in_shape)
                )
                existing_out_signature = (
                    list(out_tensor.shape_signature)
                    if out_tensor is not None and out_tensor.shape_signature is not None
                    else None
                )
                out_signature = _infer_rank4_signature_from_input(
                    input_signature=input_signature,
                    output_shape=out_shape,
                    existing_output_signature=existing_out_signature,
                    propagate_channel=False,
                )
                changed |= _update_tensor_shape(outputs[0], out_shape, out_signature)
                continue

            if op_type in {"AVERAGE_POOL_2D", "MAX_POOL_2D"} and len(inputs) >= 1 and len(outputs) == 1:
                in_tensor = model_ir.tensors.get(inputs[0], None)
                out_tensor = model_ir.tensors.get(outputs[0], None)
                if in_tensor is None or not _is_fully_known_positive_shape(in_tensor.shape):
                    continue
                in_shape = [int(v) for v in list(in_tensor.shape)]
                if len(in_shape) != 4:
                    continue

                padding = str(op.options.get("padding", "SAME")).upper()
                stride_h = int(op.options.get("strideH", 1))
                stride_w = int(op.options.get("strideW", 1))
                filter_h = int(op.options.get("filterHeight", 1))
                filter_w = int(op.options.get("filterWidth", 1))

                out_h = _infer_conv_out_dim(in_shape[1], filter_h, stride_h, 1, padding)
                out_w = _infer_conv_out_dim(in_shape[2], filter_w, stride_w, 1, padding)

                # GlobalAveragePool lowering can become stale after aggressive transpose/layout
                # rewrites. Recover invalid VALID+stride=1 average-pool metadata by snapping
                # pool kernel to the current input spatial size.
                if (
                    op_type == "AVERAGE_POOL_2D"
                    and (out_h is None or out_w is None or int(out_h) <= 0 or int(out_w) <= 0)
                    and padding == "VALID"
                    and int(stride_h) == 1
                    and int(stride_w) == 1
                ):
                    if int(filter_h) > int(in_shape[1]) or int(filter_w) > int(in_shape[2]):
                        filter_h = int(in_shape[1])
                        filter_w = int(in_shape[2])
                        op.options["filterHeight"] = int(filter_h)
                        op.options["filterWidth"] = int(filter_w)
                        out_h = _infer_conv_out_dim(in_shape[1], filter_h, stride_h, 1, padding)
                        out_w = _infer_conv_out_dim(in_shape[2], filter_w, stride_w, 1, padding)

                if out_h is None or out_w is None or int(out_h) <= 0 or int(out_w) <= 0:
                    continue
                out_shape = [int(in_shape[0]), int(out_h), int(out_w), int(in_shape[3])]
                input_signature = (
                    list(in_tensor.shape_signature)
                    if in_tensor.shape_signature is not None
                    else list(in_shape)
                )
                existing_out_signature = (
                    list(out_tensor.shape_signature)
                    if out_tensor is not None and out_tensor.shape_signature is not None
                    else None
                )
                out_signature = _infer_rank4_signature_from_input(
                    input_signature=input_signature,
                    output_shape=out_shape,
                    existing_output_signature=existing_out_signature,
                    propagate_channel=True,
                )
                changed |= _update_tensor_shape(outputs[0], out_shape, out_signature)
                continue

            if op_type in {"RESIZE_BILINEAR", "RESIZE_NEAREST_NEIGHBOR"} and len(inputs) >= 2 and len(outputs) == 1:
                in_tensor = model_ir.tensors.get(inputs[0], None)
                size_tensor = model_ir.tensors.get(inputs[1], None)
                out_tensor = model_ir.tensors.get(outputs[0], None)
                if in_tensor is None or not _is_fully_known_positive_shape(in_tensor.shape):
                    continue
                in_shape = [int(v) for v in list(in_tensor.shape)]
                if len(in_shape) != 4:
                    continue

                out_h = None
                out_w = None
                size_source = "unknown"
                size_vals = _read_const_ints_from_tensor(size_tensor)
                size_tensor_is_const = bool(size_tensor is not None and size_tensor.data is not None)
                onnx_sizes_hw = op.options.get("onnxSizesHW", None)
                if isinstance(onnx_sizes_hw, (list, tuple)) and len(onnx_sizes_hw) >= 2:
                    try:
                        out_h = int(onnx_sizes_hw[0])
                        out_w = int(onnx_sizes_hw[1])
                        size_source = "onnx_sizes"
                    except Exception:
                        out_h = None
                        out_w = None
                        size_source = "unknown"
                if out_h is None or out_w is None:
                    onnx_scales_hw = op.options.get("onnxScalesHW", None)
                    if isinstance(onnx_scales_hw, (list, tuple)) and len(onnx_scales_hw) >= 2:
                        try:
                            out_h = int(round(float(in_shape[1]) * float(onnx_scales_hw[0])))
                            out_w = int(round(float(in_shape[2]) * float(onnx_scales_hw[1])))
                            size_source = "onnx_scales"
                        except Exception:
                            out_h = None
                            out_w = None
                            size_source = "unknown"
                if out_h is None or out_w is None:
                    if size_vals is None or len(size_vals) < 2:
                        continue
                    out_h = int(size_vals[0])
                    out_w = int(size_vals[1])
                    size_source = "const_size"
                if out_h <= 0 or out_w <= 0:
                    continue
                # Synchronize resize-size constants with ONNX-derived hints so downstream
                # prepare-time shape inference follows the reconciled NHWC metadata.
                if size_tensor_is_const and size_source in {"onnx_sizes", "onnx_scales"}:
                    changed |= _write_const_ints_to_tensor(size_tensor, [int(out_h), int(out_w)])
                out_shape = [int(in_shape[0]), int(out_h), int(out_w), int(in_shape[3])]
                input_signature = (
                    list(in_tensor.shape_signature)
                    if in_tensor.shape_signature is not None
                    else list(in_shape)
                )
                existing_out_signature = (
                    list(out_tensor.shape_signature)
                    if out_tensor is not None and out_tensor.shape_signature is not None
                    else None
                )
                out_signature = _infer_rank4_signature_from_input(
                    input_signature=input_signature,
                    output_shape=out_shape,
                    existing_output_signature=existing_out_signature,
                    propagate_channel=True,
                )
                if len(out_signature) == 4 and len(input_signature) == 4 and size_source == "onnx_scales":
                    if int(input_signature[1]) < 0:
                        out_signature[1] = -1
                    if int(input_signature[2]) < 0:
                        out_signature[2] = -1
                changed |= _update_tensor_shape(outputs[0], out_shape, out_signature)
                continue

        if not changed:
            break

    return {"reconciled_static_tensor_shapes": int(updated_tensors)}


def _optimize_transpose_quant_dequant_bridges(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose-quantize/dequantize-transpose bridges when both transposes cancel.

    Target patterns:
      X --Transpose(P)--> A --QUANTIZE--> B --Transpose(inv(P))--> Y
      X --Transpose(P)--> A --DEQUANTIZE--> B --Transpose(inv(P))--> Y

    This is safe for per-tensor quantization only.
    """
    removed_bridge_pairs = 0

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)

        # Pattern A:
        #   X -T(P)-> A -Q-> B -DQ-> C -T(invP)-> Y
        # -> X -Q-> B -DQ-> Y
        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            bridge_a = pre_op.outputs[0]
            q_users = consumers.get(bridge_a, [])
            if len(q_users) != 1:
                continue
            q_idx = int(q_users[0])
            q_op = model_ir.operators[q_idx]
            if str(q_op.op_type) != "QUANTIZE" or len(q_op.inputs) != 1 or len(q_op.outputs) != 1:
                continue
            if q_op.inputs[0] != bridge_a:
                continue

            bridge_b = q_op.outputs[0]
            dq_users = consumers.get(bridge_b, [])
            if len(dq_users) != 1:
                continue
            dq_idx = int(dq_users[0])
            dq_op = model_ir.operators[dq_idx]
            if str(dq_op.op_type) != "DEQUANTIZE" or len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                continue
            if dq_op.inputs[0] != bridge_b:
                continue

            bridge_c = dq_op.outputs[0]
            post_users = consumers.get(bridge_c, [])
            if len(post_users) != 1:
                continue
            post_idx = int(post_users[0])
            post_op = model_ir.operators[post_idx]
            if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                continue
            if post_op.inputs[0] != bridge_c:
                continue

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            perm_post = _read_transpose_perm(model_ir, post_op)
            if perm_pre is None or perm_post is None:
                continue
            if not _is_inverse_perm(perm_pre, perm_post):
                continue

            q_out_tensor = model_ir.tensors.get(bridge_b, None)
            if q_out_tensor is None or not _is_per_tensor_quantization(q_out_tensor.quantization):
                continue

            if bridge_a in model_ir.outputs or bridge_b in model_ir.outputs or bridge_c in model_ir.outputs:
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=q_op,
                new_inputs=[pre_op.inputs[0]],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=dq_op,
                new_outputs=[post_op.outputs[0]],
            )

            new_dq_out = model_ir.tensors.get(post_op.outputs[0], None)
            old_dq_out = model_ir.tensors.get(bridge_c, None)
            if new_dq_out is not None and old_dq_out is not None:
                new_dq_out.dtype = str(old_dq_out.dtype)

            for remove_idx in sorted([pre_idx, post_idx], reverse=True):
                del model_ir.operators[remove_idx]
            removed_bridge_pairs += 1
            changed = True
            break

        if changed:
            continue

        # Pattern B:
        #   X -T(P)-> A -(Q|DQ)-> B -T(invP)-> Y
        # -> X -(Q|DQ)-> Y
        for mid_idx, mid_op in enumerate(model_ir.operators):
            if str(mid_op.op_type) not in {"QUANTIZE", "DEQUANTIZE"}:
                continue
            if len(mid_op.inputs) != 1 or len(mid_op.outputs) != 1:
                continue

            bridge_in = mid_op.inputs[0]
            bridge_out = mid_op.outputs[0]

            pre_idx = producers.get(bridge_in, None)
            if pre_idx is None:
                continue
            pre_op = model_ir.operators[pre_idx]
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.outputs) != 1 or len(pre_op.inputs) < 2:
                continue
            if pre_op.outputs[0] != bridge_in:
                continue
            in_users = set(consumers.get(bridge_in, []))
            if int(mid_idx) not in in_users:
                continue
            can_remove_pre = in_users == {int(mid_idx)}

            post_users = [int(v) for v in consumers.get(bridge_out, []) if int(v) != int(mid_idx)]
            if len(post_users) == 0:
                continue

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue

            post_indices: List[int] = []
            post_output_names: List[str] = []
            valid_posts = True
            for post_idx in post_users:
                post_op = model_ir.operators[int(post_idx)]
                if (
                    str(post_op.op_type) != "TRANSPOSE"
                    or len(post_op.inputs) < 2
                    or len(post_op.outputs) != 1
                    or post_op.inputs[0] != bridge_out
                ):
                    valid_posts = False
                    break
                perm_post = _read_transpose_perm(model_ir, post_op)
                if perm_post is None or not _is_inverse_perm(perm_pre, perm_post):
                    valid_posts = False
                    break
                post_indices.append(int(post_idx))
                post_output_names.append(str(post_op.outputs[0]))
            if not valid_posts or len(post_indices) == 0:
                continue

            # Keep visible output names stable.
            if bridge_out in model_ir.outputs:
                continue
            if can_remove_pre and bridge_in in model_ir.outputs:
                continue
            single_post = len(post_indices) == 1
            if (not single_post) and any(
                post_output_name in model_ir.outputs for post_output_name in post_output_names
            ):
                continue

            pre_input_name = pre_op.inputs[0]
            representative_post_output_name = post_output_names[0]

            if str(mid_op.op_type) == "QUANTIZE":
                bridge_out_tensor = model_ir.tensors.get(bridge_out, None)
                if bridge_out_tensor is None:
                    continue
                if not _is_per_tensor_quantization(bridge_out_tensor.quantization):
                    continue
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=mid_op,
                    new_inputs=[pre_input_name],
                )
                if single_post:
                    post_output_name = representative_post_output_name
                    _set_operator_outputs(
                        model_ir=model_ir,
                        op=mid_op,
                        new_outputs=[post_output_name],
                    )
                    post_output_tensor = model_ir.tensors.get(post_output_name, None)
                    if post_output_tensor is not None:
                        post_output_tensor.dtype = str(bridge_out_tensor.dtype)
                        post_output_tensor.quantization = _clone_quantization(
                            bridge_out_tensor.quantization
                        )
                else:
                    rep_post_tensor = model_ir.tensors.get(representative_post_output_name, None)
                    if rep_post_tensor is not None:
                        bridge_out_tensor.shape = list(rep_post_tensor.shape)
                        bridge_out_tensor.shape_signature = (
                            list(rep_post_tensor.shape_signature)
                            if rep_post_tensor.shape_signature is not None
                            else list(rep_post_tensor.shape)
                        )
                        bridge_out_tensor.dtype = str(rep_post_tensor.dtype)
                    bridge_out_tensor.quantization = _clone_quantization(
                        bridge_out_tensor.quantization
                    )
            else:
                bridge_in_tensor = model_ir.tensors.get(bridge_in, None)
                if bridge_in_tensor is None:
                    continue
                if not _is_per_tensor_quantization(bridge_in_tensor.quantization):
                    continue
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=mid_op,
                    new_inputs=[pre_input_name],
                )
                if single_post:
                    post_output_name = representative_post_output_name
                    _set_operator_outputs(
                        model_ir=model_ir,
                        op=mid_op,
                        new_outputs=[post_output_name],
                    )
                    pre_input_tensor = model_ir.tensors.get(pre_input_name, None)
                    if pre_input_tensor is not None and pre_input_tensor.quantization is None:
                        pre_input_tensor.quantization = _clone_quantization(
                            bridge_in_tensor.quantization
                        )
                    post_output_tensor = model_ir.tensors.get(post_output_name, None)
                    bridge_out_tensor = model_ir.tensors.get(bridge_out, None)
                    if post_output_tensor is not None and bridge_out_tensor is not None:
                        post_output_tensor.dtype = str(bridge_out_tensor.dtype)
                else:
                    pre_input_tensor = model_ir.tensors.get(pre_input_name, None)
                    if pre_input_tensor is not None and pre_input_tensor.quantization is None:
                        pre_input_tensor.quantization = _clone_quantization(
                            bridge_in_tensor.quantization
                        )
                    bridge_out_tensor = model_ir.tensors.get(bridge_out, None)
                    rep_post_tensor = model_ir.tensors.get(representative_post_output_name, None)
                    if bridge_out_tensor is not None and rep_post_tensor is not None:
                        bridge_out_tensor.shape = list(rep_post_tensor.shape)
                        bridge_out_tensor.shape_signature = (
                            list(rep_post_tensor.shape_signature)
                            if rep_post_tensor.shape_signature is not None
                            else list(rep_post_tensor.shape)
                        )
                        bridge_out_tensor.dtype = str(rep_post_tensor.dtype)

            if not single_post:
                for post_output_name in post_output_names:
                    _replace_tensor_inputs(model_ir, post_output_name, bridge_out)

            remove_indices = list(post_indices)
            if can_remove_pre:
                remove_indices.append(pre_idx)
            for remove_idx in sorted(remove_indices, reverse=True):
                del model_ir.operators[remove_idx]
            removed_bridge_pairs += int(1 if single_post else max(1, len(post_indices)))
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "removed_transpose_quantize_dequantize_bridges": int(removed_bridge_pairs),
    }


def _optimize_duplicate_transpose_fanout(model_ir: ModelIR) -> Dict[str, int]:
    """
    Deduplicate fan-out TRANSPOSE nodes with identical input and permutation.

    Target pattern:
      X --TRANSPOSE(P)--> Y0
      X --TRANSPOSE(P)--> Y1
      ...

    Rewritten:
      X --TRANSPOSE(P)--> Y0
      (all uses of Y1, ... are rewired to Y0; duplicate TRANSPOSE nodes removed)
    """
    removed_duplicates = 0

    while True:
        changed = False
        canonical_by_key: Dict[Tuple[str, Tuple[int, ...]], int] = {}

        for op_idx, op in enumerate(model_ir.operators):
            if str(op.op_type) != "TRANSPOSE":
                continue
            if len(op.inputs) < 2 or len(op.outputs) != 1:
                continue

            input_name = str(op.inputs[0])
            output_name = str(op.outputs[0])
            perm = _read_transpose_perm(model_ir, op)
            if perm is None:
                continue

            key = (input_name, tuple(int(v) for v in perm))
            canonical_idx = canonical_by_key.get(key, None)
            if canonical_idx is None:
                canonical_by_key[key] = int(op_idx)
                continue

            if output_name in model_ir.outputs:
                # Preserve user-visible graph output names.
                continue

            canonical_op = model_ir.operators[int(canonical_idx)]
            if len(canonical_op.outputs) != 1:
                continue
            canonical_output = str(canonical_op.outputs[0])
            if canonical_output == output_name:
                continue

            canonical_tensor = model_ir.tensors.get(canonical_output, None)
            duplicate_tensor = model_ir.tensors.get(output_name, None)
            if canonical_tensor is not None and duplicate_tensor is not None:
                if canonical_tensor.shape == [1] and duplicate_tensor.shape != [1]:
                    canonical_tensor.shape = [int(v) for v in list(duplicate_tensor.shape)]
                    canonical_tensor.shape_signature = (
                        [int(v) for v in list(duplicate_tensor.shape_signature)]
                        if duplicate_tensor.shape_signature is not None
                        else [int(v) for v in list(duplicate_tensor.shape)]
                    )
                if canonical_tensor.quantization is None and duplicate_tensor.quantization is not None:
                    canonical_tensor.quantization = _clone_quantization(duplicate_tensor.quantization)
                if str(canonical_tensor.dtype) == "FLOAT32" and str(duplicate_tensor.dtype) != "FLOAT32":
                    canonical_tensor.dtype = str(duplicate_tensor.dtype)

            _replace_tensor_inputs(model_ir, output_name, canonical_output)
            del model_ir.operators[int(op_idx)]
            removed_duplicates += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "removed_duplicate_transpose_fanout": int(removed_duplicates),
    }


def _optimize_transpose_dequant_prelu_quantize_bridges(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose wrappers around DEQUANTIZE->PRELU->QUANTIZE chains.

    Target pattern:
      Xq --Transpose(P)--> Aq --DEQUANTIZE--> A --PRELU(alpha)--> B --QUANTIZE--> Bq --Transpose(inv(P))--> Yq

    Rewritten:
      Xq --DEQUANTIZE--> A --PRELU(alpha')--> B --QUANTIZE--> Yq

    Safety conditions:
    - Chain is linear (single consumer at each bridge tensor)
    - Pre/Post transpose permutations are exact inverses
    - Quantized tensors use per-tensor quantization only
    - PRELU alpha tensor is constant if rank remap is required
    """
    removed_prelu_bridges = 0

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue

            bridge_q_in = str(pre_op.outputs[0])
            dq_users = consumers.get(bridge_q_in, [])
            if len(dq_users) != 1:
                continue
            dq_idx = int(dq_users[0])
            dq_op = model_ir.operators[dq_idx]
            if str(dq_op.op_type) != "DEQUANTIZE" or len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                continue
            if str(dq_op.inputs[0]) != bridge_q_in:
                continue

            bridge_f_in = str(dq_op.outputs[0])
            prelu_users = consumers.get(bridge_f_in, [])
            if len(prelu_users) != 1:
                continue
            prelu_idx = int(prelu_users[0])
            prelu_op = model_ir.operators[prelu_idx]
            if str(prelu_op.op_type) != "PRELU" or len(prelu_op.inputs) != 2 or len(prelu_op.outputs) != 1:
                continue
            if str(prelu_op.inputs[0]) != bridge_f_in:
                continue

            bridge_f_out = str(prelu_op.outputs[0])
            q_users = consumers.get(bridge_f_out, [])
            if len(q_users) != 1:
                continue
            q_idx = int(q_users[0])
            q_op = model_ir.operators[q_idx]
            if str(q_op.op_type) != "QUANTIZE" or len(q_op.inputs) != 1 or len(q_op.outputs) != 1:
                continue
            if str(q_op.inputs[0]) != bridge_f_out:
                continue

            bridge_q_out = str(q_op.outputs[0])
            post_users = consumers.get(bridge_q_out, [])
            if len(post_users) != 1:
                continue
            post_idx = int(post_users[0])
            post_op = model_ir.operators[post_idx]
            if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                continue
            if str(post_op.inputs[0]) != bridge_q_out:
                continue

            perm_post = _read_transpose_perm(model_ir, post_op)
            if perm_post is None or not _is_inverse_perm(perm_pre, perm_post):
                continue

            # Keep user-visible output names stable and avoid breaking observable intermediates.
            if (
                bridge_q_in in model_ir.outputs
                or bridge_f_in in model_ir.outputs
                or bridge_f_out in model_ir.outputs
                or bridge_q_out in model_ir.outputs
            ):
                continue

            q_src_name = str(pre_op.inputs[0])
            q_dst_name = str(post_op.outputs[0])
            if q_src_name in model_ir.outputs:
                continue

            q_src_tensor = model_ir.tensors.get(q_src_name, None)
            q_mid_in_tensor = model_ir.tensors.get(bridge_q_in, None)
            q_mid_out_tensor = model_ir.tensors.get(bridge_q_out, None)
            q_dst_tensor = model_ir.tensors.get(q_dst_name, None)
            if not _all_per_tensor_quantized([q_src_tensor, q_mid_in_tensor, q_mid_out_tensor, q_dst_tensor]):
                continue

            # PRELU alpha layout follows data layout. When alpha rank matches the transposed rank,
            # remap alpha using post permutation so PRELU can run directly on non-transposed data.
            alpha_name = str(prelu_op.inputs[1])
            alpha_tensor = model_ir.tensors.get(alpha_name, None)
            if alpha_tensor is not None and isinstance(alpha_tensor.data, np.ndarray):
                alpha_data = np.asarray(alpha_tensor.data)
                if alpha_data.ndim == len(perm_post):
                    alpha_data = np.transpose(alpha_data, axes=perm_post)
                    alpha_tensor.data = alpha_data
                    alpha_tensor.shape = [int(v) for v in alpha_data.shape]
                    alpha_tensor.shape_signature = [int(v) for v in alpha_data.shape]

            _set_operator_inputs(
                model_ir=model_ir,
                op=dq_op,
                new_inputs=[q_src_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=q_op,
                new_outputs=[q_dst_name],
            )

            # Update bridge tensor metadata to the non-transposed layout.
            q_src_shape = list(q_src_tensor.shape) if q_src_tensor is not None else None
            q_src_signature = (
                list(q_src_tensor.shape_signature)
                if q_src_tensor is not None and q_src_tensor.shape_signature is not None
                else q_src_shape
            )
            if q_src_shape is not None:
                dq_out_tensor = model_ir.tensors.get(bridge_f_in, None)
                prelu_out_tensor = model_ir.tensors.get(bridge_f_out, None)
                if dq_out_tensor is not None:
                    dq_out_tensor.shape = [int(v) for v in q_src_shape]
                    dq_out_tensor.shape_signature = (
                        [int(v) for v in q_src_signature]
                        if q_src_signature is not None
                        else [int(v) for v in q_src_shape]
                    )
                if prelu_out_tensor is not None:
                    prelu_out_tensor.shape = [int(v) for v in q_src_shape]
                    prelu_out_tensor.shape_signature = (
                        [int(v) for v in q_src_signature]
                        if q_src_signature is not None
                        else [int(v) for v in q_src_shape]
                    )

            if q_dst_tensor is not None and q_mid_out_tensor is not None:
                q_dst_tensor.dtype = str(q_mid_out_tensor.dtype)
                q_dst_tensor.quantization = _clone_quantization(q_mid_out_tensor.quantization)

            for remove_idx in sorted([pre_idx, post_idx], reverse=True):
                del model_ir.operators[remove_idx]
            removed_prelu_bridges += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "removed_transpose_dequant_prelu_quantize_bridges": int(removed_prelu_bridges),
    }


def _optimize_transpose_dequant_relu_quantize_bridges(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose wrappers around DEQUANTIZE->(RELU|RELU6)->QUANTIZE chains.

    Target pattern:
      Xq --Transpose(P)--> Aq --DEQUANTIZE--> A --(RELU|RELU6)--> B --QUANTIZE--> Bq --Transpose(inv(P))--> Yq

    Rewritten:
      Xq --DEQUANTIZE--> A --(RELU|RELU6)--> B --QUANTIZE--> Yq

    Safety conditions:
    - Chain is linear (single consumer at each bridge tensor)
    - Pre/Post transpose permutations are exact inverses
    - Quantized tensors use per-tensor quantization only
    """
    removed_relu_bridges = 0

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue

            bridge_q_in = str(pre_op.outputs[0])
            dq_users = consumers.get(bridge_q_in, [])
            if len(dq_users) != 1:
                continue
            dq_idx = int(dq_users[0])
            dq_op = model_ir.operators[dq_idx]
            if str(dq_op.op_type) != "DEQUANTIZE" or len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                continue
            if str(dq_op.inputs[0]) != bridge_q_in:
                continue

            bridge_f_in = str(dq_op.outputs[0])
            relu_users = consumers.get(bridge_f_in, [])
            if len(relu_users) != 1:
                continue
            relu_idx = int(relu_users[0])
            relu_op = model_ir.operators[relu_idx]
            if str(relu_op.op_type) not in {"RELU", "RELU6"} or len(relu_op.inputs) != 1 or len(relu_op.outputs) != 1:
                continue
            if str(relu_op.inputs[0]) != bridge_f_in:
                continue

            bridge_f_out = str(relu_op.outputs[0])
            q_users = consumers.get(bridge_f_out, [])
            if len(q_users) != 1:
                continue
            q_idx = int(q_users[0])
            q_op = model_ir.operators[q_idx]
            if str(q_op.op_type) != "QUANTIZE" or len(q_op.inputs) != 1 or len(q_op.outputs) != 1:
                continue
            if str(q_op.inputs[0]) != bridge_f_out:
                continue

            bridge_q_out = str(q_op.outputs[0])
            post_users = consumers.get(bridge_q_out, [])
            if len(post_users) != 1:
                continue
            post_idx = int(post_users[0])
            post_op = model_ir.operators[post_idx]
            if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                continue
            if str(post_op.inputs[0]) != bridge_q_out:
                continue

            perm_post = _read_transpose_perm(model_ir, post_op)
            if perm_post is None or not _is_inverse_perm(perm_pre, perm_post):
                continue

            # Keep user-visible output names stable and avoid breaking observable intermediates.
            if (
                bridge_q_in in model_ir.outputs
                or bridge_f_in in model_ir.outputs
                or bridge_f_out in model_ir.outputs
                or bridge_q_out in model_ir.outputs
            ):
                continue

            q_src_name = str(pre_op.inputs[0])
            q_dst_name = str(post_op.outputs[0])
            if q_src_name in model_ir.outputs:
                continue

            q_src_tensor = model_ir.tensors.get(q_src_name, None)
            q_mid_in_tensor = model_ir.tensors.get(bridge_q_in, None)
            q_mid_out_tensor = model_ir.tensors.get(bridge_q_out, None)
            q_dst_tensor = model_ir.tensors.get(q_dst_name, None)
            if not _all_per_tensor_quantized([q_src_tensor, q_mid_in_tensor, q_mid_out_tensor, q_dst_tensor]):
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=dq_op,
                new_inputs=[q_src_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=q_op,
                new_outputs=[q_dst_name],
            )

            # Update bridge tensor metadata to the non-transposed layout.
            q_src_shape = list(q_src_tensor.shape) if q_src_tensor is not None else None
            q_src_signature = (
                list(q_src_tensor.shape_signature)
                if q_src_tensor is not None and q_src_tensor.shape_signature is not None
                else q_src_shape
            )
            if q_src_shape is not None:
                dq_out_tensor = model_ir.tensors.get(bridge_f_in, None)
                relu_out_tensor = model_ir.tensors.get(bridge_f_out, None)
                if dq_out_tensor is not None:
                    dq_out_tensor.shape = [int(v) for v in q_src_shape]
                    dq_out_tensor.shape_signature = (
                        [int(v) for v in q_src_signature]
                        if q_src_signature is not None
                        else [int(v) for v in q_src_shape]
                    )
                if relu_out_tensor is not None:
                    relu_out_tensor.shape = [int(v) for v in q_src_shape]
                    relu_out_tensor.shape_signature = (
                        [int(v) for v in q_src_signature]
                        if q_src_signature is not None
                        else [int(v) for v in q_src_shape]
                    )

            if q_dst_tensor is not None and q_mid_out_tensor is not None:
                q_dst_tensor.dtype = str(q_mid_out_tensor.dtype)
                q_dst_tensor.quantization = _clone_quantization(q_mid_out_tensor.quantization)

            for remove_idx in sorted([pre_idx, post_idx], reverse=True):
                del model_ir.operators[remove_idx]
            removed_relu_bridges += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "removed_transpose_dequant_relu_quantize_bridges": int(removed_relu_bridges),
    }


def _optimize_transpose_dequant_mul_add_prelu_quantize_bridges(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose wrappers around DEQUANTIZE->MUL->ADD->PRELU->QUANTIZE chains.

    Target pattern:
      Xq --Transpose(P)--> Aq --DEQUANTIZE--> A --MUL(c1)--> B --ADD(c2)--> C
         --PRELU(alpha)--> D --QUANTIZE--> Dq --Transpose(inv(P))--> Yq

    Rewritten:
      Xq --DEQUANTIZE--> A --MUL(c1')--> B --ADD(c2')--> C --PRELU(alpha')--> D --QUANTIZE--> Yq

    Safety conditions:
    - Chain is linear (single consumer at each bridge tensor)
    - Pre/Post transpose permutations are exact inverses
    - Quantized tensors use per-tensor quantization only
    - Side inputs c1/c2/alpha are constants; rank-matched constants are layout-remapped
    """
    removed_mul_add_prelu_bridges = 0

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue

            bridge_q_in = str(pre_op.outputs[0])
            dq_users = consumers.get(bridge_q_in, [])
            if len(dq_users) != 1:
                continue
            dq_idx = int(dq_users[0])
            dq_op = model_ir.operators[dq_idx]
            if str(dq_op.op_type) != "DEQUANTIZE" or len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                continue
            if str(dq_op.inputs[0]) != bridge_q_in:
                continue

            bridge_f_in = str(dq_op.outputs[0])
            mul_users = consumers.get(bridge_f_in, [])
            if len(mul_users) != 1:
                continue
            mul_idx = int(mul_users[0])
            mul_op = model_ir.operators[mul_idx]
            if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                continue
            mul_in0 = str(mul_op.inputs[0])
            mul_in1 = str(mul_op.inputs[1])
            if mul_in0 == bridge_f_in:
                mul_const_input_index = 1
            elif mul_in1 == bridge_f_in:
                mul_const_input_index = 0
            else:
                continue

            bridge_mul_out = str(mul_op.outputs[0])
            add_users = consumers.get(bridge_mul_out, [])
            if len(add_users) != 1:
                continue
            add_idx = int(add_users[0])
            add_op = model_ir.operators[add_idx]
            if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                continue
            add_in0 = str(add_op.inputs[0])
            add_in1 = str(add_op.inputs[1])
            if add_in0 == bridge_mul_out:
                add_const_input_index = 1
            elif add_in1 == bridge_mul_out:
                add_const_input_index = 0
            else:
                continue

            bridge_add_out = str(add_op.outputs[0])
            prelu_users = consumers.get(bridge_add_out, [])
            if len(prelu_users) != 1:
                continue
            prelu_idx = int(prelu_users[0])
            prelu_op = model_ir.operators[prelu_idx]
            if str(prelu_op.op_type) != "PRELU" or len(prelu_op.inputs) != 2 or len(prelu_op.outputs) != 1:
                continue
            if str(prelu_op.inputs[0]) != bridge_add_out:
                continue

            bridge_prelu_out = str(prelu_op.outputs[0])
            q_users = consumers.get(bridge_prelu_out, [])
            if len(q_users) != 1:
                continue
            q_idx = int(q_users[0])
            q_op = model_ir.operators[q_idx]
            if str(q_op.op_type) != "QUANTIZE" or len(q_op.inputs) != 1 or len(q_op.outputs) != 1:
                continue
            if str(q_op.inputs[0]) != bridge_prelu_out:
                continue

            bridge_q_out = str(q_op.outputs[0])
            post_users = consumers.get(bridge_q_out, [])
            if len(post_users) != 1:
                continue
            post_idx = int(post_users[0])
            post_op = model_ir.operators[post_idx]
            if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                continue
            if str(post_op.inputs[0]) != bridge_q_out:
                continue

            perm_post = _read_transpose_perm(model_ir, post_op)
            if perm_post is None or not _is_inverse_perm(perm_pre, perm_post):
                continue

            # Keep user-visible output names stable and avoid breaking observable intermediates.
            if (
                bridge_q_in in model_ir.outputs
                or bridge_f_in in model_ir.outputs
                or bridge_mul_out in model_ir.outputs
                or bridge_add_out in model_ir.outputs
                or bridge_prelu_out in model_ir.outputs
                or bridge_q_out in model_ir.outputs
            ):
                continue

            q_src_name = str(pre_op.inputs[0])
            q_dst_name = str(post_op.outputs[0])
            if q_src_name in model_ir.outputs:
                continue

            q_src_tensor = model_ir.tensors.get(q_src_name, None)
            q_mid_in_tensor = model_ir.tensors.get(bridge_q_in, None)
            q_mid_out_tensor = model_ir.tensors.get(bridge_q_out, None)
            q_dst_tensor = model_ir.tensors.get(q_dst_name, None)
            if not _all_per_tensor_quantized([q_src_tensor, q_mid_in_tensor, q_mid_out_tensor, q_dst_tensor]):
                continue

            mul_const_name = str(mul_op.inputs[mul_const_input_index])
            add_const_name = str(add_op.inputs[add_const_input_index])
            alpha_name = str(prelu_op.inputs[1])
            mul_const_tensor = model_ir.tensors.get(mul_const_name, None)
            add_const_tensor = model_ir.tensors.get(add_const_name, None)
            alpha_tensor = model_ir.tensors.get(alpha_name, None)
            if (
                mul_const_tensor is None
                or add_const_tensor is None
                or alpha_tensor is None
                or not isinstance(mul_const_tensor.data, np.ndarray)
                or not isinstance(add_const_tensor.data, np.ndarray)
                or not isinstance(alpha_tensor.data, np.ndarray)
            ):
                continue

            def _remap_constant_input_for_op(
                *,
                op: OperatorIR,
                op_idx: int,
                input_index: int,
            ) -> bool:
                const_name = str(op.inputs[input_index])
                const_tensor = model_ir.tensors.get(const_name, None)
                if const_tensor is None or not isinstance(const_tensor.data, np.ndarray):
                    return False
                const_data = np.asarray(const_tensor.data)
                if const_data.ndim != len(perm_post):
                    return True
                transposed_data = np.transpose(const_data, axes=perm_post)
                const_users = consumers.get(const_name, [])
                if len(const_users) == 1 and int(const_users[0]) == int(op_idx):
                    const_tensor.data = np.asarray(transposed_data)
                    const_tensor.shape = [int(v) for v in transposed_data.shape]
                    const_tensor.shape_signature = [int(v) for v in transposed_data.shape]
                    return True
                new_name = _unique_tensor_name(f"{const_name}_nhwc")
                model_ir.tensors[new_name] = TensorIR(
                    name=new_name,
                    dtype=str(const_tensor.dtype),
                    shape=[int(v) for v in transposed_data.shape],
                    shape_signature=[int(v) for v in transposed_data.shape],
                    data=np.asarray(transposed_data),
                    is_variable=False,
                    quantization=_clone_quantization(const_tensor.quantization),
                )
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=op,
                    input_index=int(input_index),
                    new_input_name=new_name,
                )
                return True

            if not _remap_constant_input_for_op(
                op=mul_op,
                op_idx=mul_idx,
                input_index=mul_const_input_index,
            ):
                continue
            if not _remap_constant_input_for_op(
                op=add_op,
                op_idx=add_idx,
                input_index=add_const_input_index,
            ):
                continue
            if not _remap_constant_input_for_op(
                op=prelu_op,
                op_idx=prelu_idx,
                input_index=1,
            ):
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=dq_op,
                new_inputs=[q_src_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=q_op,
                new_outputs=[q_dst_name],
            )

            # Update bridge tensor metadata to the non-transposed layout.
            q_src_shape = list(q_src_tensor.shape) if q_src_tensor is not None else None
            q_src_signature = (
                list(q_src_tensor.shape_signature)
                if q_src_tensor is not None and q_src_tensor.shape_signature is not None
                else q_src_shape
            )
            if q_src_shape is not None:
                dq_out_tensor = model_ir.tensors.get(bridge_f_in, None)
                mul_out_tensor = model_ir.tensors.get(bridge_mul_out, None)
                add_out_tensor = model_ir.tensors.get(bridge_add_out, None)
                prelu_out_tensor = model_ir.tensors.get(bridge_prelu_out, None)
                if dq_out_tensor is not None:
                    dq_out_tensor.shape = [int(v) for v in q_src_shape]
                    dq_out_tensor.shape_signature = (
                        [int(v) for v in q_src_signature]
                        if q_src_signature is not None
                        else [int(v) for v in q_src_shape]
                    )
                if mul_out_tensor is not None:
                    mul_out_tensor.shape = [int(v) for v in q_src_shape]
                    mul_out_tensor.shape_signature = (
                        [int(v) for v in q_src_signature]
                        if q_src_signature is not None
                        else [int(v) for v in q_src_shape]
                    )
                if add_out_tensor is not None:
                    add_out_tensor.shape = [int(v) for v in q_src_shape]
                    add_out_tensor.shape_signature = (
                        [int(v) for v in q_src_signature]
                        if q_src_signature is not None
                        else [int(v) for v in q_src_shape]
                    )
                if prelu_out_tensor is not None:
                    prelu_out_tensor.shape = [int(v) for v in q_src_shape]
                    prelu_out_tensor.shape_signature = (
                        [int(v) for v in q_src_signature]
                        if q_src_signature is not None
                        else [int(v) for v in q_src_shape]
                    )

            if q_dst_tensor is not None and q_mid_out_tensor is not None:
                q_dst_tensor.dtype = str(q_mid_out_tensor.dtype)
                q_dst_tensor.quantization = _clone_quantization(q_mid_out_tensor.quantization)

            for remove_idx in sorted([pre_idx, post_idx], reverse=True):
                del model_ir.operators[remove_idx]
            removed_mul_add_prelu_bridges += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "removed_transpose_dequant_mul_add_prelu_quantize_bridges": int(removed_mul_add_prelu_bridges),
    }


def _optimize_transpose_dequant_prelu_transpose_bridges(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose wrappers around DEQUANTIZE->PRELU chains.

    Target pattern:
      Xq --Transpose(P)--> Aq --DEQUANTIZE--> A --PRELU(alpha)--> B --Transpose(inv(P))--> Y

    Rewritten:
      Xq --DEQUANTIZE--> A' --PRELU(alpha')--> Y

    Safety conditions:
    - Chain is linear (single consumer at each bridge tensor)
    - Pre/Post transpose permutations are exact inverses
    - Quantized tensors on DEQUANTIZE input path are per-tensor
    """
    removed_prelu_transpose_bridges = 0

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue

            bridge_q_in = str(pre_op.outputs[0])
            dq_users = consumers.get(bridge_q_in, [])
            if len(dq_users) != 1:
                continue
            dq_idx = int(dq_users[0])
            dq_op = model_ir.operators[dq_idx]
            if str(dq_op.op_type) != "DEQUANTIZE" or len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                continue
            if str(dq_op.inputs[0]) != bridge_q_in:
                continue

            bridge_f_in = str(dq_op.outputs[0])
            prelu_users = consumers.get(bridge_f_in, [])
            if len(prelu_users) != 1:
                continue
            prelu_idx = int(prelu_users[0])
            prelu_op = model_ir.operators[prelu_idx]
            if str(prelu_op.op_type) != "PRELU" or len(prelu_op.inputs) != 2 or len(prelu_op.outputs) != 1:
                continue
            if str(prelu_op.inputs[0]) != bridge_f_in:
                continue

            bridge_f_out = str(prelu_op.outputs[0])
            post_users = consumers.get(bridge_f_out, [])
            if len(post_users) != 1:
                continue
            post_idx = int(post_users[0])
            post_op = model_ir.operators[post_idx]
            if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                continue
            if str(post_op.inputs[0]) != bridge_f_out:
                continue

            perm_post = _read_transpose_perm(model_ir, post_op)
            if perm_post is None or not _is_inverse_perm(perm_pre, perm_post):
                continue

            if (
                bridge_q_in in model_ir.outputs
                or bridge_f_in in model_ir.outputs
                or bridge_f_out in model_ir.outputs
                or post_op.outputs[0] in model_ir.outputs
            ):
                continue

            q_src_name = str(pre_op.inputs[0])
            y_name = str(post_op.outputs[0])
            q_src_tensor = model_ir.tensors.get(q_src_name, None)
            q_mid_tensor = model_ir.tensors.get(bridge_q_in, None)
            if not _all_per_tensor_quantized([q_src_tensor, q_mid_tensor]):
                continue

            alpha_name = str(prelu_op.inputs[1])
            alpha_tensor = model_ir.tensors.get(alpha_name, None)
            if alpha_tensor is not None:
                alpha_data = alpha_tensor.data
                if isinstance(alpha_data, np.ndarray) and alpha_data.ndim == len(perm_post):
                    transposed_alpha = np.transpose(alpha_data, axes=perm_post)
                    alpha_users = consumers.get(alpha_name, [])
                    if len(alpha_users) == 1 and int(alpha_users[0]) == int(prelu_idx):
                        alpha_tensor.data = transposed_alpha
                        alpha_tensor.shape = [int(v) for v in transposed_alpha.shape]
                        alpha_tensor.shape_signature = [int(v) for v in transposed_alpha.shape]
                    else:
                        new_alpha_name = _unique_tensor_name(f"{alpha_name}_nhwc")
                        model_ir.tensors[new_alpha_name] = TensorIR(
                            name=new_alpha_name,
                            dtype=str(alpha_tensor.dtype),
                            shape=[int(v) for v in transposed_alpha.shape],
                            shape_signature=[int(v) for v in transposed_alpha.shape],
                            data=np.asarray(transposed_alpha),
                            is_variable=False,
                            quantization=_clone_quantization(alpha_tensor.quantization),
                        )
                        _replace_operator_input_at(
                            model_ir=model_ir,
                            op=prelu_op,
                            input_index=1,
                            new_input_name=new_alpha_name,
                        )

            _set_operator_inputs(
                model_ir=model_ir,
                op=dq_op,
                new_inputs=[q_src_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=prelu_op,
                new_outputs=[y_name],
            )

            q_src_shape = list(q_src_tensor.shape) if q_src_tensor is not None else None
            q_src_signature = (
                list(q_src_tensor.shape_signature)
                if q_src_tensor is not None and q_src_tensor.shape_signature is not None
                else q_src_shape
            )
            if q_src_shape is not None:
                dq_out_tensor = model_ir.tensors.get(bridge_f_in, None)
                y_tensor = model_ir.tensors.get(y_name, None)
                if dq_out_tensor is not None:
                    dq_out_tensor.shape = [int(v) for v in q_src_shape]
                    dq_out_tensor.shape_signature = (
                        [int(v) for v in q_src_signature]
                        if q_src_signature is not None
                        else [int(v) for v in q_src_shape]
                    )
                if y_tensor is not None:
                    y_tensor.shape = [int(v) for v in q_src_shape]
                    y_tensor.shape_signature = (
                        [int(v) for v in q_src_signature]
                        if q_src_signature is not None
                        else [int(v) for v in q_src_shape]
                    )

            for remove_idx in sorted([pre_idx, post_idx], reverse=True):
                del model_ir.operators[remove_idx]
            removed_prelu_transpose_bridges += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "removed_transpose_dequant_prelu_transpose_bridges": int(removed_prelu_transpose_bridges),
    }


def _optimize_transpose_binary_bridges(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold symmetric transpose wrappers around elementwise binary ops.

    Target pattern:
      A --Transpose(P)--> A'
      B --Transpose(P)--> B'
      A',B' --(ADD|SUB|MUL|DIV)--> C'
      C' --Transpose(inv(P))--> C

    Constraints:
    - Both pre-transposed tensors are consumed only by the binary op.
    - Binary output is consumed only by the post transpose.
    - pre/post permutations are exact inverses.
    """
    removed_binary_bridges = 0
    removed_binary_asymmetric_bridges = 0
    binary_ops = {"ADD", "SUB", "MUL", "DIV"}
    enable_fanout_pattern_c = False

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)

        for mid_idx, mid_op in enumerate(model_ir.operators):
            if str(mid_op.op_type) not in binary_ops:
                continue
            if len(mid_op.inputs) != 2 or len(mid_op.outputs) != 1:
                continue

            in0_name = mid_op.inputs[0]
            in1_name = mid_op.inputs[1]
            out_name = mid_op.outputs[0]

            pre0_idx = producers.get(in0_name, None)
            pre1_idx = producers.get(in1_name, None)
            if pre0_idx is None or pre1_idx is None:
                continue
            pre0_op = model_ir.operators[pre0_idx]
            pre1_op = model_ir.operators[pre1_idx]
            if str(pre0_op.op_type) != "TRANSPOSE" or str(pre1_op.op_type) != "TRANSPOSE":
                continue
            if len(pre0_op.inputs) < 2 or len(pre1_op.inputs) < 2:
                continue
            if len(pre0_op.outputs) != 1 or len(pre1_op.outputs) != 1:
                continue
            if pre0_op.outputs[0] != in0_name or pre1_op.outputs[0] != in1_name:
                continue

            in0_users = set(consumers.get(in0_name, []))
            in1_users = set(consumers.get(in1_name, []))
            if in0_users != {int(mid_idx)} or in1_users != {int(mid_idx)}:
                continue

            perm0 = _read_transpose_perm(model_ir, pre0_op)
            perm1 = _read_transpose_perm(model_ir, pre1_op)
            if perm0 is None or perm1 is None:
                continue
            if perm0 != perm1:
                continue

            out_users = {int(v) for v in consumers.get(out_name, []) if int(v) != int(mid_idx)}
            if len(out_users) == 0:
                continue

            post_candidates: List[int] = []
            for user_idx in sorted(list(out_users)):
                post_candidate = model_ir.operators[int(user_idx)]
                if (
                    str(post_candidate.op_type) != "TRANSPOSE"
                    or len(post_candidate.inputs) < 2
                    or len(post_candidate.outputs) != 1
                    or post_candidate.inputs[0] != out_name
                ):
                    continue
                perm_post = _read_transpose_perm(model_ir, post_candidate)
                if perm_post is None or not _is_inverse_perm(perm0, perm_post):
                    continue
                post_candidates.append(int(user_idx))

            synthesize_post = False
            if len(post_candidates) == 0:
                if any(str(model_ir.operators[int(user_idx)].op_type) == "TRANSPOSE" for user_idx in out_users):
                    continue
                synthesize_post = True
            if len(post_candidates) > 1:
                continue
            post_idx = None
            post_op = None
            post_perm_name = None
            keep_post_for_fanout = False
            if not synthesize_post:
                post_idx = int(post_candidates[0])
                post_op = model_ir.operators[post_idx]
                post_perm_name = post_op.inputs[1]
                extra_users = set(out_users) - {int(post_idx)}
                # Extra users may remain on out_name, but must not be transpose producers.
                if any(str(model_ir.operators[int(user_idx)].op_type) == "TRANSPOSE" for user_idx in extra_users):
                    continue
                keep_post_for_fanout = len(extra_users) > 0

            # Keep user-visible output names stable.
            if in0_name in model_ir.outputs or in1_name in model_ir.outputs or out_name in model_ir.outputs:
                continue

            original_in0 = pre0_op.inputs[0]
            original_in1 = pre1_op.inputs[0]
            final_out = (
                post_op.outputs[0]
                if post_op is not None
                else out_name
            )

            _set_operator_inputs(
                model_ir=model_ir,
                op=mid_op,
                new_inputs=[original_in0, original_in1],
            )
            if synthesize_post:
                out_tensor = model_ir.tensors.get(out_name, None)
                if out_tensor is None:
                    continue
                if not _is_per_tensor_quantization(out_tensor.quantization):
                    continue
                inv_perm = _invert_perm(perm0)
                if inv_perm is None:
                    continue
                raw_shape = _permute_shape(list(out_tensor.shape), inv_perm)
                raw_signature = _permute_shape(
                    list(out_tensor.shape_signature)
                    if out_tensor.shape_signature is not None
                    else list(out_tensor.shape),
                    inv_perm,
                )
                if raw_shape is None:
                    continue
                if raw_signature is None:
                    raw_signature = list(raw_shape)
                raw_out_name = f"{out_name}__raw"
                serial = 0
                while raw_out_name in model_ir.tensors:
                    serial += 1
                    raw_out_name = f"{out_name}__raw_{serial}"
                model_ir.tensors[raw_out_name] = TensorIR(
                    name=raw_out_name,
                    dtype=str(out_tensor.dtype),
                    shape=[int(v) for v in raw_shape],
                    shape_signature=[int(v) for v in raw_signature],
                    data=None,
                    is_variable=False,
                    quantization=_clone_quantization(out_tensor.quantization),
                )
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=mid_op,
                    new_outputs=[raw_out_name],
                )
            else:
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=mid_op,
                    new_outputs=[final_out],
                )

            final_tensor = model_ir.tensors.get(final_out, None)
            old_out_tensor = model_ir.tensors.get(out_name, None)
            if final_tensor is not None and old_out_tensor is not None:
                final_tensor.dtype = str(old_out_tensor.dtype)
                if final_tensor.quantization is None and old_out_tensor.quantization is not None:
                    final_tensor.quantization = _clone_quantization(old_out_tensor.quantization)

            if keep_post_for_fanout and post_op is not None and post_perm_name is not None:
                perm_tensor = model_ir.tensors.get(post_perm_name, None)
                if perm_tensor is not None:
                    perm_tensor.data = np.asarray(perm0, dtype=np.int32)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=post_op,
                    new_inputs=[final_out, post_perm_name],
                )
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=post_op,
                    new_outputs=[out_name],
                )

            if synthesize_post:
                reuse_perm_name = pre0_op.inputs[1]
                insert_at = int(min(out_users))
                remove_indices = sorted(list({int(pre0_idx), int(pre1_idx)}), reverse=True)
                shift = sum(1 for idx in remove_indices if int(idx) < insert_at)
                for remove_idx in remove_indices:
                    del model_ir.operators[remove_idx]
                adjusted_insert_at = int(insert_at - shift)
                model_ir.operators.insert(
                    adjusted_insert_at,
                    OperatorIR(
                        op_type="TRANSPOSE",
                        inputs=[raw_out_name, reuse_perm_name],
                        outputs=[out_name],
                    ),
                )
            else:
                remove_indices = (
                    sorted(list({int(pre0_idx), int(pre1_idx)}), reverse=True)
                    if keep_post_for_fanout
                    else sorted(list({int(pre0_idx), int(pre1_idx), int(post_idx)}), reverse=True)
                )
                for remove_idx in remove_indices:
                    del model_ir.operators[remove_idx]
            removed_binary_bridges += 1
            changed = True
            break

        if changed:
            continue

        # Pattern B:
        #   A,B' --(ADD|SUB|MUL|DIV)--> C' --T(invP)--> C
        # where B' is produced by T(P) from B.
        # Rewrite to:
        #   A' --T(invP)--> A'
        #   A',B --(ADD|SUB|MUL|DIV)--> C
        # This removes one transpose around the binary op.
        for mid_idx, mid_op in enumerate(model_ir.operators):
            if str(mid_op.op_type) not in binary_ops:
                continue
            if len(mid_op.inputs) != 2 or len(mid_op.outputs) != 1:
                continue

            in0_name = mid_op.inputs[0]
            in1_name = mid_op.inputs[1]
            out_name = mid_op.outputs[0]

            pre0_idx = producers.get(in0_name, None)
            pre1_idx = producers.get(in1_name, None)
            pre0_is_transpose = False
            pre1_is_transpose = False
            pre0_op = None
            pre1_op = None

            if pre0_idx is not None:
                pre0_op = model_ir.operators[int(pre0_idx)]
                pre0_is_transpose = (
                    str(pre0_op.op_type) == "TRANSPOSE"
                    and len(pre0_op.inputs) >= 2
                    and len(pre0_op.outputs) == 1
                    and pre0_op.outputs[0] == in0_name
                )
            if pre1_idx is not None:
                pre1_op = model_ir.operators[int(pre1_idx)]
                pre1_is_transpose = (
                    str(pre1_op.op_type) == "TRANSPOSE"
                    and len(pre1_op.inputs) >= 2
                    and len(pre1_op.outputs) == 1
                    and pre1_op.outputs[0] == in1_name
                )

            # Asymmetric-only pass: exactly one input is wrapped by pre-transpose.
            if pre0_is_transpose == pre1_is_transpose:
                continue

            if pre0_is_transpose:
                pre_idx = int(pre0_idx)
                pre_op = pre0_op
                transposed_input_name = in0_name
                plain_input_name = in1_name
                transpose_on_lhs = True
            else:
                pre_idx = int(pre1_idx)
                pre_op = pre1_op
                transposed_input_name = in1_name
                plain_input_name = in0_name
                transpose_on_lhs = False

            if pre_op is None:
                continue
            if len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue

            transposed_users = set(consumers.get(transposed_input_name, []))
            if transposed_users != {int(mid_idx)}:
                continue

            out_users = set(consumers.get(out_name, []))
            if len(out_users) != 1:
                continue
            post_idx = int(list(out_users)[0])
            if post_idx == mid_idx:
                continue
            post_op = model_ir.operators[post_idx]
            if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                continue
            if post_op.inputs[0] != out_name:
                continue

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            perm_post = _read_transpose_perm(model_ir, post_op)
            if perm_pre is None or perm_post is None:
                continue
            if not _is_inverse_perm(perm_pre, perm_post):
                continue

            # Keep user-visible output names stable.
            if transposed_input_name in model_ir.outputs or out_name in model_ir.outputs:
                continue

            raw_from_pre_name = pre_op.inputs[0]
            final_out_name = post_op.outputs[0]

            transposed_tensor = model_ir.tensors.get(transposed_input_name, None)
            plain_tensor = model_ir.tensors.get(plain_input_name, None)
            raw_tensor = model_ir.tensors.get(raw_from_pre_name, None)
            out_tensor = model_ir.tensors.get(out_name, None)
            final_out_tensor = model_ir.tensors.get(final_out_name, None)

            if not _all_per_tensor_quantized(
                [transposed_tensor, plain_tensor, raw_tensor, out_tensor, final_out_tensor]
            ):
                continue

            transposed_input_shape = (
                list(transposed_tensor.shape) if transposed_tensor is not None else None
            )
            plain_input_shape = list(plain_tensor.shape) if plain_tensor is not None else None
            plain_input_signature = (
                list(plain_tensor.shape_signature)
                if plain_tensor is not None and plain_tensor.shape_signature is not None
                else plain_input_shape
            )
            raw_pre_shape = list(raw_tensor.shape) if raw_tensor is not None else None
            final_out_shape = list(final_out_tensor.shape) if final_out_tensor is not None else None

            # Require no broadcasting ambiguity.
            if not _shapes_equal(transposed_input_shape, plain_input_shape):
                continue
            expected_raw_shape = _permute_shape(plain_input_shape, perm_post)
            expected_raw_signature = _permute_shape(plain_input_signature, perm_post)
            if expected_raw_shape is None:
                continue
            if expected_raw_signature is None:
                expected_raw_signature = list(expected_raw_shape)
            if raw_pre_shape is not None and not _shapes_equal(expected_raw_shape, raw_pre_shape):
                continue
            if final_out_shape is not None and not _shapes_equal(expected_raw_shape, final_out_shape):
                continue

            # Reuse pre-transpose node by moving it to the other input with inverse perm.
            _set_operator_inputs(
                model_ir=model_ir,
                op=pre_op,
                new_inputs=[plain_input_name, post_op.inputs[1]],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=pre_op,
                new_outputs=[transposed_input_name],
            )

            if transpose_on_lhs:
                # op(T(A), B) then T(invP) -> op(A, T(invP)(B))
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=mid_op,
                    new_inputs=[raw_from_pre_name, transposed_input_name],
                )
            else:
                # op(A, T(B)) then T(invP) -> op(T(invP)(A), B)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=mid_op,
                    new_inputs=[transposed_input_name, raw_from_pre_name],
                )
            _set_operator_outputs(
                model_ir=model_ir,
                op=mid_op,
                new_outputs=[final_out_name],
            )

            if transposed_tensor is not None:
                transposed_tensor.shape = list(expected_raw_shape)
                transposed_tensor.shape_signature = list(expected_raw_signature)
                if plain_tensor is not None:
                    transposed_tensor.dtype = str(plain_tensor.dtype)
                    if transposed_tensor.quantization is None and plain_tensor.quantization is not None:
                        transposed_tensor.quantization = _clone_quantization(plain_tensor.quantization)

            if final_out_tensor is not None and out_tensor is not None:
                final_out_tensor.dtype = str(out_tensor.dtype)
                if final_out_tensor.quantization is None and out_tensor.quantization is not None:
                    final_out_tensor.quantization = _clone_quantization(out_tensor.quantization)

            del model_ir.operators[post_idx]
            removed_binary_asymmetric_bridges += 1
            changed = True
            break

        if changed:
            continue

        # Pattern C:
        # Fanout-aware binary bridge optimization.
        # Allows output consumers to include:
        # - inverse TRANSPOSE nodes (removed)
        # - downstream binary ops (kept, enabling chained rewrites)
        if not enable_fanout_pattern_c:
            break
        binary_chain_cache: Dict[int, bool] = {}

        def _is_rewritable_binary_chain(
            start_idx: int,
            base_perm_local: List[int],
            visiting: Optional[set[int]] = None,
        ) -> bool:
            if start_idx in binary_chain_cache:
                return bool(binary_chain_cache[start_idx])
            if visiting is None:
                visiting = set()
            if int(start_idx) in visiting:
                binary_chain_cache[int(start_idx)] = False
                return False
            if start_idx < 0 or start_idx >= len(model_ir.operators):
                binary_chain_cache[int(start_idx)] = False
                return False
            op_local = model_ir.operators[int(start_idx)]
            if str(op_local.op_type) not in binary_ops or len(op_local.outputs) != 1:
                binary_chain_cache[int(start_idx)] = False
                return False
            out_local = str(op_local.outputs[0])
            if out_local in model_ir.outputs:
                binary_chain_cache[int(start_idx)] = False
                return False

            downstream = [int(v) for v in consumers.get(out_local, []) if int(v) != int(start_idx)]
            if len(downstream) == 0:
                binary_chain_cache[int(start_idx)] = False
                return False

            visiting.add(int(start_idx))
            for down_idx in downstream:
                down_op = model_ir.operators[int(down_idx)]
                if (
                    str(down_op.op_type) == "TRANSPOSE"
                    and len(down_op.inputs) >= 2
                    and len(down_op.outputs) == 1
                    and down_op.inputs[0] == out_local
                ):
                    down_perm = _read_transpose_perm(model_ir, down_op)
                    if down_perm is None or not _is_inverse_perm(base_perm_local, down_perm):
                        visiting.remove(int(start_idx))
                        binary_chain_cache[int(start_idx)] = False
                        return False
                    if str(down_op.outputs[0]) in model_ir.outputs:
                        visiting.remove(int(start_idx))
                        binary_chain_cache[int(start_idx)] = False
                        return False
                    continue
                if str(down_op.op_type) in binary_ops and out_local in set(down_op.inputs):
                    if not _is_rewritable_binary_chain(
                        int(down_idx),
                        base_perm_local,
                        visiting,
                    ):
                        visiting.remove(int(start_idx))
                        binary_chain_cache[int(start_idx)] = False
                        return False
                    continue
                visiting.remove(int(start_idx))
                binary_chain_cache[int(start_idx)] = False
                return False

            visiting.remove(int(start_idx))
            binary_chain_cache[int(start_idx)] = True
            return True

        for mid_idx, mid_op in enumerate(model_ir.operators):
            if str(mid_op.op_type) not in binary_ops:
                continue
            if len(mid_op.inputs) != 2 or len(mid_op.outputs) != 1:
                continue

            in0_name = mid_op.inputs[0]
            in1_name = mid_op.inputs[1]
            out_name = mid_op.outputs[0]

            if out_name in model_ir.outputs:
                continue

            def _input_info(input_name: str) -> Tuple[str, Optional[int], Optional[List[int]]]:
                pre_idx_local = producers.get(input_name, None)
                if pre_idx_local is None:
                    return input_name, None, None
                pre_op_local = model_ir.operators[int(pre_idx_local)]
                if (
                    str(pre_op_local.op_type) != "TRANSPOSE"
                    or len(pre_op_local.inputs) < 2
                    or len(pre_op_local.outputs) != 1
                    or pre_op_local.outputs[0] != input_name
                ):
                    return input_name, None, None
                if set(consumers.get(input_name, [])) != {int(mid_idx)}:
                    return input_name, None, None
                perm_local = _read_transpose_perm(model_ir, pre_op_local)
                if perm_local is None:
                    return input_name, None, None
                return pre_op_local.inputs[0], int(pre_idx_local), perm_local

            raw_in0_name, pre0_idx, perm0 = _input_info(in0_name)
            raw_in1_name, pre1_idx, perm1 = _input_info(in1_name)

            if perm0 is None and perm1 is None:
                continue
            if in0_name in model_ir.outputs or in1_name in model_ir.outputs:
                continue

            perm_candidates = []
            if perm0 is not None:
                perm_candidates.append(list(perm0))
            if perm1 is not None:
                perm_candidates.append(list(perm1))
            if len(perm_candidates) == 0:
                continue
            base_perm = perm_candidates[0]
            if any(perm != base_perm for perm in perm_candidates[1:]):
                continue

            raw_in0_tensor = model_ir.tensors.get(raw_in0_name, None)
            raw_in1_tensor = model_ir.tensors.get(raw_in1_name, None)
            if raw_in0_tensor is None or raw_in1_tensor is None:
                continue
            raw_shape0 = list(raw_in0_tensor.shape)
            raw_shape1 = list(raw_in1_tensor.shape)
            if not _shapes_equal(raw_shape0, raw_shape1):
                continue
            raw_signature0 = (
                list(raw_in0_tensor.shape_signature)
                if raw_in0_tensor.shape_signature is not None
                else list(raw_shape0)
            )

            out_users = [int(v) for v in consumers.get(out_name, []) if int(v) != int(mid_idx)]
            if len(out_users) == 0:
                continue

            post_indices: List[int] = []
            post_output_names: List[str] = []
            users_valid = True

            for user_idx in out_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and user_op.inputs[0] == out_name
                ):
                    perm_post = _read_transpose_perm(model_ir, user_op)
                    if perm_post is None or not _is_inverse_perm(base_perm, perm_post):
                        users_valid = False
                        break
                    post_output_name = str(user_op.outputs[0])
                    if post_output_name in model_ir.outputs:
                        users_valid = False
                        break
                    post_indices.append(int(user_idx))
                    post_output_names.append(post_output_name)
                    continue

                if str(user_op.op_type) in binary_ops and out_name in set(user_op.inputs):
                    if len(user_op.inputs) != 2:
                        users_valid = False
                        break
                    if user_op.inputs[0] == out_name:
                        other_input_name = user_op.inputs[1]
                    elif user_op.inputs[1] == out_name:
                        other_input_name = user_op.inputs[0]
                    else:
                        users_valid = False
                        break

                    other_ok = False
                    other_prod_idx = producers.get(other_input_name, None)
                    if other_prod_idx is not None:
                        other_prod_op = model_ir.operators[int(other_prod_idx)]
                        if (
                            str(other_prod_op.op_type) == "TRANSPOSE"
                            and len(other_prod_op.inputs) >= 2
                            and len(other_prod_op.outputs) == 1
                            and other_prod_op.outputs[0] == other_input_name
                            and set(consumers.get(other_input_name, [])) == {int(user_idx)}
                        ):
                            other_perm = _read_transpose_perm(model_ir, other_prod_op)
                            if other_perm is not None and other_perm == base_perm:
                                other_ok = True
                    if not other_ok:
                        other_tensor = model_ir.tensors.get(other_input_name, None)
                        if other_tensor is not None and _shapes_equal(list(other_tensor.shape), raw_shape0):
                            other_ok = True
                    if not other_ok:
                        users_valid = False
                        break

                    if not _is_rewritable_binary_chain(int(user_idx), base_perm):
                        users_valid = False
                        break

                    continue

                users_valid = False
                break

            if not users_valid:
                continue

            removable_pre_indices = [idx for idx in [pre0_idx, pre1_idx] if idx is not None]
            if len(removable_pre_indices) == 0 and len(post_indices) == 0:
                continue

            # Rewire binary inputs to raw layout.
            _set_operator_inputs(
                model_ir=model_ir,
                op=mid_op,
                new_inputs=[raw_in0_name, raw_in1_name],
            )

            out_tensor = model_ir.tensors.get(out_name, None)
            if out_tensor is not None:
                out_tensor.shape = list(raw_shape0)
                out_tensor.shape_signature = list(raw_signature0)

            for post_output_name in post_output_names:
                _replace_tensor_inputs(model_ir, post_output_name, out_name)

            remove_indices = sorted(list(set(removable_pre_indices + post_indices)), reverse=True)
            for remove_idx in remove_indices:
                del model_ir.operators[remove_idx]

            removed_binary_bridges += int(max(1, len(post_indices) + len(removable_pre_indices)))
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "removed_transpose_binary_bridges": int(removed_binary_bridges),
        "removed_transpose_binary_asymmetric_bridges": int(removed_binary_asymmetric_bridges),
    }


def _optimize_transpose_binary_asymmetric_fanout_bridges(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold asymmetric transpose wrappers around binary ops when output has fanout.

    Target pattern:
      T(P)(X) + Y -> Z
      T(inv(P))(Z) -> Z_nhwc
      (Z may have extra non-transpose consumers)

    Rewritten:
      X + T(inv(P))(Y) -> Z_nhwc
      (optional adapter) T(P)(Z_nhwc) -> Z

    This reduces one transpose in fanout cases where the simple asymmetric bridge
    optimization cannot apply.
    """
    rewritten = 0
    binary_ops = {"ADD", "SUB", "MUL", "DIV"}

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)

        for mid_idx, mid_op in enumerate(model_ir.operators):
            if str(mid_op.op_type) not in binary_ops:
                continue
            if len(mid_op.inputs) != 2 or len(mid_op.outputs) != 1:
                continue

            in0_name = str(mid_op.inputs[0])
            in1_name = str(mid_op.inputs[1])
            out_name = str(mid_op.outputs[0])

            pre0_idx = producers.get(in0_name, None)
            pre1_idx = producers.get(in1_name, None)
            pre0_is_transpose = False
            pre1_is_transpose = False
            pre0_op = None
            pre1_op = None

            if pre0_idx is not None:
                pre0_op = model_ir.operators[int(pre0_idx)]
                pre0_is_transpose = (
                    str(pre0_op.op_type) == "TRANSPOSE"
                    and len(pre0_op.inputs) >= 2
                    and len(pre0_op.outputs) == 1
                    and str(pre0_op.outputs[0]) == in0_name
                )
            if pre1_idx is not None:
                pre1_op = model_ir.operators[int(pre1_idx)]
                pre1_is_transpose = (
                    str(pre1_op.op_type) == "TRANSPOSE"
                    and len(pre1_op.inputs) >= 2
                    and len(pre1_op.outputs) == 1
                    and str(pre1_op.outputs[0]) == in1_name
                )

            # Exactly one pre-transposed input.
            if pre0_is_transpose == pre1_is_transpose:
                continue

            if pre0_is_transpose:
                pre_idx = int(pre0_idx)
                pre_op = pre0_op
                transposed_input_name = in0_name
                plain_input_name = in1_name
                transpose_on_lhs = True
            else:
                pre_idx = int(pre1_idx)
                pre_op = pre1_op
                transposed_input_name = in1_name
                plain_input_name = in0_name
                transpose_on_lhs = False

            if pre_op is None:
                continue

            transposed_users = [int(v) for v in consumers.get(transposed_input_name, [])]
            if transposed_users != [int(mid_idx)] and set(transposed_users) != {int(mid_idx)}:
                continue

            out_users = [int(v) for v in consumers.get(out_name, []) if int(v) != int(mid_idx)]
            if len(out_users) == 0:
                continue

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue
            inv_perm = _invert_perm(perm_pre)
            if inv_perm is None:
                continue

            post_idx = None
            post_op = None
            for user_idx in out_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == out_name
                ):
                    perm_post = _read_transpose_perm(model_ir, user_op)
                    if perm_post is not None and perm_post == inv_perm:
                        post_idx = int(user_idx)
                        post_op = user_op
                        break
            if post_idx is None or post_op is None:
                continue

            post_output_name = str(post_op.outputs[0])
            if post_output_name in model_ir.outputs and out_name in model_ir.outputs:
                # Avoid ambiguous observable output rewrites.
                continue

            # Find an existing transpose(plain_input, inv_perm) to reuse.
            plain_users = [int(v) for v in consumers.get(plain_input_name, [])]
            plain_transpose_idx = None
            plain_transpose_out = None
            for plain_user_idx in plain_users:
                plain_user_op = model_ir.operators[int(plain_user_idx)]
                if (
                    str(plain_user_op.op_type) == "TRANSPOSE"
                    and len(plain_user_op.inputs) >= 2
                    and len(plain_user_op.outputs) == 1
                    and str(plain_user_op.inputs[0]) == plain_input_name
                ):
                    perm_plain = _read_transpose_perm(model_ir, plain_user_op)
                    if perm_plain is not None and perm_plain == inv_perm:
                        plain_transpose_idx = int(plain_user_idx)
                        plain_transpose_out = str(plain_user_op.outputs[0])
                        break
            if plain_transpose_idx is None or plain_transpose_out is None:
                continue

            raw_from_pre_name = str(pre_op.inputs[0])
            if transpose_on_lhs:
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=mid_op,
                    new_inputs=[raw_from_pre_name, plain_transpose_out],
                )
            else:
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=mid_op,
                    new_inputs=[plain_transpose_out, raw_from_pre_name],
                )
            _set_operator_outputs(
                model_ir=model_ir,
                op=mid_op,
                new_outputs=[post_output_name],
            )

            out_tensor = model_ir.tensors.get(out_name, None)
            post_out_tensor = model_ir.tensors.get(post_output_name, None)
            if out_tensor is not None and post_out_tensor is not None:
                post_out_tensor.dtype = str(out_tensor.dtype)
                if post_out_tensor.quantization is None and out_tensor.quantization is not None:
                    post_out_tensor.quantization = _clone_quantization(out_tensor.quantization)

            extra_users = [int(v) for v in out_users if int(v) != int(post_idx)]
            adapter_needed = len(extra_users) > 0 or out_name in model_ir.outputs
            if adapter_needed:
                adapter = OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[post_output_name, str(pre_op.inputs[1])],
                    outputs=[out_name],
                )

            remove_indices = sorted(list({int(pre_idx), int(post_idx)}), reverse=True)
            shift = sum(1 for ridx in remove_indices if int(ridx) < int(mid_idx))
            for ridx in remove_indices:
                del model_ir.operators[int(ridx)]
            mid_new_idx = int(mid_idx - shift)
            if adapter_needed:
                model_ir.operators.insert(int(mid_new_idx) + 1, adapter)

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "rewritten_transpose_binary_asymmetric_fanout_bridges": int(rewritten),
    }


def _optimize_transpose_binary_full_post_fanout_bridges(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold a strict transpose-binary-transpose fanout pattern.

    Target:
      T(P)(A) + T(P)(B) -> C
      C -> T(inv(P)) -> C0
      C -> T(inv(P)) -> C1
      ...

    Rewrite:
      A + B -> C0
      (all uses of C1... are rewired to C0)

    Safety:
    - Binary op has exactly 2 inputs / 1 output (ADD|SUB|MUL|DIV)
    - Both inputs are produced by TRANSPOSE with identical permutation
    - Both pre-transpose outputs are consumed only by the binary op
    - All consumers of binary output are inverse TRANSPOSE ops
    - No broadcasting ambiguity: all participating tensor shapes match exactly
    - Intermediate tensors are not graph outputs
    """
    rewritten = 0
    binary_ops = {"ADD", "SUB", "MUL", "DIV"}

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)

        for mid_idx, mid_op in enumerate(model_ir.operators):
            if str(mid_op.op_type) not in binary_ops:
                continue
            if len(mid_op.inputs) != 2 or len(mid_op.outputs) != 1:
                continue

            in0_name = str(mid_op.inputs[0])
            in1_name = str(mid_op.inputs[1])
            out_name = str(mid_op.outputs[0])

            pre0_idx = producers.get(in0_name, None)
            pre1_idx = producers.get(in1_name, None)
            if pre0_idx is None or pre1_idx is None:
                continue
            pre0_op = model_ir.operators[int(pre0_idx)]
            pre1_op = model_ir.operators[int(pre1_idx)]
            if str(pre0_op.op_type) != "TRANSPOSE" or str(pre1_op.op_type) != "TRANSPOSE":
                continue
            if len(pre0_op.inputs) < 2 or len(pre1_op.inputs) < 2:
                continue
            if len(pre0_op.outputs) != 1 or len(pre1_op.outputs) != 1:
                continue
            if str(pre0_op.outputs[0]) != in0_name or str(pre1_op.outputs[0]) != in1_name:
                continue

            # Pre-transposed tensors must be exclusive to the binary op.
            if set(consumers.get(in0_name, [])) != {int(mid_idx)}:
                continue
            if set(consumers.get(in1_name, [])) != {int(mid_idx)}:
                continue

            perm_pre0 = _read_transpose_perm(model_ir, pre0_op)
            perm_pre1 = _read_transpose_perm(model_ir, pre1_op)
            if perm_pre0 is None or perm_pre1 is None:
                continue
            if perm_pre0 != perm_pre1:
                continue

            out_users = [int(v) for v in consumers.get(out_name, []) if int(v) != int(mid_idx)]
            if len(out_users) < 2:
                continue

            post_indices: List[int] = []
            post_output_names: List[str] = []
            for user_idx in out_users:
                post_op = model_ir.operators[int(user_idx)]
                if (
                    str(post_op.op_type) != "TRANSPOSE"
                    or len(post_op.inputs) < 2
                    or len(post_op.outputs) != 1
                    or str(post_op.inputs[0]) != out_name
                ):
                    post_indices = []
                    break
                perm_post = _read_transpose_perm(model_ir, post_op)
                if perm_post is None or not _is_inverse_perm(perm_pre0, perm_post):
                    post_indices = []
                    break
                post_indices.append(int(user_idx))
                post_output_names.append(str(post_op.outputs[0]))
            if len(post_indices) != len(out_users):
                continue

            if (
                in0_name in model_ir.outputs
                or in1_name in model_ir.outputs
                or out_name in model_ir.outputs
                or any(name in model_ir.outputs for name in post_output_names)
            ):
                continue

            raw_in0_name = str(pre0_op.inputs[0])
            raw_in1_name = str(pre1_op.inputs[0])
            raw_in0_tensor = model_ir.tensors.get(raw_in0_name, None)
            raw_in1_tensor = model_ir.tensors.get(raw_in1_name, None)
            in0_tensor = model_ir.tensors.get(in0_name, None)
            in1_tensor = model_ir.tensors.get(in1_name, None)
            out_tensor = model_ir.tensors.get(out_name, None)
            if not _all_per_tensor_quantized(
                [raw_in0_tensor, raw_in1_tensor, in0_tensor, in1_tensor, out_tensor]
            ):
                continue

            # Conservative shape guards with broadcast-aware validation.
            raw_shape0 = list(raw_in0_tensor.shape) if raw_in0_tensor is not None else None
            raw_shape1 = list(raw_in1_tensor.shape) if raw_in1_tensor is not None else None
            raw_broadcast_shape = _broadcast_static_shapes(raw_shape0, raw_shape1)
            if raw_broadcast_shape is None:
                continue
            mid_expected_shape = _permute_shape(list(raw_broadcast_shape), perm_pre0)
            if mid_expected_shape is None:
                continue

            in_shape0 = list(in0_tensor.shape) if in0_tensor is not None else None
            in_shape1 = list(in1_tensor.shape) if in1_tensor is not None else None
            mid_broadcast_shape = _broadcast_static_shapes(in_shape0, in_shape1)
            if mid_broadcast_shape is None:
                continue
            if not _shapes_match_if_known(mid_broadcast_shape, mid_expected_shape):
                continue
            out_shape = list(out_tensor.shape) if out_tensor is not None else None
            if not _shapes_match_if_known(out_shape, mid_expected_shape):
                continue

            valid_post_shapes = True
            for post_output_name in post_output_names:
                post_tensor = model_ir.tensors.get(post_output_name, None)
                post_shape = list(post_tensor.shape) if post_tensor is not None else None
                if not _shapes_match_if_known(post_shape, raw_broadcast_shape):
                    valid_post_shapes = False
                    break
            if not valid_post_shapes:
                continue

            canonical_post_output = str(post_output_names[0])
            canonical_tensor = model_ir.tensors.get(canonical_post_output, None)

            _set_operator_inputs(
                model_ir=model_ir,
                op=mid_op,
                new_inputs=[raw_in0_name, raw_in1_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=mid_op,
                new_outputs=[canonical_post_output],
            )

            if canonical_tensor is not None:
                canonical_tensor.shape = [int(v) for v in list(raw_broadcast_shape)]
                raw_sig0 = (
                    list(raw_in0_tensor.shape_signature)
                    if raw_in0_tensor is not None and raw_in0_tensor.shape_signature is not None
                    else list(raw_shape0) if raw_shape0 is not None else None
                )
                raw_sig1 = (
                    list(raw_in1_tensor.shape_signature)
                    if raw_in1_tensor is not None and raw_in1_tensor.shape_signature is not None
                    else list(raw_shape1) if raw_shape1 is not None else None
                )
                raw_broadcast_signature = _broadcast_static_shapes(raw_sig0, raw_sig1)
                if raw_broadcast_signature is None:
                    raw_broadcast_signature = [int(v) for v in list(raw_broadcast_shape)]
                canonical_tensor.shape_signature = [int(v) for v in list(raw_broadcast_signature)]
                if out_tensor is not None:
                    canonical_tensor.dtype = str(out_tensor.dtype)
                    canonical_tensor.quantization = _clone_quantization(out_tensor.quantization)

            for post_output_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, post_output_name, canonical_post_output)

            remove_indices = sorted(
                list(set([int(pre0_idx), int(pre1_idx)] + [int(idx) for idx in post_indices])),
                reverse=True,
            )
            for remove_idx in remove_indices:
                del model_ir.operators[remove_idx]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"rewritten_transpose_binary_full_post_fanout_bridges": int(rewritten)}


def _optimize_transpose_binary_single_post_bridges_safe(model_ir: ModelIR) -> Dict[str, int]:
    """
    Conservative transpose-binary bridge folding with exactly one inverse post-transpose.

    Target:
      T(P)(A), T(P)(B) -> C
      C -> T(inv(P)) -> C_raw
      (C may also have extra non-transpose consumers)

    Rewrite:
      A, B -> C_raw
      If C has extra consumers:
        keep adapter T(P): C_raw -> C
      else:
        remove post-transpose.

    This pass intentionally uses strict shape guards to avoid layout corruption.
    """
    rewritten = 0
    binary_ops = {"ADD", "SUB", "MUL", "DIV"}
    preserve_layout_boundary_marker = "__preserve_layout_boundary__"

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)

        for mid_idx, mid_op in enumerate(model_ir.operators):
            if str(mid_op.op_type) not in binary_ops:
                continue
            if len(mid_op.inputs) != 2 or len(mid_op.outputs) != 1:
                continue

            in0_name = str(mid_op.inputs[0])
            in1_name = str(mid_op.inputs[1])
            out_name = str(mid_op.outputs[0])

            pre0_idx = producers.get(in0_name, None)
            pre1_idx = producers.get(in1_name, None)
            if pre0_idx is None or pre1_idx is None:
                continue
            pre0_op = model_ir.operators[int(pre0_idx)]
            pre1_op = model_ir.operators[int(pre1_idx)]
            if str(pre0_op.op_type) != "TRANSPOSE" or str(pre1_op.op_type) != "TRANSPOSE":
                continue
            if len(pre0_op.inputs) < 2 or len(pre1_op.inputs) < 2:
                continue
            if len(pre0_op.outputs) != 1 or len(pre1_op.outputs) != 1:
                continue
            if str(pre0_op.outputs[0]) != in0_name or str(pre1_op.outputs[0]) != in1_name:
                continue

            if set(consumers.get(in0_name, [])) != {int(mid_idx)}:
                continue
            if set(consumers.get(in1_name, [])) != {int(mid_idx)}:
                continue

            perm_pre0 = _read_transpose_perm(model_ir, pre0_op)
            perm_pre1 = _read_transpose_perm(model_ir, pre1_op)
            if perm_pre0 is None or perm_pre1 is None:
                continue
            if perm_pre0 != perm_pre1:
                continue

            out_users = {int(v) for v in consumers.get(out_name, []) if int(v) != int(mid_idx)}
            if len(out_users) == 0:
                continue

            post_candidates: List[int] = []
            for user_idx in sorted(list(out_users)):
                post_op = model_ir.operators[int(user_idx)]
                if (
                    str(post_op.op_type) != "TRANSPOSE"
                    or len(post_op.inputs) < 2
                    or len(post_op.outputs) != 1
                    or str(post_op.inputs[0]) != out_name
                ):
                    continue
                perm_post = _read_transpose_perm(model_ir, post_op)
                if perm_post is None or not _is_inverse_perm(perm_pre0, perm_post):
                    continue
                post_candidates.append(int(user_idx))

            if len(post_candidates) != 1:
                continue

            post_idx = int(post_candidates[0])
            post_op = model_ir.operators[post_idx]
            post_out_name = str(post_op.outputs[0])
            post_perm_name = str(post_op.inputs[1])
            extra_users = set(out_users) - {int(post_idx)}

            # Avoid ambiguous fanout rewrites if any extra fanout is another transpose.
            if any(str(model_ir.operators[int(v)].op_type) == "TRANSPOSE" for v in extra_users):
                continue

            if in0_name in model_ir.outputs or in1_name in model_ir.outputs:
                continue

            raw_in0_name = str(pre0_op.inputs[0])
            raw_in1_name = str(pre1_op.inputs[0])

            raw_in0_tensor = model_ir.tensors.get(raw_in0_name, None)
            raw_in1_tensor = model_ir.tensors.get(raw_in1_name, None)
            in0_tensor = model_ir.tensors.get(in0_name, None)
            in1_tensor = model_ir.tensors.get(in1_name, None)
            out_tensor = model_ir.tensors.get(out_name, None)
            post_out_tensor = model_ir.tensors.get(post_out_name, None)

            if not _all_per_tensor_quantized(
                [raw_in0_tensor, raw_in1_tensor, in0_tensor, in1_tensor, out_tensor, post_out_tensor]
            ):
                continue

            raw_shape0 = list(raw_in0_tensor.shape) if raw_in0_tensor is not None else None
            raw_shape1 = list(raw_in1_tensor.shape) if raw_in1_tensor is not None else None
            # NOTE:
            # Some optimized branches can retain stale static shapes in IR while runtime
            # shapes are valid. For strict single-post bridge chains, rely on topology
            # constraints and quantization compatibility instead of hard shape equality.

            _set_operator_inputs(
                model_ir=model_ir,
                op=mid_op,
                new_inputs=[raw_in0_name, raw_in1_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=mid_op,
                new_outputs=[post_out_name],
            )

            if post_out_tensor is not None and out_tensor is not None:
                post_out_tensor.dtype = str(out_tensor.dtype)
                post_out_tensor.quantization = _clone_quantization(out_tensor.quantization)
                if not _is_unknown_shape(raw_shape0):
                    post_out_tensor.shape = [int(v) for v in list(raw_shape0)]
                    raw_sig0 = (
                        list(raw_in0_tensor.shape_signature)
                        if raw_in0_tensor is not None and raw_in0_tensor.shape_signature is not None
                        else list(raw_shape0)
                    )
                    post_out_tensor.shape_signature = [int(v) for v in list(raw_sig0)]

            if len(extra_users) > 0:
                post_opts = dict(post_op.options) if isinstance(post_op.options, dict) else {}
                post_opts[preserve_layout_boundary_marker] = True
                post_op.options = post_opts
                perm_tensor = model_ir.tensors.get(post_perm_name, None)
                if perm_tensor is not None:
                    perm_tensor.data = np.asarray(perm_pre0, dtype=np.int32)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=post_op,
                    new_inputs=[post_out_name, post_perm_name],
                )
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=post_op,
                    new_outputs=[out_name],
                )
                remove_indices = sorted(list({int(pre0_idx), int(pre1_idx)}), reverse=True)
            else:
                remove_indices = sorted(list({int(pre0_idx), int(pre1_idx), int(post_idx)}), reverse=True)

            for remove_idx in remove_indices:
                del model_ir.operators[remove_idx]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"rewritten_transpose_binary_single_post_bridges_safe": int(rewritten)}


def _optimize_transpose_binary_mixed_fanout_bridges_safe(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose-binary pattern when output fanout mixes:
    - inverse TRANSPOSE consumers (layout adapters)
    - non-TRANSPOSE consumers (legacy layout path)

    Rewrite keeps one transpose adapter for legacy consumers and removes the
    inverse transpose fanout consumers.
    """
    rewritten = 0
    binary_ops = {"ADD", "SUB", "MUL", "DIV"}
    preserve_layout_boundary_marker = "__preserve_layout_boundary__"

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)

        for mid_idx, mid_op in enumerate(model_ir.operators):
            if str(mid_op.op_type) not in binary_ops:
                continue
            if len(mid_op.inputs) != 2 or len(mid_op.outputs) != 1:
                continue

            in0_name = str(mid_op.inputs[0])
            in1_name = str(mid_op.inputs[1])
            out_name = str(mid_op.outputs[0])

            pre0_idx = producers.get(in0_name, None)
            pre1_idx = producers.get(in1_name, None)
            if pre0_idx is None or pre1_idx is None:
                continue
            pre0_op = model_ir.operators[int(pre0_idx)]
            pre1_op = model_ir.operators[int(pre1_idx)]
            if str(pre0_op.op_type) != "TRANSPOSE" or str(pre1_op.op_type) != "TRANSPOSE":
                continue
            if len(pre0_op.inputs) < 2 or len(pre1_op.inputs) < 2:
                continue
            if len(pre0_op.outputs) != 1 or len(pre1_op.outputs) != 1:
                continue
            if str(pre0_op.outputs[0]) != in0_name or str(pre1_op.outputs[0]) != in1_name:
                continue

            if set(consumers.get(in0_name, [])) != {int(mid_idx)}:
                continue
            if set(consumers.get(in1_name, [])) != {int(mid_idx)}:
                continue

            perm_pre0 = _read_transpose_perm(model_ir, pre0_op)
            perm_pre1 = _read_transpose_perm(model_ir, pre1_op)
            if perm_pre0 is None or perm_pre1 is None or perm_pre0 != perm_pre1:
                continue

            out_users = [int(v) for v in consumers.get(out_name, []) if int(v) != int(mid_idx)]
            if len(out_users) < 2:
                continue

            post_indices: List[int] = []
            post_output_names: List[str] = []
            legacy_users: List[int] = []
            valid = True
            for user_idx in out_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == out_name
                ):
                    perm_post = _read_transpose_perm(model_ir, user_op)
                    if perm_post is None or not _is_inverse_perm(perm_pre0, perm_post):
                        valid = False
                        break
                    post_indices.append(int(user_idx))
                    post_output_names.append(str(user_op.outputs[0]))
                else:
                    legacy_users.append(int(user_idx))

            if not valid:
                continue
            if len(post_indices) == 0 or len(legacy_users) == 0:
                continue

            if (
                in0_name in model_ir.outputs
                or in1_name in model_ir.outputs
                or out_name in model_ir.outputs
                or any(name in model_ir.outputs for name in post_output_names)
            ):
                continue

            raw_in0_name = str(pre0_op.inputs[0])
            raw_in1_name = str(pre1_op.inputs[0])
            raw_in0_tensor = model_ir.tensors.get(raw_in0_name, None)
            raw_in1_tensor = model_ir.tensors.get(raw_in1_name, None)
            in0_tensor = model_ir.tensors.get(in0_name, None)
            in1_tensor = model_ir.tensors.get(in1_name, None)
            out_tensor = model_ir.tensors.get(out_name, None)
            if not _all_per_tensor_quantized(
                [raw_in0_tensor, raw_in1_tensor, in0_tensor, in1_tensor, out_tensor]
            ):
                continue

            raw_shape0 = list(raw_in0_tensor.shape) if raw_in0_tensor is not None else None
            raw_shape1 = list(raw_in1_tensor.shape) if raw_in1_tensor is not None else None
            if not _shapes_match_if_known(raw_shape0, raw_shape1):
                continue
            in_shape0 = list(in0_tensor.shape) if in0_tensor is not None else None
            in_shape1 = list(in1_tensor.shape) if in1_tensor is not None else None
            if not _shapes_match_if_known(in_shape0, in_shape1):
                continue
            if not _is_unknown_shape(raw_shape0) and not _is_unknown_shape(in_shape0):
                expected_trans_shape = _permute_shape(raw_shape0, perm_pre0)
                if expected_trans_shape is None or not _shapes_equal(expected_trans_shape, in_shape0):
                    continue

            valid_post_shapes = True
            for post_output_name in post_output_names:
                post_tensor = model_ir.tensors.get(post_output_name, None)
                post_shape = list(post_tensor.shape) if post_tensor is not None else None
                if not _shapes_match_if_known(post_shape, raw_shape0):
                    valid_post_shapes = False
                    break
            if not valid_post_shapes:
                continue

            keep_post_idx = int(post_indices[0])
            keep_post_op = model_ir.operators[int(keep_post_idx)]
            canonical_raw_name = str(keep_post_op.outputs[0])
            keep_perm_name = str(keep_post_op.inputs[1])
            canonical_raw_tensor = model_ir.tensors.get(canonical_raw_name, None)

            _set_operator_inputs(
                model_ir=model_ir,
                op=mid_op,
                new_inputs=[raw_in0_name, raw_in1_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=mid_op,
                new_outputs=[canonical_raw_name],
            )

            if canonical_raw_tensor is not None and out_tensor is not None:
                canonical_raw_tensor.dtype = str(out_tensor.dtype)
                canonical_raw_tensor.quantization = _clone_quantization(out_tensor.quantization)
                if not _is_unknown_shape(raw_shape0):
                    canonical_raw_tensor.shape = [int(v) for v in list(raw_shape0)]
                    raw_sig0 = (
                        list(raw_in0_tensor.shape_signature)
                        if raw_in0_tensor is not None and raw_in0_tensor.shape_signature is not None
                        else list(raw_shape0)
                    )
                    canonical_raw_tensor.shape_signature = [int(v) for v in list(raw_sig0)]

            for post_output_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, post_output_name, canonical_raw_name)

            # Keep one adapter transpose for legacy consumers: raw -> original out layout.
            keep_post_opts = dict(keep_post_op.options) if isinstance(keep_post_op.options, dict) else {}
            keep_post_opts[preserve_layout_boundary_marker] = True
            keep_post_op.options = keep_post_opts
            keep_perm_tensor = model_ir.tensors.get(keep_perm_name, None)
            if keep_perm_tensor is not None:
                keep_perm_tensor.data = np.asarray(perm_pre0, dtype=np.int32)
            _set_operator_inputs(
                model_ir=model_ir,
                op=keep_post_op,
                new_inputs=[canonical_raw_name, keep_perm_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=keep_post_op,
                new_outputs=[out_name],
            )

            remove_indices = sorted(
                list(set([int(pre0_idx), int(pre1_idx)] + [int(idx) for idx in post_indices[1:]])),
                reverse=True,
            )
            for remove_idx in remove_indices:
                del model_ir.operators[remove_idx]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"rewritten_transpose_binary_mixed_fanout_bridges_safe": int(rewritten)}


def _optimize_transpose_binary_symmetric_legacy_only_bridges_safe(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold symmetric pre-transpose binary pattern when output has only legacy consumers.

    Pattern:
      T(P)(A), T(P)(B) -> C
      C -> legacy consumers only (no inverse-post transpose)

    Rewrite:
      A, B -> C_raw
      T(P)(C_raw) -> C

    Net effect: remove 2 pre-transposes and insert 1 adapter transpose.
    """
    rewritten = 0
    binary_ops = {"ADD", "SUB", "MUL", "DIV"}
    preserve_layout_boundary_marker = "__preserve_layout_boundary__"

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)

        for mid_idx, mid_op in enumerate(model_ir.operators):
            if str(mid_op.op_type) not in binary_ops:
                continue
            if len(mid_op.inputs) != 2 or len(mid_op.outputs) != 1:
                continue

            in0_name = str(mid_op.inputs[0])
            in1_name = str(mid_op.inputs[1])
            out_name = str(mid_op.outputs[0])

            pre0_idx = producers.get(in0_name, None)
            pre1_idx = producers.get(in1_name, None)
            if pre0_idx is None or pre1_idx is None:
                continue
            pre0_op = model_ir.operators[int(pre0_idx)]
            pre1_op = model_ir.operators[int(pre1_idx)]
            if str(pre0_op.op_type) != "TRANSPOSE" or str(pre1_op.op_type) != "TRANSPOSE":
                continue
            if len(pre0_op.inputs) < 2 or len(pre1_op.inputs) < 2:
                continue
            if len(pre0_op.outputs) != 1 or len(pre1_op.outputs) != 1:
                continue
            if str(pre0_op.outputs[0]) != in0_name or str(pre1_op.outputs[0]) != in1_name:
                continue

            if set(consumers.get(in0_name, [])) != {int(mid_idx)}:
                continue
            if set(consumers.get(in1_name, [])) != {int(mid_idx)}:
                continue

            perm_pre0 = _read_transpose_perm(model_ir, pre0_op)
            perm_pre1 = _read_transpose_perm(model_ir, pre1_op)
            if perm_pre0 is None or perm_pre1 is None or perm_pre0 != perm_pre1:
                continue

            out_users = [int(v) for v in consumers.get(out_name, []) if int(v) != int(mid_idx)]
            if len(out_users) == 0:
                continue

            # This pass targets legacy-only fanout; inverse post-transpose is handled elsewhere.
            has_inverse_post = False
            for user_idx in out_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == out_name
                ):
                    perm_post = _read_transpose_perm(model_ir, user_op)
                    if perm_post is not None and _is_inverse_perm(perm_pre0, perm_post):
                        has_inverse_post = True
                        break
            if has_inverse_post:
                continue

            if in0_name in model_ir.outputs or in1_name in model_ir.outputs:
                continue

            raw_in0_name = str(pre0_op.inputs[0])
            raw_in1_name = str(pre1_op.inputs[0])

            raw_in0_tensor = model_ir.tensors.get(raw_in0_name, None)
            raw_in1_tensor = model_ir.tensors.get(raw_in1_name, None)
            in0_tensor = model_ir.tensors.get(in0_name, None)
            in1_tensor = model_ir.tensors.get(in1_name, None)
            out_tensor = model_ir.tensors.get(out_name, None)
            if not _all_per_tensor_quantized(
                [raw_in0_tensor, raw_in1_tensor, in0_tensor, in1_tensor, out_tensor]
            ):
                continue

            raw_shape0 = list(raw_in0_tensor.shape) if raw_in0_tensor is not None else None
            raw_shape1 = list(raw_in1_tensor.shape) if raw_in1_tensor is not None else None
            if not _shapes_match_if_known(raw_shape0, raw_shape1):
                continue

            # Prepare raw output tensor.
            raw_out_name = f"{out_name}__raw"
            suffix = 1
            while raw_out_name in model_ir.tensors:
                raw_out_name = f"{out_name}__raw_{suffix}"
                suffix += 1

            raw_sig0 = (
                list(raw_in0_tensor.shape_signature)
                if raw_in0_tensor is not None and raw_in0_tensor.shape_signature is not None
                else raw_shape0
            )
            model_ir.tensors[raw_out_name] = TensorIR(
                name=raw_out_name,
                dtype=str(out_tensor.dtype) if out_tensor is not None else "INT8",
                shape=[int(v) for v in list(raw_shape0)] if not _is_unknown_shape(raw_shape0) else [1],
                shape_signature=(
                    [int(v) for v in list(raw_sig0)]
                    if raw_sig0 is not None and not _is_unknown_shape(raw_sig0)
                    else [1]
                ),
                data=None,
                is_variable=False,
                quantization=_clone_quantization(out_tensor.quantization if out_tensor is not None else None),
            )

            _set_operator_inputs(
                model_ir=model_ir,
                op=mid_op,
                new_inputs=[raw_in0_name, raw_in1_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=mid_op,
                new_outputs=[raw_out_name],
            )

            insert_at = min(out_users)
            remove_indices = sorted([int(pre0_idx), int(pre1_idx)], reverse=True)
            shift = sum(1 for idx in remove_indices if idx < insert_at)
            for idx in remove_indices:
                del model_ir.operators[idx]
            adjusted_insert_at = int(insert_at - shift)
            model_ir.operators.insert(
                adjusted_insert_at,
                OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[raw_out_name, str(pre0_op.inputs[1])],
                    outputs=[out_name],
                    options={preserve_layout_boundary_marker: True},
                ),
            )

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"rewritten_transpose_binary_symmetric_legacy_only_bridges_safe": int(rewritten)}


def _is_singleton_constant_tensor(
    model_ir: ModelIR,
    tensor_name: str,
) -> bool:
    tensor = model_ir.tensors.get(str(tensor_name), None)
    if tensor is None or tensor.data is None:
        return False
    try:
        array = np.asarray(tensor.data)
    except Exception:
        return False
    return int(array.size) == 1


def _read_singleton_constant_float(
    model_ir: ModelIR,
    tensor_name: str,
) -> Optional[float]:
    tensor = model_ir.tensors.get(str(tensor_name), None)
    if tensor is None or tensor.data is None:
        return None
    try:
        array = np.asarray(tensor.data)
    except Exception:
        return None
    if int(array.size) != 1:
        return None
    value = float(array.reshape(-1)[0])
    if not np.isfinite(value):
        return None
    return float(value)


def _optimize_maximum_minimum_relu0to1_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Replace clamp chains MAXIMUM(0.0) -> MINIMUM(1.0) with RELU_0_TO_1.

    Target:
      X --MAXIMUM(0.0)--> M --MINIMUM(1.0)--> Y

    Rewrite:
      X --RELU_0_TO_1--> Y

    Safety:
    - MAXIMUM and MINIMUM side inputs must be singleton constants.
    - MAXIMUM output must be consumed only by the matched MINIMUM.
    """
    rewritten = 0
    atol = 1e-6

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for min_idx, min_op in enumerate(model_ir.operators):
            if str(min_op.op_type) != "MINIMUM" or len(min_op.inputs) != 2 or len(min_op.outputs) != 1:
                continue

            min_input0 = str(min_op.inputs[0])
            min_input1 = str(min_op.inputs[1])
            if _is_singleton_constant_tensor(model_ir, min_input0):
                min_data_name = str(min_input1)
                min_const_name = str(min_input0)
            elif _is_singleton_constant_tensor(model_ir, min_input1):
                min_data_name = str(min_input0)
                min_const_name = str(min_input1)
            else:
                continue
            min_const_value = _read_singleton_constant_float(model_ir, min_const_name)
            if min_const_value is None or not np.isclose(float(min_const_value), 1.0, atol=atol):
                continue
            if min_data_name in model_outputs:
                continue

            max_idx = producers.get(min_data_name, None)
            if max_idx is None:
                continue
            max_op = model_ir.operators[int(max_idx)]
            if str(max_op.op_type) != "MAXIMUM" or len(max_op.inputs) != 2 or len(max_op.outputs) != 1:
                continue
            if str(max_op.outputs[0]) != str(min_data_name):
                continue

            max_input0 = str(max_op.inputs[0])
            max_input1 = str(max_op.inputs[1])
            if _is_singleton_constant_tensor(model_ir, max_input0):
                max_data_name = str(max_input1)
                max_const_name = str(max_input0)
            elif _is_singleton_constant_tensor(model_ir, max_input1):
                max_data_name = str(max_input0)
                max_const_name = str(max_input1)
            else:
                continue
            max_const_value = _read_singleton_constant_float(model_ir, max_const_name)
            if max_const_value is None or not np.isclose(float(max_const_value), 0.0, atol=atol):
                continue

            max_users = [int(v) for v in consumers.get(str(min_data_name), [])]
            if len(max_users) != 1 or int(max_users[0]) != int(min_idx):
                continue

            min_op.op_type = "RELU_0_TO_1"
            min_op.version = 1
            _set_operator_inputs(
                model_ir=model_ir,
                op=min_op,
                new_inputs=[str(max_data_name)],
            )
            min_op.options = {}

            del model_ir.operators[int(max_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"rewritten_maximum_minimum_relu0to1_chains": int(rewritten)}


def _optimize_fuse_pseudo_leakyrelu_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fuse pseudo-op-expanded LeakyReLU chain into single LEAKY_RELU op.

    Target:
      x --NEG--> n --RELU--> nr --MUL(alpha)--> m
      x --RELU--> p
      p --SUB(m)--> y
    """
    fused = 0

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for sub_idx, sub_op in enumerate(model_ir.operators):
            if str(sub_op.op_type) != "SUB" or len(sub_op.inputs) != 2 or len(sub_op.outputs) != 1:
                continue

            relu_pos_out_name = str(sub_op.inputs[0])
            mul_out_name = str(sub_op.inputs[1])
            output_name = str(sub_op.outputs[0])

            relu_pos_idx = producers.get(relu_pos_out_name, None)
            mul_idx = producers.get(mul_out_name, None)
            if relu_pos_idx is None or mul_idx is None:
                continue
            relu_pos_op = model_ir.operators[int(relu_pos_idx)]
            mul_op = model_ir.operators[int(mul_idx)]
            if str(relu_pos_op.op_type) != "RELU" or len(relu_pos_op.inputs) != 1 or len(relu_pos_op.outputs) != 1:
                continue
            if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                continue
            if str(relu_pos_op.outputs[0]) != relu_pos_out_name:
                continue
            if str(mul_op.outputs[0]) != mul_out_name:
                continue

            x_name = str(relu_pos_op.inputs[0])
            mul_input0 = str(mul_op.inputs[0])
            mul_input1 = str(mul_op.inputs[1])
            alpha_name: Optional[str] = None
            relu_neg_out_name: Optional[str] = None
            if _is_singleton_constant_tensor(model_ir, mul_input0):
                alpha_name = mul_input0
                relu_neg_out_name = mul_input1
            elif _is_singleton_constant_tensor(model_ir, mul_input1):
                alpha_name = mul_input1
                relu_neg_out_name = mul_input0
            if alpha_name is None or relu_neg_out_name is None:
                continue
            if relu_neg_out_name == relu_pos_out_name:
                continue

            alpha = _read_singleton_constant_float(model_ir, alpha_name)
            if alpha is None:
                continue

            relu_neg_idx = producers.get(relu_neg_out_name, None)
            if relu_neg_idx is None:
                continue
            relu_neg_op = model_ir.operators[int(relu_neg_idx)]
            if str(relu_neg_op.op_type) != "RELU" or len(relu_neg_op.inputs) != 1 or len(relu_neg_op.outputs) != 1:
                continue
            if str(relu_neg_op.outputs[0]) != relu_neg_out_name:
                continue

            neg_out_name = str(relu_neg_op.inputs[0])
            neg_idx = producers.get(neg_out_name, None)
            if neg_idx is None:
                continue
            neg_op = model_ir.operators[int(neg_idx)]
            if str(neg_op.op_type) != "NEG" or len(neg_op.inputs) != 1 or len(neg_op.outputs) != 1:
                continue
            if str(neg_op.outputs[0]) != neg_out_name:
                continue
            if str(neg_op.inputs[0]) != x_name:
                continue

            if any(
                name in model_outputs
                for name in [
                    relu_pos_out_name,
                    mul_out_name,
                    relu_neg_out_name,
                    neg_out_name,
                ]
            ):
                continue

            if [int(v) for v in consumers.get(relu_pos_out_name, [])] != [int(sub_idx)]:
                continue
            if [int(v) for v in consumers.get(mul_out_name, [])] != [int(sub_idx)]:
                continue
            if [int(v) for v in consumers.get(relu_neg_out_name, [])] != [int(mul_idx)]:
                continue
            if [int(v) for v in consumers.get(neg_out_name, [])] != [int(relu_neg_idx)]:
                continue

            x_tensor = model_ir.tensors.get(x_name, None)
            y_tensor = model_ir.tensors.get(output_name, None)
            if x_tensor is not None and y_tensor is not None:
                x_dtype = str(x_tensor.dtype).upper()
                y_dtype = str(y_tensor.dtype).upper()
                if not x_dtype.startswith("FLOAT") or not y_dtype.startswith("FLOAT"):
                    continue

            model_ir.operators[int(sub_idx)] = OperatorIR(
                op_type="LEAKY_RELU",
                inputs=[x_name],
                outputs=[output_name],
                options={"alpha": float(alpha)},
            )

            for remove_idx in sorted(
                [int(neg_idx), int(relu_neg_idx), int(mul_idx), int(relu_pos_idx)],
                reverse=True,
            ):
                del model_ir.operators[int(remove_idx)]

            fused += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"fused_pseudo_leakyrelu_chains": int(fused)}


def _permute_tensor_metadata_if_rank_matches(
    tensor: Optional[TensorIR],
    perm: List[int],
) -> None:
    if tensor is None:
        return
    shape_src = list(tensor.shape) if tensor.shape is not None else None
    if shape_src is not None and len(shape_src) == len(perm):
        new_shape = _permute_shape(shape_src, perm)
        if new_shape is not None:
            tensor.shape = [int(v) for v in list(new_shape)]
    signature_src = (
        list(tensor.shape_signature)
        if tensor.shape_signature is not None
        else (list(tensor.shape) if tensor.shape is not None else None)
    )
    if signature_src is not None and len(signature_src) == len(perm):
        new_signature = _permute_shape(signature_src, perm)
        if new_signature is not None:
            tensor.shape_signature = [int(v) for v in list(new_signature)]


def _optimize_leading_input_transpose_passthrough_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold leading input-boundary transpose chains through layout-agnostic ops.

    Target:
      X_in(NHWC) --T(P)--> X_ncx --(CAST|SUB|ADD|MUL|DIV|MAXIMUM|MINIMUM|ATAN2|QUANTIZE|DEQUANTIZE)*--> Y_ncx --T(inv(P))--> Y_nhwc
      X_in(NHWC) --T(P)--> X_ncx --(same chain)*--> Y_ncx (Y_ncx is model output)

    Rewrite:
      X_in(NHWC) --(same chain)*--> Y_nhwc

    Safety:
    - Leading transpose input must be a model input tensor.
    - Chain must be strictly linear (single-consumer on the main path).
    - Binary ops in the chain must use constant side inputs.
    - Quantization in the chain must remain per-tensor only.
    """
    rewritten = 0
    unary_passthrough_ops = {"CAST", "QUANTIZE", "DEQUANTIZE"}
    binary_passthrough_ops = {"ADD", "SUB", "MUL", "DIV", "MAXIMUM", "MINIMUM", "ATAN2"}

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_inputs = set(model_ir.inputs)
        model_outputs = set(model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE":
                continue
            if len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue

            pre_input_name = str(pre_op.inputs[0])
            if pre_input_name not in model_inputs:
                continue

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue
            perm_post_expected = _invert_perm(perm_pre)
            if perm_post_expected is None:
                continue

            pre_output_name = str(pre_op.outputs[0])
            if pre_output_name in model_outputs:
                continue

            # Build a strict linear passthrough chain.
            chain_indices: List[int] = []
            chain_ops: List[OperatorIR] = []
            chain_output_names: List[str] = []
            chain_main_input_index: Dict[int, int] = {}
            chain_binary_side_const_by_op: Dict[int, str] = {}
            current_tensor = pre_output_name
            while True:
                current_users = [int(v) for v in consumers.get(current_tensor, [])]
                if len(current_users) != 1:
                    break
                op_idx = int(current_users[0])
                op = model_ir.operators[op_idx]
                op_type = str(op.op_type)

                if op_type in unary_passthrough_ops:
                    if len(op.inputs) != 1 or len(op.outputs) != 1:
                        break
                    if str(op.inputs[0]) != current_tensor:
                        break
                    out_name = str(op.outputs[0])
                    out_tensor = model_ir.tensors.get(out_name, None)
                    if out_tensor is not None and not _is_per_tensor_quantization(out_tensor.quantization):
                        break
                    chain_indices.append(int(op_idx))
                    chain_ops.append(op)
                    chain_output_names.append(out_name)
                    current_tensor = out_name
                    if out_name in model_outputs:
                        break
                    continue

                if op_type in binary_passthrough_ops:
                    if len(op.inputs) != 2 or len(op.outputs) != 1:
                        break
                    input_0 = str(op.inputs[0])
                    input_1 = str(op.inputs[1])
                    if input_0 == current_tensor:
                        side_input_name = input_1
                    elif input_1 == current_tensor:
                        side_input_name = input_0
                    else:
                        break
                    side_tensor = model_ir.tensors.get(side_input_name, None)
                    if side_tensor is None or side_tensor.data is None:
                        break
                    side_array = np.asarray(side_tensor.data)
                    if int(side_array.size) != 1 and int(side_array.ndim) != int(len(perm_pre)):
                        break
                    if side_tensor is not None and not _is_per_tensor_quantization(side_tensor.quantization):
                        break
                    out_name = str(op.outputs[0])
                    out_tensor = model_ir.tensors.get(out_name, None)
                    if out_tensor is not None and not _is_per_tensor_quantization(out_tensor.quantization):
                        break
                    chain_indices.append(int(op_idx))
                    chain_ops.append(op)
                    chain_output_names.append(out_name)
                    chain_binary_side_const_by_op[int(op_idx)] = str(side_input_name)
                    current_tensor = out_name
                    if out_name in model_outputs:
                        break
                    continue

                break

            if len(chain_ops) == 0:
                continue

            # Chain must end with one inverse transpose or a model output.
            tail_users = [int(v) for v in consumers.get(current_tensor, [])]
            terminal_mode = ""
            post_idx: Optional[int] = None
            post_op: Optional[OperatorIR] = None
            post_output_name = ""
            if len(tail_users) == 1:
                post_idx = int(tail_users[0])
                if post_idx in set(chain_indices):
                    continue
                post_op = model_ir.operators[post_idx]
                if str(post_op.op_type) == "TRANSPOSE" and len(post_op.inputs) >= 2 and len(post_op.outputs) == 1:
                    if str(post_op.inputs[0]) == current_tensor:
                        perm_post = _read_transpose_perm(model_ir, post_op)
                        if perm_post is not None and perm_post == perm_post_expected:
                            terminal_mode = "inverse_post_transpose"
                            post_output_name = str(post_op.outputs[0])
            if terminal_mode == "" and current_tensor in model_outputs and len(tail_users) == 0:
                terminal_mode = "model_output"
                post_output_name = str(current_tensor)
            if terminal_mode == "":
                continue

            # Ensure chain topology remains linear on the main path.
            linear_ok = True
            previous_tensor_name = pre_output_name
            chain_index_to_pos = {int(idx): pos for pos, idx in enumerate(chain_indices)}
            for op_idx, op in zip(chain_indices, chain_ops):
                if previous_tensor_name not in set(str(v) for v in op.inputs):
                    linear_ok = False
                    break
                out_name = str(op.outputs[0]) if len(op.outputs) > 0 else ""
                if out_name == "":
                    linear_ok = False
                    break
                expected_users = [int(v) for v in consumers.get(out_name, [])]
                pos = int(chain_index_to_pos[int(op_idx)])
                if pos < len(chain_indices) - 1:
                    if expected_users != [int(chain_indices[pos + 1])]:
                        linear_ok = False
                        break
                else:
                    if terminal_mode == "inverse_post_transpose":
                        if post_idx is None or expected_users != [int(post_idx)]:
                            linear_ok = False
                            break
                    else:
                        if len(expected_users) != 0:
                            linear_ok = False
                            break
                previous_tensor_name = out_name
            if not linear_ok:
                continue

            old_last_name = str(chain_ops[-1].outputs[0])
            if terminal_mode == "inverse_post_transpose" and old_last_name in model_outputs:
                continue

            # Rewire chain head: consume model input directly.
            first_op = chain_ops[0]
            first_input_names = [str(v) for v in first_op.inputs]
            if first_input_names[0] == pre_output_name:
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=first_op,
                    new_inputs=[pre_input_name] + first_input_names[1:],
                )
            elif len(first_input_names) > 1 and first_input_names[1] == pre_output_name:
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=first_op,
                    new_inputs=[first_input_names[0], pre_input_name],
                )
            else:
                continue

            # Permute non-scalar side constants that carry NCX axis order.
            chain_index_set = set(int(v) for v in chain_indices)
            for op_idx, side_name in chain_binary_side_const_by_op.items():
                side_tensor = model_ir.tensors.get(str(side_name), None)
                if side_tensor is None or side_tensor.data is None:
                    continue
                side_array = np.asarray(side_tensor.data)
                if int(side_array.size) == 1 or int(side_array.ndim) != int(len(perm_post_expected)):
                    continue
                transposed_const = np.transpose(side_array, axes=perm_post_expected)
                side_users = [int(v) for v in consumers.get(str(side_name), [])]
                unique_to_chain = all(int(v) in chain_index_set for v in side_users)
                replacement_name = str(side_name)
                if unique_to_chain:
                    side_tensor.data = transposed_const
                    shape, signature = normalize_onnx_shape(list(transposed_const.shape))
                    side_tensor.shape = [int(v) for v in list(shape)]
                    side_tensor.shape_signature = [int(v) for v in list(signature)]
                else:
                    replacement_name = _unique_tensor_name(f"{side_name}_nhwc")
                    shape, signature = normalize_onnx_shape(list(transposed_const.shape))
                    model_ir.tensors[replacement_name] = TensorIR(
                        name=replacement_name,
                        dtype=str(side_tensor.dtype),
                        shape=[int(v) for v in list(shape)],
                        shape_signature=[int(v) for v in list(signature)],
                        data=transposed_const,
                        is_variable=False,
                        quantization=_clone_quantization(side_tensor.quantization),
                    )
                if replacement_name != str(side_name):
                    target_op = model_ir.operators[int(op_idx)]
                    _set_operator_inputs(
                        model_ir=model_ir,
                        op=target_op,
                        new_inputs=[
                            replacement_name if str(inp) == str(side_name) else str(inp)
                            for inp in list(target_op.inputs)
                        ],
                    )

            # Chain tail now produces post-transpose output name directly.
            if terminal_mode == "inverse_post_transpose":
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=chain_ops[-1],
                    new_outputs=[post_output_name],
                )

            # Update metadata to NHWC-side layout.
            for out_name in chain_output_names[:-1]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(out_name, None),
                    perm_post_expected,
                )
            if terminal_mode == "inverse_post_transpose":
                old_last_tensor = model_ir.tensors.get(old_last_name, None)
                post_output_tensor = model_ir.tensors.get(post_output_name, None)
                if post_output_tensor is not None and old_last_tensor is not None:
                    post_output_tensor.dtype = str(old_last_tensor.dtype)
                    post_output_tensor.quantization = _clone_quantization(old_last_tensor.quantization)
                    _permute_tensor_metadata_if_rank_matches(
                        post_output_tensor,
                        perm_post_expected,
                    )
            else:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(post_output_name, None),
                    perm_post_expected,
                )

            # Remove boundary transposes.
            remove_set = {int(pre_idx)}
            if terminal_mode == "inverse_post_transpose" and post_idx is not None:
                remove_set.add(int(post_idx))
            remove_indices = sorted(list(remove_set), reverse=True)
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"rewritten_leading_input_transpose_passthrough_chains": int(rewritten)}


def _optimize_hardswish_transpose_passthrough_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose wrappers around pseudo-op-expanded HardSwish chains.

    Target:
      X --TRANSPOSE(P)--> x_t
      x_t --ADD(c3)--> a --RELU6--> r --DIV(c6)--> d
      MUL(x_t, d) --> y_t
      y_t --TRANSPOSE(inv(P))--> Y

    Rewrite:
      X --ADD(c3)--> a --RELU6--> r --DIV(c6)--> d
      MUL(X, d) --> Y

    Safety:
    - Strict HardSwish topology (ADD->RELU6->DIV with residual MUL input).
    - ADD/DIV side inputs must be singleton constants.
    - Single-consumer chain on the main path.
    """
    rewritten = 0

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE":
                continue
            if len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue
            perm_post_expected = _invert_perm(perm_pre)
            if perm_post_expected is None:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) != 2:
                continue

            add_idx = None
            mul_idx = None
            for user_idx in pre_users:
                user_op = model_ir.operators[int(user_idx)]
                user_type = str(user_op.op_type)
                if user_type == "ADD":
                    add_idx = int(user_idx)
                elif user_type == "MUL":
                    mul_idx = int(user_idx)
            if add_idx is None or mul_idx is None:
                continue

            add_op = model_ir.operators[int(add_idx)]
            if len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                continue
            add_inputs = [str(v) for v in add_op.inputs]
            if pre_output_name == add_inputs[0]:
                add_data_input_index = 0
                add_side_input_name = add_inputs[1]
            elif pre_output_name == add_inputs[1]:
                add_data_input_index = 1
                add_side_input_name = add_inputs[0]
            else:
                continue
            if not _is_singleton_constant_tensor(model_ir, add_side_input_name):
                continue
            add_out_name = str(add_op.outputs[0])

            add_users = [int(v) for v in consumers.get(add_out_name, [])]
            if len(add_users) != 1:
                continue
            relu_idx = int(add_users[0])
            relu_op = model_ir.operators[int(relu_idx)]
            if str(relu_op.op_type) != "RELU6" or len(relu_op.inputs) != 1 or len(relu_op.outputs) != 1:
                continue
            if str(relu_op.inputs[0]) != add_out_name:
                continue
            relu_out_name = str(relu_op.outputs[0])

            relu_users = [int(v) for v in consumers.get(relu_out_name, [])]
            if len(relu_users) != 1:
                continue
            div_idx = int(relu_users[0])
            div_op = model_ir.operators[int(div_idx)]
            if str(div_op.op_type) != "DIV" or len(div_op.inputs) != 2 or len(div_op.outputs) != 1:
                continue
            div_inputs = [str(v) for v in div_op.inputs]
            if relu_out_name == div_inputs[0]:
                div_side_input_name = div_inputs[1]
            elif relu_out_name == div_inputs[1]:
                div_side_input_name = div_inputs[0]
            else:
                continue
            if not _is_singleton_constant_tensor(model_ir, div_side_input_name):
                continue
            div_out_name = str(div_op.outputs[0])

            div_users = [int(v) for v in consumers.get(div_out_name, [])]
            if len(div_users) != 1 or int(div_users[0]) != int(mul_idx):
                continue

            mul_op = model_ir.operators[int(mul_idx)]
            if len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                continue
            mul_inputs = [str(v) for v in mul_op.inputs]
            if pre_output_name == mul_inputs[0] and div_out_name == mul_inputs[1]:
                mul_data_input_index = 0
            elif pre_output_name == mul_inputs[1] and div_out_name == mul_inputs[0]:
                mul_data_input_index = 1
            else:
                continue
            mul_out_name = str(mul_op.outputs[0])

            mul_users = [int(v) for v in consumers.get(mul_out_name, [])]
            if len(mul_users) != 1:
                continue
            post_idx = int(mul_users[0])
            post_op = model_ir.operators[int(post_idx)]
            if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                continue
            if str(post_op.inputs[0]) != mul_out_name:
                continue
            perm_post = _read_transpose_perm(model_ir, post_op)
            if perm_post is None or perm_post != perm_post_expected:
                continue
            post_output_name = str(post_op.outputs[0])

            # Rewire the pseudo-HardSwish chain to consume NHWC source directly.
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add_op,
                input_index=int(add_data_input_index),
                new_input_name=pre_input_name,
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul_op,
                input_index=int(mul_data_input_index),
                new_input_name=pre_input_name,
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=mul_op,
                new_outputs=[post_output_name],
            )

            # Update intermediate metadata from transposed layout to source layout.
            for intermediate_name in [add_out_name, relu_out_name, div_out_name]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(intermediate_name, None),
                    perm_post_expected,
                )

            # Keep final tensor metadata stable on the post-transpose name.
            pre_input_tensor = model_ir.tensors.get(pre_input_name, None)
            old_mul_tensor = model_ir.tensors.get(mul_out_name, None)
            post_output_tensor = model_ir.tensors.get(post_output_name, None)
            if post_output_tensor is not None:
                if pre_input_tensor is not None:
                    post_output_tensor.shape = [int(v) for v in list(pre_input_tensor.shape)]
                    post_output_tensor.shape_signature = (
                        [int(v) for v in list(pre_input_tensor.shape_signature)]
                        if pre_input_tensor.shape_signature is not None
                        else [int(v) for v in list(pre_input_tensor.shape)]
                    )
                if old_mul_tensor is not None:
                    post_output_tensor.dtype = str(old_mul_tensor.dtype)
                    post_output_tensor.quantization = _clone_quantization(old_mul_tensor.quantization)

            remove_indices = sorted(list({int(pre_idx), int(post_idx)}), reverse=True)
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"rewritten_hardswish_transpose_passthrough_chains": int(rewritten)}


def _optimize_hardsigmoid_mul_transpose_passthrough_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose wrappers around HardSigmoid-expanded residual MUL chains.

    Target:
      X --TRANSPOSE(P)--> x_t
      x_t --MUL(alpha)--> m1 --ADD(beta)--> a1 --(MAXIMUM(0)->MINIMUM(1) | RELU_0_TO_1)--> h1
      MUL(x_t, h1) --> y_t
      y_t --TRANSPOSE(inv(P))--> Y

    Rewrite:
      X --MUL(alpha)--> m1 --ADD(beta)--> a1 --(MAXIMUM(0)->MINIMUM(1) | RELU_0_TO_1)--> h1
      MUL(X, h1) --> Y

    Safety:
    - Strict HardSigmoid decomposition topology on one branch.
    - HardSigmoid branch constants must be singleton constants.
    - Chain on the HardSigmoid branch must be linear.
    """
    rewritten = 0

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE":
                continue
            if len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue
            perm_post_expected = _invert_perm(perm_pre)
            if perm_post_expected is None:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) != 2:
                continue

            def _try_match_pair(hs_mul_idx: int, residual_mul_idx: int) -> Optional[Dict[str, Any]]:
                hs_mul_op = model_ir.operators[int(hs_mul_idx)]
                if str(hs_mul_op.op_type) != "MUL" or len(hs_mul_op.inputs) != 2 or len(hs_mul_op.outputs) != 1:
                    return None
                hs_mul_inputs = [str(v) for v in list(hs_mul_op.inputs)]
                if pre_output_name == hs_mul_inputs[0]:
                    hs_mul_data_input_index = 0
                    hs_mul_side_name = hs_mul_inputs[1]
                elif pre_output_name == hs_mul_inputs[1]:
                    hs_mul_data_input_index = 1
                    hs_mul_side_name = hs_mul_inputs[0]
                else:
                    return None
                if not _is_singleton_constant_tensor(model_ir, hs_mul_side_name):
                    return None
                hs_mul_out_name = str(hs_mul_op.outputs[0])

                hs_mul_users = [int(v) for v in consumers.get(hs_mul_out_name, [])]
                if len(hs_mul_users) != 1:
                    return None
                hs_add_idx = int(hs_mul_users[0])
                hs_add_op = model_ir.operators[int(hs_add_idx)]
                if str(hs_add_op.op_type) != "ADD" or len(hs_add_op.inputs) != 2 or len(hs_add_op.outputs) != 1:
                    return None
                hs_add_inputs = [str(v) for v in list(hs_add_op.inputs)]
                if hs_mul_out_name == hs_add_inputs[0]:
                    hs_add_side_name = hs_add_inputs[1]
                elif hs_mul_out_name == hs_add_inputs[1]:
                    hs_add_side_name = hs_add_inputs[0]
                else:
                    return None
                if not _is_singleton_constant_tensor(model_ir, hs_add_side_name):
                    return None
                hs_add_out_name = str(hs_add_op.outputs[0])

                hs_add_users = [int(v) for v in consumers.get(hs_add_out_name, [])]
                if len(hs_add_users) != 1:
                    return None
                hs_clamp_idx = int(hs_add_users[0])
                hs_clamp_op = model_ir.operators[int(hs_clamp_idx)]
                hs_intermediate_names: List[str] = [str(hs_mul_out_name), str(hs_add_out_name)]
                if (
                    str(hs_clamp_op.op_type) == "RELU_0_TO_1"
                    and len(hs_clamp_op.inputs) == 1
                    and len(hs_clamp_op.outputs) == 1
                    and str(hs_clamp_op.inputs[0]) == hs_add_out_name
                ):
                    hs_out_name = str(hs_clamp_op.outputs[0])
                else:
                    if str(hs_clamp_op.op_type) != "MAXIMUM" or len(hs_clamp_op.inputs) != 2 or len(hs_clamp_op.outputs) != 1:
                        return None
                    hs_max_inputs = [str(v) for v in list(hs_clamp_op.inputs)]
                    if hs_add_out_name == hs_max_inputs[0]:
                        hs_max_side_name = hs_max_inputs[1]
                    elif hs_add_out_name == hs_max_inputs[1]:
                        hs_max_side_name = hs_max_inputs[0]
                    else:
                        return None
                    if not _is_singleton_constant_tensor(model_ir, hs_max_side_name):
                        return None
                    hs_max_out_name = str(hs_clamp_op.outputs[0])
                    hs_intermediate_names.append(str(hs_max_out_name))

                    hs_max_users = [int(v) for v in consumers.get(hs_max_out_name, [])]
                    if len(hs_max_users) != 1:
                        return None
                    hs_min_idx = int(hs_max_users[0])
                    hs_min_op = model_ir.operators[int(hs_min_idx)]
                    if str(hs_min_op.op_type) != "MINIMUM" or len(hs_min_op.inputs) != 2 or len(hs_min_op.outputs) != 1:
                        return None
                    hs_min_inputs = [str(v) for v in list(hs_min_op.inputs)]
                    if hs_max_out_name == hs_min_inputs[0]:
                        hs_min_side_name = hs_min_inputs[1]
                    elif hs_max_out_name == hs_min_inputs[1]:
                        hs_min_side_name = hs_min_inputs[0]
                    else:
                        return None
                    if not _is_singleton_constant_tensor(model_ir, hs_min_side_name):
                        return None
                    hs_out_name = str(hs_min_op.outputs[0])

                residual_mul_op = model_ir.operators[int(residual_mul_idx)]
                if (
                    str(residual_mul_op.op_type) != "MUL"
                    or len(residual_mul_op.inputs) != 2
                    or len(residual_mul_op.outputs) != 1
                ):
                    return None
                residual_mul_inputs = [str(v) for v in list(residual_mul_op.inputs)]
                if pre_output_name == residual_mul_inputs[0] and hs_out_name == residual_mul_inputs[1]:
                    residual_mul_data_input_index = 0
                elif pre_output_name == residual_mul_inputs[1] and hs_out_name == residual_mul_inputs[0]:
                    residual_mul_data_input_index = 1
                else:
                    return None
                residual_mul_out_name = str(residual_mul_op.outputs[0])
                residual_mul_users = [int(v) for v in consumers.get(residual_mul_out_name, []) if int(v) != int(residual_mul_idx)]
                if len(residual_mul_users) == 0:
                    return None

                post_indices: List[int] = []
                post_output_names: List[str] = []
                legacy_users: List[int] = []
                valid_users = True
                for user_idx in residual_mul_users:
                    user_op = model_ir.operators[int(user_idx)]
                    if (
                        str(user_op.op_type) == "TRANSPOSE"
                        and len(user_op.inputs) >= 2
                        and len(user_op.outputs) == 1
                        and str(user_op.inputs[0]) == residual_mul_out_name
                    ):
                        perm_post = _read_transpose_perm(model_ir, user_op)
                        if perm_post is None or perm_post != perm_post_expected:
                            valid_users = False
                            break
                        post_indices.append(int(user_idx))
                        post_output_names.append(str(user_op.outputs[0]))
                    else:
                        legacy_users.append(int(user_idx))
                if not valid_users or len(post_indices) == 0:
                    return None

                return {
                    "hs_mul_idx": int(hs_mul_idx),
                    "hs_mul_data_input_index": int(hs_mul_data_input_index),
                    "hs_intermediate_names": [str(v) for v in hs_intermediate_names],
                    "residual_mul_idx": int(residual_mul_idx),
                    "residual_mul_data_input_index": int(residual_mul_data_input_index),
                    "residual_mul_out_name": str(residual_mul_out_name),
                    "post_indices": [int(v) for v in post_indices],
                    "post_output_names": [str(v) for v in post_output_names],
                    "legacy_users": [int(v) for v in legacy_users],
                }

            matched = _try_match_pair(int(pre_users[0]), int(pre_users[1]))
            if matched is None:
                matched = _try_match_pair(int(pre_users[1]), int(pre_users[0]))
            if matched is None:
                continue

            hs_mul_op = model_ir.operators[int(matched["hs_mul_idx"])]
            residual_mul_op = model_ir.operators[int(matched["residual_mul_idx"])]
            residual_mul_out_name = str(matched["residual_mul_out_name"])
            post_indices = [int(v) for v in list(matched.get("post_indices", []))]
            post_output_names = [str(v) for v in list(matched.get("post_output_names", []))]
            legacy_users = [int(v) for v in list(matched.get("legacy_users", []))]
            if len(post_indices) == 0 or len(post_output_names) == 0:
                continue
            representative_output_name = str(post_output_names[0])

            _replace_operator_input_at(
                model_ir=model_ir,
                op=hs_mul_op,
                input_index=int(matched["hs_mul_data_input_index"]),
                new_input_name=pre_input_name,
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=residual_mul_op,
                input_index=int(matched["residual_mul_data_input_index"]),
                new_input_name=pre_input_name,
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=residual_mul_op,
                new_outputs=[representative_output_name],
            )
            for alias_output_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, alias_output_name, representative_output_name)

            for intermediate_name in [str(v) for v in list(matched.get("hs_intermediate_names", []))]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(intermediate_name, None),
                    perm_post_expected,
                )

            old_mul_tensor = model_ir.tensors.get(residual_mul_out_name, None)
            representative_tensor = model_ir.tensors.get(representative_output_name, None)
            if representative_tensor is not None and old_mul_tensor is not None:
                representative_tensor.dtype = str(old_mul_tensor.dtype)
                representative_tensor.quantization = _clone_quantization(old_mul_tensor.quantization)
                _permute_tensor_metadata_if_rank_matches(
                    representative_tensor,
                    perm_post_expected,
                )

            preserve_nchw_adapter = len(legacy_users) > 0 or residual_mul_out_name in model_ir.outputs
            if preserve_nchw_adapter:
                keep_post_idx = int(post_indices[0])
                keep_post_op = model_ir.operators[keep_post_idx]
                keep_perm_name = str(keep_post_op.inputs[1])
                keep_perm_tensor = model_ir.tensors.get(keep_perm_name, None)
                if keep_perm_tensor is not None:
                    keep_perm_tensor.data = np.asarray(perm_pre, dtype=np.int32)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_inputs=[representative_output_name, keep_perm_name],
                )
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_outputs=[residual_mul_out_name],
                )
                post_remove_indices = [int(v) for v in post_indices[1:]]
            else:
                post_remove_indices = [int(v) for v in post_indices]

            remove_indices = sorted(list({int(pre_idx), *post_remove_indices}), reverse=True)
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"rewritten_hardsigmoid_mul_transpose_passthrough_chains": int(rewritten)}


def _optimize_hardsigmoid_transpose_passthrough_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose wrappers around standalone HardSigmoid-expanded chains.

    Target:
      X --TRANSPOSE(P)--> x_t
      x_t --MUL(alpha)--> m1 --ADD(beta)--> a1 --(MAXIMUM(0)->MINIMUM(1) | RELU_0_TO_1)--> h1
      h1 --TRANSPOSE(inv(P))--> Y

    Rewrite:
      X --MUL(alpha)--> m1 --ADD(beta)--> a1 --(MAXIMUM(0)->MINIMUM(1) | RELU_0_TO_1)--> Y

    Safety:
    - Strict HardSigmoid decomposition topology.
    - All side inputs must be singleton constants.
    - Main branch must be strictly linear.
    """
    rewritten = 0

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE":
                continue
            if len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue
            perm_post_expected = _invert_perm(perm_pre)
            if perm_post_expected is None:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) != 1:
                continue
            hs_mul_idx = int(pre_users[0])
            hs_mul_op = model_ir.operators[int(hs_mul_idx)]
            if str(hs_mul_op.op_type) != "MUL" or len(hs_mul_op.inputs) != 2 or len(hs_mul_op.outputs) != 1:
                continue

            hs_mul_inputs = [str(v) for v in list(hs_mul_op.inputs)]
            if pre_output_name == hs_mul_inputs[0]:
                hs_mul_data_input_index = 0
                hs_mul_side_name = hs_mul_inputs[1]
            elif pre_output_name == hs_mul_inputs[1]:
                hs_mul_data_input_index = 1
                hs_mul_side_name = hs_mul_inputs[0]
            else:
                continue
            if not _is_singleton_constant_tensor(model_ir, hs_mul_side_name):
                continue
            hs_mul_out_name = str(hs_mul_op.outputs[0])

            hs_mul_users = [int(v) for v in consumers.get(hs_mul_out_name, [])]
            if len(hs_mul_users) != 1:
                continue
            hs_add_idx = int(hs_mul_users[0])
            hs_add_op = model_ir.operators[int(hs_add_idx)]
            if str(hs_add_op.op_type) != "ADD" or len(hs_add_op.inputs) != 2 or len(hs_add_op.outputs) != 1:
                continue
            hs_add_inputs = [str(v) for v in list(hs_add_op.inputs)]
            if hs_mul_out_name == hs_add_inputs[0]:
                hs_add_side_name = hs_add_inputs[1]
            elif hs_mul_out_name == hs_add_inputs[1]:
                hs_add_side_name = hs_add_inputs[0]
            else:
                continue
            if not _is_singleton_constant_tensor(model_ir, hs_add_side_name):
                continue
            hs_add_out_name = str(hs_add_op.outputs[0])

            hs_add_users = [int(v) for v in consumers.get(hs_add_out_name, [])]
            if len(hs_add_users) != 1:
                continue
            hs_clamp_idx = int(hs_add_users[0])
            hs_clamp_op = model_ir.operators[int(hs_clamp_idx)]
            hs_intermediate_names: List[str] = [str(hs_mul_out_name), str(hs_add_out_name)]
            if (
                str(hs_clamp_op.op_type) == "RELU_0_TO_1"
                and len(hs_clamp_op.inputs) == 1
                and len(hs_clamp_op.outputs) == 1
                and str(hs_clamp_op.inputs[0]) == hs_add_out_name
            ):
                hs_terminal_op = hs_clamp_op
                hs_out_name = str(hs_clamp_op.outputs[0])
            else:
                if str(hs_clamp_op.op_type) != "MAXIMUM" or len(hs_clamp_op.inputs) != 2 or len(hs_clamp_op.outputs) != 1:
                    continue
                hs_max_inputs = [str(v) for v in list(hs_clamp_op.inputs)]
                if hs_add_out_name == hs_max_inputs[0]:
                    hs_max_side_name = hs_max_inputs[1]
                elif hs_add_out_name == hs_max_inputs[1]:
                    hs_max_side_name = hs_max_inputs[0]
                else:
                    continue
                if not _is_singleton_constant_tensor(model_ir, hs_max_side_name):
                    continue
                hs_max_out_name = str(hs_clamp_op.outputs[0])
                hs_intermediate_names.append(str(hs_max_out_name))

                hs_max_users = [int(v) for v in consumers.get(hs_max_out_name, [])]
                if len(hs_max_users) != 1:
                    continue
                hs_min_idx = int(hs_max_users[0])
                hs_min_op = model_ir.operators[int(hs_min_idx)]
                if str(hs_min_op.op_type) != "MINIMUM" or len(hs_min_op.inputs) != 2 or len(hs_min_op.outputs) != 1:
                    continue
                hs_min_inputs = [str(v) for v in list(hs_min_op.inputs)]
                if hs_max_out_name == hs_min_inputs[0]:
                    hs_min_side_name = hs_min_inputs[1]
                elif hs_max_out_name == hs_min_inputs[1]:
                    hs_min_side_name = hs_min_inputs[0]
                else:
                    continue
                if not _is_singleton_constant_tensor(model_ir, hs_min_side_name):
                    continue
                hs_terminal_op = hs_min_op
                hs_out_name = str(hs_min_op.outputs[0])

            hs_out_users = [int(v) for v in consumers.get(hs_out_name, [])]
            if len(hs_out_users) != 1:
                continue
            post_idx = int(hs_out_users[0])
            post_op = model_ir.operators[int(post_idx)]
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or str(post_op.inputs[0]) != hs_out_name
            ):
                continue
            perm_post = _read_transpose_perm(model_ir, post_op)
            if perm_post is None or perm_post != perm_post_expected:
                continue
            post_output_name = str(post_op.outputs[0])

            _replace_operator_input_at(
                model_ir=model_ir,
                op=hs_mul_op,
                input_index=int(hs_mul_data_input_index),
                new_input_name=pre_input_name,
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=hs_terminal_op,
                new_outputs=[post_output_name],
            )

            for intermediate_name in hs_intermediate_names:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(intermediate_name, None),
                    perm_post_expected,
                )

            old_hs_tensor = model_ir.tensors.get(hs_out_name, None)
            post_output_tensor = model_ir.tensors.get(post_output_name, None)
            if post_output_tensor is not None and old_hs_tensor is not None:
                post_output_tensor.dtype = str(old_hs_tensor.dtype)
                post_output_tensor.quantization = _clone_quantization(old_hs_tensor.quantization)
                _permute_tensor_metadata_if_rank_matches(
                    post_output_tensor,
                    perm_post_expected,
                )

            remove_indices = sorted(list({int(pre_idx), int(post_idx)}), reverse=True)
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"rewritten_hardsigmoid_transpose_passthrough_chains": int(rewritten)}


def _optimize_swish_transpose_passthrough_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose wrappers around pseudo-op-expanded Swish chains.

    Target:
      X --TRANSPOSE(P)--> x_t
      x_t --LOGISTIC--> s_t
      MUL(x_t, s_t) --> y_t
      y_t --TRANSPOSE(inv(P))--> Y

    Rewrite:
      X --LOGISTIC--> s
      MUL(X, s) --> Y

    Safety:
    - Strict Swish topology (LOGISTIC + residual MUL input).
    - LOGISTIC output must be consumed only by the MUL.
    - Requires at least one inverse post-transpose consumer.
    """
    rewritten = 0

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE":
                continue
            if len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_output_name in model_outputs:
                continue

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue
            perm_post_expected = _invert_perm(perm_pre)
            if perm_post_expected is None:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) != 2:
                continue

            log_idx = None
            mul_idx = None
            for user_idx in pre_users:
                user_op = model_ir.operators[int(user_idx)]
                user_type = str(user_op.op_type)
                if (
                    user_type == "LOGISTIC"
                    and len(user_op.inputs) == 1
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == pre_output_name
                ):
                    log_idx = int(user_idx)
                elif user_type == "MUL":
                    mul_idx = int(user_idx)
            if log_idx is None or mul_idx is None:
                continue

            log_op = model_ir.operators[int(log_idx)]
            log_out_name = str(log_op.outputs[0])
            log_users = [int(v) for v in consumers.get(log_out_name, [])]
            if len(log_users) != 1 or int(log_users[0]) != int(mul_idx):
                continue

            mul_op = model_ir.operators[int(mul_idx)]
            if len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                continue
            mul_inputs = [str(v) for v in mul_op.inputs]
            if mul_inputs[0] == pre_output_name and mul_inputs[1] == log_out_name:
                mul_data_input_index = 0
            elif mul_inputs[1] == pre_output_name and mul_inputs[0] == log_out_name:
                mul_data_input_index = 1
            else:
                continue

            mul_out_name = str(mul_op.outputs[0])
            mul_users = [int(v) for v in consumers.get(mul_out_name, []) if int(v) != int(mul_idx)]
            if len(mul_users) == 0:
                continue

            post_indices: List[int] = []
            post_output_names: List[str] = []
            legacy_users: List[int] = []
            valid_users = True
            for user_idx in mul_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == mul_out_name
                ):
                    perm_post = _read_transpose_perm(model_ir, user_op)
                    if perm_post is None or perm_post != perm_post_expected:
                        valid_users = False
                        break
                    post_output_name = str(user_op.outputs[0])
                    if post_output_name in model_outputs:
                        valid_users = False
                        break
                    post_indices.append(int(user_idx))
                    post_output_names.append(post_output_name)
                else:
                    legacy_users.append(int(user_idx))
            if not valid_users or len(post_indices) == 0:
                continue

            representative_output_name = str(post_output_names[0])

            _set_operator_inputs(
                model_ir=model_ir,
                op=log_op,
                new_inputs=[pre_input_name],
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul_op,
                input_index=int(mul_data_input_index),
                new_input_name=pre_input_name,
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=mul_op,
                new_outputs=[representative_output_name],
            )
            for alias_output_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, alias_output_name, representative_output_name)

            # LOGISTIC is layout-agnostic; update metadata from transposed to source layout.
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(log_out_name, None),
                perm_post_expected,
            )

            old_mul_tensor = model_ir.tensors.get(mul_out_name, None)
            representative_tensor = model_ir.tensors.get(representative_output_name, None)
            if old_mul_tensor is not None and representative_tensor is not None:
                representative_tensor.dtype = str(old_mul_tensor.dtype)
                representative_tensor.quantization = _clone_quantization(old_mul_tensor.quantization)
                representative_tensor.shape = [int(v) for v in list(old_mul_tensor.shape)]
                representative_tensor.shape_signature = (
                    [int(v) for v in list(old_mul_tensor.shape_signature)]
                    if old_mul_tensor.shape_signature is not None
                    else [int(v) for v in list(old_mul_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    representative_tensor,
                    perm_post_expected,
                )

            preserve_nchw_adapter = len(legacy_users) > 0 or mul_out_name in model_outputs
            if preserve_nchw_adapter:
                keep_post_idx = int(post_indices[0])
                keep_post_op = model_ir.operators[keep_post_idx]
                keep_perm_name = str(keep_post_op.inputs[1])
                keep_perm_tensor = model_ir.tensors.get(keep_perm_name, None)
                if keep_perm_tensor is not None:
                    keep_perm_tensor.data = np.asarray(perm_pre, dtype=np.int32)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_inputs=[representative_output_name, keep_perm_name],
                )
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_outputs=[mul_out_name],
                )
                post_remove_indices = [int(v) for v in post_indices[1:]]
            else:
                post_remove_indices = [int(v) for v in post_indices]

            remove_indices = sorted(list({int(pre_idx), *post_remove_indices}), reverse=True)
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"rewritten_swish_transpose_passthrough_chains": int(rewritten)}


def _optimize_gelu_tanh_transpose_passthrough_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose wrappers around tanh-approx GELU expansion chains.

    Target:
      X --TRANSPOSE(P)--> x_t
      m2 = MUL(MUL(x_t, x_t), x_t)
      t0 = MUL(m2, c0)
      t1 = ADD(x_t, t0)
      t2 = MUL(t1, c1)
      t3 = TANH(t2)
      t4 = ADD(t3, c2)
      t5 = MUL(x_t, t4)
      y_t = MUL(t5, c3)
      y_t --TRANSPOSE(inv(P))--> Y

    Rewrite:
      Same chain with x_t replaced by X and Y produced directly from final MUL.

    Safety:
    - Requires exact tanh-GELU topology with scalar-like constants c0..c3.
    - Final GELU output must be consumed by inverse post-transpose adapters only.
    """
    rewritten = 0

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_output_name in model_outputs:
                continue

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue
            perm_post_expected = _invert_perm(perm_pre)
            if perm_post_expected is None:
                continue

            pre_users = sorted(list(set(int(v) for v in consumers.get(pre_output_name, []))))
            if len(pre_users) == 0:
                continue

            gelu_match_found = False
            for msq_idx in pre_users:
                msq_op = model_ir.operators[int(msq_idx)]
                if str(msq_op.op_type) != "MUL" or len(msq_op.inputs) != 2 or len(msq_op.outputs) != 1:
                    continue
                if not (str(msq_op.inputs[0]) == pre_output_name and str(msq_op.inputs[1]) == pre_output_name):
                    continue
                msq_out_name = str(msq_op.outputs[0])
                msq_users = [int(v) for v in consumers.get(msq_out_name, [])]
                if len(msq_users) != 1:
                    continue

                mcube_idx = int(msq_users[0])
                mcube_op = model_ir.operators[int(mcube_idx)]
                if str(mcube_op.op_type) != "MUL" or len(mcube_op.inputs) != 2 or len(mcube_op.outputs) != 1:
                    continue
                mcube_inputs = [str(v) for v in mcube_op.inputs]
                if pre_output_name == mcube_inputs[0] and msq_out_name == mcube_inputs[1]:
                    pass
                elif pre_output_name == mcube_inputs[1] and msq_out_name == mcube_inputs[0]:
                    pass
                else:
                    continue
                mcube_out_name = str(mcube_op.outputs[0])

                m1_users = [int(v) for v in consumers.get(mcube_out_name, [])]
                if len(m1_users) != 1:
                    continue
                m1_idx = int(m1_users[0])
                m1_op = model_ir.operators[int(m1_idx)]
                if str(m1_op.op_type) != "MUL" or len(m1_op.inputs) != 2 or len(m1_op.outputs) != 1:
                    continue
                m1_inputs = [str(v) for v in m1_op.inputs]
                if m1_inputs[0] == mcube_out_name:
                    m1_side_name = m1_inputs[1]
                elif m1_inputs[1] == mcube_out_name:
                    m1_side_name = m1_inputs[0]
                else:
                    continue
                if not _is_singleton_constant_tensor(model_ir, m1_side_name):
                    continue
                m1_out_name = str(m1_op.outputs[0])

                add1_users = [int(v) for v in consumers.get(m1_out_name, [])]
                if len(add1_users) != 1:
                    continue
                add1_idx = int(add1_users[0])
                add1_op = model_ir.operators[int(add1_idx)]
                if str(add1_op.op_type) != "ADD" or len(add1_op.inputs) != 2 or len(add1_op.outputs) != 1:
                    continue
                add1_inputs = [str(v) for v in add1_op.inputs]
                if pre_output_name == add1_inputs[0] and m1_out_name == add1_inputs[1]:
                    pass
                elif pre_output_name == add1_inputs[1] and m1_out_name == add1_inputs[0]:
                    pass
                else:
                    continue
                add1_out_name = str(add1_op.outputs[0])

                m2_users = [int(v) for v in consumers.get(add1_out_name, [])]
                if len(m2_users) != 1:
                    continue
                m2_idx = int(m2_users[0])
                m2_op = model_ir.operators[int(m2_idx)]
                if str(m2_op.op_type) != "MUL" or len(m2_op.inputs) != 2 or len(m2_op.outputs) != 1:
                    continue
                m2_inputs = [str(v) for v in m2_op.inputs]
                if m2_inputs[0] == add1_out_name:
                    m2_side_name = m2_inputs[1]
                elif m2_inputs[1] == add1_out_name:
                    m2_side_name = m2_inputs[0]
                else:
                    continue
                if not _is_singleton_constant_tensor(model_ir, m2_side_name):
                    continue
                m2_out_name = str(m2_op.outputs[0])

                tanh_users = [int(v) for v in consumers.get(m2_out_name, [])]
                if len(tanh_users) != 1:
                    continue
                tanh_idx = int(tanh_users[0])
                tanh_op = model_ir.operators[int(tanh_idx)]
                if (
                    str(tanh_op.op_type) != "TANH"
                    or len(tanh_op.inputs) != 1
                    or len(tanh_op.outputs) != 1
                    or str(tanh_op.inputs[0]) != m2_out_name
                ):
                    continue
                tanh_out_name = str(tanh_op.outputs[0])

                add2_users = [int(v) for v in consumers.get(tanh_out_name, [])]
                if len(add2_users) != 1:
                    continue
                add2_idx = int(add2_users[0])
                add2_op = model_ir.operators[int(add2_idx)]
                if str(add2_op.op_type) != "ADD" or len(add2_op.inputs) != 2 or len(add2_op.outputs) != 1:
                    continue
                add2_inputs = [str(v) for v in add2_op.inputs]
                if add2_inputs[0] == tanh_out_name:
                    add2_side_name = add2_inputs[1]
                elif add2_inputs[1] == tanh_out_name:
                    add2_side_name = add2_inputs[0]
                else:
                    continue
                if not _is_singleton_constant_tensor(model_ir, add2_side_name):
                    continue
                add2_out_name = str(add2_op.outputs[0])

                m3_users = [int(v) for v in consumers.get(add2_out_name, [])]
                if len(m3_users) != 1:
                    continue
                m3_idx = int(m3_users[0])
                m3_op = model_ir.operators[int(m3_idx)]
                if str(m3_op.op_type) != "MUL" or len(m3_op.inputs) != 2 or len(m3_op.outputs) != 1:
                    continue
                m3_inputs = [str(v) for v in m3_op.inputs]
                if pre_output_name == m3_inputs[0] and add2_out_name == m3_inputs[1]:
                    pass
                elif pre_output_name == m3_inputs[1] and add2_out_name == m3_inputs[0]:
                    pass
                else:
                    continue
                m3_out_name = str(m3_op.outputs[0])

                m4_users = [int(v) for v in consumers.get(m3_out_name, [])]
                if len(m4_users) != 1:
                    continue
                m4_idx = int(m4_users[0])
                m4_op = model_ir.operators[int(m4_idx)]
                if str(m4_op.op_type) != "MUL" or len(m4_op.inputs) != 2 or len(m4_op.outputs) != 1:
                    continue
                m4_inputs = [str(v) for v in m4_op.inputs]
                if m4_inputs[0] == m3_out_name:
                    m4_side_name = m4_inputs[1]
                elif m4_inputs[1] == m3_out_name:
                    m4_side_name = m4_inputs[0]
                else:
                    continue
                if not _is_singleton_constant_tensor(model_ir, m4_side_name):
                    continue
                gelu_out_name = str(m4_op.outputs[0])

                gelu_users = [int(v) for v in consumers.get(gelu_out_name, []) if int(v) != int(m4_idx)]
                if len(gelu_users) == 0:
                    continue

                post_indices: List[int] = []
                post_output_names: List[str] = []
                valid_users = True
                for user_idx in gelu_users:
                    user_op = model_ir.operators[int(user_idx)]
                    if (
                        str(user_op.op_type) != "TRANSPOSE"
                        or len(user_op.inputs) < 2
                        or len(user_op.outputs) != 1
                        or str(user_op.inputs[0]) != gelu_out_name
                    ):
                        valid_users = False
                        break
                    perm_post = _read_transpose_perm(model_ir, user_op)
                    if perm_post is None or perm_post != perm_post_expected:
                        valid_users = False
                        break
                    post_output_name = str(user_op.outputs[0])
                    if post_output_name in model_outputs:
                        valid_users = False
                        break
                    post_indices.append(int(user_idx))
                    post_output_names.append(post_output_name)
                if not valid_users or len(post_indices) == 0:
                    continue

                representative_output_name = str(post_output_names[0])
                for op_idx in [int(msq_idx), int(mcube_idx), int(add1_idx), int(m3_idx)]:
                    op = model_ir.operators[int(op_idx)]
                    updated_inputs = [
                        pre_input_name if str(v) == pre_output_name else str(v)
                        for v in list(op.inputs)
                    ]
                    _set_operator_inputs(
                        model_ir=model_ir,
                        op=op,
                        new_inputs=updated_inputs,
                    )

                _set_operator_outputs(
                    model_ir=model_ir,
                    op=m4_op,
                    new_outputs=[representative_output_name],
                )
                for alias_name in post_output_names[1:]:
                    _replace_tensor_inputs(model_ir, alias_name, representative_output_name)

                for tensor_name in [
                    msq_out_name,
                    mcube_out_name,
                    m1_out_name,
                    add1_out_name,
                    m2_out_name,
                    tanh_out_name,
                    add2_out_name,
                    m3_out_name,
                ]:
                    _permute_tensor_metadata_if_rank_matches(
                        model_ir.tensors.get(tensor_name, None),
                        perm_post_expected,
                    )

                old_gelu_tensor = model_ir.tensors.get(gelu_out_name, None)
                representative_tensor = model_ir.tensors.get(representative_output_name, None)
                if old_gelu_tensor is not None and representative_tensor is not None:
                    representative_tensor.dtype = str(old_gelu_tensor.dtype)
                    representative_tensor.quantization = _clone_quantization(old_gelu_tensor.quantization)
                    representative_tensor.shape = [int(v) for v in list(old_gelu_tensor.shape)]
                    representative_tensor.shape_signature = (
                        [int(v) for v in list(old_gelu_tensor.shape_signature)]
                        if old_gelu_tensor.shape_signature is not None
                        else [int(v) for v in list(old_gelu_tensor.shape)]
                    )
                    _permute_tensor_metadata_if_rank_matches(
                        representative_tensor,
                        perm_post_expected,
                    )

                remove_indices = sorted(list({int(pre_idx), *post_indices}), reverse=True)
                for remove_idx in remove_indices:
                    del model_ir.operators[int(remove_idx)]

                rewritten += 1
                changed = True
                gelu_match_found = True
                break

            if gelu_match_found:
                break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"rewritten_gelu_tanh_transpose_passthrough_chains": int(rewritten)}


def _optimize_center_size_offset_terminal_transpose_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Remove redundant NHWC->NCHW adapters in center/size/offset terminal heads.

    Typical target structure:
      center_nhwc --T(0,3,1,2)--> center_nchw --LOGISTIC->MAXIMUM->MINIMUM->RESHAPE([N,HW])
      size_nhwc   --T(0,3,1,2)--> size_nchw   --LOGISTIC->MAXIMUM->MINIMUM->RESHAPE([N,C,HW])->GATHER_ND
      offset_nhwc --T(0,3,1,2)--> offset_nchw --RESHAPE([N,C,HW])->GATHER_ND

    Rewrite:
      - Bypass the three transposes.
      - Keep branch math in NHWC.
      - Convert size/offset reshape shapes from [N,C,HW] to [N,HW,C].
      - Reorder GATHER_ND coords concat from [batch, channel, axis] to [batch, axis, channel].
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _single_consumer_op(
        tensor_name: str,
        consumers: Dict[str, List[int]],
        expected_type: str,
    ) -> Optional[int]:
        user_indices = [int(v) for v in consumers.get(str(tensor_name), [])]
        if len(user_indices) != 1:
            return None
        op_idx = int(user_indices[0])
        op = model_ir.operators[int(op_idx)]
        if str(op.op_type) != str(expected_type):
            return None
        return int(op_idx)

    def _next_unary_chain(
        start_tensor_name: str,
        consumers: Dict[str, List[int]],
        op_type: str,
    ) -> Optional[Tuple[int, str]]:
        op_idx = _single_consumer_op(start_tensor_name, consumers, op_type)
        if op_idx is None:
            return None
        op = model_ir.operators[int(op_idx)]
        if len(op.inputs) == 0 or len(op.outputs) != 1:
            return None
        if str(op.inputs[0]) != str(start_tensor_name):
            return None
        return int(op_idx), str(op.outputs[0])

    def _next_binary_const_chain(
        start_tensor_name: str,
        consumers: Dict[str, List[int]],
        op_type: str,
    ) -> Optional[Tuple[int, str]]:
        op_idx = _single_consumer_op(start_tensor_name, consumers, op_type)
        if op_idx is None:
            return None
        op = model_ir.operators[int(op_idx)]
        if len(op.inputs) != 2 or len(op.outputs) != 1:
            return None
        in0 = str(op.inputs[0])
        in1 = str(op.inputs[1])
        if in0 == str(start_tensor_name):
            side_name = str(in1)
        elif in1 == str(start_tensor_name):
            side_name = str(in0)
        else:
            return None
        if not _is_singleton_constant_tensor(model_ir, side_name):
            return None
        return int(op_idx), str(op.outputs[0])

    def _resolve_gather_coords_reorder_plan(
        *,
        gather_idx: int,
        producers: Dict[str, int],
    ) -> Optional[Tuple[int, List[str]]]:
        gather_op = model_ir.operators[int(gather_idx)]
        if str(gather_op.op_type) != "GATHER_ND" or len(gather_op.inputs) != 2:
            return None
        coords_name = str(gather_op.inputs[1])
        concat_idx = producers.get(coords_name, None)
        if concat_idx is None:
            return None
        concat_op = model_ir.operators[int(concat_idx)]
        if (
            str(concat_op.op_type) != "CONCATENATION"
            or len(concat_op.inputs) != 3
            or len(concat_op.outputs) != 1
            or str(concat_op.outputs[0]) != coords_name
            or int(concat_op.options.get("axis", -1)) != 3
        ):
            return None

        concat_inputs = [str(v) for v in list(concat_op.inputs)]
        axis_pos: Optional[int] = None
        for pos, input_name in enumerate(concat_inputs):
            prod_idx = producers.get(str(input_name), None)
            if prod_idx is None:
                continue
            prod_op = model_ir.operators[int(prod_idx)]
            if str(prod_op.op_type) != "RESHAPE":
                continue
            axis_tensor = model_ir.tensors.get(str(input_name), None)
            if axis_tensor is None or len(list(axis_tensor.shape)) != 4:
                continue
            if int(axis_tensor.shape[-1]) != 1:
                continue
            axis_pos = int(pos)
            break
        if axis_pos is None:
            return None

        other_positions = [int(v) for v in [0, 1, 2] if int(v) != int(axis_pos)]
        if len(other_positions) != 2:
            return None

        channel_pos: Optional[int] = None
        for pos in other_positions:
            tensor = model_ir.tensors.get(concat_inputs[int(pos)], None)
            if tensor is None or tensor.data is None:
                continue
            values = np.asarray(tensor.data).reshape(-1)
            if values.size == 0:
                continue
            unique_vals = sorted(list({int(v) for v in values.tolist()}))
            if len(unique_vals) > 1:
                channel_pos = int(pos)
                break
        if channel_pos is None:
            channel_pos = int(other_positions[-1])
        batch_pos = int(other_positions[0] if int(other_positions[0]) != int(channel_pos) else other_positions[1])

        reordered = [
            concat_inputs[int(batch_pos)],
            concat_inputs[int(axis_pos)],
            concat_inputs[int(channel_pos)],
        ]
        return int(concat_idx), [str(v) for v in reordered]

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for center_pre_idx, center_pre_op in enumerate(model_ir.operators):
            if str(center_pre_op.op_type) != "TRANSPOSE" or len(center_pre_op.inputs) < 2 or len(center_pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, center_pre_op) != perm_nhwc_to_nchw:
                continue
            center_nhwc_name = str(center_pre_op.inputs[0])
            center_nchw_name = str(center_pre_op.outputs[0])
            if center_nhwc_name in model_outputs or center_nchw_name in model_outputs:
                continue

            center_log_idx = _single_consumer_op(center_nchw_name, consumers, "LOGISTIC")
            if center_log_idx is None:
                continue
            center_log_op = model_ir.operators[int(center_log_idx)]
            if len(center_log_op.inputs) != 1 or len(center_log_op.outputs) != 1:
                continue
            if str(center_log_op.inputs[0]) != center_nchw_name:
                continue
            center_log_out = str(center_log_op.outputs[0])

            center_max_info = _next_binary_const_chain(center_log_out, consumers, "MAXIMUM")
            if center_max_info is None:
                continue
            center_max_idx, center_max_out = center_max_info
            center_min_info = _next_binary_const_chain(center_max_out, consumers, "MINIMUM")
            if center_min_info is None:
                continue
            center_min_idx, center_min_out = center_min_info

            center_flat_idx = _single_consumer_op(center_min_out, consumers, "RESHAPE")
            if center_flat_idx is None:
                continue
            center_flat_op = model_ir.operators[int(center_flat_idx)]
            if len(center_flat_op.inputs) < 2 or len(center_flat_op.outputs) != 1:
                continue
            if str(center_flat_op.inputs[0]) != center_min_out:
                continue
            center_flat_shape_tensor = model_ir.tensors.get(str(center_flat_op.inputs[1]), None)
            center_flat_shape = _read_const_ints_from_tensor(center_flat_shape_tensor)
            if center_flat_shape is None or len(center_flat_shape) != 2:
                continue

            # Find paired size/offset pre-transposes in the same region.
            size_pre_idx: Optional[int] = None
            size_pre_op: Optional[OperatorIR] = None
            offset_pre_idx: Optional[int] = None
            offset_pre_op: Optional[OperatorIR] = None
            for candidate_idx in range(int(center_pre_idx) + 1, min(len(model_ir.operators), int(center_pre_idx) + 16)):
                candidate_op = model_ir.operators[int(candidate_idx)]
                if str(candidate_op.op_type) != "TRANSPOSE" or len(candidate_op.inputs) < 2 or len(candidate_op.outputs) != 1:
                    continue
                if _read_transpose_perm(model_ir, candidate_op) != perm_nhwc_to_nchw:
                    continue
                candidate_out = str(candidate_op.outputs[0])
                candidate_users = [int(v) for v in consumers.get(candidate_out, [])]
                if len(candidate_users) != 1:
                    continue
                user_op = model_ir.operators[int(candidate_users[0])]
                if str(user_op.op_type) == "LOGISTIC" and size_pre_idx is None:
                    size_pre_idx = int(candidate_idx)
                    size_pre_op = candidate_op
                    continue
                if str(user_op.op_type) == "RESHAPE" and offset_pre_idx is None:
                    offset_pre_idx = int(candidate_idx)
                    offset_pre_op = candidate_op
                    continue
            if size_pre_idx is None or size_pre_op is None or offset_pre_idx is None or offset_pre_op is None:
                continue

            size_nhwc_name = str(size_pre_op.inputs[0])
            size_nchw_name = str(size_pre_op.outputs[0])
            offset_nhwc_name = str(offset_pre_op.inputs[0])
            offset_nchw_name = str(offset_pre_op.outputs[0])
            if (
                size_nhwc_name in model_outputs
                or size_nchw_name in model_outputs
                or offset_nhwc_name in model_outputs
                or offset_nchw_name in model_outputs
            ):
                continue

            size_log_idx = _single_consumer_op(size_nchw_name, consumers, "LOGISTIC")
            if size_log_idx is None:
                continue
            size_log_op = model_ir.operators[int(size_log_idx)]
            if len(size_log_op.inputs) != 1 or len(size_log_op.outputs) != 1:
                continue
            if str(size_log_op.inputs[0]) != size_nchw_name:
                continue
            size_log_out = str(size_log_op.outputs[0])

            size_max_info = _next_binary_const_chain(size_log_out, consumers, "MAXIMUM")
            if size_max_info is None:
                continue
            size_max_idx, size_max_out = size_max_info
            size_min_info = _next_binary_const_chain(size_max_out, consumers, "MINIMUM")
            if size_min_info is None:
                continue
            size_min_idx, size_min_out = size_min_info

            size_reshape_idx = _single_consumer_op(size_min_out, consumers, "RESHAPE")
            if size_reshape_idx is None:
                continue
            size_reshape_op = model_ir.operators[int(size_reshape_idx)]
            if len(size_reshape_op.inputs) < 2 or len(size_reshape_op.outputs) != 1:
                continue
            if str(size_reshape_op.inputs[0]) != size_min_out:
                continue
            size_reshape_shape_tensor = model_ir.tensors.get(str(size_reshape_op.inputs[1]), None)
            size_reshape_shape = _read_const_ints_from_tensor(size_reshape_shape_tensor)
            if size_reshape_shape is None or len(size_reshape_shape) != 3:
                continue
            size_reshape_out = str(size_reshape_op.outputs[0])

            offset_reshape_idx = _single_consumer_op(offset_nchw_name, consumers, "RESHAPE")
            if offset_reshape_idx is None:
                continue
            offset_reshape_op = model_ir.operators[int(offset_reshape_idx)]
            if len(offset_reshape_op.inputs) < 2 or len(offset_reshape_op.outputs) != 1:
                continue
            if str(offset_reshape_op.inputs[0]) != offset_nchw_name:
                continue
            offset_reshape_shape_tensor = model_ir.tensors.get(str(offset_reshape_op.inputs[1]), None)
            offset_reshape_shape = _read_const_ints_from_tensor(offset_reshape_shape_tensor)
            if offset_reshape_shape is None or len(offset_reshape_shape) != 3:
                continue
            if [int(v) for v in offset_reshape_shape] != [int(v) for v in size_reshape_shape]:
                continue
            offset_reshape_out = str(offset_reshape_op.outputs[0])

            size_gather_idx = _single_consumer_op(size_reshape_out, consumers, "GATHER_ND")
            if size_gather_idx is None:
                continue
            offset_gather_idx = _single_consumer_op(offset_reshape_out, consumers, "GATHER_ND")
            if offset_gather_idx is None:
                continue

            size_concat_plan = _resolve_gather_coords_reorder_plan(
                gather_idx=int(size_gather_idx),
                producers=producers,
            )
            if size_concat_plan is None:
                continue
            offset_concat_plan = _resolve_gather_coords_reorder_plan(
                gather_idx=int(offset_gather_idx),
                producers=producers,
            )
            if offset_concat_plan is None:
                continue

            # Rewire to NHWC sources.
            _set_operator_inputs(
                model_ir=model_ir,
                op=center_log_op,
                new_inputs=[center_nhwc_name],
            )
            _set_operator_inputs(
                model_ir=model_ir,
                op=size_log_op,
                new_inputs=[size_nhwc_name],
            )
            offset_inputs = [str(v) for v in list(offset_reshape_op.inputs)]
            offset_inputs[0] = str(offset_nhwc_name)
            _set_operator_inputs(
                model_ir=model_ir,
                op=offset_reshape_op,
                new_inputs=offset_inputs,
            )

            for tensor_name in [
                center_log_out,
                center_max_out,
                center_min_out,
                size_log_out,
                size_max_out,
                size_min_out,
            ]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(tensor_name, None),
                    perm_nchw_to_nhwc,
                )

            new_reshape_shape = [
                int(size_reshape_shape[0]),
                int(size_reshape_shape[2]),
                int(size_reshape_shape[1]),
            ]
            if not _write_const_ints_to_tensor(size_reshape_shape_tensor, [int(v) for v in new_reshape_shape]):
                continue
            if not _write_const_ints_to_tensor(offset_reshape_shape_tensor, [int(v) for v in new_reshape_shape]):
                continue

            size_opts = dict(size_reshape_op.options) if isinstance(size_reshape_op.options, dict) else {}
            if "newShape" in size_opts and isinstance(size_opts["newShape"], list):
                size_opts["newShape"] = [int(v) for v in list(new_reshape_shape)]
            if "onnxRawNewShape" in size_opts and isinstance(size_opts["onnxRawNewShape"], list) and len(size_opts["onnxRawNewShape"]) == 3:
                old_raw = [int(v) for v in list(size_opts["onnxRawNewShape"])]
                size_opts["onnxRawNewShape"] = [int(old_raw[0]), int(old_raw[2]), int(old_raw[1])]
            size_reshape_op.options = size_opts

            offset_opts = dict(offset_reshape_op.options) if isinstance(offset_reshape_op.options, dict) else {}
            if "newShape" in offset_opts and isinstance(offset_opts["newShape"], list):
                offset_opts["newShape"] = [int(v) for v in list(new_reshape_shape)]
            if "onnxRawNewShape" in offset_opts and isinstance(offset_opts["onnxRawNewShape"], list) and len(offset_opts["onnxRawNewShape"]) == 3:
                old_raw = [int(v) for v in list(offset_opts["onnxRawNewShape"])]
                offset_opts["onnxRawNewShape"] = [int(old_raw[0]), int(old_raw[2]), int(old_raw[1])]
            offset_reshape_op.options = offset_opts

            size_out_tensor = model_ir.tensors.get(size_reshape_out, None)
            if size_out_tensor is not None:
                size_out_tensor.shape = [int(v) for v in list(new_reshape_shape)]
                size_out_tensor.shape_signature = [int(v) for v in list(new_reshape_shape)]
            offset_out_tensor = model_ir.tensors.get(offset_reshape_out, None)
            if offset_out_tensor is not None:
                offset_out_tensor.shape = [int(v) for v in list(new_reshape_shape)]
                offset_out_tensor.shape_signature = [int(v) for v in list(new_reshape_shape)]

            size_concat_idx, size_concat_inputs = size_concat_plan
            _set_operator_inputs(
                model_ir=model_ir,
                op=model_ir.operators[int(size_concat_idx)],
                new_inputs=[str(v) for v in size_concat_inputs],
            )
            offset_concat_idx, offset_concat_inputs = offset_concat_plan
            _set_operator_inputs(
                model_ir=model_ir,
                op=model_ir.operators[int(offset_concat_idx)],
                new_inputs=[str(v) for v in offset_concat_inputs],
            )

            remove_indices = sorted(
                list({int(center_pre_idx), int(size_pre_idx), int(offset_pre_idx)}),
                reverse=True,
            )
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_center_size_offset_terminal_transpose_chains": int(rewritten)}


def _optimize_leakyrelu_transpose_passthrough_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose wrappers around pseudo-op-expanded LeakyReLU chains.

    Target:
      X --TRANSPOSE(P)--> x_t
      x_t --NEG--> n --RELU--> nr --MUL(alpha)--> m
      x_t --RELU--> p
      p --SUB(m)--> y_t
      y_t --TRANSPOSE(inv(P))--> Y

    Rewrite:
      X --NEG--> n --RELU--> nr --MUL(alpha)--> m
      X --RELU--> p
      p --SUB(m)--> Y

    Safety:
    - Strict LeakyReLU topology (NEG/RELU fanout + RELU + MUL + SUB).
    - MUL side input must be singleton constant (alpha scalar-like).
    - Single-consumer chain on each branch and tail.
    """
    rewritten = 0

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE":
                continue
            if len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue
            perm_post_expected = _invert_perm(perm_pre)
            if perm_post_expected is None:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) != 2:
                continue

            neg_idx = None
            relu_pos_idx = None
            for user_idx in pre_users:
                user_op = model_ir.operators[int(user_idx)]
                user_type = str(user_op.op_type)
                if (
                    user_type == "NEG"
                    and len(user_op.inputs) == 1
                    and str(user_op.inputs[0]) == pre_output_name
                    and len(user_op.outputs) == 1
                ):
                    neg_idx = int(user_idx)
                elif (
                    user_type == "RELU"
                    and len(user_op.inputs) == 1
                    and str(user_op.inputs[0]) == pre_output_name
                    and len(user_op.outputs) == 1
                ):
                    relu_pos_idx = int(user_idx)
            if neg_idx is None or relu_pos_idx is None:
                continue

            neg_op = model_ir.operators[int(neg_idx)]
            neg_out_name = str(neg_op.outputs[0])
            neg_users = [int(v) for v in consumers.get(neg_out_name, [])]
            if len(neg_users) != 1:
                continue
            relu_neg_idx = int(neg_users[0])
            relu_neg_op = model_ir.operators[int(relu_neg_idx)]
            if (
                str(relu_neg_op.op_type) != "RELU"
                or len(relu_neg_op.inputs) != 1
                or len(relu_neg_op.outputs) != 1
                or str(relu_neg_op.inputs[0]) != neg_out_name
            ):
                continue
            relu_neg_out_name = str(relu_neg_op.outputs[0])

            relu_neg_users = [int(v) for v in consumers.get(relu_neg_out_name, [])]
            if len(relu_neg_users) != 1:
                continue
            mul_idx = int(relu_neg_users[0])
            mul_op = model_ir.operators[int(mul_idx)]
            if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                continue
            mul_inputs = [str(v) for v in mul_op.inputs]
            if relu_neg_out_name == mul_inputs[0]:
                mul_side_input_name = mul_inputs[1]
            elif relu_neg_out_name == mul_inputs[1]:
                mul_side_input_name = mul_inputs[0]
            else:
                continue
            if not _is_singleton_constant_tensor(model_ir, mul_side_input_name):
                continue
            mul_out_name = str(mul_op.outputs[0])

            relu_pos_op = model_ir.operators[int(relu_pos_idx)]
            relu_pos_out_name = str(relu_pos_op.outputs[0])
            relu_pos_users = [int(v) for v in consumers.get(relu_pos_out_name, [])]
            if len(relu_pos_users) != 1:
                continue

            mul_users = [int(v) for v in consumers.get(mul_out_name, [])]
            if len(mul_users) != 1:
                continue
            sub_idx = int(mul_users[0])
            if relu_pos_users[0] != sub_idx:
                continue

            sub_op = model_ir.operators[int(sub_idx)]
            if str(sub_op.op_type) != "SUB" or len(sub_op.inputs) != 2 or len(sub_op.outputs) != 1:
                continue
            sub_inputs = [str(v) for v in sub_op.inputs]
            if sub_inputs != [relu_pos_out_name, mul_out_name]:
                continue
            sub_out_name = str(sub_op.outputs[0])

            sub_users = [int(v) for v in consumers.get(sub_out_name, []) if int(v) != int(sub_idx)]
            if len(sub_users) == 0:
                continue
            post_indices: List[int] = []
            post_output_names: List[str] = []
            legacy_users: List[int] = []
            valid_users = True
            for user_idx in sub_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == sub_out_name
                ):
                    perm_post = _read_transpose_perm(model_ir, user_op)
                    if perm_post is None or perm_post != perm_post_expected:
                        valid_users = False
                        break
                    post_output_name = str(user_op.outputs[0])
                    if post_output_name in model_outputs:
                        valid_users = False
                        break
                    post_indices.append(int(user_idx))
                    post_output_names.append(post_output_name)
                else:
                    legacy_users.append(int(user_idx))
            if not valid_users or len(post_indices) == 0:
                continue
            post_output_name = str(post_output_names[0])

            # Rewire the pseudo-LeakyReLU chain to consume source layout directly.
            _set_operator_inputs(
                model_ir=model_ir,
                op=neg_op,
                new_inputs=[pre_input_name],
            )
            _set_operator_inputs(
                model_ir=model_ir,
                op=relu_pos_op,
                new_inputs=[pre_input_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=sub_op,
                new_outputs=[post_output_name],
            )
            for alias_output_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, alias_output_name, post_output_name)

            # Update intermediate metadata from transposed layout to source layout.
            for intermediate_name in [neg_out_name, relu_pos_out_name, relu_neg_out_name, mul_out_name]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(intermediate_name, None),
                    perm_post_expected,
                )

            # Keep final tensor metadata stable on the post-transpose name.
            pre_input_tensor = model_ir.tensors.get(pre_input_name, None)
            old_sub_tensor = model_ir.tensors.get(sub_out_name, None)
            post_output_tensor = model_ir.tensors.get(post_output_name, None)
            if post_output_tensor is not None:
                if pre_input_tensor is not None:
                    post_output_tensor.shape = [int(v) for v in list(pre_input_tensor.shape)]
                    post_output_tensor.shape_signature = (
                        [int(v) for v in list(pre_input_tensor.shape_signature)]
                        if pre_input_tensor.shape_signature is not None
                        else [int(v) for v in list(pre_input_tensor.shape)]
                    )
                if old_sub_tensor is not None:
                    post_output_tensor.dtype = str(old_sub_tensor.dtype)
                    post_output_tensor.quantization = _clone_quantization(old_sub_tensor.quantization)

            preserve_nchw_adapter = len(legacy_users) > 0 or sub_out_name in model_outputs
            if preserve_nchw_adapter:
                keep_post_idx = int(post_indices[0])
                keep_post_op = model_ir.operators[keep_post_idx]
                keep_perm_name = str(keep_post_op.inputs[1])
                keep_perm_tensor = model_ir.tensors.get(keep_perm_name, None)
                if keep_perm_tensor is not None:
                    keep_perm_tensor.data = np.asarray(perm_pre, dtype=np.int32)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_inputs=[post_output_name, keep_perm_name],
                )
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_outputs=[sub_out_name],
                )
                post_remove_indices = [int(v) for v in post_indices[1:]]
            else:
                post_remove_indices = [int(v) for v in post_indices]

            remove_indices = sorted(list({int(pre_idx), *post_remove_indices}), reverse=True)
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    fuse_stats = _optimize_fuse_pseudo_leakyrelu_chains(model_ir)
    _prune_unused_tensors(model_ir)
    return {
        "rewritten_leakyrelu_transpose_passthrough_chains": int(rewritten),
        "fused_pseudo_leakyrelu_chains": int(
            fuse_stats.get("fused_pseudo_leakyrelu_chains", 0)
        ),
    }


def _optimize_prelu_transpose_passthrough_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose wrappers around PRELU chains.

    Target:
      X --TRANSPOSE(P)--> x_t
      x_t --PRELU(alpha)--> y_t
      y_t --TRANSPOSE(inv(P))--> Y

    Rewrite:
      X --PRELU(alpha')--> Y

    Safety:
    - PRELU alpha must be constant.
    - Requires at least one inverse post-transpose consumer.
    - Keeps one adapter transpose when legacy NCHW consumers remain.
    """
    rewritten = 0

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_output_name in model_outputs:
                continue

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue
            perm_post_expected = _invert_perm(perm_pre)
            if perm_post_expected is None:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) == 0:
                continue

            prelu_candidates: List[int] = []
            for user_idx in pre_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "PRELU"
                    and len(user_op.inputs) == 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == pre_output_name
                ):
                    prelu_candidates.append(int(user_idx))
            if len(prelu_candidates) != 1:
                continue

            prelu_idx = int(prelu_candidates[0])
            prelu_op = model_ir.operators[int(prelu_idx)]
            prelu_out_name = str(prelu_op.outputs[0])
            if prelu_out_name in model_outputs:
                continue

            prelu_users = [int(v) for v in consumers.get(prelu_out_name, [])]
            if len(prelu_users) == 0:
                continue

            post_indices: List[int] = []
            post_output_names: List[str] = []
            legacy_users: List[int] = []
            valid_users = True
            for user_idx in prelu_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == prelu_out_name
                ):
                    perm_post = _read_transpose_perm(model_ir, user_op)
                    post_output_name = str(user_op.outputs[0])
                    if (
                        perm_post is None
                        or perm_post != perm_post_expected
                        or post_output_name in model_outputs
                    ):
                        valid_users = False
                        break
                    post_indices.append(int(user_idx))
                    post_output_names.append(post_output_name)
                else:
                    legacy_users.append(int(user_idx))
            if not valid_users or len(post_indices) == 0:
                continue

            alpha_name = str(prelu_op.inputs[1])
            alpha_tensor = model_ir.tensors.get(alpha_name, None)
            if alpha_tensor is None or not isinstance(alpha_tensor.data, np.ndarray):
                continue

            pre_input_tensor = model_ir.tensors.get(pre_input_name, None)
            target_shape = (
                [int(v) for v in list(pre_input_tensor.shape)]
                if pre_input_tensor is not None and pre_input_tensor.shape is not None
                else None
            )

            alpha_data = np.asarray(alpha_tensor.data)
            alpha_candidates: List[np.ndarray] = [np.asarray(alpha_data)]
            if int(alpha_data.ndim) == int(len(perm_post_expected)):
                alpha_candidates.append(
                    np.transpose(alpha_data, axes=perm_post_expected).astype(alpha_data.dtype, copy=False)
                )
            if perm_pre == [0, 3, 1, 2] and perm_post_expected == [0, 2, 3, 1] and int(alpha_data.ndim) == 3:
                alpha_candidates.append(
                    np.transpose(alpha_data, axes=[1, 2, 0]).astype(alpha_data.dtype, copy=False)
                )

            def _broadcastable_to_target(candidate: np.ndarray) -> bool:
                if target_shape is None:
                    return True
                return (
                    _broadcast_static_shapes(
                        [int(v) for v in list(target_shape)],
                        [int(v) for v in list(candidate.shape)],
                    )
                    is not None
                )

            selected_alpha: Optional[np.ndarray] = None
            for candidate in alpha_candidates:
                if _broadcastable_to_target(candidate):
                    selected_alpha = np.asarray(candidate)
                    break
            if selected_alpha is None:
                continue

            selected_alpha_name = str(alpha_name)
            alpha_users = [int(v) for v in consumers.get(alpha_name, [])]
            alpha_needs_rewrite = (
                selected_alpha.shape != alpha_data.shape
                or not np.array_equal(selected_alpha, alpha_data)
            )
            if alpha_needs_rewrite:
                if len(alpha_users) == 1 and int(alpha_users[0]) == int(prelu_idx):
                    shape, signature = normalize_onnx_shape(list(selected_alpha.shape))
                    alpha_tensor.data = np.asarray(selected_alpha)
                    alpha_tensor.shape = [int(v) for v in list(shape)]
                    alpha_tensor.shape_signature = [int(v) for v in list(signature)]
                else:
                    selected_alpha_name = _unique_tensor_name(f"{alpha_name}_nhwc")
                    shape, signature = normalize_onnx_shape(list(selected_alpha.shape))
                    model_ir.tensors[selected_alpha_name] = TensorIR(
                        name=selected_alpha_name,
                        dtype=str(alpha_tensor.dtype),
                        shape=[int(v) for v in list(shape)],
                        shape_signature=[int(v) for v in list(signature)],
                        data=np.asarray(selected_alpha),
                        is_variable=False,
                        quantization=_clone_quantization(alpha_tensor.quantization),
                    )

            representative_output_name = str(post_output_names[0])
            _set_operator_inputs(
                model_ir=model_ir,
                op=prelu_op,
                new_inputs=[pre_input_name, selected_alpha_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=prelu_op,
                new_outputs=[representative_output_name],
            )
            for alias_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, alias_name, representative_output_name)

            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(prelu_out_name, None),
                perm_post_expected,
            )

            old_prelu_tensor = model_ir.tensors.get(prelu_out_name, None)
            representative_tensor = model_ir.tensors.get(representative_output_name, None)
            if old_prelu_tensor is not None and representative_tensor is not None:
                representative_tensor.dtype = str(old_prelu_tensor.dtype)
                representative_tensor.quantization = _clone_quantization(old_prelu_tensor.quantization)
                representative_tensor.shape = [int(v) for v in list(old_prelu_tensor.shape)]
                representative_tensor.shape_signature = (
                    [int(v) for v in list(old_prelu_tensor.shape_signature)]
                    if old_prelu_tensor.shape_signature is not None
                    else [int(v) for v in list(old_prelu_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    representative_tensor,
                    perm_post_expected,
                )

            preserve_nchw_adapter = len(legacy_users) > 0 or prelu_out_name in model_outputs
            if preserve_nchw_adapter:
                keep_post_idx = int(post_indices[0])
                keep_post_op = model_ir.operators[keep_post_idx]
                keep_perm_name = str(keep_post_op.inputs[1])
                keep_perm_tensor = model_ir.tensors.get(keep_perm_name, None)
                if keep_perm_tensor is not None:
                    keep_perm_tensor.data = np.asarray(perm_pre, dtype=np.int32)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_inputs=[representative_output_name, keep_perm_name],
                )
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_outputs=[prelu_out_name],
                )
                post_remove_indices = [int(v) for v in post_indices[1:]]
            else:
                post_remove_indices = [int(v) for v in post_indices]

            remove_indices = set(int(v) for v in post_remove_indices)
            pre_remaining_users = [int(v) for v in pre_users if int(v) != int(prelu_idx)]
            if len(pre_remaining_users) == 0:
                remove_indices.add(int(pre_idx))
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"rewritten_prelu_transpose_passthrough_chains": int(rewritten)}


def _optimize_transpose_elementwise_concat_conv_nhwc_groups(model_ir: ModelIR) -> Dict[str, int]:
    """
    Lift NCHW elementwise/concat groups back to NHWC when they are terminated by
    CONCAT(axis=1) -> TRANSPOSE(0,2,3,1) adapters into Conv inputs.

    This pass rewrites a whole connected concat group at once (not per-node),
    so shared upstream elementwise producers are converted consistently.
    """
    optimized_groups = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    perm_nhwc_to_nchw_const_name = "__nhwc_to_nchw_perm_rank4__"
    unary_ops = {"RELU", "RELU6", "LEAKY_RELU", "LOGISTIC", "TANH", "NEG", "EXP", "ABS", "SQRT", "GELU"}
    binary_ops = {"ADD", "SUB", "MUL", "DIV", "MAXIMUM", "MINIMUM"}
    legacy_consumer_safe_ops = set(unary_ops) | set(binary_ops)

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    if perm_nhwc_to_nchw_const_name not in model_ir.tensors:
        model_ir.tensors[perm_nhwc_to_nchw_const_name] = TensorIR(
            name=perm_nhwc_to_nchw_const_name,
            dtype="INT32",
            shape=[4],
            shape_signature=[4],
            data=np.asarray(perm_nhwc_to_nchw, dtype=np.int32),
            is_variable=False,
            quantization=None,
        )

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        candidate_concats: List[int] = []
        post_by_concat: Dict[int, List[int]] = {}
        for concat_idx, concat_op in enumerate(model_ir.operators):
            if str(concat_op.op_type) != "CONCATENATION" or len(concat_op.outputs) != 1:
                continue
            axis_old = int(concat_op.options.get("axis", 1))
            if axis_old < 0:
                axis_old += 4
            if axis_old != 1:
                continue
            concat_out = str(concat_op.outputs[0])
            concat_users = [int(v) for v in consumers.get(concat_out, [])]
            if len(concat_users) == 0:
                continue
            post_indices: List[int] = []
            valid_users = True
            for user_idx in concat_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) != "TRANSPOSE"
                    or len(user_op.inputs) < 2
                    or len(user_op.outputs) != 1
                    or str(user_op.inputs[0]) != concat_out
                    or _read_transpose_perm(model_ir, user_op) != perm_nchw_to_nhwc
                    or str(user_op.outputs[0]) in model_outputs
                ):
                    valid_users = False
                    break
                post_indices.append(int(user_idx))
            if not valid_users or len(post_indices) == 0:
                continue
            candidate_concats.append(int(concat_idx))
            post_by_concat[int(concat_idx)] = [int(v) for v in post_indices]

        if len(candidate_concats) == 0:
            break

        for seed_concat_idx in candidate_concats:
            target_concats: set[int] = {int(seed_concat_idx)}
            closure_ops: set[int] = set()
            boundary_transpose_by_tensor: Dict[str, Tuple[str, int]] = {}
            const_tensor_names_to_permute: set[str] = set()

            def _trace_tensor_to_nhwc(
                tensor_name: str,
                visiting: set[int],
            ) -> bool:
                if str(tensor_name) in boundary_transpose_by_tensor:
                    return True
                producer_idx = producers.get(str(tensor_name), None)
                if producer_idx is None:
                    tensor = model_ir.tensors.get(str(tensor_name), None)
                    if (
                        str(tensor_name) in set(str(v) for v in model_ir.inputs)
                        and tensor is not None
                        and len(list(tensor.shape)) == 4
                    ):
                        boundary_transpose_by_tensor[str(tensor_name)] = (str(tensor_name), -1)
                        return True
                    return False
                producer_op = model_ir.operators[int(producer_idx)]
                producer_type = str(producer_op.op_type)

                if (
                    producer_type == "TRANSPOSE"
                    and len(producer_op.inputs) >= 2
                    and len(producer_op.outputs) == 1
                    and str(producer_op.outputs[0]) == str(tensor_name)
                    and _read_transpose_perm(model_ir, producer_op) == perm_nhwc_to_nchw
                ):
                    boundary_transpose_by_tensor[str(tensor_name)] = (
                        str(producer_op.inputs[0]),
                        int(producer_idx),
                    )
                    return True

                # Also accept an existing forward NCHW->NHWC adapter produced
                # from this tensor by a consumer TRANSPOSE.
                for consumer_idx in [int(v) for v in consumers.get(str(tensor_name), [])]:
                    consumer_op = model_ir.operators[int(consumer_idx)]
                    if (
                        str(consumer_op.op_type) == "TRANSPOSE"
                        and len(consumer_op.inputs) >= 2
                        and len(consumer_op.outputs) == 1
                        and str(consumer_op.inputs[0]) == str(tensor_name)
                        and _read_transpose_perm(model_ir, consumer_op) == perm_nchw_to_nhwc
                        and str(consumer_op.outputs[0]) not in model_outputs
                    ):
                        boundary_transpose_by_tensor[str(tensor_name)] = (
                            str(consumer_op.outputs[0]),
                            -1,
                        )
                        return True

                if int(producer_idx) in closure_ops:
                    return True
                if int(producer_idx) in visiting:
                    return False
                if str(tensor_name) in model_outputs:
                    return False

                if producer_type in unary_ops:
                    if len(producer_op.inputs) != 1 or len(producer_op.outputs) != 1:
                        return False
                    visiting.add(int(producer_idx))
                    closure_ops.add(int(producer_idx))
                    ok = _trace_tensor_to_nhwc(str(producer_op.inputs[0]), visiting)
                    visiting.remove(int(producer_idx))
                    return bool(ok)

                if producer_type in binary_ops:
                    if len(producer_op.inputs) != 2 or len(producer_op.outputs) != 1:
                        return False
                    visiting.add(int(producer_idx))
                    closure_ops.add(int(producer_idx))
                    ok = True
                    for input_name in [str(v) for v in list(producer_op.inputs)]:
                        input_tensor = model_ir.tensors.get(str(input_name), None)
                        if input_tensor is not None and input_tensor.data is not None:
                            try:
                                const_arr = np.asarray(input_tensor.data)
                            except Exception:
                                const_arr = None
                            if const_arr is not None and const_arr.ndim == 4 and int(const_arr.size) > 1:
                                const_tensor_names_to_permute.add(str(input_name))
                            continue
                        if not _trace_tensor_to_nhwc(str(input_name), visiting):
                            ok = False
                            break
                    visiting.remove(int(producer_idx))
                    return bool(ok)

                return False

            analysis_ok = True
            while True:
                closure_ops.clear()
                boundary_transpose_by_tensor.clear()
                const_tensor_names_to_permute.clear()

                for concat_idx in sorted(list(target_concats)):
                    concat_op = model_ir.operators[int(concat_idx)]
                    if str(concat_op.op_type) != "CONCATENATION" or len(concat_op.inputs) == 0:
                        analysis_ok = False
                        break
                    for concat_input_name in [str(v) for v in list(concat_op.inputs)]:
                        if not _trace_tensor_to_nhwc(concat_input_name, set()):
                            analysis_ok = False
                            break
                    if not analysis_ok:
                        break
                if not analysis_ok:
                    break

                expanded = False
                for candidate_concat_idx in candidate_concats:
                    if int(candidate_concat_idx) in target_concats:
                        continue
                    candidate_concat_op = model_ir.operators[int(candidate_concat_idx)]
                    for candidate_input_name in [str(v) for v in list(candidate_concat_op.inputs)]:
                        candidate_input_prod = producers.get(str(candidate_input_name), None)
                        if candidate_input_prod is not None and int(candidate_input_prod) in closure_ops:
                            target_concats.add(int(candidate_concat_idx))
                            expanded = True
                            break
                if not expanded:
                    break

            if not analysis_ok:
                continue

            target_post_indices: set[int] = set()
            for concat_idx in target_concats:
                target_post_indices.update(set(int(v) for v in post_by_concat.get(int(concat_idx), [])))
            allowed_consumer_indices = set(int(v) for v in closure_ops) | set(int(v) for v in target_concats) | set(
                int(v) for v in target_post_indices
            )

            valid_group = True
            legacy_consumer_slots_by_output: Dict[str, List[Tuple[int, int]]] = {}
            for op_idx in sorted(list(closure_ops)):
                op = model_ir.operators[int(op_idx)]
                if any(str(output_name) in model_outputs for output_name in op.outputs):
                    valid_group = False
                    break
                for output_name in [str(v) for v in list(op.outputs)]:
                    external_slots: List[Tuple[int, int]] = []
                    for user_idx in [int(v) for v in consumers.get(str(output_name), [])]:
                        if int(user_idx) in allowed_consumer_indices:
                            continue
                        user_op = model_ir.operators[int(user_idx)]
                        if str(user_op.op_type) not in legacy_consumer_safe_ops:
                            valid_group = False
                            break
                        input_indices = [
                            int(input_idx)
                            for input_idx, input_name in enumerate(list(user_op.inputs))
                            if str(input_name) == str(output_name)
                        ]
                        if len(input_indices) == 0:
                            valid_group = False
                            break
                        for input_idx in input_indices:
                            external_slots.append((int(id(user_op)), int(input_idx)))
                    if not valid_group:
                        break
                    if len(external_slots) > 0:
                        legacy_consumer_slots_by_output[str(output_name)] = list(external_slots)
                if not valid_group:
                    break

            if not valid_group:
                continue

            for const_name in sorted(list(const_tensor_names_to_permute)):
                const_users = [int(v) for v in consumers.get(str(const_name), [])]
                if any(int(user_idx) not in closure_ops for user_idx in const_users):
                    valid_group = False
                    break
            if not valid_group:
                continue

            for concat_idx in sorted(list(target_concats)):
                concat_op = model_ir.operators[int(concat_idx)]
                concat_out_name = str(concat_op.outputs[0])
                concat_users = set(int(v) for v in consumers.get(str(concat_out_name), []))
                expected_users = set(int(v) for v in post_by_concat.get(int(concat_idx), []))
                if concat_users != expected_users:
                    valid_group = False
                    break
            if not valid_group:
                continue

            remove_indices: set[int] = set()
            legacy_nchw_tensor_meta_by_output: Dict[str, Tuple[str, Optional[Any], List[int], List[int]]] = {}
            for const_name in sorted(list(const_tensor_names_to_permute)):
                const_tensor = model_ir.tensors.get(str(const_name), None)
                if const_tensor is None or const_tensor.data is None:
                    continue
                const_arr = np.asarray(const_tensor.data)
                if const_arr.ndim != 4 or int(const_arr.size) <= 1:
                    continue
                transposed = np.transpose(const_arr, axes=perm_nchw_to_nhwc)
                const_tensor.data = np.asarray(transposed)
                const_tensor.shape = [int(v) for v in list(transposed.shape)]
                const_tensor.shape_signature = [int(v) for v in list(transposed.shape)]

            for op_idx in sorted(list(closure_ops)):
                op = model_ir.operators[int(op_idx)]
                old_inputs = [str(v) for v in list(op.inputs)]
                new_inputs: List[str] = []
                for input_name in old_inputs:
                    boundary = boundary_transpose_by_tensor.get(str(input_name), None)
                    if boundary is not None:
                        new_inputs.append(str(boundary[0]))
                        remove_indices.add(int(boundary[1]))
                    else:
                        new_inputs.append(str(input_name))
                if new_inputs != old_inputs:
                    _set_operator_inputs(
                        model_ir=model_ir,
                        op=op,
                        new_inputs=[str(v) for v in list(new_inputs)],
                    )
                for output_name in [str(v) for v in list(op.outputs)]:
                    if str(output_name) in legacy_consumer_slots_by_output:
                        output_tensor = model_ir.tensors.get(str(output_name), None)
                        if output_tensor is not None and len(list(output_tensor.shape)) == 4:
                            legacy_nchw_tensor_meta_by_output[str(output_name)] = (
                                str(output_tensor.dtype),
                                _clone_quantization(output_tensor.quantization),
                                [int(v) for v in list(output_tensor.shape)],
                                (
                                    [int(v) for v in list(output_tensor.shape_signature)]
                                    if output_tensor.shape_signature is not None
                                    else [int(v) for v in list(output_tensor.shape)]
                                ),
                            )
                    _permute_tensor_metadata_if_rank_matches(
                        model_ir.tensors.get(str(output_name), None),
                        perm_nchw_to_nhwc,
                    )

            post_indices_to_remove: set[int] = set()
            for concat_idx in sorted(list(target_concats)):
                concat_op = model_ir.operators[int(concat_idx)]
                old_concat_out_name = str(concat_op.outputs[0])
                old_concat_tensor = model_ir.tensors.get(old_concat_out_name, None)
                old_inputs = [str(v) for v in list(concat_op.inputs)]
                new_inputs: List[str] = []
                for input_name in old_inputs:
                    boundary = boundary_transpose_by_tensor.get(str(input_name), None)
                    if boundary is not None:
                        new_inputs.append(str(boundary[0]))
                        remove_indices.add(int(boundary[1]))
                    else:
                        new_inputs.append(str(input_name))
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=concat_op,
                    new_inputs=[str(v) for v in list(new_inputs)],
                )
                concat_op.options["axis"] = 3
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(old_concat_out_name, None),
                    perm_nchw_to_nhwc,
                )

                post_indices = sorted([int(v) for v in post_by_concat.get(int(concat_idx), [])])
                if len(post_indices) == 0:
                    valid_group = False
                    break
                canonical_post_idx = int(post_indices[0])
                canonical_post_op = model_ir.operators[int(canonical_post_idx)]
                canonical_post_out_name = str(canonical_post_op.outputs[0])
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=concat_op,
                    new_outputs=[canonical_post_out_name],
                )
                for alias_post_idx in post_indices[1:]:
                    alias_post_op = model_ir.operators[int(alias_post_idx)]
                    alias_output_name = str(alias_post_op.outputs[0])
                    _replace_tensor_inputs(model_ir, alias_output_name, canonical_post_out_name)
                canonical_post_tensor = model_ir.tensors.get(canonical_post_out_name, None)
                if old_concat_tensor is not None and canonical_post_tensor is not None:
                    canonical_post_tensor.dtype = str(old_concat_tensor.dtype)
                    canonical_post_tensor.quantization = _clone_quantization(old_concat_tensor.quantization)
                    canonical_post_tensor.shape = [int(v) for v in list(old_concat_tensor.shape)]
                    canonical_post_tensor.shape_signature = (
                        [int(v) for v in list(old_concat_tensor.shape_signature)]
                        if old_concat_tensor.shape_signature is not None
                        else [int(v) for v in list(old_concat_tensor.shape)]
                    )
                for post_idx in post_indices:
                    post_indices_to_remove.add(int(post_idx))

            if not valid_group:
                continue

            for post_idx in post_indices_to_remove:
                remove_indices.add(int(post_idx))

            consumers_after = _build_tensor_consumer_map(model_ir)
            final_remove_indices: set[int] = set()
            for remove_idx in sorted(list(remove_indices)):
                if int(remove_idx) < 0 or int(remove_idx) >= len(model_ir.operators):
                    continue
                if int(remove_idx) in post_indices_to_remove:
                    final_remove_indices.add(int(remove_idx))
                    continue
                remove_op = model_ir.operators[int(remove_idx)]
                if str(remove_op.op_type) != "TRANSPOSE" or len(remove_op.outputs) != 1:
                    continue
                remove_out_name = str(remove_op.outputs[0])
                if remove_out_name in model_outputs:
                    continue
                if len(consumers_after.get(remove_out_name, [])) == 0:
                    final_remove_indices.add(int(remove_idx))

            for remove_idx in sorted(list(final_remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            adapter_insertions: List[Tuple[int, OperatorIR]] = []
            op_index_by_id = {int(id(op)): int(op_idx) for op_idx, op in enumerate(model_ir.operators)}
            for output_name, legacy_slots in legacy_consumer_slots_by_output.items():
                output_tensor = model_ir.tensors.get(str(output_name), None)
                if output_tensor is None or len(list(output_tensor.shape)) != 4:
                    continue
                slot_targets: List[Tuple[int, int]] = []
                for consumer_op_id, input_index in legacy_slots:
                    consumer_index = op_index_by_id.get(int(consumer_op_id), None)
                    if consumer_index is None:
                        continue
                    if int(consumer_index) < 0 or int(consumer_index) >= len(model_ir.operators):
                        continue
                    consumer_op = model_ir.operators[int(consumer_index)]
                    if int(input_index) < 0 or int(input_index) >= len(consumer_op.inputs):
                        continue
                    if str(consumer_op.inputs[int(input_index)]) != str(output_name):
                        continue
                    slot_targets.append((int(consumer_index), int(input_index)))
                if len(slot_targets) == 0:
                    continue

                adapter_name = _unique_tensor_name(f"{output_name}_nchw_adapter")
                legacy_meta = legacy_nchw_tensor_meta_by_output.get(str(output_name), None)
                if legacy_meta is not None:
                    adapter_dtype, adapter_quant, adapter_shape, adapter_shape_signature = legacy_meta
                else:
                    adapter_dtype = str(output_tensor.dtype)
                    adapter_quant = _clone_quantization(output_tensor.quantization)
                    adapter_shape = [int(v) for v in list(output_tensor.shape)]
                    adapter_shape_signature = (
                        [int(v) for v in list(output_tensor.shape_signature)]
                        if output_tensor.shape_signature is not None
                        else [int(v) for v in list(output_tensor.shape)]
                    )
                model_ir.tensors[adapter_name] = TensorIR(
                    name=adapter_name,
                    dtype=str(adapter_dtype),
                    shape=[int(v) for v in list(adapter_shape)],
                    shape_signature=[int(v) for v in list(adapter_shape_signature)],
                    data=None,
                    is_variable=False,
                    quantization=_clone_quantization(adapter_quant),
                )
                adapter_op = OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[str(output_name), perm_nhwc_to_nchw_const_name],
                    outputs=[adapter_name],
                )
                for consumer_index, input_index in slot_targets:
                    consumer_op = model_ir.operators[int(consumer_index)]
                    new_inputs = [str(v) for v in list(consumer_op.inputs)]
                    new_inputs[int(input_index)] = str(adapter_name)
                    _set_operator_inputs(
                        model_ir=model_ir,
                        op=consumer_op,
                        new_inputs=new_inputs,
                    )
                insert_index = min(int(v[0]) for v in slot_targets)
                adapter_insertions.append((int(insert_index), adapter_op))

            if len(adapter_insertions) > 0:
                inserted = 0
                for insert_idx, adapter_op in sorted(adapter_insertions, key=lambda v: int(v[0])):
                    model_ir.operators.insert(int(insert_idx + inserted), adapter_op)
                    inserted += 1

            optimized_groups += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_elementwise_concat_conv_nhwc_groups": int(optimized_groups)}


def _optimize_transpose_pre_concat_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Convert NCHW concat blocks back to NHWC when they are wrapped by transpose adapters.

    Target:
      ... -> t_i_nchw (some inputs may be pseudo-LeakyRelu outputs from transpose-wrapped NHWC)
      CONCAT(axis=1, [t_0_nchw, ...]) -> y_nchw
      y_nchw -> TRANSPOSE(0,2,3,1) -> y_nhwc

    Rewrite:
      ... -> t_i_nhwc
      CONCAT(axis=3, [t_0_nhwc, ...]) -> y_nhwc
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _analyze_swish_input_to_nhwc(
        *,
        input_name: str,
        consumer_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        mul_idx = producers.get(str(input_name), None)
        if mul_idx is None:
            return None
        mul_op = model_ir.operators[int(mul_idx)]
        if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
            return None
        if str(mul_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        if set(int(v) for v in consumers.get(str(input_name), [])) != {int(consumer_idx)}:
            return None

        in0_name = str(mul_op.inputs[0])
        in1_name = str(mul_op.inputs[1])
        in0_prod_idx = producers.get(in0_name, None)
        in1_prod_idx = producers.get(in1_name, None)

        log_idx: Optional[int] = None
        log_out_name: Optional[str] = None
        pre_nchw_name: Optional[str] = None
        mul_data_input_index: Optional[int] = None

        if in0_prod_idx is not None:
            in0_prod_op = model_ir.operators[int(in0_prod_idx)]
            if (
                str(in0_prod_op.op_type) == "LOGISTIC"
                and len(in0_prod_op.inputs) == 1
                and len(in0_prod_op.outputs) == 1
                and str(in0_prod_op.outputs[0]) == in0_name
            ):
                log_idx = int(in0_prod_idx)
                log_out_name = in0_name
                pre_nchw_name = str(in0_prod_op.inputs[0])
                mul_data_input_index = 1

        if log_idx is None and in1_prod_idx is not None:
            in1_prod_op = model_ir.operators[int(in1_prod_idx)]
            if (
                str(in1_prod_op.op_type) == "LOGISTIC"
                and len(in1_prod_op.inputs) == 1
                and len(in1_prod_op.outputs) == 1
                and str(in1_prod_op.outputs[0]) == in1_name
            ):
                log_idx = int(in1_prod_idx)
                log_out_name = in1_name
                pre_nchw_name = str(in1_prod_op.inputs[0])
                mul_data_input_index = 0

        if log_idx is None or log_out_name is None or pre_nchw_name is None or mul_data_input_index is None:
            return None

        if str(mul_op.inputs[int(mul_data_input_index)]) != str(pre_nchw_name):
            return None

        pre_idx = producers.get(str(pre_nchw_name), None)
        if pre_idx is None:
            return None
        pre_op = model_ir.operators[int(pre_idx)]
        if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
            return None
        if str(pre_op.outputs[0]) != str(pre_nchw_name):
            return None
        if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
            return None
        if str(pre_nchw_name) in model_outputs:
            return None

        if set(int(v) for v in consumers.get(str(pre_nchw_name), [])) != {int(log_idx), int(mul_idx)}:
            return None
        if set(int(v) for v in consumers.get(str(log_out_name), [])) != {int(mul_idx)}:
            return None

        return {
            "pre_idx": int(pre_idx),
            "pre_input_name": str(pre_op.inputs[0]),
            "log_idx": int(log_idx),
            "mul_idx": int(mul_idx),
            "mul_data_input_index": int(mul_data_input_index),
            "log_out_name": str(log_out_name),
            "mul_out_name": str(input_name),
        }

    def _apply_swish_nhwc_plan(*, plan: Dict[str, Any]) -> List[int]:
        pre_idx = int(plan["pre_idx"])
        pre_input_name = str(plan["pre_input_name"])
        log_idx = int(plan["log_idx"])
        mul_idx = int(plan["mul_idx"])
        mul_data_input_index = int(plan["mul_data_input_index"])
        log_out_name = str(plan["log_out_name"])
        mul_out_name = str(plan["mul_out_name"])

        mul_op = model_ir.operators[int(mul_idx)]
        _set_operator_inputs(
            model_ir=model_ir,
            op=model_ir.operators[int(log_idx)],
            new_inputs=[pre_input_name],
        )
        _replace_operator_input_at(
            model_ir=model_ir,
            op=mul_op,
            input_index=int(mul_data_input_index),
            new_input_name=pre_input_name,
        )

        for tensor_name in [log_out_name, mul_out_name]:
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(tensor_name, None),
                perm_nchw_to_nhwc,
            )
        return [int(pre_idx)]

    def _try_rewrite_swish_input_to_nhwc(
        *,
        input_name: str,
        consumer_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        return _analyze_swish_input_to_nhwc(
            input_name=input_name,
            consumer_idx=consumer_idx,
            producers=producers,
            consumers=consumers,
            model_outputs=model_outputs,
        )

    def _try_rewrite_leaky_input_to_nhwc(
        *,
        input_name: str,
        concat_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        sub_idx = producers.get(str(input_name), None)
        if sub_idx is None:
            return None
        sub_op = model_ir.operators[int(sub_idx)]
        if str(sub_op.op_type) != "SUB" or len(sub_op.inputs) != 2 or len(sub_op.outputs) != 1:
            return None
        if str(sub_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        input_users = [int(v) for v in consumers.get(str(input_name), [])]
        if set(input_users) != {int(concat_idx)}:
            return None

        relu_pos_out_name = str(sub_op.inputs[0])
        mul_out_name = str(sub_op.inputs[1])

        relu_pos_idx = producers.get(relu_pos_out_name, None)
        mul_idx = producers.get(mul_out_name, None)
        if relu_pos_idx is None or mul_idx is None:
            return None
        relu_pos_op = model_ir.operators[int(relu_pos_idx)]
        mul_op = model_ir.operators[int(mul_idx)]
        if str(relu_pos_op.op_type) != "RELU" or len(relu_pos_op.inputs) != 1 or len(relu_pos_op.outputs) != 1:
            return None
        if str(relu_pos_op.outputs[0]) != relu_pos_out_name:
            return None
        if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
            return None
        if str(mul_op.outputs[0]) != mul_out_name:
            return None
        if not _is_singleton_constant_tensor(model_ir, str(mul_op.inputs[0])) and not _is_singleton_constant_tensor(
            model_ir, str(mul_op.inputs[1])
        ):
            return None

        relu_pos_in_name = str(relu_pos_op.inputs[0])
        mul_in0 = str(mul_op.inputs[0])
        mul_in1 = str(mul_op.inputs[1])
        relu_neg_out_name = mul_in0 if mul_in0 != relu_pos_in_name else mul_in1
        if relu_neg_out_name == relu_pos_in_name:
            relu_neg_out_name = mul_in1 if mul_in0 == relu_pos_in_name else mul_in0
        relu_neg_idx = producers.get(relu_neg_out_name, None)
        if relu_neg_idx is None:
            return None
        relu_neg_op = model_ir.operators[int(relu_neg_idx)]
        if str(relu_neg_op.op_type) != "RELU" or len(relu_neg_op.inputs) != 1 or len(relu_neg_op.outputs) != 1:
            return None
        if str(relu_neg_op.outputs[0]) != relu_neg_out_name:
            return None

        neg_out_name = str(relu_neg_op.inputs[0])
        neg_idx = producers.get(neg_out_name, None)
        if neg_idx is None:
            return None
        neg_op = model_ir.operators[int(neg_idx)]
        if str(neg_op.op_type) != "NEG" or len(neg_op.inputs) != 1 or len(neg_op.outputs) != 1:
            return None
        if str(neg_op.outputs[0]) != neg_out_name:
            return None

        pre_nchw_name = str(neg_op.inputs[0])
        if relu_pos_in_name != pre_nchw_name:
            return None
        pre_idx = producers.get(pre_nchw_name, None)
        if pre_idx is None:
            return None
        pre_op = model_ir.operators[int(pre_idx)]
        if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
            return None
        if str(pre_op.outputs[0]) != pre_nchw_name:
            return None
        if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
            return None
        if str(pre_nchw_name) in model_outputs:
            return None
        pre_users = [int(v) for v in consumers.get(pre_nchw_name, [])]
        if set(pre_users) != {int(neg_idx), int(relu_pos_idx)}:
            return None

        if set(int(v) for v in consumers.get(neg_out_name, [])) != {int(relu_neg_idx)}:
            return None
        if set(int(v) for v in consumers.get(relu_neg_out_name, [])) != {int(mul_idx)}:
            return None
        if set(int(v) for v in consumers.get(relu_pos_out_name, [])) != {int(sub_idx)}:
            return None
        if set(int(v) for v in consumers.get(mul_out_name, [])) != {int(sub_idx)}:
            return None

        return {
            "input_name": str(input_name),
            "pre_idx": int(pre_idx),
            "pre_input_name": str(pre_op.inputs[0]),
            "neg_idx": int(neg_idx),
            "relu_pos_idx": int(relu_pos_idx),
            "tensors_to_permute": [
                str(neg_out_name),
                str(relu_pos_out_name),
                str(relu_neg_out_name),
                str(mul_out_name),
                str(input_name),
            ],
        }

    def _apply_leaky_nhwc_plan(*, plan: Dict[str, Any]) -> List[int]:
        pre_idx = int(plan["pre_idx"])
        pre_input_name = str(plan["pre_input_name"])
        neg_idx = int(plan["neg_idx"])
        relu_pos_idx = int(plan["relu_pos_idx"])
        tensors_to_permute = [str(v) for v in list(plan.get("tensors_to_permute", []))]

        _set_operator_inputs(
            model_ir=model_ir,
            op=model_ir.operators[int(neg_idx)],
            new_inputs=[pre_input_name],
        )
        _set_operator_inputs(
            model_ir=model_ir,
            op=model_ir.operators[int(relu_pos_idx)],
            new_inputs=[pre_input_name],
        )
        for tensor_name in tensors_to_permute:
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(tensor_name), None),
                perm_nchw_to_nhwc,
            )
        return [int(pre_idx)]

    def _try_rewrite_add_input_to_nhwc(
        *,
        input_name: str,
        concat_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        add_idx = producers.get(str(input_name), None)
        if add_idx is None:
            return None
        add_op = model_ir.operators[int(add_idx)]
        if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
            return None
        if str(add_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        if set(int(v) for v in consumers.get(str(input_name), [])) != {int(concat_idx)}:
            return None

        actions: List[Dict[str, Any]] = []
        for add_input_name in [str(v) for v in list(add_op.inputs)]:
            input_producer_idx = producers.get(add_input_name, None)
            if input_producer_idx is not None:
                input_producer_op = model_ir.operators[int(input_producer_idx)]
                input_users = set(int(v) for v in consumers.get(add_input_name, []))
                if (
                    str(input_producer_op.op_type) == "TRANSPOSE"
                    and len(input_producer_op.inputs) >= 2
                    and len(input_producer_op.outputs) == 1
                    and str(input_producer_op.outputs[0]) == add_input_name
                    and _read_transpose_perm(model_ir, input_producer_op) == perm_nhwc_to_nchw
                    and int(add_idx) in input_users
                ):
                    extra_users = {int(v) for v in input_users if int(v) != int(add_idx)}
                    if extra_users.difference({int(concat_idx)}):
                        return None
                    actions.append(
                        {
                            "kind": "direct",
                            "new_input_name": str(input_producer_op.inputs[0]),
                            "remove_indices": (
                                [int(input_producer_idx)] if len(extra_users) == 0 else []
                            ),
                        }
                    )
                    continue

            unary_plan = _try_rewrite_unary_input_to_nhwc(
                input_name=add_input_name,
                concat_idx=int(add_idx),
                producers=producers,
                consumers=consumers,
                model_outputs=model_outputs,
            )
            if unary_plan is not None:
                actions.append(
                    {
                        "kind": "unary",
                        "new_input_name": str(add_input_name),
                        "plan": unary_plan,
                    }
                )
                continue

            swish_plan = _analyze_swish_input_to_nhwc(
                input_name=add_input_name,
                consumer_idx=int(add_idx),
                producers=producers,
                consumers=consumers,
                model_outputs=model_outputs,
            )
            if swish_plan is not None:
                actions.append(
                    {
                        "kind": "swish",
                        "new_input_name": str(add_input_name),
                        "plan": swish_plan,
                    }
                )
                continue

            return None

        new_add_inputs: List[str] = []
        remove_indices: List[int] = []
        for action in actions:
            action_kind = str(action.get("kind", ""))
            if action_kind == "direct":
                new_add_inputs.append(str(action["new_input_name"]))
                remove_indices.extend([int(v) for v in list(action.get("remove_indices", []))])
                continue
            if action_kind == "swish":
                new_add_inputs.append(str(action["new_input_name"]))
                remove_indices.extend([])
                continue
            if action_kind == "unary":
                new_add_inputs.append(str(action["new_input_name"]))
                remove_indices.extend([])
                continue
            return None

        return {
            "input_name": str(input_name),
            "add_idx": int(add_idx),
            "new_add_inputs": [str(v) for v in new_add_inputs],
            "remove_indices": [int(v) for v in remove_indices],
            "actions": [dict(v) for v in actions],
        }

    def _apply_add_nhwc_plan(*, plan: Dict[str, Any]) -> List[int]:
        input_name = str(plan["input_name"])
        add_idx = int(plan["add_idx"])
        new_add_inputs = [str(v) for v in list(plan.get("new_add_inputs", []))]
        remove_indices = [int(v) for v in list(plan.get("remove_indices", []))]
        actions = [dict(v) for v in list(plan.get("actions", []))]

        for action in actions:
            action_kind = str(action.get("kind", ""))
            if action_kind == "swish":
                swish_plan = action.get("plan", None)
                if swish_plan is None:
                    continue
                swish_pre_remove = _apply_swish_nhwc_plan(plan=dict(swish_plan))
                remove_indices.extend([int(v) for v in swish_pre_remove])
                continue
            if action_kind == "unary":
                unary_plan = action.get("plan", None)
                if unary_plan is None:
                    continue
                unary_pre_remove = _apply_unary_nhwc_plan(plan=dict(unary_plan))
                remove_indices.extend([int(v) for v in unary_pre_remove])
                continue

        _set_operator_inputs(
            model_ir=model_ir,
            op=model_ir.operators[int(add_idx)],
            new_inputs=[str(v) for v in list(new_add_inputs)],
        )
        _permute_tensor_metadata_if_rank_matches(
            model_ir.tensors.get(input_name, None),
            perm_nchw_to_nhwc,
        )
        return [int(v) for v in remove_indices]

    def _try_rewrite_pad_input_to_nhwc(
        *,
        input_name: str,
        concat_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        pad_idx = producers.get(str(input_name), None)
        if pad_idx is None:
            return None
        pad_op = model_ir.operators[int(pad_idx)]
        if str(pad_op.op_type) != "PAD" or len(pad_op.inputs) < 2 or len(pad_op.outputs) != 1:
            return None
        if str(pad_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        if set(int(v) for v in consumers.get(str(input_name), [])) != {int(concat_idx)}:
            return None

        pad_input_name = str(pad_op.inputs[0])
        pre_idx = producers.get(pad_input_name, None)
        if pre_idx is None:
            return None
        pre_op = model_ir.operators[int(pre_idx)]
        if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
            return None
        if str(pre_op.outputs[0]) != pad_input_name:
            return None
        if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
            return None
        if str(pad_input_name) in model_outputs:
            return None

        pads_tensor_name = str(pad_op.inputs[1])
        pads_tensor = model_ir.tensors.get(pads_tensor_name, None)
        if pads_tensor is None or pads_tensor.data is None:
            return None
        try:
            pads_array = np.asarray(pads_tensor.data)
            pads_pairs = pads_array.reshape(4, 2)
        except Exception:
            return None
        if int(pads_pairs.size) != 8:
            return None

        pre_users = set(int(v) for v in consumers.get(pad_input_name, []))
        remove_pre = pre_users == {int(pad_idx)}

        return {
            "input_name": str(input_name),
            "pad_idx": int(pad_idx),
            "pad_input_name": str(pad_input_name),
            "pad_input_rewritten_name": str(pre_op.inputs[0]),
            "pads_tensor_name": str(pads_tensor_name),
            "pre_idx": int(pre_idx),
            "remove_pre": bool(remove_pre),
        }

    def _apply_pad_nhwc_plan(*, plan: Dict[str, Any]) -> List[int]:
        input_name = str(plan["input_name"])
        pad_idx = int(plan["pad_idx"])
        pre_idx = int(plan["pre_idx"])
        remove_pre = bool(plan["remove_pre"])
        pad_rewritten_input_name = str(plan["pad_input_rewritten_name"])
        pads_tensor_name = str(plan["pads_tensor_name"])

        pad_op = model_ir.operators[int(pad_idx)]
        _set_operator_inputs(
            model_ir=model_ir,
            op=pad_op,
            new_inputs=[pad_rewritten_input_name, str(pad_op.inputs[1])],
        )

        pads_tensor = model_ir.tensors.get(pads_tensor_name, None)
        if pads_tensor is not None and pads_tensor.data is not None:
            pads_array = np.asarray(pads_tensor.data)
            pads_pairs = pads_array.reshape(4, 2)
            # NCHW [N,C,H,W] -> NHWC [N,H,W,C]
            pads_pairs = np.asarray(
                [pads_pairs[0], pads_pairs[2], pads_pairs[3], pads_pairs[1]],
                dtype=pads_array.dtype,
            )
            pads_tensor.data = pads_pairs
            pads_tensor.shape = [4, 2]
            pads_tensor.shape_signature = [4, 2]

        _permute_tensor_metadata_if_rank_matches(
            model_ir.tensors.get(input_name, None),
            perm_nchw_to_nhwc,
        )

        return [int(pre_idx)] if remove_pre else []

    def _try_rewrite_unary_input_to_nhwc(
        *,
        input_name: str,
        concat_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        unary_idx = producers.get(str(input_name), None)
        if unary_idx is None:
            return None
        unary_op = model_ir.operators[int(unary_idx)]
        if str(unary_op.op_type) not in {"RELU", "RELU6", "LOGISTIC", "TANH", "GELU"}:
            return None
        if len(unary_op.inputs) != 1 or len(unary_op.outputs) != 1:
            return None
        if str(unary_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        if set(int(v) for v in consumers.get(str(input_name), [])) != {int(concat_idx)}:
            return None

        pre_nchw_name = str(unary_op.inputs[0])
        pre_idx = producers.get(pre_nchw_name, None)
        if pre_idx is None:
            return None
        pre_op = model_ir.operators[int(pre_idx)]
        if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
            return None
        if str(pre_op.outputs[0]) != pre_nchw_name:
            return None
        if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
            return None
        if str(pre_nchw_name) in model_outputs:
            return None
        if set(int(v) for v in consumers.get(pre_nchw_name, [])) != {int(unary_idx)}:
            return None

        return {
            "input_name": str(input_name),
            "pre_idx": int(pre_idx),
            "pre_input_name": str(pre_op.inputs[0]),
            "unary_idx": int(unary_idx),
        }

    def _apply_unary_nhwc_plan(*, plan: Dict[str, Any]) -> List[int]:
        input_name = str(plan["input_name"])
        unary_idx = int(plan["unary_idx"])
        pre_idx = int(plan["pre_idx"])
        pre_input_name = str(plan["pre_input_name"])

        _set_operator_inputs(
            model_ir=model_ir,
            op=model_ir.operators[int(unary_idx)],
            new_inputs=[pre_input_name],
        )
        _permute_tensor_metadata_if_rank_matches(
            model_ir.tensors.get(input_name, None),
            perm_nchw_to_nhwc,
        )
        return [int(pre_idx)]

    def _project_shape_after_nchw_to_nhwc(tensor_name: str) -> Optional[List[int]]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None:
            return None
        shape = [int(v) for v in list(tensor.shape)]
        if len(shape) != 4:
            return None
        return [int(shape[0]), int(shape[2]), int(shape[3]), int(shape[1])]

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for concat_idx, concat_op in enumerate(model_ir.operators):
            if str(concat_op.op_type) != "CONCATENATION" or len(concat_op.outputs) != 1:
                continue
            concat_out_name = str(concat_op.outputs[0])
            concat_out_tensor = model_ir.tensors.get(concat_out_name, None)
            if concat_out_tensor is None or len(list(concat_out_tensor.shape)) != 4:
                continue

            concat_axis_old = int(concat_op.options.get("axis", 1))
            if concat_axis_old < 0:
                concat_axis_old += 4
            if concat_axis_old != 1:
                continue

            concat_users = [int(v) for v in consumers.get(concat_out_name, [])]
            if len(concat_users) == 0:
                continue
            post_indices: List[int] = []
            post_output_names: List[str] = []
            valid_post_only = True
            for user_idx in concat_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == concat_out_name
                    and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                    and str(user_op.outputs[0]) not in model_outputs
                ):
                    post_indices.append(int(user_idx))
                    post_output_names.append(str(user_op.outputs[0]))
                else:
                    valid_post_only = False
                    break
            if not valid_post_only or len(post_indices) == 0:
                continue

            concat_input_actions: List[Dict[str, Any]] = []
            rewritable = True
            for input_name in [str(v) for v in list(concat_op.inputs)]:
                input_producer_idx = producers.get(input_name, None)
                if input_producer_idx is not None:
                    input_producer_op = model_ir.operators[int(input_producer_idx)]
                    if (
                        str(input_producer_op.op_type) == "TRANSPOSE"
                        and len(input_producer_op.inputs) >= 2
                        and len(input_producer_op.outputs) == 1
                        and str(input_producer_op.outputs[0]) == input_name
                        and _read_transpose_perm(model_ir, input_producer_op) == perm_nhwc_to_nchw
                        and int(concat_idx) in set(int(v) for v in consumers.get(input_name, []))
                    ):
                        input_users = set(int(v) for v in consumers.get(input_name, []))
                        remove_indices = (
                            [int(input_producer_idx)]
                            if input_users == {int(concat_idx)}
                            else []
                        )
                        concat_input_actions.append(
                            {
                                "kind": "direct",
                                "input_name": str(input_name),
                                "new_input_name": str(input_producer_op.inputs[0]),
                                "remove_indices": remove_indices,
                            }
                        )
                        continue

                pad_plan = _try_rewrite_pad_input_to_nhwc(
                    input_name=input_name,
                    concat_idx=int(concat_idx),
                    producers=producers,
                    consumers=consumers,
                    model_outputs=model_outputs,
                )
                if pad_plan is not None:
                    concat_input_actions.append(
                        {
                            "kind": "pad",
                            "input_name": str(input_name),
                            "plan": dict(pad_plan),
                        }
                    )
                    continue

                leaky_plan = _try_rewrite_leaky_input_to_nhwc(
                    input_name=input_name,
                    concat_idx=int(concat_idx),
                    producers=producers,
                    consumers=consumers,
                    model_outputs=model_outputs,
                )
                if leaky_plan is not None:
                    concat_input_actions.append(
                        {
                            "kind": "leaky",
                            "input_name": str(input_name),
                            "plan": dict(leaky_plan),
                        }
                    )
                    continue

                unary_plan = _try_rewrite_unary_input_to_nhwc(
                    input_name=input_name,
                    concat_idx=int(concat_idx),
                    producers=producers,
                    consumers=consumers,
                    model_outputs=model_outputs,
                )
                if unary_plan is not None:
                    concat_input_actions.append(
                        {
                            "kind": "unary",
                            "input_name": str(input_name),
                            "plan": dict(unary_plan),
                        }
                    )
                    continue

                swish_plan = _try_rewrite_swish_input_to_nhwc(
                    input_name=input_name,
                    consumer_idx=int(concat_idx),
                    producers=producers,
                    consumers=consumers,
                    model_outputs=model_outputs,
                )
                if swish_plan is not None:
                    concat_input_actions.append(
                        {
                            "kind": "swish",
                            "input_name": str(input_name),
                            "plan": dict(swish_plan),
                        }
                    )
                    continue

                add_plan = _try_rewrite_add_input_to_nhwc(
                    input_name=input_name,
                    concat_idx=int(concat_idx),
                    producers=producers,
                    consumers=consumers,
                    model_outputs=model_outputs,
                )
                if add_plan is not None:
                    concat_input_actions.append(
                        {
                            "kind": "add",
                            "input_name": str(input_name),
                            "plan": dict(add_plan),
                        }
                    )
                    continue

                rewritable = False
                break

            if not rewritable:
                continue

            nhwc_inputs_ok = True
            nhwc_ref_shape: Optional[List[int]] = None
            for action in concat_input_actions:
                action_kind = str(action.get("kind", ""))
                if action_kind == "direct":
                    projected_input_name = str(action["new_input_name"])
                    input_tensor = model_ir.tensors.get(projected_input_name, None)
                    if input_tensor is None or len(list(input_tensor.shape)) != 4:
                        nhwc_inputs_ok = False
                        break
                    shape = [int(v) for v in list(input_tensor.shape)]
                elif action_kind in {"swish", "leaky", "add", "unary", "pad"}:
                    projected_input_name = str(action["input_name"])
                    projected_shape = _project_shape_after_nchw_to_nhwc(projected_input_name)
                    if projected_shape is None:
                        nhwc_inputs_ok = False
                        break
                    shape = [int(v) for v in list(projected_shape)]
                else:
                    nhwc_inputs_ok = False
                    break
                if nhwc_ref_shape is None:
                    nhwc_ref_shape = list(shape)
                else:
                    for dim_idx in [0, 1, 2]:
                        if int(shape[dim_idx]) != int(nhwc_ref_shape[dim_idx]):
                            nhwc_inputs_ok = False
                            break
                if not nhwc_inputs_ok:
                    break
            if not nhwc_inputs_ok or nhwc_ref_shape is None:
                continue

            new_concat_inputs: List[str] = []
            pre_remove_indices: List[int] = []
            for action in concat_input_actions:
                action_kind = str(action.get("kind", ""))
                if action_kind == "direct":
                    new_concat_inputs.append(str(action["new_input_name"]))
                    pre_remove_indices.extend([int(v) for v in list(action.get("remove_indices", []))])
                    continue
                if action_kind == "pad":
                    new_concat_inputs.append(str(action["input_name"]))
                    pre_remove_indices.extend(
                        _apply_pad_nhwc_plan(plan=dict(action["plan"]))
                    )
                    continue
                if action_kind == "swish":
                    new_concat_inputs.append(str(action["input_name"]))
                    pre_remove_indices.extend(
                        _apply_swish_nhwc_plan(plan=dict(action["plan"]))
                    )
                    continue
                if action_kind == "leaky":
                    new_concat_inputs.append(str(action["input_name"]))
                    pre_remove_indices.extend(
                        _apply_leaky_nhwc_plan(plan=dict(action["plan"]))
                    )
                    continue
                if action_kind == "add":
                    new_concat_inputs.append(str(action["input_name"]))
                    pre_remove_indices.extend(
                        _apply_add_nhwc_plan(plan=dict(action["plan"]))
                    )
                    continue
                if action_kind == "unary":
                    new_concat_inputs.append(str(action["input_name"]))
                    pre_remove_indices.extend(
                        _apply_unary_nhwc_plan(plan=dict(action["plan"]))
                    )
                    continue
                rewritable = False
                break
            if not rewritable:
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=concat_op,
                new_inputs=[str(v) for v in new_concat_inputs],
            )
            concat_op.options["axis"] = 3

            canonical_post_output_name = str(post_output_names[0])
            _set_operator_outputs(
                model_ir=model_ir,
                op=concat_op,
                new_outputs=[canonical_post_output_name],
            )
            for alias_post_output_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, alias_post_output_name, canonical_post_output_name)

            old_concat_tensor = model_ir.tensors.get(concat_out_name, None)
            canonical_post_tensor = model_ir.tensors.get(canonical_post_output_name, None)
            if old_concat_tensor is not None and canonical_post_tensor is not None:
                canonical_post_tensor.dtype = str(old_concat_tensor.dtype)
                canonical_post_tensor.quantization = _clone_quantization(old_concat_tensor.quantization)

            remove_indices = sorted(
                list({int(v) for v in pre_remove_indices + post_indices}),
                reverse=True,
            )
            for remove_idx in remove_indices:
                if int(remove_idx) == int(concat_idx):
                    continue
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_pre_concat_nhwc_chains": int(optimized)}


def _optimize_transpose_stridedslice_pre_concat_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate NCHW round-trips around stride-slice fan-in concat blocks.

    Target:
      X_nhwc --TRANSPOSE(0,3,1,2)--> X_nchw
      X_nchw --STRIDED_SLICE(...)--> s_i_nchw   (all consumed by one CONCAT axis=1)
      CONCAT(axis=1, [s_i_nchw...]) --> y_nchw
      y_nchw --TRANSPOSE(0,2,3,1)--> y_nhwc

    Rewrite:
      X_nhwc --STRIDED_SLICE'(NHWC params)--> s_i_nhwc
      CONCAT(axis=3, [s_i_nhwc...]) --> y_nhwc

    If legacy NCHW consumers of `y_nchw` exist, keep one adapter:
      y_nhwc --TRANSPOSE(0,3,1,2)--> y_nchw
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _is_supported_stridedslice(op: OperatorIR) -> bool:
        if str(op.op_type) != "STRIDED_SLICE":
            return False
        if len(op.inputs) != 4 or len(op.outputs) != 1:
            return False
        opts = op.options if isinstance(op.options, dict) else {}
        if int(opts.get("beginMask", 0)) != 0:
            return False
        if int(opts.get("endMask", 0)) != 0:
            return False
        if int(opts.get("ellipsisMask", 0)) != 0:
            return False
        if int(opts.get("newAxisMask", 0)) != 0:
            return False
        if int(opts.get("shrinkAxisMask", 0)) != 0:
            return False
        if bool(opts.get("offset", False)):
            return False
        return True

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_output_name in model_outputs:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) < 2:
                continue

            slice_indices: List[int] = []
            slice_output_names: List[str] = []
            stridedslice_consts: List[Tuple[str, str, str]] = []
            valid_slices = True
            for user_idx in pre_users:
                user_op = model_ir.operators[int(user_idx)]
                if not _is_supported_stridedslice(user_op):
                    valid_slices = False
                    break
                if str(user_op.inputs[0]) != pre_output_name:
                    valid_slices = False
                    break
                out_name = str(user_op.outputs[0])
                if out_name in model_outputs:
                    valid_slices = False
                    break

                begin_name = str(user_op.inputs[1])
                end_name = str(user_op.inputs[2])
                strides_name = str(user_op.inputs[3])
                begin_tensor = model_ir.tensors.get(begin_name, None)
                end_tensor = model_ir.tensors.get(end_name, None)
                strides_tensor = model_ir.tensors.get(strides_name, None)
                begin_vals = _read_const_ints_from_tensor(begin_tensor)
                end_vals = _read_const_ints_from_tensor(end_tensor)
                strides_vals = _read_const_ints_from_tensor(strides_tensor)
                if begin_vals is None or end_vals is None or strides_vals is None:
                    valid_slices = False
                    break
                if len(begin_vals) != 4 or len(end_vals) != 4 or len(strides_vals) != 4:
                    valid_slices = False
                    break
                if any(int(v) == 0 for v in strides_vals):
                    valid_slices = False
                    break
                # Avoid mutating shared constants.
                if set(int(v) for v in consumers.get(begin_name, [])) != {int(user_idx)}:
                    valid_slices = False
                    break
                if set(int(v) for v in consumers.get(end_name, [])) != {int(user_idx)}:
                    valid_slices = False
                    break
                if set(int(v) for v in consumers.get(strides_name, [])) != {int(user_idx)}:
                    valid_slices = False
                    break

                slice_indices.append(int(user_idx))
                slice_output_names.append(out_name)
                stridedslice_consts.append((begin_name, end_name, strides_name))

            if not valid_slices:
                continue

            concat_idx: Optional[int] = None
            for slice_out_name in slice_output_names:
                users = [int(v) for v in consumers.get(slice_out_name, [])]
                if len(users) != 1:
                    concat_idx = None
                    break
                if concat_idx is None:
                    concat_idx = int(users[0])
                elif int(concat_idx) != int(users[0]):
                    concat_idx = None
                    break
            if concat_idx is None:
                continue

            concat_op = model_ir.operators[int(concat_idx)]
            if str(concat_op.op_type) != "CONCATENATION" or len(concat_op.outputs) != 1:
                continue
            concat_axis_old = int(concat_op.options.get("axis", 1))
            if concat_axis_old < 0:
                concat_axis_old += 4
            if concat_axis_old != 1:
                continue

            concat_inputs = [str(v) for v in list(concat_op.inputs)]
            if len(concat_inputs) != len(slice_output_names):
                continue
            if set(concat_inputs) != set(slice_output_names):
                continue

            concat_out_name = str(concat_op.outputs[0])
            concat_users = [int(v) for v in consumers.get(concat_out_name, []) if int(v) != int(concat_idx)]
            if len(concat_users) == 0:
                continue

            post_indices: List[int] = []
            post_output_names: List[str] = []
            legacy_users: List[int] = []
            valid_posts = True
            for user_idx in concat_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == concat_out_name
                    and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                    and str(user_op.outputs[0]) not in model_outputs
                ):
                    post_indices.append(int(user_idx))
                    post_output_names.append(str(user_op.outputs[0]))
                else:
                    legacy_users.append(int(user_idx))
            if not valid_posts or len(post_indices) == 0:
                continue

            # Rewrite all STRIDED_SLICE params/layout from NCHW to NHWC.
            rewrite_ok = True
            for slice_idx, (begin_name, end_name, strides_name), slice_out_name in zip(
                slice_indices,
                stridedslice_consts,
                slice_output_names,
            ):
                slice_op = model_ir.operators[int(slice_idx)]
                begin_tensor = model_ir.tensors.get(begin_name, None)
                end_tensor = model_ir.tensors.get(end_name, None)
                strides_tensor = model_ir.tensors.get(strides_name, None)
                begin_vals = _read_const_ints_from_tensor(begin_tensor)
                end_vals = _read_const_ints_from_tensor(end_tensor)
                strides_vals = _read_const_ints_from_tensor(strides_tensor)
                if begin_vals is None or end_vals is None or strides_vals is None:
                    rewrite_ok = False
                    break
                begin_nhwc = _permute_shape(begin_vals, perm_nchw_to_nhwc)
                end_nhwc = _permute_shape(end_vals, perm_nchw_to_nhwc)
                strides_nhwc = _permute_shape(strides_vals, perm_nchw_to_nhwc)
                if begin_nhwc is None or end_nhwc is None or strides_nhwc is None:
                    rewrite_ok = False
                    break
                _write_const_ints_to_tensor(begin_tensor, [int(v) for v in begin_nhwc])
                _write_const_ints_to_tensor(end_tensor, [int(v) for v in end_nhwc])
                _write_const_ints_to_tensor(strides_tensor, [int(v) for v in strides_nhwc])
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=slice_op,
                    input_index=0,
                    new_input_name=pre_input_name,
                )
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(slice_out_name, None),
                    perm_nchw_to_nhwc,
                )

            if not rewrite_ok:
                continue

            concat_op.options["axis"] = 3
            canonical_post_output_name = str(post_output_names[0])
            _set_operator_outputs(
                model_ir=model_ir,
                op=concat_op,
                new_outputs=[canonical_post_output_name],
            )
            for alias_post_output_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, alias_post_output_name, canonical_post_output_name)

            old_concat_tensor = model_ir.tensors.get(concat_out_name, None)
            canonical_post_tensor = model_ir.tensors.get(canonical_post_output_name, None)
            if old_concat_tensor is not None and canonical_post_tensor is not None:
                canonical_post_tensor.dtype = str(old_concat_tensor.dtype)
                canonical_post_tensor.quantization = _clone_quantization(old_concat_tensor.quantization)
                canonical_post_tensor.shape = [int(v) for v in list(old_concat_tensor.shape)]
                canonical_post_tensor.shape_signature = (
                    [int(v) for v in list(old_concat_tensor.shape_signature)]
                    if old_concat_tensor.shape_signature is not None
                    else [int(v) for v in list(old_concat_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    canonical_post_tensor,
                    perm_nchw_to_nhwc,
                )

            preserve_nchw_adapter = len(legacy_users) > 0 or concat_out_name in model_outputs
            if preserve_nchw_adapter:
                keep_post_idx = int(post_indices[0])
                keep_post_op = model_ir.operators[int(keep_post_idx)]
                keep_perm_name = str(keep_post_op.inputs[1])
                keep_perm_tensor = model_ir.tensors.get(keep_perm_name, None)
                if keep_perm_tensor is not None:
                    keep_perm_tensor.data = np.asarray(perm_nhwc_to_nchw, dtype=np.int32)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_inputs=[canonical_post_output_name, keep_perm_name],
                )
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_outputs=[concat_out_name],
                )
                post_remove_indices = [int(v) for v in post_indices[1:]]
            else:
                post_remove_indices = [int(v) for v in post_indices]

            remove_indices = sorted(
                list({int(pre_idx), *post_remove_indices}),
                reverse=True,
            )
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_stridedslice_pre_concat_nhwc_chains": int(optimized)}


def _optimize_transpose_input_chains_pre_concat_to_single_post_adapter(model_ir: ModelIR) -> Dict[str, int]:
    """
    Collapse per-input NHWC->NCHW adapters before CONCAT into a single post-CONCAT adapter.

    Target:
      x0_nhwc --TRANSPOSE(0,3,1,2)--> x0_nchw --(optional unary)--> i0_nchw
      x1_nhwc --TRANSPOSE(0,3,1,2)--> x1_nchw --(optional unary)--> i1_nchw
      ...
      CONCAT(axis=1, [i0_nchw, i1_nchw, ...]) -> y_nchw
      y_nchw -> downstream (e.g. RESHAPE)

    Rewrite:
      x0_nhwc --(optional unary)--> i0_nhwc
      x1_nhwc --(optional unary)--> i1_nhwc
      ...
      CONCAT(axis=3, [i0_nhwc, i1_nhwc, ...]) -> y_nhwc
      y_nhwc --TRANSPOSE(0,3,1,2)--> y_nchw

    This keeps downstream NCHW semantics unchanged while reducing redundant pre-concat
    transpose chains.

    Supported layout adapters:
      - TRANSPOSE(0,3,1,2)
      - RESHAPE [N,H,W,1] -> [N,1,H,W] (singleton-channel layout adapter)
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    unary_ops = {
        "LOGISTIC",
        "RELU",
        "RELU6",
        "RELU_0_TO_1",
        "LEAKY_RELU",
        "TANH",
        "GELU",
        "HARD_SWISH",
        "ABS",
        "EXP",
        "NEG",
        "SQRT",
    }

    def _unique_tensor_name(base: str) -> str:
        if base not in model_ir.tensors:
            return base
        suffix = 1
        while True:
            candidate = f"{base}_{suffix}"
            if candidate not in model_ir.tensors:
                return candidate
            suffix += 1

    def _is_singleton_channel_nhwc_to_nchw_reshape(
        *,
        input_name: str,
        output_name: str,
    ) -> bool:
        in_tensor = model_ir.tensors.get(str(input_name), None)
        out_tensor = model_ir.tensors.get(str(output_name), None)
        if in_tensor is None or out_tensor is None:
            return False
        in_shape = [int(v) for v in list(in_tensor.shape)]
        out_shape = [int(v) for v in list(out_tensor.shape)]
        if len(in_shape) != 4 or len(out_shape) != 4:
            return False
        return (
            int(in_shape[0]) == int(out_shape[0])
            and int(in_shape[1]) == int(out_shape[2])
            and int(in_shape[2]) == int(out_shape[3])
            and int(in_shape[3]) == 1
            and int(out_shape[1]) == 1
        )

    def _find_or_create_nhwc_to_nchw_perm_tensor() -> str:
        target = np.asarray(perm_nhwc_to_nchw, dtype=np.int32)
        for tensor_name, tensor in model_ir.tensors.items():
            if tensor is None or tensor.data is None:
                continue
            data = np.asarray(tensor.data)
            if data.dtype != np.int32 or data.size != 4:
                continue
            if np.array_equal(data.reshape(-1), target):
                return str(tensor_name)
        perm_name = _unique_tensor_name("transpose_input_chains_nhwc_to_nchw_perm")
        model_ir.tensors[perm_name] = TensorIR(
            name=perm_name,
            dtype="INT32",
            shape=[4],
            shape_signature=[4],
            data=target,
            is_variable=False,
        )
        return perm_name

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for concat_idx, concat_op in enumerate(model_ir.operators):
            if str(concat_op.op_type) != "CONCATENATION" or len(concat_op.outputs) != 1:
                continue

            concat_axis_old = int(concat_op.options.get("axis", 1))
            if concat_axis_old < 0:
                concat_axis_old += 4
            if concat_axis_old != 1:
                continue

            concat_out_name = str(concat_op.outputs[0])
            concat_out_tensor = model_ir.tensors.get(concat_out_name, None)
            if concat_out_tensor is None or len(list(concat_out_tensor.shape)) != 4:
                continue

            new_concat_inputs: List[str] = []
            pre_remove_indices: List[int] = []
            unary_input_rewrites: Dict[int, str] = {}
            unary_output_names_to_permute: List[str] = []
            adapter_perm_tensor_name: Optional[str] = None
            rewritable = True

            for input_name in [str(v) for v in list(concat_op.inputs)]:
                input_producer_idx = producers.get(str(input_name), None)
                if input_producer_idx is None:
                    rewritable = False
                    break
                input_producer = model_ir.operators[int(input_producer_idx)]

                if (
                    str(input_producer.op_type) == "TRANSPOSE"
                    and len(input_producer.inputs) >= 2
                    and len(input_producer.outputs) == 1
                    and str(input_producer.outputs[0]) == str(input_name)
                    and _read_transpose_perm(model_ir, input_producer) == perm_nhwc_to_nchw
                    and set(int(v) for v in consumers.get(str(input_name), [])) == {int(concat_idx)}
                    and str(input_name) not in model_outputs
                ):
                    new_concat_inputs.append(str(input_producer.inputs[0]))
                    pre_remove_indices.append(int(input_producer_idx))
                    if adapter_perm_tensor_name is None:
                        adapter_perm_tensor_name = str(input_producer.inputs[1])
                    continue

                if (
                    str(input_producer.op_type) in unary_ops
                    and len(input_producer.inputs) == 1
                    and len(input_producer.outputs) == 1
                    and str(input_producer.outputs[0]) == str(input_name)
                    and set(int(v) for v in consumers.get(str(input_name), [])) == {int(concat_idx)}
                    and str(input_name) not in model_outputs
                ):
                    unary_in_name = str(input_producer.inputs[0])
                    pre_idx = producers.get(unary_in_name, None)
                    if pre_idx is None:
                        rewritable = False
                        break
                    pre_op = model_ir.operators[int(pre_idx)]
                    if (
                        set(int(v) for v in consumers.get(unary_in_name, [])) != {int(input_producer_idx)}
                        or unary_in_name in model_outputs
                    ):
                        rewritable = False
                        break
                    if str(pre_op.op_type) == "TRANSPOSE":
                        if (
                            len(pre_op.inputs) < 2
                            or len(pre_op.outputs) != 1
                            or str(pre_op.outputs[0]) != unary_in_name
                            or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
                        ):
                            rewritable = False
                            break
                        if adapter_perm_tensor_name is None:
                            adapter_perm_tensor_name = str(pre_op.inputs[1])
                    elif str(pre_op.op_type) == "RESHAPE":
                        if (
                            len(pre_op.inputs) < 1
                            or len(pre_op.outputs) != 1
                            or str(pre_op.outputs[0]) != unary_in_name
                            or not _is_singleton_channel_nhwc_to_nchw_reshape(
                                input_name=str(pre_op.inputs[0]),
                                output_name=unary_in_name,
                            )
                        ):
                            rewritable = False
                            break
                    else:
                        rewritable = False
                        break
                    unary_input_rewrites[int(input_producer_idx)] = str(pre_op.inputs[0])
                    unary_output_names_to_permute.append(str(input_name))
                    new_concat_inputs.append(str(input_name))
                    pre_remove_indices.append(int(pre_idx))
                    continue

                rewritable = False
                break

            if not rewritable:
                continue
            if adapter_perm_tensor_name is None:
                adapter_perm_tensor_name = _find_or_create_nhwc_to_nchw_perm_tensor()

            unary_outputs_to_permute = {str(v) for v in unary_output_names_to_permute}
            nhwc_inputs_ok = True
            nhwc_ref_shape: Optional[List[int]] = None
            for input_name in new_concat_inputs:
                input_tensor = model_ir.tensors.get(str(input_name), None)
                if input_tensor is None or len(list(input_tensor.shape)) != 4:
                    nhwc_inputs_ok = False
                    break
                shape = [int(v) for v in list(input_tensor.shape)]
                if str(input_name) in unary_outputs_to_permute:
                    permuted_shape = _permute_shape(shape, perm_nchw_to_nhwc)
                    if permuted_shape is None:
                        nhwc_inputs_ok = False
                        break
                    shape = [int(v) for v in list(permuted_shape)]
                if nhwc_ref_shape is None:
                    nhwc_ref_shape = list(shape)
                else:
                    for dim_idx in [0, 1, 2]:
                        if int(shape[dim_idx]) != int(nhwc_ref_shape[dim_idx]):
                            nhwc_inputs_ok = False
                            break
                if not nhwc_inputs_ok:
                    break
            if not nhwc_inputs_ok:
                continue

            new_concat_shape = _permute_shape(list(concat_out_tensor.shape), perm_nchw_to_nhwc)
            concat_sig_source = (
                list(concat_out_tensor.shape_signature)
                if concat_out_tensor.shape_signature is not None
                else list(concat_out_tensor.shape)
            )
            new_concat_signature = _permute_shape(concat_sig_source, perm_nchw_to_nhwc)
            if new_concat_shape is None or new_concat_signature is None:
                continue

            for unary_idx, rewrite_input_name in unary_input_rewrites.items():
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=model_ir.operators[int(unary_idx)],
                    new_inputs=[str(rewrite_input_name)],
                )
            for tensor_name in unary_output_names_to_permute:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(tensor_name), None),
                    perm_nchw_to_nhwc,
                )

            new_concat_out_name = _unique_tensor_name(f"{concat_out_name}_nhwc")
            model_ir.tensors[new_concat_out_name] = TensorIR(
                name=new_concat_out_name,
                dtype=str(concat_out_tensor.dtype),
                shape=[int(v) for v in list(new_concat_shape)],
                data=None,
                quantization=_clone_quantization(concat_out_tensor.quantization),
                shape_signature=[int(v) for v in list(new_concat_signature)],
            )

            _set_operator_inputs(
                model_ir=model_ir,
                op=concat_op,
                new_inputs=[str(v) for v in new_concat_inputs],
            )
            concat_op.options["axis"] = 3
            _set_operator_outputs(
                model_ir=model_ir,
                op=concat_op,
                new_outputs=[str(new_concat_out_name)],
            )

            adapter_op = OperatorIR(
                op_type="TRANSPOSE",
                inputs=[str(new_concat_out_name), str(adapter_perm_tensor_name)],
                outputs=[str(concat_out_name)],
                options={},
            )
            model_ir.operators.insert(int(concat_idx) + 1, adapter_op)

            remove_indices = sorted(list({int(v) for v in pre_remove_indices}), reverse=True)
            for remove_idx in remove_indices:
                if int(remove_idx) == int(concat_idx):
                    continue
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_input_chains_pre_concat_to_single_post_adapter": int(optimized)}


def _optimize_shufflenet_transpose_shuffle_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Optimize ShuffleNet-style channel-shuffle blocks that rely on NCHW transpose chains.

    Target (representative):
      x_nhwc
        -> TRANSPOSE(0,3,1,2)
        -> RESHAPE -> TRANSPOSE(1,0,2) -> RESHAPE
        -> GATHER(idx=0/1)
      one gather -> TRANSPOSE(0,2,3,1) -> conv branch -> TRANSPOSE(0,3,1,2) -> (optional unary)
      other gather -> skip branch
      CONCAT(axis=1, [skip_nchw, branch_nchw]) -> y_nchw

    Rewrite:
      x_nhwc -> GATHER(axis=3, even/odd channels) -> skip_nhwc / branch_nhwc
      conv branch runs in NHWC directly
      CONCAT(axis=3, [skip_nhwc, branch_nhwc]) -> y_nhwc
      y_nhwc -> TRANSPOSE(0,3,1,2) -> y_nchw

    This preserves downstream NCHW contracts while reducing redundant transpose chains.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    unary_ops = {
        "LOGISTIC",
        "RELU",
        "RELU6",
        "RELU_0_TO_1",
        "LEAKY_RELU",
        "TANH",
        "GELU",
        "HARD_SWISH",
        "ABS",
        "EXP",
        "NEG",
        "SQRT",
    }
    branch_passthrough_ops = {
        "CONV_2D",
        "DEPTHWISE_CONV_2D",
        "ADD",
        "SUB",
        "MUL",
        "DIV",
        "PAD",
        "PADV2",
        "MAX_POOL_2D",
        "AVERAGE_POOL_2D",
        "CAST",
    }.union(unary_ops)

    def _unique_tensor_name(base: str) -> str:
        if base not in model_ir.tensors:
            return base
        suffix = 1
        while True:
            candidate = f"{base}_{suffix}"
            if candidate not in model_ir.tensors:
                return candidate
            suffix += 1

    def _op_index(op_ref: OperatorIR) -> Optional[int]:
        for idx, op in enumerate(model_ir.operators):
            if id(op) == id(op_ref):
                return int(idx)
        return None

    def _is_singleton_channel_nhwc_to_nchw_reshape(
        *,
        input_name: str,
        output_name: str,
    ) -> bool:
        input_tensor = model_ir.tensors.get(str(input_name), None)
        output_tensor = model_ir.tensors.get(str(output_name), None)
        if input_tensor is None or output_tensor is None:
            return False
        in_shape = [int(v) for v in list(input_tensor.shape)]
        out_shape = [int(v) for v in list(output_tensor.shape)]
        if len(in_shape) != 4 or len(out_shape) != 4:
            return False
        return (
            int(in_shape[0]) == int(out_shape[0])
            and int(in_shape[1]) == int(out_shape[2])
            and int(in_shape[2]) == int(out_shape[3])
            and int(in_shape[3]) == 1
            and int(out_shape[1]) == 1
        )

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for concat0_idx, concat0_op in enumerate(model_ir.operators):
            if str(concat0_op.op_type) != "CONCATENATION" or len(concat0_op.outputs) != 1:
                continue
            if int(concat0_op.options.get("axis", -1)) != 3:
                continue
            x_nhwc_name = str(concat0_op.outputs[0])
            x_nhwc_tensor = model_ir.tensors.get(x_nhwc_name, None)
            if x_nhwc_tensor is None or len(list(x_nhwc_tensor.shape)) != 4:
                continue
            x_shape = [int(v) for v in list(x_nhwc_tensor.shape)]
            channels = int(x_shape[3])
            if int(channels) <= 0 or int(channels % 2) != 0:
                continue
            half_channels = int(channels // 2)

            t0_users = [int(v) for v in consumers.get(x_nhwc_name, [])]
            if len(t0_users) != 1:
                continue
            t0_idx = int(t0_users[0])
            t0_op = model_ir.operators[t0_idx]
            if str(t0_op.op_type) != "TRANSPOSE" or len(t0_op.inputs) < 2 or len(t0_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, t0_op) != perm_nhwc_to_nchw:
                continue
            x_nchw_name = str(t0_op.outputs[0])
            if x_nchw_name in model_outputs:
                continue

            r1_users = [int(v) for v in consumers.get(x_nchw_name, [])]
            if len(r1_users) != 1:
                continue
            r1_op = model_ir.operators[int(r1_users[0])]
            if str(r1_op.op_type) != "RESHAPE" or len(r1_op.inputs) < 1 or len(r1_op.outputs) != 1:
                continue
            r1_out = str(r1_op.outputs[0])
            if r1_out in model_outputs:
                continue

            t1_users = [int(v) for v in consumers.get(r1_out, [])]
            if len(t1_users) != 1:
                continue
            t1_op = model_ir.operators[int(t1_users[0])]
            if str(t1_op.op_type) != "TRANSPOSE" or len(t1_op.inputs) < 2 or len(t1_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, t1_op) != [1, 0, 2]:
                continue
            t1_out = str(t1_op.outputs[0])
            if t1_out in model_outputs:
                continue

            r2_users = [int(v) for v in consumers.get(t1_out, [])]
            if len(r2_users) != 1:
                continue
            r2_op = model_ir.operators[int(r2_users[0])]
            if str(r2_op.op_type) != "RESHAPE" or len(r2_op.inputs) < 1 or len(r2_op.outputs) != 1:
                continue
            split_base = str(r2_op.outputs[0])
            if split_base in model_outputs:
                continue

            gather_user_indices = [int(v) for v in consumers.get(split_base, [])]
            if len(gather_user_indices) != 2:
                continue
            gather_candidates: Dict[int, Tuple[int, OperatorIR, str]] = {}
            gather_ops: List[OperatorIR] = []
            gather_ids: set[int] = set()
            valid_gathers = True
            for g_idx in gather_user_indices:
                g_op = model_ir.operators[int(g_idx)]
                if str(g_op.op_type) != "GATHER" or len(g_op.inputs) < 2 or len(g_op.outputs) != 1:
                    valid_gathers = False
                    break
                if int(g_op.options.get("axis", 0)) != 0:
                    valid_gathers = False
                    break
                idx_vals = _read_const_ints_from_tensor(model_ir.tensors.get(str(g_op.inputs[1]), None))
                if idx_vals is None or len(idx_vals) != 1:
                    valid_gathers = False
                    break
                idx_value = int(idx_vals[0])
                if idx_value not in [0, 1] or idx_value in gather_ids:
                    valid_gathers = False
                    break
                gather_ids.add(int(idx_value))
                gather_candidates[int(idx_value)] = (int(g_idx), g_op, str(g_op.outputs[0]))
                gather_ops.append(g_op)
            if not valid_gathers or set(gather_candidates.keys()) != {0, 1}:
                continue

            # Determine which gather feeds NHWC conv-branch through NCHW->NHWC transpose.
            conv_gather_idx_value: Optional[int] = None
            pre_conv_t_idx: Optional[int] = None
            pre_conv_t_op: Optional[OperatorIR] = None
            pre_conv_out_name: Optional[str] = None
            for idx_value in [0, 1]:
                _, _, gather_out = gather_candidates[idx_value]
                users = [int(v) for v in consumers.get(gather_out, [])]
                if len(users) != 1:
                    continue
                maybe_t_idx = int(users[0])
                maybe_t_op = model_ir.operators[maybe_t_idx]
                if (
                    str(maybe_t_op.op_type) == "TRANSPOSE"
                    and len(maybe_t_op.inputs) >= 2
                    and len(maybe_t_op.outputs) == 1
                    and _read_transpose_perm(model_ir, maybe_t_op) == perm_nchw_to_nhwc
                    and str(maybe_t_op.outputs[0]) not in model_outputs
                ):
                    conv_gather_idx_value = int(idx_value)
                    pre_conv_t_idx = int(maybe_t_idx)
                    pre_conv_t_op = maybe_t_op
                    pre_conv_out_name = str(maybe_t_op.outputs[0])
                    break
            if (
                conv_gather_idx_value is None
                or pre_conv_t_idx is None
                or pre_conv_t_op is None
                or pre_conv_out_name is None
            ):
                continue
            skip_gather_idx_value = 1 - int(conv_gather_idx_value)
            _, _, skip_gather_out_name = gather_candidates[int(skip_gather_idx_value)]
            if skip_gather_out_name in model_outputs:
                continue

            pre_conv_out_users = [int(v) for v in consumers.get(pre_conv_out_name, [])]
            if len(pre_conv_out_users) != 1:
                continue
            first_branch_op = model_ir.operators[int(pre_conv_out_users[0])]

            # Trace branch NHWC flow until NHWC->NCHW transpose.
            transpose_post_idx: Optional[int] = None
            transpose_post_op: Optional[OperatorIR] = None
            branch_nhwc_cursor = str(pre_conv_out_name)
            visited_tensors: set[str] = set()
            branch_trace_valid = True
            while True:
                if branch_nhwc_cursor in visited_tensors:
                    branch_trace_valid = False
                    break
                visited_tensors.add(branch_nhwc_cursor)
                users = [int(v) for v in consumers.get(branch_nhwc_cursor, [])]
                if len(users) != 1:
                    branch_trace_valid = False
                    break
                op_idx = int(users[0])
                op = model_ir.operators[op_idx]
                if (
                    str(op.op_type) == "TRANSPOSE"
                    and len(op.inputs) >= 2
                    and len(op.outputs) == 1
                    and _read_transpose_perm(model_ir, op) == perm_nhwc_to_nchw
                ):
                    transpose_post_idx = int(op_idx)
                    transpose_post_op = op
                    break
                if str(op.op_type) not in branch_passthrough_ops or len(op.outputs) != 1:
                    branch_trace_valid = False
                    break
                branch_nhwc_cursor = str(op.outputs[0])
            if (
                not branch_trace_valid
                or transpose_post_idx is None
                or transpose_post_op is None
            ):
                continue

            branch_nhwc_tail_name = str(transpose_post_op.inputs[0])
            branch_nchw_start_name = str(transpose_post_op.outputs[0])
            if branch_nchw_start_name in model_outputs:
                continue

            skip_users = [int(v) for v in consumers.get(skip_gather_out_name, [])]
            if len(skip_users) != 1:
                continue
            concat1_idx = int(skip_users[0])
            concat1_op = model_ir.operators[concat1_idx]
            if str(concat1_op.op_type) != "CONCATENATION" or len(concat1_op.outputs) != 1:
                continue
            if int(concat1_op.options.get("axis", -1)) != 1:
                continue
            concat1_inputs = [str(v) for v in list(concat1_op.inputs)]
            if len(concat1_inputs) != 2 or skip_gather_out_name not in concat1_inputs:
                continue

            branch_nchw_cursor = branch_nchw_start_name
            unary_chain_indices: List[int] = []
            branch_trace_to_concat_ok = True
            while True:
                users = [int(v) for v in consumers.get(branch_nchw_cursor, [])]
                if len(users) != 1:
                    branch_trace_to_concat_ok = False
                    break
                user_idx = int(users[0])
                if user_idx == int(concat1_idx):
                    break
                user_op = model_ir.operators[user_idx]
                if (
                    str(user_op.op_type) in unary_ops
                    and len(user_op.inputs) == 1
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == branch_nchw_cursor
                    and branch_nchw_cursor not in model_outputs
                ):
                    unary_chain_indices.append(int(user_idx))
                    branch_nchw_cursor = str(user_op.outputs[0])
                    continue
                branch_trace_to_concat_ok = False
                break
            if not branch_trace_to_concat_ok:
                continue
            branch_concat_input_nchw = str(branch_nchw_cursor)
            if branch_concat_input_nchw not in concat1_inputs:
                continue

            # Build NHWC even/odd gather tensors from concat0 output.
            x_signature = (
                list(x_nhwc_tensor.shape_signature)
                if x_nhwc_tensor.shape_signature is not None
                else list(x_shape)
            )
            even_odd_shape = [int(x_shape[0]), int(x_shape[1]), int(x_shape[2]), int(half_channels)]
            even_odd_signature = [int(v) for v in list(x_signature)]
            if len(even_odd_signature) == 4 and int(even_odd_signature[3]) > 0:
                even_odd_signature[3] = int(half_channels)
            even_name = _unique_tensor_name(f"{x_nhwc_name}_shuffle_even_nhwc")
            odd_name = _unique_tensor_name(f"{x_nhwc_name}_shuffle_odd_nhwc")
            model_ir.tensors[even_name] = TensorIR(
                name=even_name,
                dtype=str(x_nhwc_tensor.dtype),
                shape=list(even_odd_shape),
                shape_signature=[int(v) for v in list(even_odd_signature)],
                quantization=_clone_quantization(x_nhwc_tensor.quantization),
            )
            model_ir.tensors[odd_name] = TensorIR(
                name=odd_name,
                dtype=str(x_nhwc_tensor.dtype),
                shape=list(even_odd_shape),
                shape_signature=[int(v) for v in list(even_odd_signature)],
                quantization=_clone_quantization(x_nhwc_tensor.quantization),
            )

            even_indices_name = _unique_tensor_name(f"{x_nhwc_name}_shuffle_even_indices")
            odd_indices_name = _unique_tensor_name(f"{x_nhwc_name}_shuffle_odd_indices")
            model_ir.tensors[even_indices_name] = TensorIR(
                name=even_indices_name,
                dtype="INT32",
                shape=[int(half_channels)],
                shape_signature=[int(half_channels)],
                data=np.asarray([int(v) for v in range(0, int(channels), 2)], dtype=np.int32),
                is_variable=False,
            )
            model_ir.tensors[odd_indices_name] = TensorIR(
                name=odd_indices_name,
                dtype="INT32",
                shape=[int(half_channels)],
                shape_signature=[int(half_channels)],
                data=np.asarray([int(v) for v in range(1, int(channels), 2)], dtype=np.int32),
                is_variable=False,
            )

            even_gather_op = OperatorIR(
                op_type="GATHER",
                inputs=[x_nhwc_name, even_indices_name],
                outputs=[even_name],
                options={"axis": 3, "batchDims": 0},
            )
            odd_gather_op = OperatorIR(
                op_type="GATHER",
                inputs=[x_nhwc_name, odd_indices_name],
                outputs=[odd_name],
                options={"axis": 3, "batchDims": 0},
            )

            conv_branch_input_nhwc = even_name if int(conv_gather_idx_value) == 0 else odd_name
            skip_branch_input_nhwc = odd_name if int(conv_gather_idx_value) == 0 else even_name

            # Rewrite branch start input.
            _replace_tensor_inputs(model_ir, pre_conv_out_name, conv_branch_input_nhwc)

            # Rewire unary tail (if present) to NHWC by bypassing post transpose.
            if len(unary_chain_indices) > 0:
                first_unary_idx = int(unary_chain_indices[0])
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=model_ir.operators[first_unary_idx],
                    new_inputs=[branch_nhwc_tail_name],
                )
                for unary_idx in unary_chain_indices:
                    unary_out_name = str(model_ir.operators[int(unary_idx)].outputs[0])
                    _permute_tensor_metadata_if_rank_matches(
                        model_ir.tensors.get(unary_out_name, None),
                        perm_nchw_to_nhwc,
                    )
                branch_concat_input_nhwc = str(model_ir.operators[int(unary_chain_indices[-1])].outputs[0])
            else:
                branch_concat_input_nhwc = branch_nhwc_tail_name

            concat1_out_name = str(concat1_op.outputs[0])
            concat1_out_tensor = model_ir.tensors.get(concat1_out_name, None)
            if concat1_out_tensor is None:
                continue
            concat1_out_signature = (
                list(concat1_out_tensor.shape_signature)
                if concat1_out_tensor.shape_signature is not None
                else list(concat1_out_tensor.shape)
            )
            concat1_out_nhwc_shape = _permute_shape(list(concat1_out_tensor.shape), perm_nchw_to_nhwc)
            concat1_out_nhwc_signature = _permute_shape(list(concat1_out_signature), perm_nchw_to_nhwc)
            if concat1_out_nhwc_shape is None or concat1_out_nhwc_signature is None:
                continue

            concat1_out_nhwc_name = _unique_tensor_name(f"{concat1_out_name}_nhwc")
            model_ir.tensors[concat1_out_nhwc_name] = TensorIR(
                name=concat1_out_nhwc_name,
                dtype=str(concat1_out_tensor.dtype),
                shape=[int(v) for v in list(concat1_out_nhwc_shape)],
                shape_signature=[int(v) for v in list(concat1_out_nhwc_signature)],
                quantization=_clone_quantization(concat1_out_tensor.quantization),
            )

            new_concat1_inputs: List[str] = []
            for input_name in concat1_inputs:
                if str(input_name) == str(skip_gather_out_name):
                    new_concat1_inputs.append(str(skip_branch_input_nhwc))
                elif str(input_name) == str(branch_concat_input_nchw):
                    new_concat1_inputs.append(str(branch_concat_input_nhwc))
                else:
                    new_concat1_inputs.append(str(input_name))
            if str(skip_branch_input_nhwc) not in set(new_concat1_inputs):
                continue
            if str(branch_concat_input_nhwc) not in set(new_concat1_inputs):
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=concat1_op,
                new_inputs=[str(v) for v in list(new_concat1_inputs)],
            )
            concat1_op.options["axis"] = 3
            _set_operator_outputs(
                model_ir=model_ir,
                op=concat1_op,
                new_outputs=[concat1_out_nhwc_name],
            )

            post_perm_name = str(transpose_post_op.inputs[1]) if len(transpose_post_op.inputs) >= 2 else ""
            post_perm_tensor = model_ir.tensors.get(post_perm_name, None)
            post_perm_vals = _read_const_ints_from_tensor(post_perm_tensor)
            if post_perm_vals != perm_nhwc_to_nchw:
                post_perm_name = _unique_tensor_name("shufflenet_concat_post_perm")
                model_ir.tensors[post_perm_name] = TensorIR(
                    name=post_perm_name,
                    dtype="INT32",
                    shape=[4],
                    shape_signature=[4],
                    data=np.asarray(perm_nhwc_to_nchw, dtype=np.int32),
                    is_variable=False,
                )

            concat1_current_idx = _op_index(concat1_op)
            if concat1_current_idx is None:
                continue
            model_ir.operators.insert(
                int(concat1_current_idx) + 1,
                OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[concat1_out_nhwc_name, post_perm_name],
                    outputs=[concat1_out_name],
                ),
            )

            concat0_current_idx = _op_index(concat0_op)
            if concat0_current_idx is None:
                continue
            model_ir.operators.insert(int(concat0_current_idx) + 1, even_gather_op)
            model_ir.operators.insert(int(concat0_current_idx) + 2, odd_gather_op)

            remove_ids = {
                int(id(t0_op)),
                int(id(r1_op)),
                int(id(t1_op)),
                int(id(r2_op)),
                int(id(gather_candidates[0][1])),
                int(id(gather_candidates[1][1])),
                int(id(pre_conv_t_op)),
                int(id(transpose_post_op)),
            }
            remove_indices = [
                int(idx)
                for idx, op in enumerate(model_ir.operators)
                if int(id(op)) in remove_ids
            ]
            for remove_idx in sorted(list(set(remove_indices)), reverse=True):
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_shufflenet_transpose_shuffle_chains": int(optimized)}


def _optimize_shufflenet_reshape_transpose_shuffle_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Collapse ShuffleNet channel-shuffle chains expressed as:

      x_nhwc
        -> TRANSPOSE(0,3,1,2)
        -> RESHAPE([N,g,cpg,H,W])
        -> TRANSPOSE(0,2,1,3,4)
        -> RESHAPE([N,C,H,W])
        -> TRANSPOSE(0,2,3,1)
        -> y_nhwc

    into:

      x_nhwc -> GATHER(axis=3, shuffle_indices) -> y_nhwc

    where C=g*cpg and shuffle_indices[k] = (k % g) * cpg + (k // g).
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    perm_shuffle_swap = [0, 2, 1, 3, 4]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for t0_idx, t0_op in enumerate(model_ir.operators):
            if str(t0_op.op_type) != "TRANSPOSE" or len(t0_op.inputs) < 2 or len(t0_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, t0_op) != perm_nhwc_to_nchw:
                continue

            x_nhwc_name = str(t0_op.inputs[0])
            x_nchw_name = str(t0_op.outputs[0])
            if x_nchw_name in model_outputs:
                continue

            t0_users = [int(v) for v in consumers.get(x_nchw_name, [])]
            if len(t0_users) == 0:
                continue

            for r1_idx in t0_users:
                r1_op = model_ir.operators[int(r1_idx)]
                if (
                    str(r1_op.op_type) != "RESHAPE"
                    or len(r1_op.inputs) < 1
                    or len(r1_op.outputs) != 1
                    or str(r1_op.inputs[0]) != x_nchw_name
                ):
                    continue
                r1_out_name = str(r1_op.outputs[0])
                if r1_out_name in model_outputs:
                    continue

                r1_users = [int(v) for v in consumers.get(r1_out_name, [])]
                if len(r1_users) != 1:
                    continue
                t1_idx = int(r1_users[0])
                t1_op = model_ir.operators[int(t1_idx)]
                if (
                    str(t1_op.op_type) != "TRANSPOSE"
                    or len(t1_op.inputs) < 2
                    or len(t1_op.outputs) != 1
                    or str(t1_op.inputs[0]) != r1_out_name
                    or _read_transpose_perm(model_ir, t1_op) != perm_shuffle_swap
                ):
                    continue
                t1_out_name = str(t1_op.outputs[0])
                if t1_out_name in model_outputs:
                    continue

                t1_users = [int(v) for v in consumers.get(t1_out_name, [])]
                if len(t1_users) != 1:
                    continue
                r2_idx = int(t1_users[0])
                r2_op = model_ir.operators[int(r2_idx)]
                if (
                    str(r2_op.op_type) != "RESHAPE"
                    or len(r2_op.inputs) < 1
                    or len(r2_op.outputs) != 1
                    or str(r2_op.inputs[0]) != t1_out_name
                ):
                    continue
                r2_out_name = str(r2_op.outputs[0])
                if r2_out_name in model_outputs:
                    continue

                r2_users = [int(v) for v in consumers.get(r2_out_name, [])]
                if len(r2_users) != 1:
                    continue
                t2_idx = int(r2_users[0])
                t2_op = model_ir.operators[int(t2_idx)]
                if (
                    str(t2_op.op_type) != "TRANSPOSE"
                    or len(t2_op.inputs) < 2
                    or len(t2_op.outputs) != 1
                    or str(t2_op.inputs[0]) != r2_out_name
                    or _read_transpose_perm(model_ir, t2_op) != perm_nchw_to_nhwc
                ):
                    continue

                x_tensor = model_ir.tensors.get(x_nhwc_name, None)
                r1_tensor = model_ir.tensors.get(r1_out_name, None)
                t1_tensor = model_ir.tensors.get(t1_out_name, None)
                y_tensor = model_ir.tensors.get(str(t2_op.outputs[0]), None)
                if x_tensor is None or r1_tensor is None or t1_tensor is None:
                    continue

                x_shape = [int(v) for v in list(x_tensor.shape)]
                r1_shape = [int(v) for v in list(r1_tensor.shape)]
                t1_shape = [int(v) for v in list(t1_tensor.shape)]
                if (
                    not _is_fully_known_positive_shape(x_shape)
                    or not _is_fully_known_positive_shape(r1_shape)
                    or not _is_fully_known_positive_shape(t1_shape)
                ):
                    continue
                if len(x_shape) != 4 or len(r1_shape) != 5 or len(t1_shape) != 5:
                    continue

                n, h, w, c = [int(v) for v in x_shape]
                if int(c) <= 1:
                    continue

                # r1:[N,g,cpg,H,W], t1:[N,cpg,g,H,W]
                if (
                    int(r1_shape[0]) != int(n)
                    or int(r1_shape[3]) != int(h)
                    or int(r1_shape[4]) != int(w)
                    or int(t1_shape[0]) != int(n)
                    or int(t1_shape[3]) != int(h)
                    or int(t1_shape[4]) != int(w)
                    or int(t1_shape[1]) != int(r1_shape[2])
                    or int(t1_shape[2]) != int(r1_shape[1])
                ):
                    continue
                groups = int(r1_shape[1])
                cpg = int(r1_shape[2])
                if int(groups) <= 1 or int(cpg) <= 0 or int(groups * cpg) != int(c):
                    continue

                shuffle_indices = np.asarray(
                    [int((k % groups) * cpg + (k // groups)) for k in range(int(c))],
                    dtype=np.int32,
                )
                if np.array_equal(shuffle_indices, np.arange(int(c), dtype=np.int32)):
                    continue

                gather_idx_name = _unique_tensor_name(f"{x_nhwc_name}_shuffle_indices")
                model_ir.tensors[gather_idx_name] = TensorIR(
                    name=gather_idx_name,
                    dtype="INT32",
                    shape=[int(c)],
                    shape_signature=[int(c)],
                    data=shuffle_indices,
                    is_variable=False,
                )

                t2_op.op_type = "GATHER"
                t2_op.version = 1
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=t2_op,
                    new_inputs=[x_nhwc_name, gather_idx_name],
                )
                t2_op.options = {"axis": 3, "batchDims": 0}

                if y_tensor is not None:
                    y_tensor.shape = [int(v) for v in list(x_shape)]
                    y_signature = (
                        [int(v) for v in list(x_tensor.shape_signature)]
                        if x_tensor.shape_signature is not None
                        else [int(v) for v in list(x_shape)]
                    )
                    y_tensor.shape_signature = [int(v) for v in list(y_signature)]

                remove_indices = {int(r1_idx), int(t1_idx), int(r2_idx)}
                t0_remaining_users = [int(v) for v in t0_users if int(v) != int(r1_idx)]
                if len(t0_remaining_users) == 0:
                    remove_indices.add(int(t0_idx))

                for remove_idx in sorted(list(remove_indices), reverse=True):
                    del model_ir.operators[int(remove_idx)]

                optimized += 1
                changed = True
                break

            if changed:
                break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_shufflenet_reshape_transpose_shuffle_nhwc_chains": int(optimized)}


def _optimize_transpose_pre_add_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Convert NCHW Add blocks back to NHWC when wrapped by transpose adapters.

    Target:
      a_nhwc -> (optional swish-wrapped NCHW adapters) -> a_nchw
      b_nhwc -> (optional swish-wrapped NCHW adapters) -> b_nchw
      ADD(a_nchw, b_nchw) -> y_nchw
      (optional unary RELU/RELU6/LOGISTIC/TANH) -> y2_nchw
      y_or_y2_nchw -> TRANSPOSE(0,2,3,1) -> y_nhwc

    Rewrite:
      ADD(a_nhwc, b_nhwc) -> y_nhwc
      (if unary exists, keep unary and bridge its output instead of ADD output directly)

    Notes:
    - If y_nchw has legacy consumers, keep one adapter TRANSPOSE(0,3,1,2): y_nhwc -> y_nchw.
    - Swish-wrapped NCHW inputs are recognized as:
        pre_nhwc --T(0,3,1,2)--> x_nchw --LOGISTIC--> s --MUL(x_nchw,s)--> x_swish_nchw
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    unary_passthrough_ops = {"RELU", "RELU6", "LOGISTIC", "TANH", "GELU", "HARD_SWISH"}
    skip_add_activation_fuse_marker = "__skip_add_activation_fuse__"

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _analyze_swish_input_to_nhwc(
        *,
        input_name: str,
        consumer_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        mul_idx = producers.get(str(input_name), None)
        if mul_idx is None:
            return None
        mul_op = model_ir.operators[int(mul_idx)]
        if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
            return None
        if str(mul_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        if set(int(v) for v in consumers.get(str(input_name), [])) != {int(consumer_idx)}:
            return None

        in0_name = str(mul_op.inputs[0])
        in1_name = str(mul_op.inputs[1])
        in0_prod_idx = producers.get(in0_name, None)
        in1_prod_idx = producers.get(in1_name, None)

        log_idx: Optional[int] = None
        log_out_name: Optional[str] = None
        pre_nchw_name: Optional[str] = None
        mul_data_input_index: Optional[int] = None

        if in0_prod_idx is not None:
            in0_prod_op = model_ir.operators[int(in0_prod_idx)]
            if (
                str(in0_prod_op.op_type) == "LOGISTIC"
                and len(in0_prod_op.inputs) == 1
                and len(in0_prod_op.outputs) == 1
                and str(in0_prod_op.outputs[0]) == in0_name
            ):
                log_idx = int(in0_prod_idx)
                log_out_name = in0_name
                pre_nchw_name = str(in0_prod_op.inputs[0])
                mul_data_input_index = 1

        if log_idx is None and in1_prod_idx is not None:
            in1_prod_op = model_ir.operators[int(in1_prod_idx)]
            if (
                str(in1_prod_op.op_type) == "LOGISTIC"
                and len(in1_prod_op.inputs) == 1
                and len(in1_prod_op.outputs) == 1
                and str(in1_prod_op.outputs[0]) == in1_name
            ):
                log_idx = int(in1_prod_idx)
                log_out_name = in1_name
                pre_nchw_name = str(in1_prod_op.inputs[0])
                mul_data_input_index = 0

        if log_idx is None or log_out_name is None or pre_nchw_name is None or mul_data_input_index is None:
            return None
        if str(mul_op.inputs[int(mul_data_input_index)]) != str(pre_nchw_name):
            return None

        pre_idx = producers.get(str(pre_nchw_name), None)
        if pre_idx is None:
            return None
        pre_op = model_ir.operators[int(pre_idx)]
        if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
            return None
        if str(pre_op.outputs[0]) != str(pre_nchw_name):
            return None
        if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
            return None
        if str(pre_nchw_name) in model_outputs:
            return None

        if set(int(v) for v in consumers.get(str(pre_nchw_name), [])) != {int(log_idx), int(mul_idx)}:
            return None
        if set(int(v) for v in consumers.get(str(log_out_name), [])) != {int(mul_idx)}:
            return None

        return {
            "pre_idx": int(pre_idx),
            "pre_input_name": str(pre_op.inputs[0]),
            "log_idx": int(log_idx),
            "mul_idx": int(mul_idx),
            "mul_data_input_index": int(mul_data_input_index),
            "log_out_name": str(log_out_name),
            "mul_out_name": str(input_name),
        }

    def _apply_swish_nhwc_plan(*, plan: Dict[str, Any]) -> List[int]:
        pre_idx = int(plan["pre_idx"])
        pre_input_name = str(plan["pre_input_name"])
        log_idx = int(plan["log_idx"])
        mul_idx = int(plan["mul_idx"])
        mul_data_input_index = int(plan["mul_data_input_index"])
        log_out_name = str(plan["log_out_name"])
        mul_out_name = str(plan["mul_out_name"])

        mul_op = model_ir.operators[int(mul_idx)]
        _set_operator_inputs(
            model_ir=model_ir,
            op=model_ir.operators[int(log_idx)],
            new_inputs=[pre_input_name],
        )
        _replace_operator_input_at(
            model_ir=model_ir,
            op=mul_op,
            input_index=int(mul_data_input_index),
            new_input_name=pre_input_name,
        )

        for tensor_name in [log_out_name, mul_out_name]:
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(tensor_name, None),
                perm_nchw_to_nhwc,
            )
        return [int(pre_idx)]

    def _analyze_unary_input_to_nhwc(
        *,
        input_name: str,
        consumer_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        unary_idx = producers.get(str(input_name), None)
        if unary_idx is None:
            return None
        unary_op = model_ir.operators[int(unary_idx)]
        if str(unary_op.op_type) not in unary_passthrough_ops:
            return None
        if len(unary_op.inputs) != 1 or len(unary_op.outputs) != 1:
            return None
        if str(unary_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        if set(int(v) for v in consumers.get(str(input_name), [])) != {int(consumer_idx)}:
            return None

        pre_nchw_name = str(unary_op.inputs[0])
        pre_idx = producers.get(pre_nchw_name, None)
        if pre_idx is None:
            return None
        pre_op = model_ir.operators[int(pre_idx)]
        if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
            return None
        if str(pre_op.outputs[0]) != pre_nchw_name:
            return None
        if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
            return None
        if str(pre_nchw_name) in model_outputs:
            return None
        if set(int(v) for v in consumers.get(str(pre_nchw_name), [])) != {int(unary_idx)}:
            return None

        return {
            "input_name": str(input_name),
            "unary_idx": int(unary_idx),
            "pre_idx": int(pre_idx),
            "pre_input_name": str(pre_op.inputs[0]),
        }

    def _apply_unary_nhwc_plan(*, plan: Dict[str, Any]) -> List[int]:
        input_name = str(plan["input_name"])
        unary_idx = int(plan["unary_idx"])
        pre_idx = int(plan["pre_idx"])
        pre_input_name = str(plan["pre_input_name"])

        _set_operator_inputs(
            model_ir=model_ir,
            op=model_ir.operators[int(unary_idx)],
            new_inputs=[pre_input_name],
        )
        _permute_tensor_metadata_if_rank_matches(
            model_ir.tensors.get(input_name, None),
            perm_nchw_to_nhwc,
        )
        return [int(pre_idx)]

    def _analyze_mul_const_input_to_nhwc(
        *,
        input_name: str,
        consumer_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        mul_idx = producers.get(str(input_name), None)
        if mul_idx is None:
            return None
        mul_op = model_ir.operators[int(mul_idx)]
        if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
            return None
        if str(mul_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        if set(int(v) for v in consumers.get(str(input_name), [])) != {int(consumer_idx)}:
            return None

        data_input_index: Optional[int] = None
        side_input_index: Optional[int] = None
        side_input_name: Optional[str] = None
        pre_idx: Optional[int] = None
        pre_input_name: Optional[str] = None
        pre_output_name: Optional[str] = None

        for candidate_data_index, candidate_side_index in [(0, 1), (1, 0)]:
            data_name = str(mul_op.inputs[int(candidate_data_index)])
            side_name = str(mul_op.inputs[int(candidate_side_index)])
            side_tensor = model_ir.tensors.get(side_name, None)
            if side_tensor is None or side_tensor.data is None:
                continue

            data_prod_idx = producers.get(data_name, None)
            if data_prod_idx is None:
                continue
            data_prod_op = model_ir.operators[int(data_prod_idx)]
            if (
                str(data_prod_op.op_type) != "TRANSPOSE"
                or len(data_prod_op.inputs) < 2
                or len(data_prod_op.outputs) != 1
                or str(data_prod_op.outputs[0]) != data_name
                or _read_transpose_perm(model_ir, data_prod_op) != perm_nhwc_to_nchw
                or str(data_name) in model_outputs
            ):
                continue
            if set(int(v) for v in consumers.get(data_name, [])) != {int(mul_idx)}:
                continue

            data_tensor = model_ir.tensors.get(data_name, None)
            pre_in_name = str(data_prod_op.inputs[0])
            pre_in_tensor = model_ir.tensors.get(pre_in_name, None)
            if data_tensor is None or pre_in_tensor is None:
                continue
            if (
                not _is_fully_known_positive_shape(list(data_tensor.shape))
                or not _is_fully_known_positive_shape(list(pre_in_tensor.shape))
                or len(list(data_tensor.shape)) != 4
                or len(list(pre_in_tensor.shape)) != 4
            ):
                continue

            side_data = np.asarray(side_tensor.data)
            if int(side_data.size) != 1 and side_data.ndim != 4:
                continue
            if int(side_data.size) != 1:
                if _broadcast_static_shapes(list(data_tensor.shape), [int(v) for v in list(side_data.shape)]) is None:
                    continue

            data_input_index = int(candidate_data_index)
            side_input_index = int(candidate_side_index)
            side_input_name = str(side_name)
            pre_idx = int(data_prod_idx)
            pre_input_name = pre_in_name
            pre_output_name = data_name
            break

        if (
            data_input_index is None
            or side_input_index is None
            or side_input_name is None
            or pre_idx is None
            or pre_input_name is None
            or pre_output_name is None
        ):
            return None

        side_tensor = model_ir.tensors.get(side_input_name, None)
        if side_tensor is None or side_tensor.data is None:
            return None
        side_data = np.asarray(side_tensor.data)
        nhwc_side_data: Optional[np.ndarray] = None
        side_needs_update = False
        if int(side_data.size) != 1:
            target_nhwc_shape = [int(v) for v in list(model_ir.tensors[str(pre_input_name)].shape)]
            side_shape = [int(v) for v in list(side_data.shape)]
            if _broadcast_static_shapes(target_nhwc_shape, side_shape) is not None:
                nhwc_side_data = np.asarray(side_data)
                side_needs_update = False
            else:
                rotated = np.asarray(side_data)
                found = False
                for _ in range(3):
                    rotated = np.transpose(rotated, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
                    rotated_shape = [int(v) for v in list(rotated.shape)]
                    if _broadcast_static_shapes(target_nhwc_shape, rotated_shape) is not None:
                        nhwc_side_data = np.asarray(rotated)
                        side_needs_update = True
                        found = True
                        break
                if not found:
                    return None

        shared_outside_mul = any(
            int(v) != int(mul_idx)
            for v in consumers.get(str(side_input_name), [])
        )

        return {
            "pre_idx": int(pre_idx),
            "pre_input_name": str(pre_input_name),
            "mul_idx": int(mul_idx),
            "mul_data_input_index": int(data_input_index),
            "mul_side_input_index": int(side_input_index),
            "mul_side_input_name": str(side_input_name),
            "mul_out_name": str(input_name),
            "side_needs_update": bool(side_needs_update),
            "side_shared_outside_mul": bool(shared_outside_mul),
            "side_nhwc_data": (None if nhwc_side_data is None else np.asarray(nhwc_side_data)),
        }

    def _apply_mul_const_nhwc_plan(*, plan: Dict[str, Any]) -> List[int]:
        pre_idx = int(plan["pre_idx"])
        pre_input_name = str(plan["pre_input_name"])
        mul_idx = int(plan["mul_idx"])
        mul_data_input_index = int(plan["mul_data_input_index"])
        mul_side_input_index = int(plan["mul_side_input_index"])
        mul_side_input_name = str(plan["mul_side_input_name"])
        mul_out_name = str(plan["mul_out_name"])

        side_input_name_for_mul = str(mul_side_input_name)
        if bool(plan.get("side_needs_update", False)):
            nhwc_data = np.asarray(plan.get("side_nhwc_data"))
            side_tensor = model_ir.tensors.get(str(mul_side_input_name), None)
            if side_tensor is None:
                return []
            if bool(plan.get("side_shared_outside_mul", False)):
                side_input_name_for_mul = _unique_tensor_name(f"{mul_side_input_name}_nhwc")
                model_ir.tensors[side_input_name_for_mul] = TensorIR(
                    name=side_input_name_for_mul,
                    dtype=str(side_tensor.dtype),
                    shape=[int(v) for v in list(nhwc_data.shape)],
                    shape_signature=[int(v) for v in list(nhwc_data.shape)],
                    data=np.asarray(nhwc_data),
                    is_variable=False,
                    quantization=_clone_quantization(side_tensor.quantization),
                )
            else:
                side_tensor.data = np.asarray(nhwc_data)
                side_tensor.shape = [int(v) for v in list(nhwc_data.shape)]
                side_tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]

        mul_op = model_ir.operators[int(mul_idx)]
        mul_inputs = [str(v) for v in list(mul_op.inputs)]
        if int(mul_data_input_index) < 0 or int(mul_data_input_index) >= len(mul_inputs):
            return []
        if int(mul_side_input_index) < 0 or int(mul_side_input_index) >= len(mul_inputs):
            return []
        mul_inputs[int(mul_data_input_index)] = str(pre_input_name)
        mul_inputs[int(mul_side_input_index)] = str(side_input_name_for_mul)
        _set_operator_inputs(
            model_ir=model_ir,
            op=mul_op,
            new_inputs=mul_inputs,
        )
        _permute_tensor_metadata_if_rank_matches(
            model_ir.tensors.get(mul_out_name, None),
            perm_nchw_to_nhwc,
        )
        return [int(pre_idx)]

    def _resolve_add_input_to_nhwc(
        *,
        input_name: str,
        add_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
        allow_nested_add: bool = True,
    ) -> Optional[Dict[str, Any]]:
        input_producer_idx = producers.get(str(input_name), None)
        if input_producer_idx is not None:
            input_producer_op = model_ir.operators[int(input_producer_idx)]
            input_users = set(int(v) for v in consumers.get(str(input_name), []))

            if (
                str(input_producer_op.op_type) == "TRANSPOSE"
                and len(input_producer_op.inputs) >= 2
                and len(input_producer_op.outputs) == 1
                and str(input_producer_op.outputs[0]) == str(input_name)
                and _read_transpose_perm(model_ir, input_producer_op) == perm_nhwc_to_nchw
                and int(add_idx) in input_users
                and str(input_name) not in model_outputs
            ):
                extra_user_indices = [int(v) for v in sorted(input_users) if int(v) != int(add_idx)]
                return {
                    "nhwc_input_name": str(input_producer_op.inputs[0]),
                    "pre_remove_indices": (
                        [int(input_producer_idx)] if len(extra_user_indices) == 0 else []
                    ),
                    "swish_plan": None,
                    "unary_plan": None,
                    "mul_const_plan": None,
                    "nested_add_plan": None,
                }

        swish_plan = _analyze_swish_input_to_nhwc(
            input_name=input_name,
            consumer_idx=int(add_idx),
            producers=producers,
            consumers=consumers,
            model_outputs=model_outputs,
        )
        if swish_plan is not None:
            return {
                "nhwc_input_name": str(input_name),
                "pre_remove_indices": [],
                "swish_plan": swish_plan,
                "unary_plan": None,
                "mul_const_plan": None,
                "nested_add_plan": None,
            }

        unary_plan = _analyze_unary_input_to_nhwc(
            input_name=input_name,
            consumer_idx=int(add_idx),
            producers=producers,
            consumers=consumers,
            model_outputs=model_outputs,
        )
        if unary_plan is not None:
            return {
                "nhwc_input_name": str(input_name),
                "pre_remove_indices": [],
                "swish_plan": None,
                "unary_plan": unary_plan,
                "mul_const_plan": None,
                "nested_add_plan": None,
            }

        mul_const_plan = _analyze_mul_const_input_to_nhwc(
            input_name=input_name,
            consumer_idx=int(add_idx),
            producers=producers,
            consumers=consumers,
            model_outputs=model_outputs,
        )
        if mul_const_plan is not None:
            return {
                "nhwc_input_name": str(input_name),
                "pre_remove_indices": [],
                "swish_plan": None,
                "unary_plan": None,
                "mul_const_plan": mul_const_plan,
                "nested_add_plan": None,
            }

        if input_producer_idx is not None and allow_nested_add:
            input_producer_op = model_ir.operators[int(input_producer_idx)]
            if (
                str(input_producer_op.op_type) == "ADD"
                and len(input_producer_op.inputs) == 2
                and len(input_producer_op.outputs) == 1
                and str(input_producer_op.outputs[0]) == str(input_name)
                and str(input_name) not in model_outputs
            ):
                input_users = set(int(v) for v in consumers.get(str(input_name), []))
                if input_users == {int(add_idx)}:
                    nested_input_plans: List[Dict[str, Any]] = []
                    nested_rewritable = True
                    for nested_input_name in [str(v) for v in list(input_producer_op.inputs)]:
                        nested_plan = _resolve_add_input_to_nhwc(
                            input_name=str(nested_input_name),
                            add_idx=int(input_producer_idx),
                            producers=producers,
                            consumers=consumers,
                            model_outputs=model_outputs,
                            allow_nested_add=False,
                        )
                        if nested_plan is None:
                            nested_rewritable = False
                            break
                        nested_input_plans.append(dict(nested_plan))
                    if nested_rewritable:
                        return {
                            "nhwc_input_name": str(input_name),
                            "pre_remove_indices": [],
                            "swish_plan": None,
                            "unary_plan": None,
                            "mul_const_plan": None,
                            "nested_add_plan": {
                                "input_name": str(input_name),
                                "add_idx": int(input_producer_idx),
                                "input_plans": [dict(v) for v in nested_input_plans],
                            },
                        }

        if input_producer_idx is not None:
            input_producer_op = model_ir.operators[int(input_producer_idx)]
            if (
                str(input_producer_op.op_type) == "ADD"
                and len(input_producer_op.outputs) == 1
                and str(input_producer_op.outputs[0]) == str(input_name)
            ):
                input_users = [int(v) for v in consumers.get(str(input_name), []) if int(v) != int(input_producer_idx)]
                post_candidates: List[str] = []
                for user_idx in input_users:
                    user_op = model_ir.operators[int(user_idx)]
                    if (
                        str(user_op.op_type) == "TRANSPOSE"
                        and len(user_op.inputs) >= 2
                        and len(user_op.outputs) == 1
                        and str(user_op.inputs[0]) == str(input_name)
                        and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                        and str(user_op.outputs[0]) not in model_outputs
                    ):
                        post_candidates.append(str(user_op.outputs[0]))
                if len(post_candidates) > 0:
                    return {
                        "nhwc_input_name": str(post_candidates[0]),
                        "pre_remove_indices": [],
                        "swish_plan": None,
                        "unary_plan": None,
                        "mul_const_plan": None,
                        "nested_add_plan": None,
                    }

        return None

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for add_idx, add_op in enumerate(model_ir.operators):
            if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                continue
            add_out_name = str(add_op.outputs[0])

            bridge_output_name = add_out_name
            bridge_output_producer_idx = int(add_idx)
            bridge_output_producer_op = add_op

            # Also support: ADD -> unary -> post-transpose fanout.
            add_out_users = [int(v) for v in consumers.get(add_out_name, []) if int(v) != int(add_idx)]
            if len(add_out_users) == 1:
                unary_idx = int(add_out_users[0])
                unary_op = model_ir.operators[int(unary_idx)]
                if (
                    str(unary_op.op_type) in unary_passthrough_ops
                    and len(unary_op.inputs) == 1
                    and len(unary_op.outputs) == 1
                    and str(unary_op.inputs[0]) == add_out_name
                ):
                    unary_out_name = str(unary_op.outputs[0])
                    if add_out_name not in model_outputs and unary_out_name not in model_outputs:
                        bridge_output_name = unary_out_name
                        bridge_output_producer_idx = int(unary_idx)
                        bridge_output_producer_op = unary_op

            out_users = [
                int(v)
                for v in consumers.get(bridge_output_name, [])
                if int(v) != int(bridge_output_producer_idx)
            ]
            if len(out_users) == 0:
                continue

            post_indices: List[int] = []
            post_output_names: List[str] = []
            legacy_users: List[int] = []
            valid_users = True
            for user_idx in out_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == bridge_output_name
                    and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                    and str(user_op.outputs[0]) not in model_outputs
                ):
                    post_indices.append(int(user_idx))
                    post_output_names.append(str(user_op.outputs[0]))
                else:
                    legacy_users.append(int(user_idx))
            if not valid_users or len(post_indices) == 0:
                continue

            input_plans: List[Dict[str, Any]] = []
            rewritable = True
            for input_name in [str(v) for v in list(add_op.inputs)]:
                resolved = _resolve_add_input_to_nhwc(
                    input_name=input_name,
                    add_idx=int(add_idx),
                    producers=producers,
                    consumers=consumers,
                    model_outputs=model_outputs,
                )
                if resolved is None:
                    rewritable = False
                    break
                input_plans.append(dict(resolved))
            if not rewritable:
                continue

            def _apply_nested_add_nhwc_plan(*, plan: Dict[str, Any]) -> List[int]:
                nested_input_name = str(plan["input_name"])
                nested_add_idx = int(plan["add_idx"])
                nested_input_plans = [dict(v) for v in list(plan.get("input_plans", []))]

                nested_remove_indices: List[int] = []
                nested_new_inputs: List[str] = []
                for nested_input_plan in nested_input_plans:
                    nested_swish_plan = nested_input_plan.get("swish_plan", None)
                    if nested_swish_plan is not None:
                        nested_remove_indices.extend(_apply_swish_nhwc_plan(plan=dict(nested_swish_plan)))
                    nested_unary_plan = nested_input_plan.get("unary_plan", None)
                    if nested_unary_plan is not None:
                        nested_remove_indices.extend(_apply_unary_nhwc_plan(plan=dict(nested_unary_plan)))
                    nested_mul_const_plan = nested_input_plan.get("mul_const_plan", None)
                    if nested_mul_const_plan is not None:
                        nested_remove_indices.extend(_apply_mul_const_nhwc_plan(plan=dict(nested_mul_const_plan)))
                    nested_nested_add_plan = nested_input_plan.get("nested_add_plan", None)
                    if nested_nested_add_plan is not None:
                        nested_remove_indices.extend(
                            _apply_nested_add_nhwc_plan(plan=dict(nested_nested_add_plan))
                        )
                    nested_new_inputs.append(str(nested_input_plan["nhwc_input_name"]))
                    nested_remove_indices.extend(
                        [int(v) for v in list(nested_input_plan.get("pre_remove_indices", []))]
                    )

                nested_add_op = model_ir.operators[int(nested_add_idx)]
                if (
                    str(nested_add_op.op_type) != "ADD"
                    or len(nested_add_op.inputs) != 2
                    or len(nested_add_op.outputs) != 1
                ):
                    return nested_remove_indices
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=nested_add_op,
                    new_inputs=[str(v) for v in list(nested_new_inputs)],
                )
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(nested_input_name, None),
                    perm_nchw_to_nhwc,
                )
                return nested_remove_indices

            new_add_inputs: List[str] = []
            pre_remove_indices: List[int] = []
            for plan in input_plans:
                swish_plan = plan.get("swish_plan", None)
                if swish_plan is not None:
                    pre_remove_indices.extend(_apply_swish_nhwc_plan(plan=dict(swish_plan)))
                unary_plan = plan.get("unary_plan", None)
                if unary_plan is not None:
                    pre_remove_indices.extend(_apply_unary_nhwc_plan(plan=dict(unary_plan)))
                mul_const_plan = plan.get("mul_const_plan", None)
                if mul_const_plan is not None:
                    pre_remove_indices.extend(_apply_mul_const_nhwc_plan(plan=dict(mul_const_plan)))
                nested_add_plan = plan.get("nested_add_plan", None)
                if nested_add_plan is not None:
                    pre_remove_indices.extend(_apply_nested_add_nhwc_plan(plan=dict(nested_add_plan)))
                new_add_inputs.append(str(plan["nhwc_input_name"]))
                pre_remove_indices.extend([int(v) for v in list(plan.get("pre_remove_indices", []))])

            _set_operator_inputs(
                model_ir=model_ir,
                op=add_op,
                new_inputs=[str(v) for v in new_add_inputs],
            )

            canonical_post_output_name = str(post_output_names[0])
            _set_operator_outputs(
                model_ir=model_ir,
                op=bridge_output_producer_op,
                new_outputs=[canonical_post_output_name],
            )
            for alias_post_output_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, alias_post_output_name, canonical_post_output_name)

            old_bridge_tensor = model_ir.tensors.get(bridge_output_name, None)
            canonical_post_tensor = model_ir.tensors.get(canonical_post_output_name, None)
            if old_bridge_tensor is not None and canonical_post_tensor is not None:
                canonical_post_tensor.dtype = str(old_bridge_tensor.dtype)
                canonical_post_tensor.quantization = _clone_quantization(old_bridge_tensor.quantization)
                canonical_post_tensor.shape = [int(v) for v in list(old_bridge_tensor.shape)]
                canonical_post_tensor.shape_signature = (
                    [int(v) for v in list(old_bridge_tensor.shape_signature)]
                    if old_bridge_tensor.shape_signature is not None
                    else [int(v) for v in list(old_bridge_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    canonical_post_tensor,
                    perm_nchw_to_nhwc,
                )

            if len(legacy_users) > 0:
                keep_post_idx = int(post_indices[0])
                keep_post_op = model_ir.operators[int(keep_post_idx)]
                keep_perm_name = str(keep_post_op.inputs[1])
                keep_perm_tensor = model_ir.tensors.get(keep_perm_name, None)
                if keep_perm_tensor is not None:
                    keep_perm_tensor.data = np.asarray(perm_nhwc_to_nchw, dtype=np.int32)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_inputs=[canonical_post_output_name, keep_perm_name],
                )
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_outputs=[bridge_output_name],
                )
                post_remove_indices = [int(v) for v in post_indices[1:]]
            else:
                post_remove_indices = [int(v) for v in post_indices]

            remove_indices = sorted(
                list({int(v) for v in pre_remove_indices + post_remove_indices}),
                reverse=True,
            )
            for remove_idx in remove_indices:
                if int(remove_idx) == int(add_idx):
                    continue
                del model_ir.operators[int(remove_idx)]

            # Keep explicit unary ops after transpose-bridge rewrites for stability.
            add_opts = dict(add_op.options) if isinstance(add_op.options, dict) else {}
            add_opts[skip_add_activation_fuse_marker] = True
            add_op.options = add_opts

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_pre_add_nhwc_chains": int(optimized)}


def _optimize_transpose_pre_add_mul_add_prelu_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Lift NCHW residual blocks back to NHWC when they follow:
      ADD -> MUL(const) -> ADD(const) -> PRELU -> TRANSPOSE(0,2,3,1)

    Inputs to the first ADD must be wrapped by TRANSPOSE(0,3,1,2) adapters.
    If PRELU keeps legacy NCHW consumers, preserve one adapter transpose.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _rewrite_binary_const_to_nhwc(
        *,
        op_idx: int,
        side_input_index: int,
        side_input_name: str,
        target_broadcast_shape: Optional[List[int]],
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> bool:
        side_tensor = model_ir.tensors.get(str(side_input_name), None)
        if side_tensor is None or side_tensor.data is None:
            return False
        side_data = np.asarray(side_tensor.data)
        if int(side_data.size) == 1:
            return True
        if side_data.ndim != 4:
            return False

        nhwc_data: Optional[np.ndarray] = None
        target_shape = (
            [int(v) for v in list(target_broadcast_shape)]
            if _is_fully_known_positive_shape(target_broadcast_shape)
            else None
        )
        if target_shape is not None:
            side_shape = [int(v) for v in list(side_data.shape)]
            if _broadcast_static_shapes(target_shape, side_shape) is not None:
                return True
            # NCHW per-channel const [1,C,1,1] is mapped once to NHWC [1,1,1,C].
            # Avoid multi-step rotations, which can accidentally produce [1,1,C,1]
            # when target metadata is stale/non-canonical.
            if (
                len(side_shape) == 4
                and int(side_shape[0]) == 1
                and int(side_shape[1]) > 0
                and int(side_shape[2]) == 1
                and int(side_shape[3]) == 1
            ):
                rotated = np.transpose(side_data, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
                rotated_shape = [int(v) for v in list(rotated.shape)]
                if _broadcast_static_shapes(target_shape, rotated_shape) is not None:
                    nhwc_data = np.asarray(rotated)
            else:
                rotated = np.asarray(side_data)
                for _ in range(3):
                    rotated = np.transpose(rotated, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
                    rotated_shape = [int(v) for v in list(rotated.shape)]
                    if _broadcast_static_shapes(target_shape, rotated_shape) is not None:
                        nhwc_data = np.asarray(rotated)
                        break
            if nhwc_data is None:
                return False
        else:
            side_shape = [int(v) for v in list(side_data.shape)]
            if (
                len(side_shape) == 4
                and int(side_shape[0]) == 1
                and int(side_shape[1]) > 1
                and int(side_shape[2]) == 1
                and int(side_shape[3]) == 1
            ):
                nhwc_data = np.transpose(side_data, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
            else:
                # Unknown target rank-4 shape: avoid speculative re-rotation to keep
                # repeated optimization sweeps idempotent.
                return True

        side_users = [int(v) for v in consumers.get(str(side_input_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)
        target_name = str(side_input_name)
        if shared_outside_chain:
            target_name = _unique_tensor_name(f"{side_input_name}_nhwc")
            model_ir.tensors[target_name] = TensorIR(
                name=target_name,
                dtype=str(side_tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(side_tensor.quantization),
            )
        else:
            side_tensor.data = np.asarray(nhwc_data)
            side_tensor.shape = [int(v) for v in list(nhwc_data.shape)]
            side_tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]

        _replace_operator_input_at(
            model_ir=model_ir,
            op=model_ir.operators[int(op_idx)],
            input_index=int(side_input_index),
            new_input_name=str(target_name),
        )
        return True

    def _can_rewrite_binary_const_to_nhwc(
        *,
        side_input_name: str,
        target_broadcast_shape: Optional[List[int]],
    ) -> bool:
        side_tensor = model_ir.tensors.get(str(side_input_name), None)
        if side_tensor is None or side_tensor.data is None:
            return False
        side_data = np.asarray(side_tensor.data)
        if int(side_data.size) == 1:
            return True
        if side_data.ndim != 4:
            return False
        target_shape = (
            [int(v) for v in list(target_broadcast_shape)]
            if _is_fully_known_positive_shape(target_broadcast_shape)
            else None
        )
        if target_shape is None:
            return True
        side_shape = [int(v) for v in list(side_data.shape)]
        if _broadcast_static_shapes(target_shape, side_shape) is not None:
            return True
        if (
            len(side_shape) == 4
            and int(side_shape[0]) == 1
            and int(side_shape[1]) > 0
            and int(side_shape[2]) == 1
            and int(side_shape[3]) == 1
        ):
            rotated = np.transpose(side_data, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
            rotated_shape = [int(v) for v in list(rotated.shape)]
            return _broadcast_static_shapes(target_shape, rotated_shape) is not None
        rotated = np.asarray(side_data)
        for _ in range(3):
            rotated = np.transpose(rotated, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
            rotated_shape = [int(v) for v in list(rotated.shape)]
            if _broadcast_static_shapes(target_shape, rotated_shape) is not None:
                return True
        return False

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for add_idx, add_op in enumerate(model_ir.operators):
            if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                continue

            add_out_name = str(add_op.outputs[0])
            if add_out_name in model_outputs:
                continue
            add_out_users = [int(v) for v in consumers.get(add_out_name, []) if int(v) != int(add_idx)]
            if len(add_out_users) != 1:
                continue
            mul_idx = int(add_out_users[0])
            mul_op = model_ir.operators[int(mul_idx)]
            if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                continue
            mul_in0 = str(mul_op.inputs[0])
            mul_in1 = str(mul_op.inputs[1])
            if mul_in0 == add_out_name:
                mul_side_input_index = 1
                mul_side_name = mul_in1
            elif mul_in1 == add_out_name:
                mul_side_input_index = 0
                mul_side_name = mul_in0
            else:
                continue

            mul_out_name = str(mul_op.outputs[0])
            if mul_out_name in model_outputs:
                continue
            mul_out_users = [int(v) for v in consumers.get(mul_out_name, []) if int(v) != int(mul_idx)]
            if len(mul_out_users) != 1:
                continue
            add2_idx = int(mul_out_users[0])
            add2_op = model_ir.operators[int(add2_idx)]
            if str(add2_op.op_type) != "ADD" or len(add2_op.inputs) != 2 or len(add2_op.outputs) != 1:
                continue
            add2_in0 = str(add2_op.inputs[0])
            add2_in1 = str(add2_op.inputs[1])
            if add2_in0 == mul_out_name:
                add2_side_input_index = 1
                add2_side_name = add2_in1
            elif add2_in1 == mul_out_name:
                add2_side_input_index = 0
                add2_side_name = add2_in0
            else:
                continue

            add2_out_name = str(add2_op.outputs[0])
            if add2_out_name in model_outputs:
                continue
            add2_out_users = [int(v) for v in consumers.get(add2_out_name, []) if int(v) != int(add2_idx)]
            if len(add2_out_users) != 1:
                continue
            prelu_idx = int(add2_out_users[0])
            prelu_op = model_ir.operators[int(prelu_idx)]
            if (
                str(prelu_op.op_type) != "PRELU"
                or len(prelu_op.inputs) != 2
                or len(prelu_op.outputs) != 1
                or str(prelu_op.inputs[0]) != add2_out_name
            ):
                continue
            prelu_side_input_index = 1
            prelu_side_name = str(prelu_op.inputs[1])
            prelu_out_name = str(prelu_op.outputs[0])
            if prelu_out_name in model_outputs:
                continue

            prelu_users = [int(v) for v in consumers.get(prelu_out_name, []) if int(v) != int(prelu_idx)]
            if len(prelu_users) == 0:
                continue
            post_indices: List[int] = []
            post_output_names: List[str] = []
            legacy_users: List[int] = []
            for user_idx in prelu_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == prelu_out_name
                    and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                    and str(user_op.outputs[0]) not in model_outputs
                ):
                    post_indices.append(int(user_idx))
                    post_output_names.append(str(user_op.outputs[0]))
                else:
                    legacy_users.append(int(user_idx))
            if len(post_indices) == 0:
                continue

            input_plans: List[Dict[str, Any]] = []
            rewritable_inputs = True
            for add_input_name in [str(v) for v in list(add_op.inputs)]:
                pre_idx = producers.get(str(add_input_name), None)
                if pre_idx is None:
                    rewritable_inputs = False
                    break
                pre_op = model_ir.operators[int(pre_idx)]
                if (
                    str(pre_op.op_type) != "TRANSPOSE"
                    or len(pre_op.inputs) < 2
                    or len(pre_op.outputs) != 1
                    or str(pre_op.outputs[0]) != str(add_input_name)
                    or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
                    or str(add_input_name) in model_outputs
                ):
                    rewritable_inputs = False
                    break
                users = [int(v) for v in consumers.get(str(add_input_name), [])]
                if int(add_idx) not in users:
                    rewritable_inputs = False
                    break
                input_plans.append(
                    {
                        "nhwc_input_name": str(pre_op.inputs[0]),
                        "pre_remove_indices": [int(pre_idx)] if set(users) == {int(add_idx)} else [],
                    }
                )
            if not rewritable_inputs or len(input_plans) != 2:
                continue

            target_nhwc_shape = (
                list(model_ir.tensors[str(input_plans[0]["nhwc_input_name"])].shape)
                if str(input_plans[0]["nhwc_input_name"]) in model_ir.tensors
                else None
            )
            chain_index_set = {int(mul_idx), int(add2_idx), int(prelu_idx)}
            if not _can_rewrite_binary_const_to_nhwc(
                side_input_name=str(mul_side_name),
                target_broadcast_shape=target_nhwc_shape,
            ):
                continue
            if not _can_rewrite_binary_const_to_nhwc(
                side_input_name=str(add2_side_name),
                target_broadcast_shape=target_nhwc_shape,
            ):
                continue
            if not _can_rewrite_binary_const_to_nhwc(
                side_input_name=str(prelu_side_name),
                target_broadcast_shape=target_nhwc_shape,
            ):
                continue
            if not _rewrite_binary_const_to_nhwc(
                op_idx=int(mul_idx),
                side_input_index=int(mul_side_input_index),
                side_input_name=str(mul_side_name),
                target_broadcast_shape=target_nhwc_shape,
                chain_index_set=chain_index_set,
                consumers=consumers,
            ):
                continue
            if not _rewrite_binary_const_to_nhwc(
                op_idx=int(add2_idx),
                side_input_index=int(add2_side_input_index),
                side_input_name=str(add2_side_name),
                target_broadcast_shape=target_nhwc_shape,
                chain_index_set=chain_index_set,
                consumers=consumers,
            ):
                continue
            if not _rewrite_binary_const_to_nhwc(
                op_idx=int(prelu_idx),
                side_input_index=int(prelu_side_input_index),
                side_input_name=str(prelu_side_name),
                target_broadcast_shape=target_nhwc_shape,
                chain_index_set=chain_index_set,
                consumers=consumers,
            ):
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=add_op,
                new_inputs=[str(plan["nhwc_input_name"]) for plan in input_plans],
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(add_out_name, None),
                perm_nchw_to_nhwc,
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(mul_out_name, None),
                perm_nchw_to_nhwc,
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(add2_out_name, None),
                perm_nchw_to_nhwc,
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(prelu_out_name, None),
                perm_nchw_to_nhwc,
            )

            canonical_post_output_name = str(post_output_names[0])
            _set_operator_outputs(
                model_ir=model_ir,
                op=prelu_op,
                new_outputs=[canonical_post_output_name],
            )
            for alias_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, str(alias_name), canonical_post_output_name)

            old_prelu_out_tensor = model_ir.tensors.get(prelu_out_name, None)
            canonical_tensor = model_ir.tensors.get(canonical_post_output_name, None)
            if old_prelu_out_tensor is not None and canonical_tensor is not None:
                canonical_tensor.dtype = str(old_prelu_out_tensor.dtype)
                canonical_tensor.quantization = _clone_quantization(old_prelu_out_tensor.quantization)
                canonical_tensor.shape = [int(v) for v in list(old_prelu_out_tensor.shape)]
                canonical_tensor.shape_signature = (
                    [int(v) for v in list(old_prelu_out_tensor.shape_signature)]
                    if old_prelu_out_tensor.shape_signature is not None
                    else [int(v) for v in list(old_prelu_out_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    canonical_tensor,
                    perm_nchw_to_nhwc,
                )

            if len(legacy_users) > 0:
                keep_post_idx = int(post_indices[0])
                keep_post_op = model_ir.operators[int(keep_post_idx)]
                keep_perm_name = str(keep_post_op.inputs[1])
                keep_perm_tensor = model_ir.tensors.get(keep_perm_name, None)
                if keep_perm_tensor is not None:
                    keep_perm_tensor.data = np.asarray(perm_nhwc_to_nchw, dtype=np.int32)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_inputs=[canonical_post_output_name, keep_perm_name],
                )
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_outputs=[prelu_out_name],
                )
                post_remove_indices = [int(v) for v in post_indices[1:]]
            else:
                post_remove_indices = [int(v) for v in post_indices]

            remove_indices = set(int(v) for v in post_remove_indices)
            for plan in input_plans:
                for pre_remove_idx in list(plan.get("pre_remove_indices", [])):
                    remove_indices.add(int(pre_remove_idx))
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_pre_add_mul_add_prelu_nhwc_chains": int(optimized)}


def _optimize_transpose_pre_add_reshape_transpose_suffix_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate NCHW add bridges that immediately feed [N,C,HW] reshape + [0,2,1] transpose.

    Target:
      a_nhwc --TRANSPOSE(0,3,1,2)--> a_nchw
      b_nhwc --TRANSPOSE(0,3,1,2)--> b_nchw
      ADD(a_nchw, b_nchw) -> y_nchw
      y_nchw --RESHAPE([N,C,HW])--> r
      r --TRANSPOSE([0,2,1])--> z
      (optional legacy users consume y_nchw)

    Rewrite:
      ADD(a_nhwc, b_nhwc) -> y_nhwc
      y_nhwc --RESHAPE([N,HW,C])--> z
      (if legacy users exist, keep one adapter TRANSPOSE(0,3,1,2): y_nhwc -> y_nchw)
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    perm_3d_nchw_to_nhwc = [0, 2, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _maybe_swap_reshape_shape_tensor(
        *,
        reshape_op: OperatorIR,
        reshape_idx: int,
        consumers: Dict[str, List[int]],
    ) -> None:
        if len(reshape_op.inputs) < 2:
            return
        shape_name = str(reshape_op.inputs[1])
        shape_tensor = model_ir.tensors.get(shape_name, None)
        if shape_tensor is None or shape_tensor.data is None:
            return
        shape_data = np.asarray(shape_tensor.data)
        if int(shape_data.size) != 3:
            return
        flat = shape_data.reshape(-1).copy()
        flat[[1, 2]] = flat[[2, 1]]
        swapped = flat.reshape(shape_data.shape).astype(shape_data.dtype, copy=False)

        shape_consumers = [int(v) for v in consumers.get(shape_name, [])]
        if any(int(v) != int(reshape_idx) for v in shape_consumers):
            cloned_name = _unique_tensor_name(f"{shape_name}_nhwc")
            model_ir.tensors[cloned_name] = TensorIR(
                name=cloned_name,
                dtype=str(shape_tensor.dtype),
                shape=[int(v) for v in list(swapped.shape)],
                shape_signature=[int(v) for v in list(swapped.shape)],
                data=np.asarray(swapped),
                is_variable=False,
                quantization=_clone_quantization(shape_tensor.quantization),
            )
            reshape_inputs = [str(v) for v in list(reshape_op.inputs)]
            reshape_inputs[1] = str(cloned_name)
            _set_operator_inputs(
                model_ir=model_ir,
                op=reshape_op,
                new_inputs=reshape_inputs,
            )
        else:
            shape_tensor.data = np.asarray(swapped)
            shape_tensor.shape = [int(v) for v in list(swapped.shape)]
            shape_tensor.shape_signature = [int(v) for v in list(swapped.shape)]

    def _maybe_swap_reshape_option_shape(reshape_op: OperatorIR) -> None:
        if not isinstance(reshape_op.options, dict):
            return
        opts = dict(reshape_op.options)
        changed = False
        for key in ["newShape", "onnxRawNewShape"]:
            value = opts.get(key, None)
            if not isinstance(value, list) or len(value) != 3:
                continue
            swapped = [value[0], value[2], value[1]]
            if swapped != value:
                opts[key] = [int(v) for v in swapped]
                changed = True
        if changed:
            reshape_op.options = opts

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for add_idx, add_op in enumerate(model_ir.operators):
            if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                continue

            add_out_name = str(add_op.outputs[0])
            if add_out_name in model_outputs:
                continue

            add_users = [int(v) for v in consumers.get(add_out_name, []) if int(v) != int(add_idx)]
            if len(add_users) == 0:
                continue

            suffix_reshape_idx: Optional[int] = None
            suffix_transpose_idx: Optional[int] = None
            suffix_output_name: Optional[str] = None
            legacy_users: List[int] = []

            valid = True
            for user_idx in add_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "RESHAPE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == add_out_name
                ):
                    reshape_out_name = str(user_op.outputs[0])
                    reshape_users = [
                        int(v)
                        for v in consumers.get(reshape_out_name, [])
                        if int(v) != int(user_idx)
                    ]
                    if len(reshape_users) != 1:
                        legacy_users.append(int(user_idx))
                        continue
                    post_idx = int(reshape_users[0])
                    post_op = model_ir.operators[int(post_idx)]
                    if (
                        str(post_op.op_type) != "TRANSPOSE"
                        or len(post_op.inputs) < 2
                        or len(post_op.outputs) != 1
                        or str(post_op.inputs[0]) != reshape_out_name
                        or _read_transpose_perm(model_ir, post_op) != perm_3d_nchw_to_nhwc
                    ):
                        legacy_users.append(int(user_idx))
                        continue
                    post_out_name = str(post_op.outputs[0])
                    if post_out_name in model_outputs:
                        valid = False
                        break
                    if suffix_reshape_idx is not None:
                        valid = False
                        break
                    suffix_reshape_idx = int(user_idx)
                    suffix_transpose_idx = int(post_idx)
                    suffix_output_name = post_out_name
                else:
                    legacy_users.append(int(user_idx))
            if not valid or suffix_reshape_idx is None or suffix_transpose_idx is None or suffix_output_name is None:
                continue

            input_plans: List[Dict[str, Any]] = []
            can_rewrite_inputs = True
            for input_name in [str(v) for v in list(add_op.inputs)]:
                pre_idx = producers.get(input_name, None)
                if pre_idx is None:
                    can_rewrite_inputs = False
                    break
                pre_op = model_ir.operators[int(pre_idx)]
                if (
                    str(pre_op.op_type) != "TRANSPOSE"
                    or len(pre_op.inputs) < 2
                    or len(pre_op.outputs) != 1
                    or str(pre_op.outputs[0]) != input_name
                    or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
                    or input_name in model_outputs
                ):
                    can_rewrite_inputs = False
                    break

                input_users = [int(v) for v in consumers.get(input_name, [])]
                if int(add_idx) not in input_users:
                    can_rewrite_inputs = False
                    break
                pre_remove = [int(pre_idx)] if set(input_users) == {int(add_idx)} else []
                input_plans.append(
                    {
                        "nhwc_input_name": str(pre_op.inputs[0]),
                        "pre_remove_indices": pre_remove,
                    }
                )
            if not can_rewrite_inputs:
                continue

            add_nhwc_name = (
                _unique_tensor_name(f"{add_out_name}_nhwc")
                if len(legacy_users) > 0
                else str(add_out_name)
            )
            new_add_inputs = [str(plan["nhwc_input_name"]) for plan in input_plans]
            _set_operator_inputs(
                model_ir=model_ir,
                op=add_op,
                new_inputs=new_add_inputs,
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=add_op,
                new_outputs=[add_nhwc_name],
            )

            old_add_tensor = model_ir.tensors.get(add_out_name, None)
            if add_nhwc_name != add_out_name:
                if old_add_tensor is not None and add_nhwc_name not in model_ir.tensors:
                    model_ir.tensors[add_nhwc_name] = TensorIR(
                        name=add_nhwc_name,
                        dtype=str(old_add_tensor.dtype),
                        shape=[int(v) for v in list(old_add_tensor.shape)],
                        shape_signature=(
                            [int(v) for v in list(old_add_tensor.shape_signature)]
                            if old_add_tensor.shape_signature is not None
                            else [int(v) for v in list(old_add_tensor.shape)]
                        ),
                        data=None,
                        is_variable=False,
                        quantization=_clone_quantization(old_add_tensor.quantization),
                    )

            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(add_nhwc_name, None),
                perm_nchw_to_nhwc,
            )

            reshape_op = model_ir.operators[int(suffix_reshape_idx)]
            reshape_inputs = [str(v) for v in list(reshape_op.inputs)]
            reshape_inputs[0] = add_nhwc_name
            _set_operator_inputs(
                model_ir=model_ir,
                op=reshape_op,
                new_inputs=reshape_inputs,
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=reshape_op,
                new_outputs=[str(suffix_output_name)],
            )
            _maybe_swap_reshape_shape_tensor(
                reshape_op=reshape_op,
                reshape_idx=int(suffix_reshape_idx),
                consumers=consumers,
            )
            _maybe_swap_reshape_option_shape(reshape_op)

            remove_indices = [int(suffix_transpose_idx)]
            for plan in input_plans:
                remove_indices.extend([int(v) for v in list(plan.get("pre_remove_indices", []))])
            remove_indices = sorted(list(set(remove_indices)), reverse=True)
            removed_before_add = sum(1 for idx in remove_indices if int(idx) < int(add_idx))
            new_add_idx = int(add_idx) - int(removed_before_add)
            for remove_idx in remove_indices:
                if int(remove_idx) == int(add_idx):
                    continue
                del model_ir.operators[int(remove_idx)]

            if len(legacy_users) > 0:
                adapter_perm_name = _unique_tensor_name(f"{add_out_name}_adapter_perm")
                model_ir.tensors[adapter_perm_name] = TensorIR(
                    name=adapter_perm_name,
                    dtype="INT32",
                    shape=[4],
                    shape_signature=[4],
                    data=np.asarray(perm_nhwc_to_nchw, dtype=np.int32),
                    is_variable=False,
                    quantization=None,
                )
                adapter_op = OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[add_nhwc_name, adapter_perm_name],
                    outputs=[add_out_name],
                    options={},
                )
                model_ir.operators.insert(int(new_add_idx) + 1, adapter_op)

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_pre_add_reshape_transpose_suffix_nhwc_chains": int(rewritten)}


def _optimize_transpose_pre_add_mulconst_reshape_transpose_suffix_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate NCHW add bridges with mul-const inputs that feed [N,C,HW] reshape + [0,2,1] transpose.

    Target:
      a_nhwc --TRANSPOSE(0,3,1,2)--> a_nchw
      b_nhwc --TRANSPOSE(0,3,1,2)--> b_nchw --MUL(const)--> b_scaled_nchw
      ADD(a_nchw, b_scaled_nchw) -> y_nchw
      y_nchw --RESHAPE([N,C,HW])--> r --TRANSPOSE([0,2,1])--> z
      (optional legacy users consume y_nchw)

    Rewrite:
      ADD(a_nhwc, b_scaled_nhwc) -> y_nhwc
      y_nhwc --RESHAPE([N,HW,C])--> z
      (if legacy users exist, keep one adapter TRANSPOSE(0,3,1,2): y_nhwc -> y_nchw)
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    perm_3d_nchw_to_nhwc = [0, 2, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _maybe_swap_reshape_shape_tensor(
        *,
        reshape_op: OperatorIR,
        reshape_idx: int,
        consumers: Dict[str, List[int]],
    ) -> None:
        if len(reshape_op.inputs) < 2:
            return
        shape_name = str(reshape_op.inputs[1])
        shape_tensor = model_ir.tensors.get(shape_name, None)
        if shape_tensor is None or shape_tensor.data is None:
            return
        shape_data = np.asarray(shape_tensor.data)
        if int(shape_data.size) != 3:
            return
        flat = shape_data.reshape(-1).copy()
        flat[[1, 2]] = flat[[2, 1]]
        swapped = flat.reshape(shape_data.shape).astype(shape_data.dtype, copy=False)

        shape_consumers = [int(v) for v in consumers.get(shape_name, [])]
        if any(int(v) != int(reshape_idx) for v in shape_consumers):
            cloned_name = _unique_tensor_name(f"{shape_name}_nhwc")
            model_ir.tensors[cloned_name] = TensorIR(
                name=cloned_name,
                dtype=str(shape_tensor.dtype),
                shape=[int(v) for v in list(swapped.shape)],
                shape_signature=[int(v) for v in list(swapped.shape)],
                data=np.asarray(swapped),
                is_variable=False,
                quantization=_clone_quantization(shape_tensor.quantization),
            )
            reshape_inputs = [str(v) for v in list(reshape_op.inputs)]
            reshape_inputs[1] = str(cloned_name)
            _set_operator_inputs(
                model_ir=model_ir,
                op=reshape_op,
                new_inputs=reshape_inputs,
            )
        else:
            shape_tensor.data = np.asarray(swapped)
            shape_tensor.shape = [int(v) for v in list(swapped.shape)]
            shape_tensor.shape_signature = [int(v) for v in list(swapped.shape)]

    def _maybe_swap_reshape_option_shape(reshape_op: OperatorIR) -> None:
        if not isinstance(reshape_op.options, dict):
            return
        opts = dict(reshape_op.options)
        changed = False
        for key in ["newShape", "onnxRawNewShape"]:
            value = opts.get(key, None)
            if not isinstance(value, list) or len(value) != 3:
                continue
            swapped = [value[0], value[2], value[1]]
            if swapped != value:
                opts[key] = [int(v) for v in swapped]
                changed = True
        if changed:
            reshape_op.options = opts

    def _analyze_input_plan(
        *,
        input_name: str,
        add_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        pre_idx = producers.get(str(input_name), None)
        if pre_idx is not None:
            pre_op = model_ir.operators[int(pre_idx)]
            if (
                str(pre_op.op_type) == "TRANSPOSE"
                and len(pre_op.inputs) >= 2
                and len(pre_op.outputs) == 1
                and str(pre_op.outputs[0]) == str(input_name)
                and _read_transpose_perm(model_ir, pre_op) == perm_nhwc_to_nchw
                and str(input_name) not in model_outputs
            ):
                users = [int(v) for v in consumers.get(str(input_name), [])]
                if int(add_idx) in users:
                    return {
                        "nhwc_input_name": str(pre_op.inputs[0]),
                        "pre_remove_indices": [int(pre_idx)] if set(users) == {int(add_idx)} else [],
                        "mul_plan": None,
                    }

        mul_idx = producers.get(str(input_name), None)
        if mul_idx is None:
            return None
        mul_op = model_ir.operators[int(mul_idx)]
        if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
            return None
        if str(mul_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        input_users = [int(v) for v in consumers.get(str(input_name), [])]
        if int(add_idx) not in input_users:
            return None

        data_input_index: Optional[int] = None
        side_input_index: Optional[int] = None
        side_input_name: Optional[str] = None
        data_pre_idx: Optional[int] = None
        data_pre_input_name: Optional[str] = None

        for cand_data_idx, cand_side_idx in [(0, 1), (1, 0)]:
            data_name = str(mul_op.inputs[int(cand_data_idx)])
            side_name = str(mul_op.inputs[int(cand_side_idx)])
            side_tensor = model_ir.tensors.get(side_name, None)
            if side_tensor is None or side_tensor.data is None:
                continue
            side_data = np.asarray(side_tensor.data)
            if int(side_data.size) != 1 and side_data.ndim != 4:
                continue

            data_prod_idx = producers.get(data_name, None)
            if data_prod_idx is None:
                continue
            data_prod_op = model_ir.operators[int(data_prod_idx)]
            if (
                str(data_prod_op.op_type) != "TRANSPOSE"
                or len(data_prod_op.inputs) < 2
                or len(data_prod_op.outputs) != 1
                or str(data_prod_op.outputs[0]) != data_name
                or _read_transpose_perm(model_ir, data_prod_op) != perm_nhwc_to_nchw
                or str(data_name) in model_outputs
            ):
                continue
            if set(int(v) for v in consumers.get(data_name, [])) != {int(mul_idx)}:
                continue

            data_tensor = model_ir.tensors.get(data_name, None)
            pre_input_name = str(data_prod_op.inputs[0])
            pre_input_tensor = model_ir.tensors.get(pre_input_name, None)
            if data_tensor is None or pre_input_tensor is None:
                continue
            if (
                not _is_fully_known_positive_shape(list(data_tensor.shape))
                or not _is_fully_known_positive_shape(list(pre_input_tensor.shape))
                or len(list(data_tensor.shape)) != 4
                or len(list(pre_input_tensor.shape)) != 4
            ):
                continue

            if int(side_data.size) != 1:
                if _broadcast_static_shapes(list(data_tensor.shape), [int(v) for v in list(side_data.shape)]) is None:
                    continue

            data_input_index = int(cand_data_idx)
            side_input_index = int(cand_side_idx)
            side_input_name = str(side_name)
            data_pre_idx = int(data_prod_idx)
            data_pre_input_name = str(pre_input_name)
            break

        if (
            data_input_index is None
            or side_input_index is None
            or side_input_name is None
            or data_pre_idx is None
            or data_pre_input_name is None
        ):
            return None

        side_tensor = model_ir.tensors.get(side_input_name, None)
        if side_tensor is None or side_tensor.data is None:
            return None
        side_data = np.asarray(side_tensor.data)
        nhwc_side_data: Optional[np.ndarray] = None
        side_needs_update = False
        if int(side_data.size) != 1:
            target_shape = [int(v) for v in list(model_ir.tensors[str(data_pre_input_name)].shape)]
            side_shape = [int(v) for v in list(side_data.shape)]
            if _broadcast_static_shapes(target_shape, side_shape) is not None:
                nhwc_side_data = np.asarray(side_data)
            else:
                rotated = np.asarray(side_data)
                found = False
                for _ in range(3):
                    rotated = np.transpose(rotated, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
                    rotated_shape = [int(v) for v in list(rotated.shape)]
                    if _broadcast_static_shapes(target_shape, rotated_shape) is not None:
                        nhwc_side_data = np.asarray(rotated)
                        side_needs_update = True
                        found = True
                        break
                if not found:
                    return None

        side_users = [int(v) for v in consumers.get(str(side_input_name), [])]
        side_shared_outside_mul = any(int(v) != int(mul_idx) for v in side_users)

        return {
            "nhwc_input_name": str(input_name),
            "pre_remove_indices": [],
            "mul_plan": {
                "mul_idx": int(mul_idx),
                "mul_data_input_index": int(data_input_index),
                "mul_side_input_index": int(side_input_index),
                "mul_side_input_name": str(side_input_name),
                "mul_out_name": str(input_name),
                "data_pre_idx": int(data_pre_idx),
                "data_pre_input_name": str(data_pre_input_name),
                "side_needs_update": bool(side_needs_update),
                "side_shared_outside_mul": bool(side_shared_outside_mul),
                "side_nhwc_data": (None if nhwc_side_data is None else np.asarray(nhwc_side_data)),
            },
        }

    def _apply_mul_plan(*, plan: Dict[str, Any]) -> List[int]:
        mul_idx = int(plan["mul_idx"])
        mul_data_input_index = int(plan["mul_data_input_index"])
        mul_side_input_index = int(plan["mul_side_input_index"])
        mul_side_input_name = str(plan["mul_side_input_name"])
        mul_out_name = str(plan["mul_out_name"])
        data_pre_idx = int(plan["data_pre_idx"])
        data_pre_input_name = str(plan["data_pre_input_name"])

        side_input_name_for_mul = str(mul_side_input_name)
        if bool(plan.get("side_needs_update", False)):
            nhwc_data = np.asarray(plan.get("side_nhwc_data"))
            side_tensor = model_ir.tensors.get(str(mul_side_input_name), None)
            if side_tensor is None:
                return []
            if bool(plan.get("side_shared_outside_mul", False)):
                side_input_name_for_mul = _unique_tensor_name(f"{mul_side_input_name}_nhwc")
                model_ir.tensors[side_input_name_for_mul] = TensorIR(
                    name=side_input_name_for_mul,
                    dtype=str(side_tensor.dtype),
                    shape=[int(v) for v in list(nhwc_data.shape)],
                    shape_signature=[int(v) for v in list(nhwc_data.shape)],
                    data=np.asarray(nhwc_data),
                    is_variable=False,
                    quantization=_clone_quantization(side_tensor.quantization),
                )
            else:
                side_tensor.data = np.asarray(nhwc_data)
                side_tensor.shape = [int(v) for v in list(nhwc_data.shape)]
                side_tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]

        mul_op = model_ir.operators[int(mul_idx)]
        mul_inputs = [str(v) for v in list(mul_op.inputs)]
        if int(mul_data_input_index) < 0 or int(mul_data_input_index) >= len(mul_inputs):
            return []
        if int(mul_side_input_index) < 0 or int(mul_side_input_index) >= len(mul_inputs):
            return []
        mul_inputs[int(mul_data_input_index)] = str(data_pre_input_name)
        mul_inputs[int(mul_side_input_index)] = str(side_input_name_for_mul)
        _set_operator_inputs(
            model_ir=model_ir,
            op=mul_op,
            new_inputs=mul_inputs,
        )
        _permute_tensor_metadata_if_rank_matches(
            model_ir.tensors.get(mul_out_name, None),
            perm_nchw_to_nhwc,
        )
        return [int(data_pre_idx)]

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for add_idx, add_op in enumerate(model_ir.operators):
            if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                continue

            add_out_name = str(add_op.outputs[0])
            if add_out_name in model_outputs:
                continue

            add_users = [int(v) for v in consumers.get(add_out_name, []) if int(v) != int(add_idx)]
            if len(add_users) == 0:
                continue

            suffix_reshape_idx: Optional[int] = None
            suffix_transpose_idx: Optional[int] = None
            suffix_output_name: Optional[str] = None
            legacy_users: List[int] = []
            valid_users = True
            for user_idx in add_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "RESHAPE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == add_out_name
                ):
                    reshape_out_name = str(user_op.outputs[0])
                    reshape_users = [
                        int(v)
                        for v in consumers.get(reshape_out_name, [])
                        if int(v) != int(user_idx)
                    ]
                    if len(reshape_users) != 1:
                        legacy_users.append(int(user_idx))
                        continue
                    post_idx = int(reshape_users[0])
                    post_op = model_ir.operators[int(post_idx)]
                    if (
                        str(post_op.op_type) != "TRANSPOSE"
                        or len(post_op.inputs) < 2
                        or len(post_op.outputs) != 1
                        or str(post_op.inputs[0]) != reshape_out_name
                        or _read_transpose_perm(model_ir, post_op) != perm_3d_nchw_to_nhwc
                    ):
                        legacy_users.append(int(user_idx))
                        continue
                    post_out_name = str(post_op.outputs[0])
                    if post_out_name in model_outputs:
                        valid_users = False
                        break
                    if suffix_reshape_idx is not None:
                        valid_users = False
                        break
                    suffix_reshape_idx = int(user_idx)
                    suffix_transpose_idx = int(post_idx)
                    suffix_output_name = str(post_out_name)
                else:
                    legacy_users.append(int(user_idx))
            if not valid_users or suffix_reshape_idx is None or suffix_transpose_idx is None or suffix_output_name is None:
                continue

            input_plans: List[Dict[str, Any]] = []
            rewritable = True
            for input_name in [str(v) for v in list(add_op.inputs)]:
                plan = _analyze_input_plan(
                    input_name=input_name,
                    add_idx=int(add_idx),
                    producers=producers,
                    consumers=consumers,
                    model_outputs=model_outputs,
                )
                if plan is None:
                    rewritable = False
                    break
                input_plans.append(dict(plan))
            if not rewritable:
                continue

            pre_remove_indices: List[int] = []
            for plan in input_plans:
                mul_plan = plan.get("mul_plan", None)
                if mul_plan is not None:
                    pre_remove_indices.extend(_apply_mul_plan(plan=dict(mul_plan)))
                pre_remove_indices.extend([int(v) for v in list(plan.get("pre_remove_indices", []))])

            add_nhwc_name = (
                _unique_tensor_name(f"{add_out_name}_nhwc")
                if len(legacy_users) > 0
                else str(add_out_name)
            )
            new_add_inputs = [str(plan["nhwc_input_name"]) for plan in input_plans]
            _set_operator_inputs(
                model_ir=model_ir,
                op=add_op,
                new_inputs=new_add_inputs,
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=add_op,
                new_outputs=[add_nhwc_name],
            )

            old_add_tensor = model_ir.tensors.get(add_out_name, None)
            if add_nhwc_name != add_out_name:
                if old_add_tensor is not None and add_nhwc_name not in model_ir.tensors:
                    model_ir.tensors[add_nhwc_name] = TensorIR(
                        name=add_nhwc_name,
                        dtype=str(old_add_tensor.dtype),
                        shape=[int(v) for v in list(old_add_tensor.shape)],
                        shape_signature=(
                            [int(v) for v in list(old_add_tensor.shape_signature)]
                            if old_add_tensor.shape_signature is not None
                            else [int(v) for v in list(old_add_tensor.shape)]
                        ),
                        data=None,
                        is_variable=False,
                        quantization=_clone_quantization(old_add_tensor.quantization),
                    )

            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(add_nhwc_name, None),
                perm_nchw_to_nhwc,
            )

            reshape_op = model_ir.operators[int(suffix_reshape_idx)]
            reshape_inputs = [str(v) for v in list(reshape_op.inputs)]
            reshape_inputs[0] = add_nhwc_name
            _set_operator_inputs(
                model_ir=model_ir,
                op=reshape_op,
                new_inputs=reshape_inputs,
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=reshape_op,
                new_outputs=[str(suffix_output_name)],
            )
            _maybe_swap_reshape_shape_tensor(
                reshape_op=reshape_op,
                reshape_idx=int(suffix_reshape_idx),
                consumers=consumers,
            )
            _maybe_swap_reshape_option_shape(reshape_op)

            remove_indices = [int(suffix_transpose_idx)]
            remove_indices.extend([int(v) for v in pre_remove_indices])
            remove_indices = sorted(list(set(remove_indices)), reverse=True)
            removed_before_add = sum(1 for idx in remove_indices if int(idx) < int(add_idx))
            new_add_idx = int(add_idx) - int(removed_before_add)
            for remove_idx in remove_indices:
                if int(remove_idx) == int(add_idx):
                    continue
                del model_ir.operators[int(remove_idx)]

            if len(legacy_users) > 0:
                adapter_perm_name = _unique_tensor_name(f"{add_out_name}_adapter_perm")
                model_ir.tensors[adapter_perm_name] = TensorIR(
                    name=adapter_perm_name,
                    dtype="INT32",
                    shape=[4],
                    shape_signature=[4],
                    data=np.asarray(perm_nhwc_to_nchw, dtype=np.int32),
                    is_variable=False,
                    quantization=None,
                )
                adapter_op = OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[add_nhwc_name, adapter_perm_name],
                    outputs=[add_out_name],
                    options={},
                )
                model_ir.operators.insert(int(new_add_idx) + 1, adapter_op)

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "optimized_transpose_pre_add_mulconst_reshape_transpose_suffix_nhwc_chains": int(rewritten)
    }


def _optimize_transpose_mul_add_const_prepost_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate NCHW round-trips around linear TRANSPOSE->MUL(const)->ADD(const)->TRANSPOSE chains.

    Target:
      x_nhwc --TRANSPOSE(0,3,1,2)--> x_nchw
      x_nchw --MUL(const)--> m_nchw --ADD(const)--> y_nchw
      y_nchw --TRANSPOSE(0,2,3,1)--> y_nhwc

    Rewrite:
      x_nhwc --MUL(const_nhwc)--> m_nhwc --ADD(const_nhwc)--> y_nhwc
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _rewrite_binary_const_to_nhwc(
        *,
        op_idx: int,
        side_input_index: int,
        side_input_name: str,
        target_broadcast_shape: Optional[List[int]],
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> bool:
        side_tensor = model_ir.tensors.get(str(side_input_name), None)
        if side_tensor is None or side_tensor.data is None:
            return False
        side_data = np.asarray(side_tensor.data)
        if int(side_data.size) == 1:
            return True
        if side_data.ndim != 4:
            return False

        nhwc_data: Optional[np.ndarray] = None
        target_shape = (
            [int(v) for v in list(target_broadcast_shape)]
            if _is_fully_known_positive_shape(target_broadcast_shape)
            else None
        )
        if target_shape is not None:
            side_shape = [int(v) for v in list(side_data.shape)]
            if _broadcast_static_shapes(target_shape, side_shape) is not None:
                # Already NHWC-compatible. Keep idempotent across repeated sweeps.
                return True
            rotated = np.asarray(side_data)
            for _ in range(3):
                rotated = np.transpose(rotated, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
                rotated_shape = [int(v) for v in list(rotated.shape)]
                if _broadcast_static_shapes(target_shape, rotated_shape) is not None:
                    nhwc_data = np.asarray(rotated)
                    break
            if nhwc_data is None:
                return False
        else:
            side_shape = [int(v) for v in list(side_data.shape)]
            if (
                len(side_shape) == 4
                and int(side_shape[0]) == 1
                and int(side_shape[1]) > 1
                and int(side_shape[2]) == 1
                and int(side_shape[3]) == 1
            ):
                nhwc_data = np.transpose(side_data, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
            else:
                return True

        side_users = [int(v) for v in consumers.get(str(side_input_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)

        target_name = str(side_input_name)
        if shared_outside_chain:
            target_name = _unique_tensor_name(f"{side_input_name}_nhwc")
            model_ir.tensors[target_name] = TensorIR(
                name=target_name,
                dtype=str(side_tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(side_tensor.quantization),
            )
        else:
            side_tensor.data = np.asarray(nhwc_data)
            side_tensor.shape = [int(v) for v in list(nhwc_data.shape)]
            side_tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]

        _replace_operator_input_at(
            model_ir=model_ir,
            op=model_ir.operators[int(op_idx)],
            input_index=int(side_input_index),
            new_input_name=str(target_name),
        )
        return True

    def _can_rewrite_binary_const_to_nhwc(
        *,
        side_input_name: str,
        target_broadcast_shape: Optional[List[int]],
    ) -> bool:
        side_tensor = model_ir.tensors.get(str(side_input_name), None)
        if side_tensor is None or side_tensor.data is None:
            return False
        side_data = np.asarray(side_tensor.data)
        if int(side_data.size) == 1:
            return True
        if side_data.ndim != 4:
            return False
        target_shape = (
            [int(v) for v in list(target_broadcast_shape)]
            if _is_fully_known_positive_shape(target_broadcast_shape)
            else None
        )
        if target_shape is None:
            return True
        side_shape = [int(v) for v in list(side_data.shape)]
        if _broadcast_static_shapes(target_shape, side_shape) is not None:
            return True
        rotated = np.asarray(side_data)
        for _ in range(3):
            rotated = np.transpose(rotated, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
            rotated_shape = [int(v) for v in list(rotated.shape)]
            if _broadcast_static_shapes(target_shape, rotated_shape) is not None:
                return True
        return False

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue
            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_input_name in model_outputs or pre_output_name in model_outputs:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) == 0:
                continue
            for mul_idx in pre_users:
                mul_op = model_ir.operators[int(mul_idx)]
                if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                    continue
                mul_in0 = str(mul_op.inputs[0])
                mul_in1 = str(mul_op.inputs[1])
                if mul_in0 == pre_output_name:
                    mul_side_input_index = 1
                    mul_side_name = mul_in1
                elif mul_in1 == pre_output_name:
                    mul_side_input_index = 0
                    mul_side_name = mul_in0
                else:
                    continue

                add_input_name = str(mul_op.outputs[0])
                if add_input_name in model_outputs:
                    continue
                add_users = [int(v) for v in consumers.get(add_input_name, [])]
                if len(add_users) != 1:
                    continue
                add_idx = int(add_users[0])
                add_op = model_ir.operators[add_idx]
                if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                    continue
                add_in0 = str(add_op.inputs[0])
                add_in1 = str(add_op.inputs[1])
                if add_in0 == add_input_name:
                    add_side_input_index = 1
                    add_side_name = add_in1
                elif add_in1 == add_input_name:
                    add_side_input_index = 0
                    add_side_name = add_in0
                else:
                    continue

                add_output_name = str(add_op.outputs[0])
                if add_output_name in model_outputs:
                    continue

                bridge_output_name = str(add_output_name)
                bridge_output_producer_idx = int(add_idx)
                bridge_output_producer_op = add_op
                prelu_idx: Optional[int] = None
                prelu_side_input_index: Optional[int] = None
                prelu_side_name: Optional[str] = None

                add_output_users = [int(v) for v in consumers.get(add_output_name, []) if int(v) != int(add_idx)]
                if len(add_output_users) == 0:
                    continue
                if False and len(add_output_users) == 1:
                    candidate_idx = int(add_output_users[0])
                    candidate_op = model_ir.operators[int(candidate_idx)]
                    if (
                        str(candidate_op.op_type) == "PRELU"
                        and len(candidate_op.inputs) == 2
                        and len(candidate_op.outputs) == 1
                        and str(candidate_op.inputs[0]) == add_output_name
                    ):
                        candidate_out_name = str(candidate_op.outputs[0])
                        if candidate_out_name in model_outputs:
                            continue
                        prelu_idx = int(candidate_idx)
                        prelu_side_input_index = 1
                        prelu_side_name = str(candidate_op.inputs[1])
                        bridge_output_name = str(candidate_out_name)
                        bridge_output_producer_idx = int(candidate_idx)
                        bridge_output_producer_op = candidate_op

                bridge_output_users = [
                    int(v)
                    for v in consumers.get(bridge_output_name, [])
                    if int(v) != int(bridge_output_producer_idx)
                ]
                if len(bridge_output_users) == 0:
                    continue

                post_indices: List[int] = []
                post_output_names: List[str] = []
                legacy_users: List[int] = []
                valid_posts = True
                for user_idx in bridge_output_users:
                    user_op = model_ir.operators[int(user_idx)]
                    if (
                        str(user_op.op_type) == "TRANSPOSE"
                        and len(user_op.inputs) >= 2
                        and len(user_op.outputs) == 1
                        and str(user_op.inputs[0]) == bridge_output_name
                        and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                        and str(user_op.outputs[0]) not in model_outputs
                    ):
                        post_indices.append(int(user_idx))
                        post_output_names.append(str(user_op.outputs[0]))
                    else:
                        legacy_users.append(int(user_idx))
                if not valid_posts or len(post_indices) == 0:
                    continue
                if len(legacy_users) > 0:
                    continue

                chain_index_set = {int(mul_idx), int(add_idx)}
                if prelu_idx is not None:
                    chain_index_set.add(int(prelu_idx))
                target_nhwc_shape = (
                    list(model_ir.tensors[pre_input_name].shape)
                    if pre_input_name in model_ir.tensors
                    else None
                )
                if not _can_rewrite_binary_const_to_nhwc(
                    side_input_name=str(mul_side_name),
                    target_broadcast_shape=target_nhwc_shape,
                ):
                    continue
                if not _can_rewrite_binary_const_to_nhwc(
                    side_input_name=str(add_side_name),
                    target_broadcast_shape=target_nhwc_shape,
                ):
                    continue
                if not _rewrite_binary_const_to_nhwc(
                    op_idx=int(mul_idx),
                    side_input_index=int(mul_side_input_index),
                    side_input_name=str(mul_side_name),
                    target_broadcast_shape=target_nhwc_shape,
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                ):
                    continue
                if not _rewrite_binary_const_to_nhwc(
                    op_idx=int(add_idx),
                    side_input_index=int(add_side_input_index),
                    side_input_name=str(add_side_name),
                    target_broadcast_shape=target_nhwc_shape,
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                ):
                    continue
                if prelu_idx is not None:
                    if prelu_side_input_index is None or prelu_side_name is None:
                        continue
                    if not _can_rewrite_binary_const_to_nhwc(
                        side_input_name=str(prelu_side_name),
                        target_broadcast_shape=target_nhwc_shape,
                    ):
                        continue
                    if not _rewrite_binary_const_to_nhwc(
                        op_idx=int(prelu_idx),
                        side_input_index=int(prelu_side_input_index),
                        side_input_name=str(prelu_side_name),
                        target_broadcast_shape=target_nhwc_shape,
                        chain_index_set=chain_index_set,
                        consumers=consumers,
                    ):
                        continue

                # Bypass only this branch input from pre_output to pre_input.
                mul_inputs = [str(v) for v in list(mul_op.inputs)]
                if mul_inputs[0] == pre_output_name:
                    mul_inputs[0] = pre_input_name
                elif mul_inputs[1] == pre_output_name:
                    mul_inputs[1] = pre_input_name
                else:
                    continue
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=mul_op,
                    new_inputs=mul_inputs,
                )

                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(add_input_name, None),
                    perm_nchw_to_nhwc,
                )
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(add_output_name, None),
                    perm_nchw_to_nhwc,
                )
                if prelu_idx is not None:
                    _permute_tensor_metadata_if_rank_matches(
                        model_ir.tensors.get(bridge_output_name, None),
                        perm_nchw_to_nhwc,
                    )

                canonical_post_output_name = str(post_output_names[0])
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=bridge_output_producer_op,
                    new_outputs=[canonical_post_output_name],
                )
                for alias_name in post_output_names[1:]:
                    _replace_tensor_inputs(model_ir, str(alias_name), canonical_post_output_name)

                old_add_out_tensor = model_ir.tensors.get(bridge_output_name, None)
                canonical_tensor = model_ir.tensors.get(canonical_post_output_name, None)
                if old_add_out_tensor is not None and canonical_tensor is not None:
                    canonical_tensor.dtype = str(old_add_out_tensor.dtype)
                    canonical_tensor.quantization = _clone_quantization(old_add_out_tensor.quantization)
                    canonical_tensor.shape = [int(v) for v in list(old_add_out_tensor.shape)]
                    canonical_tensor.shape_signature = (
                        [int(v) for v in list(old_add_out_tensor.shape_signature)]
                        if old_add_out_tensor.shape_signature is not None
                        else [int(v) for v in list(old_add_out_tensor.shape)]
                    )
                    _permute_tensor_metadata_if_rank_matches(
                        canonical_tensor,
                        perm_nchw_to_nhwc,
                    )

                post_remove_indices = [int(v) for v in post_indices]

                remove_indices = set(int(v) for v in post_remove_indices)
                # Drop pre transpose only when this rewrite consumed its last user.
                pre_remaining_users = [int(v) for v in pre_users if int(v) != int(mul_idx)]
                if len(pre_remaining_users) == 0:
                    remove_indices.add(int(pre_idx))
                for remove_idx in sorted(remove_indices, reverse=True):
                    del model_ir.operators[int(remove_idx)]

                rewritten += 1
                changed = True
                break

            if changed:
                break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_mul_add_const_prepost_nhwc_chains": int(rewritten)}


def _optimize_sinet_shuffle_residual_transpose_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Optimize a strict ShuffleNet-like residual pattern observed in SiNet blocks:

      T13: a_nhwc -> a_nchw
      T26/T36: x_nhwc,y_nhwc -> x_nchw,y_nchw
      ADD -> MUL(const) -> ADD(const) -> PRELU -> T42 (to NHWC conv branch)
      CONCAT(a_nchw, prelu_nchw) -> MUL(const) -> ADD(const) -> PRELU -> T49

    Rewrite to NHWC core and drop redundant adapters:
      - remove T26/T36 and run first residual chain in NHWC
      - remove T42 by exposing first PRELU output as NHWC directly
      - rewrite CONCAT to NHWC (axis=3), consume a_nhwc directly (drop T13)
      - run second residual chain in NHWC and remove T49
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _ensure_channel_last_const(
        *,
        tensor_name: str,
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> Optional[str]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.data is None:
            return None
        data = np.asarray(tensor.data)
        if int(data.size) == 1:
            return str(tensor_name)
        if data.ndim != 4:
            return None
        shape = [int(v) for v in list(data.shape)]
        if (
            int(shape[0]) == 1
            and int(shape[1]) == 1
            and int(shape[2]) == 1
            and int(shape[3]) > 0
        ):
            nhwc_data = np.asarray(data)
        elif (
            int(shape[0]) == 1
            and int(shape[1]) > 0
            and int(shape[2]) == 1
            and int(shape[3]) == 1
        ):
            nhwc_data = np.transpose(data, perm_nchw_to_nhwc).astype(data.dtype, copy=False)
        else:
            return None

        side_users = [int(v) for v in consumers.get(str(tensor_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)
        if shared_outside_chain:
            cloned_name = _unique_tensor_name(f"{tensor_name}_nhwc")
            model_ir.tensors[cloned_name] = TensorIR(
                name=cloned_name,
                dtype=str(tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(tensor.quantization),
            )
            return str(cloned_name)

        tensor.data = np.asarray(nhwc_data)
        tensor.shape = [int(v) for v in list(nhwc_data.shape)]
        tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]
        return str(tensor_name)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for post2_idx, post2_op in enumerate(model_ir.operators):
            if (
                str(post2_op.op_type) != "TRANSPOSE"
                or len(post2_op.inputs) < 2
                or len(post2_op.outputs) != 1
                or _read_transpose_perm(model_ir, post2_op) != perm_nchw_to_nhwc
            ):
                continue
            post2_input_name = str(post2_op.inputs[0])
            post2_output_name = str(post2_op.outputs[0])
            if post2_output_name in model_outputs:
                continue

            prelu2_idx = producers.get(post2_input_name, None)
            if prelu2_idx is None:
                continue
            prelu2_op = model_ir.operators[int(prelu2_idx)]
            if (
                str(prelu2_op.op_type) != "PRELU"
                or len(prelu2_op.inputs) != 2
                or len(prelu2_op.outputs) != 1
                or str(prelu2_op.outputs[0]) != post2_input_name
            ):
                continue

            add2_idx = producers.get(str(prelu2_op.inputs[0]), None)
            if add2_idx is None:
                continue
            add2_op = model_ir.operators[int(add2_idx)]
            if str(add2_op.op_type) != "ADD" or len(add2_op.inputs) != 2 or len(add2_op.outputs) != 1:
                continue
            add2_out_name = str(add2_op.outputs[0])
            if str(prelu2_op.inputs[0]) != add2_out_name:
                continue
            add2_in0 = str(add2_op.inputs[0])
            add2_in1 = str(add2_op.inputs[1])

            mul2_idx = producers.get(add2_in0, None)
            if mul2_idx is None:
                mul2_idx = producers.get(add2_in1, None)
            if mul2_idx is None:
                continue
            mul2_op = model_ir.operators[int(mul2_idx)]
            if str(mul2_op.op_type) != "MUL" or len(mul2_op.inputs) != 2 or len(mul2_op.outputs) != 1:
                continue
            mul2_out_name = str(mul2_op.outputs[0])
            if mul2_out_name == add2_in0:
                add2_side_input_index = 1
                add2_side_name = add2_in1
            elif mul2_out_name == add2_in1:
                add2_side_input_index = 0
                add2_side_name = add2_in0
            else:
                continue

            mul2_in0 = str(mul2_op.inputs[0])
            mul2_in1 = str(mul2_op.inputs[1])
            if str(mul2_out_name) != str(prelu2_op.inputs[0]) and str(mul2_out_name) != str(add2_in0) and str(mul2_out_name) != str(add2_in1):
                continue
            if str(mul2_out_name) in model_outputs:
                continue

            if mul2_in0 == str(mul2_in1):
                continue
            if mul2_in0 in model_outputs or mul2_in1 in model_outputs:
                continue

            if mul2_in0 in producers and str(model_ir.operators[int(producers[mul2_in0])].op_type) == "CONCATENATION":
                concat2_data_name = str(mul2_in0)
                mul2_side_input_index = 1
                mul2_side_name = str(mul2_in1)
            elif mul2_in1 in producers and str(model_ir.operators[int(producers[mul2_in1])].op_type) == "CONCATENATION":
                concat2_data_name = str(mul2_in1)
                mul2_side_input_index = 0
                mul2_side_name = str(mul2_in0)
            else:
                continue

            concat2_idx = producers.get(concat2_data_name, None)
            if concat2_idx is None:
                continue
            concat2_op = model_ir.operators[int(concat2_idx)]
            if (
                str(concat2_op.op_type) != "CONCATENATION"
                or len(concat2_op.inputs) != 2
                or len(concat2_op.outputs) != 1
                or int(concat2_op.options.get("axis", 1)) != 1
                or str(concat2_op.outputs[0]) != concat2_data_name
            ):
                continue

            concat2_inputs = [str(v) for v in list(concat2_op.inputs)]
            pre13_idx: Optional[int] = None
            pre13_input_name: Optional[str] = None
            prelu1_out_name: Optional[str] = None
            for input_name in concat2_inputs:
                input_prod_idx = producers.get(str(input_name), None)
                if input_prod_idx is None:
                    continue
                input_prod_op = model_ir.operators[int(input_prod_idx)]
                if (
                    str(input_prod_op.op_type) == "TRANSPOSE"
                    and len(input_prod_op.inputs) >= 2
                    and len(input_prod_op.outputs) == 1
                    and str(input_prod_op.outputs[0]) == str(input_name)
                    and _read_transpose_perm(model_ir, input_prod_op) == perm_nhwc_to_nchw
                ):
                    pre13_idx = int(input_prod_idx)
                    pre13_input_name = str(input_prod_op.inputs[0])
                elif str(input_prod_op.op_type) == "PRELU":
                    prelu1_out_name = str(input_name)
            if pre13_idx is None or pre13_input_name is None or prelu1_out_name is None:
                continue

            prelu1_idx = producers.get(str(prelu1_out_name), None)
            if prelu1_idx is None:
                continue
            prelu1_op = model_ir.operators[int(prelu1_idx)]
            if (
                str(prelu1_op.op_type) != "PRELU"
                or len(prelu1_op.inputs) != 2
                or len(prelu1_op.outputs) != 1
                or str(prelu1_op.outputs[0]) != str(prelu1_out_name)
            ):
                continue
            if str(prelu1_out_name) in model_outputs:
                continue

            prelu1_users = [int(v) for v in consumers.get(str(prelu1_out_name), []) if int(v) != int(prelu1_idx)]
            if len(prelu1_users) != 2 or int(concat2_idx) not in prelu1_users:
                continue
            post1_idx = None
            for u in prelu1_users:
                if int(u) == int(concat2_idx):
                    continue
                u_op = model_ir.operators[int(u)]
                if (
                    str(u_op.op_type) == "TRANSPOSE"
                    and len(u_op.inputs) >= 2
                    and len(u_op.outputs) == 1
                    and str(u_op.inputs[0]) == str(prelu1_out_name)
                    and _read_transpose_perm(model_ir, u_op) == perm_nchw_to_nhwc
                    and str(u_op.outputs[0]) not in model_outputs
                ):
                    post1_idx = int(u)
            if post1_idx is None:
                continue
            post1_op = model_ir.operators[int(post1_idx)]
            post1_output_name = str(post1_op.outputs[0])

            add1_idx = producers.get(str(prelu1_op.inputs[0]), None)
            if add1_idx is None:
                continue
            add1_op = model_ir.operators[int(add1_idx)]
            if str(add1_op.op_type) != "ADD" or len(add1_op.inputs) != 2 or len(add1_op.outputs) != 1:
                continue
            add1_in0 = str(add1_op.inputs[0])
            add1_in1 = str(add1_op.inputs[1])

            mul1_idx = producers.get(add1_in0, None)
            if mul1_idx is None:
                mul1_idx = producers.get(add1_in1, None)
            if mul1_idx is None:
                continue
            mul1_op = model_ir.operators[int(mul1_idx)]
            if str(mul1_op.op_type) != "MUL" or len(mul1_op.inputs) != 2 or len(mul1_op.outputs) != 1:
                continue
            mul1_out_name = str(mul1_op.outputs[0])
            if mul1_out_name == add1_in0:
                add1_side_input_index = 1
                add1_side_name = add1_in1
            elif mul1_out_name == add1_in1:
                add1_side_input_index = 0
                add1_side_name = add1_in0
            else:
                continue

            mul1_in0 = str(mul1_op.inputs[0])
            mul1_in1 = str(mul1_op.inputs[1])
            add0_out_name: Optional[str] = None
            mul1_side_input_index: Optional[int] = None
            mul1_side_name: Optional[str] = None
            for data_idx, side_idx in [(0, 1), (1, 0)]:
                cand_data = str(mul1_op.inputs[int(data_idx)])
                cand_side = str(mul1_op.inputs[int(side_idx)])
                cand_prod_idx = producers.get(cand_data, None)
                if cand_prod_idx is not None:
                    cand_prod_op = model_ir.operators[int(cand_prod_idx)]
                    if str(cand_prod_op.op_type) == "ADD":
                        add0_out_name = str(cand_data)
                        mul1_side_input_index = int(side_idx)
                        mul1_side_name = str(cand_side)
                        break
            if add0_out_name is None or mul1_side_input_index is None or mul1_side_name is None:
                continue

            add0_idx = producers.get(str(add0_out_name), None)
            if add0_idx is None:
                continue
            add0_op = model_ir.operators[int(add0_idx)]
            if str(add0_op.op_type) != "ADD" or len(add0_op.inputs) != 2 or len(add0_op.outputs) != 1:
                continue
            if str(add0_op.outputs[0]) != str(add0_out_name):
                continue

            pre_add_indices: List[int] = []
            pre_add_inputs_nhwc: List[str] = []
            pre_add_out_names = [str(v) for v in list(add0_op.inputs)]
            valid_pre_add = True
            for pre_add_out in pre_add_out_names:
                pre_add_idx = producers.get(str(pre_add_out), None)
                if pre_add_idx is None:
                    valid_pre_add = False
                    break
                pre_add_op = model_ir.operators[int(pre_add_idx)]
                if (
                    str(pre_add_op.op_type) != "TRANSPOSE"
                    or len(pre_add_op.inputs) < 2
                    or len(pre_add_op.outputs) != 1
                    or str(pre_add_op.outputs[0]) != str(pre_add_out)
                    or _read_transpose_perm(model_ir, pre_add_op) != perm_nhwc_to_nchw
                ):
                    valid_pre_add = False
                    break
                if set(int(v) for v in consumers.get(str(pre_add_out), [])) != {int(add0_idx)}:
                    valid_pre_add = False
                    break
                pre_add_indices.append(int(pre_add_idx))
                pre_add_inputs_nhwc.append(str(pre_add_op.inputs[0]))
            if not valid_pre_add or len(pre_add_indices) != 2:
                continue

            if set(int(v) for v in consumers.get(str(concat2_inputs[0]), [])) != {int(concat2_idx)} and set(
                int(v) for v in consumers.get(str(concat2_inputs[1]), [])
            ) != {int(concat2_idx)}:
                continue
            if set(int(v) for v in consumers.get(str(pre13_input_name if pre13_input_name else ""), [])):
                pass
            if set(int(v) for v in consumers.get(str(model_ir.operators[int(pre13_idx)].outputs[0]), [])) != {int(concat2_idx)}:
                continue

            chain_index_set = {
                int(add0_idx),
                int(mul1_idx),
                int(add1_idx),
                int(prelu1_idx),
                int(concat2_idx),
                int(mul2_idx),
                int(add2_idx),
                int(prelu2_idx),
                int(pre13_idx),
                int(post1_idx),
                int(post2_idx),
                int(pre_add_indices[0]),
                int(pre_add_indices[1]),
            }
            mul1_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mul1_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            add1_side_for_op = _ensure_channel_last_const(
                tensor_name=str(add1_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            prelu1_side_for_op = _ensure_channel_last_const(
                tensor_name=str(prelu1_op.inputs[1]),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            mul2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mul2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            add2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(add2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            prelu2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(prelu2_op.inputs[1]),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            if any(
                v is None
                for v in [
                    mul1_side_for_op,
                    add1_side_for_op,
                    prelu1_side_for_op,
                    mul2_side_for_op,
                    add2_side_for_op,
                    prelu2_side_for_op,
                ]
            ):
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=add0_op,
                new_inputs=[str(pre_add_inputs_nhwc[0]), str(pre_add_inputs_nhwc[1])],
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul1_op,
                input_index=int(mul1_side_input_index),
                new_input_name=str(mul1_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add1_op,
                input_index=int(add1_side_input_index),
                new_input_name=str(add1_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=prelu1_op,
                input_index=1,
                new_input_name=str(prelu1_side_for_op),
            )

            _set_operator_outputs(
                model_ir=model_ir,
                op=prelu1_op,
                new_outputs=[str(post1_output_name)],
            )

            new_concat_inputs = []
            for inp in concat2_inputs:
                if str(inp) == str(model_ir.operators[int(pre13_idx)].outputs[0]):
                    new_concat_inputs.append(str(pre13_input_name))
                elif str(inp) == str(prelu1_out_name):
                    new_concat_inputs.append(str(post1_output_name))
                else:
                    new_concat_inputs.append(str(inp))
            _set_operator_inputs(
                model_ir=model_ir,
                op=concat2_op,
                new_inputs=[str(v) for v in new_concat_inputs],
            )
            concat2_op.options["axis"] = 3

            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul2_op,
                input_index=int(mul2_side_input_index),
                new_input_name=str(mul2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add2_op,
                input_index=int(add2_side_input_index),
                new_input_name=str(add2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=prelu2_op,
                input_index=1,
                new_input_name=str(prelu2_side_for_op),
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=prelu2_op,
                new_outputs=[str(post2_output_name)],
            )

            for t_name in [add0_out_name, mul1_out_name, str(add1_op.outputs[0]), str(post1_output_name)]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(t_name), None),
                    perm_nchw_to_nhwc,
                )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(concat2_data_name), None),
                perm_nchw_to_nhwc,
            )
            for t_name in [mul2_out_name, add2_out_name, str(post2_output_name)]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(t_name), None),
                    perm_nchw_to_nhwc,
                )

            remove_indices = set([int(post1_idx), int(post2_idx), int(pre13_idx)])
            remove_indices.update(set(int(v) for v in pre_add_indices))
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_sinet_shuffle_residual_transpose_chains": int(optimized)}


def _optimize_sinet_concat_resize_affine_transpose_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Optimize strict SiNet branch merge blocks with three NHWC->NCHW adapters:

      pre_nhwc --T(0,3,1,2)--> pre_nchw
      branch0_nhwc --T(0,3,1,2)--> b0_nchw
      resize_nhwc --T(0,3,1,2)--> rz_nchw --MUL(const)--ADD(const)--> b1_nchw
      CONCAT(axis=1, [b0_nchw, b1_nchw]) -> c_nchw
      ADD(pre_nchw, c_nchw) -> a_nchw --MUL(const)--ADD(const)--PRELU--> p_nchw
      p_nchw --T(0,2,3,1)--> p_nhwc

    Rewrite to NHWC core and remove the four transpose adapters.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _ensure_channel_last_const(
        *,
        tensor_name: str,
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> Optional[str]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.data is None:
            return None
        data = np.asarray(tensor.data)
        if int(data.size) == 1:
            return str(tensor_name)
        if data.ndim != 4:
            return None
        shape = [int(v) for v in list(data.shape)]
        if (
            int(shape[0]) == 1
            and int(shape[1]) == 1
            and int(shape[2]) == 1
            and int(shape[3]) > 0
        ):
            nhwc_data = np.asarray(data)
        elif (
            int(shape[0]) == 1
            and int(shape[1]) > 0
            and int(shape[2]) == 1
            and int(shape[3]) == 1
        ):
            nhwc_data = np.transpose(data, perm_nchw_to_nhwc).astype(data.dtype, copy=False)
        else:
            return None

        side_users = [int(v) for v in consumers.get(str(tensor_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)
        if shared_outside_chain:
            cloned_name = _unique_tensor_name(f"{tensor_name}_nhwc")
            model_ir.tensors[cloned_name] = TensorIR(
                name=cloned_name,
                dtype=str(tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(tensor.quantization),
            )
            return str(cloned_name)

        tensor.data = np.asarray(nhwc_data)
        tensor.shape = [int(v) for v in list(nhwc_data.shape)]
        tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]
        return str(tensor_name)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if (
                str(pre_op.op_type) != "TRANSPOSE"
                or len(pre_op.inputs) < 2
                or len(pre_op.outputs) != 1
                or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
            ):
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_output_name in model_outputs:
                continue
            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) != 1:
                continue

            add0_idx = int(pre_users[0])
            add0_op = model_ir.operators[int(add0_idx)]
            if str(add0_op.op_type) != "ADD" or len(add0_op.inputs) != 2 or len(add0_op.outputs) != 1:
                continue
            add0_inputs = [str(v) for v in list(add0_op.inputs)]
            if add0_inputs[0] == pre_output_name:
                concat_name = str(add0_inputs[1])
            elif add0_inputs[1] == pre_output_name:
                concat_name = str(add0_inputs[0])
            else:
                continue
            add0_out_name = str(add0_op.outputs[0])
            if add0_out_name in model_outputs:
                continue

            concat_idx = producers.get(concat_name, None)
            if concat_idx is None:
                continue
            concat_op = model_ir.operators[int(concat_idx)]
            if (
                str(concat_op.op_type) != "CONCATENATION"
                or len(concat_op.inputs) != 2
                or len(concat_op.outputs) != 1
                or str(concat_op.outputs[0]) != concat_name
                or int(concat_op.options.get("axis", 1)) != 1
            ):
                continue
            if set(int(v) for v in consumers.get(concat_name, [])) != {int(add0_idx)}:
                continue

            trans_a_idx: Optional[int] = None
            trans_a_in_name: Optional[str] = None
            trans_a_out_name: Optional[str] = None
            addb_idx: Optional[int] = None
            addb_out_name: Optional[str] = None
            for c_in in [str(v) for v in list(concat_op.inputs)]:
                c_prod_idx = producers.get(str(c_in), None)
                if c_prod_idx is None:
                    continue
                c_prod_op = model_ir.operators[int(c_prod_idx)]
                if (
                    str(c_prod_op.op_type) == "TRANSPOSE"
                    and len(c_prod_op.inputs) >= 2
                    and len(c_prod_op.outputs) == 1
                    and str(c_prod_op.outputs[0]) == str(c_in)
                    and _read_transpose_perm(model_ir, c_prod_op) == perm_nhwc_to_nchw
                    and set(int(v) for v in consumers.get(str(c_in), [])) == {int(concat_idx)}
                    and str(c_in) not in model_outputs
                ):
                    trans_a_idx = int(c_prod_idx)
                    trans_a_in_name = str(c_prod_op.inputs[0])
                    trans_a_out_name = str(c_in)
                elif (
                    str(c_prod_op.op_type) == "ADD"
                    and len(c_prod_op.inputs) == 2
                    and len(c_prod_op.outputs) == 1
                    and str(c_prod_op.outputs[0]) == str(c_in)
                    and set(int(v) for v in consumers.get(str(c_in), [])) == {int(concat_idx)}
                    and str(c_in) not in model_outputs
                ):
                    addb_idx = int(c_prod_idx)
                    addb_out_name = str(c_in)
            if (
                trans_a_idx is None
                or trans_a_in_name is None
                or trans_a_out_name is None
                or addb_idx is None
                or addb_out_name is None
            ):
                continue

            addb_op = model_ir.operators[int(addb_idx)]
            addb_in0 = str(addb_op.inputs[0])
            addb_in1 = str(addb_op.inputs[1])
            mulb_idx = producers.get(addb_in0, None)
            if mulb_idx is None:
                mulb_idx = producers.get(addb_in1, None)
            if mulb_idx is None:
                continue
            mulb_op = model_ir.operators[int(mulb_idx)]
            if str(mulb_op.op_type) != "MUL" or len(mulb_op.inputs) != 2 or len(mulb_op.outputs) != 1:
                continue
            mulb_out_name = str(mulb_op.outputs[0])
            if mulb_out_name == addb_in0:
                addb_side_index = 1
                addb_side_name = str(addb_in1)
            elif mulb_out_name == addb_in1:
                addb_side_index = 0
                addb_side_name = str(addb_in0)
            else:
                continue

            mulb_inputs = [str(v) for v in list(mulb_op.inputs)]
            if mulb_inputs[0] == mulb_inputs[1]:
                continue
            trans_b_idx: Optional[int] = None
            trans_b_in_name: Optional[str] = None
            mulb_data_index: Optional[int] = None
            mulb_side_name: Optional[str] = None
            for data_idx, side_idx in [(0, 1), (1, 0)]:
                trans_idx = producers.get(str(mulb_inputs[int(data_idx)]), None)
                if trans_idx is None:
                    continue
                trans_op = model_ir.operators[int(trans_idx)]
                if (
                    str(trans_op.op_type) != "TRANSPOSE"
                    or len(trans_op.inputs) < 2
                    or len(trans_op.outputs) != 1
                    or str(trans_op.outputs[0]) != str(mulb_inputs[int(data_idx)])
                    or _read_transpose_perm(model_ir, trans_op) != perm_nhwc_to_nchw
                    or set(int(v) for v in consumers.get(str(mulb_inputs[int(data_idx)]), [])) != {int(mulb_idx)}
                    or str(mulb_inputs[int(data_idx)]) in model_outputs
                ):
                    continue
                trans_b_idx = int(trans_idx)
                trans_b_in_name = str(trans_op.inputs[0])
                mulb_data_index = int(data_idx)
                mulb_side_name = str(mulb_inputs[int(side_idx)])
                break
            if trans_b_idx is None or trans_b_in_name is None or mulb_data_index is None or mulb_side_name is None:
                continue

            add0_users = [int(v) for v in consumers.get(str(add0_out_name), [])]
            if len(add0_users) != 1:
                continue
            mul2_idx = int(add0_users[0])
            mul2_op = model_ir.operators[int(mul2_idx)]
            if str(mul2_op.op_type) != "MUL" or len(mul2_op.inputs) != 2 or len(mul2_op.outputs) != 1:
                continue
            mul2_in0 = str(mul2_op.inputs[0])
            mul2_in1 = str(mul2_op.inputs[1])
            if mul2_in0 == add0_out_name:
                mul2_side_index = 1
                mul2_side_name = str(mul2_in1)
            elif mul2_in1 == add0_out_name:
                mul2_side_index = 0
                mul2_side_name = str(mul2_in0)
            else:
                continue
            mul2_out_name = str(mul2_op.outputs[0])
            if mul2_out_name in model_outputs:
                continue

            mul2_users = [int(v) for v in consumers.get(str(mul2_out_name), [])]
            if len(mul2_users) != 1:
                continue
            add2_idx = int(mul2_users[0])
            add2_op = model_ir.operators[int(add2_idx)]
            if str(add2_op.op_type) != "ADD" or len(add2_op.inputs) != 2 or len(add2_op.outputs) != 1:
                continue
            add2_in0 = str(add2_op.inputs[0])
            add2_in1 = str(add2_op.inputs[1])
            if add2_in0 == mul2_out_name:
                add2_side_index = 1
                add2_side_name = str(add2_in1)
            elif add2_in1 == mul2_out_name:
                add2_side_index = 0
                add2_side_name = str(add2_in0)
            else:
                continue
            add2_out_name = str(add2_op.outputs[0])
            if add2_out_name in model_outputs:
                continue

            add2_users = [int(v) for v in consumers.get(str(add2_out_name), [])]
            if len(add2_users) != 1:
                continue
            prelu2_idx = int(add2_users[0])
            prelu2_op = model_ir.operators[int(prelu2_idx)]
            if (
                str(prelu2_op.op_type) != "PRELU"
                or len(prelu2_op.inputs) != 2
                or len(prelu2_op.outputs) != 1
                or str(prelu2_op.inputs[0]) != str(add2_out_name)
            ):
                continue
            prelu2_out_name = str(prelu2_op.outputs[0])
            if prelu2_out_name in model_outputs:
                continue

            prelu2_users = [int(v) for v in consumers.get(str(prelu2_out_name), [])]
            if len(prelu2_users) == 0:
                continue
            post_indices: List[int] = []
            post_output_names: List[str] = []
            legacy_users: List[int] = []
            for u_idx in prelu2_users:
                u_op = model_ir.operators[int(u_idx)]
                if (
                    str(u_op.op_type) == "TRANSPOSE"
                    and len(u_op.inputs) >= 2
                    and len(u_op.outputs) == 1
                    and str(u_op.inputs[0]) == str(prelu2_out_name)
                    and _read_transpose_perm(model_ir, u_op) == perm_nchw_to_nhwc
                    and str(u_op.outputs[0]) not in model_outputs
                ):
                    post_indices.append(int(u_idx))
                    post_output_names.append(str(u_op.outputs[0]))
                else:
                    legacy_users.append(int(u_idx))
            if len(post_indices) == 0:
                continue
            post_out_name = str(post_output_names[0])

            chain_index_set = {
                int(pre_idx),
                int(trans_a_idx),
                int(trans_b_idx),
                int(addb_idx),
                int(mulb_idx),
                int(concat_idx),
                int(add0_idx),
                int(mul2_idx),
                int(add2_idx),
                int(prelu2_idx),
                *[int(v) for v in list(post_indices)],
            }
            mulb_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mulb_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            addb_side_for_op = _ensure_channel_last_const(
                tensor_name=str(addb_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            mul2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mul2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            add2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(add2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            prelu2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(prelu2_op.inputs[1]),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            if any(
                v is None
                for v in [
                    mulb_side_for_op,
                    addb_side_for_op,
                    mul2_side_for_op,
                    add2_side_for_op,
                    prelu2_side_for_op,
                ]
            ):
                continue

            _replace_operator_input_at(
                model_ir=model_ir,
                op=mulb_op,
                input_index=int(mulb_data_index),
                new_input_name=str(trans_b_in_name),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=mulb_op,
                input_index=int(1 - int(mulb_data_index)),
                new_input_name=str(mulb_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=addb_op,
                input_index=int(addb_side_index),
                new_input_name=str(addb_side_for_op),
            )

            new_concat_inputs = [
                str(trans_a_in_name) if str(v) == str(trans_a_out_name) else str(v)
                for v in list(concat_op.inputs)
            ]
            _set_operator_inputs(
                model_ir=model_ir,
                op=concat_op,
                new_inputs=[str(v) for v in new_concat_inputs],
            )
            concat_op.options["axis"] = 3

            new_add0_inputs = [str(v) for v in add0_inputs]
            if new_add0_inputs[0] == str(pre_output_name):
                new_add0_inputs[0] = str(pre_input_name)
            elif new_add0_inputs[1] == str(pre_output_name):
                new_add0_inputs[1] = str(pre_input_name)
            _set_operator_inputs(
                model_ir=model_ir,
                op=add0_op,
                new_inputs=[str(v) for v in new_add0_inputs],
            )

            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul2_op,
                input_index=int(mul2_side_index),
                new_input_name=str(mul2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add2_op,
                input_index=int(add2_side_index),
                new_input_name=str(add2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=prelu2_op,
                input_index=1,
                new_input_name=str(prelu2_side_for_op),
            )

            _set_operator_outputs(
                model_ir=model_ir,
                op=prelu2_op,
                new_outputs=[str(post_out_name)],
            )
            for alias_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, str(alias_name), str(post_out_name))

            for t_name in [
                str(mulb_out_name),
                str(addb_out_name),
                str(concat_name),
                str(add0_out_name),
                str(mul2_out_name),
                str(add2_out_name),
                str(post_out_name),
            ]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(t_name), None),
                    perm_nchw_to_nhwc,
                )

            old_prelu2_tensor = model_ir.tensors.get(str(prelu2_out_name), None)
            post_tensor = model_ir.tensors.get(str(post_out_name), None)
            if old_prelu2_tensor is not None and post_tensor is not None:
                post_tensor.dtype = str(old_prelu2_tensor.dtype)
                post_tensor.quantization = _clone_quantization(old_prelu2_tensor.quantization)
                post_tensor.shape = [int(v) for v in list(old_prelu2_tensor.shape)]
                post_tensor.shape_signature = (
                    [int(v) for v in list(old_prelu2_tensor.shape_signature)]
                    if old_prelu2_tensor.shape_signature is not None
                    else [int(v) for v in list(old_prelu2_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    post_tensor,
                    perm_nchw_to_nhwc,
                )

            if len(legacy_users) > 0:
                # Preserve NCHW legacy fan-out from the rewritten NHWC output.
                adapter_op = OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[str(post_out_name), str(pre_op.inputs[1])],
                    outputs=[str(prelu2_out_name)],
                    options={},
                )
                op_index_by_id = {int(id(op)): int(op_idx) for op_idx, op in enumerate(model_ir.operators)}
                live_legacy_indices = [
                    int(op_index_by_id[int(id(model_ir.operators[int(v)]))])
                    for v in legacy_users
                    if int(v) < len(model_ir.operators)
                ]
                insert_index = int(min(live_legacy_indices)) if len(live_legacy_indices) > 0 else int(len(model_ir.operators))
                model_ir.operators.insert(int(insert_index), adapter_op)

            remove_indices = {
                int(pre_idx),
                int(trans_a_idx),
                int(trans_b_idx),
                *[int(v) for v in list(post_indices)],
            }
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_sinet_concat_resize_affine_transpose_chains": int(optimized)}


def _optimize_sinet_dual_resize_affine_transpose_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Optimize strict SiNet branch-merge blocks where BOTH concat branches are:
      RESIZE -> TRANSPOSE(NHWC->NCHW) -> MUL(const) -> ADD(const)

    Target:
      pre_nhwc --T(0,3,1,2)--> pre_nchw
      b0_nhwc --Resize--> r0_nhwc --T(0,3,1,2)--> r0_nchw --MUL(c0)--ADD(c1)--> b0_nchw
      b1_nhwc --Resize--> r1_nhwc --T(0,3,1,2)--> r1_nchw --MUL(c2)--ADD(c3)--> b1_nchw
      CONCAT(axis=1, [b0_nchw, b1_nchw]) -> c_nchw
      ADD(pre_nchw, c_nchw) -> a_nchw --MUL(const)--ADD(const)--PRELU--> p_nchw
      p_nchw --T(0,2,3,1)--> p_nhwc

    Rewrite to NHWC core and remove the four transpose adapters.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _ensure_channel_last_const(
        *,
        tensor_name: str,
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> Optional[str]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.data is None:
            return None
        data = np.asarray(tensor.data)
        if int(data.size) == 1:
            return str(tensor_name)
        if data.ndim != 4:
            return None
        shape = [int(v) for v in list(data.shape)]
        if (
            int(shape[0]) == 1
            and int(shape[1]) == 1
            and int(shape[2]) == 1
            and int(shape[3]) > 0
        ):
            nhwc_data = np.asarray(data)
        elif (
            int(shape[0]) == 1
            and int(shape[1]) > 0
            and int(shape[2]) == 1
            and int(shape[3]) == 1
        ):
            nhwc_data = np.transpose(data, perm_nchw_to_nhwc).astype(data.dtype, copy=False)
        else:
            return None

        side_users = [int(v) for v in consumers.get(str(tensor_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)
        if shared_outside_chain:
            cloned_name = _unique_tensor_name(f"{tensor_name}_nhwc")
            model_ir.tensors[cloned_name] = TensorIR(
                name=cloned_name,
                dtype=str(tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(tensor.quantization),
            )
            return str(cloned_name)

        tensor.data = np.asarray(nhwc_data)
        tensor.shape = [int(v) for v in list(nhwc_data.shape)]
        tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]
        return str(tensor_name)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if (
                str(pre_op.op_type) != "TRANSPOSE"
                or len(pre_op.inputs) < 2
                or len(pre_op.outputs) != 1
                or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
            ):
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_output_name in model_outputs:
                continue
            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) != 1:
                continue

            add0_idx = int(pre_users[0])
            add0_op = model_ir.operators[int(add0_idx)]
            if str(add0_op.op_type) != "ADD" or len(add0_op.inputs) != 2 or len(add0_op.outputs) != 1:
                continue
            add0_inputs = [str(v) for v in list(add0_op.inputs)]
            if add0_inputs[0] == pre_output_name:
                concat_name = str(add0_inputs[1])
            elif add0_inputs[1] == pre_output_name:
                concat_name = str(add0_inputs[0])
            else:
                continue
            add0_out_name = str(add0_op.outputs[0])
            if add0_out_name in model_outputs:
                continue

            concat_idx = producers.get(concat_name, None)
            if concat_idx is None:
                continue
            concat_op = model_ir.operators[int(concat_idx)]
            if (
                str(concat_op.op_type) != "CONCATENATION"
                or len(concat_op.inputs) != 2
                or len(concat_op.outputs) != 1
                or str(concat_op.outputs[0]) != concat_name
                or int(concat_op.options.get("axis", 1)) != 1
            ):
                continue
            if set(int(v) for v in consumers.get(concat_name, [])) != {int(add0_idx)}:
                continue

            branch_plans: List[Dict[str, Any]] = []

            def _match_resize_affine_branch(add_out_name: str) -> Optional[Dict[str, Any]]:
                add_idx = producers.get(str(add_out_name), None)
                if add_idx is None:
                    return None
                add_op = model_ir.operators[int(add_idx)]
                if (
                    str(add_op.op_type) != "ADD"
                    or len(add_op.inputs) != 2
                    or len(add_op.outputs) != 1
                    or str(add_op.outputs[0]) != str(add_out_name)
                ):
                    return None
                if set(int(v) for v in consumers.get(str(add_out_name), [])) != {int(concat_idx)}:
                    return None

                add_in0 = str(add_op.inputs[0])
                add_in1 = str(add_op.inputs[1])
                mul_idx = producers.get(add_in0, None)
                if mul_idx is None:
                    mul_idx = producers.get(add_in1, None)
                if mul_idx is None:
                    return None
                mul_op = model_ir.operators[int(mul_idx)]
                if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                    return None

                mul_out_name = str(mul_op.outputs[0])
                if mul_out_name == add_in0:
                    add_side_index = 1
                    add_side_name = str(add_in1)
                elif mul_out_name == add_in1:
                    add_side_index = 0
                    add_side_name = str(add_in0)
                else:
                    return None

                mul_inputs = [str(v) for v in list(mul_op.inputs)]
                if mul_inputs[0] == mul_inputs[1]:
                    return None

                trans_idx: Optional[int] = None
                trans_in_name: Optional[str] = None
                mul_data_index: Optional[int] = None
                mul_side_name: Optional[str] = None

                for data_idx, side_idx in [(0, 1), (1, 0)]:
                    candidate_trans_idx = producers.get(str(mul_inputs[int(data_idx)]), None)
                    if candidate_trans_idx is None:
                        continue
                    candidate_trans_op = model_ir.operators[int(candidate_trans_idx)]
                    if (
                        str(candidate_trans_op.op_type) != "TRANSPOSE"
                        or len(candidate_trans_op.inputs) < 2
                        or len(candidate_trans_op.outputs) != 1
                        or str(candidate_trans_op.outputs[0]) != str(mul_inputs[int(data_idx)])
                        or _read_transpose_perm(model_ir, candidate_trans_op) != perm_nhwc_to_nchw
                        or set(int(v) for v in consumers.get(str(mul_inputs[int(data_idx)]), []))
                        != {int(mul_idx)}
                        or str(mul_inputs[int(data_idx)]) in model_outputs
                    ):
                        continue
                    candidate_resize_out_name = str(candidate_trans_op.inputs[0])
                    resize_idx = producers.get(candidate_resize_out_name, None)
                    if resize_idx is None:
                        continue
                    resize_op = model_ir.operators[int(resize_idx)]
                    if str(resize_op.op_type) not in {"RESIZE_BILINEAR", "RESIZE_NEAREST_NEIGHBOR"}:
                        continue
                    if len(resize_op.outputs) != 1 or str(resize_op.outputs[0]) != candidate_resize_out_name:
                        continue
                    trans_idx = int(candidate_trans_idx)
                    trans_in_name = candidate_resize_out_name
                    mul_data_index = int(data_idx)
                    mul_side_name = str(mul_inputs[int(side_idx)])
                    break

                if trans_idx is None or trans_in_name is None or mul_data_index is None or mul_side_name is None:
                    return None

                return {
                    "add_idx": int(add_idx),
                    "add_op": add_op,
                    "add_out_name": str(add_out_name),
                    "add_side_index": int(add_side_index),
                    "add_side_name": str(add_side_name),
                    "mul_idx": int(mul_idx),
                    "mul_op": mul_op,
                    "mul_out_name": str(mul_out_name),
                    "mul_data_index": int(mul_data_index),
                    "mul_side_name": str(mul_side_name),
                    "trans_idx": int(trans_idx),
                    "trans_in_name": str(trans_in_name),
                }

            valid_branches = True
            for concat_input_name in [str(v) for v in list(concat_op.inputs)]:
                plan = _match_resize_affine_branch(str(concat_input_name))
                if plan is None:
                    valid_branches = False
                    break
                branch_plans.append(plan)
            if not valid_branches or len(branch_plans) != 2:
                continue

            add0_users = [int(v) for v in consumers.get(str(add0_out_name), [])]
            if len(add0_users) != 1:
                continue
            mul2_idx = int(add0_users[0])
            mul2_op = model_ir.operators[int(mul2_idx)]
            if str(mul2_op.op_type) != "MUL" or len(mul2_op.inputs) != 2 or len(mul2_op.outputs) != 1:
                continue
            mul2_in0 = str(mul2_op.inputs[0])
            mul2_in1 = str(mul2_op.inputs[1])
            if mul2_in0 == add0_out_name:
                mul2_side_index = 1
                mul2_side_name = str(mul2_in1)
            elif mul2_in1 == add0_out_name:
                mul2_side_index = 0
                mul2_side_name = str(mul2_in0)
            else:
                continue
            mul2_out_name = str(mul2_op.outputs[0])
            if mul2_out_name in model_outputs:
                continue

            mul2_users = [int(v) for v in consumers.get(str(mul2_out_name), [])]
            if len(mul2_users) != 1:
                continue
            add2_idx = int(mul2_users[0])
            add2_op = model_ir.operators[int(add2_idx)]
            if str(add2_op.op_type) != "ADD" or len(add2_op.inputs) != 2 or len(add2_op.outputs) != 1:
                continue
            add2_in0 = str(add2_op.inputs[0])
            add2_in1 = str(add2_op.inputs[1])
            if add2_in0 == mul2_out_name:
                add2_side_index = 1
                add2_side_name = str(add2_in1)
            elif add2_in1 == mul2_out_name:
                add2_side_index = 0
                add2_side_name = str(add2_in0)
            else:
                continue
            add2_out_name = str(add2_op.outputs[0])
            if add2_out_name in model_outputs:
                continue

            add2_users = [int(v) for v in consumers.get(str(add2_out_name), [])]
            if len(add2_users) != 1:
                continue
            prelu2_idx = int(add2_users[0])
            prelu2_op = model_ir.operators[int(prelu2_idx)]
            if (
                str(prelu2_op.op_type) != "PRELU"
                or len(prelu2_op.inputs) != 2
                or len(prelu2_op.outputs) != 1
                or str(prelu2_op.inputs[0]) != str(add2_out_name)
            ):
                continue
            prelu2_out_name = str(prelu2_op.outputs[0])
            if prelu2_out_name in model_outputs:
                continue

            prelu2_users = [int(v) for v in consumers.get(str(prelu2_out_name), [])]
            if len(prelu2_users) == 0:
                continue
            post_indices: List[int] = []
            post_output_names: List[str] = []
            legacy_users: List[int] = []
            for u_idx in prelu2_users:
                u_op = model_ir.operators[int(u_idx)]
                if (
                    str(u_op.op_type) == "TRANSPOSE"
                    and len(u_op.inputs) >= 2
                    and len(u_op.outputs) == 1
                    and str(u_op.inputs[0]) == str(prelu2_out_name)
                    and _read_transpose_perm(model_ir, u_op) == perm_nchw_to_nhwc
                    and str(u_op.outputs[0]) not in model_outputs
                ):
                    post_indices.append(int(u_idx))
                    post_output_names.append(str(u_op.outputs[0]))
                else:
                    legacy_users.append(int(u_idx))
            if len(post_indices) == 0:
                continue
            post_out_name = str(post_output_names[0])

            chain_index_set = {
                int(pre_idx),
                int(concat_idx),
                int(add0_idx),
                int(mul2_idx),
                int(add2_idx),
                int(prelu2_idx),
                *[int(v) for v in list(post_indices)],
            }
            for plan in branch_plans:
                chain_index_set.add(int(plan["trans_idx"]))
                chain_index_set.add(int(plan["mul_idx"]))
                chain_index_set.add(int(plan["add_idx"]))

            branch_mul_side_names: List[str] = []
            branch_add_side_names: List[str] = []
            for plan in branch_plans:
                branch_mul_side = _ensure_channel_last_const(
                    tensor_name=str(plan["mul_side_name"]),
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                )
                branch_add_side = _ensure_channel_last_const(
                    tensor_name=str(plan["add_side_name"]),
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                )
                if branch_mul_side is None or branch_add_side is None:
                    branch_mul_side_names = []
                    branch_add_side_names = []
                    break
                branch_mul_side_names.append(str(branch_mul_side))
                branch_add_side_names.append(str(branch_add_side))
            if len(branch_mul_side_names) != 2 or len(branch_add_side_names) != 2:
                continue

            mul2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mul2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            add2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(add2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            prelu2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(prelu2_op.inputs[1]),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            if any(v is None for v in [mul2_side_for_op, add2_side_for_op, prelu2_side_for_op]):
                continue

            for plan, branch_mul_side, branch_add_side in zip(
                branch_plans,
                branch_mul_side_names,
                branch_add_side_names,
            ):
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=plan["mul_op"],
                    input_index=int(plan["mul_data_index"]),
                    new_input_name=str(plan["trans_in_name"]),
                )
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=plan["mul_op"],
                    input_index=int(1 - int(plan["mul_data_index"])),
                    new_input_name=str(branch_mul_side),
                )
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=plan["add_op"],
                    input_index=int(plan["add_side_index"]),
                    new_input_name=str(branch_add_side),
                )

            concat_op.options["axis"] = 3

            new_add0_inputs = [str(v) for v in add0_inputs]
            if new_add0_inputs[0] == str(pre_output_name):
                new_add0_inputs[0] = str(pre_input_name)
            elif new_add0_inputs[1] == str(pre_output_name):
                new_add0_inputs[1] = str(pre_input_name)
            _set_operator_inputs(
                model_ir=model_ir,
                op=add0_op,
                new_inputs=[str(v) for v in new_add0_inputs],
            )

            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul2_op,
                input_index=int(mul2_side_index),
                new_input_name=str(mul2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add2_op,
                input_index=int(add2_side_index),
                new_input_name=str(add2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=prelu2_op,
                input_index=1,
                new_input_name=str(prelu2_side_for_op),
            )

            _set_operator_outputs(
                model_ir=model_ir,
                op=prelu2_op,
                new_outputs=[str(post_out_name)],
            )
            for alias_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, str(alias_name), str(post_out_name))

            for plan in branch_plans:
                for t_name in [str(plan["mul_out_name"]), str(plan["add_out_name"])]:
                    _permute_tensor_metadata_if_rank_matches(
                        model_ir.tensors.get(str(t_name), None),
                        perm_nchw_to_nhwc,
                    )
            for t_name in [
                str(concat_name),
                str(add0_out_name),
                str(mul2_out_name),
                str(add2_out_name),
                str(post_out_name),
            ]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(t_name), None),
                    perm_nchw_to_nhwc,
                )

            old_prelu2_tensor = model_ir.tensors.get(str(prelu2_out_name), None)
            post_tensor = model_ir.tensors.get(str(post_out_name), None)
            if old_prelu2_tensor is not None and post_tensor is not None:
                post_tensor.dtype = str(old_prelu2_tensor.dtype)
                post_tensor.quantization = _clone_quantization(old_prelu2_tensor.quantization)
                post_tensor.shape = [int(v) for v in list(old_prelu2_tensor.shape)]
                post_tensor.shape_signature = (
                    [int(v) for v in list(old_prelu2_tensor.shape_signature)]
                    if old_prelu2_tensor.shape_signature is not None
                    else [int(v) for v in list(old_prelu2_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    post_tensor,
                    perm_nchw_to_nhwc,
                )

            if len(legacy_users) > 0:
                adapter_op = OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[str(post_out_name), str(pre_op.inputs[1])],
                    outputs=[str(prelu2_out_name)],
                    options={},
                )
                op_index_by_id = {int(id(op)): int(op_idx) for op_idx, op in enumerate(model_ir.operators)}
                live_legacy_indices = [
                    int(op_index_by_id[int(id(model_ir.operators[int(v)]))])
                    for v in legacy_users
                    if int(v) < len(model_ir.operators)
                ]
                insert_index = int(min(live_legacy_indices)) if len(live_legacy_indices) > 0 else int(len(model_ir.operators))
                model_ir.operators.insert(int(insert_index), adapter_op)

            remove_indices = {
                int(pre_idx),
                *[int(v) for v in list(post_indices)],
                *[int(plan["trans_idx"]) for plan in branch_plans],
            }
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_sinet_dual_resize_affine_transpose_chains": int(optimized)}


def _optimize_sinet_concat_resize_affine_tail_concat_transpose_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Optimize a late SiNet residual variant:

      skip_nhwc --T(0,3,1,2)--> skip_nchw
      pre_nhwc --T(0,3,1,2)--> pre_nchw
      b0_nhwc --T(0,3,1,2)--> b0_nchw
      rz_nhwc --T(0,3,1,2)--> rz_nchw --MUL(const)--ADD(const)--> b1_nchw
      CONCAT(axis=1,[b0_nchw,b1_nchw]) -> c1_nchw
      ADD(pre_nchw,c1_nchw)->MUL(const)->ADD(const)->PRELU -> p1_nchw
      CONCAT(axis=1,[skip_nchw,p1_nchw]) -> c2_nchw
      c2_nchw -> MUL(const) -> ADD(const) -> PRELU -> T(0,2,3,1)

    Rewrite the whole block to NHWC and remove redundant transpose bridges.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _ensure_channel_last_const(
        *,
        tensor_name: str,
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> Optional[str]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.data is None:
            return None
        data = np.asarray(tensor.data)
        if int(data.size) == 1:
            return str(tensor_name)
        if data.ndim != 4:
            return None
        shape = [int(v) for v in list(data.shape)]
        if (
            int(shape[0]) == 1
            and int(shape[1]) == 1
            and int(shape[2]) == 1
            and int(shape[3]) > 0
        ):
            nhwc_data = np.asarray(data)
        elif (
            int(shape[0]) == 1
            and int(shape[1]) > 0
            and int(shape[2]) == 1
            and int(shape[3]) == 1
        ):
            nhwc_data = np.transpose(data, perm_nchw_to_nhwc).astype(data.dtype, copy=False)
        else:
            return None

        side_users = [int(v) for v in consumers.get(str(tensor_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)
        if shared_outside_chain:
            cloned_name = _unique_tensor_name(f"{tensor_name}_nhwc")
            model_ir.tensors[cloned_name] = TensorIR(
                name=cloned_name,
                dtype=str(tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(tensor.quantization),
            )
            return str(cloned_name)

        tensor.data = np.asarray(nhwc_data)
        tensor.shape = [int(v) for v in list(nhwc_data.shape)]
        tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]
        return str(tensor_name)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for post2_idx, post2_op in enumerate(model_ir.operators):
            if (
                str(post2_op.op_type) != "TRANSPOSE"
                or len(post2_op.inputs) < 2
                or len(post2_op.outputs) != 1
                or _read_transpose_perm(model_ir, post2_op) != perm_nchw_to_nhwc
            ):
                continue
            post2_input_name = str(post2_op.inputs[0])
            post2_output_name = str(post2_op.outputs[0])
            if post2_output_name in model_outputs:
                continue

            prelu2_idx = producers.get(post2_input_name, None)
            if prelu2_idx is None:
                continue
            prelu2_op = model_ir.operators[int(prelu2_idx)]
            if (
                str(prelu2_op.op_type) != "PRELU"
                or len(prelu2_op.inputs) != 2
                or len(prelu2_op.outputs) != 1
                or str(prelu2_op.outputs[0]) != str(post2_input_name)
            ):
                continue

            add2_idx = producers.get(str(prelu2_op.inputs[0]), None)
            if add2_idx is None:
                continue
            add2_op = model_ir.operators[int(add2_idx)]
            if str(add2_op.op_type) != "ADD" or len(add2_op.inputs) != 2 or len(add2_op.outputs) != 1:
                continue
            add2_out_name = str(add2_op.outputs[0])
            if str(prelu2_op.inputs[0]) != str(add2_out_name):
                continue

            add2_in0 = str(add2_op.inputs[0])
            add2_in1 = str(add2_op.inputs[1])
            if add2_in0 == add2_in1:
                continue
            if add2_out_name in model_outputs:
                continue

            mul2_idx = producers.get(add2_in0, None)
            if mul2_idx is None:
                mul2_idx = producers.get(add2_in1, None)
            if mul2_idx is None:
                continue
            mul2_op = model_ir.operators[int(mul2_idx)]
            if str(mul2_op.op_type) != "MUL" or len(mul2_op.inputs) != 2 or len(mul2_op.outputs) != 1:
                continue
            mul2_out_name = str(mul2_op.outputs[0])
            if mul2_out_name == add2_in0:
                add2_side_index = 1
                add2_side_name = str(add2_in1)
            elif mul2_out_name == add2_in1:
                add2_side_index = 0
                add2_side_name = str(add2_in0)
            else:
                continue

            mul2_in0 = str(mul2_op.inputs[0])
            mul2_in1 = str(mul2_op.inputs[1])
            if mul2_in0 == mul2_in1:
                continue
            if mul2_out_name in model_outputs:
                continue

            if mul2_in0 in producers and str(model_ir.operators[int(producers[mul2_in0])].op_type) == "CONCATENATION":
                concat2_name = str(mul2_in0)
                mul2_side_index = 1
                mul2_side_name = str(mul2_in1)
            elif mul2_in1 in producers and str(model_ir.operators[int(producers[mul2_in1])].op_type) == "CONCATENATION":
                concat2_name = str(mul2_in1)
                mul2_side_index = 0
                mul2_side_name = str(mul2_in0)
            else:
                continue

            concat2_idx = producers.get(concat2_name, None)
            if concat2_idx is None:
                continue
            concat2_op = model_ir.operators[int(concat2_idx)]
            if (
                str(concat2_op.op_type) != "CONCATENATION"
                or len(concat2_op.inputs) != 2
                or len(concat2_op.outputs) != 1
                or str(concat2_op.outputs[0]) != str(concat2_name)
                or int(concat2_op.options.get("axis", 1)) != 1
            ):
                continue
            if set(int(v) for v in consumers.get(str(concat2_name), [])) != {int(mul2_idx)}:
                continue

            pre13_idx: Optional[int] = None
            pre13_in_name: Optional[str] = None
            pre13_out_name: Optional[str] = None
            prelu1_idx: Optional[int] = None
            prelu1_out_name: Optional[str] = None
            for c_in in [str(v) for v in list(concat2_op.inputs)]:
                prod_idx = producers.get(str(c_in), None)
                if prod_idx is None:
                    continue
                prod_op = model_ir.operators[int(prod_idx)]
                if (
                    str(prod_op.op_type) == "TRANSPOSE"
                    and len(prod_op.inputs) >= 2
                    and len(prod_op.outputs) == 1
                    and str(prod_op.outputs[0]) == str(c_in)
                    and _read_transpose_perm(model_ir, prod_op) == perm_nhwc_to_nchw
                    and set(int(v) for v in consumers.get(str(c_in), [])) == {int(concat2_idx)}
                    and str(c_in) not in model_outputs
                ):
                    pre13_idx = int(prod_idx)
                    pre13_in_name = str(prod_op.inputs[0])
                    pre13_out_name = str(c_in)
                elif str(prod_op.op_type) == "PRELU":
                    prelu1_idx = int(prod_idx)
                    prelu1_out_name = str(c_in)
            if (
                pre13_idx is None
                or pre13_in_name is None
                or pre13_out_name is None
                or prelu1_idx is None
                or prelu1_out_name is None
            ):
                continue

            prelu1_op = model_ir.operators[int(prelu1_idx)]
            if (
                str(prelu1_op.op_type) != "PRELU"
                or len(prelu1_op.inputs) != 2
                or len(prelu1_op.outputs) != 1
                or str(prelu1_op.outputs[0]) != str(prelu1_out_name)
                or str(prelu1_out_name) in model_outputs
            ):
                continue
            # strict variant: prelu1 only feeds concat2
            if set(int(v) for v in consumers.get(str(prelu1_out_name), [])) != {int(concat2_idx)}:
                continue

            add1_idx = producers.get(str(prelu1_op.inputs[0]), None)
            if add1_idx is None:
                continue
            add1_op = model_ir.operators[int(add1_idx)]
            if str(add1_op.op_type) != "ADD" or len(add1_op.inputs) != 2 or len(add1_op.outputs) != 1:
                continue
            add1_out_name = str(add1_op.outputs[0])
            if str(prelu1_op.inputs[0]) != str(add1_out_name):
                continue
            add1_in0 = str(add1_op.inputs[0])
            add1_in1 = str(add1_op.inputs[1])

            mul1_idx = producers.get(add1_in0, None)
            if mul1_idx is None:
                mul1_idx = producers.get(add1_in1, None)
            if mul1_idx is None:
                continue
            mul1_op = model_ir.operators[int(mul1_idx)]
            if str(mul1_op.op_type) != "MUL" or len(mul1_op.inputs) != 2 or len(mul1_op.outputs) != 1:
                continue
            mul1_out_name = str(mul1_op.outputs[0])
            if mul1_out_name == add1_in0:
                add1_side_index = 1
                add1_side_name = str(add1_in1)
            elif mul1_out_name == add1_in1:
                add1_side_index = 0
                add1_side_name = str(add1_in0)
            else:
                continue

            add0_name: Optional[str] = None
            mul1_side_index: Optional[int] = None
            mul1_side_name: Optional[str] = None
            for data_idx, side_idx in [(0, 1), (1, 0)]:
                cand_data = str(mul1_op.inputs[int(data_idx)])
                cand_side = str(mul1_op.inputs[int(side_idx)])
                cand_prod_idx = producers.get(cand_data, None)
                if cand_prod_idx is None:
                    continue
                cand_prod_op = model_ir.operators[int(cand_prod_idx)]
                if str(cand_prod_op.op_type) == "ADD":
                    add0_name = str(cand_data)
                    mul1_side_index = int(side_idx)
                    mul1_side_name = str(cand_side)
                    break
            if add0_name is None or mul1_side_index is None or mul1_side_name is None:
                continue

            add0_idx = producers.get(str(add0_name), None)
            if add0_idx is None:
                continue
            add0_op = model_ir.operators[int(add0_idx)]
            if (
                str(add0_op.op_type) != "ADD"
                or len(add0_op.inputs) != 2
                or len(add0_op.outputs) != 1
                or str(add0_op.outputs[0]) != str(add0_name)
                or str(add0_name) in model_outputs
            ):
                continue

            # add0 inputs: pre transpose + concat(axis=1)
            pre_idx: Optional[int] = None
            pre_in_name: Optional[str] = None
            pre_out_name: Optional[str] = None
            concat1_idx: Optional[int] = None
            concat1_name: Optional[str] = None
            for a_in in [str(v) for v in list(add0_op.inputs)]:
                a_prod_idx = producers.get(str(a_in), None)
                if a_prod_idx is None:
                    continue
                a_prod_op = model_ir.operators[int(a_prod_idx)]
                if (
                    str(a_prod_op.op_type) == "TRANSPOSE"
                    and len(a_prod_op.inputs) >= 2
                    and len(a_prod_op.outputs) == 1
                    and str(a_prod_op.outputs[0]) == str(a_in)
                    and _read_transpose_perm(model_ir, a_prod_op) == perm_nhwc_to_nchw
                    and set(int(v) for v in consumers.get(str(a_in), [])) == {int(add0_idx)}
                    and str(a_in) not in model_outputs
                ):
                    pre_idx = int(a_prod_idx)
                    pre_in_name = str(a_prod_op.inputs[0])
                    pre_out_name = str(a_in)
                elif (
                    str(a_prod_op.op_type) == "CONCATENATION"
                    and len(a_prod_op.inputs) == 2
                    and len(a_prod_op.outputs) == 1
                    and str(a_prod_op.outputs[0]) == str(a_in)
                    and int(a_prod_op.options.get("axis", 1)) == 1
                    and set(int(v) for v in consumers.get(str(a_in), [])) == {int(add0_idx)}
                    and str(a_in) not in model_outputs
                ):
                    concat1_idx = int(a_prod_idx)
                    concat1_name = str(a_in)
            if (
                pre_idx is None
                or pre_in_name is None
                or pre_out_name is None
                or concat1_idx is None
                or concat1_name is None
            ):
                continue

            concat1_op = model_ir.operators[int(concat1_idx)]
            trans_a_idx: Optional[int] = None
            trans_a_in_name: Optional[str] = None
            trans_a_out_name: Optional[str] = None
            addb_idx: Optional[int] = None
            addb_out_name: Optional[str] = None
            for c1_in in [str(v) for v in list(concat1_op.inputs)]:
                c1_prod_idx = producers.get(str(c1_in), None)
                if c1_prod_idx is None:
                    continue
                c1_prod_op = model_ir.operators[int(c1_prod_idx)]
                if (
                    str(c1_prod_op.op_type) == "TRANSPOSE"
                    and len(c1_prod_op.inputs) >= 2
                    and len(c1_prod_op.outputs) == 1
                    and str(c1_prod_op.outputs[0]) == str(c1_in)
                    and _read_transpose_perm(model_ir, c1_prod_op) == perm_nhwc_to_nchw
                    and set(int(v) for v in consumers.get(str(c1_in), [])) == {int(concat1_idx)}
                    and str(c1_in) not in model_outputs
                ):
                    trans_a_idx = int(c1_prod_idx)
                    trans_a_in_name = str(c1_prod_op.inputs[0])
                    trans_a_out_name = str(c1_in)
                elif (
                    str(c1_prod_op.op_type) == "ADD"
                    and len(c1_prod_op.inputs) == 2
                    and len(c1_prod_op.outputs) == 1
                    and str(c1_prod_op.outputs[0]) == str(c1_in)
                    and set(int(v) for v in consumers.get(str(c1_in), [])) == {int(concat1_idx)}
                    and str(c1_in) not in model_outputs
                ):
                    addb_idx = int(c1_prod_idx)
                    addb_out_name = str(c1_in)
            if (
                trans_a_idx is None
                or trans_a_in_name is None
                or trans_a_out_name is None
                or addb_idx is None
                or addb_out_name is None
            ):
                continue

            addb_op = model_ir.operators[int(addb_idx)]
            addb_in0 = str(addb_op.inputs[0])
            addb_in1 = str(addb_op.inputs[1])
            mulb_idx = producers.get(addb_in0, None)
            if mulb_idx is None:
                mulb_idx = producers.get(addb_in1, None)
            if mulb_idx is None:
                continue
            mulb_op = model_ir.operators[int(mulb_idx)]
            if str(mulb_op.op_type) != "MUL" or len(mulb_op.inputs) != 2 or len(mulb_op.outputs) != 1:
                continue
            mulb_out_name = str(mulb_op.outputs[0])
            if mulb_out_name == addb_in0:
                addb_side_index = 1
                addb_side_name = str(addb_in1)
            elif mulb_out_name == addb_in1:
                addb_side_index = 0
                addb_side_name = str(addb_in0)
            else:
                continue

            trans_b_idx: Optional[int] = None
            trans_b_in_name: Optional[str] = None
            trans_b_out_name: Optional[str] = None
            mulb_side_index: Optional[int] = None
            mulb_side_name: Optional[str] = None
            for data_idx, side_idx in [(0, 1), (1, 0)]:
                cand_data = str(mulb_op.inputs[int(data_idx)])
                cand_side = str(mulb_op.inputs[int(side_idx)])
                t_idx = producers.get(str(cand_data), None)
                if t_idx is None:
                    continue
                t_op = model_ir.operators[int(t_idx)]
                if (
                    str(t_op.op_type) != "TRANSPOSE"
                    or len(t_op.inputs) < 2
                    or len(t_op.outputs) != 1
                    or str(t_op.outputs[0]) != str(cand_data)
                    or _read_transpose_perm(model_ir, t_op) != perm_nhwc_to_nchw
                    or set(int(v) for v in consumers.get(str(cand_data), [])) != {int(mulb_idx)}
                    or str(cand_data) in model_outputs
                ):
                    continue
                rz_name = str(t_op.inputs[0])
                rz_idx = producers.get(rz_name, None)
                if rz_idx is None:
                    continue
                rz_op = model_ir.operators[int(rz_idx)]
                if str(rz_op.op_type) not in {"RESIZE_BILINEAR", "RESIZE_NEAREST_NEIGHBOR"}:
                    continue
                if len(rz_op.outputs) != 1 or str(rz_op.outputs[0]) != rz_name:
                    continue
                trans_b_idx = int(t_idx)
                trans_b_in_name = str(rz_name)
                trans_b_out_name = str(cand_data)
                mulb_side_index = int(side_idx)
                mulb_side_name = str(cand_side)
                break
            if (
                trans_b_idx is None
                or trans_b_in_name is None
                or trans_b_out_name is None
                or mulb_side_index is None
                or mulb_side_name is None
            ):
                continue

            chain_index_set = {
                int(pre13_idx),
                int(pre_idx),
                int(trans_a_idx),
                int(trans_b_idx),
                int(concat1_idx),
                int(addb_idx),
                int(mulb_idx),
                int(add0_idx),
                int(mul1_idx),
                int(add1_idx),
                int(prelu1_idx),
                int(concat2_idx),
                int(mul2_idx),
                int(add2_idx),
                int(prelu2_idx),
                int(post2_idx),
            }
            mulb_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mulb_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            addb_side_for_op = _ensure_channel_last_const(
                tensor_name=str(addb_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            mul1_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mul1_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            add1_side_for_op = _ensure_channel_last_const(
                tensor_name=str(add1_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            prelu1_side_for_op = _ensure_channel_last_const(
                tensor_name=str(prelu1_op.inputs[1]),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            mul2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mul2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            add2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(add2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            prelu2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(prelu2_op.inputs[1]),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            if any(
                v is None
                for v in [
                    mulb_side_for_op,
                    addb_side_for_op,
                    mul1_side_for_op,
                    add1_side_for_op,
                    prelu1_side_for_op,
                    mul2_side_for_op,
                    add2_side_for_op,
                    prelu2_side_for_op,
                ]
            ):
                continue

            _replace_operator_input_at(
                model_ir=model_ir,
                op=mulb_op,
                input_index=int(1 - int(mulb_side_index)),
                new_input_name=str(trans_b_in_name),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=mulb_op,
                input_index=int(mulb_side_index),
                new_input_name=str(mulb_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=addb_op,
                input_index=int(addb_side_index),
                new_input_name=str(addb_side_for_op),
            )

            new_concat1_inputs = [
                str(trans_a_in_name) if str(v) == str(trans_a_out_name) else str(v)
                for v in list(concat1_op.inputs)
            ]
            _set_operator_inputs(
                model_ir=model_ir,
                op=concat1_op,
                new_inputs=[str(v) for v in new_concat1_inputs],
            )
            concat1_op.options["axis"] = 3

            _replace_operator_input_at(
                model_ir=model_ir,
                op=add0_op,
                input_index=0 if str(add0_op.inputs[0]) == str(pre_out_name) else 1,
                new_input_name=str(pre_in_name),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul1_op,
                input_index=int(mul1_side_index),
                new_input_name=str(mul1_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add1_op,
                input_index=int(add1_side_index),
                new_input_name=str(add1_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=prelu1_op,
                input_index=1,
                new_input_name=str(prelu1_side_for_op),
            )

            new_concat2_inputs = [
                str(pre13_in_name) if str(v) == str(pre13_out_name) else str(v)
                for v in list(concat2_op.inputs)
            ]
            _set_operator_inputs(
                model_ir=model_ir,
                op=concat2_op,
                new_inputs=[str(v) for v in new_concat2_inputs],
            )
            concat2_op.options["axis"] = 3

            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul2_op,
                input_index=int(mul2_side_index),
                new_input_name=str(mul2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add2_op,
                input_index=int(add2_side_index),
                new_input_name=str(add2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=prelu2_op,
                input_index=1,
                new_input_name=str(prelu2_side_for_op),
            )

            _set_operator_outputs(
                model_ir=model_ir,
                op=prelu2_op,
                new_outputs=[str(post2_output_name)],
            )

            for t_name in [
                str(mulb_out_name),
                str(addb_out_name),
                str(concat1_name),
                str(add0_name),
                str(mul1_out_name),
                str(add1_out_name),
                str(prelu1_out_name),
                str(concat2_name),
                str(mul2_out_name),
                str(add2_out_name),
                str(post2_output_name),
            ]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(t_name), None),
                    perm_nchw_to_nhwc,
                )

            old_prelu2_tensor = model_ir.tensors.get(str(post2_input_name), None)
            post2_tensor = model_ir.tensors.get(str(post2_output_name), None)
            if old_prelu2_tensor is not None and post2_tensor is not None:
                post2_tensor.dtype = str(old_prelu2_tensor.dtype)
                post2_tensor.quantization = _clone_quantization(old_prelu2_tensor.quantization)
                post2_tensor.shape = [int(v) for v in list(old_prelu2_tensor.shape)]
                post2_tensor.shape_signature = (
                    [int(v) for v in list(old_prelu2_tensor.shape_signature)]
                    if old_prelu2_tensor.shape_signature is not None
                    else [int(v) for v in list(old_prelu2_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    post2_tensor,
                    perm_nchw_to_nhwc,
                )

            remove_indices = {
                int(pre13_idx),
                int(pre_idx),
                int(trans_a_idx),
                int(trans_b_idx),
                int(post2_idx),
            }
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_sinet_concat_resize_affine_tail_concat_transpose_chains": int(optimized)}


def _optimize_sinet_softmax_mask_residual_nhwc_tail_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Optimize late SiNet tail blocks where NCHW adapters remain around
    Softmax+mask residual composition.

    Target sketch:
      side_nhwc --T(0,3,1,2)--> side_nchw --PRELU--> side_prelu_nchw
      main_nhwc --T(0,3,1,2)--> main_nchw --MUL(const)--ADD(const)--> bn_nchw
      bn_nchw --T(0,3,2,1)--> s_in --SOFTMAX--> s_out --T(0,3,2,1)--> soft_nchw
      REDUCE_MAX(axis=1)->SUB->RESHAPE([N,1,H,W])->MUL(ones)
      MUL(side_prelu_nchw, mask_nchw) + bn_nchw -> sum_nchw --T(0,2,3,1)--> sum_nhwc

    Rewrite:
      - keep side/main branches in NHWC
      - remove the three NCHW bridge transposes plus terminal pre-resize transpose
      - run SOFTMAX directly on NHWC tensor and remap reduce axis/reshape/consts
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    perm_nchw_to_nwhc = [0, 3, 2, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _set_const_int_data(
        *,
        tensor_name: str,
        new_values: List[int],
        target_consumer_idx: int,
        consumers: Dict[str, List[int]],
    ) -> Optional[str]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.data is None:
            return None
        users = [int(v) for v in consumers.get(str(tensor_name), [])]
        new_data = np.asarray([int(v) for v in list(new_values)], dtype=np.int32)
        if len(users) == 1 and int(users[0]) == int(target_consumer_idx):
            tensor.data = new_data
            tensor.dtype = "INT32"
            tensor.shape = [int(len(new_values))]
            tensor.shape_signature = [int(len(new_values))]
            return str(tensor_name)

        cloned_name = _unique_tensor_name(f"{tensor_name}_nhwc")
        model_ir.tensors[cloned_name] = TensorIR(
            name=cloned_name,
            dtype="INT32",
            shape=[int(len(new_values))],
            shape_signature=[int(len(new_values))],
            data=new_data,
            is_variable=False,
            quantization=None,
        )
        return str(cloned_name)

    def _ensure_const_matches_target_nhwc(
        *,
        tensor_name: str,
        target_shape: Optional[List[int]],
        target_consumer_idx: int,
        consumers: Dict[str, List[int]],
    ) -> Optional[str]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.data is None:
            return None
        data = np.asarray(tensor.data)
        if int(data.size) == 1:
            return str(tensor_name)
        if data.ndim != 4:
            return None

        shape = [int(v) for v in list(data.shape)]
        nhwc_data: Optional[np.ndarray] = None
        if _is_fully_known_positive_shape(target_shape):
            target = [int(v) for v in list(target_shape)]
            if _broadcast_static_shapes(target, shape) is not None:
                nhwc_data = np.asarray(data)
            else:
                rotated = np.transpose(data, perm_nchw_to_nhwc).astype(data.dtype, copy=False)
                rotated_shape = [int(v) for v in list(rotated.shape)]
                if _broadcast_static_shapes(target, rotated_shape) is None:
                    return None
                nhwc_data = np.asarray(rotated)
        else:
            # Unknown target: preserve idempotence and only rotate strict NCHW-per-channel constants.
            if (
                int(shape[0]) == 1
                and int(shape[1]) > 0
                and int(shape[2]) == 1
                and int(shape[3]) == 1
            ):
                nhwc_data = np.transpose(data, perm_nchw_to_nhwc).astype(data.dtype, copy=False)
            elif (
                int(shape[0]) == 1
                and int(shape[1]) == 1
                and int(shape[2]) == 1
                and int(shape[3]) > 0
            ):
                nhwc_data = np.asarray(data)
            else:
                return None

        users = [int(v) for v in consumers.get(str(tensor_name), [])]
        if len(users) == 1 and int(users[0]) == int(target_consumer_idx):
            tensor.data = np.asarray(nhwc_data)
            tensor.shape = [int(v) for v in list(nhwc_data.shape)]
            tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]
            return str(tensor_name)

        cloned_name = _unique_tensor_name(f"{tensor_name}_nhwc")
        model_ir.tensors[cloned_name] = TensorIR(
            name=cloned_name,
            dtype=str(tensor.dtype),
            shape=[int(v) for v in list(nhwc_data.shape)],
            shape_signature=[int(v) for v in list(nhwc_data.shape)],
            data=np.asarray(nhwc_data),
            is_variable=False,
            quantization=_clone_quantization(tensor.quantization),
        )
        return str(cloned_name)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for post_idx, post_op in enumerate(model_ir.operators):
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc
            ):
                continue

            post_in = str(post_op.inputs[0])
            post_out = str(post_op.outputs[0])
            if post_out in model_outputs:
                continue

            add_res_idx = producers.get(str(post_in), None)
            if add_res_idx is None:
                continue
            add_res_op = model_ir.operators[int(add_res_idx)]
            if (
                str(add_res_op.op_type) != "ADD"
                or len(add_res_op.inputs) != 2
                or len(add_res_op.outputs) != 1
                or str(add_res_op.outputs[0]) != str(post_in)
            ):
                continue

            # Parse add_res inputs:
            #   - main_nchw (ADD from BN affine)
            #   - side_mask_nchw (MUL from side-prelu and mask)
            add_res_inputs = [str(v) for v in list(add_res_op.inputs)]
            main_name: Optional[str] = None
            side_mask_name: Optional[str] = None
            main_add_idx: Optional[int] = None
            side_mask_idx: Optional[int] = None
            for inp in add_res_inputs:
                inp_prod_idx = producers.get(str(inp), None)
                if inp_prod_idx is None:
                    continue
                inp_prod_op = model_ir.operators[int(inp_prod_idx)]
                if str(inp_prod_op.op_type) == "ADD":
                    # Candidate: BN affine result
                    a_in0 = str(inp_prod_op.inputs[0])
                    a_in1 = str(inp_prod_op.inputs[1])
                    m_idx = producers.get(a_in0, None)
                    if m_idx is None:
                        m_idx = producers.get(a_in1, None)
                    if m_idx is None:
                        continue
                    m_op = model_ir.operators[int(m_idx)]
                    if str(m_op.op_type) != "MUL" or len(m_op.inputs) != 2:
                        continue
                    if str(m_op.outputs[0]) not in {a_in0, a_in1}:
                        continue
                    main_name = str(inp)
                    main_add_idx = int(inp_prod_idx)
                elif str(inp_prod_op.op_type) == "MUL":
                    side_mask_name = str(inp)
                    side_mask_idx = int(inp_prod_idx)
            if (
                main_name is None
                or side_mask_name is None
                or main_add_idx is None
                or side_mask_idx is None
            ):
                continue

            main_add_op = model_ir.operators[int(main_add_idx)]
            main_add_in0 = str(main_add_op.inputs[0])
            main_add_in1 = str(main_add_op.inputs[1])
            main_mul_idx = producers.get(main_add_in0, None)
            if main_mul_idx is None:
                main_mul_idx = producers.get(main_add_in1, None)
            if main_mul_idx is None:
                continue
            main_mul_op = model_ir.operators[int(main_mul_idx)]
            if str(main_mul_op.op_type) != "MUL" or len(main_mul_op.inputs) != 2:
                continue
            if str(main_mul_op.outputs[0]) == str(main_add_in0):
                main_add_side_idx = 1
                main_add_side_name = str(main_add_in1)
            elif str(main_mul_op.outputs[0]) == str(main_add_in1):
                main_add_side_idx = 0
                main_add_side_name = str(main_add_in0)
            else:
                continue

            main_pre_idx: Optional[int] = None
            main_pre_in_name: Optional[str] = None
            main_pre_out_name: Optional[str] = None
            main_mul_side_idx: Optional[int] = None
            main_mul_side_name: Optional[str] = None
            for data_idx, side_idx in [(0, 1), (1, 0)]:
                cand_data = str(main_mul_op.inputs[int(data_idx)])
                cand_side = str(main_mul_op.inputs[int(side_idx)])
                cand_pre_idx = producers.get(str(cand_data), None)
                if cand_pre_idx is None:
                    continue
                cand_pre_op = model_ir.operators[int(cand_pre_idx)]
                if (
                    str(cand_pre_op.op_type) != "TRANSPOSE"
                    or len(cand_pre_op.inputs) < 2
                    or len(cand_pre_op.outputs) != 1
                    or str(cand_pre_op.outputs[0]) != str(cand_data)
                    or _read_transpose_perm(model_ir, cand_pre_op) != perm_nhwc_to_nchw
                    or set(int(v) for v in consumers.get(str(cand_data), [])) != {int(main_mul_idx)}
                    or str(cand_data) in model_outputs
                ):
                    continue
                main_pre_idx = int(cand_pre_idx)
                main_pre_in_name = str(cand_pre_op.inputs[0])
                main_pre_out_name = str(cand_data)
                main_mul_side_idx = int(side_idx)
                main_mul_side_name = str(cand_side)
                break
            if (
                main_pre_idx is None
                or main_pre_in_name is None
                or main_pre_out_name is None
                or main_mul_side_idx is None
                or main_mul_side_name is None
            ):
                continue

            # Softmax chain on main_name.
            main_users = set(int(v) for v in consumers.get(str(main_name), []))
            if int(add_res_idx) not in main_users or len(main_users) != 2:
                continue
            soft_pre_idx = next((int(v) for v in main_users if int(v) != int(add_res_idx)), None)
            if soft_pre_idx is None:
                continue
            soft_pre_op = model_ir.operators[int(soft_pre_idx)]
            if (
                str(soft_pre_op.op_type) != "TRANSPOSE"
                or len(soft_pre_op.inputs) < 2
                or len(soft_pre_op.outputs) != 1
                or str(soft_pre_op.inputs[0]) != str(main_name)
                or _read_transpose_perm(model_ir, soft_pre_op) != perm_nchw_to_nwhc
            ):
                continue
            soft_pre_out = str(soft_pre_op.outputs[0])
            softmax_idx = consumers.get(str(soft_pre_out), [])
            if len(softmax_idx) != 1:
                continue
            softmax_idx = int(softmax_idx[0])
            softmax_op = model_ir.operators[int(softmax_idx)]
            if (
                str(softmax_op.op_type) != "SOFTMAX"
                or len(softmax_op.inputs) != 1
                or len(softmax_op.outputs) != 1
                or str(softmax_op.inputs[0]) != str(soft_pre_out)
            ):
                continue
            softmax_out = str(softmax_op.outputs[0])
            soft_post_users = [int(v) for v in consumers.get(str(softmax_out), [])]
            if len(soft_post_users) != 1:
                continue
            soft_post_idx = int(soft_post_users[0])
            soft_post_op = model_ir.operators[int(soft_post_idx)]
            if (
                str(soft_post_op.op_type) != "TRANSPOSE"
                or len(soft_post_op.inputs) < 2
                or len(soft_post_op.outputs) != 1
                or str(soft_post_op.inputs[0]) != str(softmax_out)
                or _read_transpose_perm(model_ir, soft_post_op) != perm_nchw_to_nwhc
            ):
                continue
            soft_back_name = str(soft_post_op.outputs[0])

            reduce_users = [int(v) for v in consumers.get(str(soft_back_name), [])]
            if len(reduce_users) != 1:
                continue
            reduce_idx = int(reduce_users[0])
            reduce_op = model_ir.operators[int(reduce_idx)]
            if (
                str(reduce_op.op_type) != "REDUCE_MAX"
                or len(reduce_op.inputs) < 2
                or len(reduce_op.outputs) != 1
                or str(reduce_op.inputs[0]) != str(soft_back_name)
                or bool(reduce_op.options.get("keepDims", False))
            ):
                continue
            reduce_axis_name = str(reduce_op.inputs[1])
            reduce_axis_tensor = model_ir.tensors.get(str(reduce_axis_name), None)
            reduce_axis_vals = _read_const_ints_from_tensor(reduce_axis_tensor)
            if reduce_axis_vals is None or list(reduce_axis_vals) != [1]:
                continue
            reduce_out = str(reduce_op.outputs[0])

            sub_users = [int(v) for v in consumers.get(str(reduce_out), [])]
            if len(sub_users) != 1:
                continue
            sub_idx = int(sub_users[0])
            sub_op = model_ir.operators[int(sub_idx)]
            if str(sub_op.op_type) != "SUB" or len(sub_op.inputs) != 2 or len(sub_op.outputs) != 1:
                continue
            sub_in0 = str(sub_op.inputs[0])
            sub_in1 = str(sub_op.inputs[1])
            if sub_in1 == str(reduce_out):
                if not _is_singleton_constant_tensor(model_ir, sub_in0):
                    continue
            elif sub_in0 == str(reduce_out):
                if not _is_singleton_constant_tensor(model_ir, sub_in1):
                    continue
            else:
                continue
            sub_out = str(sub_op.outputs[0])

            reshape_users = [int(v) for v in consumers.get(str(sub_out), [])]
            if len(reshape_users) != 1:
                continue
            reshape_idx = int(reshape_users[0])
            reshape_op = model_ir.operators[int(reshape_idx)]
            if (
                str(reshape_op.op_type) != "RESHAPE"
                or len(reshape_op.inputs) < 2
                or len(reshape_op.outputs) != 1
                or str(reshape_op.inputs[0]) != str(sub_out)
            ):
                continue
            reshape_shape_name = str(reshape_op.inputs[1])
            reshape_shape_tensor = model_ir.tensors.get(str(reshape_shape_name), None)
            reshape_vals = _read_const_ints_from_tensor(reshape_shape_tensor)
            if reshape_vals is None or len(reshape_vals) != 4:
                continue
            if int(reshape_vals[0]) != 1 or int(reshape_vals[1]) != 1:
                continue
            reshape_out = str(reshape_op.outputs[0])

            expand_users = [int(v) for v in consumers.get(str(reshape_out), [])]
            if len(expand_users) != 1:
                continue
            expand_idx = int(expand_users[0])
            expand_op = model_ir.operators[int(expand_idx)]
            if str(expand_op.op_type) != "MUL" or len(expand_op.inputs) != 2 or len(expand_op.outputs) != 1:
                continue
            expand_in0 = str(expand_op.inputs[0])
            expand_in1 = str(expand_op.inputs[1])
            if expand_in0 == str(reshape_out):
                expand_const_idx = 1
                expand_const_name = str(expand_in1)
            elif expand_in1 == str(reshape_out):
                expand_const_idx = 0
                expand_const_name = str(expand_in0)
            else:
                continue
            expand_const_tensor = model_ir.tensors.get(str(expand_const_name), None)
            if expand_const_tensor is None or expand_const_tensor.data is None:
                continue
            expand_out = str(expand_op.outputs[0])

            side_mask_op = model_ir.operators[int(side_mask_idx)]
            side_mask_in0 = str(side_mask_op.inputs[0])
            side_mask_in1 = str(side_mask_op.inputs[1])
            if side_mask_in0 == str(expand_out):
                side_tensor_name = str(side_mask_in1)
            elif side_mask_in1 == str(expand_out):
                side_tensor_name = str(side_mask_in0)
            else:
                continue

            side_prelu_idx = producers.get(str(side_tensor_name), None)
            if side_prelu_idx is None:
                continue
            side_prelu_op = model_ir.operators[int(side_prelu_idx)]
            if (
                str(side_prelu_op.op_type) != "PRELU"
                or len(side_prelu_op.inputs) != 2
                or len(side_prelu_op.outputs) != 1
                or str(side_prelu_op.outputs[0]) != str(side_tensor_name)
            ):
                continue
            side_pre_in = str(side_prelu_op.inputs[0])
            side_pre_idx = producers.get(str(side_pre_in), None)
            if side_pre_idx is None:
                continue
            side_pre_op = model_ir.operators[int(side_pre_idx)]
            if (
                str(side_pre_op.op_type) != "TRANSPOSE"
                or len(side_pre_op.inputs) < 2
                or len(side_pre_op.outputs) != 1
                or str(side_pre_op.outputs[0]) != str(side_pre_in)
                or _read_transpose_perm(model_ir, side_pre_op) != perm_nhwc_to_nchw
                or set(int(v) for v in consumers.get(str(side_pre_in), [])) != {int(side_prelu_idx)}
                or str(side_pre_in) in model_outputs
            ):
                continue
            side_pre_in_name = str(side_pre_op.inputs[0])

            # Locality and output guards.
            if any(
                name in model_outputs
                for name in [
                    str(main_name),
                    str(side_tensor_name),
                    str(soft_pre_out),
                    str(softmax_out),
                    str(soft_back_name),
                    str(post_in),
                ]
            ):
                continue

            main_nhwc_shape = (
                list(model_ir.tensors[str(main_pre_in_name)].shape)
                if str(main_pre_in_name) in model_ir.tensors
                else None
            )
            side_nhwc_shape = (
                list(model_ir.tensors[str(side_pre_in_name)].shape)
                if str(side_pre_in_name) in model_ir.tensors
                else None
            )

            main_mul_const = _ensure_const_matches_target_nhwc(
                tensor_name=str(main_mul_side_name),
                target_shape=main_nhwc_shape,
                target_consumer_idx=int(main_mul_idx),
                consumers=consumers,
            )
            main_add_const = _ensure_const_matches_target_nhwc(
                tensor_name=str(main_add_side_name),
                target_shape=main_nhwc_shape,
                target_consumer_idx=int(main_add_idx),
                consumers=consumers,
            )
            side_prelu_const = _ensure_const_matches_target_nhwc(
                tensor_name=str(side_prelu_op.inputs[1]),
                target_shape=side_nhwc_shape,
                target_consumer_idx=int(side_prelu_idx),
                consumers=consumers,
            )
            expand_const_nhwc = _ensure_const_matches_target_nhwc(
                tensor_name=str(expand_const_name),
                target_shape=side_nhwc_shape,
                target_consumer_idx=int(expand_idx),
                consumers=consumers,
            )
            if any(v is None for v in [main_mul_const, main_add_const, side_prelu_const, expand_const_nhwc]):
                continue

            new_reduce_axis_name = _set_const_int_data(
                tensor_name=str(reduce_axis_name),
                new_values=[3],
                target_consumer_idx=int(reduce_idx),
                consumers=consumers,
            )
            if new_reduce_axis_name is None:
                continue
            new_reshape_shape_name = _set_const_int_data(
                tensor_name=str(reshape_shape_name),
                new_values=[int(reshape_vals[0]), int(reshape_vals[2]), int(reshape_vals[3]), int(reshape_vals[1])],
                target_consumer_idx=int(reshape_idx),
                consumers=consumers,
            )
            if new_reshape_shape_name is None:
                continue

            # Rewrite side branch to NHWC.
            _set_operator_inputs(
                model_ir=model_ir,
                op=side_prelu_op,
                new_inputs=[str(side_pre_in_name), str(side_prelu_const)],
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(side_tensor_name), None),
                perm_nchw_to_nhwc,
            )

            # Rewrite main branch to NHWC.
            _replace_operator_input_at(
                model_ir=model_ir,
                op=main_mul_op,
                input_index=int(1 - int(main_mul_side_idx)),
                new_input_name=str(main_pre_in_name),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=main_mul_op,
                input_index=int(main_mul_side_idx),
                new_input_name=str(main_mul_const),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=main_add_op,
                input_index=int(main_add_side_idx),
                new_input_name=str(main_add_const),
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(main_mul_op.outputs[0]), None),
                perm_nchw_to_nhwc,
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(main_name), None),
                perm_nchw_to_nhwc,
            )

            # Remove softmax wrapper transposes.
            _set_operator_inputs(
                model_ir=model_ir,
                op=softmax_op,
                new_inputs=[str(main_name)],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=softmax_op,
                new_outputs=[str(soft_back_name)],
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=reduce_op,
                input_index=1,
                new_input_name=str(new_reduce_axis_name),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=reshape_op,
                input_index=1,
                new_input_name=str(new_reshape_shape_name),
            )
            reshape_opts = dict(reshape_op.options) if isinstance(reshape_op.options, dict) else {}
            for shape_key in ["newShape", "onnxRawNewShape"]:
                shape_val = reshape_opts.get(shape_key, None)
                if isinstance(shape_val, list) and len(shape_val) == 4:
                    reshape_opts[shape_key] = [
                        int(shape_val[0]),
                        int(shape_val[2]),
                        int(shape_val[3]),
                        int(shape_val[1]),
                    ]
            reshape_op.options = reshape_opts
            _replace_operator_input_at(
                model_ir=model_ir,
                op=expand_op,
                input_index=int(expand_const_idx),
                new_input_name=str(expand_const_nhwc),
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(soft_back_name), None),
                perm_nchw_to_nhwc,
            )

            # Keep mask/residual in NHWC and bypass terminal transpose.
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(expand_out), None),
                perm_nchw_to_nhwc,
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(side_mask_name), None),
                perm_nchw_to_nhwc,
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=add_res_op,
                new_outputs=[str(post_out)],
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(post_out), None),
                perm_nchw_to_nhwc,
            )

            remove_indices = {
                int(side_pre_idx),
                int(main_pre_idx),
                int(soft_pre_idx),
                int(soft_post_idx),
                int(post_idx),
            }
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_sinet_softmax_mask_residual_nhwc_tail_chains": int(optimized)}


def _optimize_transpose_mul_add_const_prelu_prepost_nhwc_terminal_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Terminal rewrite for:
      TRANSPOSE(NHWC->NCHW) -> MUL(const) -> ADD(const) -> PRELU(const) -> TRANSPOSE(NCHW->NHWC)

    This pass is intentionally strict and runs only in the terminal stage to avoid
    interacting with earlier graph-wide transpose optimizers.
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _ensure_const_nhwc_channel_last(
        *,
        tensor_name: str,
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> Optional[str]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.data is None:
            return None
        data = np.asarray(tensor.data)
        if int(data.size) == 1:
            return str(tensor_name)
        if data.ndim != 4:
            return None
        shape = [int(v) for v in list(data.shape)]
        nhwc_data: Optional[np.ndarray] = None
        if (
            int(shape[0]) == 1
            and int(shape[1]) == 1
            and int(shape[2]) == 1
            and int(shape[3]) > 0
        ):
            nhwc_data = np.asarray(data)
        elif (
            int(shape[0]) == 1
            and int(shape[1]) > 0
            and int(shape[2]) == 1
            and int(shape[3]) == 1
        ):
            nhwc_data = np.transpose(data, perm_nchw_to_nhwc).astype(data.dtype, copy=False)
        else:
            return None

        side_users = [int(v) for v in consumers.get(str(tensor_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)
        if shared_outside_chain:
            cloned_name = _unique_tensor_name(f"{tensor_name}_nhwc")
            model_ir.tensors[cloned_name] = TensorIR(
                name=cloned_name,
                dtype=str(tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(tensor.quantization),
            )
            return str(cloned_name)

        tensor.data = np.asarray(nhwc_data)
        tensor.shape = [int(v) for v in list(nhwc_data.shape)]
        tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]
        return str(tensor_name)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue
            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_input_name in model_outputs or pre_output_name in model_outputs:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) == 0:
                continue
            for mul_idx in pre_users:
                mul_op = model_ir.operators[int(mul_idx)]
                if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                    continue
                mul_inputs = [str(v) for v in list(mul_op.inputs)]
                if mul_inputs[0] == pre_output_name:
                    mul_side_input_index = 1
                    mul_side_name = str(mul_inputs[1])
                elif mul_inputs[1] == pre_output_name:
                    mul_side_input_index = 0
                    mul_side_name = str(mul_inputs[0])
                else:
                    continue

                mul_out_name = str(mul_op.outputs[0])
                if mul_out_name in model_outputs:
                    continue
                mul_out_users = [int(v) for v in consumers.get(mul_out_name, []) if int(v) != int(mul_idx)]
                if len(mul_out_users) != 1:
                    continue
                add_idx = int(mul_out_users[0])
                add_op = model_ir.operators[int(add_idx)]
                if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                    continue
                add_inputs = [str(v) for v in list(add_op.inputs)]
                if add_inputs[0] == mul_out_name:
                    add_side_input_index = 1
                    add_side_name = str(add_inputs[1])
                elif add_inputs[1] == mul_out_name:
                    add_side_input_index = 0
                    add_side_name = str(add_inputs[0])
                else:
                    continue

                add_out_name = str(add_op.outputs[0])
                if add_out_name in model_outputs:
                    continue
                add_out_users = [int(v) for v in consumers.get(add_out_name, []) if int(v) != int(add_idx)]
                if len(add_out_users) != 1:
                    continue
                prelu_idx = int(add_out_users[0])
                prelu_op = model_ir.operators[int(prelu_idx)]
                if (
                    str(prelu_op.op_type) != "PRELU"
                    or len(prelu_op.inputs) != 2
                    or len(prelu_op.outputs) != 1
                    or str(prelu_op.inputs[0]) != add_out_name
                ):
                    continue
                prelu_side_name = str(prelu_op.inputs[1])
                prelu_out_name = str(prelu_op.outputs[0])
                if prelu_out_name in model_outputs:
                    continue

                prelu_users = [int(v) for v in consumers.get(prelu_out_name, []) if int(v) != int(prelu_idx)]
                if len(prelu_users) == 0:
                    continue
                post_indices: List[int] = []
                post_output_names: List[str] = []
                legacy_users: List[int] = []
                for user_idx in prelu_users:
                    user_op = model_ir.operators[int(user_idx)]
                    if (
                        str(user_op.op_type) == "TRANSPOSE"
                        and len(user_op.inputs) >= 2
                        and len(user_op.outputs) == 1
                        and str(user_op.inputs[0]) == prelu_out_name
                        and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                        and str(user_op.outputs[0]) not in model_outputs
                    ):
                        post_indices.append(int(user_idx))
                        post_output_names.append(str(user_op.outputs[0]))
                    else:
                        legacy_users.append(int(user_idx))
                if len(post_indices) == 0:
                    continue

                chain_index_set = {int(mul_idx), int(add_idx), int(prelu_idx)}
                mul_side_for_op = _ensure_const_nhwc_channel_last(
                    tensor_name=str(mul_side_name),
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                )
                if mul_side_for_op is None:
                    continue
                add_side_for_op = _ensure_const_nhwc_channel_last(
                    tensor_name=str(add_side_name),
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                )
                if add_side_for_op is None:
                    continue
                prelu_side_for_op = _ensure_const_nhwc_channel_last(
                    tensor_name=str(prelu_side_name),
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                )
                if prelu_side_for_op is None:
                    continue

                mul_inputs[int(mul_side_input_index)] = str(mul_side_for_op)
                if mul_inputs[0] == pre_output_name:
                    mul_inputs[0] = str(pre_input_name)
                elif mul_inputs[1] == pre_output_name:
                    mul_inputs[1] = str(pre_input_name)
                else:
                    continue
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=mul_op,
                    new_inputs=mul_inputs,
                )
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=add_op,
                    input_index=int(add_side_input_index),
                    new_input_name=str(add_side_for_op),
                )
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=prelu_op,
                    input_index=1,
                    new_input_name=str(prelu_side_for_op),
                )

                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(mul_out_name, None),
                    perm_nchw_to_nhwc,
                )
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(add_out_name, None),
                    perm_nchw_to_nhwc,
                )
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(prelu_out_name, None),
                    perm_nchw_to_nhwc,
                )

                canonical_post_output_name = str(post_output_names[0])
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=prelu_op,
                    new_outputs=[canonical_post_output_name],
                )
                for alias_name in post_output_names[1:]:
                    _replace_tensor_inputs(model_ir, str(alias_name), canonical_post_output_name)

                old_prelu_tensor = model_ir.tensors.get(prelu_out_name, None)
                canonical_tensor = model_ir.tensors.get(canonical_post_output_name, None)
                if old_prelu_tensor is not None and canonical_tensor is not None:
                    canonical_tensor.dtype = str(old_prelu_tensor.dtype)
                    canonical_tensor.quantization = _clone_quantization(old_prelu_tensor.quantization)
                    canonical_tensor.shape = [int(v) for v in list(old_prelu_tensor.shape)]
                    canonical_tensor.shape_signature = (
                        [int(v) for v in list(old_prelu_tensor.shape_signature)]
                        if old_prelu_tensor.shape_signature is not None
                        else [int(v) for v in list(old_prelu_tensor.shape)]
                    )
                    _permute_tensor_metadata_if_rank_matches(
                        canonical_tensor,
                        perm_nchw_to_nhwc,
                    )

                if len(legacy_users) > 0:
                    keep_post_idx = int(post_indices[0])
                    keep_post_op = model_ir.operators[int(keep_post_idx)]
                    keep_perm_name = str(keep_post_op.inputs[1])
                    keep_perm_tensor = model_ir.tensors.get(keep_perm_name, None)
                    if keep_perm_tensor is not None:
                        keep_perm_tensor.data = np.asarray(perm_nhwc_to_nchw, dtype=np.int32)
                    _set_operator_inputs(
                        model_ir=model_ir,
                        op=keep_post_op,
                        new_inputs=[canonical_post_output_name, keep_perm_name],
                    )
                    _set_operator_outputs(
                        model_ir=model_ir,
                        op=keep_post_op,
                        new_outputs=[prelu_out_name],
                    )
                    post_remove_indices = [int(v) for v in post_indices[1:]]
                else:
                    post_remove_indices = [int(v) for v in post_indices]

                remove_indices = set(int(v) for v in post_remove_indices)
                pre_remaining_users = [int(v) for v in pre_users if int(v) != int(mul_idx)]
                if len(pre_remaining_users) == 0:
                    remove_indices.add(int(pre_idx))
                for remove_idx in sorted(list(remove_indices), reverse=True):
                    del model_ir.operators[int(remove_idx)]

                rewritten += 1
                changed = True
                break

            if changed:
                break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_mul_add_const_prelu_prepost_nhwc_terminal_chains": int(rewritten)}


def _optimize_transpose_mean_mul_add_const_prepost_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate NCHW round-trips around TRANSPOSE->MEAN->MUL(const)->ADD(const)->TRANSPOSE chains.

    Target:
      x_nhwc --TRANSPOSE(0,3,1,2)--> x_nchw
      x_nchw --MEAN(axes_nchw, keepDims=True)--> m_nchw
      m_nchw --MUL(const)--> u_nchw --ADD(const)--> y_nchw
      y_nchw --TRANSPOSE(0,2,3,1)--> y_nhwc

    Rewrite:
      x_nhwc --MEAN(axes_nhwc, keepDims=True)--> m_nhwc
      m_nhwc --MUL(const_nhwc)--> u_nhwc --ADD(const_nhwc)--> y_nhwc
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _rewrite_binary_const_to_nhwc(
        *,
        op_idx: int,
        side_input_index: int,
        side_input_name: str,
        target_broadcast_shape: Optional[List[int]],
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> bool:
        side_tensor = model_ir.tensors.get(str(side_input_name), None)
        if side_tensor is None or side_tensor.data is None:
            return False
        side_data = np.asarray(side_tensor.data)
        if int(side_data.size) == 1:
            return True
        if side_data.ndim != 4:
            return False

        nhwc_data: Optional[np.ndarray] = None
        target_shape = (
            [int(v) for v in list(target_broadcast_shape)]
            if _is_fully_known_positive_shape(target_broadcast_shape)
            else None
        )
        if target_shape is not None:
            side_shape = [int(v) for v in list(side_data.shape)]
            if _broadcast_static_shapes(target_shape, side_shape) is not None:
                # Already NHWC-compatible. Keep idempotent across repeated sweeps.
                return True
            rotated = np.asarray(side_data)
            for _ in range(3):
                rotated = np.transpose(rotated, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
                rotated_shape = [int(v) for v in list(rotated.shape)]
                if _broadcast_static_shapes(target_shape, rotated_shape) is not None:
                    nhwc_data = np.asarray(rotated)
                    break
            if nhwc_data is None:
                return False
        else:
            side_shape = [int(v) for v in list(side_data.shape)]
            if (
                len(side_shape) == 4
                and int(side_shape[0]) == 1
                and int(side_shape[1]) > 1
                and int(side_shape[2]) == 1
                and int(side_shape[3]) == 1
            ):
                nhwc_data = np.transpose(side_data, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
            else:
                return True

        side_users = [int(v) for v in consumers.get(str(side_input_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)

        target_name = str(side_input_name)
        if shared_outside_chain:
            target_name = _unique_tensor_name(f"{side_input_name}_nhwc")
            model_ir.tensors[target_name] = TensorIR(
                name=target_name,
                dtype=str(side_tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(side_tensor.quantization),
            )
        else:
            side_tensor.data = np.asarray(nhwc_data)
            side_tensor.shape = [int(v) for v in list(nhwc_data.shape)]
            side_tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]

        _replace_operator_input_at(
            model_ir=model_ir,
            op=model_ir.operators[int(op_idx)],
            input_index=int(side_input_index),
            new_input_name=str(target_name),
        )
        return True

    def _can_rewrite_binary_const_to_nhwc(
        *,
        side_input_name: str,
        target_broadcast_shape: Optional[List[int]],
    ) -> bool:
        side_tensor = model_ir.tensors.get(str(side_input_name), None)
        if side_tensor is None or side_tensor.data is None:
            return False
        side_data = np.asarray(side_tensor.data)
        if int(side_data.size) == 1:
            return True
        if side_data.ndim != 4:
            return False
        target_shape = (
            [int(v) for v in list(target_broadcast_shape)]
            if _is_fully_known_positive_shape(target_broadcast_shape)
            else None
        )
        if target_shape is None:
            return True
        side_shape = [int(v) for v in list(side_data.shape)]
        if _broadcast_static_shapes(target_shape, side_shape) is not None:
            return True
        rotated = np.asarray(side_data)
        for _ in range(3):
            rotated = np.transpose(rotated, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
            rotated_shape = [int(v) for v in list(rotated.shape)]
            if _broadcast_static_shapes(target_shape, rotated_shape) is not None:
                return True
        return False

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue
            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_input_name in model_outputs or pre_output_name in model_outputs:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) == 0:
                continue

            for mean_idx in pre_users:
                mean_op = model_ir.operators[int(mean_idx)]
                if str(mean_op.op_type) != "MEAN" or len(mean_op.inputs) < 2 or len(mean_op.outputs) != 1:
                    continue
                if str(mean_op.inputs[0]) != pre_output_name:
                    continue
                if not bool(mean_op.options.get("keepDims", False)):
                    continue

                mean_axes_name = str(mean_op.inputs[1])
                mean_axes_tensor = model_ir.tensors.get(mean_axes_name, None)
                mean_axes = _read_const_ints_from_tensor(mean_axes_tensor)
                if mean_axes is None or len(mean_axes) == 0:
                    continue

                mean_output_name = str(mean_op.outputs[0])
                if mean_output_name in model_outputs:
                    continue
                mul_users = [int(v) for v in consumers.get(mean_output_name, [])]
                if len(mul_users) != 1:
                    continue
                mul_idx = int(mul_users[0])
                mul_op = model_ir.operators[mul_idx]
                if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                    continue

                mul_in0 = str(mul_op.inputs[0])
                mul_in1 = str(mul_op.inputs[1])
                if mul_in0 == mean_output_name:
                    mul_side_input_index = 1
                    mul_side_name = mul_in1
                elif mul_in1 == mean_output_name:
                    mul_side_input_index = 0
                    mul_side_name = mul_in0
                else:
                    continue

                add_input_name = str(mul_op.outputs[0])
                if add_input_name in model_outputs:
                    continue
                add_users = [int(v) for v in consumers.get(add_input_name, [])]
                if len(add_users) != 1:
                    continue
                add_idx = int(add_users[0])
                add_op = model_ir.operators[add_idx]
                if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                    continue

                add_in0 = str(add_op.inputs[0])
                add_in1 = str(add_op.inputs[1])
                if add_in0 == add_input_name:
                    add_side_input_index = 1
                    add_side_name = add_in1
                elif add_in1 == add_input_name:
                    add_side_input_index = 0
                    add_side_name = add_in0
                else:
                    continue

                add_output_name = str(add_op.outputs[0])
                if add_output_name in model_outputs:
                    continue
                add_output_users = [int(v) for v in consumers.get(add_output_name, [])]
                if len(add_output_users) == 0:
                    continue

                post_indices: List[int] = []
                post_output_names: List[str] = []
                valid_posts = True
                for user_idx in add_output_users:
                    user_op = model_ir.operators[int(user_idx)]
                    if (
                        str(user_op.op_type) == "TRANSPOSE"
                        and len(user_op.inputs) >= 2
                        and len(user_op.outputs) == 1
                        and str(user_op.inputs[0]) == add_output_name
                        and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                        and str(user_op.outputs[0]) not in model_outputs
                    ):
                        post_indices.append(int(user_idx))
                        post_output_names.append(str(user_op.outputs[0]))
                    else:
                        valid_posts = False
                        break
                if not valid_posts or len(post_indices) == 0:
                    continue

                # Normalize NCHW-side axes and map them to NHWC-side axes.
                mapped_axes: List[int] = []
                valid_axes = True
                for axis in mean_axes:
                    a = int(axis)
                    if a < 0:
                        a += 4
                    if a < 0 or a >= 4:
                        valid_axes = False
                        break
                    mapped_axes.append(int(perm_nchw_to_nhwc[int(a)]))
                if not valid_axes or len(mapped_axes) == 0:
                    continue

                chain_index_set = {int(mean_idx), int(mul_idx), int(add_idx)}
                target_nhwc_shape = (
                    list(model_ir.tensors[pre_input_name].shape)
                    if pre_input_name in model_ir.tensors
                    else None
                )
                if not _can_rewrite_binary_const_to_nhwc(
                    side_input_name=str(mul_side_name),
                    target_broadcast_shape=target_nhwc_shape,
                ):
                    continue
                if not _can_rewrite_binary_const_to_nhwc(
                    side_input_name=str(add_side_name),
                    target_broadcast_shape=target_nhwc_shape,
                ):
                    continue
                if not _rewrite_binary_const_to_nhwc(
                    op_idx=int(mul_idx),
                    side_input_index=int(mul_side_input_index),
                    side_input_name=str(mul_side_name),
                    target_broadcast_shape=target_nhwc_shape,
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                ):
                    continue
                if not _rewrite_binary_const_to_nhwc(
                    op_idx=int(add_idx),
                    side_input_index=int(add_side_input_index),
                    side_input_name=str(add_side_name),
                    target_broadcast_shape=target_nhwc_shape,
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                ):
                    continue

                if not _write_const_ints_to_tensor(mean_axes_tensor, [int(v) for v in mapped_axes]):
                    # Keep going even when unchanged; rewrite still valid.
                    pass

                mean_inputs = [str(v) for v in list(mean_op.inputs)]
                mean_inputs[0] = pre_input_name
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=mean_op,
                    new_inputs=mean_inputs,
                )
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(mean_output_name, None),
                    perm_nchw_to_nhwc,
                )
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(add_input_name, None),
                    perm_nchw_to_nhwc,
                )

                canonical_post_output_name = str(post_output_names[0])
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=add_op,
                    new_outputs=[canonical_post_output_name],
                )
                for alias_name in post_output_names[1:]:
                    _replace_tensor_inputs(model_ir, str(alias_name), canonical_post_output_name)

                old_add_out_tensor = model_ir.tensors.get(add_output_name, None)
                canonical_tensor = model_ir.tensors.get(canonical_post_output_name, None)
                if old_add_out_tensor is not None and canonical_tensor is not None:
                    canonical_tensor.dtype = str(old_add_out_tensor.dtype)
                    canonical_tensor.quantization = _clone_quantization(old_add_out_tensor.quantization)
                    canonical_tensor.shape = [int(v) for v in list(old_add_out_tensor.shape)]
                    canonical_tensor.shape_signature = (
                        [int(v) for v in list(old_add_out_tensor.shape_signature)]
                        if old_add_out_tensor.shape_signature is not None
                        else [int(v) for v in list(old_add_out_tensor.shape)]
                    )
                    _permute_tensor_metadata_if_rank_matches(
                        canonical_tensor,
                        perm_nchw_to_nhwc,
                    )

                remove_indices = set(int(v) for v in post_indices)
                # Drop pre transpose only when this rewrite consumed its last user.
                pre_remaining_users = [int(v) for v in pre_users if int(v) != int(mean_idx)]
                if len(pre_remaining_users) == 0:
                    remove_indices.add(int(pre_idx))
                for remove_idx in sorted(remove_indices, reverse=True):
                    del model_ir.operators[int(remove_idx)]

                rewritten += 1
                changed = True
                break

            if changed:
                break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_mean_mul_add_const_prepost_nhwc_chains": int(rewritten)}


def _optimize_transpose_mean_prepost_nhwc_passthrough_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate NCHW round-trips around TRANSPOSE->MEAN->TRANSPOSE chains.

    Target:
      x_nhwc --TRANSPOSE(0,3,1,2)--> x_nchw
      x_nchw --MEAN(axes_nchw, keepDims=True)--> m_nchw
      m_nchw --TRANSPOSE(0,2,3,1)--> m_nhwc

    Rewrite:
      x_nhwc --MEAN(axes_nhwc, keepDims=True)--> m_nhwc

    Safety:
    - MEAN output is consumed only by inverse post-transpose adapters.
    - Rank-4 and constant MEAN axes.
    - When pre-transpose has extra consumers, keep that transpose and bypass only the MEAN branch.
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue
            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_output_name in model_outputs:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) == 0:
                continue

            for mean_idx in pre_users:
                mean_op = model_ir.operators[int(mean_idx)]
                if str(mean_op.op_type) != "MEAN" or len(mean_op.inputs) < 2 or len(mean_op.outputs) != 1:
                    continue
                if str(mean_op.inputs[0]) != pre_output_name:
                    continue
                if not bool(mean_op.options.get("keepDims", False)):
                    continue

                mean_axes_name = str(mean_op.inputs[1])
                mean_axes_tensor = model_ir.tensors.get(mean_axes_name, None)
                mean_axes_vals = _read_const_ints_from_tensor(mean_axes_tensor)
                if mean_axes_vals is None or len(mean_axes_vals) == 0:
                    continue

                rank = 4
                pre_input_tensor = model_ir.tensors.get(pre_input_name, None)
                if pre_input_tensor is not None and pre_input_tensor.shape is not None and len(pre_input_tensor.shape) > 0:
                    rank = int(len(list(pre_input_tensor.shape)))
                if rank != 4:
                    continue

                normalized_axes: List[int] = []
                valid_axes = True
                for axis in mean_axes_vals:
                    a = int(axis)
                    if a < 0:
                        a += int(rank)
                    if a < 0 or a >= int(rank):
                        valid_axes = False
                        break
                    normalized_axes.append(int(a))
                if not valid_axes:
                    continue
                mapped_axes = [int(perm_nhwc_to_nchw[int(axis)]) for axis in normalized_axes]

                mean_out_name = str(mean_op.outputs[0])
                if mean_out_name in model_outputs:
                    continue
                mean_users = [int(v) for v in consumers.get(mean_out_name, [])]
                if len(mean_users) == 0:
                    continue

                post_indices: List[int] = []
                post_output_names: List[str] = []
                valid_posts = True
                for user_idx in mean_users:
                    user_op = model_ir.operators[int(user_idx)]
                    if (
                        str(user_op.op_type) != "TRANSPOSE"
                        or len(user_op.inputs) < 2
                        or len(user_op.outputs) != 1
                        or str(user_op.inputs[0]) != mean_out_name
                        or _read_transpose_perm(model_ir, user_op) != perm_nchw_to_nhwc
                    ):
                        valid_posts = False
                        break
                    post_indices.append(int(user_idx))
                    post_output_names.append(str(user_op.outputs[0]))
                if not valid_posts or len(post_indices) == 0:
                    continue

                # Commit axis remap only when this rewrite is actually applicable.
                _write_const_ints_to_tensor(mean_axes_tensor, [int(v) for v in mapped_axes])

                _set_operator_inputs(
                    model_ir=model_ir,
                    op=mean_op,
                    new_inputs=[pre_input_name, mean_axes_name],
                )
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(mean_out_name, None),
                    perm_nchw_to_nhwc,
                )

                representative_output_name = str(post_output_names[0])
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=mean_op,
                    new_outputs=[representative_output_name],
                )
                for alias_name in post_output_names[1:]:
                    _replace_tensor_inputs(model_ir, str(alias_name), representative_output_name)

                old_mean_tensor = model_ir.tensors.get(mean_out_name, None)
                representative_tensor = model_ir.tensors.get(representative_output_name, None)
                if old_mean_tensor is not None and representative_tensor is not None:
                    representative_tensor.dtype = str(old_mean_tensor.dtype)
                    representative_tensor.quantization = _clone_quantization(old_mean_tensor.quantization)
                    representative_tensor.shape = [int(v) for v in list(old_mean_tensor.shape)]
                    representative_tensor.shape_signature = (
                        [int(v) for v in list(old_mean_tensor.shape_signature)]
                        if old_mean_tensor.shape_signature is not None
                        else [int(v) for v in list(old_mean_tensor.shape)]
                    )
                    _permute_tensor_metadata_if_rank_matches(
                        representative_tensor,
                        perm_nchw_to_nhwc,
                    )

                remove_indices = set(int(v) for v in post_indices)
                pre_remaining_users = [int(v) for v in pre_users if int(v) != int(mean_idx)]
                if len(pre_remaining_users) == 0:
                    remove_indices.add(int(pre_idx))
                for remove_idx in sorted(list(remove_indices), reverse=True):
                    del model_ir.operators[int(remove_idx)]

                rewritten += 1
                changed = True
                break

            if changed:
                break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_mean_prepost_nhwc_passthrough_chains": int(rewritten)}


def _optimize_transpose_se_fc_mul_prepost_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate NCHW round-trips in SE-like gating blocks.

    Target:
      x_nhwc --T(0,3,1,2)--> x_nchw
      x_nhwc --AVG_POOL_2D--> p_nhwc --T(0,3,1,2)--> p_nchw
      p_nchw --RESHAPE--> r --FULLY_CONNECTED--> f --PRELU--> g --RESHAPE--> s_nchw
      MUL(x_nchw, s_nchw) -> m_nchw --T(0,2,3,1)--> m_nhwc

    Rewrite:
      - Bypass both pre-transposes and the post-transpose.
      - Keep AVG_POOL/FC/PRELU chain as-is, but rewrite final gate reshape to NHWC.
      - Feed MUL directly with x_nhwc and gate_nhwc.
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_mul_idx, pre_mul_op in enumerate(model_ir.operators):
            if str(pre_mul_op.op_type) != "TRANSPOSE" or len(pre_mul_op.inputs) < 2 or len(pre_mul_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_mul_op) != perm_nhwc_to_nchw:
                continue

            x_nhwc_name = str(pre_mul_op.inputs[0])
            x_nchw_name = str(pre_mul_op.outputs[0])
            if x_nchw_name in model_outputs:
                continue

            x_nchw_users = [int(v) for v in consumers.get(x_nchw_name, [])]
            if len(x_nchw_users) == 0:
                continue

            for mul_idx in x_nchw_users:
                mul_op = model_ir.operators[int(mul_idx)]
                if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                    continue

                mul_in0 = str(mul_op.inputs[0])
                mul_in1 = str(mul_op.inputs[1])
                if mul_in0 == x_nchw_name:
                    gate_name = str(mul_in1)
                    x_side_index = 0
                elif mul_in1 == x_nchw_name:
                    gate_name = str(mul_in0)
                    x_side_index = 1
                else:
                    continue

                gate_reshape_idx = producers.get(gate_name, None)
                if gate_reshape_idx is None:
                    continue
                gate_reshape_op = model_ir.operators[int(gate_reshape_idx)]
                if str(gate_reshape_op.op_type) != "RESHAPE" or len(gate_reshape_op.inputs) < 1 or len(gate_reshape_op.outputs) != 1:
                    continue
                if str(gate_reshape_op.outputs[0]) != gate_name:
                    continue
                if gate_name in model_outputs:
                    continue

                # Allow stacked MLP gate heads:
                #   RESHAPE -> (FULLY_CONNECTED -> PRELU)+ -> RESHAPE(gate)
                gate_mlp_input_name = str(gate_reshape_op.inputs[0])
                flat_idx: Optional[int] = None
                flat_op: Optional[OperatorIR] = None
                saw_fc = False
                max_hops = 16
                hop = 0
                while hop < max_hops:
                    producer_idx = producers.get(gate_mlp_input_name, None)
                    if producer_idx is None:
                        break
                    producer_op = model_ir.operators[int(producer_idx)]
                    producer_type = str(producer_op.op_type)
                    if (
                        producer_type == "RESHAPE"
                        and len(producer_op.inputs) >= 1
                        and len(producer_op.outputs) == 1
                        and str(producer_op.outputs[0]) == gate_mlp_input_name
                    ):
                        flat_idx = int(producer_idx)
                        flat_op = producer_op
                        break
                    if (
                        producer_type == "PRELU"
                        and len(producer_op.inputs) == 2
                        and len(producer_op.outputs) == 1
                        and str(producer_op.outputs[0]) == gate_mlp_input_name
                    ):
                        gate_mlp_input_name = str(producer_op.inputs[0])
                        hop += 1
                        continue
                    if (
                        producer_type == "FULLY_CONNECTED"
                        and len(producer_op.inputs) >= 2
                        and len(producer_op.outputs) == 1
                        and str(producer_op.outputs[0]) == gate_mlp_input_name
                    ):
                        saw_fc = True
                        gate_mlp_input_name = str(producer_op.inputs[0])
                        hop += 1
                        continue
                    break
                if flat_idx is None or flat_op is None or not saw_fc:
                    continue

                pre_gate_name = str(flat_op.inputs[0])
                pre_gate_idx = producers.get(pre_gate_name, None)
                if pre_gate_idx is None:
                    continue
                pre_gate_op = model_ir.operators[int(pre_gate_idx)]

                pool_out_name: Optional[str] = None
                pool_idx: Optional[int] = None
                removable_pre_gate_idx: Optional[int] = None

                # Legacy path: AVG_POOL_2D output is wrapped by NHWC->NCHW transpose.
                if (
                    str(pre_gate_op.op_type) == "TRANSPOSE"
                    and len(pre_gate_op.inputs) >= 2
                    and len(pre_gate_op.outputs) == 1
                    and str(pre_gate_op.outputs[0]) == pre_gate_name
                    and _read_transpose_perm(model_ir, pre_gate_op) == perm_nhwc_to_nchw
                    and pre_gate_name not in model_outputs
                ):
                    pool_out_name = str(pre_gate_op.inputs[0])
                    pool_idx = producers.get(pool_out_name, None)
                    removable_pre_gate_idx = int(pre_gate_idx)
                # Already optimized path: flatten consumes AVG_POOL_2D NHWC output directly.
                elif (
                    str(pre_gate_op.op_type) == "AVERAGE_POOL_2D"
                    and len(pre_gate_op.inputs) == 1
                    and len(pre_gate_op.outputs) == 1
                    and str(pre_gate_op.outputs[0]) == pre_gate_name
                ):
                    pool_out_name = str(pre_gate_name)
                    pool_idx = int(pre_gate_idx)
                    removable_pre_gate_idx = None
                else:
                    continue

                if pool_out_name is None or pool_idx is None:
                    continue
                pool_op = model_ir.operators[int(pool_idx)]
                if str(pool_op.op_type) != "AVERAGE_POOL_2D" or len(pool_op.inputs) != 1 or len(pool_op.outputs) != 1:
                    continue
                if str(pool_op.outputs[0]) != str(pool_out_name):
                    continue
                if str(pool_op.inputs[0]) != x_nhwc_name:
                    continue

                mul_out_name = str(mul_op.outputs[0])
                if mul_out_name in model_outputs:
                    continue
                mul_users = [int(v) for v in consumers.get(mul_out_name, [])]
                if len(mul_users) == 0:
                    continue

                post_indices: List[int] = []
                post_output_names: List[str] = []
                valid_posts = True
                for user_idx in mul_users:
                    user_op = model_ir.operators[int(user_idx)]
                    if (
                        str(user_op.op_type) != "TRANSPOSE"
                        or len(user_op.inputs) < 2
                        or len(user_op.outputs) != 1
                        or str(user_op.inputs[0]) != mul_out_name
                        or _read_transpose_perm(model_ir, user_op) != perm_nchw_to_nhwc
                        or str(user_op.outputs[0]) in model_outputs
                    ):
                        valid_posts = False
                        break
                    post_indices.append(int(user_idx))
                    post_output_names.append(str(user_op.outputs[0]))
                if not valid_posts or len(post_indices) == 0:
                    continue

                # Rewrite gate reshape shape [N,C,H,W] -> [N,H,W,C].
                shape_rewritten = False
                if len(gate_reshape_op.inputs) >= 2:
                    gate_shape_name = str(gate_reshape_op.inputs[1])
                    gate_shape_tensor = model_ir.tensors.get(gate_shape_name, None)
                    gate_shape_vals = _read_const_ints_from_tensor(gate_shape_tensor)
                    if gate_shape_vals is not None and len(gate_shape_vals) == 4:
                        swapped_shape = [
                            int(gate_shape_vals[0]),
                            int(gate_shape_vals[2]),
                            int(gate_shape_vals[3]),
                            int(gate_shape_vals[1]),
                        ]
                        _write_const_ints_to_tensor(gate_shape_tensor, swapped_shape)
                        shape_rewritten = True

                if isinstance(gate_reshape_op.options, dict):
                    opts = dict(gate_reshape_op.options)
                    options_changed = False
                    for key in ["newShape", "onnxRawNewShape"]:
                        value = opts.get(key, None)
                        if not isinstance(value, list) or len(value) != 4:
                            continue
                        swapped_value = [
                            int(value[0]),
                            int(value[2]),
                            int(value[3]),
                            int(value[1]),
                        ]
                        if [int(v) for v in list(value)] != swapped_value:
                            opts[key] = swapped_value
                            options_changed = True
                            shape_rewritten = True
                    if options_changed:
                        gate_reshape_op.options = opts

                if not shape_rewritten:
                    continue

                # Bypass pre-gate transpose into flatten reshape when present.
                if removable_pre_gate_idx is not None:
                    _replace_operator_input_at(
                        model_ir=model_ir,
                        op=flat_op,
                        input_index=0,
                        new_input_name=pool_out_name,
                    )

                # Bypass pre-mul transpose into MUL.
                mul_inputs = [str(v) for v in list(mul_op.inputs)]
                mul_inputs[int(x_side_index)] = str(x_nhwc_name)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=mul_op,
                    new_inputs=mul_inputs,
                )

                # Gate/MUL metadata: convert from NCHW to NHWC.
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(gate_name, None),
                    perm_nchw_to_nhwc,
                )
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(mul_out_name, None),
                    perm_nchw_to_nhwc,
                )

                # Remove post transpose by letting MUL produce NHWC directly.
                representative_output_name = str(post_output_names[0])
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=mul_op,
                    new_outputs=[representative_output_name],
                )
                for alias_name in post_output_names[1:]:
                    _replace_tensor_inputs(model_ir, alias_name, representative_output_name)

                old_mul_tensor = model_ir.tensors.get(mul_out_name, None)
                representative_tensor = model_ir.tensors.get(representative_output_name, None)
                if old_mul_tensor is not None and representative_tensor is not None:
                    representative_tensor.dtype = str(old_mul_tensor.dtype)
                    representative_tensor.quantization = _clone_quantization(old_mul_tensor.quantization)
                    representative_tensor.shape = [int(v) for v in list(old_mul_tensor.shape)]
                    representative_tensor.shape_signature = (
                        [int(v) for v in list(old_mul_tensor.shape_signature)]
                        if old_mul_tensor.shape_signature is not None
                        else [int(v) for v in list(old_mul_tensor.shape)]
                    )
                    _permute_tensor_metadata_if_rank_matches(
                        representative_tensor,
                        perm_nchw_to_nhwc,
                    )

                remove_indices = set(int(v) for v in post_indices)
                pre_mul_remaining_users = [int(v) for v in x_nchw_users if int(v) != int(mul_idx)]
                if len(pre_mul_remaining_users) == 0:
                    remove_indices.add(int(pre_mul_idx))

                if removable_pre_gate_idx is not None:
                    pre_gate_users = [int(v) for v in consumers.get(pre_gate_name, [])]
                    pre_gate_remaining_users = [int(v) for v in pre_gate_users if int(v) != int(flat_idx)]
                    if len(pre_gate_remaining_users) == 0:
                        remove_indices.add(int(removable_pre_gate_idx))

                for remove_idx in sorted(list(remove_indices), reverse=True):
                    del model_ir.operators[int(remove_idx)]

                rewritten += 1
                changed = True
                break

            if changed:
                break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_se_fc_mul_prepost_nhwc_chains": int(rewritten)}


def _optimize_transpose_sum_logistic_muladd_prepost_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate NCHW round-trips around SUM/LOGISTIC/SUB + MUL + ADD merge blocks.

    Target:
      a_nhwc --T(0,3,1,2)--> a_nchw
      b_nhwc --T(0,3,1,2)--> b_nchw
      c_nhwc --T(0,3,1,2)--> c_nchw --SUM(axis=1, keepDims=True)--> s_nchw --LOGISTIC--> sig_nchw
      one-sigmoid branch: SUB(one, sig_nchw) -> sub_nchw (optional)
      MUL(sub_or_sig_nchw, a_nchw) -> m0_nchw
      MUL(sig_nchw, b_nchw)        -> m1_nchw
      ADD(m0_nchw, m1_nchw) -> y_nchw
      y_nchw --T(0,2,3,1)--> y_nhwc

    Rewrite:
      - Bypass all three pre-transposes (a/b/c) to NHWC.
      - Remap SUM reduction axes from NCHW to NHWC.
      - Keep SUM/LOGISTIC/SUB/MUL/ADD in NHWC.
      - Remove post-transpose by making ADD produce NHWC output directly.
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        def _extract_mul_pre_gate(
            mul_idx: int,
        ) -> Optional[Tuple[int, str, str, str]]:
            mul_op = model_ir.operators[int(mul_idx)]
            if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                return None
            pre_idx: Optional[int] = None
            pre_input_name: Optional[str] = None
            pre_output_name: Optional[str] = None
            gate_name: Optional[str] = None
            for input_name in list(mul_op.inputs):
                prod_idx = producers.get(str(input_name), None)
                if prod_idx is not None:
                    prod_op = model_ir.operators[int(prod_idx)]
                    if (
                        str(prod_op.op_type) == "TRANSPOSE"
                        and len(prod_op.inputs) >= 2
                        and len(prod_op.outputs) == 1
                        and str(prod_op.outputs[0]) == str(input_name)
                        and _read_transpose_perm(model_ir, prod_op) == perm_nhwc_to_nchw
                        and str(prod_op.inputs[0]) not in model_outputs
                        and str(prod_op.outputs[0]) not in model_outputs
                    ):
                        if pre_idx is not None:
                            return None
                        pre_idx = int(prod_idx)
                        pre_input_name = str(prod_op.inputs[0])
                        pre_output_name = str(prod_op.outputs[0])
                        continue
                if gate_name is not None:
                    return None
                gate_name = str(input_name)
            if pre_idx is None or pre_input_name is None or pre_output_name is None or gate_name is None:
                return None
            return int(pre_idx), str(pre_input_name), str(pre_output_name), str(gate_name)

        for post_idx, post_op in enumerate(model_ir.operators):
            if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc:
                continue
            add_output_name = str(post_op.inputs[0])
            post_output_name = str(post_op.outputs[0])
            if add_output_name in model_outputs or post_output_name in model_outputs:
                continue

            add_idx = producers.get(add_output_name, None)
            if add_idx is None:
                continue
            add_op = model_ir.operators[int(add_idx)]
            if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                continue
            if str(add_op.outputs[0]) != add_output_name:
                continue

            add_inputs = [str(v) for v in list(add_op.inputs)]
            mul0_idx = producers.get(add_inputs[0], None)
            mul1_idx = producers.get(add_inputs[1], None)
            if mul0_idx is None or mul1_idx is None:
                continue
            if int(mul0_idx) == int(mul1_idx):
                continue

            mul0_info = _extract_mul_pre_gate(int(mul0_idx))
            mul1_info = _extract_mul_pre_gate(int(mul1_idx))
            if mul0_info is None or mul1_info is None:
                continue

            pre0_idx, pre0_in_name, pre0_out_name, gate0_name = mul0_info
            pre1_idx, pre1_in_name, pre1_out_name, gate1_name = mul1_info
            if int(pre0_idx) == int(pre1_idx):
                continue

            # Identify LOGISTIC gate and optional SUB(one, sigmoid) gate.
            logistic_idx: Optional[int] = None
            logistic_out_name: Optional[str] = None
            sub_idx: Optional[int] = None
            sub_out_name: Optional[str] = None

            def _try_resolve_gate_pair(
                g_logistic: str,
                g_other: str,
            ) -> Optional[Tuple[int, str, Optional[int], Optional[str]]]:
                g_logistic_prod = producers.get(str(g_logistic), None)
                if g_logistic_prod is None:
                    return None
                g_logistic_op = model_ir.operators[int(g_logistic_prod)]
                if str(g_logistic_op.op_type) != "LOGISTIC" or len(g_logistic_op.outputs) != 1:
                    return None
                if str(g_logistic_op.outputs[0]) != str(g_logistic):
                    return None
                if str(g_other) == str(g_logistic):
                    return int(g_logistic_prod), str(g_logistic), None, None
                g_other_prod = producers.get(str(g_other), None)
                if g_other_prod is None:
                    return None
                g_other_op = model_ir.operators[int(g_other_prod)]
                if str(g_other_op.op_type) != "SUB" or len(g_other_op.inputs) != 2 or len(g_other_op.outputs) != 1:
                    return None
                if str(g_other_op.outputs[0]) != str(g_other):
                    return None
                if str(g_logistic) not in {str(v) for v in list(g_other_op.inputs)}:
                    return None
                return int(g_logistic_prod), str(g_logistic), int(g_other_prod), str(g_other)

            resolved = _try_resolve_gate_pair(gate0_name, gate1_name)
            if resolved is None:
                resolved = _try_resolve_gate_pair(gate1_name, gate0_name)
            if resolved is None:
                continue
            logistic_idx, logistic_out_name, sub_idx, sub_out_name = resolved

            logistic_op = model_ir.operators[int(logistic_idx)]
            if len(logistic_op.inputs) != 1:
                continue
            sum_output_name = str(logistic_op.inputs[0])
            if sum_output_name in model_outputs:
                continue

            sum_idx = producers.get(sum_output_name, None)
            if sum_idx is None:
                continue
            sum_op = model_ir.operators[int(sum_idx)]
            if str(sum_op.op_type) != "SUM" or len(sum_op.inputs) < 2 or len(sum_op.outputs) != 1:
                continue
            if str(sum_op.outputs[0]) != sum_output_name:
                continue
            if str(sum_op.inputs[0]) in model_outputs:
                continue

            pre2_out_name = str(sum_op.inputs[0])
            pre2_idx = producers.get(pre2_out_name, None)
            if pre2_idx is None:
                continue
            pre2_op = model_ir.operators[int(pre2_idx)]
            if (
                str(pre2_op.op_type) != "TRANSPOSE"
                or len(pre2_op.inputs) < 2
                or len(pre2_op.outputs) != 1
                or str(pre2_op.outputs[0]) != pre2_out_name
                or _read_transpose_perm(model_ir, pre2_op) != perm_nhwc_to_nchw
            ):
                continue
            pre2_in_name = str(pre2_op.inputs[0])
            if pre2_in_name in model_outputs or pre2_out_name in model_outputs:
                continue

            # Pre-transpose outputs must be local to this chain.
            if set(int(v) for v in consumers.get(pre0_out_name, [])) != {int(mul0_idx)} and set(
                int(v) for v in consumers.get(pre0_out_name, [])
            ) != {int(mul1_idx)}:
                continue
            if set(int(v) for v in consumers.get(pre1_out_name, [])) != {int(mul0_idx)} and set(
                int(v) for v in consumers.get(pre1_out_name, [])
            ) != {int(mul1_idx)}:
                continue
            if set(int(v) for v in consumers.get(pre2_out_name, [])) != {int(sum_idx)}:
                continue

            # ADD output must fan out only to inverse post-transposes.
            add_out_users = [int(v) for v in consumers.get(add_output_name, [])]
            if len(add_out_users) == 0:
                continue
            post_indices: List[int] = []
            post_output_names: List[str] = []
            valid_posts = True
            for user_idx in add_out_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == add_output_name
                    and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                    and str(user_op.outputs[0]) not in model_outputs
                ):
                    post_indices.append(int(user_idx))
                    post_output_names.append(str(user_op.outputs[0]))
                else:
                    valid_posts = False
                    break
            if not valid_posts or len(post_indices) == 0:
                continue

            # Remap SUM axes from NCHW to NHWC.
            sum_axes_name = str(sum_op.inputs[1])
            sum_axes_tensor = model_ir.tensors.get(sum_axes_name, None)
            sum_axes_vals = _read_const_ints_from_tensor(sum_axes_tensor)
            if sum_axes_vals is None or len(sum_axes_vals) == 0:
                continue
            rank = 4
            pre2_in_tensor = model_ir.tensors.get(pre2_in_name, None)
            if pre2_in_tensor is not None and pre2_in_tensor.shape is not None and len(pre2_in_tensor.shape) > 0:
                rank = int(len(pre2_in_tensor.shape))
            if rank != 4:
                continue
            old_to_new_axis = _invert_perm(perm_nchw_to_nhwc)
            if old_to_new_axis is None:
                continue
            mapped_axes: List[int] = []
            valid_axes = True
            for axis in sum_axes_vals:
                a = int(axis)
                if a < 0:
                    a += int(rank)
                if a < 0 or a >= int(rank):
                    valid_axes = False
                    break
                mapped_axes.append(int(old_to_new_axis[int(a)]))
            if not valid_axes or len(mapped_axes) == 0:
                continue
            _write_const_ints_to_tensor(sum_axes_tensor, [int(v) for v in mapped_axes])

            # Rewire SUM to NHWC source.
            sum_inputs = [str(v) for v in list(sum_op.inputs)]
            sum_inputs[0] = str(pre2_in_name)
            _set_operator_inputs(
                model_ir=model_ir,
                op=sum_op,
                new_inputs=sum_inputs,
            )

            # Rewire both MULs from transpose outputs to transpose inputs.
            for mul_idx, pre_out_name, pre_in_name in [
                (int(mul0_idx), str(pre0_out_name), str(pre0_in_name)),
                (int(mul1_idx), str(pre1_out_name), str(pre1_in_name)),
            ]:
                mul_op = model_ir.operators[int(mul_idx)]
                mul_inputs = [str(v) for v in list(mul_op.inputs)]
                replaced = False
                for in_idx, in_name in enumerate(list(mul_inputs)):
                    if str(in_name) == str(pre_out_name):
                        mul_inputs[in_idx] = str(pre_in_name)
                        replaced = True
                if not replaced:
                    valid_posts = False
                    break
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=mul_op,
                    new_inputs=mul_inputs,
                )
            if not valid_posts:
                continue

            # Update metadata to NHWC across the rewritten chain.
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(sum_output_name, None),
                perm_nchw_to_nhwc,
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(logistic_out_name), None),
                perm_nchw_to_nhwc,
            )
            if sub_out_name is not None:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(sub_out_name), None),
                    perm_nchw_to_nhwc,
                )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(model_ir.operators[int(mul0_idx)].outputs[0]), None),
                perm_nchw_to_nhwc,
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(model_ir.operators[int(mul1_idx)].outputs[0]), None),
                perm_nchw_to_nhwc,
            )

            # Canonicalize ADD output to post-transpose output tensor.
            canonical_post_output_name = str(post_output_names[0])
            _set_operator_outputs(
                model_ir=model_ir,
                op=add_op,
                new_outputs=[canonical_post_output_name],
            )
            for alias_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, str(alias_name), canonical_post_output_name)

            old_add_out_tensor = model_ir.tensors.get(add_output_name, None)
            canonical_tensor = model_ir.tensors.get(canonical_post_output_name, None)
            if old_add_out_tensor is not None and canonical_tensor is not None:
                canonical_tensor.dtype = str(old_add_out_tensor.dtype)
                canonical_tensor.quantization = _clone_quantization(old_add_out_tensor.quantization)
                canonical_tensor.shape = [int(v) for v in list(old_add_out_tensor.shape)]
                canonical_tensor.shape_signature = (
                    [int(v) for v in list(old_add_out_tensor.shape_signature)]
                    if old_add_out_tensor.shape_signature is not None
                    else [int(v) for v in list(old_add_out_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    canonical_tensor,
                    perm_nchw_to_nhwc,
                )

            remove_indices = {
                int(pre0_idx),
                int(pre1_idx),
                int(pre2_idx),
                *[int(v) for v in post_indices],
            }
            for remove_idx in sorted(remove_indices, reverse=True):
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_sum_logistic_muladd_prepost_nhwc_chains": int(rewritten)}


def _optimize_transpose_logistic_sub_muladd_dual_postconv_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate NCHW round-trips around a logistic/sub-gated dual-MUL/ADD block feeding two convs.

    Target:
      g_nhwc --T(0,3,1,2)--> g_nchw --LOGISTIC--> sig_nchw --SUB(1, sig)->sub_nchw
      a_nhwc --T(0,3,1,2)--> a_nchw
      b_nhwc --T(0,3,1,2)--> b_nchw
      MUL(sig_nchw, a_nchw) -> m0_nchw
      MUL(sub_nchw, b_nchw) -> m1_nchw
      ADD(b_nchw, m0_nchw)  -> y0_nchw --T(0,2,3,1)--> y0_nhwc -> CONV
      ADD(m1_nchw, a_nchw)  -> y1_nchw --T(0,2,3,1)--> y1_nhwc -> CONV

    Rewrite:
      - Bypass all three pre-transposes to NHWC.
      - Keep LOGISTIC/SUB/MUL/ADD in NHWC.
      - Remove both post-transposes and feed CONV inputs directly.
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for gate_pre_idx, gate_pre_op in enumerate(model_ir.operators):
            if str(gate_pre_op.op_type) != "TRANSPOSE" or len(gate_pre_op.inputs) < 2 or len(gate_pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, gate_pre_op) != perm_nhwc_to_nchw:
                continue

            gate_pre_in_name = str(gate_pre_op.inputs[0])
            gate_pre_out_name = str(gate_pre_op.outputs[0])
            if gate_pre_in_name in model_outputs or gate_pre_out_name in model_outputs:
                continue

            gate_users = [int(v) for v in consumers.get(gate_pre_out_name, [])]
            if len(gate_users) != 1:
                continue
            logistic_idx = int(gate_users[0])
            logistic_op = model_ir.operators[int(logistic_idx)]
            if str(logistic_op.op_type) != "LOGISTIC" or len(logistic_op.inputs) != 1 or len(logistic_op.outputs) != 1:
                continue
            if str(logistic_op.inputs[0]) != gate_pre_out_name:
                continue

            logistic_out_name = str(logistic_op.outputs[0])
            if logistic_out_name in model_outputs:
                continue
            logistic_users = [int(v) for v in consumers.get(logistic_out_name, [])]
            if len(logistic_users) != 2:
                continue

            sub_idx: Optional[int] = None
            mul_sig_idx: Optional[int] = None
            for user_idx in logistic_users:
                user_op = model_ir.operators[int(user_idx)]
                if str(user_op.op_type) == "SUB":
                    if sub_idx is not None:
                        sub_idx = None
                        break
                    sub_idx = int(user_idx)
                elif str(user_op.op_type) == "MUL":
                    if mul_sig_idx is not None:
                        mul_sig_idx = None
                        break
                    mul_sig_idx = int(user_idx)
            if sub_idx is None or mul_sig_idx is None:
                continue

            sub_op = model_ir.operators[int(sub_idx)]
            if len(sub_op.inputs) != 2 or len(sub_op.outputs) != 1:
                continue
            if str(sub_op.outputs[0]) in model_outputs:
                continue
            if str(logistic_out_name) not in {str(v) for v in list(sub_op.inputs)}:
                continue
            sub_out_name = str(sub_op.outputs[0])
            sub_users = [int(v) for v in consumers.get(sub_out_name, [])]
            if len(sub_users) != 1:
                continue
            mul_sub_idx = int(sub_users[0])
            mul_sub_op = model_ir.operators[int(mul_sub_idx)]
            if str(mul_sub_op.op_type) != "MUL" or len(mul_sub_op.inputs) != 2 or len(mul_sub_op.outputs) != 1:
                continue

            mul_sig_op = model_ir.operators[int(mul_sig_idx)]
            if str(mul_sig_op.op_type) != "MUL" or len(mul_sig_op.inputs) != 2 or len(mul_sig_op.outputs) != 1:
                continue

            def _resolve_pre_for_mul(
                mul_op: OperatorIR,
                gate_tensor_candidates: List[str],
            ) -> Optional[Tuple[int, str, str]]:
                pre_idx_local: Optional[int] = None
                pre_in_name_local: Optional[str] = None
                pre_out_name_local: Optional[str] = None
                for input_name in list(mul_op.inputs):
                    if str(input_name) in set(str(v) for v in gate_tensor_candidates):
                        continue
                    prod_idx = producers.get(str(input_name), None)
                    if prod_idx is None:
                        continue
                    prod_op = model_ir.operators[int(prod_idx)]
                    if (
                        str(prod_op.op_type) == "TRANSPOSE"
                        and len(prod_op.inputs) >= 2
                        and len(prod_op.outputs) == 1
                        and str(prod_op.outputs[0]) == str(input_name)
                        and _read_transpose_perm(model_ir, prod_op) == perm_nhwc_to_nchw
                        and str(prod_op.inputs[0]) not in model_outputs
                        and str(prod_op.outputs[0]) not in model_outputs
                    ):
                        pre_idx_local = int(prod_idx)
                        pre_in_name_local = str(prod_op.inputs[0])
                        pre_out_name_local = str(prod_op.outputs[0])
                        break
                if pre_idx_local is None or pre_in_name_local is None or pre_out_name_local is None:
                    return None
                return int(pre_idx_local), str(pre_in_name_local), str(pre_out_name_local)

            sig_pre_info = _resolve_pre_for_mul(
                mul_sig_op,
                gate_tensor_candidates=[str(logistic_out_name)],
            )
            sub_pre_info = _resolve_pre_for_mul(
                mul_sub_op,
                gate_tensor_candidates=[str(sub_out_name)],
            )
            if sig_pre_info is None or sub_pre_info is None:
                continue

            sig_pre_idx, sig_pre_in_name, sig_pre_out_name = sig_pre_info
            sub_pre_idx, sub_pre_in_name, sub_pre_out_name = sub_pre_info
            if int(sig_pre_idx) == int(sub_pre_idx):
                continue

            mul_sig_out_name = str(mul_sig_op.outputs[0])
            mul_sub_out_name = str(mul_sub_op.outputs[0])
            if mul_sig_out_name in model_outputs or mul_sub_out_name in model_outputs:
                continue
            mul_sig_users = [int(v) for v in consumers.get(mul_sig_out_name, [])]
            mul_sub_users = [int(v) for v in consumers.get(mul_sub_out_name, [])]
            if len(mul_sig_users) != 1 or len(mul_sub_users) != 1:
                continue
            add_sig_idx = int(mul_sig_users[0])
            add_sub_idx = int(mul_sub_users[0])
            if int(add_sig_idx) == int(add_sub_idx):
                continue
            add_sig_op = model_ir.operators[int(add_sig_idx)]
            add_sub_op = model_ir.operators[int(add_sub_idx)]
            if str(add_sig_op.op_type) != "ADD" or len(add_sig_op.inputs) != 2 or len(add_sig_op.outputs) != 1:
                continue
            if str(add_sub_op.op_type) != "ADD" or len(add_sub_op.inputs) != 2 or len(add_sub_op.outputs) != 1:
                continue

            add_sig_inputs = [str(v) for v in list(add_sig_op.inputs)]
            add_sub_inputs = [str(v) for v in list(add_sub_op.inputs)]
            if str(mul_sig_out_name) not in set(add_sig_inputs):
                continue
            if str(mul_sub_out_name) not in set(add_sub_inputs):
                continue
            add_sig_other = (
                add_sig_inputs[1] if add_sig_inputs[0] == str(mul_sig_out_name) else add_sig_inputs[0]
            )
            add_sub_other = (
                add_sub_inputs[1] if add_sub_inputs[0] == str(mul_sub_out_name) else add_sub_inputs[0]
            )
            if set([str(add_sig_other), str(add_sub_other)]) != set([str(sig_pre_out_name), str(sub_pre_out_name)]):
                continue

            add_sig_out_name = str(add_sig_op.outputs[0])
            add_sub_out_name = str(add_sub_op.outputs[0])
            if add_sig_out_name in model_outputs or add_sub_out_name in model_outputs:
                continue

            def _collect_inverse_posts(add_out_name: str) -> Optional[Tuple[List[int], List[str]]]:
                out_users = [int(v) for v in consumers.get(str(add_out_name), [])]
                if len(out_users) == 0:
                    return None
                post_indices_local: List[int] = []
                post_output_names_local: List[str] = []
                for u_idx in out_users:
                    u_op = model_ir.operators[int(u_idx)]
                    if (
                        str(u_op.op_type) == "TRANSPOSE"
                        and len(u_op.inputs) >= 2
                        and len(u_op.outputs) == 1
                        and str(u_op.inputs[0]) == str(add_out_name)
                        and _read_transpose_perm(model_ir, u_op) == perm_nchw_to_nhwc
                        and str(u_op.outputs[0]) not in model_outputs
                    ):
                        post_indices_local.append(int(u_idx))
                        post_output_names_local.append(str(u_op.outputs[0]))
                    else:
                        return None
                return post_indices_local, post_output_names_local

            sig_post_info = _collect_inverse_posts(add_sig_out_name)
            sub_post_info = _collect_inverse_posts(add_sub_out_name)
            if sig_post_info is None or sub_post_info is None:
                continue
            sig_post_indices, sig_post_output_names = sig_post_info
            sub_post_indices, sub_post_output_names = sub_post_info

            # Ensure pre-transpose outputs are local to this chain.
            allowed_users = {
                int(mul_sig_idx),
                int(mul_sub_idx),
                int(add_sig_idx),
                int(add_sub_idx),
            }
            if not set(int(v) for v in consumers.get(str(sig_pre_out_name), [])).issubset(allowed_users):
                continue
            if not set(int(v) for v in consumers.get(str(sub_pre_out_name), [])).issubset(allowed_users):
                continue

            # 1) Bypass gate pre-transpose.
            _set_operator_inputs(
                model_ir=model_ir,
                op=logistic_op,
                new_inputs=[str(gate_pre_in_name)],
            )

            # 2) Bypass the two data pre-transposes in MUL and ADD.
            for mul_op, pre_out_name, pre_in_name in [
                (mul_sig_op, sig_pre_out_name, sig_pre_in_name),
                (mul_sub_op, sub_pre_out_name, sub_pre_in_name),
            ]:
                mul_inputs = [str(v) for v in list(mul_op.inputs)]
                mul_inputs = [
                    str(pre_in_name) if str(v) == str(pre_out_name) else str(v)
                    for v in mul_inputs
                ]
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=mul_op,
                    new_inputs=mul_inputs,
                )

            for add_op, pre_out_name, pre_in_name in [
                (add_sig_op, sig_pre_out_name, sig_pre_in_name),
                (add_sig_op, sub_pre_out_name, sub_pre_in_name),
                (add_sub_op, sig_pre_out_name, sig_pre_in_name),
                (add_sub_op, sub_pre_out_name, sub_pre_in_name),
            ]:
                add_inputs = [str(v) for v in list(add_op.inputs)]
                rewritten_inputs = [
                    str(pre_in_name) if str(v) == str(pre_out_name) else str(v)
                    for v in add_inputs
                ]
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=add_op,
                    new_inputs=rewritten_inputs,
                )

            # 3) Mark rewritten intermediates as NHWC.
            for tensor_name in [
                str(logistic_out_name),
                str(sub_out_name),
                str(mul_sig_out_name),
                str(mul_sub_out_name),
                str(add_sig_out_name),
                str(add_sub_out_name),
            ]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(tensor_name), None),
                    perm_nchw_to_nhwc,
                )

            # 4) Bypass both post-transpose groups.
            for add_op, old_add_out_name, post_output_names in [
                (add_sig_op, add_sig_out_name, sig_post_output_names),
                (add_sub_op, add_sub_out_name, sub_post_output_names),
            ]:
                canonical_post_output_name = str(post_output_names[0])
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=add_op,
                    new_outputs=[canonical_post_output_name],
                )
                for alias_name in list(post_output_names[1:]):
                    _replace_tensor_inputs(model_ir, str(alias_name), canonical_post_output_name)

                old_add_out_tensor = model_ir.tensors.get(str(old_add_out_name), None)
                canonical_tensor = model_ir.tensors.get(str(canonical_post_output_name), None)
                if old_add_out_tensor is not None and canonical_tensor is not None:
                    canonical_tensor.dtype = str(old_add_out_tensor.dtype)
                    canonical_tensor.quantization = _clone_quantization(old_add_out_tensor.quantization)
                    canonical_tensor.shape = [int(v) for v in list(old_add_out_tensor.shape)]
                    canonical_tensor.shape_signature = (
                        [int(v) for v in list(old_add_out_tensor.shape_signature)]
                        if old_add_out_tensor.shape_signature is not None
                        else [int(v) for v in list(old_add_out_tensor.shape)]
                    )
                    _permute_tensor_metadata_if_rank_matches(
                        canonical_tensor,
                        perm_nchw_to_nhwc,
                    )

            remove_indices = {
                int(gate_pre_idx),
                int(sig_pre_idx),
                int(sub_pre_idx),
                *[int(v) for v in sig_post_indices],
                *[int(v) for v in sub_post_indices],
            }
            for remove_idx in sorted(remove_indices, reverse=True):
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_logistic_sub_muladd_dual_postconv_nhwc_chains": int(rewritten)}


def _optimize_transpose_conv_attention_nhwc_propagation_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Propagate NHWC layout through Conv-attention motifs and remove bridge transposes.

    Target motif (rank-4):
      x_nhwc --T(0,3,1,2)--> x_nchw --ACT--> a_nchw
      a_nchw --MEAN(keepDims=True, axes in NCHW)--> m_nchw --T(0,2,3,1)--> m_nhwc --CONV--CONV--> c_nhwc
      c_nhwc --T(0,3,1,2)--> c_nchw --GATE--> s_nchw
      MUL(a_nchw, s_nchw) --> y_nchw --T(0,2,3,1)--> y_nhwc

    Rewrite:
      - bypass both NCHW pre-transposes and all post-transposes in the motif
      - remap MEAN axes from NCHW to NHWC
      - keep ACT/MEAN/GATE/MUL in NHWC

    Supported GATE:
      - LOGISTIC
      - HardSigmoid expansion: MUL(const)->ADD(const)->RELU_0_TO_1
      - HardSigmoid expansion: MUL(const)->ADD(const)->MAXIMUM(const)->MINIMUM(const)
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    perm_nhwc_to_nchw_const_name = "__nhwc_to_nchw_perm_rank4__"
    activation_ops = {"RELU", "LEAKY_RELU", "RELU6"}
    legacy_consumer_safe_ops = {
        "ADD",
        "SUB",
        "MUL",
        "DIV",
        "MAXIMUM",
        "MINIMUM",
        "RELU",
        "RELU6",
        "LEAKY_RELU",
        "LOGISTIC",
        "TANH",
        "NEG",
        "ABS",
        "SQRT",
        "EXP",
    }

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    if perm_nhwc_to_nchw_const_name not in model_ir.tensors:
        model_ir.tensors[perm_nhwc_to_nchw_const_name] = TensorIR(
            name=perm_nhwc_to_nchw_const_name,
            dtype="INT32",
            shape=[4],
            shape_signature=[4],
            data=np.asarray(perm_nhwc_to_nchw, dtype=np.int32),
            is_variable=False,
            quantization=None,
        )

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        def _match_hardsigmoid_gate_from_output(gate_output_name: str) -> Optional[Dict[str, Any]]:
            gate_idx = producers.get(str(gate_output_name), None)
            if gate_idx is None:
                return None
            gate_op = model_ir.operators[int(gate_idx)]
            gate_type = str(gate_op.op_type)
            add_output_name: Optional[str] = None
            chain_indices: List[int] = []
            metadata_names: List[str] = []

            if gate_type == "RELU_0_TO_1":
                if len(gate_op.inputs) != 1 or len(gate_op.outputs) != 1:
                    return None
                add_output_name = str(gate_op.inputs[0])
                if set(int(v) for v in consumers.get(add_output_name, [])) != {int(gate_idx)}:
                    return None
                chain_indices.append(int(gate_idx))
                metadata_names.append(str(gate_output_name))
            elif gate_type == "MINIMUM":
                if len(gate_op.inputs) != 2 or len(gate_op.outputs) != 1:
                    return None
                min_inputs = [str(v) for v in list(gate_op.inputs)]
                max_output_name: Optional[str] = None
                min_side_name: Optional[str] = None
                for candidate_name, other_name in [(min_inputs[0], min_inputs[1]), (min_inputs[1], min_inputs[0])]:
                    producer_idx = producers.get(candidate_name, None)
                    if producer_idx is None:
                        continue
                    producer_op = model_ir.operators[int(producer_idx)]
                    if str(producer_op.op_type) != "MAXIMUM":
                        continue
                    max_output_name = str(candidate_name)
                    min_side_name = str(other_name)
                    break
                if max_output_name is None or min_side_name is None:
                    return None
                if not _is_singleton_constant_tensor(model_ir, min_side_name):
                    return None
                if set(int(v) for v in consumers.get(max_output_name, [])) != {int(gate_idx)}:
                    return None

                max_idx = producers.get(max_output_name, None)
                if max_idx is None:
                    return None
                max_op = model_ir.operators[int(max_idx)]
                if str(max_op.op_type) != "MAXIMUM" or len(max_op.inputs) != 2 or len(max_op.outputs) != 1:
                    return None
                max_inputs = [str(v) for v in list(max_op.inputs)]
                for candidate_name, other_name in [(max_inputs[0], max_inputs[1]), (max_inputs[1], max_inputs[0])]:
                    producer_idx = producers.get(candidate_name, None)
                    if producer_idx is None:
                        continue
                    producer_op = model_ir.operators[int(producer_idx)]
                    if str(producer_op.op_type) != "ADD":
                        continue
                    add_output_name = str(candidate_name)
                    if not _is_singleton_constant_tensor(model_ir, str(other_name)):
                        return None
                    break
                if add_output_name is None:
                    return None
                if set(int(v) for v in consumers.get(add_output_name, [])) != {int(max_idx)}:
                    return None
                chain_indices.extend([int(max_idx), int(gate_idx)])
                metadata_names.extend([max_output_name, str(gate_output_name)])
            else:
                return None

            add_idx = producers.get(str(add_output_name), None)
            if add_idx is None:
                return None
            add_op = model_ir.operators[int(add_idx)]
            if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                return None
            add_inputs = [str(v) for v in list(add_op.inputs)]
            mul_output_name: Optional[str] = None
            for candidate_name, other_name in [(add_inputs[0], add_inputs[1]), (add_inputs[1], add_inputs[0])]:
                producer_idx = producers.get(candidate_name, None)
                if producer_idx is None:
                    continue
                producer_op = model_ir.operators[int(producer_idx)]
                if str(producer_op.op_type) != "MUL":
                    continue
                if not _is_singleton_constant_tensor(model_ir, str(other_name)):
                    return None
                mul_output_name = str(candidate_name)
                break
            if mul_output_name is None:
                return None
            if set(int(v) for v in consumers.get(mul_output_name, [])) != {int(add_idx)}:
                return None
            chain_indices.append(int(add_idx))
            metadata_names.insert(0, str(add_output_name))

            mul_idx = producers.get(mul_output_name, None)
            if mul_idx is None:
                return None
            mul_op = model_ir.operators[int(mul_idx)]
            if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                return None
            mul_inputs = [str(v) for v in list(mul_op.inputs)]
            main_input_name: Optional[str] = None
            main_input_index: Optional[int] = None
            for input_index, input_name in enumerate(mul_inputs):
                side_name = str(mul_inputs[1 - input_index])
                if _is_singleton_constant_tensor(model_ir, side_name):
                    main_input_name = str(input_name)
                    main_input_index = int(input_index)
                    break
            if main_input_name is None or main_input_index is None:
                return None

            chain_indices.append(int(mul_idx))
            metadata_names.insert(0, str(mul_output_name))

            return {
                "head_idx": int(mul_idx),
                "head_input_name": str(main_input_name),
                "head_input_index": int(main_input_index),
                "output_name": str(gate_output_name),
                "chain_indices": [int(v) for v in chain_indices],
                "metadata_names": [str(v) for v in metadata_names],
            }

        def _match_hardswish_activation_from_output(activation_output_name: str) -> Optional[Dict[str, Any]]:
            activation_idx = producers.get(str(activation_output_name), None)
            if activation_idx is None:
                return None
            activation_op = model_ir.operators[int(activation_idx)]
            if (
                str(activation_op.op_type) != "MUL"
                or len(activation_op.inputs) != 2
                or len(activation_op.outputs) != 1
                or str(activation_op.outputs[0]) != str(activation_output_name)
            ):
                return None

            activation_inputs = [str(v) for v in list(activation_op.inputs)]
            for data_input_index in [0, 1]:
                data_input_name = str(activation_inputs[int(data_input_index)])
                gate_output_name = str(activation_inputs[1 - int(data_input_index)])

                gate_match = _match_hardsigmoid_gate_from_output(gate_output_name)
                if gate_match is None:
                    continue
                if str(gate_match["head_input_name"]) != str(data_input_name):
                    continue

                gate_users = set(int(v) for v in consumers.get(str(gate_output_name), []))
                if gate_users != {int(activation_idx)}:
                    continue

                expected_data_users = {int(activation_idx), int(gate_match["head_idx"])}
                data_users = set(int(v) for v in consumers.get(str(data_input_name), []))
                if data_users != expected_data_users:
                    continue

                activation_metadata_names = [str(v) for v in list(gate_match.get("metadata_names", []))]
                activation_metadata_names.append(str(activation_output_name))
                rewire_specs = [
                    (int(gate_match["head_idx"]), int(gate_match["head_input_index"])),
                    (int(activation_idx), int(data_input_index)),
                ]

                return {
                    "activation_idx": int(activation_idx),
                    "activation_input_name": str(data_input_name),
                    "activation_input_expected_users": sorted(list(expected_data_users)),
                    "activation_output_name": str(activation_output_name),
                    "activation_metadata_names": activation_metadata_names,
                    "rewire_specs": rewire_specs,
                }
            return None

        for candidate_post_idx, candidate_post_op in enumerate(model_ir.operators):
            if (
                str(candidate_post_op.op_type) != "TRANSPOSE"
                or len(candidate_post_op.inputs) < 2
                or len(candidate_post_op.outputs) != 1
                or _read_transpose_perm(model_ir, candidate_post_op) != perm_nchw_to_nhwc
            ):
                continue

            mul_output_name = str(candidate_post_op.inputs[0])
            if mul_output_name in model_outputs:
                continue
            mul_idx = producers.get(mul_output_name, None)
            if mul_idx is None:
                continue
            mul_op = model_ir.operators[int(mul_idx)]
            if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                continue
            if str(mul_op.outputs[0]) != mul_output_name:
                continue

            mul_output_users = [int(v) for v in consumers.get(mul_output_name, [])]
            if len(mul_output_users) == 0:
                continue
            post_pairs: List[Tuple[int, OperatorIR]] = []
            legacy_slots: List[Tuple[int, int]] = []
            valid_posts = True
            for user_idx in mul_output_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) != "TRANSPOSE"
                    or len(user_op.inputs) < 2
                    or len(user_op.outputs) != 1
                    or str(user_op.inputs[0]) != mul_output_name
                    or _read_transpose_perm(model_ir, user_op) != perm_nchw_to_nhwc
                    or str(user_op.outputs[0]) in model_outputs
                ):
                    if str(user_op.op_type) not in legacy_consumer_safe_ops:
                        valid_posts = False
                        break
                    input_indices = [
                        int(input_idx)
                        for input_idx, input_name in enumerate(list(user_op.inputs))
                        if str(input_name) == str(mul_output_name)
                    ]
                    if len(input_indices) == 0:
                        valid_posts = False
                        break
                    for input_idx in input_indices:
                        legacy_slots.append((int(id(user_op)), int(input_idx)))
                    continue
                post_pairs.append((int(user_idx), user_op))
            if not valid_posts or len(post_pairs) == 0:
                continue
            post_pairs = sorted(post_pairs, key=lambda v: int(v[0]))
            post_indices = [int(v[0]) for v in post_pairs]
            post_output_names = [str(v[1].outputs[0]) for v in post_pairs]

            input0_name = str(mul_op.inputs[0])
            input1_name = str(mul_op.inputs[1])
            activation_idx: Optional[int] = None
            activation_input_name: Optional[str] = None
            activation_input_expected_users: Optional[set[int]] = None
            activation_output_name: Optional[str] = None
            activation_rewire_specs: List[Tuple[int, int]] = []
            activation_metadata_names: List[str] = []
            gate_kind: Optional[str] = None
            gate_head_idx: Optional[int] = None
            gate_head_input_name: Optional[str] = None
            gate_head_input_index: Optional[int] = None
            gate_output_name: Optional[str] = None
            gate_metadata_names: List[str] = []
            for lhs_name, rhs_name in [(input0_name, input1_name), (input1_name, input0_name)]:
                lhs_prod_idx = producers.get(lhs_name, None)
                if lhs_prod_idx is None:
                    continue
                lhs_op = model_ir.operators[int(lhs_prod_idx)]
                lhs_activation_match: Optional[Dict[str, Any]] = None
                if str(lhs_op.op_type) in activation_ops:
                    if len(lhs_op.inputs) == 1 and len(lhs_op.outputs) == 1 and str(lhs_op.outputs[0]) == str(lhs_name):
                        lhs_activation_match = {
                            "activation_idx": int(lhs_prod_idx),
                            "activation_input_name": str(lhs_op.inputs[0]),
                            "activation_input_expected_users": [int(lhs_prod_idx)],
                            "activation_output_name": str(lhs_name),
                            "activation_metadata_names": [str(lhs_name)],
                            "rewire_specs": [(int(lhs_prod_idx), 0)],
                        }
                else:
                    lhs_activation_match = _match_hardswish_activation_from_output(str(lhs_name))
                if lhs_activation_match is None:
                    continue

                rhs_prod_idx = producers.get(rhs_name, None)
                if rhs_prod_idx is None:
                    continue
                rhs_op = model_ir.operators[int(rhs_prod_idx)]

                if str(rhs_op.op_type) == "LOGISTIC":
                    if len(rhs_op.inputs) != 1 or len(rhs_op.outputs) != 1:
                        continue
                    if str(rhs_op.outputs[0]) != rhs_name:
                        continue
                    activation_idx = int(lhs_activation_match["activation_idx"])
                    activation_input_name = str(lhs_activation_match["activation_input_name"])
                    activation_input_expected_users = set(
                        int(v) for v in list(lhs_activation_match["activation_input_expected_users"])
                    )
                    activation_output_name = str(lhs_activation_match["activation_output_name"])
                    activation_rewire_specs = [
                        (int(v[0]), int(v[1])) for v in list(lhs_activation_match["rewire_specs"])
                    ]
                    activation_metadata_names = [
                        str(v) for v in list(lhs_activation_match.get("activation_metadata_names", []))
                    ]
                    gate_kind = "LOGISTIC"
                    gate_head_idx = int(rhs_prod_idx)
                    gate_head_input_name = str(rhs_op.inputs[0])
                    gate_head_input_index = 0
                    gate_output_name = str(rhs_name)
                    gate_metadata_names = [str(rhs_name)]
                    break

                hsig_match = _match_hardsigmoid_gate_from_output(str(rhs_name))
                if hsig_match is None:
                    continue
                activation_idx = int(lhs_activation_match["activation_idx"])
                activation_input_name = str(lhs_activation_match["activation_input_name"])
                activation_input_expected_users = set(
                    int(v) for v in list(lhs_activation_match["activation_input_expected_users"])
                )
                activation_output_name = str(lhs_activation_match["activation_output_name"])
                activation_rewire_specs = [
                    (int(v[0]), int(v[1])) for v in list(lhs_activation_match["rewire_specs"])
                ]
                activation_metadata_names = [
                    str(v) for v in list(lhs_activation_match.get("activation_metadata_names", []))
                ]
                gate_kind = "HARDSIGMOID"
                gate_head_idx = int(hsig_match["head_idx"])
                gate_head_input_name = str(hsig_match["head_input_name"])
                gate_head_input_index = int(hsig_match["head_input_index"])
                gate_output_name = str(hsig_match["output_name"])
                gate_metadata_names = [str(v) for v in list(hsig_match.get("metadata_names", []))]
                break
            if (
                activation_idx is None
                or activation_input_name is None
                or activation_input_expected_users is None
                or activation_output_name is None
                or gate_kind is None
                or gate_head_idx is None
                or gate_head_input_name is None
                or gate_head_input_index is None
                or gate_output_name is None
            ):
                continue

            gate_head_op = model_ir.operators[int(gate_head_idx)]
            if (
                activation_input_name in model_outputs
                or activation_output_name in model_outputs
                or gate_head_input_name in model_outputs
                or gate_output_name in model_outputs
            ):
                continue

            pre_activation_idx = producers.get(activation_input_name, None)
            if pre_activation_idx is None:
                continue
            pre_activation_op = model_ir.operators[int(pre_activation_idx)]
            if (
                str(pre_activation_op.op_type) != "TRANSPOSE"
                or len(pre_activation_op.inputs) < 2
                or len(pre_activation_op.outputs) != 1
                or str(pre_activation_op.outputs[0]) != activation_input_name
                or _read_transpose_perm(model_ir, pre_activation_op) != perm_nhwc_to_nchw
            ):
                continue
            source_nhwc_name = str(pre_activation_op.inputs[0])
            if source_nhwc_name in model_outputs:
                continue

            mean_idx_candidates = [
                int(v)
                for v in consumers.get(activation_output_name, [])
                if int(v) != int(mul_idx)
            ]
            if len(mean_idx_candidates) != 1:
                continue
            mean_idx = int(mean_idx_candidates[0])
            mean_op = model_ir.operators[int(mean_idx)]
            if str(mean_op.op_type) != "MEAN" or len(mean_op.inputs) < 2 or len(mean_op.outputs) != 1:
                continue
            if str(mean_op.inputs[0]) != activation_output_name:
                continue
            if not bool(mean_op.options.get("keepDims", False)):
                continue
            mean_output_name = str(mean_op.outputs[0])
            if mean_output_name in model_outputs:
                continue

            mean_post_users = [int(v) for v in consumers.get(mean_output_name, [])]
            if len(mean_post_users) != 1:
                continue
            mean_post_idx = int(mean_post_users[0])
            mean_post_op = model_ir.operators[int(mean_post_idx)]
            if (
                str(mean_post_op.op_type) != "TRANSPOSE"
                or len(mean_post_op.inputs) < 2
                or len(mean_post_op.outputs) != 1
                or str(mean_post_op.inputs[0]) != mean_output_name
                or _read_transpose_perm(model_ir, mean_post_op) != perm_nchw_to_nhwc
            ):
                continue
            conv1_input_name = str(mean_post_op.outputs[0])
            if conv1_input_name in model_outputs:
                continue

            conv1_users = [int(v) for v in consumers.get(conv1_input_name, [])]
            if len(conv1_users) != 1:
                continue
            conv1_idx = int(conv1_users[0])
            conv1_op = model_ir.operators[int(conv1_idx)]
            if str(conv1_op.op_type) != "CONV_2D" or len(conv1_op.inputs) < 1 or len(conv1_op.outputs) != 1:
                continue
            if str(conv1_op.inputs[0]) != conv1_input_name:
                continue
            conv1_output_name = str(conv1_op.outputs[0])
            if conv1_output_name in model_outputs:
                continue
            conv1_output_users = [int(v) for v in consumers.get(conv1_output_name, [])]
            if len(conv1_output_users) != 1:
                continue
            conv2_idx = int(conv1_output_users[0])
            conv2_op = model_ir.operators[int(conv2_idx)]
            if str(conv2_op.op_type) != "CONV_2D" or len(conv2_op.inputs) < 1 or len(conv2_op.outputs) != 1:
                continue
            if str(conv2_op.inputs[0]) != conv1_output_name:
                continue
            conv2_output_name = str(conv2_op.outputs[0])
            if conv2_output_name in model_outputs:
                continue

            pre_gate_idx = producers.get(gate_head_input_name, None)
            if pre_gate_idx is None:
                continue
            pre_gate_op = model_ir.operators[int(pre_gate_idx)]
            if (
                str(pre_gate_op.op_type) != "TRANSPOSE"
                or len(pre_gate_op.inputs) < 2
                or len(pre_gate_op.outputs) != 1
                or str(pre_gate_op.outputs[0]) != gate_head_input_name
                or _read_transpose_perm(model_ir, pre_gate_op) != perm_nhwc_to_nchw
                or str(pre_gate_op.inputs[0]) != conv2_output_name
            ):
                continue

            # Locality guards: this rewrite assumes a closed motif.
            if set(int(v) for v in consumers.get(activation_input_name, [])) != set(int(v) for v in activation_input_expected_users):
                continue
            if set(int(v) for v in consumers.get(activation_output_name, [])) != {int(mean_idx), int(mul_idx)}:
                continue
            if set(int(v) for v in consumers.get(mean_output_name, [])) != {int(mean_post_idx)}:
                continue
            if set(int(v) for v in consumers.get(conv1_input_name, [])) != {int(conv1_idx)}:
                continue
            if set(int(v) for v in consumers.get(conv1_output_name, [])) != {int(conv2_idx)}:
                continue
            if set(int(v) for v in consumers.get(conv2_output_name, [])) != {int(pre_gate_idx)}:
                continue
            if set(int(v) for v in consumers.get(gate_head_input_name, [])) != {int(gate_head_idx)}:
                continue
            if set(int(v) for v in consumers.get(gate_output_name, [])) != {int(mul_idx)}:
                continue

            # Remap MEAN axes from NCHW to NHWC.
            mean_axes_tensor = model_ir.tensors.get(str(mean_op.inputs[1]), None)
            mean_axes_vals = _read_const_ints_from_tensor(mean_axes_tensor)
            if mean_axes_vals is None or len(mean_axes_vals) == 0:
                continue
            source_tensor = model_ir.tensors.get(source_nhwc_name, None)
            rank = 4
            if source_tensor is not None and source_tensor.shape is not None and len(list(source_tensor.shape)) > 0:
                rank = int(len(list(source_tensor.shape)))
            if rank != 4:
                continue
            normalized_axes: List[int] = []
            valid_axes = True
            for axis in mean_axes_vals:
                a = int(axis)
                if a < 0:
                    a += int(rank)
                if a < 0 or a >= int(rank):
                    valid_axes = False
                    break
                normalized_axes.append(int(a))
            if not valid_axes:
                continue
            mapped_axes = [int(perm_nhwc_to_nchw[int(axis)]) for axis in normalized_axes]
            if not _write_const_ints_to_tensor(mean_axes_tensor, [int(v) for v in mapped_axes]):
                continue

            # Rewire to NHWC.
            for rewire_op_idx, rewire_input_idx in activation_rewire_specs:
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=model_ir.operators[int(rewire_op_idx)],
                    input_index=int(rewire_input_idx),
                    new_input_name=source_nhwc_name,
                )
            conv1_inputs = [str(v) for v in list(conv1_op.inputs)]
            conv1_inputs[0] = str(mean_output_name)
            _set_operator_inputs(
                model_ir=model_ir,
                op=conv1_op,
                new_inputs=conv1_inputs,
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=gate_head_op,
                input_index=int(gate_head_input_index),
                new_input_name=conv2_output_name,
            )

            # Update metadata of tensors that switch from NCHW to NHWC.
            old_mul_tensor = model_ir.tensors.get(mul_output_name, None)
            legacy_mul_shape = (
                [int(v) for v in list(old_mul_tensor.shape)]
                if old_mul_tensor is not None and old_mul_tensor.shape is not None
                else None
            )
            legacy_mul_shape_signature = None
            if old_mul_tensor is not None:
                legacy_mul_shape_signature = (
                    [int(v) for v in list(old_mul_tensor.shape_signature)]
                    if old_mul_tensor.shape_signature is not None
                    else (
                        [int(v) for v in list(old_mul_tensor.shape)]
                        if old_mul_tensor.shape is not None
                        else None
                    )
                )
            metadata_targets = [str(v) for v in list(activation_metadata_names)]
            metadata_targets.append(str(mean_output_name))
            metadata_targets.extend([str(v) for v in list(gate_metadata_names)])
            metadata_targets.append(str(mul_output_name))
            for tensor_name in list(dict.fromkeys(metadata_targets)):
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(tensor_name), None),
                    perm_nchw_to_nhwc,
                )

            canonical_post_output_name = str(post_output_names[0])
            _set_operator_outputs(
                model_ir=model_ir,
                op=mul_op,
                new_outputs=[canonical_post_output_name],
            )
            _replace_tensor_inputs(model_ir, mul_output_name, canonical_post_output_name)
            for alias_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, str(alias_name), canonical_post_output_name)

            canonical_tensor = model_ir.tensors.get(canonical_post_output_name, None)
            if old_mul_tensor is not None and canonical_tensor is not None:
                canonical_tensor.dtype = str(old_mul_tensor.dtype)
                canonical_tensor.quantization = _clone_quantization(old_mul_tensor.quantization)
                canonical_tensor.shape = [int(v) for v in list(old_mul_tensor.shape)]
                canonical_tensor.shape_signature = (
                    [int(v) for v in list(old_mul_tensor.shape_signature)]
                    if old_mul_tensor.shape_signature is not None
                    else [int(v) for v in list(old_mul_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    canonical_tensor,
                    perm_nchw_to_nhwc,
                )

            pending_legacy_slots = list(legacy_slots)

            remove_indices = {
                int(pre_activation_idx),
                int(mean_post_idx),
                int(pre_gate_idx),
                *[int(v) for v in post_indices],
            }
            for remove_idx in sorted(remove_indices, reverse=True):
                del model_ir.operators[int(remove_idx)]

            if len(pending_legacy_slots) > 0:
                op_index_by_id = {int(id(op)): int(op_idx) for op_idx, op in enumerate(model_ir.operators)}
                valid_legacy_slots: List[Tuple[int, int]] = []
                for op_id, input_idx in pending_legacy_slots:
                    op_idx = op_index_by_id.get(int(op_id), None)
                    if op_idx is None:
                        continue
                    if int(op_idx) < 0 or int(op_idx) >= len(model_ir.operators):
                        continue
                    legacy_op = model_ir.operators[int(op_idx)]
                    if int(input_idx) < 0 or int(input_idx) >= len(legacy_op.inputs):
                        continue
                    if str(legacy_op.inputs[int(input_idx)]) != str(canonical_post_output_name):
                        continue
                    valid_legacy_slots.append((int(op_idx), int(input_idx)))

                if len(valid_legacy_slots) > 0:
                    adapter_name = _unique_tensor_name(f"{mul_output_name}_nchw_adapter")
                    adapter_dtype = str(old_mul_tensor.dtype) if old_mul_tensor is not None else "FLOAT32"
                    adapter_quant = (
                        _clone_quantization(old_mul_tensor.quantization)
                        if old_mul_tensor is not None
                        else None
                    )
                    adapter_shape = (
                        [int(v) for v in list(legacy_mul_shape)]
                        if legacy_mul_shape is not None
                        else [1]
                    )
                    adapter_shape_signature = (
                        [int(v) for v in list(legacy_mul_shape_signature)]
                        if legacy_mul_shape_signature is not None
                        else [int(v) for v in list(adapter_shape)]
                    )
                    model_ir.tensors[adapter_name] = TensorIR(
                        name=adapter_name,
                        dtype=str(adapter_dtype),
                        shape=[int(v) for v in list(adapter_shape)],
                        shape_signature=[int(v) for v in list(adapter_shape_signature)],
                        data=None,
                        is_variable=False,
                        quantization=_clone_quantization(adapter_quant),
                    )
                    adapter_op = OperatorIR(
                        op_type="TRANSPOSE",
                        inputs=[str(canonical_post_output_name), perm_nhwc_to_nchw_const_name],
                        outputs=[str(adapter_name)],
                    )
                    for op_idx, input_idx in valid_legacy_slots:
                        legacy_op = model_ir.operators[int(op_idx)]
                        new_inputs = [str(v) for v in list(legacy_op.inputs)]
                        new_inputs[int(input_idx)] = str(adapter_name)
                        _set_operator_inputs(
                            model_ir=model_ir,
                            op=legacy_op,
                            new_inputs=new_inputs,
                        )
                    insert_index = int(min(v[0] for v in valid_legacy_slots))
                    model_ir.operators.insert(int(insert_index), adapter_op)

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_conv_attention_nhwc_propagation_chains": int(rewritten)}


def _optimize_transpose_add_concat_const_suffix_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate NCHW round-trips around ADD fan-in concat blocks with const suffixes.

    Target:
      (x_i_nhwc --T(0,3,1,2)--> x_i_nchw)
      (b_nhwc  --T(0,3,1,2)--> b_nchw; shared)
      ADD(x_i_nchw, b_nchw) -> a_i_nchw
      CONCAT(axis=1, [a_i_nchw...]) -> c_nchw
      c_nchw --(MUL|ADD with const)*--> z_nchw
      z_nchw --T(0,2,3,1)--> z_nhwc

    Rewrite:
      ADD(x_i_nhwc, b_nhwc) -> a_i_nhwc
      CONCAT(axis=3, [a_i_nhwc...]) -> c_nhwc
      c_nhwc --(MUL|ADD with const_nhwc)*--> z_nhwc
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for concat_idx, concat_op in enumerate(model_ir.operators):
            if str(concat_op.op_type) != "CONCATENATION" or len(concat_op.outputs) != 1:
                continue
            concat_out_name = str(concat_op.outputs[0])
            if concat_out_name in model_outputs:
                continue
            concat_axis = int(concat_op.options.get("axis", 1))
            if concat_axis < 0:
                concat_axis += 4
            if concat_axis != 1:
                continue

            concat_inputs = [str(v) for v in list(concat_op.inputs)]
            if len(concat_inputs) < 2:
                continue

            add_rewrites: List[Tuple[int, List[str]]] = []
            branch_pre_remove_indices: List[int] = []
            base_pre_idx: Optional[int] = None
            base_pre_input_name: Optional[str] = None
            rewritable = True

            for add_out_name in concat_inputs:
                add_idx = producers.get(str(add_out_name), None)
                if add_idx is None:
                    rewritable = False
                    break
                add_op = model_ir.operators[int(add_idx)]
                if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                    rewritable = False
                    break
                if str(add_op.outputs[0]) != str(add_out_name):
                    rewritable = False
                    break
                if set(int(v) for v in consumers.get(str(add_out_name), [])) != {int(concat_idx)}:
                    rewritable = False
                    break

                add_inputs = [str(v) for v in list(add_op.inputs)]
                transpose_inputs: List[Tuple[int, int, str, bool]] = []
                for input_index, add_input_name in enumerate(add_inputs):
                    pre_idx = producers.get(str(add_input_name), None)
                    if pre_idx is None:
                        continue
                    pre_op = model_ir.operators[int(pre_idx)]
                    if (
                        str(pre_op.op_type) != "TRANSPOSE"
                        or len(pre_op.inputs) < 2
                        or len(pre_op.outputs) != 1
                        or str(pre_op.outputs[0]) != str(add_input_name)
                        or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
                        or str(add_input_name) in model_outputs
                    ):
                        continue
                    direct_only = set(int(v) for v in consumers.get(str(add_input_name), [])) == {int(add_idx)}
                    transpose_inputs.append((int(input_index), int(pre_idx), str(pre_op.inputs[0]), bool(direct_only)))

                if len(transpose_inputs) < 2:
                    rewritable = False
                    break

                branch_plan = None
                base_plan = None
                for plan in transpose_inputs:
                    if bool(plan[3]):
                        branch_plan = plan
                        break
                if branch_plan is None:
                    rewritable = False
                    break
                for plan in transpose_inputs:
                    if int(plan[1]) != int(branch_plan[1]):
                        base_plan = plan
                        break
                if base_plan is None:
                    rewritable = False
                    break

                if base_pre_idx is None:
                    base_pre_idx = int(base_plan[1])
                    base_pre_input_name = str(base_plan[2])
                elif int(base_pre_idx) != int(base_plan[1]):
                    rewritable = False
                    break

                new_add_inputs = list(add_inputs)
                new_add_inputs[int(branch_plan[0])] = str(branch_plan[2])
                new_add_inputs[int(base_plan[0])] = str(base_plan[2])
                add_rewrites.append((int(add_idx), [str(v) for v in new_add_inputs]))
                branch_pre_remove_indices.append(int(branch_plan[1]))

            if not rewritable or base_pre_idx is None or base_pre_input_name is None:
                continue

            # Strict suffix: CONCAT -> MUL(const) -> ADD(const) -> TRANSPOSE(NCHW->NHWC)
            concat_users = [int(v) for v in consumers.get(concat_out_name, [])]
            if len(concat_users) != 1:
                continue
            mul_idx = int(concat_users[0])
            mul_op = model_ir.operators[mul_idx]
            if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                continue
            mul_in0 = str(mul_op.inputs[0])
            mul_in1 = str(mul_op.inputs[1])
            if mul_in0 == concat_out_name:
                mul_side_index = 1
                mul_side_name = mul_in1
            elif mul_in1 == concat_out_name:
                mul_side_index = 0
                mul_side_name = mul_in0
            else:
                continue
            mul_side_tensor = model_ir.tensors.get(mul_side_name, None)
            if mul_side_tensor is None or mul_side_tensor.data is None:
                continue
            mul_out_name = str(mul_op.outputs[0])
            if mul_out_name in model_outputs:
                continue

            mul_users = [int(v) for v in consumers.get(mul_out_name, [])]
            if len(mul_users) != 1:
                continue
            add2_idx = int(mul_users[0])
            add2_op = model_ir.operators[add2_idx]
            if str(add2_op.op_type) != "ADD" or len(add2_op.inputs) != 2 or len(add2_op.outputs) != 1:
                continue
            add2_in0 = str(add2_op.inputs[0])
            add2_in1 = str(add2_op.inputs[1])
            if add2_in0 == mul_out_name:
                add2_side_index = 1
                add2_side_name = add2_in1
            elif add2_in1 == mul_out_name:
                add2_side_index = 0
                add2_side_name = add2_in0
            else:
                continue
            add2_side_tensor = model_ir.tensors.get(add2_side_name, None)
            if add2_side_tensor is None or add2_side_tensor.data is None:
                continue
            add2_out_name = str(add2_op.outputs[0])
            if add2_out_name in model_outputs:
                continue

            add2_users = [int(v) for v in consumers.get(add2_out_name, [])]
            if len(add2_users) != 1:
                continue
            post_idx = int(add2_users[0])
            post_op = model_ir.operators[post_idx]
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or str(post_op.inputs[0]) != add2_out_name
                or _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc
            ):
                continue
            post_out_name = str(post_op.outputs[0])
            if post_out_name in model_outputs:
                continue

            # Apply rewrites atomically after full validation.
            for add_idx, new_inputs in add_rewrites:
                add_op = model_ir.operators[int(add_idx)]
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=add_op,
                    new_inputs=[str(v) for v in new_inputs],
                )
                if len(add_op.outputs) == 1:
                    _permute_tensor_metadata_if_rank_matches(
                        model_ir.tensors.get(str(add_op.outputs[0]), None),
                        perm_nchw_to_nhwc,
                    )

            if np.asarray(mul_side_tensor.data).ndim == 4:
                mul_nhwc = np.transpose(np.asarray(mul_side_tensor.data), perm_nchw_to_nhwc).astype(
                    np.asarray(mul_side_tensor.data).dtype, copy=False
                )
                mul_side_tensor.data = np.asarray(mul_nhwc)
                mul_side_tensor.shape = [int(v) for v in list(mul_nhwc.shape)]
                mul_side_tensor.shape_signature = [int(v) for v in list(mul_nhwc.shape)]
            if np.asarray(add2_side_tensor.data).ndim == 4:
                add2_nhwc = np.transpose(np.asarray(add2_side_tensor.data), perm_nchw_to_nhwc).astype(
                    np.asarray(add2_side_tensor.data).dtype, copy=False
                )
                add2_side_tensor.data = np.asarray(add2_nhwc)
                add2_side_tensor.shape = [int(v) for v in list(add2_nhwc.shape)]
                add2_side_tensor.shape_signature = [int(v) for v in list(add2_nhwc.shape)]

            concat_op.options["axis"] = 3
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(concat_out_name, None),
                perm_nchw_to_nhwc,
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(mul_out_name, None),
                perm_nchw_to_nhwc,
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(add2_out_name, None),
                perm_nchw_to_nhwc,
            )

            _set_operator_outputs(
                model_ir=model_ir,
                op=add2_op,
                new_outputs=[post_out_name],
            )

            old_add2_tensor = model_ir.tensors.get(add2_out_name, None)
            post_tensor = model_ir.tensors.get(post_out_name, None)
            if old_add2_tensor is not None and post_tensor is not None:
                post_tensor.dtype = str(old_add2_tensor.dtype)
                post_tensor.quantization = _clone_quantization(old_add2_tensor.quantization)
                post_tensor.shape = [int(v) for v in list(old_add2_tensor.shape)]
                post_tensor.shape_signature = (
                    [int(v) for v in list(old_add2_tensor.shape_signature)]
                    if old_add2_tensor.shape_signature is not None
                    else [int(v) for v in list(old_add2_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    post_tensor,
                    perm_nchw_to_nhwc,
                )

            remove_indices = set(int(v) for v in branch_pre_remove_indices)
            remove_indices.add(int(post_idx))
            # Remove base transpose only when it became dead.
            base_nchw_name = str(model_ir.operators[int(base_pre_idx)].outputs[0])
            remaining_users = [int(v) for v in consumers.get(base_nchw_name, [])]
            if set(int(v) for v in remaining_users).issubset(set(int(idx) for idx, _ in add_rewrites)):
                remove_indices.add(int(base_pre_idx))

            for remove_idx in sorted(remove_indices, reverse=True):
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_add_concat_const_suffix_nhwc_chains": int(optimized)}


def _optimize_transposeconv_output_nhwc_passthrough_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Propagate NHWC through transpose wrappers around Conv-family outputs.

    Target:
      Y_nhwc(from CONV_2D|DEPTHWISE_CONV_2D|TRANSPOSE_CONV)
        --TRANSPOSE(0,3,1,2)--> Y_nchw
      Y_nchw --(QUANTIZE|DEQUANTIZE|RELU|RELU6|ADD|SUB|MUL|DIV|MAXIMUM|MINIMUM)*--> Z_nchw
      Z_nchw --TRANSPOSE(0,2,3,1)--> Z_nhwc

    Rewrite:
      Y_nhwc --(same chain with NHWC metadata/constants)*--> Z_nhwc

    Safety:
    - Leading transpose input must be produced by CONV_2D, DEPTHWISE_CONV_2D, or TRANSPOSE_CONV.
    - Chain must be strictly linear and end with exactly one inverse transpose.
    - Binary side inputs must be constants and broadcast-safe after NCHW->NHWC remap.
    - Activation quantization must remain per-tensor.
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    unary_passthrough_ops = {
        "QUANTIZE",
        "DEQUANTIZE",
        "CAST",
        "RELU",
        "RELU6",
        "RELU_0_TO_1",
        "HARD_SWISH",
    }
    binary_passthrough_ops = {"ADD", "SUB", "MUL", "DIV", "MAXIMUM", "MINIMUM"}

    def _unique_tensor_name(base: str) -> str:
        candidate = str(base)
        suffix = 1
        while candidate in model_ir.tensors:
            candidate = f"{base}_{suffix}"
            suffix += 1
        return candidate

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_input_name in model_outputs or pre_output_name in model_outputs:
                continue

            pre_input_prod_idx = producers.get(pre_input_name, None)
            if pre_input_prod_idx is None:
                continue
            pre_input_prod_op = model_ir.operators[int(pre_input_prod_idx)]
            if str(pre_input_prod_op.op_type) not in {
                "CONV_2D",
                "DEPTHWISE_CONV_2D",
                "TRANSPOSE_CONV",
            }:
                continue

            chain_indices: List[int] = []
            chain_ops: List[OperatorIR] = []
            chain_output_names: List[str] = []
            chain_binary_specs: List[Tuple[int, int, str, str]] = []
            current_tensor = pre_output_name
            chain_build_valid = True

            while True:
                current_users = [int(v) for v in consumers.get(current_tensor, [])]
                if len(current_users) != 1:
                    break
                op_idx = int(current_users[0])
                op = model_ir.operators[int(op_idx)]
                op_type = str(op.op_type)

                if op_type in unary_passthrough_ops:
                    if len(op.inputs) != 1 or len(op.outputs) != 1:
                        break
                    if str(op.inputs[0]) != current_tensor:
                        break
                    out_name = str(op.outputs[0])
                    if out_name in model_outputs:
                        chain_build_valid = False
                        break
                    out_tensor = model_ir.tensors.get(out_name, None)
                    if out_tensor is not None and not _is_per_tensor_quantization(out_tensor.quantization):
                        chain_build_valid = False
                        break
                    chain_indices.append(int(op_idx))
                    chain_ops.append(op)
                    chain_output_names.append(out_name)
                    current_tensor = out_name
                    continue

                if op_type in binary_passthrough_ops:
                    if len(op.inputs) != 2 or len(op.outputs) != 1:
                        break
                    input_0 = str(op.inputs[0])
                    input_1 = str(op.inputs[1])
                    if input_0 == current_tensor:
                        side_input_index = 1
                        side_input_name = input_1
                    elif input_1 == current_tensor:
                        side_input_index = 0
                        side_input_name = input_0
                    else:
                        break

                    side_tensor = model_ir.tensors.get(side_input_name, None)
                    if side_tensor is None or side_tensor.data is None:
                        break
                    if not _is_per_tensor_quantization(side_tensor.quantization):
                        break

                    side_data = np.asarray(side_tensor.data)
                    if int(side_data.size) != 1:
                        if side_data.ndim != 4:
                            break
                        current_tensor_ir = model_ir.tensors.get(current_tensor, None)
                        if (
                            current_tensor_ir is None
                            or not _is_fully_known_positive_shape(current_tensor_ir.shape)
                            or len(list(current_tensor_ir.shape)) != 4
                        ):
                            break
                        nchw_shape = [int(v) for v in list(current_tensor_ir.shape)]
                        side_shape = [int(v) for v in list(side_data.shape)]
                        if _broadcast_static_shapes(nchw_shape, side_shape) is None:
                            break
                        side_shape_nhwc = _permute_shape(side_shape, perm_nchw_to_nhwc)
                        nchw_to_nhwc_shape = _permute_shape(nchw_shape, perm_nchw_to_nhwc)
                        if side_shape_nhwc is None or nchw_to_nhwc_shape is None:
                            break
                        if _broadcast_static_shapes(nchw_to_nhwc_shape, side_shape_nhwc) is None:
                            break

                    out_name = str(op.outputs[0])
                    if out_name in model_outputs:
                        chain_build_valid = False
                        break
                    out_tensor = model_ir.tensors.get(out_name, None)
                    if out_tensor is not None and not _is_per_tensor_quantization(out_tensor.quantization):
                        chain_build_valid = False
                        break

                    chain_indices.append(int(op_idx))
                    chain_ops.append(op)
                    chain_output_names.append(out_name)
                    chain_binary_specs.append((int(op_idx), int(side_input_index), side_input_name, current_tensor))
                    current_tensor = out_name
                    continue

                break

            if len(chain_ops) == 0 or not chain_build_valid:
                continue

            tail_users = [int(v) for v in consumers.get(current_tensor, [])]
            if len(tail_users) != 1:
                continue
            post_idx = int(tail_users[0])
            if post_idx in set(chain_indices):
                continue
            post_op = model_ir.operators[int(post_idx)]
            if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                continue
            if str(post_op.inputs[0]) != current_tensor:
                continue
            if _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc:
                continue

            post_output_name = str(post_op.outputs[0])
            if post_output_name in model_outputs:
                continue

            linear_ok = True
            previous_tensor_name = pre_output_name
            chain_index_to_pos = {int(idx): pos for pos, idx in enumerate(chain_indices)}
            for op_idx, op in zip(chain_indices, chain_ops):
                if previous_tensor_name not in set(str(v) for v in op.inputs):
                    linear_ok = False
                    break
                out_name = str(op.outputs[0]) if len(op.outputs) > 0 else ""
                if out_name == "":
                    linear_ok = False
                    break
                expected_users = [int(v) for v in consumers.get(out_name, [])]
                pos = int(chain_index_to_pos[int(op_idx)])
                if pos < len(chain_indices) - 1:
                    if expected_users != [int(chain_indices[pos + 1])]:
                        linear_ok = False
                        break
                else:
                    if expected_users != [int(post_idx)]:
                        linear_ok = False
                        break
                previous_tensor_name = out_name
            if not linear_ok:
                continue

            tensors_for_quant_validation: List[Optional[TensorIR]] = [
                model_ir.tensors.get(pre_input_name, None),
                model_ir.tensors.get(pre_output_name, None),
            ] + [model_ir.tensors.get(name, None) for name in chain_output_names]
            if not _all_per_tensor_quantized(tensors_for_quant_validation):
                continue

            chain_index_set = set(int(v) for v in chain_indices)
            const_rewrite_ok = True
            for op_idx, side_input_index, side_input_name, _ in chain_binary_specs:
                side_tensor = model_ir.tensors.get(side_input_name, None)
                if side_tensor is None or side_tensor.data is None:
                    const_rewrite_ok = False
                    break
                side_data = np.asarray(side_tensor.data)
                if int(side_data.size) == 1:
                    continue
                if side_data.ndim != 4:
                    const_rewrite_ok = False
                    break

                permuted_data = np.transpose(side_data, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
                side_users = [int(v) for v in consumers.get(side_input_name, [])]
                shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)

                target_const_name = str(side_input_name)
                if shared_outside_chain:
                    target_const_name = _unique_tensor_name(f"{side_input_name}_nhwc")
                    model_ir.tensors[target_const_name] = TensorIR(
                        name=target_const_name,
                        dtype=str(side_tensor.dtype),
                        shape=[int(v) for v in list(permuted_data.shape)],
                        shape_signature=[int(v) for v in list(permuted_data.shape)],
                        data=np.asarray(permuted_data),
                        is_variable=False,
                        quantization=_clone_quantization(side_tensor.quantization),
                    )
                else:
                    side_tensor.data = np.asarray(permuted_data)
                    side_tensor.shape = [int(v) for v in list(permuted_data.shape)]
                    side_tensor.shape_signature = [int(v) for v in list(permuted_data.shape)]

                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=model_ir.operators[int(op_idx)],
                    input_index=int(side_input_index),
                    new_input_name=target_const_name,
                )

            if not const_rewrite_ok:
                continue

            old_last_name = str(chain_ops[-1].outputs[0])
            old_last_tensor = model_ir.tensors.get(old_last_name, None)
            post_output_tensor = model_ir.tensors.get(post_output_name, None)

            first_op = chain_ops[0]
            first_input_names = [str(v) for v in first_op.inputs]
            if first_input_names[0] == pre_output_name:
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=first_op,
                    new_inputs=[pre_input_name] + first_input_names[1:],
                )
            elif len(first_input_names) > 1 and first_input_names[1] == pre_output_name:
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=first_op,
                    new_inputs=[first_input_names[0], pre_input_name],
                )
            else:
                continue

            _set_operator_outputs(
                model_ir=model_ir,
                op=chain_ops[-1],
                new_outputs=[post_output_name],
            )

            for out_name in chain_output_names[:-1]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(out_name, None),
                    perm_nchw_to_nhwc,
                )

            if post_output_tensor is not None:
                if old_last_tensor is not None:
                    post_output_tensor.dtype = str(old_last_tensor.dtype)
                    post_output_tensor.quantization = _clone_quantization(old_last_tensor.quantization)
                _permute_tensor_metadata_if_rank_matches(
                    post_output_tensor,
                    perm_nchw_to_nhwc,
                )

            remove_indices = sorted(list({int(pre_idx), int(post_idx)}), reverse=True)
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"rewritten_transposeconv_output_nhwc_passthrough_chains": int(rewritten)}


def _optimize_transposeconv_output_channel1_terminal_transpose_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Remove terminal NCHW adapter transposes after TRANSPOSE_CONV when channel dim is singleton.

    Target:
      Y_nhwc(from TRANSPOSE_CONV) --TRANSPOSE(0,3,1,2)--> Y_nchw
      Y_nchw --(ELEMENTWISE|SQUEEZE)*--> Z_out(graph output)

    Rewrite:
      Y_nhwc --(same chain with NHWC metadata/constants and remapped squeeze axes)*--> Z_out

    Safety:
    - Leading transpose input must be produced by TRANSPOSE_CONV.
    - TRANSPOSE_CONV output channel dim must be statically 1.
    - Chain must be strictly linear and terminate at a graph output tensor.
    - Chain must include at least one SQUEEZE with remappable singleton axes.
    - Binary side inputs must be constants and broadcast-safe after NCHW->NHWC remap.
    - Activation quantization must remain per-tensor.
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    nchw_axis_to_nhwc_axis = {0: 0, 1: 3, 2: 1, 3: 2}
    unary_passthrough_ops = {
        "QUANTIZE",
        "DEQUANTIZE",
        "CAST",
        "RELU",
        "RELU6",
        "RELU_0_TO_1",
        "LOGISTIC",
        "TANH",
        "GELU",
        "HARD_SWISH",
        "ABS",
        "NEG",
        "SQRT",
        "EXP",
    }
    binary_passthrough_ops = {"ADD", "SUB", "MUL", "DIV", "MAXIMUM", "MINIMUM"}

    def _unique_tensor_name(base: str) -> str:
        candidate = str(base)
        suffix = 1
        while candidate in model_ir.tensors:
            candidate = f"{base}_{suffix}"
            suffix += 1
        return candidate

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_input_name in model_outputs or pre_output_name in model_outputs:
                continue

            pre_input_prod_idx = producers.get(pre_input_name, None)
            if pre_input_prod_idx is None:
                continue
            pre_input_prod_op = model_ir.operators[int(pre_input_prod_idx)]
            if str(pre_input_prod_op.op_type) != "TRANSPOSE_CONV":
                continue

            pre_input_tensor = model_ir.tensors.get(pre_input_name, None)
            if (
                pre_input_tensor is None
                or not _is_fully_known_positive_shape(pre_input_tensor.shape)
                or len(list(pre_input_tensor.shape)) != 4
            ):
                continue
            pre_input_shape = [int(v) for v in list(pre_input_tensor.shape)]
            if int(pre_input_shape[3]) != 1:
                continue

            chain_indices: List[int] = []
            chain_ops: List[OperatorIR] = []
            chain_output_names: List[str] = []
            chain_binary_specs: List[Tuple[int, int, str]] = []
            chain_main_input_index: Dict[int, int] = {}
            squeeze_axis_rewrites: List[Tuple[int, List[int]]] = []
            current_tensor = pre_output_name
            chain_build_valid = True
            seen_squeeze = False

            while True:
                current_users = [int(v) for v in consumers.get(current_tensor, [])]
                if len(current_users) != 1:
                    break
                op_idx = int(current_users[0])
                op = model_ir.operators[int(op_idx)]
                op_type = str(op.op_type)

                if op_type in unary_passthrough_ops:
                    if len(op.inputs) != 1 or len(op.outputs) != 1:
                        break
                    if str(op.inputs[0]) != current_tensor:
                        break
                    out_name = str(op.outputs[0])
                    out_tensor = model_ir.tensors.get(out_name, None)
                    if out_tensor is not None and not _is_per_tensor_quantization(out_tensor.quantization):
                        chain_build_valid = False
                        break
                    chain_indices.append(int(op_idx))
                    chain_ops.append(op)
                    chain_output_names.append(out_name)
                    current_tensor = out_name
                    continue

                if op_type in binary_passthrough_ops:
                    if len(op.inputs) != 2 or len(op.outputs) != 1:
                        break
                    input_0 = str(op.inputs[0])
                    input_1 = str(op.inputs[1])
                    if input_0 == current_tensor:
                        side_input_index = 1
                        side_input_name = input_1
                        main_input_index = 0
                    elif input_1 == current_tensor:
                        side_input_index = 0
                        side_input_name = input_0
                        main_input_index = 1
                    else:
                        break

                    side_tensor = model_ir.tensors.get(side_input_name, None)
                    if side_tensor is None or side_tensor.data is None:
                        break
                    if not _is_per_tensor_quantization(side_tensor.quantization):
                        break

                    side_data = np.asarray(side_tensor.data)
                    if int(side_data.size) != 1:
                        if side_data.ndim != 4:
                            break
                        current_tensor_ir = model_ir.tensors.get(current_tensor, None)
                        if (
                            current_tensor_ir is None
                            or not _is_fully_known_positive_shape(current_tensor_ir.shape)
                            or len(list(current_tensor_ir.shape)) != 4
                        ):
                            break
                        nchw_shape = [int(v) for v in list(current_tensor_ir.shape)]
                        side_shape = [int(v) for v in list(side_data.shape)]
                        if _broadcast_static_shapes(nchw_shape, side_shape) is None:
                            break
                        side_shape_nhwc = _permute_shape(side_shape, perm_nchw_to_nhwc)
                        nhwc_shape = _permute_shape(nchw_shape, perm_nchw_to_nhwc)
                        if side_shape_nhwc is None or nhwc_shape is None:
                            break
                        if _broadcast_static_shapes(nhwc_shape, side_shape_nhwc) is None:
                            break

                    out_name = str(op.outputs[0])
                    out_tensor = model_ir.tensors.get(out_name, None)
                    if out_tensor is not None and not _is_per_tensor_quantization(out_tensor.quantization):
                        chain_build_valid = False
                        break

                    chain_indices.append(int(op_idx))
                    chain_ops.append(op)
                    chain_output_names.append(out_name)
                    chain_binary_specs.append((int(op_idx), int(side_input_index), side_input_name))
                    chain_main_input_index[int(op_idx)] = int(main_input_index)
                    current_tensor = out_name
                    continue

                if op_type == "SQUEEZE":
                    if seen_squeeze:
                        break
                    if len(op.inputs) != 1 or len(op.outputs) != 1:
                        break
                    if str(op.inputs[0]) != current_tensor:
                        break
                    current_tensor_ir = model_ir.tensors.get(current_tensor, None)
                    if (
                        current_tensor_ir is None
                        or not _is_fully_known_positive_shape(current_tensor_ir.shape)
                        or len(list(current_tensor_ir.shape)) != 4
                    ):
                        chain_build_valid = False
                        break
                    nchw_shape = [int(v) for v in list(current_tensor_ir.shape)]
                    nhwc_shape = _permute_shape(nchw_shape, perm_nchw_to_nhwc)
                    if nhwc_shape is None:
                        chain_build_valid = False
                        break

                    raw_axes = op.options.get("squeezeDims", [])
                    if raw_axes is None:
                        raw_axes_list: List[int] = []
                    elif isinstance(raw_axes, (list, tuple, np.ndarray)):
                        raw_axes_list = [int(v) for v in list(raw_axes)]
                    else:
                        raw_axes_list = [int(raw_axes)]
                    normalized_axes: List[int] = []
                    if len(raw_axes_list) == 0:
                        normalized_axes = [int(idx) for idx, dim in enumerate(nchw_shape) if int(dim) == 1]
                    else:
                        for axis in raw_axes_list:
                            axis_norm = int(axis)
                            if axis_norm < 0:
                                axis_norm += 4
                            if axis_norm < 0 or axis_norm >= 4:
                                chain_build_valid = False
                                break
                            if axis_norm not in normalized_axes:
                                normalized_axes.append(int(axis_norm))
                        if not chain_build_valid:
                            break

                    if len(normalized_axes) == 0:
                        chain_build_valid = False
                        break

                    mapped_axes: List[int] = []
                    for axis in normalized_axes:
                        if int(nchw_shape[int(axis)]) != 1:
                            chain_build_valid = False
                            break
                        mapped_axis = int(nchw_axis_to_nhwc_axis[int(axis)])
                        if int(nhwc_shape[int(mapped_axis)]) != 1:
                            chain_build_valid = False
                            break
                        if mapped_axis not in mapped_axes:
                            mapped_axes.append(int(mapped_axis))
                    if not chain_build_valid:
                        break

                    out_name = str(op.outputs[0])
                    out_tensor = model_ir.tensors.get(out_name, None)
                    if out_tensor is not None and not _is_per_tensor_quantization(out_tensor.quantization):
                        chain_build_valid = False
                        break

                    chain_indices.append(int(op_idx))
                    chain_ops.append(op)
                    chain_output_names.append(out_name)
                    squeeze_axis_rewrites.append((int(op_idx), [int(v) for v in mapped_axes]))
                    current_tensor = out_name
                    seen_squeeze = True
                    continue

                break

            if len(chain_ops) == 0 or not chain_build_valid or not seen_squeeze:
                continue
            if current_tensor not in model_outputs:
                continue
            if len(consumers.get(current_tensor, [])) != 0:
                continue

            # Verify strict linearity on the main path.
            linear_ok = True
            previous_tensor_name = pre_output_name
            chain_index_to_pos = {int(idx): pos for pos, idx in enumerate(chain_indices)}
            for op_idx, op in zip(chain_indices, chain_ops):
                if previous_tensor_name not in set(str(v) for v in op.inputs):
                    linear_ok = False
                    break
                out_name = str(op.outputs[0]) if len(op.outputs) > 0 else ""
                if out_name == "":
                    linear_ok = False
                    break
                expected_users = [int(v) for v in consumers.get(out_name, [])]
                pos = int(chain_index_to_pos[int(op_idx)])
                if pos < len(chain_indices) - 1:
                    if expected_users != [int(chain_indices[pos + 1])]:
                        linear_ok = False
                        break
                else:
                    if len(expected_users) != 0:
                        linear_ok = False
                        break
                previous_tensor_name = out_name
            if not linear_ok:
                continue

            tensors_for_quant_validation: List[Optional[TensorIR]] = [
                model_ir.tensors.get(pre_input_name, None),
                model_ir.tensors.get(pre_output_name, None),
            ] + [model_ir.tensors.get(name, None) for name in chain_output_names]
            if not _all_per_tensor_quantized(tensors_for_quant_validation):
                continue

            chain_index_set = set(int(v) for v in chain_indices)
            const_rewrite_ok = True
            for op_idx, side_input_index, side_input_name in chain_binary_specs:
                side_tensor = model_ir.tensors.get(side_input_name, None)
                if side_tensor is None or side_tensor.data is None:
                    const_rewrite_ok = False
                    break
                side_data = np.asarray(side_tensor.data)
                if int(side_data.size) == 1:
                    continue
                if side_data.ndim != 4:
                    const_rewrite_ok = False
                    break

                permuted_data = np.transpose(side_data, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
                side_users = [int(v) for v in consumers.get(side_input_name, [])]
                shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)

                target_const_name = str(side_input_name)
                if shared_outside_chain:
                    target_const_name = _unique_tensor_name(f"{side_input_name}_nhwc")
                    model_ir.tensors[target_const_name] = TensorIR(
                        name=target_const_name,
                        dtype=str(side_tensor.dtype),
                        shape=[int(v) for v in list(permuted_data.shape)],
                        shape_signature=[int(v) for v in list(permuted_data.shape)],
                        data=np.asarray(permuted_data),
                        is_variable=False,
                        quantization=_clone_quantization(side_tensor.quantization),
                    )
                else:
                    side_tensor.data = np.asarray(permuted_data)
                    side_tensor.shape = [int(v) for v in list(permuted_data.shape)]
                    side_tensor.shape_signature = [int(v) for v in list(permuted_data.shape)]

                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=model_ir.operators[int(op_idx)],
                    input_index=int(side_input_index),
                    new_input_name=target_const_name,
                )

            if not const_rewrite_ok:
                continue

            first_op = chain_ops[0]
            first_input_names = [str(v) for v in first_op.inputs]
            if len(first_input_names) == 1:
                if first_input_names[0] != pre_output_name:
                    continue
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=first_op,
                    new_inputs=[pre_input_name],
                )
            elif len(first_input_names) == 2:
                first_op_idx = int(chain_indices[0])
                main_input_index = int(chain_main_input_index.get(first_op_idx, -1))
                if main_input_index not in [0, 1]:
                    if first_input_names[0] == pre_output_name:
                        main_input_index = 0
                    elif first_input_names[1] == pre_output_name:
                        main_input_index = 1
                    else:
                        continue
                first_input_names[main_input_index] = str(pre_input_name)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=first_op,
                    new_inputs=first_input_names,
                )
            else:
                continue

            for squeeze_op_idx, mapped_axes in squeeze_axis_rewrites:
                squeeze_op = model_ir.operators[int(squeeze_op_idx)]
                squeeze_options = dict(squeeze_op.options) if isinstance(squeeze_op.options, dict) else {}
                squeeze_options["squeezeDims"] = [int(v) for v in mapped_axes]
                squeeze_op.options = squeeze_options

            for out_name in chain_output_names:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(out_name, None),
                    perm_nchw_to_nhwc,
                )

            del model_ir.operators[int(pre_idx)]
            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"rewritten_transposeconv_output_channel1_terminal_transpose_chains": int(rewritten)}


def _optimize_singleton_channel_layout_transpose_to_reshape(model_ir: ModelIR) -> Dict[str, int]:
    """
    Replace rank-4 NHWC<->NCHW TRANSPOSE with RESHAPE when channel dim is singleton.

    Safe cases:
    - NHWC -> NCHW with input shape [N,H,W,1]
    - NCHW -> NHWC with input shape [N,1,H,W]

    For C=1 these layout permutations are memory-order no-ops, so RESHAPE is exact.
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    for op in model_ir.operators:
        if str(op.op_type) != "TRANSPOSE" or len(op.inputs) < 2 or len(op.outputs) != 1:
            continue

        perm = _read_transpose_perm(model_ir, op)
        if perm not in [perm_nhwc_to_nchw, perm_nchw_to_nhwc]:
            continue

        input_name = str(op.inputs[0])
        output_name = str(op.outputs[0])
        input_tensor = model_ir.tensors.get(input_name, None)
        output_tensor = model_ir.tensors.get(output_name, None)
        if (
            input_tensor is None
            or output_tensor is None
            or not _is_fully_known_positive_shape(input_tensor.shape)
            or not _is_fully_known_positive_shape(output_tensor.shape)
        ):
            continue

        input_shape = [int(v) for v in list(input_tensor.shape)]
        output_shape = [int(v) for v in list(output_tensor.shape)]
        if len(input_shape) != 4 or len(output_shape) != 4:
            continue

        if perm == perm_nhwc_to_nchw:
            if int(input_shape[3]) != 1 or int(output_shape[1]) != 1:
                continue
        else:
            if int(input_shape[1]) != 1 or int(output_shape[3]) != 1:
                continue

        expected_output_shape = _permute_shape(input_shape, perm)
        if expected_output_shape is None or [int(v) for v in list(expected_output_shape)] != output_shape:
            continue

        reshape_shape_name = _unique_tensor_name(f"{output_name}_reshape_shape")
        model_ir.tensors[reshape_shape_name] = TensorIR(
            name=reshape_shape_name,
            dtype="INT32",
            shape=[len(output_shape)],
            shape_signature=[len(output_shape)],
            data=np.asarray(output_shape, dtype=np.int32),
            is_variable=False,
            quantization=None,
        )

        op.op_type = "RESHAPE"
        op.inputs = [input_name, reshape_shape_name]
        op.options = {"newShape": [int(v) for v in output_shape]}
        rewritten += 1

    if rewritten > 0:
        _prune_unused_tensors(model_ir)
    return {"rewritten_singleton_channel_layout_transpose_to_reshape": int(rewritten)}


def _optimize_singleton_spatial_nhwc_transpose_reshape_flatten(model_ir: ModelIR) -> Dict[str, int]:
    """
    Remove NHWC->NCHW transpose before 2D flatten reshape when spatial dims are 1x1.

    Pattern:
      x_nhwc [N,1,1,C] -> TRANSPOSE(0,3,1,2) -> x_nchw [N,C,1,1]
      x_nchw -> RESHAPE -> y [N,C]

    For singleton spatial dims, flatten result is identical without transpose:
      RESHAPE(x_nhwc) -> y
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for transpose_idx, transpose_op in enumerate(model_ir.operators):
            if (
                str(transpose_op.op_type) != "TRANSPOSE"
                or len(transpose_op.inputs) < 2
                or len(transpose_op.outputs) != 1
                or _read_transpose_perm(model_ir, transpose_op) != perm_nhwc_to_nchw
            ):
                continue

            transpose_input_name = str(transpose_op.inputs[0])
            transpose_output_name = str(transpose_op.outputs[0])
            users = [int(v) for v in consumers.get(transpose_output_name, [])]
            if len(users) != 1:
                continue

            reshape_idx = int(users[0])
            reshape_op = model_ir.operators[int(reshape_idx)]
            if (
                str(reshape_op.op_type) != "RESHAPE"
                or len(reshape_op.inputs) < 1
                or str(reshape_op.inputs[0]) != transpose_output_name
                or len(reshape_op.outputs) != 1
            ):
                continue

            input_tensor = model_ir.tensors.get(transpose_input_name, None)
            output_tensor = model_ir.tensors.get(transpose_output_name, None)
            reshape_output_tensor = model_ir.tensors.get(str(reshape_op.outputs[0]), None)
            if (
                input_tensor is None
                or output_tensor is None
                or reshape_output_tensor is None
                or not _is_fully_known_positive_shape(input_tensor.shape)
                or not _is_fully_known_positive_shape(output_tensor.shape)
                or not _is_fully_known_positive_shape(reshape_output_tensor.shape)
            ):
                continue

            input_shape = [int(v) for v in list(input_tensor.shape)]
            output_shape = [int(v) for v in list(output_tensor.shape)]
            reshape_output_shape = [int(v) for v in list(reshape_output_tensor.shape)]
            if len(input_shape) != 4 or len(output_shape) != 4 or len(reshape_output_shape) != 2:
                continue
            if int(input_shape[1]) != 1 or int(input_shape[2]) != 1:
                continue
            expected_output_shape = _permute_shape(input_shape, perm_nhwc_to_nchw)
            if expected_output_shape is None or [int(v) for v in list(expected_output_shape)] != output_shape:
                continue
            if int(reshape_output_shape[1]) != int(input_shape[3]):
                continue

            reshape_inputs = [str(v) for v in list(reshape_op.inputs)]
            reshape_inputs[0] = str(transpose_input_name)
            _set_operator_inputs(
                model_ir=model_ir,
                op=reshape_op,
                new_inputs=reshape_inputs,
            )
            del model_ir.operators[int(transpose_idx)]
            rewritten += 1
            changed = True
            break

        if not changed:
            break

    if rewritten > 0:
        _prune_unused_tensors(model_ir)
    return {"optimized_singleton_spatial_nhwc_transpose_reshape_flatten": int(rewritten)}


def _optimize_singleton_reshape_concat_post_transpose_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Rewrite singleton-channel NCHW concat blocks back to NHWC and remove trailing transpose.

    Target:
      x_i_nhwc --RESHAPE([N,1,H,W])--> x_i_nchw (subset of inputs; some may be reused elsewhere)
      c_nchw --CONCAT(axis=1)--> y_nchw --TRANSPOSE(0,2,3,1)--> y_nhwc

    Rewrite:
      - CONCAT inputs switch to NHWC aliases (reshape sources when available)
      - direct singleton NCHW inputs receive local NCHW->NHWC RESHAPE adapters
      - CONCAT axis becomes 3
      - trailing TRANSPOSE is removed and CONCAT directly produces y_nhwc
    """
    rewritten = 0
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    perm_nhwc_to_nchw = [0, 3, 1, 2]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for post_idx, post_op in enumerate(model_ir.operators):
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc
            ):
                continue

            concat_output_name = str(post_op.inputs[0])
            post_output_name = str(post_op.outputs[0])
            if concat_output_name in model_outputs:
                continue

            concat_idx = producers.get(concat_output_name, None)
            if concat_idx is None:
                continue
            concat_op = model_ir.operators[int(concat_idx)]
            if str(concat_op.op_type) != "CONCATENATION" or len(concat_op.outputs) != 1:
                continue
            if str(concat_op.outputs[0]) != concat_output_name:
                continue
            concat_axis = int(concat_op.options.get("axis", 1))
            if concat_axis < 0:
                concat_axis += 4
            if concat_axis != 1:
                continue
            if set(int(v) for v in consumers.get(concat_output_name, [])) != {int(post_idx)}:
                continue

            concat_inputs = [str(v) for v in list(concat_op.inputs)]
            if len(concat_inputs) < 2:
                continue

            mapped_concat_inputs: List[str] = []
            reshape_ops_to_remove: List[OperatorIR] = []
            adapters_to_insert: List[Tuple[str, str, str, List[int]]] = []
            valid = True

            for input_name in concat_inputs:
                input_tensor = model_ir.tensors.get(str(input_name), None)
                if (
                    input_tensor is None
                    or not _is_fully_known_positive_shape(input_tensor.shape)
                    or len(list(input_tensor.shape)) != 4
                ):
                    valid = False
                    break
                input_shape = [int(v) for v in list(input_tensor.shape)]

                input_prod_idx = producers.get(str(input_name), None)
                if input_prod_idx is not None:
                    input_prod_op = model_ir.operators[int(input_prod_idx)]
                    if (
                        str(input_prod_op.op_type) == "RESHAPE"
                        and len(input_prod_op.inputs) >= 1
                        and len(input_prod_op.outputs) == 1
                        and str(input_prod_op.outputs[0]) == str(input_name)
                    ):
                        source_name = str(input_prod_op.inputs[0])
                        source_tensor = model_ir.tensors.get(source_name, None)
                        if (
                            source_tensor is not None
                            and _is_fully_known_positive_shape(source_tensor.shape)
                            and len(list(source_tensor.shape)) == 4
                        ):
                            source_shape = [int(v) for v in list(source_tensor.shape)]
                            expected_shape = _permute_shape(source_shape, perm_nhwc_to_nchw)
                            if (
                                expected_shape is not None
                                and [int(v) for v in list(expected_shape)] == input_shape
                                and int(source_shape[3]) == 1
                                and int(input_shape[1]) == 1
                            ):
                                mapped_concat_inputs.append(str(source_name))
                                input_users = [int(v) for v in consumers.get(str(input_name), [])]
                                if set(input_users) == {int(concat_idx)}:
                                    reshape_ops_to_remove.append(input_prod_op)
                                continue

                # Direct NCHW singleton input: create local NCHW->NHWC reshape adapter.
                if int(input_shape[1]) != 1:
                    valid = False
                    break
                nhwc_shape = _permute_shape(input_shape, perm_nchw_to_nhwc)
                if nhwc_shape is None or len(nhwc_shape) != 4 or int(nhwc_shape[3]) != 1:
                    valid = False
                    break

                adapter_name = _unique_tensor_name(f"{input_name}_nhwc_adapter")
                shape_name = _unique_tensor_name(f"{adapter_name}_reshape_shape")
                adapters_to_insert.append(
                    (
                        str(input_name),
                        str(adapter_name),
                        str(shape_name),
                        [int(v) for v in list(nhwc_shape)],
                    )
                )
                mapped_concat_inputs.append(str(adapter_name))

            if not valid:
                continue

            # Insert local adapters right before concat.
            if len(adapters_to_insert) > 0:
                concat_pos = int(model_ir.operators.index(concat_op))
                insert_pos = int(concat_pos)
                for source_name, adapter_name, shape_name, nhwc_shape in adapters_to_insert:
                    source_tensor = model_ir.tensors.get(source_name, None)
                    source_dtype = str(source_tensor.dtype) if source_tensor is not None else "FLOAT32"
                    source_quant = (
                        _clone_quantization(source_tensor.quantization)
                        if source_tensor is not None
                        else None
                    )
                    model_ir.tensors[shape_name] = TensorIR(
                        name=str(shape_name),
                        dtype="INT32",
                        shape=[len(nhwc_shape)],
                        shape_signature=[len(nhwc_shape)],
                        data=np.asarray(nhwc_shape, dtype=np.int32),
                        is_variable=False,
                        quantization=None,
                    )
                    model_ir.tensors[adapter_name] = TensorIR(
                        name=str(adapter_name),
                        dtype=str(source_dtype),
                        shape=[int(v) for v in list(nhwc_shape)],
                        shape_signature=[int(v) for v in list(nhwc_shape)],
                        data=None,
                        is_variable=False,
                        quantization=_clone_quantization(source_quant),
                    )
                    model_ir.operators.insert(
                        int(insert_pos),
                        OperatorIR(
                            op_type="RESHAPE",
                            inputs=[str(source_name), str(shape_name)],
                            outputs=[str(adapter_name)],
                            options={"newShape": [int(v) for v in list(nhwc_shape)]},
                        ),
                    )
                    insert_pos += 1

            # Re-find operators after insertion.
            concat_op = next((op for op in model_ir.operators if op is concat_op), None)
            post_op = next((op for op in model_ir.operators if op is post_op), None)
            if concat_op is None or post_op is None:
                continue

            concat_old_output_name = str(concat_op.outputs[0])
            concat_op.options = {
                **(dict(concat_op.options) if isinstance(concat_op.options, dict) else {}),
                "axis": 3,
            }
            _set_operator_inputs(
                model_ir=model_ir,
                op=concat_op,
                new_inputs=[str(v) for v in mapped_concat_inputs],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=concat_op,
                new_outputs=[str(post_output_name)],
            )
            _replace_tensor_inputs(model_ir, concat_old_output_name, post_output_name)

            post_out_tensor = model_ir.tensors.get(str(post_output_name), None)
            if post_out_tensor is not None and post_out_tensor.shape is not None and len(list(post_out_tensor.shape)) == 4:
                # Keep transpose output metadata authoritative.
                pass
            else:
                concat_old_tensor = model_ir.tensors.get(str(concat_old_output_name), None)
                if concat_old_tensor is not None and concat_old_tensor.shape is not None:
                    mapped_shape = _permute_shape(
                        [int(v) for v in list(concat_old_tensor.shape)],
                        perm_nchw_to_nhwc,
                    )
                    if mapped_shape is not None:
                        model_ir.tensors[str(post_output_name)] = TensorIR(
                            name=str(post_output_name),
                            dtype=str(concat_old_tensor.dtype),
                            shape=[int(v) for v in list(mapped_shape)],
                            shape_signature=[int(v) for v in list(mapped_shape)],
                            data=None,
                            is_variable=False,
                            quantization=_clone_quantization(concat_old_tensor.quantization),
                        )

            remove_indices: List[int] = []
            post_index = next((idx for idx, op in enumerate(model_ir.operators) if op is post_op), None)
            if post_index is not None:
                remove_indices.append(int(post_index))
            for reshape_op in reshape_ops_to_remove:
                reshape_index = next((idx for idx, op in enumerate(model_ir.operators) if op is reshape_op), None)
                if reshape_index is not None:
                    remove_indices.append(int(reshape_index))
            for remove_idx in sorted(set(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"rewritten_singleton_reshape_concat_post_transpose_nhwc_chains": int(rewritten)}


def _optimize_transpose_unary_passthrough_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose wrappers around strict unary passthrough chains.

    Target:
      X --TRANSPOSE(P)--> A --(UNARY)*--> B --TRANSPOSE(inv(P))--> Y

    Rewrite:
      X --(UNARY)*--> Y

    Safety:
    - Unary chain must be strictly linear (single consumer per main-path output).
    - Only layout-agnostic unary ops are allowed.
    """
    rewritten = 0
    unary_passthrough_ops = {
        "RELU",
        "RELU6",
        "RELU_0_TO_1",
        "HARD_SWISH",
        "LEAKY_RELU",
        "LOGISTIC",
        "TANH",
        "GELU",
        "ABS",
        "NEG",
        "SQRT",
        "EXP",
        "FLOOR",
        "CEIL",
    }

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE":
                continue
            if len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_output_name in model_ir.outputs:
                continue

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue
            perm_post_expected = _invert_perm(perm_pre)
            if perm_post_expected is None:
                continue

            chain_indices: List[int] = []
            chain_ops: List[OperatorIR] = []
            chain_output_names: List[str] = []
            chain_main_input_index: Dict[int, int] = {}
            current_tensor = pre_output_name

            while True:
                current_users = [int(v) for v in consumers.get(current_tensor, [])]
                if len(current_users) != 1:
                    break
                op_idx = int(current_users[0])
                op = model_ir.operators[op_idx]
                op_type = str(op.op_type)
                if op_type not in unary_passthrough_ops:
                    break
                if len(op.inputs) != 1 or len(op.outputs) != 1:
                    break
                if str(op.inputs[0]) != current_tensor:
                    break
                out_name = str(op.outputs[0])
                if out_name in model_ir.outputs:
                    break
                chain_indices.append(int(op_idx))
                chain_ops.append(op)
                chain_output_names.append(out_name)
                current_tensor = out_name

            if len(chain_ops) == 0:
                continue

            tail_users = [int(v) for v in consumers.get(current_tensor, [])]
            if len(tail_users) != 1:
                continue
            post_idx = int(tail_users[0])
            if post_idx in set(chain_indices):
                continue
            post_op = model_ir.operators[int(post_idx)]
            if str(post_op.op_type) != "TRANSPOSE":
                continue
            if len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                continue
            if str(post_op.inputs[0]) != current_tensor:
                continue
            perm_post = _read_transpose_perm(model_ir, post_op)
            if perm_post is None or perm_post != perm_post_expected:
                continue
            post_output_name = str(post_op.outputs[0])

            # Rewire chain head to the pre-transpose source.
            _set_operator_inputs(
                model_ir=model_ir,
                op=chain_ops[0],
                new_inputs=[pre_input_name],
            )
            # Preserve output name expected after post-transpose.
            _set_operator_outputs(
                model_ir=model_ir,
                op=chain_ops[-1],
                new_outputs=[post_output_name],
            )

            # Update intermediate metadata to post-transpose layout.
            for out_name in chain_output_names[:-1]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(out_name, None),
                    perm_post_expected,
                )

            old_last_name = str(chain_output_names[-1])
            old_last_tensor = model_ir.tensors.get(old_last_name, None)
            post_output_tensor = model_ir.tensors.get(post_output_name, None)
            if old_last_tensor is not None and post_output_tensor is not None:
                post_output_tensor.dtype = str(old_last_tensor.dtype)
                post_output_tensor.quantization = _clone_quantization(old_last_tensor.quantization)
                post_output_tensor.shape = [int(v) for v in list(old_last_tensor.shape)]
                post_output_tensor.shape_signature = (
                    [int(v) for v in list(old_last_tensor.shape_signature)]
                    if old_last_tensor.shape_signature is not None
                    else [int(v) for v in list(old_last_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    post_output_tensor,
                    perm_post_expected,
                )

            remove_indices = sorted(list({int(pre_idx), int(post_idx)}), reverse=True)
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"rewritten_transpose_unary_passthrough_chains": int(rewritten)}


def _optimize_transpose_unary_fanout_inverse_post_bridges(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate transpose wrappers around unary fanout branches with inverse post-transpose consumers.

    Target:
      X --TRANSPOSE(P)--> A --(RELU|RELU6|LOGISTIC|TANH)--> B
      B --TRANSPOSE(inv(P))--> Y0
      B --TRANSPOSE(inv(P))--> Y1
      ...
      (optionally: B also has non-transpose legacy consumers)

    Rewrite:
      X --(UNARY)--> Y0
      (all uses of Y1... are rewired to Y0)
      If legacy consumers exist:
        keep one adapter TRANSPOSE(P): Y0 -> B for legacy consumers.

    Safety:
    - Pre-transpose output is consumed only by the unary op.
    - Inverse-post transpose consumers must use inv(P).
    - Fanout post-transpose outputs are not graph outputs.
    - If non-transpose legacy consumers exist, preserve B via one adapter.
    """
    rewritten = 0
    unary_ops = {"RELU", "RELU6", "RELU_0_TO_1", "HARD_SWISH", "LEAKY_RELU", "LOGISTIC", "TANH", "GELU"}

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_output_name in model_outputs:
                continue

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue
            perm_post_expected = _invert_perm(perm_pre)
            if perm_post_expected is None:
                continue

            unary_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(unary_users) != 1:
                continue
            unary_idx = int(unary_users[0])
            unary_op = model_ir.operators[unary_idx]
            if str(unary_op.op_type) not in unary_ops:
                continue
            if len(unary_op.inputs) != 1 or len(unary_op.outputs) != 1:
                continue
            if str(unary_op.inputs[0]) != pre_output_name:
                continue

            unary_output_name = str(unary_op.outputs[0])
            if unary_output_name in model_outputs:
                continue
            output_users = [int(v) for v in consumers.get(unary_output_name, [])]
            if len(output_users) == 0:
                continue

            post_indices: List[int] = []
            post_output_names: List[str] = []
            legacy_users: List[int] = []
            valid_users = True
            for user_idx in output_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == unary_output_name
                ):
                    perm_post = _read_transpose_perm(model_ir, user_op)
                    if perm_post is None or perm_post != perm_post_expected:
                        valid_users = False
                        break
                    post_output_name = str(user_op.outputs[0])
                    if post_output_name in model_outputs:
                        valid_users = False
                        break
                    post_indices.append(int(user_idx))
                    post_output_names.append(post_output_name)
                else:
                    legacy_users.append(int(user_idx))
            if not valid_users or len(post_indices) == 0:
                continue

            representative_output_name = str(post_output_names[0])
            _set_operator_inputs(
                model_ir=model_ir,
                op=unary_op,
                new_inputs=[pre_input_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=unary_op,
                new_outputs=[representative_output_name],
            )

            for post_output_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, post_output_name, representative_output_name)

            old_unary_tensor = model_ir.tensors.get(unary_output_name, None)
            representative_tensor = model_ir.tensors.get(representative_output_name, None)
            if old_unary_tensor is not None and representative_tensor is not None:
                representative_tensor.dtype = str(old_unary_tensor.dtype)
                representative_tensor.quantization = _clone_quantization(old_unary_tensor.quantization)

            if len(legacy_users) > 0:
                keep_post_idx = int(post_indices[0])
                keep_post_op = model_ir.operators[keep_post_idx]
                keep_perm_name = str(keep_post_op.inputs[1])
                keep_perm_tensor = model_ir.tensors.get(keep_perm_name, None)
                if keep_perm_tensor is not None:
                    keep_perm_tensor.data = np.asarray(perm_pre, dtype=np.int32)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_inputs=[representative_output_name, keep_perm_name],
                )
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_outputs=[unary_output_name],
                )
                remove_post_indices = [int(v) for v in post_indices[1:]]
            else:
                remove_post_indices = [int(v) for v in post_indices]

            remove_indices = sorted(list({int(pre_idx), *remove_post_indices}), reverse=True)
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"rewritten_transpose_unary_fanout_inverse_post_bridges": int(rewritten)}


def _optimize_transpose_unary_binary_full_post_fanout_bridges(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose wrappers around unary->binary chains with inverse post-transpose fanout.

    Target:
      X --T(P)--> X_t --(RELU|RELU6|LOGISTIC|TANH)--> U_t
      Y --T(P)--> Y_t
      U_t,Y_t --(ADD|SUB|MUL|DIV)--> Z_t
      Z_t --T(inv(P))--> Z0
      Z_t --T(inv(P))--> Z1
      ...

    Rewrite:
      X --(UNARY)--> U
      U,Y --(BINARY)--> Z0
      (all uses of Z1... are rewired to Z0)

    Safety:
    - The unary-side transpose output is consumed only by the unary op.
    - The unary output and the other transpose output are consumed only by the binary op.
    - All binary consumers are inverse post-transpose ops.
    - Intermediate tensors and post outputs are not graph outputs.
    """
    rewritten = 0
    unary_ops = {"RELU", "RELU6", "RELU_0_TO_1", "HARD_SWISH", "LOGISTIC", "TANH", "GELU"}
    binary_ops = {"ADD", "SUB", "MUL", "DIV"}

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for mid_idx, mid_op in enumerate(model_ir.operators):
            if str(mid_op.op_type) not in binary_ops:
                continue
            if len(mid_op.inputs) != 2 or len(mid_op.outputs) != 1:
                continue

            in0_name = str(mid_op.inputs[0])
            in1_name = str(mid_op.inputs[1])
            out_name = str(mid_op.outputs[0])

            if in0_name in model_outputs or in1_name in model_outputs or out_name in model_outputs:
                continue

            # One binary input must be produced by unary-from-transpose,
            # and the other by a matching transpose.
            candidate = None
            for unary_on_lhs in [True, False]:
                unary_input_name = in0_name if unary_on_lhs else in1_name
                other_input_name = in1_name if unary_on_lhs else in0_name

                unary_idx = producers.get(unary_input_name, None)
                if unary_idx is None:
                    continue
                unary_op = model_ir.operators[int(unary_idx)]
                if (
                    str(unary_op.op_type) not in unary_ops
                    or len(unary_op.inputs) != 1
                    or len(unary_op.outputs) != 1
                    or str(unary_op.outputs[0]) != unary_input_name
                ):
                    continue

                pre_unary_out_name = str(unary_op.inputs[0])
                pre_unary_idx = producers.get(pre_unary_out_name, None)
                if pre_unary_idx is None:
                    continue
                pre_unary_op = model_ir.operators[int(pre_unary_idx)]
                if (
                    str(pre_unary_op.op_type) != "TRANSPOSE"
                    or len(pre_unary_op.inputs) < 2
                    or len(pre_unary_op.outputs) != 1
                    or str(pre_unary_op.outputs[0]) != pre_unary_out_name
                ):
                    continue

                pre_other_idx = producers.get(other_input_name, None)
                if pre_other_idx is None:
                    continue
                pre_other_op = model_ir.operators[int(pre_other_idx)]
                if (
                    str(pre_other_op.op_type) != "TRANSPOSE"
                    or len(pre_other_op.inputs) < 2
                    or len(pre_other_op.outputs) != 1
                    or str(pre_other_op.outputs[0]) != other_input_name
                ):
                    continue

                if set(consumers.get(pre_unary_out_name, [])) != {int(unary_idx)}:
                    continue
                if set(consumers.get(unary_input_name, [])) != {int(mid_idx)}:
                    continue
                if set(consumers.get(other_input_name, [])) != {int(mid_idx)}:
                    continue

                perm_pre_unary = _read_transpose_perm(model_ir, pre_unary_op)
                perm_pre_other = _read_transpose_perm(model_ir, pre_other_op)
                if perm_pre_unary is None or perm_pre_other is None:
                    continue
                if perm_pre_unary != perm_pre_other:
                    continue

                candidate = {
                    "unary_on_lhs": bool(unary_on_lhs),
                    "unary_idx": int(unary_idx),
                    "unary_op": unary_op,
                    "unary_input_name": unary_input_name,
                    "pre_unary_idx": int(pre_unary_idx),
                    "pre_unary_op": pre_unary_op,
                    "pre_unary_out_name": pre_unary_out_name,
                    "other_input_name": other_input_name,
                    "pre_other_idx": int(pre_other_idx),
                    "pre_other_op": pre_other_op,
                    "perm_pre": perm_pre_unary,
                }
                break

            if candidate is None:
                continue

            unary_idx = int(candidate["unary_idx"])
            unary_op = candidate["unary_op"]
            unary_input_name = str(candidate["unary_input_name"])
            pre_unary_idx = int(candidate["pre_unary_idx"])
            pre_unary_op = candidate["pre_unary_op"]
            pre_unary_out_name = str(candidate["pre_unary_out_name"])
            other_input_name = str(candidate["other_input_name"])
            pre_other_idx = int(candidate["pre_other_idx"])
            pre_other_op = candidate["pre_other_op"]
            perm_pre = candidate["perm_pre"]
            unary_on_lhs = bool(candidate["unary_on_lhs"])

            out_users = [int(v) for v in consumers.get(out_name, []) if int(v) != int(mid_idx)]
            if len(out_users) == 0:
                continue

            post_indices: List[int] = []
            post_output_names: List[str] = []
            legacy_users: List[int] = []
            valid_users = True
            for user_idx in out_users:
                post_op = model_ir.operators[int(user_idx)]
                if (
                    str(post_op.op_type) == "TRANSPOSE"
                    and len(post_op.inputs) >= 2
                    and len(post_op.outputs) == 1
                    and str(post_op.inputs[0]) == out_name
                ):
                    perm_post = _read_transpose_perm(model_ir, post_op)
                    if perm_post is None or not _is_inverse_perm(perm_pre, perm_post):
                        valid_users = False
                        break
                    post_output_name = str(post_op.outputs[0])
                    if post_output_name in model_outputs:
                        valid_users = False
                        break
                    post_indices.append(int(user_idx))
                    post_output_names.append(post_output_name)
                else:
                    legacy_users.append(int(user_idx))

            if not valid_users or len(post_indices) == 0:
                continue

            if pre_unary_out_name in model_outputs:
                continue

            raw_unary_input_name = str(pre_unary_op.inputs[0])
            raw_other_input_name = str(pre_other_op.inputs[0])
            raw_unary_tensor = model_ir.tensors.get(raw_unary_input_name, None)
            raw_other_tensor = model_ir.tensors.get(raw_other_input_name, None)
            unary_input_tensor = model_ir.tensors.get(unary_input_name, None)
            other_input_tensor = model_ir.tensors.get(other_input_name, None)
            out_tensor = model_ir.tensors.get(out_name, None)
            if not _all_per_tensor_quantized(
                [raw_unary_tensor, raw_other_tensor, unary_input_tensor, other_input_tensor, out_tensor]
            ):
                continue

            raw_shape_unary = list(raw_unary_tensor.shape) if raw_unary_tensor is not None else None
            raw_shape_other = list(raw_other_tensor.shape) if raw_other_tensor is not None else None
            raw_broadcast_shape = _broadcast_static_shapes(raw_shape_unary, raw_shape_other)
            if raw_broadcast_shape is not None:
                mid_expected_shape = _permute_shape(list(raw_broadcast_shape), perm_pre)
                if mid_expected_shape is None:
                    continue

                in0_tensor = model_ir.tensors.get(in0_name, None)
                in1_tensor = model_ir.tensors.get(in1_name, None)
                in_shape0 = list(in0_tensor.shape) if in0_tensor is not None else None
                in_shape1 = list(in1_tensor.shape) if in1_tensor is not None else None
                mid_broadcast_shape = _broadcast_static_shapes(in_shape0, in_shape1)
                if mid_broadcast_shape is not None and not _shapes_match_if_known(mid_broadcast_shape, mid_expected_shape):
                    continue

                out_shape = list(out_tensor.shape) if out_tensor is not None else None
                if not _shapes_match_if_known(out_shape, mid_expected_shape):
                    continue

                valid_post_shapes = True
                for post_output_name in post_output_names:
                    post_tensor = model_ir.tensors.get(post_output_name, None)
                    post_shape = list(post_tensor.shape) if post_tensor is not None else None
                    if not _shapes_match_if_known(post_shape, raw_broadcast_shape):
                        valid_post_shapes = False
                        break
                if not valid_post_shapes:
                    continue

            canonical_post_output = str(post_output_names[0])
            canonical_tensor = model_ir.tensors.get(canonical_post_output, None)
            keep_post_idx = int(post_indices[0])
            keep_post_op = model_ir.operators[keep_post_idx]
            keep_post_perm_name = str(keep_post_op.inputs[1])

            _set_operator_inputs(
                model_ir=model_ir,
                op=unary_op,
                new_inputs=[raw_unary_input_name],
            )

            if unary_on_lhs:
                new_binary_inputs = [unary_input_name, raw_other_input_name]
            else:
                new_binary_inputs = [raw_other_input_name, unary_input_name]
            _set_operator_inputs(
                model_ir=model_ir,
                op=mid_op,
                new_inputs=new_binary_inputs,
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=mid_op,
                new_outputs=[canonical_post_output],
            )

            unary_out_tensor = model_ir.tensors.get(unary_input_name, None)
            if unary_out_tensor is not None and raw_unary_tensor is not None:
                unary_out_tensor.shape = [int(v) for v in list(raw_unary_tensor.shape)]
                unary_out_tensor.shape_signature = (
                    [int(v) for v in list(raw_unary_tensor.shape_signature)]
                    if raw_unary_tensor.shape_signature is not None
                    else [int(v) for v in list(raw_unary_tensor.shape)]
                )

            if canonical_tensor is not None and raw_broadcast_shape is not None:
                canonical_tensor.shape = [int(v) for v in list(raw_broadcast_shape)]
                raw_sig_unary = (
                    list(raw_unary_tensor.shape_signature)
                    if raw_unary_tensor is not None and raw_unary_tensor.shape_signature is not None
                    else list(raw_shape_unary) if raw_shape_unary is not None else None
                )
                raw_sig_other = (
                    list(raw_other_tensor.shape_signature)
                    if raw_other_tensor is not None and raw_other_tensor.shape_signature is not None
                    else list(raw_shape_other) if raw_shape_other is not None else None
                )
                raw_broadcast_signature = _broadcast_shape_signatures(raw_sig_unary, raw_sig_other)
                if raw_broadcast_signature is None:
                    raw_broadcast_signature = [int(v) for v in list(raw_broadcast_shape)]
                canonical_tensor.shape_signature = [int(v) for v in list(raw_broadcast_signature)]
                if out_tensor is not None:
                    canonical_tensor.dtype = str(out_tensor.dtype)
                    canonical_tensor.quantization = _clone_quantization(out_tensor.quantization)

            for post_output_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, post_output_name, canonical_post_output)

            if len(legacy_users) > 0:
                # Keep one adapter transpose for legacy NCHW consumers.
                keep_perm_tensor = model_ir.tensors.get(keep_post_perm_name, None)
                if keep_perm_tensor is not None:
                    keep_perm_tensor.data = np.asarray(perm_pre, dtype=np.int32)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_inputs=[canonical_post_output, keep_post_perm_name],
                )
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_outputs=[out_name],
                )
                post_remove_indices = [int(v) for v in post_indices[1:]]
            else:
                post_remove_indices = [int(v) for v in post_indices]

            remove_indices = sorted(
                list(set([int(pre_unary_idx), int(pre_other_idx)] + post_remove_indices)),
                reverse=True,
            )
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"rewritten_transpose_unary_binary_full_post_fanout_bridges": int(rewritten)}


def _optimize_trailing_output_transpose_passthrough_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate trailing layout transposes on output-side passthrough chains.

    Targets:
      X --TRANSPOSE(P)--> Y_out(graph output)
      X --TRANSPOSE(P)--> A --(UNARY|BINARY_WITH_CONST)*--> Y_out(graph output)

    Rewrite:
      X --(same chain without TRANSPOSE)--> Y_out

    Safety:
    - Main path must be strictly linear.
    - Binary ops must use singleton constant as side input.
    - Layout metadata is updated by applying inverse(P).
    """
    rewritten = 0
    preserve_layout_boundary_marker = "__preserve_layout_boundary__"
    unary_passthrough_ops = {
        "RELU",
        "RELU6",
        "RELU_0_TO_1",
        "HARD_SWISH",
        "LEAKY_RELU",
        "LOGISTIC",
        "TANH",
        "GELU",
        "ABS",
        "NEG",
        "SQRT",
        "EXP",
        "FLOOR",
        "CEIL",
    }
    binary_passthrough_ops = {"ADD", "SUB", "MUL", "DIV", "MAXIMUM", "MINIMUM"}

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE":
                continue
            if len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            pre_opts = dict(pre_op.options) if isinstance(pre_op.options, dict) else {}
            if bool(pre_opts.get(preserve_layout_boundary_marker, False)):
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue
            perm_inv = _invert_perm(perm_pre)
            if perm_inv is None:
                continue

            chain_indices: List[int] = []
            chain_ops: List[OperatorIR] = []
            chain_output_names: List[str] = []
            chain_main_input_index: Dict[int, int] = {}
            current_tensor = pre_output_name

            while True:
                current_users = [int(v) for v in consumers.get(current_tensor, [])]
                if len(current_users) != 1:
                    break
                op_idx = int(current_users[0])
                op = model_ir.operators[int(op_idx)]
                op_type = str(op.op_type)

                if op_type in unary_passthrough_ops:
                    if len(op.inputs) != 1 or len(op.outputs) != 1:
                        break
                    if str(op.inputs[0]) != current_tensor:
                        break
                    out_name = str(op.outputs[0])
                    chain_indices.append(int(op_idx))
                    chain_ops.append(op)
                    chain_output_names.append(out_name)
                    current_tensor = out_name
                    continue

                if op_type in binary_passthrough_ops:
                    if len(op.inputs) != 2 or len(op.outputs) != 1:
                        break
                    input_0 = str(op.inputs[0])
                    input_1 = str(op.inputs[1])
                    if input_0 == current_tensor:
                        side_input_name = input_1
                        main_input_index = 0
                    elif input_1 == current_tensor:
                        side_input_name = input_0
                        main_input_index = 1
                    else:
                        break
                    if not _is_singleton_constant_tensor(model_ir, side_input_name):
                        break
                    out_name = str(op.outputs[0])
                    chain_indices.append(int(op_idx))
                    chain_ops.append(op)
                    chain_output_names.append(out_name)
                    chain_main_input_index[int(op_idx)] = int(main_input_index)
                    current_tensor = out_name
                    continue

                break

            # Case 1: direct terminal transpose output.
            if len(chain_ops) == 0:
                # Leave terminal transpose for symmetric transpose-binary patterns so
                # dedicated bridge passes can remove both pre-transposes safely.
                terminal_binary_bridge_candidate = False
                producer_idx = producers.get(pre_input_name, None)
                if producer_idx is not None:
                    producer_op = model_ir.operators[int(producer_idx)]
                    producer_type = str(producer_op.op_type)
                    if (
                        producer_type in {"ADD", "SUB", "MUL", "DIV"}
                        and len(producer_op.inputs) == 2
                        and len(producer_op.outputs) == 1
                        and str(producer_op.outputs[0]) == pre_input_name
                    ):
                        mid_in0 = str(producer_op.inputs[0])
                        mid_in1 = str(producer_op.inputs[1])
                        pre0_idx = producers.get(mid_in0, None)
                        pre1_idx = producers.get(mid_in1, None)
                        if pre0_idx is not None and pre1_idx is not None:
                            pre0_op = model_ir.operators[int(pre0_idx)]
                            pre1_op = model_ir.operators[int(pre1_idx)]
                            if (
                                str(pre0_op.op_type) == "TRANSPOSE"
                                and str(pre1_op.op_type) == "TRANSPOSE"
                                and len(pre0_op.inputs) >= 2
                                and len(pre1_op.inputs) >= 2
                                and len(pre0_op.outputs) == 1
                                and len(pre1_op.outputs) == 1
                                and str(pre0_op.outputs[0]) == mid_in0
                                and str(pre1_op.outputs[0]) == mid_in1
                                and set(int(v) for v in consumers.get(mid_in0, [])) == {int(producer_idx)}
                                and set(int(v) for v in consumers.get(mid_in1, [])) == {int(producer_idx)}
                            ):
                                perm_mid0 = _read_transpose_perm(model_ir, pre0_op)
                                perm_mid1 = _read_transpose_perm(model_ir, pre1_op)
                                if (
                                    perm_mid0 is not None
                                    and perm_mid1 is not None
                                    and perm_mid0 == perm_mid1
                                    and _is_inverse_perm(perm_mid0, perm_pre)
                                ):
                                    terminal_binary_bridge_candidate = True
                if terminal_binary_bridge_candidate:
                    continue

                if pre_output_name not in model_outputs:
                    continue
                if len(consumers.get(pre_output_name, [])) != 0:
                    continue
                producer_idx = producers.get(pre_input_name, None)
                if producer_idx is None:
                    continue
                producer_op = model_ir.operators[int(producer_idx)]
                # Keep explicit output transpose after SOFTMAX to preserve graph
                # output layout contract (axis semantics are layout-sensitive).
                if str(producer_op.op_type) == "SOFTMAX":
                    continue
                producer_outputs = [str(v) for v in list(producer_op.outputs)]
                if pre_input_name not in set(producer_outputs):
                    continue
                new_outputs = [
                    str(pre_output_name) if str(v) == str(pre_input_name) else str(v)
                    for v in producer_outputs
                ]
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=producer_op,
                    new_outputs=new_outputs,
                )
                src_tensor = model_ir.tensors.get(pre_input_name, None)
                dst_tensor = model_ir.tensors.get(pre_output_name, None)
                if src_tensor is not None and dst_tensor is not None:
                    dst_tensor.dtype = str(src_tensor.dtype)
                    dst_tensor.quantization = _clone_quantization(src_tensor.quantization)
                    dst_tensor.shape = [int(v) for v in list(src_tensor.shape)]
                    dst_tensor.shape_signature = (
                        [int(v) for v in list(src_tensor.shape_signature)]
                        if src_tensor.shape_signature is not None
                        else [int(v) for v in list(src_tensor.shape)]
                    )
                del model_ir.operators[int(pre_idx)]
                rewritten += 1
                changed = True
                break

            # Case 2: transpose + passthrough chain ending at graph output.
            if current_tensor not in model_outputs:
                continue

            # Rewire chain head to bypass pre-transpose.
            first_op = chain_ops[0]
            first_inputs = [str(v) for v in list(first_op.inputs)]
            if str(first_op.op_type) in unary_passthrough_ops:
                if len(first_inputs) != 1 or first_inputs[0] != pre_output_name:
                    continue
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=first_op,
                    new_inputs=[pre_input_name],
                )
            else:
                if len(first_inputs) != 2:
                    continue
                main_input_index = int(chain_main_input_index.get(int(chain_indices[0]), -1))
                if main_input_index not in [0, 1]:
                    if first_inputs[0] == pre_output_name:
                        main_input_index = 0
                    elif first_inputs[1] == pre_output_name:
                        main_input_index = 1
                    else:
                        continue
                first_inputs[main_input_index] = str(pre_input_name)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=first_op,
                    new_inputs=first_inputs,
                )

            # Adjust metadata from transposed layout back to source layout.
            for out_name in chain_output_names:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(out_name), None),
                    perm_inv,
                )

            del model_ir.operators[int(pre_idx)]
            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"rewritten_trailing_output_transpose_passthrough_chains": int(rewritten)}


def _optimize_dequant_prelu_quantize_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold DEQUANTIZE->PRELU->QUANTIZE into quantized PRELU.

    Target pattern:
      Xq --DEQUANTIZE--> Xf --PRELU(alpha_f)--> Yf --QUANTIZE--> Yq

    Rewritten:
      Xq --PRELU(alpha_q)--> Yq
    """
    folded = 0

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for dq_idx, dq_op in enumerate(model_ir.operators):
            if str(dq_op.op_type) != "DEQUANTIZE" or len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                continue
            q_in_name = str(dq_op.inputs[0])
            f_in_name = str(dq_op.outputs[0])

            prelu_users = consumers.get(f_in_name, [])
            if len(prelu_users) != 1:
                continue
            prelu_idx = int(prelu_users[0])
            prelu_op = model_ir.operators[prelu_idx]
            if str(prelu_op.op_type) != "PRELU" or len(prelu_op.inputs) != 2 or len(prelu_op.outputs) != 1:
                continue
            if str(prelu_op.inputs[0]) != f_in_name:
                continue

            f_out_name = str(prelu_op.outputs[0])
            q_users = consumers.get(f_out_name, [])
            if len(q_users) != 1:
                continue
            q_idx = int(q_users[0])
            q_op = model_ir.operators[q_idx]
            if str(q_op.op_type) != "QUANTIZE" or len(q_op.inputs) != 1 or len(q_op.outputs) != 1:
                continue
            if str(q_op.inputs[0]) != f_out_name:
                continue
            q_out_name = str(q_op.outputs[0])

            if f_in_name in model_ir.outputs or f_out_name in model_ir.outputs:
                continue

            q_in_tensor = model_ir.tensors.get(q_in_name, None)
            q_out_tensor = model_ir.tensors.get(q_out_name, None)
            alpha_name = str(prelu_op.inputs[1])
            alpha_tensor = model_ir.tensors.get(alpha_name, None)
            if q_in_tensor is None or q_out_tensor is None or alpha_tensor is None:
                continue
            if not _all_per_tensor_quantized([q_in_tensor, q_out_tensor]):
                continue

            target_dtype = str(q_in_tensor.dtype)
            if target_dtype not in {"INT8", "UINT8"}:
                continue
            if str(q_out_tensor.dtype) != target_dtype:
                continue
            if not isinstance(alpha_tensor.data, np.ndarray):
                continue

            try:
                alpha_q, alpha_qparams = _quantize_prelu_alpha(alpha_tensor.data, target_dtype)
            except Exception:
                continue

            alpha_users = consumers.get(alpha_name, [])
            if len(alpha_users) == 1 and int(alpha_users[0]) == int(prelu_idx):
                alpha_q_name = alpha_name
                alpha_tensor.data = np.asarray(alpha_q)
                alpha_tensor.dtype = target_dtype
                alpha_tensor.shape = [int(v) for v in alpha_q.shape]
                alpha_tensor.shape_signature = [int(v) for v in alpha_q.shape]
                alpha_tensor.quantization = alpha_qparams
            else:
                alpha_q_name = _unique_tensor_name(f"{alpha_name}_q")
                model_ir.tensors[alpha_q_name] = TensorIR(
                    name=alpha_q_name,
                    dtype=target_dtype,
                    shape=[int(v) for v in alpha_q.shape],
                    shape_signature=[int(v) for v in alpha_q.shape],
                    data=np.asarray(alpha_q),
                    is_variable=False,
                    quantization=alpha_qparams,
                )

            _set_operator_inputs(
                model_ir=model_ir,
                op=prelu_op,
                new_inputs=[q_in_name, alpha_q_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=prelu_op,
                new_outputs=[q_out_name],
            )

            for remove_idx in sorted([dq_idx, q_idx], reverse=True):
                del model_ir.operators[remove_idx]
            folded += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"folded_dequant_prelu_quantize_chains": int(folded)}


def _optimize_dequant_prelu_depthwise_quantize_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold DEQUANTIZE->PRELU->DEPTHWISE_CONV_2D->QUANTIZE into quantized PRELU+DEPTHWISE_CONV_2D.

    Target pattern:
      Xq --DEQUANTIZE--> Xf --PRELU(alpha_f)--> Pf --DEPTHWISE_CONV_2D(w_f,b_f)--> Yf --QUANTIZE--> Yq

    Rewritten:
      Xq --PRELU(alpha_q)--> Pq --DEPTHWISE_CONV_2D(w_q,b_q)--> Yq
    """
    folded = 0

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for dq_idx, dq_op in enumerate(model_ir.operators):
            if str(dq_op.op_type) != "DEQUANTIZE" or len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                continue
            q_in_name = str(dq_op.inputs[0])
            f_in_name = str(dq_op.outputs[0])

            prelu_users = consumers.get(f_in_name, [])
            if len(prelu_users) != 1:
                continue
            prelu_idx = int(prelu_users[0])
            prelu_op = model_ir.operators[prelu_idx]
            if str(prelu_op.op_type) != "PRELU" or len(prelu_op.inputs) != 2 or len(prelu_op.outputs) != 1:
                continue
            if str(prelu_op.inputs[0]) != f_in_name:
                continue
            p_f_name = str(prelu_op.outputs[0])

            dw_users = consumers.get(p_f_name, [])
            if len(dw_users) != 1:
                continue
            dw_idx = int(dw_users[0])
            dw_op = model_ir.operators[dw_idx]
            if str(dw_op.op_type) != "DEPTHWISE_CONV_2D" or len(dw_op.inputs) != 3 or len(dw_op.outputs) != 1:
                continue
            if str(dw_op.inputs[0]) != p_f_name:
                continue
            y_f_name = str(dw_op.outputs[0])

            q_users = consumers.get(y_f_name, [])
            if len(q_users) != 1:
                continue
            q_idx = int(q_users[0])
            q_op = model_ir.operators[q_idx]
            if str(q_op.op_type) != "QUANTIZE" or len(q_op.inputs) != 1 or len(q_op.outputs) != 1:
                continue
            if str(q_op.inputs[0]) != y_f_name:
                continue
            y_q_name = str(q_op.outputs[0])

            if f_in_name in model_ir.outputs or p_f_name in model_ir.outputs or y_f_name in model_ir.outputs:
                continue

            q_in_tensor = model_ir.tensors.get(q_in_name, None)
            y_q_tensor = model_ir.tensors.get(y_q_name, None)
            alpha_tensor = model_ir.tensors.get(str(prelu_op.inputs[1]), None)
            w_f_tensor = model_ir.tensors.get(str(dw_op.inputs[1]), None)
            b_f_tensor = model_ir.tensors.get(str(dw_op.inputs[2]), None)
            if (
                q_in_tensor is None
                or y_q_tensor is None
                or alpha_tensor is None
                or w_f_tensor is None
                or b_f_tensor is None
            ):
                continue
            if not _all_per_tensor_quantized([q_in_tensor, y_q_tensor]):
                continue

            target_dtype = str(q_in_tensor.dtype)
            if target_dtype not in {"INT8", "UINT8"}:
                continue
            if str(y_q_tensor.dtype) != target_dtype:
                continue
            if not isinstance(alpha_tensor.data, np.ndarray):
                continue
            if not isinstance(w_f_tensor.data, np.ndarray):
                continue
            if not isinstance(b_f_tensor.data, np.ndarray):
                continue

            x_qparams = _get_per_tensor_scale_zero_point(q_in_tensor.quantization)
            if x_qparams is None:
                continue
            x_scale, _x_zero_point = x_qparams

            weights_f = np.asarray(w_f_tensor.data, dtype=np.float32)
            if weights_f.ndim != 4:
                continue
            bias_f = np.asarray(b_f_tensor.data, dtype=np.float32).reshape(-1)
            if bias_f.size != int(weights_f.shape[-1]):
                continue

            try:
                alpha_q, alpha_qparams = _quantize_prelu_alpha(alpha_tensor.data, target_dtype)
                w_q, w_qparams = _quantize_tensor_per_tensor(weights_f, target_dtype)
            except Exception:
                continue

            w_scale = float(w_qparams.scale[0])
            bias_scale = max(float(x_scale * w_scale), 1e-12)
            bias_q = np.clip(
                np.round(bias_f / bias_scale),
                np.iinfo(np.int32).min,
                np.iinfo(np.int32).max,
            ).astype(np.int32)
            b_qparams = QuantParamIR(
                scale=[float(bias_scale)],
                zero_point=[0],
                quantized_dimension=0,
            )

            alpha_q_name = _unique_tensor_name(f"{prelu_op.inputs[1]}_q")
            model_ir.tensors[alpha_q_name] = TensorIR(
                name=alpha_q_name,
                dtype=target_dtype,
                shape=[int(v) for v in alpha_q.shape],
                shape_signature=[int(v) for v in alpha_q.shape],
                data=np.asarray(alpha_q),
                is_variable=False,
                quantization=alpha_qparams,
            )

            w_q_name = _unique_tensor_name(f"{dw_op.inputs[1]}_q")
            model_ir.tensors[w_q_name] = TensorIR(
                name=w_q_name,
                dtype=target_dtype,
                shape=[int(v) for v in w_q.shape],
                shape_signature=[int(v) for v in w_q.shape],
                data=np.asarray(w_q),
                is_variable=False,
                quantization=w_qparams,
            )

            b_q_name = _unique_tensor_name(f"{dw_op.inputs[2]}_q")
            model_ir.tensors[b_q_name] = TensorIR(
                name=b_q_name,
                dtype="INT32",
                shape=[int(v) for v in bias_q.shape],
                shape_signature=[int(v) for v in bias_q.shape],
                data=np.asarray(bias_q),
                is_variable=False,
                quantization=b_qparams,
            )

            p_q_tensor = model_ir.tensors.get(p_f_name, None)
            if p_q_tensor is not None:
                p_q_tensor.dtype = target_dtype
                p_q_tensor.quantization = _clone_quantization(q_in_tensor.quantization)

            _set_operator_inputs(
                model_ir=model_ir,
                op=prelu_op,
                new_inputs=[q_in_name, alpha_q_name],
            )
            _set_operator_inputs(
                model_ir=model_ir,
                op=dw_op,
                new_inputs=[p_f_name, w_q_name, b_q_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=dw_op,
                new_outputs=[y_q_name],
            )

            for remove_idx in sorted([dq_idx, q_idx], reverse=True):
                del model_ir.operators[remove_idx]
            folded += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"folded_dequant_prelu_depthwise_quantize_chains": int(folded)}


def _optimize_dequant_transposeconv_quantize_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold DEQUANTIZE->TRANSPOSE_CONV->QUANTIZE into quantized TRANSPOSE_CONV.

    Target pattern:
      Xq --DEQUANTIZE--> Xf --TRANSPOSE_CONV(Wf)--> Yf --QUANTIZE--> Yq

    Rewritten:
      Xq --TRANSPOSE_CONV(Wq)--> Yq

    Safety conditions:
    - Linear chain topology.
    - TRANSPOSE_CONV data input is the DEQUANTIZE output.
    - INT8 per-tensor activation quantization on Xq/Yq.
    - Weight tensor is a constant rank-4 tensor.
    """
    folded = 0

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for dq_idx, dq_op in enumerate(model_ir.operators):
            if str(dq_op.op_type) != "DEQUANTIZE" or len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                continue
            q_in_name = str(dq_op.inputs[0])
            f_in_name = str(dq_op.outputs[0])

            tc_users = consumers.get(f_in_name, [])
            if len(tc_users) != 1:
                continue
            tc_idx = int(tc_users[0])
            tc_op = model_ir.operators[tc_idx]
            if str(tc_op.op_type) != "TRANSPOSE_CONV" or len(tc_op.inputs) != 3 or len(tc_op.outputs) != 1:
                continue
            # TRANSPOSE_CONV inputs: [output_shape, filter, input]
            if str(tc_op.inputs[2]) != f_in_name:
                continue
            f_out_name = str(tc_op.outputs[0])

            q_users = consumers.get(f_out_name, [])
            if len(q_users) != 1:
                continue
            q_idx = int(q_users[0])
            q_op = model_ir.operators[q_idx]
            if str(q_op.op_type) != "QUANTIZE" or len(q_op.inputs) != 1 or len(q_op.outputs) != 1:
                continue
            if str(q_op.inputs[0]) != f_out_name:
                continue
            q_out_name = str(q_op.outputs[0])

            if f_in_name in model_ir.outputs or f_out_name in model_ir.outputs:
                continue

            q_in_tensor = model_ir.tensors.get(q_in_name, None)
            q_out_tensor = model_ir.tensors.get(q_out_name, None)
            f_out_tensor = model_ir.tensors.get(f_out_name, None)
            if q_in_tensor is None or q_out_tensor is None:
                continue
            if not _all_per_tensor_quantized([q_in_tensor, q_out_tensor]):
                continue

            q_in_dtype = str(q_in_tensor.dtype)
            q_out_dtype = str(q_out_tensor.dtype)
            if q_in_dtype != "INT8" or q_out_dtype != "INT8":
                continue
            if _get_per_tensor_scale_zero_point(q_in_tensor.quantization) is None:
                continue
            if _get_per_tensor_scale_zero_point(q_out_tensor.quantization) is None:
                continue

            w_name = str(tc_op.inputs[1])
            w_tensor = model_ir.tensors.get(w_name, None)
            if w_tensor is None or not isinstance(w_tensor.data, np.ndarray):
                continue
            w_data = np.asarray(w_tensor.data)
            if w_data.ndim != 4:
                continue

            if str(w_tensor.dtype) == "INT8" and _is_per_tensor_quantization(w_tensor.quantization):
                w_q_name = w_name
            elif str(w_tensor.dtype) in {"FLOAT32", "FLOAT16", "FLOAT64"}:
                try:
                    w_q, w_qparams = _quantize_tensor_per_tensor(
                        np.asarray(w_tensor.data, dtype=np.float32),
                        "INT8",
                    )
                except Exception:
                    continue

                w_users = [int(v) for v in consumers.get(w_name, [])]
                if len(w_users) == 1 and int(w_users[0]) == int(tc_idx):
                    w_q_name = w_name
                    w_tensor.data = np.asarray(w_q)
                    w_tensor.dtype = "INT8"
                    w_tensor.shape = [int(v) for v in list(w_q.shape)]
                    w_tensor.shape_signature = [int(v) for v in list(w_q.shape)]
                    w_tensor.quantization = w_qparams
                else:
                    w_q_name = _unique_tensor_name(f"{w_name}_q")
                    model_ir.tensors[w_q_name] = TensorIR(
                        name=w_q_name,
                        dtype="INT8",
                        shape=[int(v) for v in list(w_q.shape)],
                        shape_signature=[int(v) for v in list(w_q.shape)],
                        data=np.asarray(w_q),
                        is_variable=False,
                        quantization=w_qparams,
                    )
            else:
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=tc_op,
                new_inputs=[str(tc_op.inputs[0]), w_q_name, q_in_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=tc_op,
                new_outputs=[q_out_name],
            )
            # Quantized TRANSPOSE_CONV kernels are exposed with newer opcode versions.
            tc_op.version = max(int(tc_op.version), 3)

            q_out_tensor.dtype = "INT8"
            q_out_tensor.quantization = _clone_quantization(q_out_tensor.quantization)
            if f_out_tensor is not None:
                q_out_tensor.shape = [int(v) for v in list(f_out_tensor.shape)]
                q_out_tensor.shape_signature = (
                    [int(v) for v in list(f_out_tensor.shape_signature)]
                    if f_out_tensor.shape_signature is not None
                    else [int(v) for v in list(f_out_tensor.shape)]
                )

            for remove_idx in sorted([dq_idx, q_idx], reverse=True):
                del model_ir.operators[remove_idx]
            folded += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"folded_dequant_transposeconv_quantize_chains": int(folded)}


def _optimize_dequant_reshape_quantize_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold DEQUANTIZE->RESHAPE->QUANTIZE into quantized RESHAPE.

    Target pattern:
      Xq --DEQUANTIZE--> Xf --RESHAPE(shape)--> Yf --QUANTIZE--> Yq

    Rewritten:
      Xq --RESHAPE(shape)--> Yq

    Safety conditions:
    - Chain is linear (single consumer at each bridge tensor)
    - input/output quantized tensors use equivalent per-tensor quantization
    - input/output quantized dtypes are identical
    """
    folded = 0

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for dq_idx, dq_op in enumerate(model_ir.operators):
            if str(dq_op.op_type) != "DEQUANTIZE" or len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                continue
            q_in_name = str(dq_op.inputs[0])
            f_in_name = str(dq_op.outputs[0])

            reshape_users = consumers.get(f_in_name, [])
            if len(reshape_users) != 1:
                continue
            reshape_idx = int(reshape_users[0])
            reshape_op = model_ir.operators[reshape_idx]
            if str(reshape_op.op_type) != "RESHAPE" or len(reshape_op.inputs) < 1 or len(reshape_op.outputs) != 1:
                continue
            if str(reshape_op.inputs[0]) != f_in_name:
                continue
            f_out_name = str(reshape_op.outputs[0])

            q_users = consumers.get(f_out_name, [])
            if len(q_users) != 1:
                continue
            q_idx = int(q_users[0])
            q_op = model_ir.operators[q_idx]
            if str(q_op.op_type) != "QUANTIZE" or len(q_op.inputs) != 1 or len(q_op.outputs) != 1:
                continue
            if str(q_op.inputs[0]) != f_out_name:
                continue
            q_out_name = str(q_op.outputs[0])

            if f_in_name in model_ir.outputs or f_out_name in model_ir.outputs:
                continue

            q_in_tensor = model_ir.tensors.get(q_in_name, None)
            q_out_tensor = model_ir.tensors.get(q_out_name, None)
            f_out_tensor = model_ir.tensors.get(f_out_name, None)
            if q_in_tensor is None or q_out_tensor is None:
                continue
            if not _all_per_tensor_quantized([q_in_tensor, q_out_tensor]):
                continue
            if not _is_same_per_tensor_quantization(
                q_in_tensor.quantization,
                q_out_tensor.quantization,
            ):
                continue

            q_in_dtype = str(q_in_tensor.dtype)
            q_out_dtype = str(q_out_tensor.dtype)
            if q_in_dtype != q_out_dtype:
                continue
            if q_in_dtype in {"FLOAT16", "FLOAT32", "FLOAT64", "BOOL", "STRING"}:
                continue

            _replace_operator_input_at(
                model_ir=model_ir,
                op=reshape_op,
                input_index=0,
                new_input_name=q_in_name,
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=reshape_op,
                new_outputs=[q_out_name],
            )

            q_out_tensor.dtype = q_in_dtype
            q_out_tensor.quantization = _clone_quantization(q_in_tensor.quantization)
            if f_out_tensor is not None:
                q_out_tensor.shape = [int(v) for v in list(f_out_tensor.shape)]
                if f_out_tensor.shape_signature is not None:
                    q_out_tensor.shape_signature = [
                        int(v) for v in list(f_out_tensor.shape_signature)
                    ]
                else:
                    q_out_tensor.shape_signature = [int(v) for v in list(f_out_tensor.shape)]

            for remove_idx in sorted([dq_idx, q_idx], reverse=True):
                del model_ir.operators[remove_idx]
            folded += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"folded_dequant_reshape_quantize_chains": int(folded)}


def _optimize_dequant_hardsigmoid_quantize_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold DEQUANTIZE->HardSigmoid(expanded)->QUANTIZE into quantized ops.

    Target pattern:
      Xq --DEQUANTIZE--> Xf
         --MUL(alpha)--> A
         --ADD(beta)--> B
         --MAXIMUM(lo)--> C
         --MINIMUM(hi)--> Yf
      Yf --QUANTIZE--> Yq

    Rewritten:
      Xq --MUL(alpha_q)--> A_q
         --ADD(beta_q)--> B_q
         --MAXIMUM(lo_q)--> C_q
         --MINIMUM(hi_q)--> Yq

    Safety conditions:
    - Strict linear chain topology (single consumer at each bridge tensor).
    - Side inputs are singleton constants.
    - input/output quantized tensors are per-tensor INT8/UINT8.
    """
    folded = 0

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _scalar_from_const_tensor(tensor_name: str) -> Optional[float]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.data is None:
            return None
        try:
            arr = np.asarray(tensor.data, dtype=np.float32).reshape(-1)
        except Exception:
            return None
        if int(arr.size) != 1:
            return None
        return float(arr[0])

    def _quantize_values_with_qparams(
        *,
        values: np.ndarray,
        dtype: str,
        quantization: Any,
    ) -> Optional[np.ndarray]:
        qparams = _get_per_tensor_scale_zero_point(quantization)
        if qparams is None:
            return None
        scale, zero_point = qparams
        if float(scale) <= 0.0:
            return None
        values_f = np.asarray(values, dtype=np.float32)
        if str(dtype) == "INT8":
            quantized = np.round(values_f / float(scale)) + int(zero_point)
            quantized = np.clip(quantized, -128, 127)
            return np.asarray(quantized, dtype=np.int8)
        if str(dtype) == "UINT8":
            quantized = np.round(values_f / float(scale)) + int(zero_point)
            quantized = np.clip(quantized, 0, 255)
            return np.asarray(quantized, dtype=np.uint8)
        return None

    def _retarget_const_input_to_quantized(
        *,
        op_idx: int,
        op: OperatorIR,
        input_index: int,
        target_dtype: str,
        target_qparams: Any,
        consumers: Dict[str, List[int]],
    ) -> bool:
        if input_index < 0 or input_index >= len(op.inputs):
            return False
        old_name = str(op.inputs[input_index])
        old_tensor = model_ir.tensors.get(old_name, None)
        if old_tensor is None or old_tensor.data is None:
            return False
        old_values = np.asarray(old_tensor.data, dtype=np.float32)
        quantized_values = _quantize_values_with_qparams(
            values=old_values,
            dtype=target_dtype,
            quantization=target_qparams,
        )
        if quantized_values is None:
            return False

        # If the const tensor is exclusively used here, update in place.
        const_users = [int(v) for v in consumers.get(old_name, [])]
        if len(const_users) == 1 and int(const_users[0]) == int(op_idx):
            old_tensor.data = quantized_values
            old_tensor.dtype = str(target_dtype)
            old_tensor.quantization = _clone_quantization(target_qparams)
            return True

        # Otherwise clone and bind the cloned const only for this op input.
        new_name = _unique_tensor_name(f"{old_name}_q")
        model_ir.tensors[new_name] = TensorIR(
            name=new_name,
            dtype=str(target_dtype),
            shape=list(old_tensor.shape),
            shape_signature=(
                list(old_tensor.shape_signature)
                if old_tensor.shape_signature is not None
                else list(old_tensor.shape)
            ),
            data=quantized_values,
            is_variable=False,
            quantization=_clone_quantization(target_qparams),
        )
        _replace_operator_input_at(
            model_ir=model_ir,
            op=op,
            input_index=int(input_index),
            new_input_name=str(new_name),
        )
        return True

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for dq_idx, dq_op in enumerate(model_ir.operators):
            if str(dq_op.op_type) != "DEQUANTIZE" or len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                continue
            q_in_name = str(dq_op.inputs[0])
            f_in_name = str(dq_op.outputs[0])

            mul_users = consumers.get(f_in_name, [])
            if len(mul_users) != 1:
                continue
            mul_idx = int(mul_users[0])
            mul_op = model_ir.operators[mul_idx]
            if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                continue

            mul_inputs = [str(v) for v in list(mul_op.inputs)]
            if mul_inputs[0] == f_in_name:
                mul_data_input_index = 0
                alpha_name = mul_inputs[1]
                alpha_input_index = 1
            elif mul_inputs[1] == f_in_name:
                mul_data_input_index = 1
                alpha_name = mul_inputs[0]
                alpha_input_index = 0
            else:
                continue
            if not _is_singleton_constant_tensor(model_ir, alpha_name):
                continue
            mul_out_name = str(mul_op.outputs[0])
            if mul_out_name in model_ir.outputs:
                continue

            add_users = consumers.get(mul_out_name, [])
            if len(add_users) != 1:
                continue
            add_idx = int(add_users[0])
            add_op = model_ir.operators[add_idx]
            if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                continue
            add_inputs = [str(v) for v in list(add_op.inputs)]
            if add_inputs[0] == mul_out_name:
                beta_name = add_inputs[1]
                beta_input_index = 1
            elif add_inputs[1] == mul_out_name:
                beta_name = add_inputs[0]
                beta_input_index = 0
            else:
                continue
            if not _is_singleton_constant_tensor(model_ir, beta_name):
                continue
            add_out_name = str(add_op.outputs[0])
            if add_out_name in model_ir.outputs:
                continue

            max_users = consumers.get(add_out_name, [])
            if len(max_users) != 1:
                continue
            max_idx = int(max_users[0])
            max_op = model_ir.operators[max_idx]
            if str(max_op.op_type) != "MAXIMUM" or len(max_op.inputs) != 2 or len(max_op.outputs) != 1:
                continue
            max_inputs = [str(v) for v in list(max_op.inputs)]
            if max_inputs[0] == add_out_name:
                lo_name = max_inputs[1]
                lo_input_index = 1
            elif max_inputs[1] == add_out_name:
                lo_name = max_inputs[0]
                lo_input_index = 0
            else:
                continue
            if not _is_singleton_constant_tensor(model_ir, lo_name):
                continue
            max_out_name = str(max_op.outputs[0])
            if max_out_name in model_ir.outputs:
                continue

            min_users = consumers.get(max_out_name, [])
            if len(min_users) != 1:
                continue
            min_idx = int(min_users[0])
            min_op = model_ir.operators[min_idx]
            if str(min_op.op_type) != "MINIMUM" or len(min_op.inputs) != 2 or len(min_op.outputs) != 1:
                continue
            min_inputs = [str(v) for v in list(min_op.inputs)]
            if min_inputs[0] == max_out_name:
                hi_name = min_inputs[1]
                hi_input_index = 1
            elif min_inputs[1] == max_out_name:
                hi_name = min_inputs[0]
                hi_input_index = 0
            else:
                continue
            if not _is_singleton_constant_tensor(model_ir, hi_name):
                continue
            f_out_name = str(min_op.outputs[0])
            if f_out_name in model_ir.outputs:
                continue

            q_users = consumers.get(f_out_name, [])
            if len(q_users) != 1:
                continue
            q_idx = int(q_users[0])
            q_op = model_ir.operators[q_idx]
            if str(q_op.op_type) != "QUANTIZE" or len(q_op.inputs) != 1 or len(q_op.outputs) != 1:
                continue
            if str(q_op.inputs[0]) != f_out_name:
                continue
            q_out_name = str(q_op.outputs[0])

            q_in_tensor = model_ir.tensors.get(q_in_name, None)
            q_out_tensor = model_ir.tensors.get(q_out_name, None)
            f_in_tensor = model_ir.tensors.get(f_in_name, None)
            f_out_tensor = model_ir.tensors.get(f_out_name, None)
            mul_out_tensor = model_ir.tensors.get(mul_out_name, None)
            add_out_tensor = model_ir.tensors.get(add_out_name, None)
            max_out_tensor = model_ir.tensors.get(max_out_name, None)
            if (
                q_in_tensor is None
                or q_out_tensor is None
                or mul_out_tensor is None
                or add_out_tensor is None
                or max_out_tensor is None
            ):
                continue
            if not _all_per_tensor_quantized([q_in_tensor, q_out_tensor]):
                continue

            target_dtype = str(q_in_tensor.dtype).upper()
            if target_dtype not in {"INT8", "UINT8"}:
                continue
            if str(q_out_tensor.dtype).upper() != target_dtype:
                continue

            q_in_qparams = _get_per_tensor_scale_zero_point(q_in_tensor.quantization)
            q_out_qparams = _get_per_tensor_scale_zero_point(q_out_tensor.quantization)
            if q_in_qparams is None or q_out_qparams is None:
                continue
            if not _is_same_per_tensor_quantization(
                q_in_tensor.quantization,
                q_out_tensor.quantization,
            ):
                continue
            x_scale, x_zero_point = q_in_qparams
            if float(x_scale) <= 0.0:
                continue

            alpha = _scalar_from_const_tensor(alpha_name)
            beta = _scalar_from_const_tensor(beta_name)
            lo = _scalar_from_const_tensor(lo_name)
            hi = _scalar_from_const_tensor(hi_name)
            if any(v is None for v in [alpha, beta, lo, hi]):
                continue
            alpha = float(alpha)
            beta = float(beta)
            lo = float(lo)
            hi = float(hi)
            base_qparams = _clone_quantization(q_in_tensor.quantization)
            if base_qparams is None:
                continue

            # Conservative gating:
            # apply this int8ization only when scalar constants are representable
            # by the shared activation quantization with small error.
            def _is_scalar_representable(value: float) -> bool:
                q = _quantize_values_with_qparams(
                    values=np.asarray([value], dtype=np.float32),
                    dtype=target_dtype,
                    quantization=base_qparams,
                )
                if q is None:
                    return False
                recon = (float(np.asarray(q).reshape(-1)[0]) - float(x_zero_point)) * float(x_scale)
                tol = max(float(x_scale) * 0.25, 1e-3)
                return bool(abs(float(recon) - float(value)) <= tol)

            if not (
                _is_scalar_representable(alpha)
                and _is_scalar_representable(beta)
                and _is_scalar_representable(lo)
                and _is_scalar_representable(hi)
            ):
                continue

            if f_in_tensor is not None and not _shapes_match_if_known(q_in_tensor.shape, f_in_tensor.shape):
                continue
            if f_out_tensor is not None and not _shapes_match_if_known(q_out_tensor.shape, f_out_tensor.shape):
                continue

            if not _retarget_const_input_to_quantized(
                op_idx=int(mul_idx),
                op=mul_op,
                input_index=int(alpha_input_index),
                target_dtype=target_dtype,
                target_qparams=base_qparams,
                consumers=consumers,
            ):
                continue
            if not _retarget_const_input_to_quantized(
                op_idx=int(add_idx),
                op=add_op,
                input_index=int(beta_input_index),
                target_dtype=target_dtype,
                target_qparams=base_qparams,
                consumers=consumers,
            ):
                continue
            if not _retarget_const_input_to_quantized(
                op_idx=int(max_idx),
                op=max_op,
                input_index=int(lo_input_index),
                target_dtype=target_dtype,
                target_qparams=base_qparams,
                consumers=consumers,
            ):
                continue
            if not _retarget_const_input_to_quantized(
                op_idx=int(min_idx),
                op=min_op,
                input_index=int(hi_input_index),
                target_dtype=target_dtype,
                target_qparams=base_qparams,
                consumers=consumers,
            ):
                continue

            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul_op,
                input_index=int(mul_data_input_index),
                new_input_name=q_in_name,
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=min_op,
                new_outputs=[q_out_name],
            )

            mul_out_tensor.dtype = str(target_dtype)
            mul_out_tensor.quantization = _clone_quantization(base_qparams)
            add_out_tensor.dtype = str(target_dtype)
            add_out_tensor.quantization = _clone_quantization(base_qparams)
            max_out_tensor.dtype = str(target_dtype)
            max_out_tensor.quantization = _clone_quantization(base_qparams)
            q_out_tensor.dtype = str(target_dtype)
            q_out_tensor.quantization = _clone_quantization(base_qparams)

            if f_out_tensor is not None:
                q_out_tensor.shape = [int(v) for v in list(f_out_tensor.shape)]
                if f_out_tensor.shape_signature is not None:
                    q_out_tensor.shape_signature = [int(v) for v in list(f_out_tensor.shape_signature)]
                else:
                    q_out_tensor.shape_signature = [int(v) for v in list(f_out_tensor.shape)]

            for remove_idx in sorted([dq_idx, q_idx], reverse=True):
                del model_ir.operators[remove_idx]
            folded += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"folded_dequant_hardsigmoid_quantize_chains": int(folded)}


def _optimize_dequant_maxpool_quantize_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold DEQUANTIZE->MAX_POOL_2D->QUANTIZE into quantized MAX_POOL_2D.

    Target pattern:
      Xq --DEQUANTIZE--> Xf --MAX_POOL_2D--> Yf --QUANTIZE--> Yq

    Rewritten:
      Xq --MAX_POOL_2D--> Yq

    Safety conditions:
    - Chain is linear (single consumer at each bridge tensor)
    - input/output quantized tensors use equivalent per-tensor quantization
    - input/output quantized dtypes are identical INT8/UINT8
    """
    folded = 0

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for dq_idx, dq_op in enumerate(model_ir.operators):
            if str(dq_op.op_type) != "DEQUANTIZE" or len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                continue
            q_in_name = str(dq_op.inputs[0])
            f_in_name = str(dq_op.outputs[0])

            pool_users = consumers.get(f_in_name, [])
            if len(pool_users) != 1:
                continue
            pool_idx = int(pool_users[0])
            pool_op = model_ir.operators[pool_idx]
            if str(pool_op.op_type) != "MAX_POOL_2D" or len(pool_op.inputs) != 1 or len(pool_op.outputs) != 1:
                continue
            if str(pool_op.inputs[0]) != f_in_name:
                continue
            f_out_name = str(pool_op.outputs[0])

            q_users = consumers.get(f_out_name, [])
            if len(q_users) != 1:
                continue
            q_idx = int(q_users[0])
            q_op = model_ir.operators[q_idx]
            if str(q_op.op_type) != "QUANTIZE" or len(q_op.inputs) != 1 or len(q_op.outputs) != 1:
                continue
            if str(q_op.inputs[0]) != f_out_name:
                continue
            q_out_name = str(q_op.outputs[0])

            if f_in_name in model_ir.outputs or f_out_name in model_ir.outputs:
                continue

            q_in_tensor = model_ir.tensors.get(q_in_name, None)
            q_out_tensor = model_ir.tensors.get(q_out_name, None)
            f_in_tensor = model_ir.tensors.get(f_in_name, None)
            f_out_tensor = model_ir.tensors.get(f_out_name, None)
            if q_in_tensor is None or q_out_tensor is None:
                continue
            if not _all_per_tensor_quantized([q_in_tensor, q_out_tensor]):
                continue
            if not _is_same_per_tensor_quantization(
                q_in_tensor.quantization,
                q_out_tensor.quantization,
            ):
                continue

            q_in_dtype = str(q_in_tensor.dtype).upper()
            q_out_dtype = str(q_out_tensor.dtype).upper()
            if q_in_dtype not in {"INT8", "UINT8"} or q_out_dtype != q_in_dtype:
                continue

            if f_in_tensor is not None and not _shapes_match_if_known(q_in_tensor.shape, f_in_tensor.shape):
                continue
            if f_out_tensor is not None and not _shapes_match_if_known(q_out_tensor.shape, f_out_tensor.shape):
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=pool_op,
                new_inputs=[q_in_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=pool_op,
                new_outputs=[q_out_name],
            )

            q_out_tensor.dtype = q_in_dtype
            q_out_tensor.quantization = _clone_quantization(q_in_tensor.quantization)
            if f_out_tensor is not None:
                q_out_tensor.shape = [int(v) for v in list(f_out_tensor.shape)]
                if f_out_tensor.shape_signature is not None:
                    q_out_tensor.shape_signature = [
                        int(v) for v in list(f_out_tensor.shape_signature)
                    ]
                else:
                    q_out_tensor.shape_signature = [int(v) for v in list(f_out_tensor.shape)]

            for remove_idx in sorted([dq_idx, q_idx], reverse=True):
                del model_ir.operators[remove_idx]
            folded += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"folded_dequant_maxpool_quantize_chains": int(folded)}


def _optimize_dequant_softmax_quantize_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold DEQUANTIZE->SOFTMAX->QUANTIZE into quantized SOFTMAX when TFLite-compatible.

    Target pattern:
      Xq --DEQUANTIZE--> Xf --SOFTMAX(beta=1.0)--> Yf --QUANTIZE--> Yq

    Rewritten:
      Xq --SOFTMAX(int8/uint8)--> Yq

    Safety conditions:
    - Chain is linear (single consumer at each bridge tensor)
    - input/output quantized tensors are per-tensor INT8/UINT8
    - output quantization matches TFLite quantized softmax canonical params
      (INT8: scale=1/256, zp=-128; UINT8: scale=1/256, zp=0)
    - Softmax beta is approximately 1.0
    """
    folded = 0

    def _is_supported_softmax_qparams(dtype: str, quantization: Any) -> bool:
        qparams = _get_per_tensor_scale_zero_point(quantization)
        if qparams is None:
            return False
        scale, zero_point = qparams
        if not np.isclose(float(scale), 1.0 / 256.0, rtol=0.0, atol=1e-7):
            return False
        dtype_u = str(dtype).upper()
        if dtype_u == "INT8":
            return int(zero_point) == -128
        if dtype_u == "UINT8":
            return int(zero_point) == 0
        return False

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for dq_idx, dq_op in enumerate(model_ir.operators):
            if str(dq_op.op_type) != "DEQUANTIZE" or len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                continue
            q_in_name = str(dq_op.inputs[0])
            f_in_name = str(dq_op.outputs[0])

            softmax_users = consumers.get(f_in_name, [])
            if len(softmax_users) != 1:
                continue
            softmax_idx = int(softmax_users[0])
            softmax_op = model_ir.operators[softmax_idx]
            if str(softmax_op.op_type) != "SOFTMAX" or len(softmax_op.inputs) != 1 or len(softmax_op.outputs) != 1:
                continue
            if str(softmax_op.inputs[0]) != f_in_name:
                continue
            f_out_name = str(softmax_op.outputs[0])

            q_users = consumers.get(f_out_name, [])
            if len(q_users) != 1:
                continue
            q_idx = int(q_users[0])
            q_op = model_ir.operators[q_idx]
            if str(q_op.op_type) != "QUANTIZE" or len(q_op.inputs) != 1 or len(q_op.outputs) != 1:
                continue
            if str(q_op.inputs[0]) != f_out_name:
                continue
            q_out_name = str(q_op.outputs[0])

            if f_in_name in model_ir.outputs or f_out_name in model_ir.outputs:
                continue

            q_in_tensor = model_ir.tensors.get(q_in_name, None)
            q_out_tensor = model_ir.tensors.get(q_out_name, None)
            f_in_tensor = model_ir.tensors.get(f_in_name, None)
            f_out_tensor = model_ir.tensors.get(f_out_name, None)
            if q_in_tensor is None or q_out_tensor is None:
                continue
            if not _all_per_tensor_quantized([q_in_tensor, q_out_tensor]):
                continue

            q_in_dtype = str(q_in_tensor.dtype).upper()
            q_out_dtype = str(q_out_tensor.dtype).upper()
            if q_in_dtype not in {"INT8", "UINT8"} or q_out_dtype != q_in_dtype:
                continue
            if not _is_supported_softmax_qparams(q_out_dtype, q_out_tensor.quantization):
                continue

            beta = float(softmax_op.options.get("beta", 1.0))
            if not np.isclose(beta, 1.0, rtol=0.0, atol=1e-6):
                continue

            if f_in_tensor is not None and not _shapes_match_if_known(q_in_tensor.shape, f_in_tensor.shape):
                continue
            if f_out_tensor is not None and not _shapes_match_if_known(q_out_tensor.shape, f_out_tensor.shape):
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=softmax_op,
                new_inputs=[q_in_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=softmax_op,
                new_outputs=[q_out_name],
            )
            # TFLite quantized SOFTMAX opcode version differs by dtype.
            softmax_op.version = 2 if q_out_dtype == "INT8" else 1

            # Keep output tensor metadata aligned to the pre-quantized softmax output shape.
            if f_out_tensor is not None:
                q_out_tensor.shape = [int(v) for v in list(f_out_tensor.shape)]
                if f_out_tensor.shape_signature is not None:
                    q_out_tensor.shape_signature = [int(v) for v in list(f_out_tensor.shape_signature)]
                else:
                    q_out_tensor.shape_signature = [int(v) for v in list(f_out_tensor.shape)]

            for remove_idx in sorted([dq_idx, q_idx], reverse=True):
                del model_ir.operators[remove_idx]
            folded += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"folded_dequant_softmax_quantize_chains": int(folded)}


def _optimize_terminal_quantize_dequantize(model_ir: ModelIR) -> Dict[str, int]:
    """
    Remove terminal QUANTIZE->DEQUANTIZE pairs for float outputs when safe.

    Target pattern:
      x_float -> QUANTIZE -> q -> DEQUANTIZE -> y_float (graph output)

    Safety conditions:
    - q is consumed only by that DEQUANTIZE
    - y_float is a graph output and has no internal consumers
    - x_float is produced by another op and consumed only by QUANTIZE
      (allows preserving output name by renaming x_float -> y_float)
    """
    removed_pairs = 0

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)

        for q_idx, q_op in enumerate(model_ir.operators):
            if str(q_op.op_type) != "QUANTIZE":
                continue
            if len(q_op.inputs) != 1 or len(q_op.outputs) != 1:
                continue

            float_input_name = q_op.inputs[0]
            quantized_name = q_op.outputs[0]
            if float_input_name in model_ir.inputs:
                continue

            quantized_users = consumers.get(quantized_name, [])
            if len(quantized_users) != 1:
                continue

            dq_idx = int(quantized_users[0])
            if dq_idx == q_idx:
                continue
            dq_op = model_ir.operators[dq_idx]
            if str(dq_op.op_type) != "DEQUANTIZE":
                continue
            if len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                continue
            if dq_op.inputs[0] != quantized_name:
                continue

            float_output_name = dq_op.outputs[0]
            if float_output_name not in model_ir.outputs:
                continue
            if len(consumers.get(float_output_name, [])) > 0:
                continue

            float_input_users = consumers.get(float_input_name, [])
            if len(float_input_users) != 1 or int(float_input_users[0]) != q_idx:
                continue
            if float_input_name not in producers:
                continue
            if float_input_name in model_ir.outputs:
                continue

            _rename_tensor_globally(
                model_ir=model_ir,
                old_name=float_input_name,
                new_name=float_output_name,
            )

            for remove_idx in sorted([q_idx, dq_idx], reverse=True):
                del model_ir.operators[remove_idx]
            removed_pairs += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "removed_terminal_quantize_dequantize_pairs": int(removed_pairs),
    }


def _optimize_fuse_conv_activation_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fuse producer -> Activation chains into producer fusedActivationFunction in flatbuffer_direct IR.

    Target:
      (CONV_2D|DEPTHWISE_CONV_2D, fusedActivationFunction=NONE) -> (RELU|RELU6|TANH)
      (ADD|SUB|MUL|DIV, fusedActivationFunction=NONE) -> (RELU|RELU6|TANH)

    Rewrite:
      (producer, fusedActivationFunction=<activation>)

    Safety:
    - Producer output must have exactly one consumer.
    - Activation must be a unary op with one input and one output.
    - Producer output tensor and activation output tensor must have matching dtype when both exist.
    """
    fused = 0
    fused_conv = 0
    fused_add = 0
    fused_sub = 0
    fused_mul = 0
    fused_div = 0
    skip_add_activation_fuse_marker = "__skip_add_activation_fuse__"
    binary_activation_map = {
        "RELU": "RELU",
        "RELU6": "RELU6",
        "TANH": "TANH",
    }
    activation_map_by_producer = {
        "CONV_2D": {
            "RELU": "RELU",
            "RELU6": "RELU6",
        },
        "DEPTHWISE_CONV_2D": {
            "RELU": "RELU",
            "RELU6": "RELU6",
        },
        "ADD": dict(binary_activation_map),
        "SUB": dict(binary_activation_map),
        "MUL": dict(binary_activation_map),
        "DIV": dict(binary_activation_map),
    }

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for producer_idx, producer_op in enumerate(model_ir.operators):
            producer_type = str(producer_op.op_type).upper()
            activation_map = activation_map_by_producer.get(producer_type, None)
            if activation_map is None:
                continue
            if len(producer_op.outputs) != 1:
                continue

            producer_opts = dict(producer_op.options) if isinstance(producer_op.options, dict) else {}
            fused_act = str(producer_opts.get("fusedActivationFunction", "NONE")).upper()
            if fused_act != "NONE":
                continue
            producer_out_name = str(producer_op.outputs[0])
            producer_users = [int(v) for v in consumers.get(producer_out_name, [])]
            if len(producer_users) != 1:
                continue

            act_idx = int(producer_users[0])
            if act_idx < 0 or act_idx >= len(model_ir.operators):
                continue
            if act_idx == int(producer_idx):
                continue
            act_op = model_ir.operators[act_idx]
            act_type = str(act_op.op_type).upper()
            fused_target = activation_map.get(act_type, None)
            if fused_target is None:
                continue
            if len(act_op.inputs) != 1 or len(act_op.outputs) != 1:
                continue
            if str(act_op.inputs[0]) != producer_out_name:
                continue

            act_out_name = str(act_op.outputs[0])
            producer_out_tensor = model_ir.tensors.get(producer_out_name, None)
            act_out_tensor = model_ir.tensors.get(act_out_name, None)
            if producer_out_tensor is not None and act_out_tensor is not None:
                if str(producer_out_tensor.dtype).upper() != str(act_out_tensor.dtype).upper():
                    continue

            if producer_type == "ADD":
                # Transpose bridge rewrites may leave this marker behind. For strict
                # single-consumer Add->Activation chains, fusing is still safe.
                producer_opts.pop(skip_add_activation_fuse_marker, None)
            producer_opts["fusedActivationFunction"] = str(fused_target)
            producer_op.options = producer_opts
            _set_operator_outputs(
                model_ir=model_ir,
                op=producer_op,
                new_outputs=[act_out_name],
            )
            if producer_type in {"CONV_2D", "DEPTHWISE_CONV_2D"}:
                _append_tensor_lineage_event(
                    model_ir=model_ir,
                    event={
                        "kind": "fuse_conv_activation",
                        "conv_op_type": str(producer_op.op_type),
                        "activation_op_type": str(act_op.op_type),
                        "fused_activation": str(fused_target),
                        "conv_output": str(producer_out_name),
                        "fused_output": str(act_out_name),
                    },
                )
            elif producer_type == "ADD":
                _append_tensor_lineage_event(
                    model_ir=model_ir,
                    event={
                        "kind": "fuse_add_activation",
                        "add_op_type": str(producer_op.op_type),
                        "activation_op_type": str(act_op.op_type),
                        "fused_activation": str(fused_target),
                        "add_output": str(producer_out_name),
                        "fused_output": str(act_out_name),
                    },
                )
            elif producer_type in {"SUB", "MUL", "DIV"}:
                _append_tensor_lineage_event(
                    model_ir=model_ir,
                    event={
                        "kind": "fuse_binary_activation",
                        "binary_op_type": str(producer_op.op_type),
                        "activation_op_type": str(act_op.op_type),
                        "fused_activation": str(fused_target),
                        "binary_output": str(producer_out_name),
                        "fused_output": str(act_out_name),
                    },
                )

            del model_ir.operators[int(act_idx)]
            fused += 1
            if producer_type in {"CONV_2D", "DEPTHWISE_CONV_2D"}:
                fused_conv += 1
            elif producer_type == "ADD":
                fused_add += 1
            elif producer_type == "SUB":
                fused_sub += 1
            elif producer_type == "MUL":
                fused_mul += 1
            elif producer_type == "DIV":
                fused_div += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "fused_conv_activation_chains": int(fused_conv),
        "fused_add_activation_chains": int(fused_add),
        "fused_sub_activation_chains": int(fused_sub),
        "fused_mul_activation_chains": int(fused_mul),
        "fused_div_activation_chains": int(fused_div),
        "fused_binary_activation_chains": int(fused_add + fused_sub + fused_mul + fused_div),
        "fused_activation_chains_total": int(fused),
    }


def _optimize_fold_conv_mul_add_affine_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold single-path CONV_2D -> MUL(const) -> ADD(const) affine chains into CONV_2D.

    Target:
      x --CONV_2D(w,b)--> y
      y --MUL(m)--> z
      z --ADD(a)--> o

    Rewrite:
      x --CONV_2D(w',b')--> o
      where:
        w'[oc,kh,kw,ic] = w[oc,kh,kw,ic] * m[oc]
        b'[oc]          = b[oc] * m[oc] + a[oc]

    Safety:
    - Conv output must have exactly one consumer (single path).
    - MUL and ADD side inputs must be constants representable as scalar or NHWC-channelwise.
    - Conv filter/bias must be constant and not shared by other operators.
    - Chains with Conv output fan-out (>=2) are excluded.
    """

    def _extract_nhwc_channelwise_coeff(
        *,
        tensor: Optional[TensorIR],
        out_channels: int,
    ) -> Optional[np.ndarray]:
        if tensor is None or tensor.data is None:
            return None
        if int(out_channels) <= 0:
            return None
        raw = np.asarray(tensor.data)
        if raw.size == 0:
            return None
        coeff = np.asarray(raw, dtype=np.float32)
        if coeff.size == 1:
            return np.full((int(out_channels),), float(coeff.reshape(-1)[0]), dtype=np.float32)
        shape = [int(v) for v in list(coeff.shape)]
        if len(shape) == 1 and int(shape[0]) == int(out_channels):
            return coeff.reshape(int(out_channels)).astype(np.float32, copy=False)
        if len(shape) >= 2 and int(shape[-1]) == int(out_channels):
            if int(np.prod(shape[:-1])) == 1:
                return coeff.reshape(int(out_channels)).astype(np.float32, copy=False)
        return None

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    folded = 0

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for conv_idx, conv_op in enumerate(model_ir.operators):
            if str(conv_op.op_type) != "CONV_2D" or len(conv_op.inputs) < 2 or len(conv_op.outputs) != 1:
                continue
            conv_out_name = str(conv_op.outputs[0])
            conv_users = [int(v) for v in consumers.get(conv_out_name, [])]
            if len(conv_users) != 1:
                continue

            mul_idx = int(conv_users[0])
            mul_op = model_ir.operators[int(mul_idx)]
            if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                continue
            mul_inputs = [str(v) for v in list(mul_op.inputs)]
            if mul_inputs[0] == conv_out_name:
                mul_side_name = str(mul_inputs[1])
            elif mul_inputs[1] == conv_out_name:
                mul_side_name = str(mul_inputs[0])
            else:
                continue
            mul_side_tensor = model_ir.tensors.get(mul_side_name, None)
            if mul_side_tensor is None or mul_side_tensor.data is None:
                continue

            mul_out_name = str(mul_op.outputs[0])
            if mul_out_name in model_outputs:
                continue
            mul_users = [int(v) for v in consumers.get(mul_out_name, [])]
            if len(mul_users) != 1:
                continue
            add_idx = int(mul_users[0])
            add_op = model_ir.operators[int(add_idx)]
            if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                continue
            add_inputs = [str(v) for v in list(add_op.inputs)]
            if add_inputs[0] == mul_out_name:
                add_side_name = str(add_inputs[1])
            elif add_inputs[1] == mul_out_name:
                add_side_name = str(add_inputs[0])
            else:
                continue
            add_side_tensor = model_ir.tensors.get(add_side_name, None)
            if add_side_tensor is None or add_side_tensor.data is None:
                continue

            filter_name = str(conv_op.inputs[1])
            filter_tensor = model_ir.tensors.get(filter_name, None)
            if (
                filter_tensor is None
                or filter_tensor.data is None
                or bool(filter_tensor.is_variable)
                or filter_tensor.quantization is not None
            ):
                continue
            filter_users = [int(v) for v in consumers.get(filter_name, [])]
            if set(int(v) for v in filter_users) != {int(conv_idx)}:
                continue
            filter_data = np.asarray(filter_tensor.data)
            if filter_data.ndim != 4:
                continue
            out_channels = int(filter_data.shape[0])
            if out_channels <= 0:
                continue

            bias_name: Optional[str] = None
            bias_tensor: Optional[TensorIR] = None
            if len(conv_op.inputs) >= 3:
                bias_name = str(conv_op.inputs[2])
                bias_tensor = model_ir.tensors.get(bias_name, None)
                if (
                    bias_tensor is None
                    or bias_tensor.data is None
                    or bool(bias_tensor.is_variable)
                    or bias_tensor.quantization is not None
                ):
                    continue
                bias_users = [int(v) for v in consumers.get(str(bias_name), [])]
                if set(int(v) for v in bias_users) != {int(conv_idx)}:
                    continue
                bias_values = np.asarray(bias_tensor.data).reshape(-1)
                if int(bias_values.size) != int(out_channels):
                    continue
            else:
                bias_name = _unique_tensor_name(f"{conv_out_name}_affine_fold_bias")
                bias_tensor = TensorIR(
                    name=str(bias_name),
                    dtype=str(filter_tensor.dtype),
                    shape=[int(out_channels)],
                    shape_signature=[int(out_channels)],
                    data=np.zeros((int(out_channels),), dtype=np.float32),
                    is_variable=False,
                    quantization=None,
                )
                model_ir.tensors[str(bias_name)] = bias_tensor
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=conv_op,
                    new_inputs=[str(conv_op.inputs[0]), str(filter_name), str(bias_name)],
                )

            mul_coeff = _extract_nhwc_channelwise_coeff(
                tensor=mul_side_tensor,
                out_channels=int(out_channels),
            )
            add_coeff = _extract_nhwc_channelwise_coeff(
                tensor=add_side_tensor,
                out_channels=int(out_channels),
            )
            if mul_coeff is None or add_coeff is None:
                continue
            if not np.isfinite(mul_coeff).all() or not np.isfinite(add_coeff).all():
                continue

            filter_dtype = np.asarray(filter_tensor.data).dtype
            folded_filter = (
                np.asarray(filter_tensor.data, dtype=np.float32)
                * np.asarray(mul_coeff, dtype=np.float32).reshape(int(out_channels), 1, 1, 1)
            )
            filter_tensor.data = np.asarray(folded_filter, dtype=filter_dtype)

            assert bias_tensor is not None
            bias_dtype = np.asarray(bias_tensor.data).dtype
            bias_values = np.asarray(bias_tensor.data, dtype=np.float32).reshape(int(out_channels))
            folded_bias = bias_values * np.asarray(mul_coeff, dtype=np.float32) + np.asarray(add_coeff, dtype=np.float32)
            bias_tensor.data = np.asarray(folded_bias, dtype=bias_dtype)
            bias_tensor.shape = [int(out_channels)]
            bias_tensor.shape_signature = [int(out_channels)]

            add_out_name = str(add_op.outputs[0])
            _set_operator_outputs(
                model_ir=model_ir,
                op=conv_op,
                new_outputs=[add_out_name],
            )

            for remove_idx in sorted([int(mul_idx), int(add_idx)], reverse=True):
                del model_ir.operators[int(remove_idx)]

            folded += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"folded_conv_mul_add_affine_chains": int(folded)}


def _sanitize_terminal_transpose_before_dequantize(model_ir: ModelIR) -> Dict[str, int]:
    """
    Sanitize terminal TRANSPOSE->DEQUANTIZE by swapping to DEQUANTIZE->TRANSPOSE.

    Target pattern:
      q --TRANSPOSE(P)--> q_t --DEQUANTIZE--> y(graph output)

    Rewritten:
      q --DEQUANTIZE--> y_pre --TRANSPOSE(P)--> y(graph output)

    Safety conditions:
    - y is a graph output without internal consumers
    - q_t is consumed only by that DEQUANTIZE
    - q/q_t quantization is per-tensor (to avoid axis remap ambiguity)
    """
    sanitized = 0
    removed_terminal_dequantize_transpose = 0

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)

        for dq_idx, dq_op in enumerate(model_ir.operators):
            if str(dq_op.op_type) != "DEQUANTIZE":
                continue
            if len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                continue

            dq_input_name = str(dq_op.inputs[0])
            dq_output_name = str(dq_op.outputs[0])
            if dq_output_name not in model_ir.outputs:
                continue
            if len(consumers.get(dq_output_name, [])) > 0:
                continue
            if dq_input_name in model_ir.outputs:
                continue

            transpose_idx = producers.get(dq_input_name, None)
            if transpose_idx is None:
                continue
            transpose_op = model_ir.operators[int(transpose_idx)]
            if str(transpose_op.op_type) != "TRANSPOSE":
                continue
            if len(transpose_op.inputs) < 2 or len(transpose_op.outputs) != 1:
                continue
            if str(transpose_op.outputs[0]) != dq_input_name:
                continue

            q_input_name = str(transpose_op.inputs[0])
            if q_input_name in model_ir.outputs:
                continue

            dq_input_users = [int(v) for v in consumers.get(dq_input_name, [])]
            if len(dq_input_users) != 1 or int(dq_input_users[0]) != int(dq_idx):
                continue

            q_tensor = model_ir.tensors.get(q_input_name, None)
            qt_tensor = model_ir.tensors.get(dq_input_name, None)
            y_tensor = model_ir.tensors.get(dq_output_name, None)
            if q_tensor is None or qt_tensor is None or y_tensor is None:
                continue
            if not _all_per_tensor_quantized([q_tensor, qt_tensor]):
                continue

            q_shape = list(q_tensor.shape)
            q_signature = (
                list(q_tensor.shape_signature)
                if q_tensor.shape_signature is not None
                else list(q_shape)
            )
            if len(q_shape) == 0:
                continue
            perm = _read_transpose_perm(model_ir, transpose_op)
            if perm is None:
                continue
            expected_out_shape = _permute_shape(q_shape, perm)
            expected_out_signature = _permute_shape(q_signature, perm)
            if expected_out_shape is None or expected_out_signature is None:
                continue

            pre_transpose_name = _unique_tensor_name(f"{dq_output_name}_before_transpose")
            model_ir.tensors[pre_transpose_name] = TensorIR(
                name=pre_transpose_name,
                dtype=str(y_tensor.dtype),
                shape=[int(v) for v in q_shape],
                shape_signature=[int(v) for v in q_signature],
                data=None,
            )

            _set_operator_inputs(
                model_ir=model_ir,
                op=dq_op,
                new_inputs=[q_input_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=dq_op,
                new_outputs=[pre_transpose_name],
            )
            _set_operator_inputs(
                model_ir=model_ir,
                op=transpose_op,
                new_inputs=[pre_transpose_name, str(transpose_op.inputs[1])],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=transpose_op,
                new_outputs=[dq_output_name],
            )

            y_tensor.shape = [int(v) for v in expected_out_shape]
            y_tensor.shape_signature = [int(v) for v in expected_out_signature]

            transpose_idx_int = int(transpose_idx)
            if transpose_idx_int < int(dq_idx):
                moved = model_ir.operators.pop(transpose_idx_int)
                insert_idx = int(dq_idx) - 1
                model_ir.operators.insert(insert_idx + 1, moved)

            sanitized += 1
            changed = True
            break

        if changed:
            continue

        # Pattern B:
        #   q --DEQUANTIZE--> y_pre --TRANSPOSE(P)--> y(graph output)
        #   => q --DEQUANTIZE--> y(graph output)
        # Keep user-visible output tensor name stable by renaming y_pre -> y.
        for transpose_idx, transpose_op in enumerate(model_ir.operators):
            if str(transpose_op.op_type) != "TRANSPOSE":
                continue
            if len(transpose_op.inputs) < 2 or len(transpose_op.outputs) != 1:
                continue

            pre_output_name = str(transpose_op.inputs[0])
            final_output_name = str(transpose_op.outputs[0])
            if final_output_name not in model_ir.outputs:
                continue
            if len(consumers.get(final_output_name, [])) > 0:
                continue
            if pre_output_name in model_ir.outputs:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) != 1 or int(pre_users[0]) != int(transpose_idx):
                continue

            dq_idx = producers.get(pre_output_name, None)
            if dq_idx is None:
                continue
            dq_op = model_ir.operators[int(dq_idx)]
            if str(dq_op.op_type) != "DEQUANTIZE":
                continue
            if len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                continue
            if str(dq_op.outputs[0]) != pre_output_name:
                continue

            _rename_tensor_globally(
                model_ir=model_ir,
                old_name=pre_output_name,
                new_name=final_output_name,
            )
            del model_ir.operators[int(transpose_idx)]
            removed_terminal_dequantize_transpose += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "sanitized_terminal_transpose_before_dequantize": int(sanitized),
        "removed_terminal_dequantize_transpose": int(removed_terminal_dequantize_transpose),
    }


def _optimize_concat_pre_quantize_dequantize(model_ir: ModelIR) -> Dict[str, int]:
    """
    Bypass redundant QUANTIZE->DEQUANTIZE immediately before CONCATENATION inputs.

    Target pattern:
      ... -> x_float --QUANTIZE--> q --DEQUANTIZE--> x_dq --CONCATENATION--> ...

    Rewritten:
      ... -> x_float ---------------------------------> --CONCATENATION--> ...

    Safety conditions:
    - q is consumed only by that DEQUANTIZE
    - neither q nor x_dq is a graph output
    - x_float is already in a dequantized flow:
      - producer(x_float) is DEQUANTIZE, or
      - producer(x_float) has at least one DEQUANTIZE input
    """
    bypassed = 0

    def _has_dequantized_origin(
        tensor_name: str,
        producers: Dict[str, int],
        max_depth: int = 6,
    ) -> bool:
        traceable_ops = {
            "TRANSPOSE",
            "RESHAPE",
            "MAX_POOL_2D",
            "AVERAGE_POOL_2D",
            "PAD",
            "ADD",
            "SUB",
            "MUL",
            "DIV",
            "CONCATENATION",
            "MEAN",
        }
        visited = set()
        stack: List[Tuple[str, int]] = [(str(tensor_name), 0)]
        while len(stack) > 0:
            current_name, depth = stack.pop()
            key = (str(current_name), int(depth))
            if key in visited:
                continue
            visited.add(key)
            if int(depth) > int(max_depth):
                continue

            producer_idx = producers.get(str(current_name), None)
            if producer_idx is None:
                continue
            producer = model_ir.operators[int(producer_idx)]
            producer_type = str(producer.op_type)
            if producer_type == "DEQUANTIZE":
                return True
            if producer_type not in traceable_ops:
                continue
            for input_name in list(producer.inputs):
                stack.append((str(input_name), int(depth) + 1))
        return False

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)

        for concat_idx, concat_op in enumerate(model_ir.operators):
            if str(concat_op.op_type) != "CONCATENATION":
                continue
            if len(concat_op.inputs) == 0:
                continue

            concat_inputs = list(concat_op.inputs)
            for input_pos, concat_input_name in enumerate(concat_inputs):
                dq_idx = producers.get(str(concat_input_name), None)
                if dq_idx is None:
                    continue
                dq_op = model_ir.operators[int(dq_idx)]
                if str(dq_op.op_type) != "DEQUANTIZE":
                    continue
                if len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                    continue
                if str(dq_op.outputs[0]) != str(concat_input_name):
                    continue

                quantized_name = str(dq_op.inputs[0])
                if quantized_name in model_ir.outputs or str(concat_input_name) in model_ir.outputs:
                    continue

                q_idx = producers.get(quantized_name, None)
                if q_idx is None:
                    continue
                q_op = model_ir.operators[int(q_idx)]
                if str(q_op.op_type) != "QUANTIZE":
                    continue
                if len(q_op.inputs) != 1 or len(q_op.outputs) != 1:
                    continue
                if str(q_op.outputs[0]) != quantized_name:
                    continue

                q_users = [int(v) for v in consumers.get(quantized_name, [])]
                if len(q_users) != 1 or int(q_users[0]) != int(dq_idx):
                    continue

                float_name = str(q_op.inputs[0])
                float_tensor = model_ir.tensors.get(float_name, None)
                dq_tensor = model_ir.tensors.get(str(concat_input_name), None)
                if float_tensor is None or dq_tensor is None:
                    continue
                if str(float_tensor.dtype).upper().startswith("INT"):
                    continue
                if not _shapes_equal(list(float_tensor.shape), list(dq_tensor.shape)):
                    continue
                if not _has_dequantized_origin(float_name, producers):
                    continue

                updated_concat_inputs = [str(v) for v in list(concat_op.inputs)]
                if int(input_pos) >= 0 and int(input_pos) < len(updated_concat_inputs):
                    updated_concat_inputs[int(input_pos)] = str(float_name)
                    _set_operator_inputs(
                        model_ir=model_ir,
                        op=concat_op,
                        new_inputs=updated_concat_inputs,
                    )
                bypassed += 1
                changed = True
                break

            if changed:
                break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "bypassed_concat_pre_quantize_dequantize": int(bypassed),
    }


def _optimize_transpose_dequantize_mean_quantize_bridges(model_ir: ModelIR) -> Dict[str, int]:
    """
    Rewrite TRANSPOSE->DEQUANTIZE->MEAN->QUANTIZE bridges by moving TRANSPOSE after MEAN.

    Target pattern:
      X --TRANSPOSE(P)--> A --DEQUANTIZE--> B --MEAN(axes=K, keepDims=True)--> C --QUANTIZE--> Y

    Rewritten:
      X --DEQUANTIZE--> B --MEAN(axes=map(P,K), keepDims=True)--> C'
        --TRANSPOSE(P)--> C --QUANTIZE--> Y

    This preserves Y layout while avoiding transposing a large activation tensor.
    """
    moved_bridges = 0

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue

            pre_input = str(pre_op.inputs[0])
            pre_output = str(pre_op.outputs[0])
            if pre_output in model_ir.outputs:
                continue

            dq_users = consumers.get(pre_output, [])
            if len(dq_users) != 1:
                continue
            dq_idx = int(dq_users[0])
            dq_op = model_ir.operators[dq_idx]
            if str(dq_op.op_type) != "DEQUANTIZE" or len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                continue
            if str(dq_op.inputs[0]) != pre_output:
                continue
            dq_output = str(dq_op.outputs[0])
            if dq_output in model_ir.outputs:
                continue

            mean_users = consumers.get(dq_output, [])
            if len(mean_users) != 1:
                continue
            mean_idx = int(mean_users[0])
            mean_op = model_ir.operators[mean_idx]
            if str(mean_op.op_type) != "MEAN" or len(mean_op.inputs) < 2 or len(mean_op.outputs) != 1:
                continue
            if str(mean_op.inputs[0]) != dq_output:
                continue
            if not bool(mean_op.options.get("keepDims", False)):
                continue

            axes_name = str(mean_op.inputs[1])
            axes_users = consumers.get(axes_name, [])
            if len(axes_users) != 1:
                continue
            axes_tensor = model_ir.tensors.get(axes_name, None)
            if axes_tensor is None or axes_tensor.data is None:
                continue
            old_axes_raw = [int(v) for v in np.asarray(axes_tensor.data).reshape(-1).tolist()]
            if len(old_axes_raw) == 0:
                continue

            mean_output = str(mean_op.outputs[0])
            if mean_output in model_ir.outputs:
                continue

            q_users = consumers.get(mean_output, [])
            if len(q_users) != 1:
                continue
            q_idx = int(q_users[0])
            q_op = model_ir.operators[q_idx]
            if str(q_op.op_type) != "QUANTIZE" or len(q_op.inputs) != 1 or len(q_op.outputs) != 1:
                continue
            if str(q_op.inputs[0]) != mean_output:
                continue

            input_tensor = model_ir.tensors.get(pre_input, None)
            dq_tensor = model_ir.tensors.get(dq_output, None)
            mean_tensor = model_ir.tensors.get(mean_output, None)
            if input_tensor is None or dq_tensor is None or mean_tensor is None:
                continue
            rank = len(list(input_tensor.shape))
            if rank <= 0 or len(perm_pre) != rank:
                continue

            old_axes: List[int] = []
            valid_axes = True
            for axis in old_axes_raw:
                norm_axis = int(axis)
                if norm_axis < 0:
                    norm_axis += rank
                if norm_axis < 0 or norm_axis >= rank:
                    valid_axes = False
                    break
                old_axes.append(norm_axis)
            if not valid_axes:
                continue

            new_axes = [int(perm_pre[axis]) for axis in old_axes]

            # 1) Bypass pre-transpose for DEQUANTIZE.
            _set_operator_inputs(
                model_ir=model_ir,
                op=dq_op,
                new_inputs=[pre_input],
            )
            dq_tensor.shape = list(input_tensor.shape)
            dq_tensor.shape_signature = (
                list(input_tensor.shape_signature)
                if input_tensor.shape_signature is not None
                else list(input_tensor.shape)
            )

            # 2) Update MEAN axes to match input layout.
            axes_arr = np.asarray(new_axes, dtype=np.int32)
            axes_tensor.data = axes_arr
            axes_tensor.dtype = "INT32"
            axes_tensor.shape = [int(len(new_axes))]
            axes_tensor.shape_signature = [int(len(new_axes))]

            # 3) Recompute MEAN output tensor metadata in new layout.
            reduced_shape = list(dq_tensor.shape)
            reduced_signature = (
                list(dq_tensor.shape_signature)
                if dq_tensor.shape_signature is not None
                else list(dq_tensor.shape)
            )
            for axis in new_axes:
                if 0 <= int(axis) < len(reduced_shape):
                    reduced_shape[int(axis)] = 1
                if 0 <= int(axis) < len(reduced_signature):
                    reduced_signature[int(axis)] = 1
            mean_tensor.shape = list(reduced_shape)
            mean_tensor.shape_signature = list(reduced_signature)

            # 4) Insert a transpose before QUANTIZE to preserve QUANTIZE input layout.
            q_bridge_name = _unique_tensor_name(f"{mean_output}_for_quant")
            q_bridge_shape = _permute_shape(list(mean_tensor.shape), perm_pre)
            q_bridge_signature = _permute_shape(list(mean_tensor.shape_signature), perm_pre)
            if q_bridge_shape is None or q_bridge_signature is None:
                continue
            model_ir.tensors[q_bridge_name] = TensorIR(
                name=q_bridge_name,
                dtype=str(mean_tensor.dtype),
                shape=[int(v) for v in q_bridge_shape],
                shape_signature=[int(v) for v in q_bridge_signature],
                data=None,
            )

            perm_name = _unique_tensor_name(f"{q_bridge_name}_perm")
            perm_data = np.asarray(perm_pre, dtype=np.int32)
            model_ir.tensors[perm_name] = TensorIR(
                name=perm_name,
                dtype="INT32",
                shape=[int(perm_data.size)],
                shape_signature=[int(perm_data.size)],
                data=perm_data,
            )

            _set_operator_inputs(
                model_ir=model_ir,
                op=q_op,
                new_inputs=[q_bridge_name],
            )
            model_ir.operators.insert(
                q_idx,
                OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[mean_output, perm_name],
                    outputs=[q_bridge_name],
                ),
            )

            # 5) Remove the original pre-transpose.
            remove_idx = int(pre_idx if pre_idx < q_idx else pre_idx + 1)
            del model_ir.operators[remove_idx]

            moved_bridges += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "moved_transpose_dequantize_mean_quantize_bridges": int(moved_bridges),
    }


def _optimize_transpose_mean_hardsigmoid_muladd_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate redundant transpose bridges around mixed MEAN and HardSigmoid branches.

    Target pattern (rank-4, quantized):
      q0_raw --TRANSPOSE(0,3,1,2)--> q0_nchw
             --DEQUANTIZE--> ...MEAN(axes=[2,3])... --QUANTIZE--> qm_nchw --TRANSPOSE(0,2,3,1)--> qm_nhwc -> CONV
      q1_raw --TRANSPOSE(0,3,1,2)--> q1_nchw
             --DEQUANTIZE--> MUL(c)->ADD(c)->MAXIMUM(c)->MINIMUM(c) --QUANTIZE--> qsig_nchw
      MUL(q0_nchw, qsig_nchw) -> m
      ADD(q0_nchw, m) -> y

    Rewrite:
    - Bypass both pre-transposes on the two dequantize branches.
    - Convert MEAN axes to NHWC-side and remove post-quantize transpose.
    - Rewire MUL/ADD main inputs to q0_raw (NHWC).
    - Remove the three bridge transposes.
    - Insert NHWC->NCHW adapters only for legacy consumers of `y`.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    perm_nhwc_to_nchw_const_name = "__nhwc_to_nchw_perm_rank4__"

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _tensor_signature(tensor: TensorIR) -> List[int]:
        if tensor.shape_signature is not None:
            return [int(v) for v in list(tensor.shape_signature)]
        return [int(v) for v in list(tensor.shape)]

    if perm_nhwc_to_nchw_const_name not in model_ir.tensors:
        model_ir.tensors[perm_nhwc_to_nchw_const_name] = TensorIR(
            name=perm_nhwc_to_nchw_const_name,
            dtype="INT32",
            shape=[4],
            shape_signature=[4],
            data=np.asarray(perm_nhwc_to_nchw, dtype=np.int32),
            is_variable=False,
            quantization=None,
        )

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)

        for pre0_idx, pre0_op in enumerate(model_ir.operators):
            if str(pre0_op.op_type) != "TRANSPOSE" or len(pre0_op.inputs) < 2 or len(pre0_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre0_op) != perm_nhwc_to_nchw:
                continue

            q0_raw_name = str(pre0_op.inputs[0])
            q0_nchw_name = str(pre0_op.outputs[0])
            if q0_raw_name in model_ir.outputs or q0_nchw_name in model_ir.outputs:
                continue

            q0_users = [int(v) for v in consumers.get(q0_nchw_name, [])]
            if len(q0_users) != 3:
                continue

            dq0_idx: Optional[int] = None
            mul0_idx: Optional[int] = None
            add0_idx: Optional[int] = None
            for u_idx in q0_users:
                u_op = model_ir.operators[int(u_idx)]
                u_type = str(u_op.op_type)
                if u_type == "DEQUANTIZE":
                    if dq0_idx is not None:
                        dq0_idx = None
                        break
                    dq0_idx = int(u_idx)
                elif u_type == "MUL":
                    if mul0_idx is not None:
                        mul0_idx = None
                        break
                    mul0_idx = int(u_idx)
                elif u_type == "ADD":
                    if add0_idx is not None:
                        add0_idx = None
                        break
                    add0_idx = int(u_idx)
            if dq0_idx is None or mul0_idx is None or add0_idx is None:
                continue

            dq0_op = model_ir.operators[int(dq0_idx)]
            if len(dq0_op.inputs) != 1 or len(dq0_op.outputs) != 1 or str(dq0_op.inputs[0]) != q0_nchw_name:
                continue
            dq0_out_name = str(dq0_op.outputs[0])
            if dq0_out_name in model_ir.outputs:
                continue

            mean_users = [int(v) for v in consumers.get(dq0_out_name, [])]
            if len(mean_users) != 1:
                continue
            mean_idx = int(mean_users[0])
            mean_op = model_ir.operators[int(mean_idx)]
            if str(mean_op.op_type) != "MEAN" or len(mean_op.inputs) < 2 or len(mean_op.outputs) != 1:
                continue
            if str(mean_op.inputs[0]) != dq0_out_name or not bool(mean_op.options.get("keepDims", False)):
                continue
            mean_out_name = str(mean_op.outputs[0])
            if mean_out_name in model_ir.outputs:
                continue

            mean_axes_name = str(mean_op.inputs[1])
            mean_axes_tensor = model_ir.tensors.get(mean_axes_name, None)
            mean_axes = _read_const_ints_from_tensor(mean_axes_tensor)
            if mean_axes is None or len(mean_axes) == 0:
                continue

            qmean_users = [int(v) for v in consumers.get(mean_out_name, [])]
            if len(qmean_users) != 1:
                continue
            qmean_idx = int(qmean_users[0])
            qmean_op = model_ir.operators[int(qmean_idx)]
            if str(qmean_op.op_type) != "QUANTIZE" or len(qmean_op.inputs) != 1 or len(qmean_op.outputs) != 1:
                continue
            if str(qmean_op.inputs[0]) != mean_out_name:
                continue
            qmean_out_name = str(qmean_op.outputs[0])
            if qmean_out_name in model_ir.outputs:
                continue

            post_users = [int(v) for v in consumers.get(qmean_out_name, [])]
            if len(post_users) != 1:
                continue
            post_idx = int(post_users[0])
            post_op = model_ir.operators[int(post_idx)]
            if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                continue
            if str(post_op.inputs[0]) != qmean_out_name:
                continue
            if _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc:
                continue
            post_out_name = str(post_op.outputs[0])
            if post_out_name in model_ir.outputs:
                continue

            # Ensure post-transpose is a pure adapter to downstream ops.
            post_out_users = [int(v) for v in consumers.get(post_out_name, [])]
            if len(post_out_users) == 0:
                continue

            mul0_op = model_ir.operators[int(mul0_idx)]
            add0_op = model_ir.operators[int(add0_idx)]
            if len(mul0_op.inputs) != 2 or len(mul0_op.outputs) != 1:
                continue
            if len(add0_op.inputs) != 2 or len(add0_op.outputs) != 1:
                continue

            mul0_inputs = [str(v) for v in list(mul0_op.inputs)]
            if q0_nchw_name == mul0_inputs[0]:
                mul0_q0_input_idx = 0
                sig_q_name = mul0_inputs[1]
            elif q0_nchw_name == mul0_inputs[1]:
                mul0_q0_input_idx = 1
                sig_q_name = mul0_inputs[0]
            else:
                continue
            if sig_q_name in model_ir.outputs:
                continue

            add0_inputs = [str(v) for v in list(add0_op.inputs)]
            mul0_out_name = str(mul0_op.outputs[0])
            if q0_nchw_name == add0_inputs[0] and mul0_out_name == add0_inputs[1]:
                add0_q0_input_idx = 0
            elif q0_nchw_name == add0_inputs[1] and mul0_out_name == add0_inputs[0]:
                add0_q0_input_idx = 1
            else:
                continue

            sig_q_users = [int(v) for v in consumers.get(sig_q_name, [])]
            if len(sig_q_users) != 1 or int(sig_q_users[0]) != int(mul0_idx):
                continue
            mul0_users = [int(v) for v in consumers.get(mul0_out_name, [])]
            if len(mul0_users) != 1 or int(mul0_users[0]) != int(add0_idx):
                continue

            qsig_prod_idx = producers.get(sig_q_name, None)
            if qsig_prod_idx is None:
                continue
            qsig_op = model_ir.operators[int(qsig_prod_idx)]
            if str(qsig_op.op_type) != "QUANTIZE" or len(qsig_op.inputs) != 1 or len(qsig_op.outputs) != 1:
                continue
            hsig_min_out_name = str(qsig_op.inputs[0])

            hsig_min_idx = producers.get(hsig_min_out_name, None)
            if hsig_min_idx is None:
                continue
            hsig_min_op = model_ir.operators[int(hsig_min_idx)]
            if str(hsig_min_op.op_type) != "MINIMUM" or len(hsig_min_op.inputs) != 2 or len(hsig_min_op.outputs) != 1:
                continue
            hsig_max_out_name = (
                str(hsig_min_op.inputs[0])
                if str(hsig_min_op.inputs[0]) != str(hsig_min_op.inputs[1])
                else str(hsig_min_op.inputs[0])
            )
            # Identify main path input of MINIMUM.
            if producers.get(str(hsig_min_op.inputs[0]), None) is not None:
                hsig_max_out_name = str(hsig_min_op.inputs[0])
            elif producers.get(str(hsig_min_op.inputs[1]), None) is not None:
                hsig_max_out_name = str(hsig_min_op.inputs[1])
            else:
                continue

            hsig_max_idx = producers.get(hsig_max_out_name, None)
            if hsig_max_idx is None:
                continue
            hsig_max_op = model_ir.operators[int(hsig_max_idx)]
            if str(hsig_max_op.op_type) != "MAXIMUM" or len(hsig_max_op.inputs) != 2 or len(hsig_max_op.outputs) != 1:
                continue

            hsig_add_out_name = (
                str(hsig_max_op.inputs[0])
                if producers.get(str(hsig_max_op.inputs[0]), None) is not None
                else str(hsig_max_op.inputs[1])
            )
            hsig_add_idx = producers.get(hsig_add_out_name, None)
            if hsig_add_idx is None:
                continue
            hsig_add_op = model_ir.operators[int(hsig_add_idx)]
            if str(hsig_add_op.op_type) != "ADD" or len(hsig_add_op.inputs) != 2 or len(hsig_add_op.outputs) != 1:
                continue

            hsig_mul_out_name = (
                str(hsig_add_op.inputs[0])
                if producers.get(str(hsig_add_op.inputs[0]), None) is not None
                else str(hsig_add_op.inputs[1])
            )
            hsig_mul_idx = producers.get(hsig_mul_out_name, None)
            if hsig_mul_idx is None:
                continue
            hsig_mul_op = model_ir.operators[int(hsig_mul_idx)]
            if str(hsig_mul_op.op_type) != "MUL" or len(hsig_mul_op.inputs) != 2 or len(hsig_mul_op.outputs) != 1:
                continue

            dq1_out_name = (
                str(hsig_mul_op.inputs[0])
                if producers.get(str(hsig_mul_op.inputs[0]), None) is not None
                else str(hsig_mul_op.inputs[1])
            )
            dq1_idx = producers.get(dq1_out_name, None)
            if dq1_idx is None:
                continue
            dq1_op = model_ir.operators[int(dq1_idx)]
            if str(dq1_op.op_type) != "DEQUANTIZE" or len(dq1_op.inputs) != 1 or len(dq1_op.outputs) != 1:
                continue
            if str(dq1_op.outputs[0]) != dq1_out_name:
                continue
            q1_nchw_name = str(dq1_op.inputs[0])
            if q1_nchw_name in model_ir.outputs:
                continue

            pre1_idx = producers.get(q1_nchw_name, None)
            if pre1_idx is None:
                continue
            pre1_op = model_ir.operators[int(pre1_idx)]
            if str(pre1_op.op_type) != "TRANSPOSE" or len(pre1_op.inputs) < 2 or len(pre1_op.outputs) != 1:
                continue
            if str(pre1_op.outputs[0]) != q1_nchw_name:
                continue
            if _read_transpose_perm(model_ir, pre1_op) != perm_nhwc_to_nchw:
                continue
            q1_raw_name = str(pre1_op.inputs[0])
            if q1_raw_name in model_ir.outputs:
                continue
            q1_users = [int(v) for v in consumers.get(q1_nchw_name, [])]
            if len(q1_users) != 1 or int(q1_users[0]) != int(dq1_idx):
                continue

            q0_raw_tensor = model_ir.tensors.get(q0_raw_name, None)
            q0_nchw_tensor = model_ir.tensors.get(q0_nchw_name, None)
            q1_raw_tensor = model_ir.tensors.get(q1_raw_name, None)
            q1_nchw_tensor = model_ir.tensors.get(q1_nchw_name, None)
            dq0_out_tensor = model_ir.tensors.get(dq0_out_name, None)
            mean_out_tensor = model_ir.tensors.get(mean_out_name, None)
            qmean_out_tensor = model_ir.tensors.get(qmean_out_name, None)
            dq1_out_tensor = model_ir.tensors.get(dq1_out_name, None)
            hsig_mul_out_tensor = model_ir.tensors.get(hsig_mul_out_name, None)
            hsig_add_out_tensor = model_ir.tensors.get(hsig_add_out_name, None)
            hsig_max_out_tensor = model_ir.tensors.get(hsig_max_out_name, None)
            hsig_min_out_tensor = model_ir.tensors.get(hsig_min_out_name, None)
            sig_q_tensor = model_ir.tensors.get(sig_q_name, None)
            mul0_out_tensor = model_ir.tensors.get(mul0_out_name, None)
            add0_out_name = str(add0_op.outputs[0])
            add0_out_tensor = model_ir.tensors.get(add0_out_name, None)
            if any(
                t is None
                for t in [
                    q0_raw_tensor,
                    q0_nchw_tensor,
                    q1_raw_tensor,
                    q1_nchw_tensor,
                    dq0_out_tensor,
                    mean_out_tensor,
                    qmean_out_tensor,
                    dq1_out_tensor,
                    hsig_mul_out_tensor,
                    hsig_add_out_tensor,
                    hsig_max_out_tensor,
                    hsig_min_out_tensor,
                    sig_q_tensor,
                    mul0_out_tensor,
                    add0_out_tensor,
                ]
            ):
                continue

            # Avoid per-axis qdim remap complexity in this rewrite.
            if not _all_per_tensor_quantized(
                [
                    q0_raw_tensor,
                    q0_nchw_tensor,
                    q1_raw_tensor,
                    q1_nchw_tensor,
                    qmean_out_tensor,
                    sig_q_tensor,
                    mul0_out_tensor,
                    add0_out_tensor,
                ]
            ):
                continue

            # 1) Bypass pre0 transpose on mean branch.
            _set_operator_inputs(
                model_ir=model_ir,
                op=dq0_op,
                new_inputs=[q0_raw_name],
            )
            dq0_out_tensor.shape = [int(v) for v in list(q0_raw_tensor.shape)]
            dq0_out_tensor.shape_signature = _tensor_signature(q0_raw_tensor)

            # 2) Remap mean axes from NCHW to NHWC side.
            rank = len(list(q0_raw_tensor.shape))
            normalized_axes: List[int] = []
            valid_axes = True
            for axis in mean_axes:
                a = int(axis)
                if a < 0:
                    a += rank
                if a < 0 or a >= rank:
                    valid_axes = False
                    break
                normalized_axes.append(int(a))
            if not valid_axes:
                continue
            new_axes = [int(perm_nhwc_to_nchw[int(axis)]) for axis in normalized_axes]
            if not _write_const_ints_to_tensor(mean_axes_tensor, [int(v) for v in new_axes]):
                continue

            mean_shape = [int(v) for v in list(q0_raw_tensor.shape)]
            mean_sig = _tensor_signature(q0_raw_tensor)
            for axis in new_axes:
                if 0 <= int(axis) < len(mean_shape):
                    mean_shape[int(axis)] = 1
                if 0 <= int(axis) < len(mean_sig):
                    mean_sig[int(axis)] = 1
            mean_out_tensor.shape = [int(v) for v in list(mean_shape)]
            mean_out_tensor.shape_signature = [int(v) for v in list(mean_sig)]

            # qmean now follows MEAN (NHWC-side), so remove post transpose.
            qmean_out_tensor.shape = [int(v) for v in list(mean_shape)]
            qmean_out_tensor.shape_signature = [int(v) for v in list(mean_sig)]
            for post_user_idx in post_out_users:
                post_user_op = model_ir.operators[int(post_user_idx)]
                updated_inputs = [
                    str(qmean_out_name) if str(inp) == str(post_out_name) else str(inp)
                    for inp in list(post_user_op.inputs)
                ]
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=post_user_op,
                    new_inputs=updated_inputs,
                )

            # 3) Bypass pre1 transpose on HardSigmoid branch.
            _set_operator_inputs(
                model_ir=model_ir,
                op=dq1_op,
                new_inputs=[q1_raw_name],
            )
            dq1_out_tensor.shape = [int(v) for v in list(q1_raw_tensor.shape)]
            dq1_out_tensor.shape_signature = _tensor_signature(q1_raw_tensor)

            # 4) Rewire MUL/ADD main path to q0_raw.
            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul0_op,
                input_index=int(mul0_q0_input_idx),
                new_input_name=q0_raw_name,
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add0_op,
                input_index=int(add0_q0_input_idx),
                new_input_name=q0_raw_name,
            )

            # 5) Metadata now follows NHWC on rewritten branches.
            for tensor in [
                dq1_out_tensor,
                hsig_mul_out_tensor,
                hsig_add_out_tensor,
                hsig_max_out_tensor,
                hsig_min_out_tensor,
                sig_q_tensor,
                mul0_out_tensor,
                add0_out_tensor,
            ]:
                _permute_tensor_metadata_if_rank_matches(tensor, perm_nchw_to_nhwc)

            # Preserve legacy NCHW semantics for add0 downstream via adapters.
            legacy_add0_shape = [int(v) for v in list(add0_out_tensor.shape)]
            legacy_add0_sig = _tensor_signature(add0_out_tensor)
            adapter_insertions: List[Tuple[int, OperatorIR]] = []
            consumers_after = _build_tensor_consumer_map(model_ir)
            add0_consumers = [int(v) for v in consumers_after.get(add0_out_name, [])]
            for legacy_idx in add0_consumers:
                if int(legacy_idx) == int(add0_idx):
                    continue
                legacy_op = model_ir.operators[int(legacy_idx)]
                slots = [
                    int(i)
                    for i, inp in enumerate(list(legacy_op.inputs))
                    if str(inp) == str(add0_out_name)
                ]
                if len(slots) == 0:
                    continue
                adapter_name = _unique_tensor_name(f"{add0_out_name}_nchw_adapter")
                model_ir.tensors[adapter_name] = TensorIR(
                    name=adapter_name,
                    dtype=str(add0_out_tensor.dtype),
                    shape=[int(v) for v in legacy_add0_shape],
                    shape_signature=[int(v) for v in legacy_add0_sig],
                    data=None,
                    is_variable=False,
                    quantization=_clone_quantization(add0_out_tensor.quantization),
                )
                adapter_op = OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[add0_out_name, perm_nhwc_to_nchw_const_name],
                    outputs=[adapter_name],
                )
                adapter_insertions.append((int(legacy_idx), adapter_op))
                updated_inputs = [str(v) for v in list(legacy_op.inputs)]
                for slot in slots:
                    if 0 <= int(slot) < len(updated_inputs):
                        updated_inputs[int(slot)] = str(adapter_name)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=legacy_op,
                    new_inputs=updated_inputs,
                )

            if len(adapter_insertions) > 0:
                inserted = 0
                for insert_idx, adapter_op in sorted(adapter_insertions, key=lambda v: int(v[0])):
                    model_ir.operators.insert(int(insert_idx + inserted), adapter_op)
                    inserted += 1

            # 6) Remove bridge transposes.
            remove_indices = sorted(
                set([int(pre0_idx), int(post_idx), int(pre1_idx)]),
                reverse=True,
            )
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "optimized_transpose_mean_hardsigmoid_muladd_chains": int(optimized),
    }


def _optimize_nhwc_propagation_qlinear_concat_conv(model_ir: ModelIR) -> Dict[str, int]:
    """
    Propagate NHWC layout through a QLinearConcat -> QLinearConv bridge.

    Target IR shape:
      (NCHW quantized inputs)
        -> DEQUANTIZE[*]
        -> CONCATENATION(axis=1)
        -> QUANTIZE(q_out_nchw)
        -> TRANSPOSE([0,2,3,1])  # q_out_nhwc
        -> (CONV_2D|DEPTHWISE_CONV_2D)

    Rewrites:
    - Fold per-input NCHW adapters (TRANSPOSE [0,3,1,2]) into DQ inputs when safe.
    - Convert CONCAT axis from NCHW to NHWC.
    - Remove post-QUANTIZE TRANSPOSE adapters to CONV inputs.
    """
    propagated = 0
    rank4_perm_nchw_to_nhwc = [0, 2, 3, 1]
    rank4_perm_nhwc_to_nchw = [0, 3, 1, 2]
    inv_nchw_to_nhwc = _invert_perm(rank4_perm_nchw_to_nhwc)
    if inv_nchw_to_nhwc is None:
        return {"propagated_qlinear_concat_conv_nhwc_chains": 0}

    def _remap_qdim_for_permute(tensor: Optional[TensorIR], perm: List[int]) -> None:
        if tensor is None or tensor.quantization is None:
            return
        if _quant_scale_count(tensor.quantization) <= 1:
            return
        inv = _invert_perm(perm)
        if inv is None:
            return
        old_qdim = int(tensor.quantization.quantized_dimension)
        if 0 <= old_qdim < len(inv):
            tensor.quantization.quantized_dimension = int(inv[old_qdim])

    def _is_nchw_nhwc_reinterpret_safe(tensor: Optional[TensorIR]) -> bool:
        if tensor is None:
            return False
        shape = list(tensor.shape)
        if len(shape) != 4:
            return False
        signature = (
            list(tensor.shape_signature)
            if tensor.shape_signature is not None
            else list(shape)
        )
        if len(signature) != 4:
            return False
        # Reinterpretation is safe when spatial dimensions are statically singleton.
        return int(shape[2]) == 1 and int(shape[3]) == 1 and int(signature[2]) == 1 and int(signature[3]) == 1

    def _permute_tensor_shape_signature(tensor: Optional[TensorIR], perm: List[int]) -> bool:
        if tensor is None:
            return False
        new_shape = _permute_shape(list(tensor.shape), perm)
        signature_source = (
            list(tensor.shape_signature)
            if tensor.shape_signature is not None
            else list(tensor.shape)
        )
        new_signature = _permute_shape(signature_source, perm)
        if new_shape is None or new_signature is None:
            return False
        tensor.shape = [int(v) for v in new_shape]
        tensor.shape_signature = [int(v) for v in new_signature]
        _remap_qdim_for_permute(tensor, perm)
        return True

    def _permuted_shape_signature(
        tensor: Optional[TensorIR],
        perm: List[int],
    ) -> Optional[Tuple[List[int], List[int]]]:
        if tensor is None:
            return None
        new_shape = _permute_shape(list(tensor.shape), perm)
        signature_source = (
            list(tensor.shape_signature)
            if tensor.shape_signature is not None
            else list(tensor.shape)
        )
        new_signature = _permute_shape(signature_source, perm)
        if new_shape is None or new_signature is None:
            return None
        return [int(v) for v in new_shape], [int(v) for v in new_signature]

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)

        for concat_idx, concat_op in enumerate(model_ir.operators):
            if str(concat_op.op_type) != "CONCATENATION" or len(concat_op.inputs) == 0 or len(concat_op.outputs) != 1:
                continue
            concat_out_name = str(concat_op.outputs[0])
            if concat_out_name in model_ir.outputs:
                continue

            q_users = [int(v) for v in consumers.get(concat_out_name, [])]
            if len(q_users) != 1:
                continue
            q_idx = int(q_users[0])
            q_op = model_ir.operators[q_idx]
            if str(q_op.op_type) != "QUANTIZE" or len(q_op.inputs) != 1 or len(q_op.outputs) != 1:
                continue
            if str(q_op.inputs[0]) != concat_out_name:
                continue
            q_out_name = str(q_op.outputs[0])
            if q_out_name in model_ir.outputs:
                continue

            post_users = [int(v) for v in consumers.get(q_out_name, [])]
            if len(post_users) == 0:
                continue

            removable_post_indices: List[int] = []
            post_output_names: List[str] = []
            valid_posts = True
            for post_idx in post_users:
                post_op = model_ir.operators[post_idx]
                if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                    valid_posts = False
                    break
                if str(post_op.inputs[0]) != q_out_name:
                    valid_posts = False
                    break
                perm_post = _read_transpose_perm(model_ir, post_op)
                if perm_post != rank4_perm_nchw_to_nhwc:
                    valid_posts = False
                    break
                post_output_name = str(post_op.outputs[0])
                if post_output_name in model_ir.outputs:
                    valid_posts = False
                    break
                removable_post_indices.append(int(post_idx))
                post_output_names.append(post_output_name)
            if not valid_posts:
                continue

            # Collect and rewrite concat input DQ adapters.
            removable_pre_indices: List[int] = []
            convertible = True
            pending_dq_input_rewrites: Dict[int, str] = {}
            pending_quant_input_rewrites: Dict[int, str] = {}
            pending_tensor_shape_updates: Dict[str, Tuple[List[int], List[int]]] = {}
            pending_qdim_remaps: set[str] = set()
            for dq_input_name in list(concat_op.inputs):
                dq_idx = producers.get(str(dq_input_name), None)
                if dq_idx is None:
                    convertible = False
                    break
                dq_op = model_ir.operators[int(dq_idx)]
                if str(dq_op.op_type) != "DEQUANTIZE" or len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                    convertible = False
                    break
                if str(dq_op.outputs[0]) != str(dq_input_name):
                    convertible = False
                    break

                q_in_name = str(dq_op.inputs[0])
                if q_in_name in model_ir.outputs:
                    convertible = False
                    break

                q_in_tensor = model_ir.tensors.get(q_in_name, None)
                if q_in_tensor is None or len(list(q_in_tensor.shape)) != 4:
                    convertible = False
                    break

                q_in_producer_idx = producers.get(q_in_name, None)
                if q_in_producer_idx is None:
                    convertible = False
                    break
                q_in_producer = model_ir.operators[int(q_in_producer_idx)]

                # Pattern 1:
                #   q_raw --TRANSPOSE(0,3,1,2)--> q_nchw --DEQUANTIZE--> dq
                if (
                    str(q_in_producer.op_type) == "TRANSPOSE"
                    and len(q_in_producer.inputs) >= 2
                    and len(q_in_producer.outputs) == 1
                    and _read_transpose_perm(model_ir, q_in_producer) == rank4_perm_nhwc_to_nchw
                ):
                    q_raw_name = str(q_in_producer.inputs[0])
                    q_in_users = [int(v) for v in consumers.get(q_in_name, [])]
                    if len(q_in_users) != 1 or int(q_in_users[0]) != int(dq_idx):
                        convertible = False
                        break
                    if q_in_name in model_ir.outputs:
                        convertible = False
                        break

                    q_raw_tensor = model_ir.tensors.get(q_raw_name, None)
                    dq_out_tensor = model_ir.tensors.get(str(dq_op.outputs[0]), None)
                    if q_raw_tensor is None or dq_out_tensor is None:
                        convertible = False
                        break
                    pending_dq_input_rewrites[int(dq_idx)] = str(q_raw_name)
                    pending_tensor_shape_updates[str(dq_op.outputs[0])] = (
                        [int(v) for v in list(q_raw_tensor.shape)],
                        [int(v) for v in list(q_raw_tensor.shape_signature)]
                        if q_raw_tensor.shape_signature is not None
                        else [int(v) for v in list(q_raw_tensor.shape)]
                    )
                    removable_pre_indices.append(int(q_in_producer_idx))
                    continue

                # Pattern 2:
                #   x_nhwc --TRANSPOSE(0,3,1,2)--> x_nchw --QUANTIZE--> q_nchw --DEQUANTIZE--> dq
                if (
                    str(q_in_producer.op_type) == "QUANTIZE"
                    and len(q_in_producer.inputs) == 1
                    and len(q_in_producer.outputs) == 1
                    and str(q_in_producer.outputs[0]) == q_in_name
                ):
                    q_float_name = str(q_in_producer.inputs[0])
                    q_float_producer_idx = producers.get(q_float_name, None)
                    if q_float_producer_idx is not None:
                        q_float_producer = model_ir.operators[int(q_float_producer_idx)]
                        if (
                            str(q_float_producer.op_type) == "TRANSPOSE"
                            and len(q_float_producer.inputs) >= 2
                            and len(q_float_producer.outputs) == 1
                            and _read_transpose_perm(model_ir, q_float_producer) == rank4_perm_nhwc_to_nchw
                        ):
                            q_float_users = [int(v) for v in consumers.get(q_float_name, [])]
                            if len(q_float_users) != 1 or int(q_float_users[0]) != int(q_in_producer_idx):
                                convertible = False
                                break
                            if q_float_name in model_ir.outputs:
                                convertible = False
                                break

                            permuted_q_in = _permuted_shape_signature(q_in_tensor, rank4_perm_nchw_to_nhwc)
                            if permuted_q_in is None:
                                convertible = False
                                break
                            pending_quant_input_rewrites[int(q_in_producer_idx)] = str(q_float_producer.inputs[0])
                            pending_tensor_shape_updates[q_in_name] = permuted_q_in
                            pending_qdim_remaps.add(q_in_name)

                            dq_out_tensor = model_ir.tensors.get(str(dq_op.outputs[0]), None)
                            if dq_out_tensor is None:
                                convertible = False
                                break
                            pending_tensor_shape_updates[str(dq_op.outputs[0])] = (
                                list(permuted_q_in[0]),
                                list(permuted_q_in[1]),
                            )
                            removable_pre_indices.append(int(q_float_producer_idx))
                            continue

                # Pattern 3:
                #   q_nchw --DEQUANTIZE--> dq, where q_nchw is effectively layout-invariant
                #   (e.g., NCHW N,C,1,1), so we can reinterpret metadata without data movement.
                q_in_users = [int(v) for v in consumers.get(q_in_name, [])]
                if len(q_in_users) == 1 and int(q_in_users[0]) == int(dq_idx):
                    # q_in produced directly by QUANTIZE is shape-reconciled from its float input
                    # in later passes. Metadata-only reinterpretation here is unstable and can
                    # recreate NCHW/NHWC mismatches at CONCATENATION prepare time.
                    if str(q_in_producer.op_type) == "QUANTIZE":
                        convertible = False
                        break
                    if _is_nchw_nhwc_reinterpret_safe(q_in_tensor):
                        permuted_q_in = _permuted_shape_signature(q_in_tensor, rank4_perm_nchw_to_nhwc)
                        if permuted_q_in is None:
                            convertible = False
                            break
                        pending_tensor_shape_updates[q_in_name] = permuted_q_in
                        pending_qdim_remaps.add(q_in_name)
                        dq_out_tensor = model_ir.tensors.get(str(dq_op.outputs[0]), None)
                        if dq_out_tensor is None:
                            convertible = False
                            break
                        pending_tensor_shape_updates[str(dq_op.outputs[0])] = (
                            list(permuted_q_in[0]),
                            list(permuted_q_in[1]),
                        )
                        continue

                convertible = False
                break

            if not convertible:
                continue

            concat_axis_old = int(concat_op.options.get("axis", 1))
            if concat_axis_old < 0 or concat_axis_old >= len(inv_nchw_to_nhwc):
                continue
            concat_axis_new = int(inv_nchw_to_nhwc[concat_axis_old])

            # Validate prospective concat input layout compatibility before committing rewrites.
            prospective_concat_shapes: List[List[int]] = []
            prospective_concat_signatures: List[List[int]] = []
            prospective_valid = True
            for concat_input_name in list(concat_op.inputs):
                tensor = model_ir.tensors.get(str(concat_input_name), None)
                if tensor is None:
                    prospective_valid = False
                    break
                pending_shape_sig = pending_tensor_shape_updates.get(str(concat_input_name), None)
                if pending_shape_sig is not None:
                    shape_i, sig_i = pending_shape_sig
                else:
                    shape_i = [int(v) for v in list(tensor.shape)]
                    sig_i = (
                        [int(v) for v in list(tensor.shape_signature)]
                        if tensor.shape_signature is not None
                        else [int(v) for v in list(tensor.shape)]
                    )
                if len(list(shape_i)) != 4 or len(list(sig_i)) != 4:
                    prospective_valid = False
                    break
                prospective_concat_shapes.append([int(v) for v in list(shape_i)])
                prospective_concat_signatures.append([int(v) for v in list(sig_i)])
            if not prospective_valid or len(prospective_concat_shapes) == 0:
                continue
            ref_shape = list(prospective_concat_shapes[0])
            for shape_i in prospective_concat_shapes[1:]:
                for dim_idx in range(4):
                    if int(dim_idx) == int(concat_axis_new):
                        continue
                    if (
                        int(ref_shape[dim_idx]) >= 0
                        and int(shape_i[dim_idx]) >= 0
                        and int(ref_shape[dim_idx]) != int(shape_i[dim_idx])
                    ):
                        prospective_valid = False
                        break
                if not prospective_valid:
                    break
            if not prospective_valid:
                continue

            for op_idx, new_input_name in pending_dq_input_rewrites.items():
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=model_ir.operators[int(op_idx)],
                    new_inputs=[str(new_input_name)],
                )
            for op_idx, new_input_name in pending_quant_input_rewrites.items():
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=model_ir.operators[int(op_idx)],
                    new_inputs=[str(new_input_name)],
                )
            for tensor_name, (new_shape, new_signature) in pending_tensor_shape_updates.items():
                tensor = model_ir.tensors.get(str(tensor_name), None)
                if tensor is None:
                    continue
                tensor.shape = [int(v) for v in list(new_shape)]
                tensor.shape_signature = [int(v) for v in list(new_signature)]
            for tensor_name in pending_qdim_remaps:
                tensor = model_ir.tensors.get(str(tensor_name), None)
                _remap_qdim_for_permute(tensor, rank4_perm_nchw_to_nhwc)

            concat_op.options["axis"] = int(concat_axis_new)

            concat_input_tensors: List[Optional[TensorIR]] = [
                model_ir.tensors.get(str(input_name), None)
                for input_name in concat_op.inputs
            ]
            if any(t is None for t in concat_input_tensors):
                continue
            first_tensor = concat_input_tensors[0]
            if first_tensor is None:
                continue
            rank = len(list(first_tensor.shape))
            if rank != 4:
                continue

            concat_shape = [int(v) for v in list(first_tensor.shape)]
            concat_signature = (
                [int(v) for v in list(first_tensor.shape_signature)]
                if first_tensor.shape_signature is not None
                else [int(v) for v in list(first_tensor.shape)]
            )
            dynamic_concat_axis = False
            for tensor in concat_input_tensors[1:]:
                if tensor is None:
                    continue
                if len(list(tensor.shape)) != rank:
                    convertible = False
                    break
                for dim_idx in range(rank):
                    if int(dim_idx) == int(concat_axis_new):
                        continue
                    if (
                        int(concat_shape[dim_idx]) >= 0
                        and int(tensor.shape[dim_idx]) >= 0
                        and int(concat_shape[dim_idx]) != int(tensor.shape[dim_idx])
                    ):
                        convertible = False
                        break
                if not convertible:
                    break
                concat_shape[concat_axis_new] += int(tensor.shape[concat_axis_new])
            if not convertible:
                continue
            for tensor in concat_input_tensors:
                if tensor is None:
                    continue
                sig = (
                    [int(v) for v in list(tensor.shape_signature)]
                    if tensor.shape_signature is not None
                    else [int(v) for v in list(tensor.shape)]
                )
                if int(sig[concat_axis_new]) < 0:
                    dynamic_concat_axis = True
                    break
            if dynamic_concat_axis:
                concat_signature[concat_axis_new] = -1
            else:
                concat_signature[concat_axis_new] = int(
                    sum(
                        int(
                            (
                                t.shape_signature[concat_axis_new]
                                if t is not None and t.shape_signature is not None
                                else t.shape[concat_axis_new]
                            )
                        )
                        for t in concat_input_tensors
                        if t is not None
                    )
                )

            concat_out_tensor = model_ir.tensors.get(concat_out_name, None)
            if concat_out_tensor is None:
                continue
            concat_out_tensor.shape = [int(v) for v in concat_shape]
            concat_out_tensor.shape_signature = [int(v) for v in concat_signature]

            q_out_tensor = model_ir.tensors.get(q_out_name, None)
            if q_out_tensor is None:
                continue
            q_out_tensor.shape = [int(v) for v in concat_shape]
            q_out_tensor.shape_signature = [int(v) for v in concat_signature]
            _remap_qdim_for_permute(q_out_tensor, rank4_perm_nchw_to_nhwc)

            # Remove output transpose adapters and reconnect their consumers to q_out directly.
            for post_idx in removable_post_indices:
                post_op = model_ir.operators[int(post_idx)]
                post_out_name = str(post_op.outputs[0])
                _replace_tensor_inputs(model_ir, post_out_name, q_out_name)

            remove_indices = sorted(
                set(int(v) for v in (removable_pre_indices + removable_post_indices)),
                reverse=True,
            )
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            propagated += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "propagated_qlinear_concat_conv_nhwc_chains": int(propagated),
    }


def _optimize_nhwc_prefix_qlinear_silu_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Propagate NHWC through early QLinear SiLU chains and remove unnecessary
    NCHW round-trips around Conv outputs.

    Target pattern (rank-4):
      q_raw_nhwc --TRANSPOSE(0,3,1,2)--> q_nchw
      q_nchw --DEQUANTIZE--> dq --LOGISTIC--> sig_f --QUANTIZE--> sig_q
      MUL(q_nchw, sig_q) --> y_q
    or
      q_raw_nhwc --TRANSPOSE(0,3,1,2)--> q_nchw
      q_nchw --DEQUANTIZE--> dq --MUL(c1)--> --ADD(c2)--> --MAXIMUM(c3)--> --MINIMUM(c4)--> --QUANTIZE--> sig_q
      MUL(q_nchw, sig_q) --> y_q

    Rewrite:
      q_raw_nhwc --DEQUANTIZE--> dq --LOGISTIC--> sig_f --QUANTIZE--> sig_q
      MUL(q_raw_nhwc, sig_q) --> y_q

    Plus optional removal of:
      y_q --TRANSPOSE(0,2,3,1)--> y_nhwc

    Safety:
    - Strict SiLU topology
      : single DEQUANTIZE->LOGISTIC->QUANTIZE branch
      : or DEQUANTIZE->(MUL/ADD/MAXIMUM/MINIMUM)->QUANTIZE with singleton constants.
    - Per-tensor quantization only on quantized tensors touched by the rewrite.
    - For non-transpose consumers, preserve legacy NCHW semantics by inserting
      NHWC->NCHW adapters at the consumer input slots when the op is considered
      layout-safe (axis count preserving / non-layout-sensitive).
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    perm_nhwc_to_nchw_const_name = "__nhwc_to_nchw_perm_rank4__"
    # Ops excluded from generic legacy-adapter rewiring because they are
    # layout-sensitive or modify axis semantics directly.
    legacy_adapter_blocklist = {
        "CONCATENATION",
        "CONV_2D",
        "DEPTHWISE_CONV_2D",
        "MAX_POOL_2D",
        "AVERAGE_POOL_2D",
        "RESIZE_BILINEAR",
        "RESIZE_NEAREST_NEIGHBOR",
        "RESHAPE",
        "TRANSPOSE",
        "STRIDED_SLICE",
        "SLICE",
        "SOFTMAX",
        "FULLY_CONNECTED",
        "MEAN",
    }

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    if perm_nhwc_to_nchw_const_name not in model_ir.tensors:
        model_ir.tensors[perm_nhwc_to_nchw_const_name] = TensorIR(
            name=perm_nhwc_to_nchw_const_name,
            dtype="INT32",
            shape=[4],
            shape_signature=[4],
            data=np.asarray(perm_nhwc_to_nchw, dtype=np.int32),
            is_variable=False,
            quantization=None,
        )

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue

            q_raw_name = str(pre_op.inputs[0])
            q_nchw_name = str(pre_op.outputs[0])
            if q_raw_name in model_outputs or q_nchw_name in model_outputs:
                continue

            q_raw_tensor = model_ir.tensors.get(q_raw_name, None)
            q_nchw_tensor = model_ir.tensors.get(q_nchw_name, None)
            if q_raw_tensor is None or q_nchw_tensor is None:
                continue
            if len(list(q_raw_tensor.shape)) != 4 or len(list(q_nchw_tensor.shape)) != 4:
                continue
            if not _all_per_tensor_quantized([q_raw_tensor, q_nchw_tensor]):
                continue

            q_nchw_users = [int(v) for v in consumers.get(q_nchw_name, [])]
            if len(q_nchw_users) != 2:
                continue

            dq_idx: Optional[int] = None
            mul_idx: Optional[int] = None
            for user_idx in q_nchw_users:
                user_op = model_ir.operators[int(user_idx)]
                if str(user_op.op_type) == "DEQUANTIZE":
                    if dq_idx is not None:
                        dq_idx = None
                        break
                    dq_idx = int(user_idx)
                elif str(user_op.op_type) == "MUL":
                    if mul_idx is not None:
                        mul_idx = None
                        break
                    mul_idx = int(user_idx)
                else:
                    dq_idx = None
                    mul_idx = None
                    break
            if dq_idx is None or mul_idx is None:
                continue

            dq_op = model_ir.operators[int(dq_idx)]
            mul_op = model_ir.operators[int(mul_idx)]
            if len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                continue
            if str(dq_op.inputs[0]) != q_nchw_name:
                continue
            dq_out_name = str(dq_op.outputs[0])
            if dq_out_name in model_outputs:
                continue

            dq_users = [int(v) for v in consumers.get(dq_out_name, [])]
            if len(dq_users) != 1:
                continue

            sig_head_idx = int(dq_users[0])
            sig_head_op = model_ir.operators[int(sig_head_idx)]
            sig_head_type = str(sig_head_op.op_type)
            sig_intermediate_names: List[str] = []
            sig_q_name: Optional[str] = None

            # Pattern A:
            #   DEQUANTIZE -> LOGISTIC -> QUANTIZE
            if sig_head_type == "LOGISTIC":
                if len(sig_head_op.inputs) != 1 or len(sig_head_op.outputs) != 1:
                    continue
                if str(sig_head_op.inputs[0]) != dq_out_name:
                    continue
                logistic_out_name = str(sig_head_op.outputs[0])
                if logistic_out_name in model_outputs:
                    continue
                logistic_users = [int(v) for v in consumers.get(logistic_out_name, [])]
                if len(logistic_users) != 1:
                    continue
                qsig_idx = int(logistic_users[0])
                qsig_op = model_ir.operators[int(qsig_idx)]
                if str(qsig_op.op_type) != "QUANTIZE" or len(qsig_op.inputs) != 1 or len(qsig_op.outputs) != 1:
                    continue
                if str(qsig_op.inputs[0]) != logistic_out_name:
                    continue
                sig_intermediate_names = [logistic_out_name]
                sig_q_name = str(qsig_op.outputs[0])

            # Pattern B:
            #   DEQUANTIZE -> MUL(const) -> ADD(const) -> MAXIMUM(const) -> MINIMUM(const) -> QUANTIZE
            else:
                if sig_head_type != "MUL" or len(sig_head_op.inputs) != 2 or len(sig_head_op.outputs) != 1:
                    continue
                sig_head_inputs = [str(v) for v in list(sig_head_op.inputs)]
                if dq_out_name == sig_head_inputs[0]:
                    hs_mul_side = sig_head_inputs[1]
                elif dq_out_name == sig_head_inputs[1]:
                    hs_mul_side = sig_head_inputs[0]
                else:
                    continue
                if not _is_singleton_constant_tensor(model_ir, hs_mul_side):
                    continue
                hs_mul_out_name = str(sig_head_op.outputs[0])
                if hs_mul_out_name in model_outputs:
                    continue

                hs_mul_users = [int(v) for v in consumers.get(hs_mul_out_name, [])]
                if len(hs_mul_users) != 1:
                    continue
                hs_add_idx = int(hs_mul_users[0])
                hs_add_op = model_ir.operators[int(hs_add_idx)]
                if str(hs_add_op.op_type) != "ADD" or len(hs_add_op.inputs) != 2 or len(hs_add_op.outputs) != 1:
                    continue
                hs_add_inputs = [str(v) for v in list(hs_add_op.inputs)]
                if hs_mul_out_name == hs_add_inputs[0]:
                    hs_add_side = hs_add_inputs[1]
                elif hs_mul_out_name == hs_add_inputs[1]:
                    hs_add_side = hs_add_inputs[0]
                else:
                    continue
                if not _is_singleton_constant_tensor(model_ir, hs_add_side):
                    continue
                hs_add_out_name = str(hs_add_op.outputs[0])
                if hs_add_out_name in model_outputs:
                    continue

                hs_add_users = [int(v) for v in consumers.get(hs_add_out_name, [])]
                if len(hs_add_users) != 1:
                    continue
                hs_max_idx = int(hs_add_users[0])
                hs_max_op = model_ir.operators[int(hs_max_idx)]
                if str(hs_max_op.op_type) != "MAXIMUM" or len(hs_max_op.inputs) != 2 or len(hs_max_op.outputs) != 1:
                    continue
                hs_max_inputs = [str(v) for v in list(hs_max_op.inputs)]
                if hs_add_out_name == hs_max_inputs[0]:
                    hs_max_side = hs_max_inputs[1]
                elif hs_add_out_name == hs_max_inputs[1]:
                    hs_max_side = hs_max_inputs[0]
                else:
                    continue
                if not _is_singleton_constant_tensor(model_ir, hs_max_side):
                    continue
                hs_max_out_name = str(hs_max_op.outputs[0])
                if hs_max_out_name in model_outputs:
                    continue

                hs_max_users = [int(v) for v in consumers.get(hs_max_out_name, [])]
                if len(hs_max_users) != 1:
                    continue
                hs_min_idx = int(hs_max_users[0])
                hs_min_op = model_ir.operators[int(hs_min_idx)]
                if str(hs_min_op.op_type) != "MINIMUM" or len(hs_min_op.inputs) != 2 or len(hs_min_op.outputs) != 1:
                    continue
                hs_min_inputs = [str(v) for v in list(hs_min_op.inputs)]
                if hs_max_out_name == hs_min_inputs[0]:
                    hs_min_side = hs_min_inputs[1]
                elif hs_max_out_name == hs_min_inputs[1]:
                    hs_min_side = hs_min_inputs[0]
                else:
                    continue
                if not _is_singleton_constant_tensor(model_ir, hs_min_side):
                    continue
                hs_min_out_name = str(hs_min_op.outputs[0])
                if hs_min_out_name in model_outputs:
                    continue

                hs_min_users = [int(v) for v in consumers.get(hs_min_out_name, [])]
                if len(hs_min_users) != 1:
                    continue
                qsig_idx = int(hs_min_users[0])
                qsig_op = model_ir.operators[int(qsig_idx)]
                if str(qsig_op.op_type) != "QUANTIZE" or len(qsig_op.inputs) != 1 or len(qsig_op.outputs) != 1:
                    continue
                if str(qsig_op.inputs[0]) != hs_min_out_name:
                    continue
                sig_intermediate_names = [
                    hs_mul_out_name,
                    hs_add_out_name,
                    hs_max_out_name,
                    hs_min_out_name,
                ]
                sig_q_name = str(qsig_op.outputs[0])

            if sig_q_name is None or sig_q_name in model_outputs:
                continue

            if len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                continue
            mul_inputs = [str(v) for v in list(mul_op.inputs)]
            if q_nchw_name not in set(mul_inputs):
                continue
            if sig_q_name not in set(mul_inputs):
                continue
            sig_q_users = [int(v) for v in consumers.get(sig_q_name, [])]
            if sig_q_users != [int(mul_idx)] and set(sig_q_users) != {int(mul_idx)}:
                continue

            sig_q_tensor = model_ir.tensors.get(sig_q_name, None)
            mul_out_name = str(mul_op.outputs[0])
            mul_out_tensor = model_ir.tensors.get(mul_out_name, None)
            if mul_out_name in model_outputs or sig_q_tensor is None or mul_out_tensor is None:
                continue
            if not _all_per_tensor_quantized([sig_q_tensor, mul_out_tensor]):
                continue

            mul_users = [int(v) for v in consumers.get(mul_out_name, [])]
            removable_post_ops: List[OperatorIR] = []
            legacy_user_input_slots: List[Tuple[int, int]] = []
            users_supported = True
            for user_idx in mul_users:
                user_op = model_ir.operators[int(user_idx)]
                user_type = str(user_op.op_type)
                if user_type == "TRANSPOSE":
                    if len(user_op.inputs) < 2 or len(user_op.outputs) != 1:
                        users_supported = False
                        break
                    if str(user_op.inputs[0]) != mul_out_name:
                        users_supported = False
                        break
                    if _read_transpose_perm(model_ir, user_op) != perm_nchw_to_nhwc:
                        users_supported = False
                        break
                    if str(user_op.outputs[0]) in model_outputs:
                        users_supported = False
                        break
                    removable_post_ops.append(user_op)
                else:
                    if user_type in legacy_adapter_blocklist:
                        users_supported = False
                        break
                    input_indices = [
                        int(input_idx)
                        for input_idx, input_name in enumerate(user_op.inputs)
                        if str(input_name) == str(mul_out_name)
                    ]
                    if len(input_indices) == 0:
                        users_supported = False
                        break
                    if len(user_op.outputs) == 0:
                        users_supported = False
                        break
                    if any(str(output_name) in model_outputs for output_name in list(user_op.outputs)):
                        users_supported = False
                        break
                    for input_idx in input_indices:
                        legacy_user_input_slots.append((int(user_idx), int(input_idx)))
            if not users_supported:
                continue

            # Rewire SiLU branch to consume NHWC source directly.
            _set_operator_inputs(
                model_ir=model_ir,
                op=dq_op,
                new_inputs=[q_raw_name],
            )
            _set_operator_inputs(
                model_ir=model_ir,
                op=mul_op,
                new_inputs=[
                    q_raw_name if str(input_name) == q_nchw_name else str(input_name)
                    for input_name in mul_inputs
                ],
            )

            # For DEQUANTIZE users that should keep NCHW semantics downstream,
            # insert NHWC->NCHW adapters and redirect those DEQUANTIZE inputs.
            legacy_mul_shape = [int(v) for v in list(mul_out_tensor.shape)]
            legacy_mul_signature = (
                [int(v) for v in list(mul_out_tensor.shape_signature)]
                if mul_out_tensor.shape_signature is not None
                else [int(v) for v in list(mul_out_tensor.shape)]
            )
            adapter_insertions: List[Tuple[int, OperatorIR]] = []
            for legacy_user_idx, legacy_input_index in legacy_user_input_slots:
                legacy_user_op = model_ir.operators[int(legacy_user_idx)]
                adapter_name = _unique_tensor_name(f"{mul_out_name}_nchw_adapter")
                model_ir.tensors[adapter_name] = TensorIR(
                    name=adapter_name,
                    dtype=str(mul_out_tensor.dtype),
                    shape=list(legacy_mul_shape),
                    shape_signature=list(legacy_mul_signature),
                    data=None,
                    is_variable=False,
                    quantization=_clone_quantization(mul_out_tensor.quantization),
                )
                adapter_op = OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[mul_out_name, perm_nhwc_to_nchw_const_name],
                    outputs=[adapter_name],
                )
                adapter_insertions.append((int(legacy_user_idx), adapter_op))
                updated_inputs = [str(v) for v in list(legacy_user_op.inputs)]
                if 0 <= int(legacy_input_index) < len(updated_inputs):
                    updated_inputs[int(legacy_input_index)] = str(adapter_name)
                    _set_operator_inputs(
                        model_ir=model_ir,
                        op=legacy_user_op,
                        new_inputs=updated_inputs,
                    )

            if len(adapter_insertions) > 0:
                inserted = 0
                for insert_idx, adapter_op in sorted(adapter_insertions, key=lambda v: int(v[0])):
                    model_ir.operators.insert(int(insert_idx + inserted), adapter_op)
                    inserted += 1

            # Metadata now follows NHWC for the rewritten chain.
            metadata_targets = [dq_out_name] + list(sig_intermediate_names) + [sig_q_name, mul_out_name]
            for tensor_name in metadata_targets:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(tensor_name, None),
                    perm_nchw_to_nhwc,
                )

            # Remove redundant output transpose adapters.
            for post_op in removable_post_ops:
                post_out_name = str(post_op.outputs[0])
                _replace_tensor_inputs(model_ir, post_out_name, mul_out_name)

            removable_post_op_ids = {id(op) for op in removable_post_ops}
            removable_post_indices = [
                int(op_idx)
                for op_idx, op in enumerate(model_ir.operators)
                if id(op) in removable_post_op_ids
            ]
            remove_indices = sorted(
                set([int(pre_idx)] + [int(v) for v in removable_post_indices]),
                reverse=True,
            )
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "optimized_nhwc_prefix_qlinear_silu_chains": int(optimized),
    }


def _optimize_transpose_mean_maxpool_concat_conv_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate redundant NCHW/NHWC transpose chains around
    DEQUANTIZE->MEAN and MAX_POOL_2D branches before CONCATENATION->CONV.

    Target pattern (rank-4):
      q_raw_nhwc --TRANSPOSE(0,3,1,2)--> q_nchw --DEQUANTIZE--> dq_mean --MEAN(axes=[2,3])--> mean_nchw
      q_raw_nhwc --DEQUANTIZE--> dq_pool --MAX_POOL_2D--> pool_nhwc --TRANSPOSE(0,3,1,2)--> pool_nchw
      CONCAT(axis=1, [mean_nchw, pool_nchw]) -> QUANTIZE -> q_cat_nchw --TRANSPOSE(0,2,3,1)--> q_cat_nhwc -> CONV

    Rewritten:
      q_raw_nhwc --DEQUANTIZE--> dq_mean --MEAN(axes=[1,2])--> mean_nhwc
      q_raw_nhwc --DEQUANTIZE--> dq_pool --MAX_POOL_2D--> pool_nhwc
      CONCAT(axis=3, [mean_nhwc, pool_nhwc]) -> QUANTIZE -> q_cat_nhwc -> CONV
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    old_to_new_axis = perm_nhwc_to_nchw

    def _normalize_axis(axis: int, rank: int) -> Optional[int]:
        a = int(axis)
        if a < 0:
            a += int(rank)
        if a < 0 or a >= int(rank):
            return None
        return int(a)

    def _tensor_shape_signature(tensor: TensorIR) -> List[int]:
        if tensor.shape_signature is not None:
            return [int(v) for v in list(tensor.shape_signature)]
        return [int(v) for v in list(tensor.shape)]

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue

            q_raw_name = str(pre_op.inputs[0])
            q_nchw_name = str(pre_op.outputs[0])
            if q_raw_name in model_ir.outputs or q_nchw_name in model_ir.outputs:
                continue

            q_raw_tensor = model_ir.tensors.get(q_raw_name, None)
            q_nchw_tensor = model_ir.tensors.get(q_nchw_name, None)
            if q_raw_tensor is None or q_nchw_tensor is None:
                continue
            q_raw_shape = [int(v) for v in list(q_raw_tensor.shape)]
            if len(q_raw_shape) != 4:
                continue

            q_nchw_users = [int(v) for v in consumers.get(q_nchw_name, [])]
            if len(q_nchw_users) != 1:
                continue
            dq_mean_idx = int(q_nchw_users[0])
            dq_mean_op = model_ir.operators[dq_mean_idx]
            if str(dq_mean_op.op_type) != "DEQUANTIZE" or len(dq_mean_op.inputs) != 1 or len(dq_mean_op.outputs) != 1:
                continue
            dq_mean_out_name = str(dq_mean_op.outputs[0])
            if dq_mean_out_name in model_ir.outputs:
                continue

            dq_mean_out_users = [int(v) for v in consumers.get(dq_mean_out_name, [])]
            if len(dq_mean_out_users) != 1:
                continue
            mean_idx = int(dq_mean_out_users[0])
            mean_op = model_ir.operators[mean_idx]
            if str(mean_op.op_type) != "MEAN" or len(mean_op.inputs) < 2 or len(mean_op.outputs) != 1:
                continue
            if not bool(mean_op.options.get("keepDims", True)):
                continue
            mean_out_name = str(mean_op.outputs[0])
            if mean_out_name in model_ir.outputs:
                continue

            mean_axes_name = str(mean_op.inputs[1])
            mean_axes_tensor = model_ir.tensors.get(mean_axes_name, None)
            mean_axes_raw = _read_const_ints_from_tensor(mean_axes_tensor)
            if mean_axes_raw is None:
                continue
            mean_axes_old: List[int] = []
            axes_ok = True
            for axis in mean_axes_raw:
                norm_axis = _normalize_axis(int(axis), 4)
                if norm_axis is None:
                    axes_ok = False
                    break
                mean_axes_old.append(int(norm_axis))
            if not axes_ok:
                continue
            if sorted(mean_axes_old) != [2, 3]:
                continue

            q_raw_users = [int(v) for v in consumers.get(q_raw_name, [])]
            q_raw_users_wo_pre = [int(v) for v in q_raw_users if int(v) != int(pre_idx)]
            if len(q_raw_users_wo_pre) != 1:
                continue
            dq_pool_idx = int(q_raw_users_wo_pre[0])
            dq_pool_op = model_ir.operators[dq_pool_idx]
            if str(dq_pool_op.op_type) != "DEQUANTIZE" or len(dq_pool_op.inputs) != 1 or len(dq_pool_op.outputs) != 1:
                continue
            if str(dq_pool_op.inputs[0]) != q_raw_name:
                continue
            dq_pool_out_name = str(dq_pool_op.outputs[0])
            if dq_pool_out_name in model_ir.outputs:
                continue

            dq_pool_out_users = [int(v) for v in consumers.get(dq_pool_out_name, [])]
            if len(dq_pool_out_users) != 1:
                continue
            pool_idx = int(dq_pool_out_users[0])
            pool_op = model_ir.operators[pool_idx]
            if str(pool_op.op_type) != "MAX_POOL_2D" or len(pool_op.inputs) != 1 or len(pool_op.outputs) != 1:
                continue
            if str(pool_op.inputs[0]) != dq_pool_out_name:
                continue
            pool_out_name = str(pool_op.outputs[0])
            if pool_out_name in model_ir.outputs:
                continue

            pool_out_users = [int(v) for v in consumers.get(pool_out_name, [])]
            if len(pool_out_users) != 1:
                continue
            pool_post_idx = int(pool_out_users[0])
            pool_post_op = model_ir.operators[pool_post_idx]
            if str(pool_post_op.op_type) != "TRANSPOSE" or len(pool_post_op.inputs) < 2 or len(pool_post_op.outputs) != 1:
                continue
            if str(pool_post_op.inputs[0]) != pool_out_name:
                continue
            if _read_transpose_perm(model_ir, pool_post_op) != perm_nhwc_to_nchw:
                continue
            pool_nchw_name = str(pool_post_op.outputs[0])
            if pool_nchw_name in model_ir.outputs:
                continue

            mean_users = [int(v) for v in consumers.get(mean_out_name, [])]
            pool_nchw_users = [int(v) for v in consumers.get(pool_nchw_name, [])]
            if len(mean_users) != 1 or len(pool_nchw_users) != 1:
                continue
            concat_idx = int(mean_users[0])
            if int(pool_nchw_users[0]) != int(concat_idx):
                continue
            concat_op = model_ir.operators[concat_idx]
            if str(concat_op.op_type) != "CONCATENATION" or len(concat_op.outputs) != 1:
                continue
            concat_out_name = str(concat_op.outputs[0])
            if concat_out_name in model_ir.outputs:
                continue
            concat_axis_old = _normalize_axis(int(concat_op.options.get("axis", 1)), 4)
            if concat_axis_old is None or int(concat_axis_old) != 1:
                continue
            if mean_out_name not in set(str(v) for v in concat_op.inputs):
                continue
            if pool_nchw_name not in set(str(v) for v in concat_op.inputs):
                continue

            concat_out_users = [int(v) for v in consumers.get(concat_out_name, [])]
            if len(concat_out_users) != 1:
                continue
            q_cat_idx = int(concat_out_users[0])
            q_cat_op = model_ir.operators[q_cat_idx]
            if str(q_cat_op.op_type) != "QUANTIZE" or len(q_cat_op.inputs) != 1 or len(q_cat_op.outputs) != 1:
                continue
            if str(q_cat_op.inputs[0]) != concat_out_name:
                continue
            q_cat_name = str(q_cat_op.outputs[0])
            if q_cat_name in model_ir.outputs:
                continue

            post_users = [int(v) for v in consumers.get(q_cat_name, [])]
            if len(post_users) == 0:
                continue
            removable_post_indices: List[int] = []
            valid_posts = True
            for post_idx in post_users:
                post_op = model_ir.operators[post_idx]
                if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                    valid_posts = False
                    break
                if str(post_op.inputs[0]) != q_cat_name:
                    valid_posts = False
                    break
                if _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc:
                    valid_posts = False
                    break
                post_out_name = str(post_op.outputs[0])
                if post_out_name in model_ir.outputs:
                    valid_posts = False
                    break
                removable_post_indices.append(int(post_idx))
            if not valid_posts:
                continue

            dq_mean_out_tensor = model_ir.tensors.get(dq_mean_out_name, None)
            mean_out_tensor = model_ir.tensors.get(mean_out_name, None)
            pool_out_tensor = model_ir.tensors.get(pool_out_name, None)
            concat_out_tensor = model_ir.tensors.get(concat_out_name, None)
            q_cat_tensor = model_ir.tensors.get(q_cat_name, None)
            if any(t is None for t in [dq_mean_out_tensor, mean_out_tensor, pool_out_tensor, concat_out_tensor, q_cat_tensor]):
                continue

            # Keep the QDIM semantics deterministic for this metadata rewrite.
            if q_cat_tensor is not None and q_cat_tensor.quantization is not None and _quant_scale_count(q_cat_tensor.quantization) > 1:
                if int(q_cat_tensor.quantization.quantized_dimension) != 1:
                    continue

            # Rewire mean branch to consume NHWC quantized source directly.
            _set_operator_inputs(
                model_ir=model_ir,
                op=dq_mean_op,
                new_inputs=[q_raw_name],
            )
            dq_mean_out_tensor.shape = [int(v) for v in list(q_raw_tensor.shape)]
            dq_mean_out_tensor.shape_signature = _tensor_shape_signature(q_raw_tensor)

            mean_axes_new = [int(old_to_new_axis[int(axis)]) for axis in mean_axes_old]
            _write_const_ints_to_tensor(mean_axes_tensor, mean_axes_new)

            q_raw_signature = _tensor_shape_signature(q_raw_tensor)
            mean_shape = [int(v) for v in list(q_raw_tensor.shape)]
            mean_signature = [int(v) for v in list(q_raw_signature)]
            for axis in mean_axes_new:
                mean_shape[int(axis)] = 1
                mean_signature[int(axis)] = 1
            mean_out_tensor.shape = [int(v) for v in list(mean_shape)]
            mean_out_tensor.shape_signature = [int(v) for v in list(mean_signature)]

            # Replace pool NCHW adapter output with NHWC pool output.
            _set_operator_inputs(
                model_ir=model_ir,
                op=concat_op,
                new_inputs=[
                    str(pool_out_name) if str(input_name) == str(pool_nchw_name) else str(input_name)
                    for input_name in list(concat_op.inputs)
                ],
            )
            concat_op.options["axis"] = 3

            concat_inputs = [model_ir.tensors.get(str(input_name), None) for input_name in list(concat_op.inputs)]
            if any(t is None for t in concat_inputs):
                continue
            first_tensor = concat_inputs[0]
            if first_tensor is None:
                continue
            if len(list(first_tensor.shape)) != 4:
                continue
            concat_shape = [int(v) for v in list(first_tensor.shape)]
            concat_signature = _tensor_shape_signature(first_tensor)
            dynamic_concat_axis = False
            for tensor in concat_inputs[1:]:
                if tensor is None:
                    continue
                shape_i = [int(v) for v in list(tensor.shape)]
                if len(shape_i) != 4:
                    valid_posts = False
                    break
                concat_shape[3] += int(shape_i[3])
            if not valid_posts:
                continue
            for tensor in concat_inputs:
                if tensor is None:
                    continue
                sig_i = _tensor_shape_signature(tensor)
                if int(sig_i[3]) < 0:
                    dynamic_concat_axis = True
                    break
            if dynamic_concat_axis:
                concat_signature[3] = -1
            else:
                concat_signature[3] = int(
                    sum(int(_tensor_shape_signature(tensor)[3]) for tensor in concat_inputs if tensor is not None)
                )

            concat_out_tensor.shape = [int(v) for v in list(concat_shape)]
            concat_out_tensor.shape_signature = [int(v) for v in list(concat_signature)]
            q_cat_tensor.shape = [int(v) for v in list(concat_shape)]
            q_cat_tensor.shape_signature = [int(v) for v in list(concat_signature)]
            if q_cat_tensor.quantization is not None and _quant_scale_count(q_cat_tensor.quantization) > 1:
                q_cat_tensor.quantization.quantized_dimension = 3

            # Remove post-quantize transpose adapters and reconnect their consumers.
            for post_idx in removable_post_indices:
                post_op = model_ir.operators[int(post_idx)]
                post_out_name = str(post_op.outputs[0])
                _replace_tensor_inputs(model_ir, post_out_name, q_cat_name)

            remove_indices = sorted(
                set([int(pre_idx), int(pool_post_idx)] + [int(v) for v in removable_post_indices]),
                reverse=True,
            )
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "optimized_transpose_mean_maxpool_concat_conv_chains": int(optimized),
    }


def _canonicalize_softmax_transpose_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Canonicalize ONNX-driven transpose chains around SOFTMAX to expose removable pairs.

    Target template:
      T0(0,3,1,2) -> T1(0,3,2,1) -> SOFTMAX -> T2(0,3,2,1)

    Rewritten to:
      T0(0,3,1,2) -> T1(0,2,3,1) -> SOFTMAX -> T2(0,3,1,2)

    Then T0/T1 become inverse pairs and are removed by `_optimize_layout_transpose_chains`.
    """
    rewritten = 0
    softmax_nhwc_propagated_marker = "__softmax_nhwc_propagated__"
    rank4_perm_nhwc_to_nchw = [0, 3, 1, 2]
    rank4_perm_nchw_to_nhwc = [0, 2, 3, 1]
    rank4_perm_nchw_to_nwhc = [0, 3, 2, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _write_transpose_perm_for_op(
        op_idx: int,
        new_perm: List[int],
        consumers: Dict[str, List[int]],
    ) -> bool:
        op = model_ir.operators[int(op_idx)]
        if str(op.op_type) != "TRANSPOSE" or len(op.inputs) < 2:
            return False
        perm_name = str(op.inputs[1])
        perm_users = [int(v) for v in consumers.get(perm_name, [])]
        perm_data = np.asarray(new_perm, dtype=np.int32)

        # If perm tensor is shared, clone it to avoid side effects on other TRANSPOSE ops.
        if len(perm_users) != 1 or int(perm_users[0]) != int(op_idx):
            new_perm_name = _unique_tensor_name(f"{perm_name}_canon")
            model_ir.tensors[new_perm_name] = TensorIR(
                name=new_perm_name,
                dtype="INT32",
                shape=[int(len(new_perm))],
                shape_signature=[int(len(new_perm))],
                data=perm_data,
                is_variable=False,
                quantization=None,
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=op,
                input_index=1,
                new_input_name=new_perm_name,
            )
            return True

        perm_tensor = model_ir.tensors.get(perm_name, None)
        if perm_tensor is None:
            return False
        perm_tensor.data = perm_data
        perm_tensor.dtype = "INT32"
        perm_tensor.shape = [int(len(new_perm))]
        perm_tensor.shape_signature = [int(len(new_perm))]
        return True

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)

        for softmax_idx, softmax_op in enumerate(model_ir.operators):
            if str(softmax_op.op_type) != "SOFTMAX" or len(softmax_op.inputs) != 1 or len(softmax_op.outputs) != 1:
                continue
            softmax_in = str(softmax_op.inputs[0])
            softmax_out = str(softmax_op.outputs[0])
            if softmax_in in model_ir.outputs or softmax_out in model_ir.outputs:
                continue

            pre_idx = producers.get(softmax_in, None)
            if pre_idx is None:
                continue
            pre_op = model_ir.operators[int(pre_idx)]
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if str(pre_op.outputs[0]) != softmax_in:
                continue
            if _read_transpose_perm(model_ir, pre_op) != rank4_perm_nchw_to_nwhc:
                continue
            pre_users = [int(v) for v in consumers.get(softmax_in, [])]
            if pre_users != [int(softmax_idx)]:
                continue

            pre_input = str(pre_op.inputs[0])
            pre_prev_idx = producers.get(pre_input, None)
            if pre_prev_idx is None:
                continue
            pre_prev_op = model_ir.operators[int(pre_prev_idx)]
            if (
                str(pre_prev_op.op_type) != "TRANSPOSE"
                or len(pre_prev_op.inputs) < 2
                or len(pre_prev_op.outputs) != 1
                or str(pre_prev_op.outputs[0]) != pre_input
            ):
                continue
            if _read_transpose_perm(model_ir, pre_prev_op) != rank4_perm_nhwc_to_nchw:
                continue
            pre_prev_users = [int(v) for v in consumers.get(pre_input, [])]
            if pre_prev_users != [int(pre_idx)]:
                continue

            post_users = [int(v) for v in consumers.get(softmax_out, [])]
            if len(post_users) != 1:
                continue
            post_idx = int(post_users[0])
            post_op = model_ir.operators[int(post_idx)]
            if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                continue
            if str(post_op.inputs[0]) != softmax_out:
                continue
            if _read_transpose_perm(model_ir, post_op) != rank4_perm_nchw_to_nwhc:
                continue
            post_out_name = str(post_op.outputs[0])
            # Terminal graph outputs are safe as long as they are not internally consumed.
            # This enables removing redundant pre-softmax transpose pairs while preserving
            # the final output layout adapter.
            if post_out_name in model_ir.outputs and len(consumers.get(post_out_name, [])) != 0:
                continue

            # Avoid qdim remapping complexity for per-axis activation quantization.
            pre_in_tensor = model_ir.tensors.get(pre_input, None)
            softmax_out_tensor = model_ir.tensors.get(softmax_out, None)
            post_out_tensor = model_ir.tensors.get(str(post_op.outputs[0]), None)
            if not _all_per_tensor_quantized([pre_in_tensor, softmax_out_tensor, post_out_tensor]):
                continue

            if not _write_transpose_perm_for_op(int(pre_idx), rank4_perm_nchw_to_nhwc, consumers):
                continue
            if not _write_transpose_perm_for_op(int(post_idx), rank4_perm_nhwc_to_nchw, consumers):
                continue

            # Refresh static metadata conservatively; final reconcile pass will refine.
            if pre_in_tensor is not None:
                pre_out_tensor = model_ir.tensors.get(softmax_in, None)
                if pre_out_tensor is not None:
                    new_shape = _permute_shape(list(pre_in_tensor.shape), rank4_perm_nchw_to_nhwc)
                    sig_src = (
                        list(pre_in_tensor.shape_signature)
                        if pre_in_tensor.shape_signature is not None
                        else list(pre_in_tensor.shape)
                    )
                    new_sig = _permute_shape(sig_src, rank4_perm_nchw_to_nhwc)
                    if new_shape is not None:
                        pre_out_tensor.shape = [int(v) for v in new_shape]
                    if new_sig is not None:
                        pre_out_tensor.shape_signature = [int(v) for v in new_sig]

            if softmax_out_tensor is not None:
                post_out_tensor = model_ir.tensors.get(str(post_op.outputs[0]), None)
                if post_out_tensor is not None:
                    new_shape = _permute_shape(list(softmax_out_tensor.shape), rank4_perm_nhwc_to_nchw)
                    sig_src = (
                        list(softmax_out_tensor.shape_signature)
                        if softmax_out_tensor.shape_signature is not None
                        else list(softmax_out_tensor.shape)
                    )
                    new_sig = _permute_shape(sig_src, rank4_perm_nhwc_to_nchw)
                    if new_shape is not None:
                        post_out_tensor.shape = [int(v) for v in new_shape]
                    if new_sig is not None:
                        post_out_tensor.shape_signature = [int(v) for v in new_sig]

            softmax_opts = (
                dict(softmax_op.options)
                if isinstance(softmax_op.options, dict)
                else {}
            )
            softmax_opts[softmax_nhwc_propagated_marker] = True
            softmax_op.options = softmax_opts

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"canonicalized_softmax_transpose_chains": int(rewritten)}


def _optimize_terminal_softmax_transpose_after_nhwc_propagation(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Remove terminal SOFTMAX->TRANSPOSE(NHWC->NCHW) when SOFTMAX already carries
    NHWC-propagated semantics from `_canonicalize_softmax_transpose_chains`.

    Target:
      ... -> SOFTMAX(s) -> TRANSPOSE(0,3,1,2) -> y(graph output)

    Rewrite:
      ... -> SOFTMAX(y)

    Safety:
    - y must be a graph output with no internal consumers.
    - SOFTMAX output is consumed only by that terminal TRANSPOSE.
    - SOFTMAX is marked as NHWC-propagated by canonicalize pass.
    """
    rewritten = 0
    rank4_perm_nhwc_to_nchw = [0, 3, 1, 2]
    softmax_nhwc_propagated_marker = "__softmax_nhwc_propagated__"

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)

        for output_name in list(model_ir.outputs):
            output_name = str(output_name)
            if len(consumers.get(output_name, [])) != 0:
                continue

            post_idx = producers.get(output_name, None)
            if post_idx is None:
                continue
            post_op = model_ir.operators[int(post_idx)]
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or str(post_op.outputs[0]) != output_name
            ):
                continue
            if _read_transpose_perm(model_ir, post_op) != rank4_perm_nhwc_to_nchw:
                continue

            softmax_out_name = str(post_op.inputs[0])
            softmax_idx = producers.get(softmax_out_name, None)
            if softmax_idx is None:
                continue
            softmax_op = model_ir.operators[int(softmax_idx)]
            if (
                str(softmax_op.op_type) != "SOFTMAX"
                or len(softmax_op.inputs) != 1
                or len(softmax_op.outputs) != 1
                or str(softmax_op.outputs[0]) != softmax_out_name
            ):
                continue
            softmax_users = [int(v) for v in consumers.get(softmax_out_name, [])]
            if softmax_users != [int(post_idx)]:
                continue

            softmax_opts = (
                dict(softmax_op.options)
                if isinstance(softmax_op.options, dict)
                else {}
            )
            if not bool(softmax_opts.get(softmax_nhwc_propagated_marker, False)):
                continue
            softmax_opts.pop(softmax_nhwc_propagated_marker, None)
            softmax_op.options = softmax_opts

            _set_operator_outputs(
                model_ir=model_ir,
                op=softmax_op,
                new_outputs=[output_name],
            )
            src_tensor = model_ir.tensors.get(softmax_out_name, None)
            dst_tensor = model_ir.tensors.get(output_name, None)
            if src_tensor is not None and dst_tensor is not None:
                dst_tensor.dtype = str(src_tensor.dtype)
                dst_tensor.quantization = _clone_quantization(src_tensor.quantization)
                dst_tensor.shape = [int(v) for v in list(src_tensor.shape)]
                dst_tensor.shape_signature = (
                    [int(v) for v in list(src_tensor.shape_signature)]
                    if src_tensor.shape_signature is not None
                    else [int(v) for v in list(src_tensor.shape)]
                )

            del model_ir.operators[int(post_idx)]
            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"removed_terminal_softmax_transpose_after_nhwc_propagation": int(rewritten)}


def _optimize_transpose_pre_argmax_nhwc_terminal_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Remove redundant NHWC->NCHW transpose immediately before ARG_MAX by remapping axis.

    Target:
      x_nhwc --TRANSPOSE(0,3,1,2)--> x_nchw --ARG_MAX(axis=1)--> y

    Rewrite:
      x_nhwc --ARG_MAX(axis=3)--> y

    Safety:
    - Transpose output has single consumer (ARG_MAX).
    - ARG_MAX axis is constant and resolves to channel axis=1 in NCHW.
    - Rank-4 transpose permutation is exactly [0,3,1,2].
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_input_name in model_ir.outputs or pre_output_name in model_ir.outputs:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) != 1:
                continue
            argmax_idx = int(pre_users[0])
            argmax_op = model_ir.operators[int(argmax_idx)]
            if str(argmax_op.op_type) != "ARG_MAX" or len(argmax_op.inputs) < 2 or len(argmax_op.outputs) != 1:
                continue
            if str(argmax_op.inputs[0]) != pre_output_name:
                continue

            axis_name = str(argmax_op.inputs[1])
            axis_tensor = model_ir.tensors.get(axis_name, None)
            axis_vals = _read_const_ints_from_tensor(axis_tensor)
            if axis_vals is None or len(axis_vals) != 1:
                continue

            axis_old = int(axis_vals[0])
            if axis_old < 0:
                axis_old += 4
            # Restrict to channel-axis argmax in NCHW to preserve output ordering.
            if int(axis_old) != 1:
                continue
            axis_new = int(perm_nhwc_to_nchw[int(axis_old)])

            axis_users = [int(v) for v in consumers.get(axis_name, [])]
            axis_input_name = str(axis_name)
            if axis_users == [int(argmax_idx)]:
                if not _write_const_ints_to_tensor(axis_tensor, [int(axis_new)]):
                    # value may already be rewritten in prior sweep
                    pass
            else:
                axis_input_name = _unique_tensor_name(f"{axis_name}_nhwc")
                np_dtype = np.int32
                if axis_tensor is not None and axis_tensor.data is not None:
                    try:
                        np_dtype = np.asarray(axis_tensor.data).dtype
                    except Exception:
                        np_dtype = np.int32
                axis_data = np.asarray([int(axis_new)], dtype=np_dtype)
                model_ir.tensors[axis_input_name] = TensorIR(
                    name=axis_input_name,
                    dtype=str(axis_tensor.dtype) if axis_tensor is not None else "INT32",
                    shape=[1],
                    shape_signature=[1],
                    data=axis_data,
                    is_variable=False,
                    quantization=_clone_quantization(axis_tensor.quantization if axis_tensor is not None else None),
                )

            _set_operator_inputs(
                model_ir=model_ir,
                op=argmax_op,
                new_inputs=[str(pre_input_name), str(axis_input_name)],
            )

            del model_ir.operators[int(pre_idx)]
            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_pre_argmax_nhwc_terminal_chains": int(rewritten)}


def _optimize_layout_transpose_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate redundant TRANSPOSE chains introduced by channel-first/channel-last bridging.

    This pass removes:
    - identity transpose: X --Transpose(identity)--> Y
    - inverse transpose pairs with single-edge bridge:
        A --Transpose(P)--> B --Transpose(inv(P))--> C
      by directly reconnecting C consumers to A.

    The optimization is output-safe: graph outputs are never renamed.
    """
    removed_identity = 0
    removed_inverse_pairs = 0
    removed_inverse_fanout_branches = 0
    composed_consecutive_pairs = 0
    iterations = 0
    preserve_layout_boundary_marker = "__preserve_layout_boundary__"
    rank4_perm_nhwc_to_nchw = [0, 3, 1, 2]
    rank4_perm_nchw_to_nwhc = [0, 3, 2, 1]

    def _compose_permutations(perm_pre: List[int], perm_post: List[int]) -> Optional[List[int]]:
        if len(perm_pre) != len(perm_post) or len(perm_pre) == 0:
            return None
        rank = len(perm_pre)
        if sorted(int(v) for v in perm_pre) != list(range(rank)):
            return None
        if sorted(int(v) for v in perm_post) != list(range(rank)):
            return None
        try:
            return [int(perm_pre[int(v)]) for v in perm_post]
        except Exception:
            return None

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    while True:
        iterations += 1
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        # 1) Remove identity transpose.
        for op_idx, op in enumerate(model_ir.operators):
            if str(op.op_type) != "TRANSPOSE":
                continue
            if len(op.inputs) < 2 or len(op.outputs) != 1:
                continue
            perm = _read_transpose_perm(model_ir, op)
            if perm is None or not _is_identity_perm(perm):
                continue
            transposed_output = op.outputs[0]
            transposed_input = op.inputs[0]
            if transposed_output in model_ir.outputs:
                continue
            _replace_tensor_inputs(model_ir, transposed_output, transposed_input)
            del model_ir.operators[op_idx]
            removed_identity += 1
            changed = True
            break
        if changed:
            continue

        # 2) Remove inverse transpose pair.
        for op_idx, op in enumerate(model_ir.operators):
            if str(op.op_type) != "TRANSPOSE":
                continue
            if len(op.inputs) < 2 or len(op.outputs) != 1:
                continue
            bridge_tensor = op.outputs[0]
            bridge_users = consumers.get(bridge_tensor, [])
            if len(bridge_users) != 1:
                continue
            next_op_idx = int(bridge_users[0])
            if next_op_idx == op_idx:
                continue
            next_op = model_ir.operators[next_op_idx]
            if str(next_op.op_type) != "TRANSPOSE":
                continue
            if len(next_op.inputs) < 2 or len(next_op.outputs) != 1:
                continue
            if next_op.inputs[0] != bridge_tensor:
                continue

            perm_1 = _read_transpose_perm(model_ir, op)
            perm_2 = _read_transpose_perm(model_ir, next_op)
            if perm_1 is None or perm_2 is None:
                continue
            if not _is_inverse_perm(perm_1, perm_2):
                continue

            transpose_1_input = op.inputs[0]
            transpose_1_output = op.outputs[0]
            transpose_2_output = next_op.outputs[0]

            # Keep user-visible output names stable.
            if transpose_1_output in model_ir.outputs or transpose_2_output in model_ir.outputs:
                continue

            _replace_tensor_inputs(model_ir, transpose_2_output, transpose_1_input)
            for remove_idx in sorted([op_idx, next_op_idx], reverse=True):
                del model_ir.operators[remove_idx]
            removed_inverse_pairs += 1
            changed = True
            break

        if not changed:
            # 2b) Remove inverse transpose branches even when the first transpose
            # fans out to multiple consumers.
            for op_idx, op in enumerate(model_ir.operators):
                if str(op.op_type) != "TRANSPOSE":
                    continue
                if len(op.inputs) < 2 or len(op.outputs) != 1:
                    continue

                bridge_tensor = str(op.outputs[0])
                bridge_users = [int(v) for v in consumers.get(bridge_tensor, [])]
                if len(bridge_users) <= 1:
                    continue

                perm_pre = _read_transpose_perm(model_ir, op)
                if perm_pre is None:
                    continue

                for post_idx in bridge_users:
                    if int(post_idx) == int(op_idx):
                        continue
                    post_op = model_ir.operators[int(post_idx)]
                    if str(post_op.op_type) != "TRANSPOSE":
                        continue
                    if len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                        continue
                    if str(post_op.inputs[0]) != bridge_tensor:
                        continue

                    post_opts = dict(post_op.options) if isinstance(post_op.options, dict) else {}
                    if bool(post_opts.get(preserve_layout_boundary_marker, False)):
                        continue

                    perm_post = _read_transpose_perm(model_ir, post_op)
                    if perm_post is None or not _is_inverse_perm(perm_pre, perm_post):
                        continue

                    post_output = str(post_op.outputs[0])
                    if bridge_tensor in model_ir.outputs or post_output in model_ir.outputs:
                        continue

                    _replace_tensor_inputs(model_ir, post_output, str(op.inputs[0]))
                    del model_ir.operators[int(post_idx)]
                    removed_inverse_fanout_branches += 1
                    changed = True
                    break
                if changed:
                    break

        if not changed:
            # 3) Compose consecutive transpose pairs into one transpose.
            for op_idx, op in enumerate(model_ir.operators):
                if str(op.op_type) != "TRANSPOSE":
                    continue
                if len(op.inputs) < 2 or len(op.outputs) != 1:
                    continue
                op_opts = dict(op.options) if isinstance(op.options, dict) else {}
                if bool(op_opts.get(preserve_layout_boundary_marker, False)):
                    continue

                bridge_tensor = str(op.outputs[0])
                bridge_users = [int(v) for v in consumers.get(bridge_tensor, [])]
                if len(bridge_users) != 1:
                    continue

                next_op_idx = int(bridge_users[0])
                if next_op_idx == int(op_idx):
                    continue
                next_op = model_ir.operators[int(next_op_idx)]
                if str(next_op.op_type) != "TRANSPOSE":
                    continue
                if len(next_op.inputs) < 2 or len(next_op.outputs) != 1:
                    continue
                if str(next_op.inputs[0]) != bridge_tensor:
                    continue
                next_opts = dict(next_op.options) if isinstance(next_op.options, dict) else {}
                if bool(next_opts.get(preserve_layout_boundary_marker, False)):
                    continue

                perm_1 = _read_transpose_perm(model_ir, op)
                perm_2 = _read_transpose_perm(model_ir, next_op)
                if perm_1 is None or perm_2 is None:
                    continue
                # Keep this pattern intact for `_canonicalize_softmax_transpose_chains`.
                if (
                    [int(v) for v in perm_1] == rank4_perm_nhwc_to_nchw
                    and [int(v) for v in perm_2] == rank4_perm_nchw_to_nwhc
                ):
                    next_out_name = str(next_op.outputs[0])
                    next_out_users = [int(v) for v in consumers.get(next_out_name, [])]
                    if len(next_out_users) == 1:
                        softmax_idx = int(next_out_users[0])
                        if softmax_idx != int(next_op_idx):
                            softmax_op = model_ir.operators[softmax_idx]
                            if (
                                str(softmax_op.op_type) == "SOFTMAX"
                                and len(softmax_op.inputs) == 1
                                and len(softmax_op.outputs) == 1
                                and str(softmax_op.inputs[0]) == next_out_name
                            ):
                                softmax_out_name = str(softmax_op.outputs[0])
                                softmax_out_users = [int(v) for v in consumers.get(softmax_out_name, [])]
                                if len(softmax_out_users) == 1:
                                    post_idx = int(softmax_out_users[0])
                                    if post_idx != int(softmax_idx):
                                        post_op = model_ir.operators[post_idx]
                                        if (
                                            str(post_op.op_type) == "TRANSPOSE"
                                            and len(post_op.inputs) >= 2
                                            and len(post_op.outputs) == 1
                                            and str(post_op.inputs[0]) == softmax_out_name
                                            and _read_transpose_perm(model_ir, post_op) == rank4_perm_nchw_to_nwhc
                                        ):
                                            continue
                composed_perm = _compose_permutations(
                    [int(v) for v in perm_1],
                    [int(v) for v in perm_2],
                )
                if composed_perm is None:
                    continue

                next_perm_name = str(next_op.inputs[1])
                next_perm_users = [int(v) for v in consumers.get(next_perm_name, [])]
                if len(next_perm_users) == 1 and int(next_perm_users[0]) == int(next_op_idx):
                    perm_tensor = model_ir.tensors.get(next_perm_name, None)
                    if perm_tensor is None:
                        continue
                    perm_arr = np.asarray(composed_perm, dtype=np.int32)
                    perm_tensor.data = perm_arr
                    perm_tensor.dtype = "INT32"
                    perm_tensor.shape = [int(perm_arr.size)]
                    perm_tensor.shape_signature = [int(perm_arr.size)]
                    new_perm_name = next_perm_name
                else:
                    new_perm_name = _unique_tensor_name(f"{next_perm_name}_composed")
                    perm_arr = np.asarray(composed_perm, dtype=np.int32)
                    model_ir.tensors[new_perm_name] = TensorIR(
                        name=new_perm_name,
                        dtype="INT32",
                        shape=[int(perm_arr.size)],
                        shape_signature=[int(perm_arr.size)],
                        data=perm_arr,
                        is_variable=False,
                        quantization=None,
                    )

                _set_operator_inputs(
                    model_ir=model_ir,
                    op=next_op,
                    new_inputs=[str(op.inputs[0]), str(new_perm_name)],
                )
                del model_ir.operators[int(op_idx)]
                composed_consecutive_pairs += 1
                changed = True
                break

            if not changed:
                break

    _prune_unused_tensors(model_ir)
    return {
        "iterations": int(iterations),
        "removed_identity_transpose": int(removed_identity),
        "removed_inverse_transpose_pairs": int(removed_inverse_pairs),
        "removed_inverse_transpose_fanout_branches": int(removed_inverse_fanout_branches),
        "composed_consecutive_transpose_pairs": int(composed_consecutive_pairs),
    }


def _optimize_boundary_input_transpose_channel_slice_blocks(model_ir: ModelIR) -> Dict[str, int]:
    """
    Remove shared boundary input TRANSPOSE while preserving downstream NCHW semantics.

    Target:
      input(NHWC) --TRANSPOSE(0,3,1,2)--> input_onnx_ncx_internal
        |- SLICE(channel axis=1)
        |- ...
        `- other consumers

    Rewrite:
    - For eligible channel SLICE consumers, rewrite slice source to NHWC input and
      move NHWC->NCHW transpose after each slice output.
    - Localize remaining NCHW requirements by inserting per-consumer transposes.
    - Remove shared boundary TRANSPOSE so identifier=0 is no longer TRANSPOSE.
    """
    removed_boundary = 0
    rewritten_channel_slices = 0
    inserted_local_transposes = 0
    rewritten_axis_ops = 0

    layout_passthrough_unary = {
        "CAST",
        "RELU",
        "RELU6",
        "RELU_0_TO_1",
        "HARD_SWISH",
        "LOGISTIC",
        "TANH",
        "NEG",
        "EXP",
        "ABS",
        "SQRT",
    }
    layout_passthrough_binary = {
        "ADD",
        "SUB",
        "MUL",
        "DIV",
        "MAXIMUM",
        "MINIMUM",
    }

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _is_channel_slice_axis1(
        *,
        op: OperatorIR,
        source_shape_nchw: Optional[List[int]] = None,
    ) -> bool:
        if str(op.op_type) != "SLICE" or len(op.inputs) < 3 or len(op.outputs) != 1:
            return False
        begin_vals = _read_const_ints_from_tensor(model_ir.tensors.get(str(op.inputs[1]), None))
        size_vals = _read_const_ints_from_tensor(model_ir.tensors.get(str(op.inputs[2]), None))
        if begin_vals is None or size_vals is None or len(begin_vals) != 4 or len(size_vals) != 4:
            return False
        if int(size_vals[1]) != 1:
            return False
        if int(begin_vals[2]) != 0 or int(begin_vals[3]) != 0:
            return False
        if source_shape_nchw is not None and len(source_shape_nchw) == 4:
            if int(begin_vals[1]) < 0 or int(begin_vals[1]) >= int(source_shape_nchw[1]):
                return False
            h = int(source_shape_nchw[2])
            w = int(source_shape_nchw[3])
            if int(size_vals[2]) not in {h, -1}:
                return False
            if int(size_vals[3]) not in {w, -1}:
                return False
        else:
            if int(begin_vals[1]) < 0:
                return False
        return True

    def _rewrite_channel_slice_axis1_to_axis3(
        *,
        op: OperatorIR,
    ) -> bool:
        begin_tensor = model_ir.tensors.get(str(op.inputs[1]), None)
        size_tensor = model_ir.tensors.get(str(op.inputs[2]), None)
        begin_vals = _read_const_ints_from_tensor(begin_tensor)
        size_vals = _read_const_ints_from_tensor(size_tensor)
        if begin_vals is None or size_vals is None or len(begin_vals) != 4 or len(size_vals) != 4:
            return False
        new_begin = [int(begin_vals[0]), int(begin_vals[2]), int(begin_vals[3]), int(begin_vals[1])]
        new_size = [int(size_vals[0]), int(size_vals[2]), int(size_vals[3]), int(size_vals[1])]
        _write_const_ints_to_tensor(begin_tensor, new_begin)
        _write_const_ints_to_tensor(size_tensor, new_size)
        return True

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_inputs = set(str(v) for v in model_ir.inputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue

            input_name = str(pre_op.inputs[0])
            internal_name = str(pre_op.outputs[0])
            if input_name not in model_inputs:
                continue
            if not str(internal_name).endswith("_onnx_ncx_internal"):
                continue
            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre != [0, 3, 1, 2]:
                continue

            input_tensor = model_ir.tensors.get(input_name, None)
            internal_tensor = model_ir.tensors.get(internal_name, None)
            if input_tensor is None or internal_tensor is None:
                continue
            if len(list(internal_tensor.shape)) != 4:
                continue

            internal_users = [int(v) for v in consumers.get(internal_name, [])]
            if len(internal_users) == 0:
                continue

            # 1) Rewrite direct channel-slice consumers to NHWC source.
            converted_ops: set = set()
            nhwc_tensors: set = set()
            rewritten_any_slice = False
            for user_idx in sorted(internal_users):
                user_op = model_ir.operators[int(user_idx)]
                if not _is_channel_slice_axis1(
                    op=user_op,
                    source_shape_nchw=[int(v) for v in list(internal_tensor.shape)],
                ):
                    continue
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=user_op,
                    new_inputs=[input_name, str(user_op.inputs[1]), str(user_op.inputs[2])],
                )
                if _rewrite_channel_slice_axis1_to_axis3(op=user_op):
                    rewritten_channel_slices += 1
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(user_op.outputs[0]), None),
                    [0, 2, 3, 1],
                )
                converted_ops.add(int(user_idx))
                nhwc_tensors.add(str(user_op.outputs[0]))
                rewritten_any_slice = True

            if not rewritten_any_slice:
                continue

            # 2) Propagate NHWC through local axis-sensitive block.
            while True:
                propagated = False
                for op_idx, op in enumerate(model_ir.operators):
                    if int(op_idx) in converted_ops:
                        continue
                    if len(op.outputs) != 1:
                        continue
                    out_name = str(op.outputs[0])
                    op_type = str(op.op_type)

                    if op_type == "CONCATENATION":
                        axis = int(op.options.get("axis", -1))
                        if axis == 1 and len(op.inputs) > 0 and all(str(inp) in nhwc_tensors for inp in op.inputs):
                            op.options["axis"] = 3
                            _permute_tensor_metadata_if_rank_matches(
                                model_ir.tensors.get(out_name, None),
                                [0, 2, 3, 1],
                            )
                            rewritten_axis_ops += 1
                            nhwc_tensors.add(out_name)
                            converted_ops.add(int(op_idx))
                            propagated = True
                        continue

                    if op_type == "SLICE" and len(op.inputs) >= 3:
                        in_name = str(op.inputs[0])
                        if in_name in nhwc_tensors and _is_channel_slice_axis1(op=op, source_shape_nchw=None):
                            if _rewrite_channel_slice_axis1_to_axis3(op=op):
                                rewritten_axis_ops += 1
                            _permute_tensor_metadata_if_rank_matches(
                                model_ir.tensors.get(out_name, None),
                                [0, 2, 3, 1],
                            )
                            nhwc_tensors.add(out_name)
                            converted_ops.add(int(op_idx))
                            propagated = True
                        continue

                    if op_type in layout_passthrough_unary and len(op.inputs) >= 1:
                        if str(op.inputs[0]) in nhwc_tensors:
                            _permute_tensor_metadata_if_rank_matches(
                                model_ir.tensors.get(out_name, None),
                                [0, 2, 3, 1],
                            )
                            nhwc_tensors.add(out_name)
                            converted_ops.add(int(op_idx))
                            propagated = True
                        continue

                    if op_type in layout_passthrough_binary and len(op.inputs) >= 2:
                        dynamic_inputs: List[str] = []
                        for inp in list(op.inputs[:2]):
                            inp_name = str(inp)
                            inp_tensor = model_ir.tensors.get(inp_name, None)
                            if inp_tensor is not None and inp_tensor.data is not None:
                                continue
                            dynamic_inputs.append(inp_name)
                        if len(dynamic_inputs) > 0 and all(inp_name in nhwc_tensors for inp_name in dynamic_inputs):
                            _permute_tensor_metadata_if_rank_matches(
                                model_ir.tensors.get(out_name, None),
                                [0, 2, 3, 1],
                            )
                            nhwc_tensors.add(out_name)
                            converted_ops.add(int(op_idx))
                            propagated = True
                        continue

                    if op_type in {"CONV_2D", "DEPTHWISE_CONV_2D"} and len(op.inputs) >= 1:
                        # TFLite CONV_2D/DEPTHWISE_CONV_2D always produce NHWC outputs.
                        if str(op.inputs[0]) in nhwc_tensors:
                            _permute_tensor_metadata_if_rank_matches(
                                model_ir.tensors.get(out_name, None),
                                [0, 2, 3, 1],
                            )
                            nhwc_tensors.add(out_name)
                            converted_ops.add(int(op_idx))
                            propagated = True
                        continue

                if not propagated:
                    break

            # 3) Bridge NHWC tensors back to NCHW for consumers outside converted block.
            consumers_nhwc = _build_tensor_consumer_map(model_ir)
            bridge_plans: List[Tuple[int, str, str, List[int]]] = []
            for tensor_name in sorted(list(nhwc_tensors)):
                users = [
                    int(v)
                    for v in consumers_nhwc.get(str(tensor_name), [])
                    if int(v) not in converted_ops
                ]
                if len(users) == 0:
                    continue
                tensor = model_ir.tensors.get(str(tensor_name), None)
                if tensor is None or len(list(tensor.shape)) != 4:
                    continue
                bridge_name = _unique_tensor_name(f"{tensor_name}_nchw_bridge")
                bridge_shape = _permute_shape(list(tensor.shape), [0, 3, 1, 2])
                signature_src = (
                    list(tensor.shape_signature)
                    if tensor.shape_signature is not None
                    else list(tensor.shape)
                )
                bridge_signature = _permute_shape(signature_src, [0, 3, 1, 2])
                if bridge_shape is None or bridge_signature is None:
                    continue
                model_ir.tensors[bridge_name] = TensorIR(
                    name=bridge_name,
                    dtype=str(tensor.dtype),
                    shape=[int(v) for v in list(bridge_shape)],
                    shape_signature=[int(v) for v in list(bridge_signature)],
                    data=None,
                    is_variable=False,
                    quantization=_clone_quantization(tensor.quantization),
                )
                for user_idx in users:
                    user_op = model_ir.operators[int(user_idx)]
                    updated_inputs = [
                        bridge_name if str(inp) == str(tensor_name) else str(inp)
                        for inp in list(user_op.inputs)
                    ]
                    _set_operator_inputs(
                        model_ir=model_ir,
                        op=user_op,
                        new_inputs=updated_inputs,
                    )
                bridge_plans.append((int(min(users)), str(tensor_name), str(bridge_name), [int(v) for v in users]))

            inserted = 0
            for insert_idx, source_name, bridge_name, _users in sorted(bridge_plans, key=lambda v: int(v[0])):
                model_ir.operators.insert(
                    int(insert_idx + inserted),
                    OperatorIR(
                        op_type="TRANSPOSE",
                        inputs=[str(source_name), str(pre_op.inputs[1])],
                        outputs=[str(bridge_name)],
                    ),
                )
                inserted += 1
                inserted_local_transposes += 1

            # 4) Localize any remaining NCHW uses for this boundary tensor.
            consumers_after = _build_tensor_consumer_map(model_ir)
            remaining_users = [int(v) for v in consumers_after.get(internal_name, [])]
            inserted = 0
            for user_idx in sorted(remaining_users):
                user_op = model_ir.operators[int(user_idx + inserted)]
                local_name = _unique_tensor_name(f"{internal_name}_local")
                model_ir.tensors[local_name] = TensorIR(
                    name=local_name,
                    dtype=str(internal_tensor.dtype),
                    shape=[int(v) for v in list(internal_tensor.shape)],
                    shape_signature=(
                        [int(v) for v in list(internal_tensor.shape_signature)]
                        if internal_tensor.shape_signature is not None
                        else [int(v) for v in list(internal_tensor.shape)]
                    ),
                    data=None,
                    is_variable=False,
                    quantization=_clone_quantization(internal_tensor.quantization),
                )
                model_ir.operators.insert(
                    int(user_idx + inserted),
                    OperatorIR(
                        op_type="TRANSPOSE",
                        inputs=[input_name, str(pre_op.inputs[1])],
                        outputs=[local_name],
                    ),
                )
                inserted += 1
                updated_inputs = [
                    local_name if str(inp) == internal_name else str(inp)
                    for inp in list(user_op.inputs)
                ]
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=user_op,
                    new_inputs=updated_inputs,
                )
                inserted_local_transposes += 1

            # 5) Remove shared boundary transpose.
            del model_ir.operators[int(pre_idx)]
            removed_boundary += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "removed_boundary_input_transpose": int(removed_boundary),
        "rewritten_boundary_channel_slices": int(rewritten_channel_slices),
        "rewritten_boundary_axis_ops": int(rewritten_axis_ops),
        "inserted_local_boundary_transposes": int(inserted_local_transposes),
    }


def _optimize_boundary_input_layout_transposes(model_ir: ModelIR) -> Dict[str, int]:
    """
    Elide synthetic input-boundary layout adapters inserted as:
      input --TRANSPOSE--> input_onnx_ncx_internal

    Safety:
    - Matches only synthetic wrapper outputs named '*_onnx_ncx_internal'.
    - Input tensor must be a model input and not a model output.
    - Never mutates model-input metadata (public I/O contract).
    - Rewrites only when input/internal tensor metadata already match exactly.
    """
    removed = 0

    while True:
        model_inputs = set(str(v) for v in model_ir.inputs)
        model_outputs = set(str(v) for v in model_ir.outputs)
        changed = False

        for op_idx, op in enumerate(model_ir.operators):
            if str(op.op_type) != "TRANSPOSE":
                continue
            if len(op.inputs) < 2 or len(op.outputs) != 1:
                continue

            input_name = str(op.inputs[0])
            output_name = str(op.outputs[0])
            if input_name not in model_inputs:
                continue
            if input_name in model_outputs or output_name in model_outputs:
                continue
            if not str(output_name).endswith("_onnx_ncx_internal"):
                continue
            # Ensure this is the boundary adapter form [N,C,*] internalization.
            perm = _read_transpose_perm(model_ir, op)
            if perm is None:
                continue
            rank = len(perm)
            if rank == 3 and perm != [0, 2, 1]:
                continue
            if rank == 4 and perm != [0, 3, 1, 2]:
                continue
            if rank == 5 and perm != [0, 4, 1, 2, 3]:
                continue
            if rank not in {3, 4, 5}:
                continue

            internal_tensor = model_ir.tensors.get(output_name, None)
            input_tensor = model_ir.tensors.get(input_name, None)
            if internal_tensor is None or input_tensor is None:
                continue

            input_shape = [int(v) for v in list(input_tensor.shape)]
            internal_shape = [int(v) for v in list(internal_tensor.shape)]
            if input_shape != internal_shape:
                continue
            input_signature = (
                [int(v) for v in list(input_tensor.shape_signature)]
                if input_tensor.shape_signature is not None
                else input_shape
            )
            internal_signature = (
                [int(v) for v in list(internal_tensor.shape_signature)]
                if internal_tensor.shape_signature is not None
                else internal_shape
            )
            if input_signature != internal_signature:
                continue
            if str(input_tensor.dtype) != str(internal_tensor.dtype):
                continue
            if input_tensor.quantization != internal_tensor.quantization:
                continue

            # Redirect all internal users to model input without changing
            # external input tensor metadata.
            _replace_tensor_inputs(model_ir, output_name, input_name)

            del model_ir.operators[int(op_idx)]
            removed += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"removed_boundary_input_layout_transpose": int(removed)}


def _collect_schema_ops_for_range(
    *,
    opset_min: int = 13,
    opset_max: int = 18,
) -> List[str]:
    schema_ops = set()
    for schema in onnx.defs.get_all_schemas_with_history():
        if schema.domain != "":
            continue
        if int(schema.since_version) < int(opset_min) or int(schema.since_version) > int(opset_max):
            continue
        schema_ops.add(str(schema.name))
    return sorted(schema_ops)


def _build_schema_policy_matrix(
    *,
    schema_ops: set,
    supported_registry_ops: set,
    custom_candidate_ops: set,
) -> List[Dict[str, Any]]:
    matrix: List[Dict[str, Any]] = []
    for op in sorted(list(schema_ops)):
        if op in supported_registry_ops:
            policy = "builtin_supported"
        elif op in custom_candidate_ops:
            policy = "custom_candidate"
        else:
            policy = "explicit_error"
        matrix.append(
            {
                "onnx_op": str(op),
                "policy": str(policy),
            }
        )
    return matrix


def build_op_coverage_report(
    *,
    onnx_graph: onnx.ModelProto,
    output_file_name: str,
    opset_min: int = 13,
    opset_max: int = 18,
    conversion_error: Optional[str] = None,
    allow_custom_ops: bool = False,
    custom_op_allowlist: Optional[List[str]] = None,
    disable_group_convolution: bool = False,
    preprocess_report: Optional[Dict[str, Any]] = None,
    output_nms_with_argmax: bool = False,
) -> Dict[str, Any]:
    onnx_graph = _infer_shapes_with_fallback(onnx_graph)

    shape_map, dtype_map = _extract_tensor_info(onnx_graph)
    constants: Dict[str, np.ndarray] = {}
    for ini in onnx_graph.graph.initializer:
        constants[ini.name] = np.asarray(numpy_helper.to_array(ini))
    tensor_consumer_count: Dict[str, int] = {}
    for node in onnx_graph.graph.node:
        for input_name in node.input:
            if str(input_name) == "":
                continue
            tensor_consumer_count[str(input_name)] = int(tensor_consumer_count.get(str(input_name), 0) + 1)
    graph_output_names = [str(o.name) for o in onnx_graph.graph.output]

    model_ir = ModelIR(name=output_file_name)
    model_ir.metadata["tensor_lineage_events"] = []
    ctx = LoweringContext(
        model_ir=model_ir,
        shape_map=shape_map,
        dtype_map=dtype_map,
        constants=constants,
        onnx_model=onnx_graph,
        allow_custom_ops=allow_custom_ops,
        custom_op_allowlist=custom_op_allowlist,
        disable_group_convolution=disable_group_convolution,
        tensor_consumer_count=tensor_consumer_count,
        graph_output_names=graph_output_names,
        output_nms_with_argmax=output_nms_with_argmax,
    )
    initializer_names = {ini.name for ini in onnx_graph.graph.initializer}
    for graph_input in onnx_graph.graph.input:
        if graph_input.name in initializer_names:
            continue
        ctx.ensure_tensor(graph_input.name)
        model_ir.inputs.append(graph_input.name)
    for name, value in constants.items():
        if name not in model_ir.tensors:
            ctx.add_const_tensor(name, value)

    node_reports: List[Dict[str, Any]] = []
    unsupported_nodes: List[Dict[str, Any]] = []
    custom_lowered_nodes: List[Dict[str, Any]] = []
    graph_unique_ops: set = set()
    for node in onnx_graph.graph.node:
        node_name = node.name if node.name else node.op_type
        graph_unique_ops.add(node.op_type)
        if node.op_type == "Constant":
            value_attr = None
            for attr in node.attribute:
                if attr.name == "value":
                    value_attr = attr
                    break
            if value_attr is not None and len(node.output) > 0:
                const_array = np.asarray(numpy_helper.to_array(value_attr.t))
                out_name = node.output[0]
                if out_name in model_ir.tensors:
                    t = model_ir.tensors[out_name]
                    t.data = const_array
                    t.dtype = tflite_dtype_from_numpy(const_array.dtype)
                    t.shape, t.shape_signature = normalize_onnx_shape(list(const_array.shape))
                    constants[out_name] = const_array
                else:
                    _added = ctx.add_const_tensor(out_name, const_array)
                    if _added != out_name:
                        model_ir.tensors[out_name] = model_ir.tensors.pop(_added)
                        model_ir.tensors[out_name].name = out_name
                        constants[out_name] = constants.pop(_added)
            node_reports.append(
                {
                    "node_name": node_name,
                    "onnx_op": "Constant",
                    "supported": True,
                    "reason_code": "handled_inline",
                    "message": "Constant node is handled inline in lowering pass.",
                }
            )
            continue

        wrapped = _NodeWrap(node)
        try:
            resolution = resolve_node_dispatch(wrapped, ctx)
            dispatch_mode = str(resolution.dispatch_mode)
            reason_code = resolution.reason_code
            message = resolution.message
            node_reports.append(
                {
                    "node_name": node_name,
                    "onnx_op": node.op_type,
                    "supported": True,
                    "dispatch_mode": dispatch_mode,
                    "reason_code": reason_code,
                    "message": message,
                }
            )
            if dispatch_mode == "custom":
                custom_lowered_nodes.append(
                    {
                        "node_name": node_name,
                        "onnx_op": node.op_type,
                        "reason_code": reason_code,
                        "message": message,
                    }
                )
        except NodeValidationError as ve:
            issue = ve.to_dict()
            issue["supported"] = False
            issue["dispatch_mode"] = "unsupported"
            node_reports.append(issue)
            unsupported_nodes.append(issue)
        except Exception as ex:
            issue = {
                "node_name": node_name,
                "onnx_op": node.op_type,
                "supported": False,
                "dispatch_mode": "unsupported",
                "reason_code": "validation_exception",
                "message": str(ex),
            }
            node_reports.append(issue)
            unsupported_nodes.append(issue)

    supported_registry_ops = set(get_supported_onnx_ops())
    custom_candidate_ops = set(get_custom_op_candidate_ops())
    schema_ops = set(_collect_schema_ops_for_range(opset_min=opset_min, opset_max=opset_max))
    schema_policy_matrix = _build_schema_policy_matrix(
        schema_ops=schema_ops,
        supported_registry_ops=supported_registry_ops,
        custom_candidate_ops=custom_candidate_ops,
    )
    schema_policy_counts: Dict[str, int] = {
        "builtin_supported": 0,
        "custom_candidate": 0,
        "explicit_error": 0,
    }
    for item in schema_policy_matrix:
        p = str(item["policy"])
        schema_policy_counts[p] = int(schema_policy_counts.get(p, 0) + 1)
    graph_ops = sorted(graph_unique_ops)
    supported_graph_ops = sorted(
        list({r["onnx_op"] for r in node_reports if r["supported"] is True})
    )
    unsupported_graph_ops = sorted(
        list({r["onnx_op"] for r in node_reports if r["supported"] is False})
    )
    reason_counts: Dict[str, int] = {}
    for issue in unsupported_nodes:
        reason = str(issue.get("reason_code", "unknown"))
        reason_counts[reason] = int(reason_counts.get(reason, 0) + 1)

    normalized_allowlist = (
        [str(v).strip() for v in custom_op_allowlist if str(v).strip() != ""]
        if custom_op_allowlist is not None
        else None
    )
    allowlist_set = (
        {str(v) for v in normalized_allowlist}
        if normalized_allowlist is not None
        else set()
    )
    candidate_ops_now_builtin_supported = sorted(
        list(custom_candidate_ops & supported_registry_ops)
    )
    allowlist_builtin_supported_ops = sorted(
        list(allowlist_set & supported_registry_ops)
    )
    allowlist_custom_candidate_ops = sorted(
        list(allowlist_set & custom_candidate_ops)
    )
    allowlist_unknown_ops = sorted(
        list(
            allowlist_set
            - supported_registry_ops
            - custom_candidate_ops
            - schema_ops
        )
    )

    total_nodes = len(node_reports)
    supported_nodes = len([r for r in node_reports if r["supported"] is True])
    coverage = float(supported_nodes / total_nodes) if total_nodes > 0 else 1.0
    report: Dict[str, Any] = {
        "schema_version": 1,
        "target_opset_min": int(opset_min),
        "target_opset_max": int(opset_max),
        "supported_onnx_ops_registry": sorted(list(supported_registry_ops)),
        "custom_op_candidate_ops": sorted(list(custom_candidate_ops)),
        "schema_onnx_ops_target_range": sorted(list(schema_ops)),
        "schema_policy_matrix": schema_policy_matrix,
        "schema_policy_counts": schema_policy_counts,
        "schema_unresolved_ops": [],
        "registry_missing_from_schema_range": sorted(list(schema_ops - supported_registry_ops)),
        "registry_extra_outside_schema_range": sorted(list(supported_registry_ops - schema_ops)),
        "graph_ops": graph_ops,
        "graph_supported_ops": supported_graph_ops,
        "graph_unsupported_ops": unsupported_graph_ops,
        "graph_custom_ops": sorted(list({r["onnx_op"] for r in custom_lowered_nodes})),
        "graph_node_reports": node_reports,
        "custom_lowered_nodes": custom_lowered_nodes,
        "unsupported_nodes": unsupported_nodes,
        "unsupported_reason_counts": reason_counts,
        "graph_summary": {
            "total_nodes": int(total_nodes),
            "supported_nodes": int(supported_nodes),
            "custom_lowered_nodes": int(len(custom_lowered_nodes)),
            "unsupported_nodes": int(total_nodes - supported_nodes),
            "coverage_ratio": float(coverage),
        },
        "custom_op_policy": {
            "allow_custom_ops": bool(allow_custom_ops),
            "custom_op_allowlist": (
                [str(v) for v in normalized_allowlist]
                if normalized_allowlist is not None
                else None
            ),
            "candidate_count": int(len(custom_candidate_ops)),
            "candidate_count_excluding_builtin_supported": int(
                len(custom_candidate_ops - supported_registry_ops)
            ),
            "candidate_ops_now_builtin_supported": candidate_ops_now_builtin_supported,
            "allowlist_builtin_supported_ops": allowlist_builtin_supported_ops,
            "allowlist_custom_candidate_ops": allowlist_custom_candidate_ops,
            "allowlist_unknown_ops": allowlist_unknown_ops,
        },
        "preprocess_report": (
            dict(preprocess_report)
            if isinstance(preprocess_report, dict)
            else {
                "schema_version": 1,
                "pipeline_version": 1,
                "registered_rule_ids": [],
                "enabled_rule_ids": [],
                "applied_rules": [],
                "summary": {
                    "registered_rule_count": 0,
                    "enabled_rule_count": 0,
                    "executed_rule_count": 0,
                    "changed_rule_count": 0,
                    "total_matched_nodes": 0,
                    "total_rewritten_nodes": 0,
                },
            }
        ),
        "conversion_error": conversion_error,
    }
    return report


def write_op_coverage_report(
    *,
    report: Dict[str, Any],
    output_report_path: str,
) -> str:
    import json
